window.HADITH_CACHE["bukhari_12"] = {"6001":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا الشَّيْبَانِيُّ سَأَلْتُ عَبْدَ اللَّهِ بْنَ أَبِي أَوْفَىعَنْ الرَّجْمِ فَقَالَ رَجَمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ أَقَبْلَ النُّورِ أَمْ بَعْدَهُ قَالَ لَا أَدْرِيتَابَعَهُ عَلِيُّ بْنُ مُسْهِرٍ وَخَالِدُ بْنُ عَبْدِ اللَّهِ وَالْمُحَارِبِيُّ وَعَبِيدَةُ بْنُ حُمَيْدٍ عَنْ الشَّيْبَانِيِّ وَقَالَ بَعْضُهُمْ الْمَائِدَةِ وَالْأَوَّلُ أَصَحُّ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Abdul Wahid] telah menceritakan kepada kami [Asy Syaibani], aku bertanya kepada ['Abdullah bin bin Abi Awfa] tentang rajam, ia menjawab; Nabi shallallahu 'alaihi wasallam pernah merajam. Kemudian saya bertanya lagi; 'Itu terjadi sebelum diturunkan surat An Nur ataukah sesudahnya? ' Ia menjawab; 'Saya tidak tahu'. hadits ini diperkuat oleh ['Ali bin Mushir], [Khalid bin Abdullah], [Al Muharibi], [Abidah bin Humaid] dari [Asy Syaibani] dan mengatakan; 'Sebagian mereka mengatakan surat almaidah, dan yang pertama (surat An nur) lebih sahih.'"},"6002":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَبْدِ اللَّهِ حَدَّثَنِي مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا أَنَّهُ قَالَإِنَّ الْيَهُودَ جَاءُوا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرُوا لَهُ أَنَّ رَجُلًا مِنْهُمْ وَامْرَأَةً زَنَيَا فَقَالَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا تَجِدُونَ فِي التَّوْرَاةِ فِي شَأْنِ الرَّجْمِ فَقَالُوا نَفْضَحُهُمْ وَيُجْلَدُونَ قَالَ عَبْدُ اللَّهِ بْنُ سَلَامٍ كَذَبْتُمْ إِنَّ فِيهَا الرَّجْمَ فَأَتَوْا بِالتَّوْرَاةِ فَنَشَرُوهَا فَوَضَعَ أَحَدُهُمْ يَدَهُ عَلَى آيَةِ الرَّجْمِ فَقَرَأَ مَا قَبْلَهَا وَمَا بَعْدَهَا فَقَالَ لَهُ عَبْدُ اللَّهِ بْنُ سَلَامٍ ارْفَعْ يَدَكَ فَرَفَعَ يَدَهُ فَإِذَا فِيهَا آيَةُ الرَّجْمِ قَالُوا صَدَقَ يَا مُحَمَّدُ فِيهَا آيَةُ الرَّجْمِ فَأَمَرَ بِهِمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرُجِمَا فَرَأَيْتُ الرَّجُلَ يَحْنِي عَلَى الْمَرْأَةِ يَقِيهَا الْحِجَارَةَ","id":"Telah menceritakan kepada kami [Isma'il bin Abdullah] telah menceritakan kepadaku [Malik] dari [Nafi'] dari [Abdullah bin umar] radliallahu 'anhuma, bahwasanya ia menuturkan; orang-orang yahudi mendatangi Rasulullah Shallallahu'alaihiwasallam dan mengisahkan bahwa ada seorang laki-laki dari mereka dan seorang wanita melakukan perzinahan. Rasulullah bertanya: \"Bagaimana yang kalian dapatkan dalam Taurat tentang hukuman rajam?\" Mereka menjawab; 'Kami sekedar membongkar kejahatannya di depan umum dan mereka didera.' Serta merta Abdullah bin Salam berdiri dan mengatakan; 'Kalian semua bohong, dalam (Taurat) ada hukuman rajam.' Maka mereka membawa taurat dan membagikannya diantara hadirin. Salah seorang diantara mereka berusaha menutup-nutupi ayat rajam dengan tangannya sehingga ia baca sebelum dan sesudahnya. Dengan tegas Abdullah bin Salam menegur; 'angkat tanganmu! ' Ia pun mengangkat tangannya. Ternyata di sana terdapat ayat hukum rajam. Mereka menjawab; 'Benar engkau Ya Muhammad, sungguh dalam isinya terdapat hukum rajam! ' Maka Rasulullah memerintahkan keduanya untuk dirajam, dan diberlakukanlah hukuman tersebut. Dan kulihat si laki-laki berusaha membungkuk kearah si wanita untuk melindunginya dari lemparan batu."},"6003":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ عَنْ أَبِي هُرَيْرَةَ وَزَيْدِ بْنِ خَالِدٍ أَنَّهُمَا أَخْبَرَاهُأَنَّ رَجُلَيْنِ اخْتَصَمَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَحَدُهُمَا اقْضِ بَيْنَنَا بِكِتَابِ اللَّهِ وَقَالَ الْآخَرُ وَهُوَ أَفْقَهُهُمَا أَجَلْ يَا رَسُولَ اللَّهِ فَاقْضِ بَيْنَنَا بِكِتَابِ اللَّهِ وَأْذَنْ لِي أَنْ أَتَكَلَّمَ قَالَ تَكَلَّمْ قَالَ إِنَّ ابْنِي كَانَ عَسِيفًا عَلَى هَذَا قَالَ مَالِكٌ وَالْعَسِيفُ الْأَجِيرُ فَزَنَى بِامْرَأَتِهِ فَأَخْبَرُونِي أَنَّ عَلَى ابْنِي الرَّجْمَ فَافْتَدَيْتُ مِنْهُ بِمِائَةِ شَاةٍ وَبِجَارِيَةٍ لِي ثُمَّ إِنِّي سَأَلْتُ أَهْلَ الْعِلْمِ فَأَخْبَرُونِي أَنَّ مَا عَلَى ابْنِي جَلْدُ مِائَةٍ وَتَغْرِيبُ عَامٍ وَإِنَّمَا الرَّجْمُ عَلَى امْرَأَتِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَا وَالَّذِي نَفْسِي بِيَدِهِ لَأَقْضِيَنَّ بَيْنَكُمَا بِكِتَابِ اللَّهِ أَمَّا غَنَمُكَ وَجَارِيَتُكَ فَرَدٌّ عَلَيْكَ وَجَلَدَ ابْنَهُ مِائَةً وَغَرَّبَهُ عَامًا وَأَمَرَ أُنَيْسًا الْأَسْلَمِيَّ أَنْ يَأْتِيَ امْرَأَةَ الْآخَرِ فَإِنْ اعْتَرَفَتْ فَارْجُمْهَا فَاعْتَرَفَتْ فَرَجَمَهَا","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari [Ubaidullah bin Abdullah bin utbah bin Mas'ud] dari [Abu Hurairah] dan [Zaid bin Khalid], keduanya mengabarinya; dua orang laki-laki mengadukan sengketa kepada Rasulullah Shallallahu'alaihiwasallam. Salah satunya berujar; 'Putuskanlah diantara kami dengan kitabullah.' Satunya lagi berujar -dia lebih faqih daripada laki-laki pertama- 'Benar Ya Rasulullah, putuskanlah diantara kami dengan kitabullah, dan izinkanlah aku berbicara.' Maka ia pun berbicara; 'anakku menjadi pekerja laki-laki ini.' -Malik mengatakan, makna 'asif adalah pekerja.- dan dia berzina dengan isterinya. Maka mereka mengabariku bahwa anakku harus dirajam, maka aku menebusnya dengan seratus kambing dan seorang hamba sahaya. Kemudian aku bertanya kepada ahlu ilmu dan mereka mengabariku bahwa anakku harus dicambuk seratus kali dan diasingkan selama setahun, dan rajam bagi isterinya.' Maka Rasulullah shallallahu 'alaihi wasallam bersabda; \"Demi Dzat yang jiwaku berada di tangan-NYA, saya akan memutuskan kalian berdua dengan kitabullah, kambingmu dan hamba shayamu dikembali kepadamu.\" dan dia menjilid anaknya seratus kali dan asingkan selama setahun. Dan beliau menyuruh Unais Al Aslami untuk mendatangi si wanita. Jika dia mengaku, \"maka rajamlah\" dan dia mengaku, maka Unais merajamnya."},"6004":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنِي مَالِكٌ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْجَاءَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاضِعٌ رَأْسَهُ عَلَى فَخِذِي فَقَالَ حَبَسْتِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّاسَ وَلَيْسُوا عَلَى مَاءٍ فَعَاتَبَنِي وَجَعَلَ يَطْعُنُ بِيَدِهِ فِي خَاصِرَتِي وَلَا يَمْنَعُنِي مِنْ التَّحَرُّكِ إِلَّا مَكَانُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْزَلَ اللَّهُ آيَةَ التَّيَمُّمِ","id":"Telah menceritakan kepada kami [Isma'il] telah menceritakan kepada kami [Malik] dari ['Abdurrahman bin Al Qasim] dari [ayahnya] dari ['Aisyah] mengatakan, Abu Bakar radliallahu 'anhu datang ketika Rasulullah shallallahu 'alaihi wasallam meletakkan kepalanya di pahaku, Abu Bakar berujar; 'Engkau telah menghalangi Rasulullah Shallallahu'alaihiwasallam padahal manusia tidak mendapatkan air untuk tayammum.' Abu Bakar mencelaku dan mencubit lambungku dengan tangannya dan tak ada yang menghalangiku untuk bergerak selain posisi Rasulullah Shallallahu'alaihiwasallam, maka Allah kemudian menurunkan ayat tayammum."},"6005":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سُلَيْمَانَ حَدَّثَنِي ابْنُ وَهْبٍ أَخْبَرَنِي عَمْرٌو أَنَّ عَبْدَ الرَّحْمَنِ بْنَ الْقَاسِمِ حَدَّثَهُ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْأَقْبَلَ أَبُو بَكْرٍ فَلَكَزَنِي لَكْزَةً شَدِيدَةً وَقَالَ حَبَسْتِ النَّاسَ فِي قِلَادَةٍ فَبِي الْمَوْتُ لِمَكَانِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ أَوْجَعَنِي نَحْوَهُلَكَزَ وَوَكَزَ وَاحِدٌ","id":"Telah menceritakan kepada kami [Yahya bin Sulaiman] telah menceritakan kepadaku [Ibnu Wahab] telah mengabarkan kepadaku ['Amru] bahwasanya [Abdurrahman bin Al Qasim] pernah menceritakan kepadanya dari [ayahnya] dari ['Aisyah] mengatakan; 'Abu Bakar datang dengan tiba-tiba kemudian mendorong dadaku dengan sekuatnya seraya mengatakan; 'Engkau telah menahan orang-orang berangkat karena kalung! ' Maka aku seolah-olah terkena kematian karena kedudukan Rasulullah shallallahu 'alaihi wasallam yang juga telah menjadikanku tersakiti semisalnya.' Sedang istilah wakaza dan lakaza maknanya sama, yaitu menggencet dengan kuat."},"6006":{"ar":"حَدَّثَنَا مُوسَى حَدَّثَنَا أَبُو عَوَانَةَ حَدَّثَنَا عَبْدُ الْمَلِكِ عَنْ وَرَّادٍ كَاتِبِ الْمُغِيرَةِ عَنْ الْمُغِيرَةِ قَالَقَالَ سَعْدُ بْنُ عُبَادَةَ لَوْ رَأَيْتُ رَجُلًا مَعَ امْرَأَتِي لَضَرَبْتُهُ بِالسَّيْفِ غَيْرَ مُصْفَحٍ فَبَلَغَ ذَلِكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَتَعْجَبُونَ مِنْ غَيْرَةِ سَعْدٍ لَأَنَا أَغْيَرُ مِنْهُ وَاللَّهُ أَغْيَرُ مِنِّي","id":"Telah menceritakan kepada kami [Musa] Telah menceritakan kepada kami [Abu 'Awanah] Telah menceritakan kepada kami [Abdul Malik] dari [Warrad] juru tulis Almughirah, dari [Al Mughirah] mengatakan; Sa'd bin Ubadah mengatakan; 'Kalau kulihat ada seorang laki-laki bersama isteriku niscaya kusabet dengan pedang tepat dengan mata besinya. Berita ini sampai kepada Nabi shallallahu 'alaihi wasallam sehingga Nabi bertanya: \"Apakah kalian merasa heran dari kecemburan Sa'd, sungguh aku lebih cemburu daripadanya, dan Allah lebih cemburu daripadaku.\""},"6007":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنِي مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاءَهُ أَعْرَابِيٌّ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ امْرَأَتِي وَلَدَتْ غُلَامًا أَسْوَدَ فَقَالَ هَلْ لَكَ مِنْ إِبِلٍ قَالَ نَعَمْ قَالَ مَا أَلْوَانُهَا قَالَ حُمْرٌ قَالَ هَلْ فِيهَا مِنْ أَوْرَقَ قَالَ نَعَمْ قَالَ فَأَنَّى كَانَ ذَلِكَ قَالَ أُرَاهُ عِرْقٌ نَزَعَهُ قَالَ فَلَعَلَّ ابْنَكَ هَذَا نَزَعَهُ عِرْقٌ","id":"Telah menceritakan kepada kami [Isma'il] telah mengabarkan kepadaku [Malik] dari [Ibnu Syihab] dari [Sa'id bin Musayyab] dari [Abu Hurairah] radliallahu 'anhu, bahwasanya Rasulullah shallallahu 'alaihi wasallam pernah kedatangan seorang arab badui dan berujar; 'Wahai Rasulullah, istriku melahirkan bayi hitam.' Nabi bertanya; \"Apakah kamu punya unta?\" 'ya' jawabnya. Nabi bertanya lagi: \"Apa warnanya?\" 'Merah' Jawabnya. Nabi bertanya lagi: \"apakah disana ada warna kecoklat-coklatan?\" 'ya' jawabnya. Nabi bertanya lagi; \"darimana warna itu ada?\" 'pendapat saya, warna itu diturunkan karena akar keturunan.' Nabi bersabda: \"warna anakmu bisa jadi juga karena akar keturunan.\""},"6008":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا اللَّيْثُ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جَابِرِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي بُرْدةَ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يُجْلَدُ فَوْقَ عَشْرِ جَلَدَاتٍ إِلَّا فِي حَدٍّ مِنْ حُدُودِ اللَّهِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah menceritakan kepada kami [Al Laits] telah menceritakan kepadaku [Yazid bin Abu Hubaib] dari [Bukair bin Abdullah] dari [Sulaiman bin Yasar] dari ['Abdurrahman bin Jabir bin Abdullah] dari [Abu Burdah] radliallahu 'anhu, mengatakan; Nabi Shallallahu'alaihi wasallam bersabda: \"Tak boleh menjilid melebihi sepuluh kali selain dalam salah hukuman had (yang) Allah (tetapkan).\""},"6009":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا فُضَيْلُ بْنُ سُلَيْمَانَ حَدَّثَنَا مُسْلِمُ بْنُ أَبِي مَرْيَمَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ جَابِرٍ عَمَّنْ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَلَا عُقُوبَةَ فَوْقَ عَشْرِ ضَرَبَاتٍ إِلَّا فِي حَدٍّ مِنْ حُدُودِ اللَّهِ","id":"Telah menceritakan kepada kami ['Amru bin Ali] telah menceritakan kepada kami [Fudhail bin Sulaiman] telah menceritakan kepada kami [Muslim bin Abu Maryam] telah mengabarkan kepadaku [Abdurrahman bin Jabir], dari [seseorang] yang mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"tidak boleh ada hukuman melebihi sepuluh kali pukulan selain dalam salah satu hukuman had Allah.\""},"6010":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سُلَيْمَانَ حَدَّثَنِي ابْنُ وَهْبٍ أَخْبَرَنِي عَمْرٌو أَنَّ بُكَيْرًا حَدَّثَهُ قَالَ بَيْنَمَا أَنَا جَالِسٌ عِنْدَ سُلَيْمَانَ بْنِ يَسَارٍ إِذْ جَاءَ عَبْدُ الرَّحْمَنِ بْنُ جَابِرٍ فَحَدَّثَ سُلَيْمَانَ بْنَ يَسَارٍ ثُمَّ أَقْبَلَ عَلَيْنَا سُلَيْمَانُ بْنُ يَسَارٍ فَقَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ جَابِرٍ أَنَّ أَبَاهُ حَدَّثَهُ أَنَّهُ سَمِعَ أَبَا بُرْدَةَ الْأَنْصَارِيَّ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَجْلِدُوا فَوْقَ عَشْرَةِ أَسْوَاطٍ إِلَّا فِي حَدٍّ مِنْ حُدُودِ اللَّهِ","id":"Telah menceritakan kepada kami [Yahya bin Sulaiman] telah menceritakan kepadaku [Ibnu Wahb] telah mengabarkan kepadaku [Amru] bahwa [Bukair] menceritakan kepadanya, dia berkata; ketika kami sedang duduk-duduk di dekat [Sulaiman bin Yasar] datanglah [Abdurrahman bin Jabir], dan dia menceritakan kepada Sulaiman bin Yasar, kemudian Sulaiman bin Yasar menghadap ke kami dan berkata; Abdurrahman bin Jabir telah menceritakan kepadaku; bahwa [bapaknya] telah menceritakan kepadanya, bahwasanya dia telah mendengar [Abu Burdah Al Anshari] berkata; aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"janganlah kalian menjilid diatas sepuluh cambukan, kecuali dalam salah satu hukuman had Allah.\""},"6011":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ حَدَّثَنَا أَبُو سَلَمَةَ أَنَّ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْوِصَالِ فَقَالَ لَهُ رِجَالٌ مِنْ الْمُسْلِمِينَ فَإِنَّكَ يَا رَسُولَ اللَّهِ تُوَاصِلُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّكُمْ مِثْلِي إِنِّي أَبِيتُ يُطْعِمُنِي رَبِّي وَيَسْقِينِ فَلَمَّا أَبَوْا أَنْ يَنْتَهُوا عَنْ الْوِصَالِ وَاصَلَ بِهِمْ يَوْمًا ثُمَّ يَوْمًا ثُمَّ رَأَوْا الْهِلَالَ فَقَالَ لَوْ تَأَخَّرَ لَزِدْتُكُمْ كَالْمُنَكِّلِ بِهِمْ حِينَ أَبَوْاتَابَعَهُ شُعَيْبٌ وَيَحْيَى بْنُ سَعِيدٍ وَيُونُسُ عَنْ الزُّهْرِيِّ وَقَالَ عَبْدُ الرَّحْمَنِ بْنُ خَالِدٍ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari [Uqail] dari [Ibnu Syihab] telah menceritakan kepada kami [Abu Salamah] bahwasanya [Abu Hurairah] radliallahu 'anhu mengatakan; Rasulullah Shallallahu'alaihiwasallam melarang puasa wishal. Maka beberapa orang kaum muslimin bertanya; 'engkau sendiri ya Rasulullah melakukan puasa wishal.' Rasulullah Shallallahu'alaihiwasallam menjawab; \"Siapa diantara kalian sanggup seperti aku, Rabbiku memberiku makan dan minum.\" Tatkala mereka masih enggan menyudahi puasa wishal, Nabi terus melakukan wishal bersama mereka hari demi hari, lantas mereka melihat bulan sabit muncul, maka Nabi bersabda: \"Kalaulah bulan sabit itu terlambat, niscaya kutambah untuk kalian!\" Seolah-olah beliau hendak menghukum mereka tatkala mereka enggan. hadits ini diperkuat oleh [Syu'aib] dan [Yahya bin Sa'id] dan [Yunus] dari [Az Zuhri], dan [Abdurrahman bin Khalid] mengatakan dari [Ibnu Syihab] dari [Sa'id] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam."},"6012":{"ar":"حَدَّثَنِي عَيَّاشُ بْنُ الْوَلِيدِ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّهُمْ كَانُوا يُضْرَبُونَ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اشْتَرَوْا طَعَامًا جِزَافًا أَنْ يَبِيعُوهُ فِي مَكَانِهِمْ حَتَّى يُؤْوُوهُ إِلَى رِحَالِهِمْ","id":"Telah menceritakan kepadaku ['Ayyasy bin Al Walid] telah menceritakan kepada kami ['Abdul A'la] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Salim] dari [Abdullah bin Umar]; Di masa Rasulullah Shallallahu' alaihi wa sallam, jika para sahabat membeli makanan yang tak jelas takaran dan timbangannya, mereka dilarang menjualnya ditempat mereka membeli (tempat yang sama) hingga mereka memindahkannya ke kendaraan angkut mereka."},"6013":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ أَخْبَرَنِي عُرْوَةُ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْمَا انْتَقَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِنَفْسِهِ فِي شَيْءٍ يُؤْتَى إِلَيْهِ حَتَّى يُنْتَهَكَ مِنْ حُرُمَاتِ اللَّهِ فَيَنْتَقِمَ لِلَّهِ","id":"Telah menceritakan kepada kami [Abdan] Telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Yunus] dari [Az Zuhri] telah mengabarkan kepadaku ['Urwah] dari ['Aisyah] radliallahu 'anha mengatakan; Rasulullah Shallallahu'alaihiwasallam tidak pernah marah terhadap seseorang untuk dirinya sendiri karena suatu kasus yang berkaitan pribadinya, hingga jika kehormatan Allah dilecehkan, maka beliau marah karena Allah.\""},"6014":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ الزُّهْرِيُّ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَشَهِدْتُ الْمُتَلَاعِنَيْنِ وَأَنَا ابْنُ خَمْسَ عَشْرَةَ سَنَةً فَرَّقَ بَيْنَهُمَا فَقَالَ زَوْجُهَا كَذَبْتُ عَلَيْهَا إِنْ أَمْسَكْتُهَاقَالَ فَحَفِظْتُ ذَاكَ مِنَ الزُّهْرِيِّ إِنْ جَاءَتْ بِهِ كَذَا وَكَذَا فَهُوَ وَإِنْ جَاءَتْ بِهِ كَذَا وَكَذَا كَأَنَّهُ وَحَرَةٌ فَهُوَ وَسَمِعْتُ الزُّهْرِيَّ يَقُولُ جَاءَتْ بِهِ لِلَّذِي يُكْ��َهُ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Sufyan], [Az Zuhri] mengatakan dari [Sahal bin Sa'd] mengatakan, pernah aku menyaksikan dua orang yang saling meli'an, ketika itu umurku baru lima belas tahun, keduanya sama-sama mengajak berpisah, si suami mengatakan; 'berarti aku bohong terhadap dirinya jika aku terus mempertahankan dia sebagai isteri.' Kata Sahal, dan aku menghapal hadits yang serupa dari Az Zuhri yang redaksinya; 'Jika isteriku melahirkan bayi dengan ciri-ciri demikian maka,,,,, sebaliknya jika melahirkan bayi yang ciri-ciri kulitnya seperti tokek, maka demikian. Dan aku mendengar Az Zuhri mengatakan; Lantas wanita tersebut melahirkan bayi yang tidak di sukainya."},"6015":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ قَالَ ذَكَرَ ابْنُ عَبَّاسٍالْمُتَلَاعِنَيْنِ فَقَالَ عَبْدُ اللَّهِ بْنُ شَدَّادٍ هِيَ الَّتِي قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ كُنْتُ رَاجِمًا امْرَأَةً عَنْ غَيْرِ بَيِّنَةٍ قَالَ لَا تِلْكَ امْرَأَةٌ أَعْلَنَتْ","id":"Telah menceritakan kepada kami ['Ali bin Abdullah] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Abu Az Zanad] dari [Al Qasim bin Muhammad] mengatakan; [Ibnu Abbas] menceritakan tentang dua orang yang saling meli'an. Lantas Abdullah bin Syaddad bertanya; 'Itukah wanita yang Rasulullah Shallallahu'alaihiwasallam mengomentarinya dengan sabdanya: \"Jika aku merajam wanita tanpa bukti (niscaya aku merajam orang ini) \"? ' Ibnu Abbas menjawab; \"Tidak, itu adalah wanita yang terang-terangan.\""},"6016":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا اللَّيْثُ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاذُكِرَ التَّلَاعُنُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ عَاصِمُ بْنُ عَدِيٍّ فِي ذَلِكَ قَوْلًا ثُمَّ انْصَرَفَ وَأَتَاهُ رَجُلٌ مِنْ قَوْمِهِ يَشْكُو أَنَّهُ وَجَدَ مَعَ أَهْلِهِ رَجُلًا فَقَالَ عَاصِمٌ مَا ابْتُلِيتُ بِهَذَا إِلَّا لِقَوْلِي فَذَهَبَ بِهِ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَهُ بِالَّذِي وَجَدَ عَلَيْهِ امْرَأَتَهُ وَكَانَ ذَلِكَ الرَّجُلُ مُصْفَرًّا قَلِيلَ اللَّحْمِ سَبِطَ الشَّعَرِ وَكَانَ الَّذِي ادَّعَى عَلَيْهِ أَنَّهُ وَجَدَهُ عِنْدَ أَهْلِهِ آدَمَ خَدِلًا كَثِيرَ اللَّحْمِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ بَيِّنْ فَوَضَعَتْ شَبِيهًا بِالرَّجُلِ الَّذِي ذَكَرَ زَوْجُهَا أَنَّهُ وَجَدَهُ عِنْدَهَا فَلَاعَنَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَهُمَا فَقَالَ رَجُلٌ لِابْنِ عَبَّاسٍ فِي الْمَجْلِسِ هِيَ الَّتِي قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ رَجَمْتُ أَحَدًا بِغَيْرِ بَيِّنَةٍ رَجَمْتُ هَذِهِ فَقَالَ لَا تِلْكَ امْرَأَةٌ كَانَتْ تُظْهِرُ فِي الْإِسْلَامِ السُّوءَ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] telah menceritakan kepada kami [Al Laits] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Abdurrahman bin Al Qasim] dari [Al Qasim bin Muhammad] dari [Ibnu 'Abbas] radliallahu 'anhuma, Di majlis Nabi shallallahu 'alaihi wasallam dibicarakan masalah li'an. Lantas 'Ashim bin 'Adi mengucapkan satu perkataan kemudian pulang. selanjutnya dia didatangi sereorang dari kaumnya yang mengadukan keluh kesahnya bahwa dirinya menemukan isterinya sedang bersama laki-laki lain yang bukan suaminya. Maka 'Ashim bin Adi berujar; 'aku tidak diuji dengan kasus ini selain karena ucapanku sendiri! ' Lalu ia bawa orang tadi menemui Nabi shallallahu 'alaihi wasallam dan memberitahukan kepada beliau tentang kejadian bahwa dia menemukan isterinya bersama laki-laki lai nyang ciri-cirinya berkulit kuning, dagingnya sedikit, rambutnya lurus, sedang laki-laki yang mengaku bahwa dia menemukan isterinya bersama orang lain berwarna coklat, gemuk, dan berbadan gempal berisi. Nabi shallallahu 'alaihi wasallam kemudian berdoa; \"Ya allah, berilah kejelasan masalah ini.\" kemudian si wanita melahirkan bayi yang mirip dengan laki-laki yang dituduhkan suaminya bersama isterinya. Lantas Nabi shallallahu 'alaihi wasallam meli'an keduanya. Ada seseorang bertanya kepada Ibn 'Abbas; 'Wanita itukah yang dimaksud oleh ucapan Nabi: \"Sekiranya aku merajam wanita dengan tanpa bukti, niscaya kurajam wanita ini!\"? ' Ibn Abbas menjawab; ' bukan! Itu adalah wanita yang menampakkan keburukan (zina) di dalam Islam.\""},"6017":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُلَيْمَانُ عَنْ ثَوْرِ بْنِ زَيْدٍ عَنْ أَبِي الْغَيْثِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اجْتَنِبُوا السَّبْعَ الْمُوبِقَاتِ قَالُوا يَا رَسُولَ اللَّهِ وَمَا هُنَّ قَالَ الشِّرْكُ بِاللَّهِ وَالسِّحْرُ وَقَتْلُ النَّفْسِ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ وَأَكْلُ الرِّبَا وَأَكْلُ مَالِ الْيَتِيمِ وَالتَّوَلِّي يَوْمَ الزَّحْفِ وَقَذْفُ الْمُحْصَنَاتِ الْمُؤْمِنَاتِ الْغَافِلَاتِ","id":"Telah menceritakan kepada kami ['Abdul 'Aziz bin Abdullah] telah menceritakan kepada kami [Sulaiman] dari [Tsaur bin Zaid] dari [Abul Ghaits] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam bersabda; \"Jauhilah tujuh dosa besar yang membinasakan.\" Para sahabat bertanya; 'Ya Rasulullah, apa saja tujuh dosa besar yang membinasakan itu? ' Nabi menjawab; \"menyekutukan Allah, sihir, membunuh jiwa yang Allah haramkan tanpa alasan yang benar, makan riba, makan harta anak yatim, lari dari medan perang, dan menuduh wanita mukmin baik-baik melakukan perzinahan.\""},"6018":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ فُضَيْلِ بْنِ غَزْوَانَ عَنْ ابْنِ أَبِي نُعْمٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَسَمِعْتُ أَبَا الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ قَذَفَ مَمْلُوكَهُ وَهُوَ بَرِيءٌ مِمَّا قَالَ جُلِدَ يَوْمَ الْقِيَامَةِ إِلَّا أَنْ يَكُونَ كَمَا قَالَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Fudhail bin Ghazawan] dari [Ibnu Abi Nu'm] dari [Abu Hurairah] radliallahu 'anhu mengatakan; aku mendengar Abul Qasim Shallallahu'alaihiwasallam bersabda; \"Siapa yang menuduh budaknya berzina padahal ia tidak seperti yang diucapkannya, si penuduh akan didera pada hari kiamat terkecuali sebagaimana yang diucapkan (benar).\""},"6019":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ أَبِي هُرَيْرَةَ وَزَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ قَالَاجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَنْشُدُكَ اللَّهَ إِلَّا قَضَيْتَ بَيْنَنَا بِكِتَابِ اللَّهِ فَقَامَ خَصْمُهُ وَكَانَ أَفْقَهَ مِنْهُ فَقَالَ صَدَقَ اقْضِ بَيْنَنَا بِكِتَابِ اللَّهِ وَأْذَنْ لِي يَا رَسُولَ اللَّهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْ فَقَالَ إِنَّ ابْنِي كَانَ عَسِيفًا فِي أَهْلِ هَذَا فَزَنَى بِامْرَأَتِهِ فَافْتَدَيْتُ مِنْهُ بِمِائَةِ شَاةٍ وَخَادِمٍ وَإِنِّي سَأَلْتُ رِجَالًا مِنْ أَهْلِ الْعِلْمِ فَأَخْبَرُونِي أَنَّ عَلَى ابْنِي جَلْدَ مِائَةٍ وَتَغْرِيبَ عَامٍ وَأَنَّ عَلَى امْرَأَةِ هَذَا الرَّجْمَ فَقَالَ وَالَّذِي نَفْسِي بِيَدِهِ لَأَقْضِيَنَّ بَيْنَكُمَا بِكِتَابِ اللَّهِ الْمِائَةُ وَالْخَادِمُ رَدٌّ عَلَيْكَ وَعَلَى ابْنِكَ جَلْدُ مِائَةٍ وَتَغْرِيبُ عَامٍ وَيَا أُنَيْسُ اغْدُ عَلَى امْرَأَةِ هَذَا فَسَلْهَا فَإِنْ اعْتَرَفَتْ فَارْجُمْهَا فَاعْتَرَفَتْ فَرَجَمَهَا","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Ibnu Uyainah] dari [Az Zuhri] dari [Ubaidullah bin Abdullah bin Utbah] dari [Abu Hurairah] dan [Zaid bin Khalid Al Juhani] mengatakan, Seorang laki-laki mendatangi Nabi shallallahu 'alaihi wasallam dan berujar; 'Saya bersumpah kepadamu dengan nama Allah, hendaknya engkau memutuskan diantara kami dengan kitabullah.' Lantas lawan sengketanya yang lebih faqih darinya berdiri dan berkata; 'Ia benar, putuskanlah diantara kami dengan kitabullah, dan perkenankan saya ya Rasulullah untuk bicara! ' Nabi menjawab; \"Silahkan bicara\". Ia meneruskan; 'anak saya menjadi pekerja orang ini, kemudian dia berzina dengan isterinya, maka aku menebusnya dengan seratus ekor kambing dan satu pelayan. Aku kemudian bertanya kepada beberapa orang ahlul ilmu dan mereka memberitahukan kepadaku bahwa anakku didera seratus kali dan diasingkan selama setahun dan wanita ini dirajam.' Lantas Nabi bersabda: \"Demi Dzat yang jiwaku berada di tangan-NYA, sungguh aku akan putuskan diantara kalian berdua, seratus ekor kambing dan pelayan dikembalikan kepadamu, kemudian anakmu didera seratus kali dan diasingkan selama setahun, dan engkau hai Unais Al Aslami, temuilah si wanita dan tanyailah, jika ia mengakui maka rajamlah!\" Si Wanita akhirnya mengaku dan dia merajamnya."},"6020":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ عَمْرِو بْنِ شُرَحْبِيلَ قَالَ قَالَ عَبْدُ اللَّهِقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ أَيُّ الذَّنْبِ أَكْبَرُ عِنْدَ اللَّهِ قَالَ أَنْ تَدْعُوَ لِلَّهِ نِدًّا وَهُوَ خَلَقَكَ قَالَ ثُمَّ أَيٌّ قَالَ ثُمَّ أَنْ تَقْتُلَ وَلَدَكَ خَشْيَةَ أَنْ يَطْعَمَ مَعَكَ قَالَ ثُمَّ أَيٌّ قَالَ ثُمَّ أَنْ تُزَانِيَ بِحَلِيلَةِ جَارِكَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ تَصْدِيقَهَا{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ وَلَا يَقْتُلُونَ النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ وَلَا يَزْنُونَ وَمَنْ يَفْعَلْ ذَلِكَ يَلْقَ أَثَامًا }الْآيَةَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Wa`il] dari ['Amru bin Syurahbil] mengatakan, [Abdullah] Mengatakan; Seorang laki-laki bertanya; 'Ya Rasulullah, dosa apa yang paling besar disisi Allah? ' Nabi menjawab: \"Kamu jadikan tandingan bagi Allah padahal Dia yang menciptamu.\" 'selanjutnya apa? ' lanjutnya. Jawab Nabi; \"Kau membunuh anakmu karena kuatir ia makan bersamamu.\" 'kemudian apa lagi? ' Lanjutnya. Nabi menjawab: \"kamu berzina dengan istri tetanggamu.\" Allah menurunkan ayat yang membenarkan masalah ini: 'Dan orang-orang yang tidak menyeru kepada tuhan lain selain menyembah Allah, dan tidak membunuh jiwa yang Allah haramkan selain karena alasan yang benar, tidak berzina, dan barangsiapa melakukannya ia akan memperoleh dosa' (Al Furqan 68)."},"6021":{"ar":"حَدَّثَنَا عَلِيٌّ حَدَّثَنَا إِسْحَاقُ بْنُ سَعِيدِ بْنِ عَمْرِو بْنِ سَعِيدِ بْنِ الْعَاصِ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَنْ يَزَالَ الْمُؤْمِنُ فِي فُسْحَةٍ مِنْ دِينِهِ مَا لَمْ يُصِبْ دَمًا حَرَامًا","id":"Telah menceritakan kepada kami [Ali] telah menceritakan kepada kami [Ishaq bin Sa'id bin Amru bin 'Ash] dari [Ayahnya] dari [Ibnu 'Umar] radliallahu 'anhuma mengatakan, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang mukmin masih dalam kelonggaran agamanya selama dia tidak menumpahkan darah haram tanpa alasan yang dihalalkan.\""},"6022":{"ar":"حَدَّثَنِي أَحْمَدُ بْنُ يَعْقُوبَ حَدَّثَنَا إِسْحَاقُ بْنُ سَعِيدٍ سَمِعْتُ أَبِي يُحَدِّثُ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَإِنَّ مِنْ وَرَطَاتِ الْأُمُورِ الَّتِي لَا مَخْرَجَ لِمَنْ أَوْقَعَ نَفْسَهُ فِيهَا سَفْكَ الدَّمِ الْحَرَامِ بِغَيْرِ حِلِّهِ","id":"Telah menceritakan kepadaku [Ahmad bin Ya'qub] telah menceritakan kepada kami [Ishaq bin Sa'id] aku mendengar [Ayahku] menceritakan dari [Abdullah bin Umar] mengatakan; 'diantara masalah membahayakan yang jika seseorang terlanjur melakukannya, jarang sekali bisa menyelamatkan diri adalah menumpahkan darah haram tanpa alasan yang dihalalkan.'"},"6023":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوَّلُ مَا يُقْضَى بَيْنَ النَّاسِ فِي الدِّمَاءِ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Musa] dari [Al A'masy] dari [Abu Wa`il] dari [Abdullah] mengatakan; 'Nabi Shallallahu'alaihi wasallam bersabda: \"Masalah pertama yang diputuskan hari kiamat adalah masalah darah.\""},"6024":{"ar":"حَدَّثَنَا عَبْدَانُ حَدَّثَنَا عَبْدُ اللَّهِ حَدَّثَنَا يُونُسُ عَنْ الزُّهْرِيِّ حَدَّثَنَا عَطَاءُ بْنُ يَزِيدَ أَنَّ عُبَيْدَ اللَّهِ بْنَ عَدِيٍّ حَدَّثَهُ أَنَّ الْمِقْدَادَ بْنَ عَمْرٍو الْكِنْدِيَّحَلِيفَ بَنِي زُهْرَةَ حَدَّثَهُ وَكَانَ شَهِدَ بَدْرًا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ يَا رَسُولَ اللَّهِ إِنِّي لَقِيتُ كَافِرًا فَاقْتَتَلْنَا فَضَرَبَ يَدِي بِالسَّيْفِ فَقَطَعَهَا ثُمَّ لَاذَ مِنِّي بِشَجَرَةٍ وَقَالَ أَسْلَمْتُ لِلَّهِ آقْتُلُهُ بَعْدَ أَنْ قَالَهَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقْتُلْهُ قَالَ يَا رَسُولَ اللَّهِ فَإِنَّهُ طَرَحَ إِحْدَى يَدَيَّ ثُمَّ قَالَ ذَلِكَ بَعْدَ مَا قَطَعَهَا آقْتُلُهُ قَالَ لَا تَقْتُلْهُ فَإِنْ قَتَلْتَهُ فَإِنَّهُ بِمَنْزِلَتِكَ قَبْلَ أَنْ تَقْتُلَهُ وَأَنْتَ بِمَنْزِلَتِهِ قَبْلَ أَنْ يَقُولَ كَلِمَتَهُ الَّتِي قَالَوَقَالَ حَبِيبُ بْنُ أَبِي عَمْرَةَ عَنْ سَعِيدٍ عَنْ ابْنِ عَبَّاسٍ قَالَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْمِقْدَادِ إِذَا كَانَ رَجُلٌ مُؤْمِنٌ يُخْفِي إِيمَانَهُ مَعَ قَوْمٍ كُفَّارٍ فَأَظْهَرَ إِيمَانَهُ فَقَتَلْتَهُ فَكَذَلِكَ كُنْتَ أَنْتَ تُخْفِي إِيمَانَكَ بِمَكَّةَ مِنْ قَبْلُ","id":"Telah menceritakan kepada kami ['Abdan] telah menceritakan kepada kami ['Abdullah] telah menceritakan kepada kami [Yunus] dari [Az Zuhri] telah menceritakan kepada kami ['Atho' bin Yazid], bahwasanya [Ubaidullah bin Adi] menceritakan kepadanya, [Al Miqdad bin 'Amru Al Kindi] sekutu bani Zuhrah menceritakan kepadanya -ia termasuk orang yang ikut perang badar bersama Nabi shallallahu 'alaihi wasallam - ia berkata; 'ya Rasulullah, saya menjumpai orang kafir, kemudian terjadi duel antara kami. Ia berhasil menyabet tanganku dengan pedang sehingga tanganku putus. Ia kemudian bersembunyi dariku di sebuah pohon dan mengatakan; 'Saya telah masuk Islam karena Allah', bolehkah saya membunuhnya setelah ia mengucapkan kalimah laa-ilaaha-illallah? ' Rasulullah Shallallahu'alaihiwasallam menjawab: \"kamu tidak boleh membunuhnya.\" Miqdad melanjutkan; 'ya Rasulullah, ia telah menghilangkan salah satu tanganku, kemudian ia mengucapkan kalimat itu setelah memutuskannya, bolehkah saya membunuhnya? ' Nabi menjawab; \"kamu tidak boleh membunuhnya, jika kamu tetap membunuhnya berarti dia berada di posisimu ketika kamu belum membunuhnya, sedang kamu berada diposisi dia ketika sebelum ia mengucapkannya.\" Sedang Habib bin Abi 'Amrah mengatakan; dari Sa'id dari Ibn 'Abbas mengatakan, Nabi shallallahu 'alaihi wasallam berkata kepada Miqdad: \"Jika seorang mukmin menyembunyikan keimanannya bersama komunitas orang kafir selanjutnya ia menyatakan terus terang keimanannya, dan engkau kemudian membunuhnya, kamu dahulu juga seperti itu, dahulu kamu menyembunyikan keimananmu di Makkah.\""},"6025":{"ar":"حَدَّثَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُقْتَلُ نَفْسٌ إِلَّا كَانَ عَلَى ابْنِ آدَمَ الْأَوَّلِ كِفْلٌ مِنْهَا","id":"Telah menceritakan kepada kami [Qabishah] telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari ['Abdullah bin Murrah] dari [Masruq] dari [Abdullah] radliallahu 'anhu, dari Nabi Shallallahu'alaihi wasallam bersabda: \"Tidaklah seseorang membunuh, melainkan anak Adam pertama (Qabil) turut menanggung dosanya.\""},"6026":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ قَالَ وَاقِدُ بْنُ عَبْدِ اللَّهِ أَخْبَرَنِي عَنْ أَبِيهِ سَمِعَ عَبْدَ اللَّهِ بْنَ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَرْجِعُوا بَعْدِي كُفَّارًا يَضْرِبُ بَعْضُكُمْ رِقَابَ بَعْضٍ","id":"Telah menceritakan kepada kami [Abul Walid] telah menceritakan kepada kami [Syu'bah] dengan mengatakan; telah mengabarkan kepadaku [Waqid bin Abdullah] dari [ayahnya], ia mendengar [Abdullah bin Umar] dari Nabi Shallallahu'alaihi Wasallam, beliau bersabda: \"Janganlah kalian kembali kafir sepeninggalkau, sebagian kalian memenggal sebagian lainnya.\""},"6027":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ عَلِيِّ بْنِ مُدْرِكٍ قَالَ سَمِعْتُ أَبَا زُرْعَةَ بْنَ عَمْرِو بْنِ جَرِيرٍ عَنْ جَرِيرٍ قَالَقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ اسْتَنْصِتْ النَّاسَ لَا تَرْجِعُوا بَعْدِي كُفَّارًا يَضْرِبُ بَعْضُكُمْ رِقَابَ بَعْضٍرَوَاهُ أَبُو بَكْرَةَ وَابْنُ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] Telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Ali bin Mudrik] katanya, aku mendengar [Abu Zur'ah bin Amru bin Jarir] dari [Jarir] katanya, Nabi Shallallahu'alaihiwasallam pernah berujar kepadaku ketika haji wada'; \"Tolong suruhlah orang-orang diam, jangan kalian sepeninggalku menjadi kafir, sebagian kalian memenggal leher sebagian lain.\" Juga diriwayatkan Abu Bakrah dan Ibnu Abbas dari Nabi Shallallahu'alaihiwasallam."},"6028":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ فِرَاسٍ عَنْ الشَّعْبِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْكَبَائِرُ الْإِشْرَاكُ بِاللَّهِ وَعُقُوقُ الْوَالِدَيْنِ أَوْ قَالَ الْيَمِينُ الْغَمُوسُشَكَّ شُعْبَةُ وَقَالَ مُعَاذٌ حَدَّثَنَا شُعْبَةُ قَالَ الْكَبَائِرُ الْإِشْرَاكُ بِاللَّهِ وَالْيَمِينُ الْغَمُوسُ وَعُقُوقُ الْوَالِدَيْنِ أَوْ قَالَ وَقَتْلُ النَّفْسِ","id":"Telah menceritakan kepadaku [Muhammad bin Basysyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Firas] dari [Asy Sya'bi] dari [Abdullah bin Amru] dari Nabi shallallahu 'alaihi wasallam bersabda; \"Diantara dosa besar adalah, menyekutukan Allah, durhaka kepada orang tua, -atau ia mengatakan - sumpah dusta.\" Syu'bah ragu kepastian redaksinya. Dan [Mu'adz] mengatakan telah menceritakan kepada kami [Syu'bah] mengatakan; Dosa besar ialah menyekutukan Allah, sumpah dusta, dan durhaka kepada orang tua. Atau ia mengatakan; dan membunuh orang."},"6029":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ مَنْصُورٍ حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ أَبِي بَكْرٍ سَمِعَ أَنَسَ بْنَ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْكَبَائِرُ ح و حَدَّثَنَا عَمْرٌو وَهُوَ ابْنُ مَرْزُوقٍ حَدَّثَنَا شُعْبَةُ عَنْ ابْنِ أَبِي بَكْرٍ عَنْ أَنَسِ بْنِ مَالِكٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَكْبَرُ الْكَبَائِرِ الْإِشْرَاكُ بِاللَّهِ وَقَتْلُ النَّفْسِ وَعُقُوقُ الْوَالِدَيْنِ وَقَوْلُ الزُّورِ أَوْ قَالَ وَشَهَادَةُ الزُّورِ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] telah menceritakan kepada kami ['Abdushshamad] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami ['Ubaidullah bin Abi Bakr] ia mendengar [Anas bin Malik] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam bersabda: \"dosa-dosa besar yaitu\" -lewat jalur periwayatan lain-Telah menceritakan kepada kami ['Amru] tepatnya Amru bin Marzuq, telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Ibnu Abi Bakar], dari [Anas bin Malik] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam bersabda; \"Dosa paling besar diantara dosa besar ialah menyekutukan Allah, membunuh, durhaka kepada orang tua, ucapan dusta, \" atau beliau mengatakan; \"persaksian dusta.\""},"6030":{"ar":"حَدَّثَنَا عَمْرُو بْنُ زُرَارَةَ حَدَّثَنَا هُشَيْمٌ حَدَّثَنَا حُصَيْنٌ حَدَّثَنَا أَبُو ظَبْيَانَ قَالَ سَمِعْتُ أُسَامَةَ بْنَ زَيْدِ بْنِ حَارِثَةَ رَضِيَ اللَّهُ عَنْهُمَا يُحَدِّثُ قَالَبَعَثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْحُرَقَةِ مِنْ جُهَيْنَةَ قَالَ فَصَبَّحْنَا الْقَوْمَ فَهَزَمْنَاهُمْ قَالَ وَلَحِقْتُ أَنَا وَرَجُلٌ مِنْ الْأَنْصَارِ رَجُلًا مِنْهُمْ قَالَ فَلَمَّا غَشِينَاهُ قَالَ لَا إِلَهَ إِلَّا اللَّهُ قَالَ فَكَفَّ عَنْهُ الْأَنْصَارِيُّ فَطَعَنْتُهُ بِرُمْحِي حَتَّى قَتَلْتُهُ قَالَ فَلَمَّا قَدِمْنَا بَلَغَ ذَلِكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَقَالَ لِي يَا أُسَامَةُ أَقَتَلْتَهُ بَعْدَ مَا قَالَ لَا إِلَهَ إِلَّا اللَّهُ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ إِنَّمَا كَانَ مُتَعَوِّذًا قَالَ أَقَتَلْتَهُ بَعْدَ مَا قَالَ لَا إِلَهَ إِلَّا اللَّهُ قَالَ فَمَا زَالَ يُكَرِّرُهَا عَلَيَّ حَتَّى تَمَنَّيْتُ أَنِّي لَمْ أَكُنْ أَسْلَمْتُ قَبْلَ ذَلِكَ الْيَوْمِ","id":"Telah menceritakan kepada kami ['Amru bin Zurarah] telah menceritakan kepada kami [Husyaim] telah menceritakan kepada kami [Hushain] telah menceritakan kepada kami [Abu Dhibyan] mengatakan, aku mendengar [Usamah bin Zaid bin haritsah] radliallahu 'anhuma menceritakan dengan mengatakan; 'Rasulullah Shallallahu'alaihiwasallam mengutus kami ke perkampungan Hurqah di bani Juhainah. Kami menyerang mereka di pagi buta dan menjadikan mereka kocar kacir. Saya dan seorang laki-laki anshar berhasil menemukan seseorang dari mereka. Tatkala kami bisa mengepung, ia tiba-tiba mengatakan; 'laa-ilaaha-illallah.' Si laki-laki anshar menahan penyerbuannya, sedang aku meneruskannya hingga kubunuh orang itu. Ketika kami pulang, peristiwa ini disampaikan kepada Nabi shallallahu 'alaihi wasallam sehingga beliau berujar kepadaku: \"Apakah kamu membunuhnya setelah ia mengucapkan laa-ilaaha-illallah?\" Kujawab; 'betul, Ya Rasulullah, ia mengucapkannya hanya sekedar mencari keselamatan.' Nabi melanjutkan: \"Apakah kamu membunuhnya setelah ia mengucapkan laa-ilaaha-illallah?\" Nabi berulangkali menegurku dengan ucapan ini hingga aku mengandai-andai kalaulah aku belum masuk Islam sebelum itu."},"6031":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا اللَّيْثُ حَدَّثَنَا يَزِيدُ عَنْ أَبِي الْخَيْرِ عَنْ الصُّنَابِحِيِّ عَنْ عُبَادَةَ بْنِ الصَّامِتِ رَضِيَ اللَّهُ عَنْهُ قَالَإِنِّي مِنْ النُّقَبَاءِ الَّذِينَ بَايَعُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَايَعْنَاهُ عَلَى أَنْ لَا نُشْرِكَ بِاللَّهِ شَيْئًا وَلَا نَسْرِقَ وَلَا نَزْنِيَ وَلَا نَقْتُلَ النَّفْسَ الَّتِي حَرَّمَ اللَّهُ وَلَا نَنْتَهِبَ وَلَا نَعْصِيَ بِالْجَنَّةِ إِنْ فَعَلْنَا ذَلِكَ فَإِنْ غَشِينَا مِنْ ذَلِكَ شَيْئًا كَانَ قَضَاءُ ذَلِكَ إِلَى اللَّهِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah menceritakan kepada kami [Al Laits] telah menceritakan kepada kami [Yazid] dari [Abul khair] dari [Ash Shunabihi] dari ['Ubadah bin Ash Shamit] radliallahu 'anhu mengatakan; \"Saya diantara pemuka masyarakat yang berbait kepada Rasulullah Shallallahu'alaihiwasallam, kami berbaiat kepadanya untuk tidak menyekutukan Allah dengan sesuatu apapun, tidak mencuri, tidak berzina, dan tidak membunuh jiwa yang Allah haramkan, tidak merampok, kami memperoleh surga jika melakukan janji setia ini, namun jika melanggar satu perkara itu, keputusannya terserah Allah.\""},"6032":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا جُوَيْرِيَةُ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ حَمَلَ عَلَيْنَا السِّلَاحَ فَلَيْسَ مِنَّارَوَاهُ أَبُو مُوسَى عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Musa bin Ismail] telah menceritakan kepada kami [Juwairiyah] dari [Nafi'] dari [Abdullah bin Umar] radliallahu 'anhuma dari Nabi shallallahu 'alaihi wasallam bersabda; \"Barangsiapa yang menghunuskan kepada kami, maka bukan golongan kami.\" Abu Musa meriwayatkannya dari Nabi shallallahu 'alaihi wasallam."},"6033":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ الْمُبَارَكِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا أَيُّوبُ وَيُونُسُ عَنْ الْحَسَنِ عَنْ الْأَحْنَفِ بْنِ قَيْسٍ قَالَذَهَبْتُ لِأَنْصُرَ هَذَا الرَّجُلَ فَلَقِيَنِي أَبُو بَكْرَةَ فَقَالَ أَيْنَ تُرِيدُ قُلْتُ أَنْصُرُ هَذَا الرَّجُلَ قَالَ ارْجِعْ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا الْتَقَى الْمُسْلِمَانِ بِسَيْفَيْهِمَا فَالْقَاتِلُ وَالْمَقْتُولُ فِي النَّارِ قُلْتُ يَا رَسُولَ اللَّهِ هَذَا الْقَاتِلُ فَمَا بَالُ الْمَقْتُولِ قَالَ إِنَّهُ كَانَ حَرِيصًا عَلَى قَتْلِ صَاحِبِهِ","id":"Telah menceritakan kepada kami ['Abdurrahman bin Mubarak] telah menceritakan kepada kami [Hammad bin Zaid] telah menceritakan kepada kami [Ayyub] dan [Yunus] dari [Al Hasan] dari [Al Ahnaf bin Qais] mengatakan; 'aku berangkat untuk membantu lelaki ini, (di tengah perjalanan) [Abu Bakrah] memergokiku dan bertanya; 'mau kemana kau? ' Saya menjawab; 'untuk menolong orang ini.' Abu Bakrah berkata; Pulang saja kamu. Sebab aku mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Jika dua orang muslim bertemu dengan menghunuskan pedangnya, maka si pembunuh dan yang dibunuh sama-sama di neraka.\" Saya bertanya; 'Ya Rasulullah, saya maklum terhadap si pembunuh, lantas apa dosa yang dibunuh? ' Nabi menjawab: \"sesungguhnya dia juga berkeinginan keras membunuh kawannya.\""},"6034":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَنَّ يَهُودِيًّا رَضَّ رَأْسَ جَارِيَةٍ بَيْنَ حَجَرَيْنِ فَقِيلَ لَهَا مَنْ فَعَلَ بِكِ هَذَا أَفُلَانٌ أَوْ فُلَانٌ حَتَّى سُمِّيَ الْيَهُودِيُّ فَأُتِيَ بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يَزَلْ بِهِ حَتَّى أَقَرَّ بِهِ فَرُضَّ رَأْسُهُ بِالْحِجَارَةِ","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Anas bin Malik] radliallahu 'anhu, ada seorang yahudi menumbuk kepala seorang budak perempuan dengan dua batu. Maka budak perempuan tersebut ditanya; 'sebutkan siapa yang mencederaimu, apakah yang melakukannya fulan, fulan? ' hingga disebut nama seorang yahudi.' Maka orang yahudi itu lantas dihadapkan ke Nabi shallallahu 'alaihi wasallam. Nabi tiada henti menginterogasinya hingga ia mengakui, kemudian Nabi mengqisasnya dengan meretakkan kepalanya dengan batu."},"6035":{"ar":"حَدَّثَنَا مُحَمَّدٌ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ شُعْبَةَ عَنْ هِشَامِ بْنِ زَيْدِ بْنِ أَنَسٍ عَنْ جَدِّهِ أَنَسِ بْنِ مَالِكٍ قَالَخَرَجَتْ جَارِيَةٌ عَلَيْهَا أَوْضَاحٌ بِالْمَدِينَةِ قَالَ فَرَمَاهَا يَهُودِيٌّ بِحَجَرٍ قَالَ فَجِيءَ بِهَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبِهَا رَمَقٌ فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فُلَانٌ قَتَلَكِ فَرَفَعَتْ رَأْسَهَا فَأَعَادَ عَلَيْهَا قَالَ فُلَانٌ قَتَلَكِ فَرَفَعَتْ رَأْسَهَا فَقَالَ لَهَا فِي الثَّالِثَةِ فُلَانٌ قَتَلَكِ فَخَفَضَتْ رَأْسَهَا فَدَعَا بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَتَلَهُ بَيْنَ الْحَجَرَيْنِ","id":"Telah menceritakan kepada kami [Muhammad] telah mengabarkan kepada kami [Abdullah bin Idris] dari [Syu'bah] dari [Hisyam bin Zaid bin Anas] dari [kakeknya, anas bin Malik] mengatakan, seorang hamba sahaya Madinah keluar dengan menggunakan anting-anting, lantas seorang laki-laki yahudi melemparnya dengan batu. Si yahudi lantas diringkus dan diseret ke hadapan Nabi shallallahu 'alaihi wasallam yang ketika itu si hamba sahaya tinggal menyisakan sisa-sisa nyawanya. Rasulullah Shallallahu'alaihiwasallam bertanya; 'Apakah fulan yang membunuhmu? ' Si hamba sahaya menjawab; 'tidak' dengan menggelengkan kepalanya. Nabi kembali menanyainya; 'Apakah fulan yang membunuhmu? ' Kembali ia menjawab; 'tidak' dengan menggelengkan kepalanya. Untuk kali ketiganya Nabi bertanya; 'Apakah yang membunuhmu fula? ' Si hamba sahaya mengiyakan dengan menundukkan kepalanya. Nabi terus meminta si yahudi didatangkan, dan beliau membunuhnya dengan menjepitnya diantara dua batu."},"6036":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَحِلُّ دَمُ امْرِئٍ مُسْلِمٍ يَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنِّي رَسُولُ اللَّهِ إِلَّا بِإِحْدَى ثَلَاثٍ النَّفْسُ بِالنَّفْسِ وَالثَّيِّبُ الزَّانِي وَالْمَارِقُ مِنْ الدِّينِ التَّارِكُ لِلْجَمَاعَةِ","id":"Telah menceritakan kepada kami [Umar bin Hafsh], telah menceritakan kepada kami [bapakku], telah menceritakan kepada kami [Al A'masy], dari ['Abdullah bin Murrah] dari [Masruq] dari [Abdullah] mengatakan Rasulullah shallallahu 'alaihi wasallam bersabda: \"darah seorang muslim yang telah bersyahadat laa-ilaaha-illallah dan mengakui bahwa aku utusan Allah terlarang ditumpahkan selain karena alasan diantara tiga; membunuh, berzina dan dia telah menikah, dan meninggalkan agama, meninggalkan jamaah muslimin.\""},"6037":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ هِشَامِ بْنِ زَيْدٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُأَنَّ يَهُودِيًّا قَتَلَ جَارِيَةً عَلَى أَوْضَاحٍ لَهَا فَقَتَلَهَا بِحَجَرٍ فَجِيءَ بِهَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبِهَا رَمَقٌ فَقَالَ أَقَتَلَكِ فُلَانٌ فَأَشَارَتْ بِرَأْسِهَا أَنْ لَا ثُمَّ قَالَ الثَّانِيَةَ فَأَشَارَتْ بِرَأْسِهَا أَنْ لَا ثُمَّ سَأَلَهَا الثَّالِثَةَ فَأَشَارَتْ بِرَأْسِهَا أَنْ نَعَمْ فَقَتَلَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِحَجَرَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Hisyam bin Zaid] dari [Anas] radliallahu 'anhu, seorang laki-laki yahudi membunuh hamba sahaya karena ingin merampas anting-antingnya. Ia membunuhnya dengan batu. Si hamba sahaya dibawa ke hadapan Nabi shallallahu 'alaihi wasallam dengan sisa-sisa nyawanya. Nabi bertanya; \"Apakah yang membunuhmu fulan?\" Ia menjawab tidak dengan mengisyaratkan kepalanya. Nabi mengulang pertanyaannya: \"Apakah yang membunuhmu fulan?\" Ia menjawab tidak dengan mengisyaratkan kepalanya. Nabi bertanya lagi untuk kali ketiganya: \"Apakah yang membunuhmu fulan?\" ia menjawab 'iya.' Maka Nabi membunuh si yahudi dengan menjepitnya diantara dua batu."},"6038":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ أَنَّ خُزَاعَةَ قَتَلُوا رَجُلًا وَقَالَ عَبْدُ اللَّهِ بْنُ رَجَاءٍ حَدَّثَنَا حَرْبٌ عَنْ يَحْيَى حَدَّثَنَا أَبُو سَلَمَةَ حَدَّثَنَا أَبُو هُرَيْرَةَأَنَّهُ عَامَ فَتْحِ مَكَّةَ قَتَلَتْ خُزَاعَةُ رَجُلًا مِنْ بَنِي لَيْثٍ بِقَتِيلٍ لَهُمْ فِي الْجَاهِلِيَّةِ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ اللَّهَ حَبَسَ عَنْ مَكَّةَ الْفِيلَ وَسَلَّطَ عَلَيْهِمْ رَسُولَهُ وَالْمُؤْمِنِينَ أَلَا وَإِنَّهَا لَمْ تَحِلَّ لِأَحَدٍ قَبْلِي وَلَا تَحِلُّ لِأَحَدٍ بَعْدِي أَلَا وَإِنَّمَا أُحِلَّتْ لِي سَاعَةً مِنْ نَهَارٍ أَلَا وَإِنَّهَا سَاعَتِي هَذِهِ حَرَامٌ لَا يُخْتَلَى شَوْكُهَا وَلَا يُعْضَدُ شَجَرُهَا وَلَا يَلْتَقِطُ سَاقِطَتَهَا إِلَّا مُنْشِدٌ وَمَنْ قُتِلَ لَهُ قَتِيلٌ فَهُوَ بِخَيْرِ النَّظَرَيْنِ إِمَّا يُودَى وَإِمَّا يُقَادُ فَقَامَ رَجُلٌ مِنْ أَهْلِ الْيَمَنِ يُقَالُ لَهُ أَبُو شَاهٍ فَقَالَ اكْتُبْ لِي يَا رَسُولَ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اكْتُبُوا لِأَبِي شَاهٍ ثُمَّ قَامَ رَجُلٌ مِنْ قُرَيْشٍ فَقَالَ يَا رَسُولَ اللَّهِ إِلَّا الْإِذْخِرَ فَإِنَّمَا نَجْعَلُهُ فِي بُيُوتِنَا وَقُبُورِنَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا الْإِذْخِرَوَتَابَعَهُ عُبَيْدُ اللَّهِ عَنْ شَيْبَانَ فِي الْفِيلِ قَالَ بَعْضُهُمْ عَنْ أَبِي نُعَيْمٍ الْقَتْلَ وَقَالَ عُبَيْدُ اللَّهِ إِمَّا أَنْ يُقَادَ أَهْلُ الْقَتِيلِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Syaiban] dari [Yahya] dari [Abu Salamah] dari [Abu Hurairah]; bani Khuza'ah membunuh seorang laki-laki. Sedang [Abdullah bin Raja'] mengatakan; telah menceritakan kepada kami [Harb] dari [Yahya] telah menceritakan kepada kami [Abu Salamah] telah menceritakan kepada kami [Abu Hurairah]; ketika tahun pembebasan Makkah bani Khuza'ah membunuh seorang laki-laki dari bani Laits sebagai pembalasan mereka yang dibunuh semasa masih jahiliyah. Serta merta Rasulullah Shallallahu'alaihiwasallam berdiri dan menyampaikan pidato; \"Allah telah menahan pasukan gajah dari Makkah ini, dan menguasakan rasul-NYA dan orang-orang mukmin untuk mengalahkan mereka, ketahuilah, bahwasanya Makkah tidak dihalalkan bagi siapa pun baik sebelum maupun sesudahku, hanyasanya dihalalkan bagiku beberapa saat siang saja, Ketahuilah, bahwasanya Makkah pada saatku sekarang ini telah haram, durinya tidak boleh dipatahkan dan pohonnya tidak boleh ditebang, barang temuannya tidak boleh diambil kecuali orang yang hendak mengumumkannya, dan barangsiapa menjadi wali korban pembunuhan, baginya dua pilihan, ia diberi diyat atau diberi kesempatan untuk membalas qisas.\" Lantas berdirilah seorang laki-laki penduduk yaman yang dikenal dengan nama Abu Syah dan mengatakan; 'Tuliskan untukku Ya Rasulullah! ' Rasulullah Shallallahu'alaihiwasallam mengatakan; \"tuliskanlah untuk Abu Syah.\" Kemudian ada laki-laki dari Qurasy berdiri dan mengatakan; 'Ya Rasulullah, selain idzkhir, sebab rumput idzkhir sering kami manfaatkan untuk kuburan dan rumah kami.' Rasulullah Shallallahu'alaihiwasallam menjawab; \"kecuali idzkhir.\" hadits ini diperkuat oleh ['Ubaidullah] dari [Syaiban] tentang gajah, dan sebagian mereka dari [Abu Nu'aim] mengatakan dengan redaksi baginya kesempatan membunuh balasan. Sedang Ubaidullah mengatakan dengan redaksi atau keluarga terbunuh diberi diyat."},"6039":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَتْ فِي بَنِي إِسْرَائِيلَ قِصَاصٌ وَلَمْ تَكُنْ فِيهِمْ الدِّيَةُ فَقَالَ اللَّهُ لِهَذِهِ الْأُمَّةِ{ كُتِبَ عَلَيْكُمْ الْقِصَاصُ فِي الْقَتْلَى }إِلَى هَذِهِ الْآيَةِ{ فَمَنْ عُفِيَ لَهُ مِنْ أَخِيهِ شَيْءٌ }قَالَ ابْنُ عَبَّاسٍ فَالْعَفْوُ أَنْ يَقْبَلَ الدِّيَةَ فِي الْعَمْدِ قَالَ{ فَاتِّبَاعٌ بِالْمَعْرُوفِ }أَنْ يَطْلُبَ بِمَعْرُوفٍ وَيُؤَدِّيَ بِإِحْسَانٍ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Sufyan] dari ['Amru] dari [Mujahid] dari [Ibnu 'Abbas] radliallahu 'anhuma mengatakan; 'Di kalangan bani israil hanya berlaku hukum qisas dan tidak ada hukum tebusan (diyat), sehingga Allah menurunkan ayat ini 'Diwajibkan atas kalian qisas dalam pembunuhan (QS. ALbaqarah 178) Hingga ayat ini; kecuali jika ia mendapat pemaafan dari saudara (QS. Albaqarah 178), kata Ibn Abbas; istilah maaf maksudnya menerima diyat secara tulus. Dan Ibnu Abbas berkata perihal kutipan ayat; 'fattibaa'un bil ma'ruuf (Maka hendaklah ia mengikutinya dengan baik), ' maksudnya hendaklah betu-betul meminta maaf dan melakukannya dengan sebaik-baiknya."},"6040":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي حُسَيْنٍ حَدَّثَنَا نَافِعُ بْنُ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبْغَضُ النَّاسِ إِلَى اللَّهِ ثَلَاثَةٌ مُلْحِدٌ فِي الْحَرَمِ وَمُبْتَغٍ فِي الْإِسْلَامِ سُنَّةَ الْجَاهِلِيَّةِ وَمُطَّلِبُ دَمِ امْرِئٍ بِغَيْرِ حَقٍّ لِيُهَرِيقَ دَمَهُ","id":"Telah menceritakan kepada kami [Abul Yaman] Telah mengabarkan kepada kami [Syu'aib] dari ['Abdullah bin Abu Husain] telah menceritakan kepada kami [Nafi' bin Jubair] dari [Ibnu Abbas], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Manusia yang paling dimurkai Allah ada tiga, Orang yang melakukan pelanggaran di tanah haram, orang yang mencari-cari perilaku jahiliyah padahal telah masuk Islam, dan memburu darah seseorang tanpa alasan yang dibenarkan untuk menumpahkan darahnya.\""},"6041":{"ar":"حَدَّثَنَا فَرْوَةُ بْنُ أَبِي الْمَغْرَاءِ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ هُزِمَ الْمُشْرِكُونَ يَوْمَ أُحُدٍ ح و حَدَّثَنِي مُحَمَّدُ بْنُ حَرْبٍ حَدَّثَنَا أَبُو مَرْوَانَ يَحْيَى بْنُ أَبِي زَكَرِيَّاءَ يَعْنِي الْوَاسِطِيَّ عَنْ هِشَامٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْصَرَخَ إِبْلِيسُ يَوْمَ أُحُدٍ فِي النَّاسِ يَا عِبَادَ اللَّهِ أُخْرَاكُمْ فَرَجَعَتْ أُولَاهُمْ عَلَى أُخْرَاهُمْ حَتَّى قَتَلُوا الْيَمَانِ فَقَالَ حُذَيْفَةُ أَبِي أَبِي فَقَتَلُوهُ فَقَالَ حُذَيْفَةُ غَفَرَ اللَّهُ لَكُمْ قَالَ وَقَدْ كَانَ انْهَزَمَ مِنْهُمْ قَوْمٌ حَتَّى لَحِقُوا بِالطَّائِفِ","id":"Telah menceritakan kepada kami [Farwah bin Abil Maghra'] telah menceritakan kepada kami ['Ali bin Mushir] dari [Hisyam] dari [Ayahnya] dari [Aisyah]; kaum musyrikin lari tunggang langgang dalam perang Uhud -lewat jalur periwayatan lain-- telah menceritakan kepadaku [Muhammad bin harb] telah menceritakan kepada kami [Abu marwan Yahya bin Abi Zakariya alias Al Wasthi] dari [Hisyam] dari ['Urwah] dari [Aisyah] radliallahu 'anhuma mengatakan; Pada hari Uhud Iblis berteriak ditengah-tengah pasukan musuh seraya mengatakan; 'wahai hanba-hamba Allah, awas barisan belakang kalian, ' sehingga pasukan depan berbalik ke belakang sehingga mereka membunuh Al Yaman, dan Khudzaifah berteriak-teriak; 'itu ayahku, itu ayahku! ' lantas Khudzaifah mengatakan; 'Kiranya Allah mengampuni kalian.' kaum musyrikin lari tunggang langgang hingga diantara mereka ada yang lari ke Thaif."},"6042":{"ar":"حَدَّثَنِي إِسْحَاقُ أَخْبَرَنَا حَبَّانُ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍأَنَّ يَهُودِيًّا رَضَّ رَأْسَ جَارِيَةٍ بَيْنَ حَجَرَيْنِ فَقِيلَ لَهَا مَنْ فَعَلَ بِكِ هَذَا أَفُلَانٌ أَفُلَانٌ حَتَّى سُمِّيَ الْيَهُودِيُّ فَأَوْمَأَتْ بِرَأْسِهَا فَجِيءَ بِالْيَهُودِيِّ فَاعْتَرَفَ فَأَمَرَ بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرُضَّ رَأْسُهُ بِالْحِجَارَةِ وَقَدْ قَالَ هَمَّامٌ بِحَجَرَيْنِ","id":"Telah menceritakan kepadaku [Ishaq] telah mengabarkan kepada kami [Habban] telah menceritakan kepada kami [Hammam] telah mengabarkan kepada kami [Qatadah] telah menceritakan kepada kami [Anas bin Malik], ada seorang yahudi meretakkan hamba sahaya dengan menjepit diantara dua batu. Si hamba sahaya ditanya; 'sebutkan siapa yang membunuhmu, apakah fulan dan fulan, ' hingga disebutlah nama seorang yahudi, dan si hamba sahaya mengiyakan dengan mengisyaratkan kepalanya. Si yahudi ditahan dan mengakui perbuatannya. Nabi shallallahu 'alaihi wasallam memerintahkan agar si yahudi diseret kepadanya dan beliau memecah kepalanya dengan batu. Sedang Hamam mengatakan dengan redaksi; 'dengan dua batu'."},"6043":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَتَلَ يَهُودِيًّا بِجَارِيَةٍ قَتَلَهَا عَلَى أَوْضَاحٍ لَهَا","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Anas bin Malik] radliallahu 'anhu; bahwasanya Nabi Shallallahu'alaihi wasallam pernah membunuh seorang yahudi karena membunuh hamba sahaya yang ingin ia rampas anting-antingnya."},"6044":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَلِيِّ بْنِ بَحْرٍ حَدَّثَنَا يَحْيَى حَدَّثَنَا سُفْيَانُ حَدَّثَنَا مُوسَى بْنُ أَبِي عَائِشَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْلَدَدْنَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَرَضِهِ فَقَالَ لَا تُلِدُّونِي فَقُلْنَا كَرَاهِيَةُ الْمَرِيضِ لِلدَّوَاءِ فَلَمَّا أَفَاقَ قَالَ لَا يَبْقَى أَحَدٌ مِنْكُمْ إِلَّا لُدَّ غَيْرَ الْعَبَّاسِ فَإِنَّهُ لَمْ يَشْهَدْكُمْ","id":"Telah menceritakan kepada kami [Amru bin Ali bin Bahr] telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Musa bin Abi Aisyah] dari [Ubaidullah bin Abdillah] dari [Aisyah] radliallahu 'anha, mengatakan; Pernah kami memasukkan obat di mulut Nabi shallallahu 'alaihi wasallam ketika sakitnya, namun beliau berpesan: \"Janganlah kalian memasukkan obat dalam mulutku!\" Kami hanya saling mengatakan; 'Itu hanyalah kebiasaan orang sakit yang enggan minum obat'. Ketika beliau sadar, beliau bersabda: \"Tidak ada diantara kalian kecuali mulutnya harus diminumi obat, kecuali Abbas, sebab ia tidak ikut serta bersama kalian.\""},"6045":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ حَدَّثَنَا أَبُو الزِّنَادِ أَنَّ الْأَعْرَجَ حَدَّثَهُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُ إِنَّهُسَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ نَحْنُ الْآخِرُونَ السَّابِقُونَ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Abul yaman] telah mengabarkan kepada kami [Syu'aib] telah menceritakan kepada kami [Abu Az Zanad], bahwasanya [Al A'raj] menceritakan kepadanya, bahwa [Abu Hurairah] berkata; dirinya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kami adalah orang-orang terkemudian (generasi pungkasan) di dunia, namun menjadi orang-orang pemula (angkatan pemula) yang masuk surga di hari kiamat.\""},"6046":{"ar":"وَبِإِسْنَادِهِ لَوْ اطَّلَعَ فِي بَيْتِكَ أَحَدٌ وَلَمْ تَأْذَنْ لَهُ خَذَفْتَهُ بِحَصَاةٍ فَفَقَأْتَ عَيْنَهُ مَا كَانَ عَلَيْكَ مِنْ جُنَاحٍ","id":"(Masih dari jalur periwayatan yang sama dengan hadits sebelumnya -dari [Abu Hurairah]-) \"Jika seseorang mengintip rumahmu padahal kamu tidak mengijinkannya, lalu kamu melemparnya dengan batu sehingga membutakan matanya, kamu tidak mendapat dosa karenanya.\""},"6047":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ حُمَيْدٍأَنَّ رَجُلًا اطَّلَعَ فِي بَيْتِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَدَّدَ إِلَيْهِ مِشْقَصًا فَقُلْتُ مَنْ حَدَّثَكَ قَالَ أَنَسُ بْنُ مَالِكٍ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Humaid], ada seorang laki-laki mengintip rumah Nabi shallallahu 'alaihi wasallam, maka beliau memperlihatkan anak panahnya kepadanya. Saya (Yahya Al Qaththan) bertanya; 'Siapa yang menceritakan hadits ini kepadamu? ' Humaid menjawab; [Anas bin Malik]."},"6048":{"ar":"حَدَّثَنِي إِسْحَاقُ بْنُ مَنْصُورٍ أَخْبَرَنَا أَبُو أُسَامَةَ قَالَ هِشَامٌ أَخْبَرَنَا عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْلَمَّا كَانَ يَوْمُ أُحُدٍ هُزِمَ الْمُشْرِكُونَ فَصَاحَ إِبْلِيسُ أَيْ عِبَادَ اللَّهِ أُخْرَاكُمْ فَرَجَعَتْ أُولَاهُمْ فَاجْتَلَدَتْ هِيَ وَأُخْرَاهُمْ فَنَظَرَ حُذَيْفَةُ فَإِذَا هُوَ بِأَبِيهِ الْيَمَانِ فَقَالَ أَيْ عِبَادَ اللَّهِ أَبِي أَبِي قَالَتْ فَوَاللَّهِ مَا احْتَجَزُوا حَتَّى قَتَلُوهُ قَالَ حُذَيْفَةُ غَفَرَ اللَّهُ لَكُمْقَالَ عُرْوَةُ فَمَا زَالَتْ فِي حُذَيْفَةَ مِنْهُ بَقِيَّةُ خَيْرٍ حَتَّى لَحِقَ بِاللَّهِ","id":"Telah menceritakan kepadaku [Ishaq bin manshur] telah mengabarkan kepada kami [Abu Usamah], [Hisyam] mengatakan, ia mengabarkan kepada kami dari [Ayahnya] dari ['Aisyah], mengatakan, Dalam perang Uhud kaum musyrikin kocar kacir dan Iblis berseru; 'hai hamba Allah, awas barisan belakang kalian! ' Maka pasukan depan kaum musyrikin berbalik kearah belakang sehingga tubrukan sesama mereka tak terelakkan. Lantas Hudzaifah melihat anggota pasukan satu persatu, dan dia dapatkan ayahnya, Al Yaman. Maka ia berseru: 'hai hamba Allah, awas itu ayahku, awas itu ayahku! ' Aisyah berkata; Demi Allah, kaum muslimin tak sabar menahan diri hingga mereka membunuh ayahnya. Khudzaifah kemudian mengatakan; 'Semoga Allah mengampuni kalian.' 'Urwah berkomentar; pada diri Khudzaifah tiada henti tertanam sifat-sifat kebaikan hingga ia menjumpai Allah."},"6049":{"ar":"حَدَّثَنَا الْمَكِّيُّ بْنُ إِبْرَاهِيمَ حَدَّثَنَا يَزِيدُ بْنُ أَبِي عُبَيْدٍ عَنْ سَلَمَةَ قَالَخَرَجْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى خَيْبَرَ فَقَالَ رَجُلٌ مِنْهُمْ أَسْمِعْنَا يَا عَامِرُ مِنْ هُنَيْهَاتِكَ فَحَدَا بِهِمْ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ السَّائِقُ قَالُوا عَامِرٌ فَقَالَ رَحِمَهُ اللَّهُ فَقَالُوا يَا رَسُولَ اللَّهِ هَلَّا أَمْتَعْتَنَا بِهِ فَأُصِيبَ صَبِيحَةَ لَيْلَتِهِ فَقَالَ الْقَوْمُ حَبِطَ عَمَلُهُ قَتَلَ نَفْسَهُ فَلَمَّا رَجَعْتُ وَهُمْ يَتَحَدَّثُونَ أَنَّ عَامِرًا حَبِطَ عَمَلُهُ فَجِئْتُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا نَبِيَّ اللَّهِ فَدَاكَ أَبِي وَأُمِّي زَعَمُوا أَنَّ عَامِرًا حَبِطَ عَمَلُهُ فَقَالَ كَذَبَ مَنْ قَالَهَا إِنَّ لَهُ لَأَجْرَيْنِ اثْنَيْنِ إِنَّهُ لَجَاهِدٌ مُجَاهِدٌ وَأَيُّ قَتْلٍ يَزِيدُهُ عَلَيْهِ","id":"Telah menceritakan kepada kami [Makki bin Ibrahim] telah menceritakan kepada kami [Yazid bin Abi 'Ubaid] dari [Salamah bin Al Akwa'] mengatakan, Dahulu kami berangkat bersama Nabi Shallallahu'alaihiwasallam ke Khaibar. Salah seorang pasukan berujar; 'Wahai Amir, perdengarkan syair-syairmu kepada kami! ' Lantas Amir Ibn Al Akwa' memperdengarkan bait-bait syairnya sehingga terdengar oleh mereka. Selanjutnya Nabi shallallahu 'alaihi wasallam bertanya; \"Siapa yang menggiring unta-unta kita?\" 'Sahabat kita, Amir bin Al akwa' Jawab para sahabat. Nabi Terus memanjatkan doa: \"Semoga Allah merahmati dia!\" Para sahabat berujar; 'Ya Rasulullah, apakah engkau memberi kami kenyamanan lewat perantaraannya' pagi harinya ia meninggal, selanjutnya para sahabat berkomentar (mengenai peristiwa 'Amir); 'Sungguh amir sia-sia amalnya, ia telah membunuh dirinya.' Ketika aku pulang, para sahabat berbincang-bincang dengan mengatakan bahwa Amir bin Al Akwa' sia-sia amalnya karena telah membunuh dirinya sendiri. Maka kudatangi Nabi shallallahu 'alaihi wasallam dan aku berkata; 'ya Nabiyullah, demi ayahku dan ibuku menjadi tebusanmu, orang-orang beranggapan bahwa saudaraku, Amir, sia-sia amalnya! ' maka Beliau bersabda: \"Bohong semua yang mengatakan seperti itu, bahkan ia memperoleh dua pahala, sungguh ia orang yang bersungguh-sungguh sekaligus menjadi mujahid, mana ada pembunuhan yang lebih sadis dari seperti yang dialaminya?\""},"6050":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا قَتَادَةُ قَالَ سَمِعْتُ زُرَارَةَ بْنَ أَوْفَى عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ رَجُلًا عَضَّ يَدَ رَجُلٍ فَنَزَعَ يَدَهُ مِنْ فَمِهِ فَوَقَعَتْ ثَنِيَّتَاهُ فَاخْتَصَمُوا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَعَضُّ أَحَدُكُمْ أَخَاهُ كَمَا يَعَضُّ الْفَحْلُ لَا دِيَةَ لَكَ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Qatadah] mengatakan, aku mendengar [Zurarah bin Awfa] dari ['Imran bin Hushain], berkata; seorang laki-laki menggigit tangan seseorang, yang digigit lantas menarik tangannya dari mulutnya sehingga dua gigi serinya tanggal, lantas mereka mengadukan sengketa ini kepada Nabi Shallallahu'alaihiwasallam, dan Nabi bersabda: \"Salah seorang diantara kalian menggigit saudaranya sebagaimana kambing jantan menggigit, dan tidak ada diyat.\""},"6051":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ صَفْوَانَ بْنِ يَعْلَى عَنْ أَبِيهِ قَالَخَرَجْتُ فِي غَزْوَةٍ فَعَضَّ رَجُلٌ فَانْتَزَعَ ثَنِيَّتَهُ فَأَبْطَلَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari ['Atho'] dari [Shafwan bin Ya'la] dari [ayahnya] mengatakan, pernah aku berangkat untuk suatu peperangan, kemudian ada seseorang yang menggigit sehingga kedua gigi serinya tanggal, dan Nabi shallallahu 'alaihi wasallam menganggap kasus ini tak dianggap (tak ada diyat)."},"6052":{"ar":"حَدَّثَنَا الْأَنْصَارِيُّ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُأَنَّ ابْنَةَ النَّضْرِ لَطَمَتْ جَارِيَةً فَكَسَرَتْ ثَنِيَّتَهَا فَأَتَوْا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ بِالْقِصَاصِ","id":"Telah menceritakan kepada kami [Al Anshari] telah menceritakan kepada kami [Humaid] dari [Anas] radliallahu 'anhu, anak perempuan Nadhr menempeleng seorang hamba sahaya sehigga gigi serinya tanggal, maka mereka mengadukan perkaranya kepada Nabi shallallahu 'alaihi wasallam, dan Nabi memerintahkan qisas berlaku."},"6053":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ هَذِهِ وَهَذِهِ سَوَاءٌ يَعْنِي الْخِنْصَرَ وَالْإِبْهَامَحَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ شُعْبَةَ عَنْ قَتَادَةَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Adam] dari [Syu'bah] dari [Qatadah] dari [Ikrimah] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam bersabda; \"Ini dan ini sama saja, \" yang beliau maksudkan kelingking dan telunjuk. Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Ibnu Abi 'Adi] dari [Syu'bah] dari [Qatadah] dari [Ikrimah] dari [Ibnu Abbas] mengatakan; Aku mendengar Nabi shallallahu 'alaihi wasallam. Semisal hadits diatas."},"6054":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ حَدَّثَنَا مُوسَى بْنُ أَبِي عَائِشَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ قَالَ قَالَتْ عَائِشَةُلَدَدْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَرَضِهِ وَجَعَلَ يُشِيرُ إِلَيْنَا لَا تَلُدُّونِي قَالَ فَقُلْنَا كَرَاهِيَةُ الْمَرِيضِ بِالدَّوَاءِ فَلَمَّا أَفَاقَ قَالَ أَلَمْ أَنْهَكُمْ أَنْ تَلُدُّونِي قَالَ قُلْنَا كَرَاهِيَةٌ لِلدَّوَاءِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَبْقَى مِنْكُمْ أَحَدٌ إِلَّا لُدَّ وَأَنَا أَنْظُرُ إِلَّا الْعَبَّاسَ فَإِنَّهُ لَمْ يَشْهَدْكُمْ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Sufyan] telah menceritakan kepada kami [Musa bin Abu 'Aisyah] dari ['Ubaidullah bin Abdillah] mengatakan; ['Aisyah] mengatakan; 'Dahulu kami memasukkan obat ke mulut Rasulullah Shallallahu'alaihiwasallam ketika beliau sakit, beliau memberi isyarat kepada kami yang isinya; \"Janganlah kalian memasukkan obat ke dalam mulutku'. --Kata Ubaidullah, kami mengira bahwa beliau ucapkan karena orang yang sakit memang tidak suka obat-- Dikala Nabi telah sadar, beliau berkata: \"Bukankah kalian telah kularang memasukkan obat ke dalam mulutku?\" -- Kata Ubaidullah, kami berpendapat bahwa itu pertanda beliau tidak suka obat- Lantas Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang pun diantara kalian sekarang, kecuali mulutnya harus dimasuki obat dan aku sendiri harus menyaksikannya, selain Abbas, karena ia tidak ikut bersama kalian.\""},"6055":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سَعِيدُ بْنُ عُبَيْدٍ عَنْ بُشَيْرِ بْنِ يَسَارٍ زَعَمَ أَنَّ رَجُلًا مِنْ الْأَنْصَارِ يُقَالُ لَهُ سَهْلُ بْنُ أَبِي حَثْمَةَ أَخْبَرَهُأَنَّ نَفَرًا مِنْ قَوْمِهِ انْطَلَقُوا إِلَى خَيْبَرَ فَتَفَرَّقُوا فِيهَا وَوَجَدُوا أَحَدَهُمْ قَتِيلًا وَقَالُوا لِلَّذِي وُجِدَ فِيهِمْ قَدْ قَتَلْتُمْ صَاحِبَنَا قَالُوا مَا قَتَلْنَا وَلَا عَلِمْنَا قَاتِلًا فَانْطَلَقُوا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا يَا رَسُولَ اللَّهِ انْطَلَقْنَا إِلَى خَيْبَرَ فَوَجَدْنَا أَحَدَنَا قَتِيلًا فَقَالَ الْكُبْرَ الْكُبْرَ فَقَالَ لَهُمْ تَأْتُونَ بِالْبَيِّنَةِ عَلَى مَنْ قَتَلَهُ قَالُوا مَا لَنَا بَيِّنَةٌ قَالَ فَيَحْلِفُونَ قَالُوا لَا نَرْضَى بِأَيْمَانِ الْيَهُودِ فَكَرِهَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُبْطِلَ دَمَهُ فَوَدَاهُ مِائَةً مِنْ إِبِلِ الصَّدَقَةِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sa'id bin Ubaid] dari [Busyair bin Yasar], seingatnya ada seorang laki-laki Anshar yang bergelar [Sahl bin Abi Khatsmah] mengabarinya bahwa; Beberapa orang kaumnya berangkat ke Khaibar, setibanya disana mereka berpencar, lantas mereka mendapatkan salah seorang dari mereka terbunuh. Mereka pun berujar kepada penduduk yang kawan mereka terbunuh disana; \"kalian telah membunuh kawan kami!\" Penduduk tersebut mengelak seraya mengatakan; 'Kami tidak membunuh dan juga tidak tahu si pembunuhnya.' Lantas para sahabat mengadukan perkaranya kepada Nabi shallallahu 'alaihi wasallam; 'Ya Rasulullah, kami berangkat ke Khaibar, selanjutnya kami dapatkan kawan kami terbunuh.' Nabi menjawab: \"yang berbicara yang paling tua, yang berbicara yang paling tua!\" Lalu Nabi mengatakan; \"kalian harus membawa bukti terhadap si pembunuhnya!\" Para sahabat menjawab; 'kalau bukti kami tidak punya! ' Nabi menjawab; \"kalau begitu suruhlah kaum yahudi itu untuk bersumpah!\" Para sahabat menjawab; 'Kami tidak percaya dengan sumpah orang-orang yahudi.' Rupanya Rasulullah shallallahu 'alaihi wasallam tidak berkenan jika darah sahabatnya sia-sia sehingga beliau sendiri yang membayar diyatnya dengan sebanyak seratus ekor unta."},"6056":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو بِشْرٍ إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ الْأَسَدِيُّ حَدَّثَنَا الْحَجَّاجُ بْنُ أَبِي عُثْمَانَ حَدَّثَنِي أَبُو رَجَاءٍ مِنْ آلِ أَبِي قِلَابَةَ حَدَّثَنِي أَبُو قِلَابَةَأَنَّ عُمَرَ بْنَ عَبْدِ الْعَزِيزِ أَبْرَزَ سَرِيرَهُ يَوْمًا لِلنَّاسِ ثُمَّ أَذِنَ لَهُمْ فَدَخَلُوا فَقَالَ مَا تَقُولُونَ فِي الْقَسَامَةِ قَالَ نَقُولُ الْقَسَامَةُ الْقَوَدُ بِهَا حَقٌّ وَقَدْ أَقَادَتْ بِهَا الْخُلَفَاءُ قَالَ لِي مَا تَقُولُ يَا أَبَا قِلَابَةَ وَنَصَبَنِي لِلنَّاسِ فَقُلْتُ يَا أَمِيرَ الْمُؤْمِنِينَ عِنْدَكَ رُءُوسُ الْأَجْنَادِ وَأَشْرَافُ الْعَرَبِ أَرَأَيْتَ لَوْ أَنَّ خَمْسِينَ مِنْهُمْ شَهِدُوا عَلَى رَجُلٍ مُحْصَنٍ بِدِمَشْقَ أَنَّهُ قَدْ زَنَى لَمْ يَرَوْهُ أَكُنْتَ تَرْجُمُهُ قَالَ لَا قُلْتُ أَرَأَيْتَ لَوْ أَنَّ خَمْسِينَ مِنْهُمْ شَهِدُوا عَلَى رَجُلٍ بِحِمْصَ أَنَّهُ سَرَقَ أَكُنْتَ تَقْطَعُهُ وَلَمْ يَرَوْهُ قَالَ لَا قُلْتُ فَوَاللَّهِ مَا قَتَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَدًا قَطُّ إِلَّا فِي إِحْدَى ثَلَاثِ خِصَالٍ رَجُلٌ قَتَلَ بِجَرِيرَةِ نَفْسِهِ فَقُتِلَ أَوْ رَجُلٌ زَنَى بَعْدَ إِحْصَانٍ أَوْ رَجُلٌ حَارَبَ اللَّهَ وَرَسُولَهُ وَارْتَدَّ عَنْ الْإِسْلَامِ فَقَالَ الْقَوْمُ أَوَلَيْسَ قَدْ حَدَّثَ أَنَسُ بْنُ مَالِكٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَطَعَ فِي السَّرَقِ وَسَمَرَ الْأَعْيُنَ ثُمَّ نَبَذَهُمْ فِي الشَّمْسِ فَقُلْتُ أَنَا أُحَدِّثُكُمْ حَدِيثَ أَنَسٍ حَدَّثَنِي أَنَسٌ أَنَّ نَفَرًا مِنْ عُكْلٍ ثَمَانِيَةً قَدِمُوا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَايَعُوهُ عَلَى الْإِسْلَامِ فَاسْتَوْخَمُوا الْأَرْضَ فَسَقِمَتْ أَجْسَامُهُمْ فَشَكَوْا ذَلِكَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَفَلَا تَخْرُجُونَ مَعَ رَاعِينَا فِي إِبِلِهِ فَتُصِيبُونَ مِنْ أَلْبَانِهَا وَأَبْوَالِهَا قَالُوا بَلَى فَخَرَجُوا فَشَرِبُوا مِنْ أَلْبَانِهَا وَأَبْوَالِهَا فَصَحُّوا فَقَتَلُوا رَاعِيَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَطْرَدُوا النَّعَمَ فَبَلَغَ ذَلِكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَرْسَلَ فِي آثَارِهِمْ فَأُدْرِكُوا فَجِيءَ بِهِمْ فَأَمَرَ بِهِمْ فَقُطِّعَتْ أَيْدِيهِمْ وَأَرْجُلُهُمْ وَسَمَرَ أَعْيُنَهُمْ ثُمَّ نَبَذَهُمْ فِي الشَّمْسِ حَتَّى مَاتُوا قُلْتُ وَأَيُّ شَيْءٍ أَشَدُّ مِمَّا صَنَعَ هَؤُلَاءِ ارْتَدُّوا عَنْ الْإِسْلَامِ وَقَتَلُوا وَسَرَقُوا فَقَالَ عَنْبَسَةُ بْنُ سَعِيدٍ وَاللَّهِ إِنْ سَمِعْتُ كَالْيَوْمِ قَطُّ فَقُلْتُ أَتَرُدُّ عَلَيَّ حَدِيثِي يَا عَنْبَسَةُ قَالَ لَا وَلَكِنْ جِئْتَ بِالْحَدِيثِ عَلَى وَجْهِهِ وَاللَّهِ لَا يَزَالُ هَذَا الْجُنْدُ بِخَيْرٍ مَا عَاشَ هَذَا الشَّيْخُ بَيْنَ أَظْهُرِهِمْ قُلْتُ وَقَدْ كَانَ فِي هَذَا سُنَّةٌ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيْهِ نَفَرٌ مِنْ الْأَنْصَارِ فَتَحَدَّثُوا عِنْدَهُ فَخَرَجَ رَجُلٌ مِنْهُمْ بَيْنَ أَيْدِيهِمْ فَقُتِلَ فَخَرَجُوا بَعْدَهُ فَإِذَا هُمْ بِصَاحِبِهِمْ يَتَشَحَّطُ فِي الدَّمِ فَرَجَعُوا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا يَا رَسُولَ اللَّهِ صَاحِبُنَا كَانَ تَحَدَّثَ مَعَنَا فَخَرَجَ بَيْنَ أَيْدِينَا فَإِذَا نَحْنُ بِهِ يَتَشَحَّطُ فِي الدَّمِ فَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ بِمَنْ تَظُنُّونَ أَوْ مَنْ تَرَوْنَ قَتَلَهُ قَالُوا نَرَى أَنَّ الْيَهُودَ قَتَلَتْهُ فَأَرْسَلَ إِلَى الْيَهُودِ فَدَعَاهُمْ فَقَالَ آنْتُمْ قَتَلْتُمْ هَذَا قَالُوا لَا قَالَ أَتَرْضَوْنَ نَفَلَ خَمْسِينَ مِنْ الْيَهُودِ مَا قَتَلُوهُ فَقَالُوا مَا يُبَالُونَ أَنْ يَقْتُلُونَا أَجْمَعِينَ ثُمَّ يَنْتَفِلُونَ قَالَ أَفَتَسْتَحِقُّونَ الدِّيَةَ بِأَيْمَانِ خَمْسِينَ مِنْكُمْ قَالُوا مَا كُنَّا لِنَحْلِفَ فَوَدَاهُ مِنْ عِنْدِهِ قُلْتُ وَقَدْ كَانَتْ هُذَيْلٌ خَلَعُوا خَلِيعًا لَهُمْ فِي الْجَاهِلِيَّةِ فَطَرَقَ أَهْلَ بَيْتٍ مِنْ الْيَمَنِ بِالْبَطْحَاءِ فَانْتَبَهَ لَهُ رَجُلٌ مِنْهُمْ فَحَذَفَهُ بِالسَّيْفِ فَقَتَلَهُ فَجَاءَتْ هُذَيْلٌ فَأَخَذُوا الْيَمَانِيَّ فَرَفَعُوهُ إِلَى عُمَرَ بِالْمَوْسِمِ وَقَالُوا قَتَلَ صَاحِبَنَا فَقَالَ إِنَّهُمْ قَدْ خَلَعُوهُ فَقَالَ يُقْسِمُ خَمْسُونَ مِنْ هُذَيْلٍ مَا خَلَعُوهُ قَالَ فَأَقْسَمَ مِنْهُمْ تِسْعَةٌ وَأَرْبَعُونَ رَجُلًا وَقَدِمَ رَجُلٌ مِنْهُمْ مِنْ الشَّأْمِ فَسَأَلُوهُ أَنْ يُقْسِمَ فَافْتَدَى يَمِينَهُ مِنْهُمْ بِأَلْفِ دِرْهَمٍ فَأَدْخَلُوا مَكَانَهُ رَجُلًا آخَرَ فَدَفَعَهُ إِلَى أَخِي الْمَقْتُولِ فَقُرِنَتْ يَدُهُ بِيَدِهِ قَالُوا فَانْطَلَقَا وَالْخَمْسُونَ الَّذِينَ أَقْسَمُوا حَتَّى إِذَا كَانُوا بِنَخْلَةَ أَخَذَتْهُمْ السَّمَاءُ فَدَخَلُوا فِي غَارٍ فِي الْجَبَلِ فَانْهَجَمَ الْغَارُ عَلَى الْخَمْسِينَ الَّذِينَ أَقْسَمُوا فَمَاتُوا جَمِيعًا وَأَفْلَتَ الْقَرِينَانِ وَاتَّبَعَهُمَا حَجَرٌ فَكَسَرَ رِجْلَ أَخِي الْمَقْتُولِ فَعَاشَ حَوْلًا ثُمَّ مَاتَ قُلْتُ وَقَدْ كَانَ عَبْدُ الْمَلِكِ بْنُ مَرْوَانَ أَقَادَ رَجُلًا بِالْقَسَامَةِ ثُمَّ نَدِمَ بَعْدَ مَا صَنَعَ فَأَمَرَ بِالْخَمْسِينَ الَّذِينَ أَقْسَمُوا فَمُحُوا مِنْ الدِّيوَانِ وَسَيَّرَهُمْ إِلَى الشَّأْمِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Abu Bisyr Isma'il bin Ibrahim Al Asadi] telah menceritakan kepada kami [Al Hajjaj bin Abi 'Utsman] telah menceritakan kepadaku [Abu Raja`] dari keluarga Abu Qilaba, telah menceritakan kepadaku [Abu Qilabah]; Umar bin Abdul aziz suatu hari menghamparkan kasur tamunya untuk umum dan memberi mereka izin, mereka pun masuk. Lantas Umar bin Abdul azis bertanya; 'bagaimana pedapat kalian tentang Qosamah? ' Kami menjawab; 'Qosamah? Qisas karena Qasamah adalah benar, para khalifah pernah memberlakukan qisas karenanya.' Lantas Umar bin Abd aziz bertanya padaku -yang ketika itu dia memberiku kedudukan special untuk membimbing masyarakat- aku menjawab; 'Wahai amirul mukminin, engkau mempunyai panglima-panglima tentara dan pejabat-pejabat elit arab, bagaimana pendapatmu sekiranya lima puluh orang diantara mereka bersaksi bahwa seseorang yang telah menikah di Damaskus melakukan perzinahan padahal mereka tidak melihatnya, apakah anda merajamnya? ' \"TIDAK\" Jawabnya. Saya bertanya lagi; 'Bagaimana pendapatmu sekiranya lima puluh orang diantara mereka bersaksi bahwa ada seorang laki-laki di Himsh telah mencuri, apakah engkau potong tangannya padahal mereka tidak melihatnya? ' \"TIDAK\" Jawabnya. Maka saya berkata; 'Demi Allah, Rasulullah Shallallahu'alaihiwasallam sama sekali belum pernah membunuh seorang pun kecuali karena salah satu alasan diantara tiga; Seseorang yang membunuh secara sengaja, maka ia harus dibunuh, atau seseorang yang berzina setelah menikah, atau seseorang yang memerangi Allah dan rasul-NYA dan murtad dari Islam.' Lantas orang-orang menyela pembicaraan; 'Bukankah [Anas bin Malik] menceritakan bahwa Rasulullah shallallahu 'alaihi wasallam pernah memotong seseorang karena pencurian dan mencongkel matanya, dan membiarkan mereka terhempas di terik matahari? ' Kujawab; 'akan saya ceritakan kepada kalian hadits Anas yang Anas sendirilah yang menceritakan kepadaku; Bahwasanya sekelompok orang dari kabilah 'Ukl sejumlah delapan orang menemui Rasulullah Shallallahu'alaihiwasallam, mereka berbaiat kepada beliau menyatakan keIslaman. Tapi mereka tidak cocok dengan iklim Madinah sehingga tubuh mereka sakit. Lalu mereka mengadukan keluh kesahnya kepada Rasulullah Shallallahu'alaihiwasallam. Nabi menyarankan: \"Tidakkah sebaiknya kalian berangkat bersama penggembala unta-unta kami sehingga kalian bisa memperoleh susunya dan air kencingnya (untuk berobat)?\" 'baiklah' Jawab mereka. Mereka pun berangkat dan meminum susu dan air kencingnya sehingga sehat. Tapi mereka malah membunuh penggembala Rasulullah Shallallahu'alaihiwasallam dan merampok unta-untanya. Kejadian ini akhirnya sampai kepada Rasulullah Shallallahu'alaihiwasallam. Nabi pun mengirim pasukan untuk memburu jejak mereka. Mereka berhasil diringkus dan diseret di hadapan Nabi. Maka Nabi pun memerintahkan mereka untuk dipotong tangan dan kaki mereka dan mata mereka dicongkel. Lantas Nabi membuang mereka di terik panas matahari hingga tewas.' Saya bertanya; 'Siapa lagi yang lebih sadis daripada mereka? Mereka murtad dari Islam, membunuh, dan merampok.' Kemudian 'Anbasah bin Sa'id mengatakan; 'Demi Allah, saya belum pernah mendengar seperti hari ini sama sekali.' Saya berkata; 'Apakah engkau menolak haditsku ini hai 'Anbasah? ' 'tidak, engkau telah membawakan hadits seperti apa adanya. 'Demi Allah, tentara ini akan tetap dalam kebaikan selama syaikh ini hidup ditengah-tengah mereka.' Aku terus melanjutkan; dalam kasus seperti ini, juga ada pedoman lain dari Rasulullah Shallallahu'alaihiwasallam, kisahnya, Pernah beberapa orang anshar menemui Rasulullah Shallallahu'alaihiwasallam. Mereka berbincang-bincang bersama beliau, lantas seorang dari mereka keluar dari tengah-tengah mereka, dan ternyata ia dibunuh. Sesudah pembunuhan itu, para sahabat keluar, mereka temukan sahabatnya telah terbunuh bersimbah darah, sehingga mereka laporkan kasusnya kepada Rasulullah Shallallahu'alaihiwasallam. Kata mereka; ' Ya Rasulullah, kawan kita yang tadi berbincang-bincang bersama kita, kemudian keluar dari tengah-tengah kami, ternyata ia telah bersimbah darah.' Rasulullah Shallallahu'alaihiwasallam keluar dan bertanya: \"Menurut kalian, siapa yang kalian terka?\" dalam redaksi lain \"Siapa yang kalian sangka telah membunuhnya?\" Mereka menjawab; 'kami pikir, kaum yahudilah yang telah membunuhnya.' Rasul pun mengutus utusan menemui yahudi, mengundang mereka dan berujar; \"apakah kalian telah membunuh kawan kami ini?\" Mereka menjawab; 'Tidak'. Nabi kemudian mengatakan kepada para sahabat; \"apakah kalian rela jika lima puluh orang yahudi bersumpah bahwa mereka tidak membunuhnya?\" Para sahabat menjawab; 'Tentu mereka takkan peduli jika memang benar-benar membunuh kami! ' Kemudian kaum yahudi bersumpah. Lantas Nabi bertanya; \"bagaimana kalau kalian memperoleh diyat asalkan lima puluh orang diantara kalian bersumpah?\" Namun para sahabat tidak mau bersumpah. Akhirnya Nabi membayar diyatnya dari kantong beliau sendiri. Saya berkata; Dahulu kabilah Hudzail pernah melepaskan (membatalkan) persekutuan (ikrar perjanjian untuk bahagia-sengsara secara bersama) semasa jahiliyah. Tetapi Hudzail menyerang satu keluarga Yamani di malam buta di Bat-ha'. Seorang yamani dari penghuni rumah terjaga sehingga bisa memenggalnya dengan pedang dan berhasil membunuhnya. Kemudian penduduk Hudzail datang dan meringkus keluarga yamani dan mengadukannya kepada Umar di Al Mausim. Hudzail menyampaikan dengan berkata; 'dia telah membunuh sahabat kami.' Dia menjawab; 'sesungguhnya mereka (Hudzail) telah melepaskan perjanjiannya.' Lantas Umar mengatakan; 'Silahkan lima puluh orang Hudzail bersumpah bahwa mereka belum melepaskan perjanjiannya.' Lantas empat puluh sembilan orang Hudzail bersumpah bahwa mereka belum melepas perjanjiannya. Kemudian salah seorang dari mereka datang dari Syam, dan mereka pun meminta orang yang baru datang tersebut untuk bersumpah, namun ia enggan bersumpah sehingga harus menebus keengganan sumpahnya dengan membayar seribu dirham. Lantas Hudzail mencari pengganti lain untuk melengkapi lima puluh orang. Sedang laki-laki yang membayar tebusan tadi, mereka serahkan kepada saudara korban sehingga tangannya bergandengan dengan tangannya. Keduanya terus berjalan bersama lima puluh orang yang telah bersumpah, hingga setibanya mereka di sebuah pohon kurma, hujan mengguyur mereka sehingga mereka terperangkap dalam gua di sebuah gunung. Gua pun runtuh sehingga menimpa kelima puluh orang Hudzail yang bersumpah itu dan mereka semua mati. Kedua orang sisanya bisa lolos, namun tiba-tiba ada sebuah batu yang menggelinding ke arah mereka dan meretakkan kaki saudara yang terbunuh, ia masih bisa hidup setahun kemudian lantas meninggal. Saya berkata; Abdul Malik bin Marwan pernah mengqisas seseorang dengan bukti Qossamah, namun di kemudian hari ia menyesal dari yang dia lakukan, dan ia perintahkan kelima puluh orang yang bersumpah untuk dihilangkan dari catatan Negara dan beliau memutasikan kelima puluh orang tadi ke negeri Syam. "},"6057":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي بَكْرِ بْنِ أَنَسٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُأَنَّ رَجُلًا اطَّلَعَ مِنْ حُجْرٍ فِي بَعْضِ حُجَرِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَامَ إِلَيْهِ بِمِشْقَصٍ أَوْ بِمَشَاقِصَ وَجَعَلَ يَخْتِلُهُ لِيَطْعُنَهُ","id":"Telah menceritakan kepada kami [Abu Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] dari ['Ubaidullah bin Abu Bakar bin Anas] dari [Anas] radliallahu 'anhu, ada seseorang yang mengintip salah satu kamar Nabi shallallahu 'alaihi wasallam, maka beliau menuju orang itu sambil membawa guntingnya dan beliau sembunyikan untuk ditusukkannya."},"6058":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ عَنْ ابْنِ شِهَابٍ أَنَّ سَهْلَ بْنَ سَعْدٍ السَّاعِدِيَّ أَخْبَرَهُأَنَّ رَجُلًا اطَّلَعَ فِي جُحْرٍ فِي بَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِدْرًى يَحُكُّ بِهِ رَأْسَهُ فَلَمَّا رَآهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْ أَعْلَمُ أَنَّكَ تَنْتَظِرُنِي لَطَعَنْتُ بِهِ فِي عَيْنَيْكَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا جُعِلَ الْإِذْنُ مِنْ قِبَلِ الْبَصَرِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab], [Sahal bin Sa'd as Sa'idi] mengabarkannya, ada seseorang yang mengitintip melalui lubang pintu kamar Nabi shallallahu 'alaihi wasallam yang ketika itu beliau tengah menyisir kepalanya, ketika Rasulullah Shallallahu'alaihiwasallam melihatnya, beliau bersabda: \"Kalaulah aku tahu bahwa engkau mengintip, niscaya sisir itu kutusukkan pada kedua matamu, \" lalu Rasulullah Shallallahu'alaihiwasallam bersabda; \"Hanyasanya ijin demi pandangan.\""},"6059":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ أَبُو الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ أَنَّ امْرَأً اطَّلَعَ عَلَيْكَ بِغَيْرِ إِذْنٍ فَخَذَفْتَهُ بِعَصَاةٍ فَفَقَأْ��َ عَيْنَهُ لَمْ يَكُنْ عَلَيْكَ جُنَاحٌ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Abu Az Zanad] dari [Al A'raj] dari [Abu Hurairah] mengatakan, Abul Qashim Shallallahu'alaihiwasallam bersabda; \"Jika seseorang mengintipmu tanpa seijinmu, lantas engkau tusuk dengan tongkat sehingga matanya buta, maka tak ada diyat atasmu.\""},"6060":{"ar":"حَدَّثَنَا صَدَقَةُ بْنُ الْفَضْلِ أَخْبَرَنَا ابْنُ عُيَيْنَةَ حَدَّثَنَا مُطَرِّفٌ قَالَ سَمِعْتُ الشَّعْبِيَّ قَالَ سَمِعْتُ أَبَا جُحَيْفَةَ قَالَ سَأَلْتُ عَلِيًّا رَضِيَ اللَّهُ عَنْهُهَلْ عِنْدَكُمْ شَيْءٌ مِمَّا لَيْسَ فِي الْقُرْآنِ وَقَالَ مَرَّةً مَا لَيْسَ عِنْدَ النَّاسِ فَقَالَ وَالَّذِي فَلَقَ الْحَبَّةَ وَبَرَأَ النَّسَمَةَ مَا عِنْدَنَا إِلَّا مَا فِي الْقُرْآنِ إِلَّا فَهْمًا يُعْطَى رَجُلٌ فِي كِتَابِهِ وَمَا فِي الصَّحِيفَةِ قُلْتُ وَمَا فِي الصَّحِيفَةِ قَالَ الْعَقْلُ وَفِكَاكُ الْأَسِيرِ وَأَنْ لَا يُقْتَلَ مُسْلِمٌ بِكَافِرٍ","id":"Telah menceritakan kepada kami [Shadaqah bin Al Fadhl] Telah mengabarkan kepada kami [Ibnu 'Uyainah] telah menceritakan kepada kami [Mutharrif] mengatakan; aku mendengar [Asy Sya'bi], dia berkata; aku mendengar [Abu Juhaifah] mengatakan, aku bertanya kepada [Ali] radliallahu 'anhu; 'Apakah kalian mempunyai sesuatu yang tidak tersebut dalam alquran? ' kesempatan lain dia berkata; 'yang tidak ada pada orang-orang? ' ia menjawab; 'Demi Dzat yang membelah biji-bijian dan mencipta manusia, kami tidak mempunyai selain yag terdapat dalam al Qur`an, kecuali kepahaman yang diberikan kepada seseorang terhadap kitab-Nya dan yang terdapat dalam lembaran.' Saya bertanya; 'apa yang terdapat dalam lembaran? ' ia menjawab; 'yaitu membayar diyat, membebaskan tawanan, dan janganlah seorang muslim dibunuh karena orang kafir.'"},"6061":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ وَحَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ امْرَأَتَيْنِ مِنْ هُذَيْلٍ رَمَتْ إِحْدَاهُمَا الْأُخْرَى فَطَرَحَتْ جَنِينَهَا فَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهَا بِغُرَّةٍ عَبْدٍ أَوْ أَمَةٍ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] Telah mengabarkan kepada kami [Malik] dan telah menceritakan kepada kami [Isma'il] telah menceritakan kepada kami [Malik] dari [Ibnu Syihab] dari [Abu Salamah bin Abdurrahman] dari [Abu Hurairah] radliallahu 'anhu, ada dua wanita Hudzail, salah satunya memukul yang lain sehingga janin yang dikandung keguguran, dan Rasulullah Shallallahu'alaihiwasallam memutuskan untuk membayar ghurrah, budak laki-laki atau hamba sahaya perempuan."},"6062":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ عَنْ عُمَرَ رَضِيَ اللَّهُ عَنْهُأَنَّهُ اسْتَشَارَهُمْ فِي إِمْلَاصِ الْمَرْأَةِ فَقَالَ الْمُغِيرَةُ قَضَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْغُرَّةِ عَبْدٍ أَوْ أَمَةٍفَشَهِدَ مُحَمَّدُ بْنُ مَسْلَمَةَ أَنَّهُ شَهِدَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى بِهِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Hisyam] dari [ayahnya] dari [Mughirah bin Syu'bah] dari Umar radliallahu 'anhu, ia pernah meminta pendapat mereka mengenai menggugurkan janin wanita. Kontan Mughirah mengatakan; 'Nabi shallallahu 'alaihi wasallam memutuskan dengan ghurrah, budak atau hamba sahaya.' [Muhammad bin Maslamah] memberi kesaksian bahwasanya ia pernah menyaksikan Nabi shallallahu 'alaihi wasallam memutuskan sedemikian."},"6063":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ هِشَامٍ عَنْ أَبِيهِأَنَّ عُمَرَ نَشَدَ النَّاسَ مَنْ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى فِي السِّقْطِ فَقَالَ الْمُغِيرَةُ أَنَا سَمِعْتُهُ قَضَى فِيهِ بِغُرَّةٍ عَبْدٍ أَوْ أَمَةٍقَالَ ائْتِ مَنْ يَشْهَدُ مَعَكَ عَلَى هَذَا فَقَالَ مُحَمَّدُ بْنُ مَسْلَمَةَ أَنَا أَشْهَدُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِ هَذَا حَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مُحَمَّدُ بْنُ سَابِقٍ حَدَّثَنَا زَائِدَةُ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ أَنَّهُ سَمِعَ الْمُغِيرَةَ بْنَ شُعْبَةَ يُحَدِّثُ عَنْ عُمَرَ أَنَّهُ اسْتَشَارَهُمْ فِي إِمْلَاصِ الْمَرْأَةِ مِثْلَهُ","id":"Telah menceritakan kepada kami [Ubaidullah bin Musa] dari [Hisyam] dari [ayahnya], Umar pernah meminta kesaksian orang-orang, siapa diantara mereka yang mendengar Nabi shallallahu 'alaihi wasallam memutuskan masalah keguguran janin (yang di pukul). Maka [Al Mughirah] mengatakan; 'Aku mendengar beliau memutuskannya untuk membayar ghurrah, budak laki-laki atau hamba sahaya perempuan, ' lantas [Muhammad bin Maslamah] mengatakan; 'aku menyaksikan Nabi shallallahu 'alaihi wasallam dengan seperti ini.' Telah menceritakan kepadaku [Muhammad bin Abdullah] telah menceritakan kepada kami [Muhammad bin Sabiq] telah menceritakan kepada kami [Za'idah] telah menceritakan kepada kami [Hisyam bin Urwah] dari [ayahnya] ia mendengar [Mughirah bin Syu'bah] menceritakan tentang Umar, bahwa ia pernah meminta pendapat orang-orang tentang keguguran janin wanita semisalnya."},"6064":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى فِي جَنِينِ امْرَأَةٍ مِنْ بَنِي لَحْيَانَ بِغُرَّةٍ عَبْدٍ أَوْ أَمَةٍ ثُمَّ إِنَّ الْمَرْأَةَ الَّتِي قَضَى عَلَيْهَا بِالْغُرَّةِ تُوُفِّيَتْ فَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ مِيرَاثَهَا لِبَنِيهَا وَزَوْجِهَا وَأَنَّ الْعَقْلَ عَلَى عَصَبَتِهَا","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari [Sa'id bin Musayyab] dari [Abu Hurairah], Rasulullah Shallallahu'alaihiwasallam pernah memutuskan (diyat) janin wanita dari bani Lahyan dengan nilai setara ghurrah, budak laki-laki atau hamba sahaya perempuan, kemudian wanita yang beliau putuskan untuk membayar ghurrah meninggal, maka Rasulullah Shallallahu'alaihiwasallam putuskan warisannya untuk anak-anaknya dan suaminya, sedang pembayaran diyat bagi 'ashabahnya."},"6065":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ حَدَّثَنَا يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ ابْنِ الْمُسَيَّبِ وَأَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ أَنَّ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَاقْتَتَلَتْ امْرَأَتَانِ مِنْ هُذَيْلٍ فَرَمَتْ إِحْدَاهُمَا الْأُخْرَى بِحَجَرٍ فَقَتَلَتْهَا وَمَا فِي بَطْنِهَا فَاخْتَصَمُوا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَضَى أَنَّ دِيَةَ جَنِينِهَا غُرَّةٌ عَبْدٌ أَوْ وَلِيدَةٌ وَقَضَى أَنَّ دِيَةَ الْمَرْأَةِ عَلَى عَاقِلَتِهَا","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami [Ibnu Wahb] telah menceritakan kepada kami [Yunus] dari [Ibnu Syihab] dari [Ibnul Musayyab] dan [Abu Salamah bin Abdurrahman], [Abu Hurairah] radliallahu 'anhu mengatakan; Ada dua wnaita Hudzail yang berkelahi sehingga salah satunya melempar yang lain dengan batu sehingga membunuhnya dan menggugurkan kandungannya, lantas orang-orang mengadukan sengketa ini kepada Nabi shallallahu 'alaihi wasallam, dan beliau putuskan diyat janin sebesar ghurrah, setara budak laki-laki atau hamba sahaya perempuan, beliau putuskan diyat wanita ditanggung 'aqilah-nya. "},"6066":{"ar":"حَدَّثَنِي عَمْرُو بْنُ زُرَارَةَ أَخْبَرَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ عَنْ عَبْدِ الْعَزِيزِ عَنْ أَنَسٍ قَالَلَمَّا قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ أَخَذَ أَبُو طَلْحَةَ بِيَدِي فَانْطَلَقَ بِي إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ أَنَسًا غُلَامٌ كَيِّسٌ فَلْيَخْدُمْكَ قَالَ فَخَدَمْتُهُ فِي الْحَضَرِ وَالسَّفَرِ فَوَاللَّهِ مَا قَالَ لِي لِشَيْءٍ صَنَعْتُهُ لِمَ صَنَعْتَ هَذَا هَكَذَا وَلَا لِشَيْءٍ لَمْ أَصْنَعْهُ لِمَ لَمْ تَصْنَعْ هَذَا هَكَذَا","id":"Telah menceritakan kepadaku [Amru bin Zurarah] Telah mengabarkan kepada kami [Isma'il bin Ibrahim] dari ['Abdul 'Aziz] dari [Anas] mengatakan, dikala Rasulullah Shallallahu'alaihiwasallam datang ke Madinah, Abu Thalhah menggandeng tanganku dan mengajakku menemui Rasulullah shallallahu 'alaihi wasallam dan berujar; 'Wahai Rasulullah, Anas adalah anak belia yang terampil, baik sekali jika ia menjadi pembantumu! ' Kata Anas, maka aku membantu beliau baik ketika beliau di rumah maupun bepergian, dan demi Allah, beliau tidak pernah menggerutu terhadap yang kulakukan dengan mengatakan; 'mengapa kau lakukan seperti ini! ' Dan tidak pernah pula beliau menggerutu terhadapku karena pekerjaan yang tidak kulakukan dengan mengatakan; 'mengapa tidak kau kerjakan ini hah! '"},"6067":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا اللَّيْثُ حَدَّثَنَا ابْنُ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ وَأَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْعَجْمَاءُ جَرْحُهَا جُبَارٌ وَالْبِئْرُ جُبَارٌ وَالْمَعْدِنُ جُبَارٌ وَفِي الرِّكَازِ الْخُمُسُ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] telah menceritakan kepada kami [Al Laits] telah menceritakan kepada kami [Ibnu Syihab] dari [Sa'id bin Musayyab] dan [Abu Salamah bin Abdurrahman] dari [Abu Hurairah] radliallahu 'anhu, bahwasanya Rasulullah bersabda: \"Binatang ternak yang mencelakakan tidak ada kewajiban diyat, sumur yang mencelakai juga tak ada kewajiban diyat, Pertambangan (yang mencelakai juga) tak ada kewajiban diyat, dan harta karun zakatnya seperlima.\""},"6068":{"ar":"حَدَّثَنَا مُسْلِمٌ حَدَّثَنَا شُعْبَةُ عَنْ مُحَمَّدِ بْنِ زِيَادٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْعَجْمَاءُ عَقْلُهَا جُبَارٌ وَالْبِئْرُ جُبَارٌ وَالْمَعْدِنُ جُبَارٌ وَفِي الرِّكَازِ الْخُمُسُ","id":"Telah menceritakan kepada kami [Muslim] telah menceritakan kepada kami [Syu'bah] dari [Muhammad bin Ziyad] dari [Abu Hurairah] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam bersabda: \"Binatang ternak yang mencederai tak berkewajiban membayar diyat, sumur yang menjadikan celaka juga tak ada diyat, pertambangan yang menjadikan celaka juga tak ada diyat, dan harta karun zakatnya seperlima.\""},"6069":{"ar":"حَدَّثَنَا قَيْسُ بْنُ حَفْصٍ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا الْحَسَنُ حَدَّثَنَا مُجَاهِدٌ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَتَلَ نَفْسًا مُعَاهَدًا لَمْ يَرِحْ رَائِحَةَ الْجَنَّةِ وَإِنَّ رِيحَهَا لَيُوجَدُ مِنْ مَسِيرَةِ أَرْبَعِينَ عَامًا","id":"Telah menceritakan kepada kami [Qais bin Hafsh] telah menceritakan kepada kami [Abdul Wahid] telah menceritakan kepada kami [Al Hasan] telah menceritakan kepada kami [Mujahid] dari [Abdullah bin Amru] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Siapa yang membunuh orang kafir yang telah mengikat perjanjian (mu'ahid) dengan pemerintahan muslimin, ia tak dapat mencium harum surga, padahal harum surga dapat dicium dari jarak empat puluh tahun.\""},"6070":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا مُطَرِّفٌ أَنَّ عَامِرًا حَدَّثَهُمْ عَنْ أَبِي جُحَيْفَةَ قَالَ قُلْتُ لِعَلِيٍّ ح حَدَّثَنَا صَدَقَةُ بْنُ الْفَضْلِ أَخْبَرَنَا ابْنُ عُيَيْنَةَ حَدَّثَنَا مُطَرِّفٌ سَمِعْتُ الشَّعْبِيَّ يُحَدِّثُ قَالَ سَمِعْتُ أَبَا جُحَيْفَةَ قَالَ سَأَلْتُ عَلِيًّا رَضِيَ اللَّهُ عَنْهُهَلْ عِنْدَكُمْ شَيْءٌ مِمَّا لَيْسَ فِي الْقُرْآنِ وَقَالَ ابْنُ عُيَيْنَةَ مَرَّةً مَا لَيْسَ عِنْدَ النَّاسِ فَقَالَ وَالَّذِي فَلَقَ الْحَبَّةَ وَبَرَأَ النَّسَمَةَ مَا عِنْدَنَا إِلَّا مَا فِي الْقُرْآنِ إِلَّا فَهْمًا يُعْطَى رَجُلٌ فِي كِتَابِهِ وَمَا فِي الصَّحِيفَةِ قُلْتُ وَمَا فِي الصَّحِيفَةِ قَالَ الْعَقْلُ وَفِكَاكُ الْأَسِيرِ وَأَنْ لَا يُقْتَلَ مُسْلِمٌ بِكَافِرٍ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Mutharrif], bahwa [Amir] menceritakan kepada mereka, dari [Abu Juhaifah] mengatakan; Pernah aku berkata kepada [Ali] -lewat jalur periwayatan lain-telah menceritakan kepada kami [Shadaqoh bin Al Fadhl] telah mengabarkan kepada kami [Ibnu 'Uyainah] telah menceritakan kepada kami [Mutharrif] Aku mendengar [Asy Sya'bi] menceritakan dengan mengatakan; aku mendengar [Abu Juhaifah] mengatakan; aku bertanya kepada [Ali radliallahu 'anhu]; 'Apakah kamu mempunyai sesuatu yang tidak terdapat didalam alqur'an? ' sesekali Ibnu Uyainah mengatakan dengan redaksi; 'sesuatu yang tidak dimiliki manusia? ' ia menjawab; 'Demi Dzat yang membelah biji-bijian dan mencipta manusia, kami tidak mempunyai selain yang terdapat dalam al Qur`an, kecuali pemahaman yang diberikan kepada seseorang terhadap kitabNya dan yang terdapat dalam shahifah.' Saya bertanya; 'apa yang terdapat dalam shahifah? ' ia menjawab: 'kewajiban membayar diyat, membebaskan tawanan dan tidak boleh seorang muslim dibunuh karena orang kafir."},"6071":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ يَحْيَى عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُخَيِّرُوا بَيْنَ الْأَنْبِيَاءِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Amru bin Yahya] dari [Ayahnya] dari [Abu Sa'id] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Jangan kalian memilih-milih diantara para nabi.\""},"6072":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ يَحْيَى الْمَازِنِيِّ عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَجَاءَ رَجُلٌ مِنْ الْيَهُودِ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ لُطِمَ وَجْهُهُ فَقَالَ يَا مُحَمَّدُ إِنَّ رَجُلًا مِنْ أَصْحَابِكَ مِنْ الْأَنْصَارِ قَدْ لَطَمَ فِي وَجْهِي قَالَ ادْعُوهُ فَدَعَوْهُ قَالَ لِمَ لَطَمْتَ وَجْهَهُ قَالَ يَا رَسُولَ اللَّهِ إِنِّي مَرَرْتُ بِالْيَهُودِ فَسَمِعْتُهُ يَقُولُ وَالَّذِي اصْطَفَى مُوسَى عَلَى الْبَشَرِ قَالَ قُلْتُ وَعَلَى مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَأَخَذَتْنِي غَضْبَةٌ فَلَطَمْتُهُ قَالَ لَا تُخَيِّرُونِي مِنْ بَيْنِ الْأَنْبِيَاءِ فَإِنَّ النَّاسَ يَصْعَقُونَ يَوْمَ الْقِيَامَةِ فَأَكُونُ أَوَّلَ مَنْ يُفِيقُ فَإِذَا أَنَا بِمُوسَى آخِذٌ بِقَائِمَةٍ مِنْ قَوَائِمِ الْعَرْشِ فَلَا أَدْرِي أَفَاقَ قَبْلِي أَمْ جُوزِيَ بِصَعْقَةِ الطُّورِ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Amru bin Yahya Al Mazini] dari [ayahnya] dari [Abu Sa'id Al Khudzri] mengatakan, seorang laki-laki yahudi mendatangi Nabi shallallahu 'alaihi wasallam yang ketika itu wajahnya telah ditempeleng, ia berujar; 'Hai Muhammad, salah seorang sahabatmu dari Anshar telah menempeleng wajahku.' Nabi bersabda; \"panggil dia!\" Lantas para sahabat memanggilnya, dan Nabi bertanya: \"Mengapa kau tempeleng wajahnya?\" dia menjawab; 'ya Rasulullah, aku melewati orang-orang yahudi, lalu aku mendengar dia mengatakan; 'Demi Dzat yang memilih Musa diatas semua manusia.' Saya berujar; 'Dan diatas Muhammad Shallallahu'alaihiwasallam.' Maka pada saat itu aku terbawa amarah, sehingga aku menempelengnya.' Nabi terus bersabda: \"Jangan kalian memilih-memilih aku diantara para nabi, sebab padahari kiamat nanti manusia pingsan, dan aku yang pertama-tama sadarkan diri, namun ternyata Musa telah memegang penyangga arsy, saya tidak tahu, apakah dia siuman sebelumku ataukah ia telah memperoleh pembalasan dari kepingsanannya di bukit Tursina.\""},"6073":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ الَّذِينَ آمَنُوا وَلَمْ يَلْبِسُوا إِيمَانَهُمْ بِظُلْمٍ }شَقَّ ذَلِكَ عَلَى أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالُوا أَيُّنَا لَمْ يَلْبِسْ إِيمَانَهُ بِظُلْمٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُ لَيْسَ بِذَاكَ أَلَا تَسْمَعُونَ إِلَى قَوْلِ لُقْمَانَ{ إِنَّ الشِّرْكَ لَظُلْمٌ عَظِيمٌ }","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Ibrahim] dari [Alqomah] dari [Abdullah] radliallahu 'anhu, mengatakan; 'Dikala diturunkan ayat; 'Sesungguhnya orang yang beriman dan tidak mencampur adukkan keimanan mereka dengan kezhaliman' (QS. Al an'am 82), para sahabat Nabi shallallahu 'alaihi wasallam merasa gusar, sehingga bertanya; 'Siapakah diantara kami yang tidak mencampur keimananya dengan kezjhaliman? ' Maka Rasulullah Shallallahu'alaihiwasallam menjawab; \"Bukan itu yang dimaksudkan, tidakkah kalian mendengar ucapan Luqman; 'sesungguhnya kesyirikan adalah kezhaliman yang besar\" (QS. Luqman 13) "},"6074":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ حَدَّثَنَا الْجُرَيْرِيُّ ح و حَدَّثَنِي قَيْسُ بْنُ حَفْصٍ حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا سَعِيدٌ الْجُرَيْرِيُّ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي بَكْرَةَ عَنْ أَبِيهِ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكْبَرُ الْكَبَائِرِ الْإِشْرَاكُ بِاللَّهِ وَعُقُوقُ الْوَالِدَيْنِ وَشَهَادَةُ الزُّورِ وَشَهَادَةُ الزُّورِ ثَلَاثًا أَوْ قَوْلُ الزُّورِ فَمَا زَالَ يُكَرِّرُهَا حَتَّى قُلْنَا لَيْتَهُ سَكَتَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Bisyr bin Mufadhdhal] telah menceritakan kepada kami [Al Jurairi] -lewat jalur periwayatan lain- telah menceritakan kepadaku [Qais bin Hafsh] telah menceritakan kepada kami [Isma'il bin Ibrahim] Telah mengabarkan kepada kami [Sa'id Al Jurairi] telah menceritakan kepada kami [Abdurrahman bin Abu Bakrah] dari [ayahnya] radliallahu 'anhu mengatakan, Nabi shallallahu 'alaihi wasallam bersabda: \"Dosa yang paling besar diantara dosa-dosa besar lainnya adalah menyekutukan Allah, durhaka kepada orang tua, kesaksian palsu, kesaksian palsu (beliau mengulanginya tiga kali), atau ucapan dusta, \" beliau tidak henti-henti mengulang-ulanginya sehingga kami mengatakan; 'Duhai, sekiranya beliau diam.' "},"6075":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ الْحُسَيْنِ بْنِ إِبْرَاهِيمَ أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى أَخْبَرَنَا شَيْبَانُ عَنْ فِرَاسٍ عَنْ الشَّعْبِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو رَضِيَ اللَّهُ عَنْهُمَا قَالَجَاءَ أَعْرَابِيٌّ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ مَا الْكَبَائِرُ قَالَ الْإِشْرَاكُ بِاللَّهِ قَالَ ثُمَّ مَاذَا قَالَ ثُمَّ عُقُوقُ الْوَالِدَيْنِ قَالَ ثُمَّ مَاذَا قَالَ الْيَمِينُ الْغَمُوسُ قُلْتُ وَمَا الْيَمِينُ الْغَمُوسُ قَالَ الَّذِي يَقْتَطِعُ مَالَ امْرِئٍ مُسْلِمٍ هُوَ فِيهَا كَاذِبٌ","id":"telah menceritakan kepadaku [Muhammad bin Al Husain bin Ibrahim] telah mengabarkan kepada kami [Ubaidullah bin Musa] Telah mengabarkan kepada kami [Syaiban] dari [Firas] dari [Asy Sya'bi] dari [Abdullah bin Amru] mengatakan; Seorang arab badui menemui Nabi shallallahu 'alaihi wasallam dan bertanya; 'Waya Rasulullah, apa yang dianggap dosa-dosa besar itu? ' Beliau menjawab: \"Menyekutukan Allah\" 'Lantas selanjutnya apa? ' Tanyanya. Nabi menjawab: \"Mendurhakai orang tua.\" 'selanjutnya apa? ' Tanyanya. Nabi shallallahu 'alaihi wasallam menjawab: \"Sumpah ghamus.\" Kami bertanya; 'apa makna ghamus? ' Beliau jawab; \"maknanya sumpah palsu, dusta, yang karena sumpahnya ia bisa menguasai harta seorang muslim, padahal sumpahnya bohong belaka.\""},"6076":{"ar":"حَدَّثَنَا خَلَّادُ بْنُ يَحْيَى حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ وَالْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ ابْنِ مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ أَنُؤَاخَذُ بِمَا عَمِلْنَا فِي الْجَاهِلِيَّةِ قَالَ مَنْ أَحْسَنَ فِي الْإِسْلَامِ لَمْ يُؤَاخَذْ بِمَا عَمِلَ فِي الْجَاهِلِيَّةِ وَمَنْ أَسَاءَ فِي الْإِسْلَامِ أُخِذَ بِالْأَوَّلِ وَالْآخِرِ","id":"Telah menceritakan kepada kami [Khallad bin Yahya] telah menceritakan kepada kami [Sufyan] dari [Manshur] dan [Al A'masy] dari [Abu Wa`il] dari [Ibnu Mas'ud] radliallahu 'anhu mengatakan, seorang laki-laki bertanya; 'ya Rasulullah, apakah kami dihukum karena kelakuan-kelakuan kami semasa jahiliyah? ' Nabi menjawab: \"Barangsia berbuat baik dalam Islam, maka tak dihukum kelakuan-kelakuannya semasa jahiliyah, sebaliknya barangsiapa berbuat buruk dalam Islam, ia dihukum semenjak kelakuan awalnya dan akhirnya.\" "},"6077":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ مُحَمَّدُ بْنُ الْفَضْلِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ عِكْرِمَةَ قَالَأُتِيَ عَلِيٌّ رَضِيَ اللَّهُ عَنْهُ بِزَنَادِقَةٍ فَأَحْرَقَهُمْ فَبَلَغَ ذَلِكَ ابْنَ عَبَّاسٍ فَقَالَ لَوْ كُنْتُ أَنَا لَمْ أُحْرِقْهُمْ لِنَهْيِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُعَذِّبُوا بِعَذَابِ اللَّهِ وَلَقَتَلْتُهُمْ لِقَوْلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ بَدَّلَ دِينَهُ فَاقْتُلُوهُ","id":"Telah menceritakan kepada kami [Abu Nu'man Muhammad bin Fadhl] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Ikrimah] mengatakan, beberapa orang Zindiq diringkus dan dihadapkan kepada Ali radliallahu 'anhu, lalu Ali membakar mereka. Kasus ini terdengar oleh [Ibnu Abbas], sehingga ia berujar; 'Kalau aku, aku tak akan membakar mereka karena ada larangan Rasulullah Shallallahu'alaihiwasallam yang bersabda: \"Janganlah kalian menyiksa dengan siksaan Allah, \" dan aku tetap akan membunuh mereka sesuai sabda Rasulullah Shallallahu'alaihiwasallam: \"Siapa yang mengganti agamanya, bunuhlah!\""},"6078":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ قُرَّةَ بْنِ خَالِدٍ حَدَّثَنِي حُمَيْدُ بْنُ هِلَالٍ حَدَّثَنَا أَبُو بُرْدَةَ عَنْ أَبِي مُوسَى قَالَأَقْبَلْتُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعِي رَجُلَانِ مِنْ الْأَشْعَرِيِّينَ أَحَدُهُمَا عَنْ يَمِينِي وَالْآخَرُ عَنْ يَسَارِي وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْتَاكُ فَكِلَاهُمَا سَأَلَ فَقَالَ يَا أَبَا مُوسَى أَوْ يَا عَبْدَ اللَّهِ بْنَ قَيْسٍ قَالَ قُلْتُ وَالَّذِي بَعَثَكَ بِالْحَقِّ مَا أَطْلَعَانِي عَلَى مَا فِي أَنْفُسِهِمَا وَمَا شَعَرْتُ أَنَّهُمَا يَطْلُبَانِ الْعَمَلَ فَكَأَنِّي أَنْظُرُ إِلَى سِوَاكِهِ تَحْتَ شَفَتِهِ قَلَصَتْ فَقَالَ لَنْ أَوْ لَا نَسْتَعْمِلُ عَلَى عَمَلِنَا مَنْ أَرَادَهُ وَلَكِنْ اذْهَبْ أَنْتَ يَا أَبَا مُوسَى أَوْ يَا عَبْدَ اللَّهِ بْنَ قَيْسٍ إِلَى الْيَمَنِ ثُمَّ اتَّبَعَهُ مُعَاذُ بْنُ جَبَلٍ فَلَمَّا قَدِمَ عَلَيْهِ أَلْقَى لَهُ وِسَادَةً قَالَ انْزِلْ وَإِذَا رَجُلٌ عِنْدَهُ مُوثَقٌ قَالَ مَا هَذَا قَالَ كَانَ يَهُودِيًّا فَأَسْلَمَ ثُمَّ تَهَوَّدَ قَالَ اجْلِسْ قَالَ لَا أَجْلِسُ حَتَّى يُقْتَلَ قَضَاءُ اللَّهِ وَرَسُولِهِ ثَلَاثَ مَرَّاتٍ فَأَمَرَ بِهِ فَقُتِلَ ثُمَّ تَذَاكَرَا قِيَامَ اللَّيْلِ فَقَالَ أَحَدُهُمَا أَمَّا أَنَا فَأَقُومُ وَأَنَامُ وَأَرْجُو فِي نَوْمَتِي مَا أَرْجُو فِي قَوْمَتِي","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Qurrah bin Khalid] telah menceritakan kepadaku [Humaid bin Hilal] telah menceritakan kepada kami [Abu Burdah] dari [Abu Musa] mengatakan, Aku berangkat menemui Nabi shallallahu 'alaihi wasallam bersama dua orang asy'ari, satunya di sebelah kananku dan satunya di sebelah kiriku, sedang Rasulullah Shallallahu'alaihiwasallam tengah bersiwak. Keduanya sama-sama meminta pekerjaan (jabatan). Kemudian Nabi berujar: \"Wahai Abu Musa atau hai Abdullah bin Qais\" Abu Musa berkata; maka Saya menjawab; 'demi Dzat yang mengutusmu dengan kebenaran, kedua tamu itu tidak mengungkapkan isi hati mereka, dan aku tidak merasa bahwa keduanya minta pekerjaan (jabatan).' dan seolah-olah aku melihat siwak beliau dibawah bibirnya mengempes. Kemudian Nabi bersabda: \"Sekali-kali aku tidak akan mempekerjakan tugas-tugas kita kepada orang yang memintanya (menginginkannya), akan tetapi kamu ya Abu Musa atau ya Abdullah bin Qais, pergilah ke Yaman.\" kemudian Mu'adz bin jabal menyusulnya. Ketika Mu'adz bin jabal menemuinya, Abu Musa menghamparkan bantal dan berujar; 'Turunlah'. Ternyata disisinya ada seorang laki-laki yang terikat. Muadz bertanya; 'kenapa dengan orang ini? ' Abu Musa menjawab; 'dahulu dia seorang yahudi, lantas masuk Islam dan kembali lagi memeluk agama yahudinya.' Maka Abu Musa berujar; 'Duduklah engkau! ' Mu'adz menjawab; 'Saya tidak akan duduk hingga dia dibunuh untuk menunaikan ketetapan Allah dan rasul-NYA' (ia mengulang tiga kali), maka Abu Musa memerintahkan untuk membunuh yahudi tersebut. Keduanya kemudian berbincang-bincang masalah shalat malam. Satunya mengatakan; 'Adapun aku shalat malam namun juga tidur, dan kuharap dari tidurku (mendapat pahala) sebagaimana aku berharap memperoleh pahala bersama di kaumku.'"},"6079":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ أَنَّ أَبَا هُرَيْرَةَ قَالَلَمَّا تُوُفِّيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاسْتُخْلِفَ أَبُو بَكْرٍ وَكَفَرَ مَنْ كَفَرَ مِنْ الْعَرَبِ قَالَ عُمَرُ يَا أَبَا بَكْرٍ كَيْفَ تُقَاتِلُ النَّاسَ وَقَدْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمِرْتُ أَنْ أُقَاتِلَ النَّاسَ حَتَّى يَقُولُوا لَا إِلَهَ إِلَّا اللَّهُ فَمَنْ قَالَ لَا إِلَهَ إِلَّا اللَّهُ فَقَدْ عَصَمَ مِنِّي مَالَهُ وَنَفْسَهُ إِلَّا بِحَقِّهِ وَحِسَابُهُ عَلَى اللَّهِ قَالَ أَبُو بَكْرٍ وَاللَّهِ لَأُقَاتِلَنَّ مَنْ فَرَّقَ بَيْنَ الصَّلَاةِ وَالزَّكَاةِ فَإِنَّ الزَّكَاةَ حَقُّ الْمَالِ وَاللَّهِ لَوْ مَنَعُونِي عَنَاقًا كَانُوا يُؤَدُّونَهَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَاتَلْتُهُمْ عَلَى مَنْعِهَاقَالَ عُمَرُ فَوَاللَّهِ مَا هُوَ إِلَّا أَنْ رَأَيْتُ أَنْ قَدْ شَرَحَ اللَّهُ صَدْرَ أَبِي بَكْرٍ لِلْقِتَالِ فَعَرَفْتُ أَنَّهُ الْحَقُّ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari [Uqail] dari [Ibnu Syihab] telah mengabarkan kepadaku [Ubaidullah bin Abdullah bin 'Utbah], bahwasanya [Abu Hurairah] mengatakan; Tatkala Nabi shallallahu 'alaihi wasallam wafat dan Abu Bakar diangkat menjadi khalifah, beberapa orang arab menjadi kafir, lalu [Umar] bertanya; 'Hai Abu bakar, bagaimana engkau memerangi manusia padahal Rasulullah Shallallahu'alaihiwasallam bersabda; \"Saya diperintahkan memerangi manusia hingga mereka mengucapkan laa-ilaaha-illallah, siapa yang telah mengucapkan laa-ilaaha-illallah, berarti ia telah menjaga kehormatan darahnya dan jiwanya kecuali karena alasan yang dibenarkan dan hisabnya kepada Allah.\" [Abu Bakar] menjawab; 'Demi Allah, saya akan terus memerangi siapa saja yang memisahkan antara shalat dan zakat, sebab zakat adalah hak harta, Demi Allah, kalaulah mereka menghalangiku dari anak kambing yang pernah mereka bayarkan kepada Rasulullah Shallallahu'alaihiwasallam, niscaya aku perangi mereka karena tidak membayarnya.' Umar kemudian berkata; 'Demi Allah, tiada lain kuanggap memang Allah telah melapangkan Abu Bakar untuk memerangi dan aku sadar bahwa yang dilakukannya adalah benar.'"},"6080":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَبُو الْحَسَنِ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا شُعْبَةُ عَنْ هِشَامِ بْنِ زَيْدِ بْنِ أَنَسِ بْنِ مَالِكٍ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُمَرَّ يَهُودِيٌّ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ السَّامُ عَلَيْكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَدْرُونَ مَا يَقُولُ قَالَ السَّامُ عَلَيْكَ قَالُوا يَا رَسُولَ اللَّهِ أَلَا نَقْتُلُهُ قَالَ لَا إِذَا سَلَّمَ عَلَيْكُمْ أَهْلُ الْكِتَابِ فَقُولُوا وَعَلَيْكُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil Abul Hasan] Telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Syu'bah] dari [Hisyam bin Zaid bin Anas bin Malik] mengatakan, aku mendengar [Anas bin malik] mengatakan; seorang yahudi melewati Rasulullah Shallallahu'alaihiwasallam dan mengucapkan; 'Assaam 'alaikum (kiranya kalian tertimpa kematian).' Maka Rasulullah shallallahu 'alaihi wasallam menjawab: \"wa'ailaika (Dan untukmu).' kemudian Rasulullah shallallahu 'alaihi wasallam bertanya; \"tahukah kalian apa yang diucapkannya? dia telah mengatakan; 'alaikum (Semoga kalian tertimpa kematian).\" Maka para sahabat menjawab; 'bagaimana kalau dia kami bunuh? ' Nabi menjawab; \"jangan, jika ahlu kitab mengucapkan salam kepada kalian, jawablah; wa'alaikum (kepada kalian kematian)!\""},"6081":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ عَنْ ابْنِ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْاسْتَأْذَنَ رَهْطٌ مِنْ الْيَهُودِ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا السَّامُ عَلَيْكَ فَقُلْتُ بَلْ عَلَيْكُمْ السَّامُ وَاللَّعْنَةُ فَقَالَ يَا عَائِشَةُ إِنَّ اللَّهَ رَفِيقٌ يُحِبُّ الرِّفْقَ فِي الْأَمْرِ كُلِّهِ قُلْتُ أَوَلَمْ تَسْمَعْ مَا قَالُوا قَالَ قُلْتُ وَعَلَيْكُمْ","id":"Telah menceritakan kepada kami [Abu Nu'aim] dari [Ibnu Uyainah] dari [Az Zuhri] dari [Urwah] dari [Aisyah] radliallahu 'anha mengatakan; Sekelompok orang yahudi meminta izin kepada Nabi shallallahu 'alaihi wasallam dan mengucapkan; 'Assaam 'alaika (semoga kematian tertimpa kepada kalian), saya menjawab; 'bal 'alaikum Assam wal la'nah (Bahkan untuk kalian kematian dan juga laknat).' Maka Nabi berujar; 'hai Aisyah, bahwasanya Allah menyukai kelembutan dalam segala urusan.' Saya menjawab; 'Tidakkah engkau mendengar apa yang mereka ucapkan? ' Beliau menjawab: \"Saya menjawab; wa'alaikum (bahkan untuk kalian).\""},"6082":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سُفْيَانَ وَمَالِكِ بْنِ أَنَسٍ قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دِينَارٍ قَالَ سَمِعْتُ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْيَهُودَ إِذَا سَلَّمُوا عَلَى أَحَدِكُمْ إِنَّمَا يَقُولُونَ سَامٌ عَلَيْكَ فَقُلْ عَلَيْكَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sufyan] dan [Malik bin Anas] mengatakan, telah menceritakan kepada kami [Abdullah bin Dinar] mengatakan, aku mendengar [Ibnu Umar] radliallahu 'anhu mengatakan; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kaum yahudi mengucapkan salam kepada salah seorang diantara kalian, kemudian mereka katakan; Saamun 'alaika (kiranya kamu tertimpa kematian), maka katakanlah; wa'alaika (bahkan untukmu).\""},"6083":{"ar":"بَاب حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ قَالَ حَدَّثَنِي شَقِيقٌ قَالَ قَالَ عَبْدُ اللَّهِكَأَنِّي أَنْظُرُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَحْكِي نَبِيًّا مِنْ الْأَنْبِيَاءِ ضَرَبَهُ قَوْمُهُ فَأَدْمَوْهُ فَهُوَ يَمْسَحُ الدَّمَ عَنْ وَجْهِهِ وَيَقُولُ رَبِّ اغْفِرْ لِقَوْمِي فَإِنَّهُمْ لَا يَعْلَمُونَ","id":"Telah menceritakan kepada kami [Umar bin Hafsh] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Al A'masy] mengatakan, telah menceritakan kepadaku [Syaqiq] mengatakan, [Abdullah] mengatakan, Seakan-akan aku melihat Nabi shallallahu 'alaihi wasallam mengisahkan seorang Nabi yang ditempeleng oleh kaumnya sambil ia menyeka darah dari wajahnya dan memanjatkan doa; 'ya Rabbi, ampunilah kaumku, sebab mereka adalah orang yang tidak tahu.'"},"6084":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ حَدَّثَنَا خَيْثَمَةُ حَدَّثَنَا سُوَيْدُ بْنُ غَفَلَةَ قَالَ عَلِيٌّ رَضِيَ اللَّهُ عَنْهُإِذَا حَدَّثْتُكُمْ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدِيثًا فَوَاللَّهِ لَأَنْ أَخِرَّ مِنْ السَّمَاءِ أَحَبُّ إِلَيَّ مِنْ أَنْ أَكْذِبَ عَلَيْهِ وَإِذَا حَدَّثْتُكُمْ فِيمَا بَيْنِي وَبَيْنَكُمْ فَإِنَّ الْحَرْبَ خِدْعَةٌ وَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ سَيَخْرُجُ قَوْمٌ فِي آخِرِ الزَّمَانِ أَحْدَاثُ الْأَسْنَانِ سُفَهَاءُ الْأَحْلَامِ يَقُولُونَ مِنْ خَيْرِ قَوْلِ الْبَرِيَّةِ لَا يُجَاوِزُ إِيمَانُهُمْ حَنَاجِرَهُمْ يَمْرُقُونَ مِنْ الدِّينِ كَمَا يَمْرُقُ السَّهْمُ مِنْ الرَّمِيَّةِ فَأَيْنَمَا لَقِيتُمُوهُمْ فَاقْتُلُوهُمْ فَإِنَّ فِي قَتْلِهِمْ أَجْرًا لِمَنْ قَتَلَهُمْ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Umar bin Hafsh bin Ghiyats] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Al A'masy] telah menceritakan kepada kami [Khaitsumah] telah menceritakan kepada kami [Suwaid bin Ghaflah] mengatakan, [Ali] radliallahu 'anhu mengatakan; \"Jika saya menyampaikan sebuah hadits kepada kalian dari Rasulullah shallallahu 'alaihi wasallam, demi Allah, saya terjatuh dari langit adalah lebih aku sukai daripada aku mendustakannya. Karenanya, akan saya ceritakan kepada kalian sesuatu yang akan terjadi diantara saya dan kalian, sesungguhnya perang adalah tipu daya, dan aku mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Di akhir jaman nanti muncul suatu kaum yang umur-umur mereka masih muda, pikiran-pikiran mereka bodoh, mereka mengatakan dari sebaik-baik manusia, padahal iman mereka tak sampai melewati kerongkongan, mereka keluar dari agama sebagaimana anak panah keluar dari busurnya, dimanapun kalian menemukannya, bunuhlah dia, sebab siapa membunuhnya mendatangkan ganjaran pagi pelakunya di hari kiamat.\""},"6085":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ قَالَ سَمِعْتُ يَحْيَى بْنَ سَعِيدٍ قَالَ أَخْبَرَنِي مُحَمَّدُ بْنُ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ وَعَطَاءِ بْنِ يَسَارٍ أَنَّهُمَا أَتَيَا أَبَا سَعِيدٍ الْخُدْرِيَّفَسَأَلَاهُ عَنْ الْحَرُورِيَّةِ أَسَمِعْتَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا أَدْرِي مَا الْحَرُورِيَّةُ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَخْرُجُ فِي هَذِهِ الْأُمَّةِ وَلَمْ يَقُلْ مِنْهَا قَوْمٌ تَحْقِرُونَ صَلَاتَكُمْ مَعَ صَلَاتِهِمْ يَقْرَءُونَ الْقُرْآنَ لَا يُجَاوِزُ حُلُوقَهُمْ أَوْ حَنَاجِرَهُمْ يَمْرُقُونَ مِنْ الدِّينِ مُرُوقَ السَّهْمِ مِنْ الرَّمِيَّةِ فَيَنْظُرُ الرَّامِي إِلَى سَهْمِهِ إِلَى نَصْلِهِ إِلَى رِصَافِهِ فَيَتَمَارَى فِي الْفُوقَةِ هَلْ عَلِقَ بِهَا مِنْ الدَّمِ شَيْءٌ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Abdul Wahhab] mengatakan, aku mendengar [Yahya bin Sa'id] mengatakan, Telah mengabarkan kepadaku [Muhammad bin Ibrahim] dari [Abu Salamah] dan ['Atho' bin Yasar] bahwasanya keduanya pernah mendatangi [Abu Sa'id Al Khudri] dan menanyainya tentang sekte Haruriyah; 'apakah engkau mendengar dari Nabi shallallahu 'alaihi wasallam? ' Ia mengatakan; 'Saya tidak tahu menahu tentang haruriyah, hanyasaja Aku mendengar Nabi Shallallahu'alaihi wasalalm bersabda; \"Akan muncul di kalangan umat ini -dan ia tidak mengatakan dari umat ini- suatu kaum yang kalian akan meremehkan shalat kalian bila di bandingkan dengan shalat mereka, mereka membaca al Qur`an namun tidak melewati kerongkongan atau tenggorokan mereka, mereka keluar dari agama sebagimana anak panah keluar dari busurnya, lantas sang pelempar melihat anak panahnya, mata panahnya hingga kain panahnya, hingga seolah-olah anak panah itu keluar dalam tempat senar, apakah ada darah yang menempel?\""},"6086":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سُلَيْمَانَ حَدَّثَنِي ابْنُ وَهْبٍ قَالَ حَدَّثَنِي عُمَرُ أَنَّ أَبَاهُ حَدَّثَهُ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَوَذَكَرَ الْحَرُورِيَّةَ فَقَالَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْرُقُونَ مِنْ الْإِسْلَامِ مُرُوقَ السَّهْمِ مِنْ الرَّمِيَّةِ","id":"Telah menceritakan kepada kami [Yahya bin Sulaiman] telah menceritakan kepadaku [Ibnu Wahb] mengatakan, telah menceritakan kepadaku [Umar] bahwasanya [Ayahnya] menceritakan kepadanya dari [Abdullah bin Umar] dan ia menceritakan tentang al hariuriyah, kemudian dia menuturkan; Nabi shallallahu 'alaihi wasallam bersabda: \"Mereka keluar dari Islam, sebagaimana anak panah keluar dari busurnya.\""},"6087":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا هِشَامٌ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي سَعِيدٍ قَالَبَيْنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْسِمُ جَاءَ عَبْدُ اللَّهِ بْنُ ��ِي الْخُوَيْصِرَةِ التَّمِيمِيُّ فَقَالَ اعْدِلْ يَا رَسُولَ اللَّهِ فَقَالَ وَيْلَكَ وَمَنْ يَعْدِلُ إِذَا لَمْ أَعْدِلْ قَالَ عُمَرُ بْنُ الْخَطَّابِ دَعْنِي أَضْرِبْ عُنُقَهُ قَالَ دَعْهُ فَإِنَّ لَهُ أَصْحَابًا يَحْقِرُ أَحَدُكُمْ صَلَاتَهُ مَعَ صَلَاتِهِ وَصِيَامَهُ مَعَ صِيَامِهِ يَمْرُقُونَ مِنْ الدِّينِ كَمَا يَمْرُقُ السَّهْمُ مِنْ الرَّمِيَّةِ يُنْظَرُ فِي قُذَذِهِ فَلَا يُوجَدُ فِيهِ شَيْءٌ ثُمَّ يُنْظَرُ فِي نَصْلِهِ فَلَا يُوجَدُ فِيهِ شَيْءٌ ثُمَّ يُنْظَرُ فِي رِصَافِهِ فَلَا يُوجَدُ فِيهِ شَيْءٌ ثُمَّ يُنْظَرُ فِي نَضِيِّهِ فَلَا يُوجَدُ فِيهِ شَيْءٌ قَدْ سَبَقَ الْفَرْثَ وَالدَّمَ آيَتُهُمْ رَجُلٌ إِحْدَى يَدَيْهِ أَوْ قَالَ ثَدْيَيْهِ مِثْلُ ثَدْيِ الْمَرْأَةِ أَوْ قَالَ مِثْلُ الْبَضْعَةِ تَدَرْدَرُ يَخْرُجُونَ عَلَى حِينِ فُرْقَةٍ مِنْ النَّاسِ قَالَ أَبُو سَعِيدٍ أَشْهَدُ سَمِعْتُ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَشْهَدُ أَنَّ عَلِيًّا قَتَلَهُمْ وَأَنَا مَعَهُ جِيءَ بِالرَّجُلِ عَلَى النَّعْتِ الَّذِي نَعَتَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَنَزَلَتْ فِيهِ{ وَمِنْهُمْ مَنْ يَلْمِزُكَ فِي الصَّدَقَاتِ }","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] telah menceritakan kepada kami [Hisyam] Telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Abu Salamah] dai [Abu Sa'id] mengatakan; Ketika Nabi shallallahu 'alaihi wasallam sedang membagi (harta rampasan), tiba-tiba Adbdullah bin Dzil huwaishirah At Tamimi datang seraya menegur Nabi; 'Hendaklah engkau berbuat adil! ' Spontan Nabi menjawab: \"siapa lagi yang berbuat adil jika aku tak berbuat adil?\" Umar kemudian berujar; 'Biarkan aku yang memenggal lehernya! ' Nabi bersabda; \"Biarkan saja dia, sebab dia mempunyai beberapa kawan yang salah seorang diantara kalian meremehkan shalatnya dibanding dengan shalatnya, dan meremehkan puasanya dibanding puasanya, mereka keluar dari agama sebagaimana anak panah keluar dari busur, ia melihat bulu anak panahnya namun tak ada apa-apa, kemudian memperhatikan mata anak panahnya namun tidak ditemukan apa-apa, kemudian melihat kain panahnya namun tidak didapatkan apa-apa, dan telah didahulu oleh kotoran dan darah. Tanda-tanda mereka adalah salah satu diantara kedua tangannya -atau- diantara kedua putingnya seperti puting kaum perempuan atau ia seperti daging yang bergerak-gerak, mereka muncul ketika manusia mengalami perpecahan.\" Sedang Abu Sa'id mengatakan; aku bersaksi bahwa aku mendengar dari Nabi shallallahu 'alaihi wasallam shallallahu 'alaihi wasallam, dan aku bersaksi bahwa 'Ali membunuh mereka dan aku bersamanya ketika didatangkan seseorang yang ciri-cirinya seperti yang disifatkan Nabi shallallahu 'alaihi wasallam, lantas diturunlah ayat; 'Diantara mereka ada yang mengolok-olokmu karena sedekah yang kamu infakkan' (QS. Attaubah 58)."},"6088":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا الشَّيْبَانِيُّ حَدَّثَنَا يُسَيْرُ بْنُ عَمْرٍو قَالَ قُلْتُ لِسَهْلِ بْنِ حُنَيْفٍهَلْ سَمِعْتَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي الْخَوَارِجِ شَيْئًا قَالَ سَمِعْتُهُ يَقُولُ وَأَهْوَى بِيَدِهِ قِبَلَ الْعِرَاقِ يَخْرُجُ مِنْهُ قَوْمٌ يَقْرَءُونَ الْقُرْآنَ لَا يُجَاوِزُ تَرَاقِيَهُمْ يَمْرُقُونَ مِنْ الْإِسْلَامِ مُرُوقَ السَّهْمِ مِنْ الرَّمِيَّةِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Abdul Wahid] telah menceritakan kepada kami [Asy Syaibani] telah menceritakan kepada kami [Yusair bin Amru] mengatakan, aku bertanya kepada [Sahal bin Hunaif]; 'apakah engkau mendengar Nabi shallallahu 'alaihi wasallam bersabda tentang Khawarij? ' Ia menjawab; aku mendengar beliau bersabda; -sambil beliau arahkan tangannya menuju Irak- \"Dari sanalah muncul sekelompok kaum yang membaca al Qur`an tidak melebihi kerongkongan mereka, mereka keluar dari Islam sebagaimana anak panah keluar dari busurnya.\""},"6089":{"ar":"حَدَّثَنَا عَلِيٌّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقُومُ السَّاعَةُ حَتَّى تَقْتَتِلَ فِئَتَانِ دَعْوَاهُمَا وَاحِدَةٌ","id":"Telah menceritakan kepada kami [Ali] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Abu Az Zanad] dari [Al A'raj] dari [Abu Hurairah] radliallahu 'anhu mengatakan, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hari kiamat tidak terjadi hingga dua kelompok saling membunuh, padahal semboyan keduanya satu.\""},"6090":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا وَكِيعٌ ح و حَدَّثَنَا يَحْيَى حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ الَّذِينَ آمَنُوا وَلَمْ يَلْبِسُوا إِيمَانَهُمْ بِظُلْمٍ }شَقَّ ذَلِكَ عَلَى أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالُوا أَيُّنَا لَمْ يَظْلِمْ نَفْسَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ كَمَا تَظُنُّونَ إِنَّمَا هُوَ كَمَا قَالَ لُقْمَانُ لِابْنِهِ{ يَا بُنَيَّ لَا تُشْرِكْ بِاللَّهِ إِنَّ الشِّرْكَ لَظُلْمٌ عَظِيمٌ }","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] Telah mengabarkan kepada kami [Waki'] -lewat jalur periwayatan lain-Telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Ibrahim] dari [Alqomah] dari ['Abdullah] radliallahu 'anhu mengatakan; tatkala turun ayat ini; 'Sesungguhnya orang yang beriman dan tidak mencampuradukkan keimanan mereka dengan kezaliman' (QS.Luqman 82), ayat ini sangat menggusarkan para sahabat Nabi shallallahu 'alaihi wasallam, sehingga mereka bertanya; 'Siapa diantara kami yang tidak melakukan kezaliman terhadap dirinya sendiri? ' lantas Rasulullah Shallallahu'alaihiwasallam bersabda: \"Bukan seperti yang kalian sangka, hanyasanya yang dimaksudkan adalah seperti ucapan Luqman kepada anaknya; 'Wahai anakku, janganlah engkau menyekutukan Allah, sebab menyekutukan Allah adalah kezhaliman yang besar\" (QS.Luqman 82)."},"6091":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ أَخْبَرَنِي مَحْمُودُ بْنُ الرَّبِيعِ قَالَ سَمِعْتُ عِتْبَانَ بْنَ مَالِكٍ يَقُولُغَدَا عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَجُلٌ أَيْنَ مَالِكُ بْنُ الدُّخْشُنِ فَقَالَ رَجُلٌ مِنَّا ذَلِكَ مُنَافِقٌ لَا يُحِبُّ اللَّهَ وَرَسُولَهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا تَقُولُوهُ يَقُولُ لَا إِلَهَ إِلَّا اللَّهُ يَبْتَغِي بِذَلِكَ وَجْهَ اللَّهِ قَالَ بَلَى قَالَ فَإِنَّهُ لَا يُوَافَى عَبْدٌ يَوْمَ الْقِيَامَةِ بِهِ إِلَّا حَرَّمَ اللَّهُ عَلَيْهِ النَّارَ","id":"Telah menceritakan kepada kami ['Abdan] Telah mengabarkan kepada kami [Abdullah] Telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] telah menceritakan kepadaku [Mahmud bin Rabi'] mengatakan, aku mendengar [Itban bin Malik] mengatakan, Rasulullah shallallahu 'alaihi wasallam pernah menemuiku, lantas ada seseorang bertanya; 'mana Malik bin Duhsyun? ' seseorang dari kami mengatakan; 'Dia munafik, tidak mencintai Allah dan Rasul-NYA.' Spontan Nabi shallallahu 'alaihi wasallam bersabda: \"Bukankah kalian katakan bahwa ia mengucapkan; laa-ilaaha-illallah, untuk mencari wajah Allah?\" Ia menjawab; 'Benar'. Maka Nabi bersabda: \"Tidaklah seorang hamba dipenuhi kecintaan kepada Allah, melainkan Allah mengharamkan neraka baginya di hari kiamat.\""},"6092":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ حُصَيْنٍ عَنْ فُلَانٍ قَالَ تَنَازَعَ أَبُو عَبْدِ الرَّحْمَنِ وَحِبَّانُ بْنُ عَطِيَّةَ فَقَالَ أَبُو عَبْدِ الرَّحْمَنِ لِحِبَّانَ لَقَدْ عَلِمْتُ مَا الَّذِي جَرَّأَ صَاحِبَكَ عَلَى الدِّمَاءِ يَعْنِي عَلِيًّا قَالَمَا هُوَ لَا أَبَا لَكَ قَالَ شَيْءٌ سَمِعْتُهُ يَقُولُهُ قَالَ مَا هُوَ قَالَ بَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالزُّبَيْرَ وَأَبَا مَرْثَدٍ وَكُلُّنَا فَارِسٌ قَالَ انْطَلِقُوا حَتَّى تَأْتُوا رَوْضَةَ حَاجٍ قَالَ أَبُو سَلَمَةَ هَكَذَا قَالَ أَبُو عَوَانَةَ حَاجٍ فَإِنَّ فِيهَا امْرَأَةً مَعَهَا صَحِيفَةٌ مِنْ حَاطِبِ بْنِ أَبِي بَلْتَعَةَ إِلَى الْمُشْرِكِينَ فَأْتُونِي بِهَا فَانْطَلَقْنَا عَلَى أَفْرَاسِنَا حَتَّى أَدْرَكْنَاهَا حَيْثُ قَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَسِيرُ عَلَى بَعِيرٍ لَهَا وَقَدْ كَانَ كَتَبَ إِلَى أَهْلِ مَكَّةَ بِمَسِيرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَيْهِمْ فَقُلْنَا أَيْنَ الْكِتَابُ الَّذِي مَعَكِ قَالَتْ مَا مَعِي كِتَابٌ فَأَنَخْنَا بِهَا بَعِيرَهَا فَابْتَغَيْنَا فِي رَحْلِهَا فَمَا وَجَدْنَا شَيْئًا فَقَالَ صَاحِبَايَ مَا نَرَى مَعَهَا كِتَابًا قَالَ فَقُلْتُ لَقَدْ عَلِمْنَا مَا كَذَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ حَلَفَ عَلِيٌّ وَالَّذِي يُحْلَفُ بِهِ لَتُخْرِجِنَّ الْكِتَابَ أَوْ لَأُجَرِّدَنَّكِ فَأَهْوَتْ إِلَى حُجْزَتِهَا وَهِيَ مُحْتَجِزَةٌ بِكِسَاءٍ فَأَخْرَجَتْ الصَّحِيفَةَ فَأَتَوْا بِهَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ عُمَرُ يَا رَسُولَ اللَّهِ قَدْ خَانَ اللَّهَ وَرَسُولَهُ وَالْمُؤْمِنِينَ دَعْنِي فَأَضْرِبَ عُنُقَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا حَاطِبُ مَا حَمَلكَ عَلَى مَا صَنَعْتَ قَالَ يَا رَسُولَ اللَّهِ مَا لِي أَنْ لَا أَكُونَ مُؤْمِنًا بِاللَّهِ وَرَسُولِهِ وَلَكِنِّي أَرَدْتُ أَنْ يَكُونَ لِي عِنْدَ الْقَوْمِ يَدٌ يُدْفَعُ بِهَا عَنْ أَهْلِي وَمَالِي وَلَيْسَ مِنْ أَصْحَابِكَ أَحَدٌ إِلَّا لَهُ هُنَالِكَ مِنْ قَوْمِهِ مَنْ يَدْفَعُ اللَّهُ بِهِ عَنْ أَهْلِهِ وَمَالِهِ قَالَ صَدَقَ لَا تَقُولُوا لَهُ إِلَّا خَيْرًا قَالَ فَعَادَ عُمَرُ فَقَالَ يَا رَسُولَ اللَّهِ قَدْ خَانَ اللَّهَ وَرَسُولَهُ وَالْمُؤْمِنِينَ دَعْنِي فَلِأَضْرِبْ عُنُقَهُ قَالَ أَوَلَيْسَ مِنْ أَهْلِ بَدْرٍ وَمَا يُدْرِيكَ لَعَلَّ اللَّهَ اطَّلَعَ عَلَيْهِمْ فَقَالَ اعْمَلُوا مَا شِئْتُمْ فَقَدْ أَوْجَبْتُ لَكُمْ الْجَنَّةَ فَاغْرَوْرَقَتْ عَيْنَاهُ فَقَالَ اللَّهُ وَرَسُولُهُ أَعْلَمُقَالَ أَبُو عَبْد اللَّهِ خَاخٍ أَصَحُّ وَلَكِنْ كَذَا قَالَ أَبُو عَوَانَةَ حَاجٍ وَحَاجٍ تَصْحِيفٌ وَهُوَ مَوْضِعٌ وَهُشَيْمٌ يَقُولُ خَاخٍ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Abu 'Awanah] dari [Hushain] dari [fulan] mengatakan, Abu Abdurrahman dan Hibban bin 'Uthayyah bersengketa. [Abu Abdurrahman] kemudian mengatakan kepada Hibban; 'Aku tahu alasan yang memotivasi kawanmu untuk menumpahkan darah.' Maksudnya [Ali bin Abi Thalib]. 'Apa itu? ' Tanya Hibban. Abu Abdurrahman menjawab; 'Sesuatu yang aku mendengar darinya secara langsung.' 'Apa itu? ' Tanya Hibban. Abu Abdurrahman melanjutkan; dia berkata; Rasulullah shallallahu 'alaihi wasallam mengutusku bersama Zubair dan Abu Murtsad. Masing-masing kami ketika itu menunggang kuda. Nabi berpesan: \"Berangkatlah kalian hingga kalian sampai ke Raudah Haj.\" Kata Abu Salamah demikian, namun Abu Awanah mengatakan dengan redaksi; 'Haj'.\"disana ada seorang wanita yang membawa surat Hathib bin Abi Baltha'ah kepada kaum musyrikin, bawalah surat itu kepadaku.\" Lantas kami berangkat menunggang kuda kami hingga kami menemukan wanita itu sebagaimana yang disabdakan Nabi kepada kami, yaitu ia berada diatas untanya. Ketika itu Hathib bin Abi Baltha'ah telah berkirim surat kepada penduduk Makkah yang isinya mengabarkan keberangkatan Rasulullah Shallallahu'alaihiwasallam kepada mereka. Maka kami bertanya kepada wanita tersebut; 'Mana surat yang ada bersamamu? ' 'Saya tak membawa surat apapun' Jawab wanita tersebut. Maka kami menderumkan untanya, Kami mencari-cari surat itu di barang-barang bawaannya namun tidak kami dapatkan apa-apa. Kedua kawan kami mengatakan; 'Menurut hemat kami, dia tak membawa surat! ' Saya jawab; 'Kita sama-sama tahu bahwa Rasulullah shallallahu 'alaihi wasallam tak mungkin bohong.' Maka Ali bersumpah dengan mengatakan; 'Demi Dzat yang dijadikan untuk bersumpah, sekarang kamu harus mengeluarkan surat itu, atau kami benar-benar menelanjangimu.' Spontan wanita tersebut meraih ikat pinggangnya dan pada saat itu dia mengenakan ikat pinggang terbuat dari kain, dan mengeluarkan surat tersebut. Kemudian mereka membawa surat itu kepada Rasulullah Shallallahu'alaihiwasallam. Umar berkata; 'ya Rasulullah, sungguh Hathib telah mengkhianati Allah dan rasul-NYA dan juga orang-orang mukmin, biarkan diriku memenggal lehernya.' Rasulullah shallallahu 'alaihi wasallam bertanya kepada Hathib: \"Hai Hathib, apa yang mendorongmu untuk berbuat seperti itu?\" Hathib menjawab; 'ya Rasulullah, Bukan berarti saya tidak beriman kepada Allah dan rasul-NYA, akan tetapi saya ingin mempunyai di tengah-tengah kaum (di Makkah) tangan yang membela keluarga dan hartaku, dan saya berpikir tak ada satupun dari sahabatmu melainkan dia juga disana mempunyai keluarga yang lewat perantaraannya Allah menjaga keluarga dan hartanya dari kaumnya.' Maka Nabi menjawab; \"Ia jujur, maka janganlah kalian berkomentar terhadapnya selain kebaikan.\" Namun Umar belum juga reda kemarahannya sehingga kembali mengatakan; 'ya Rasulullah, ia telah berkhianat kepada Allah dan rasul-Nya dan juga orang-orang mukmin, biarkan aku memenggal kepalanya.' Spontan Nabi shallallahu 'alaihi wasallam menegur: \"bukankah dia termasuk orang yang mengikuti perang Badar? apakah kamu tahu, barangkali Allah telah melihat orang-orang yang mengikuti perang badar lantas mengatakan; 'lakukanlah sekehendak kalian, Aku telah mewajibkan surga bagi kalian!\" Kedua mata Umar pun berlinang, dan berujar; 'Allah dan Rasul-Nya-lah yang lebih tahu! ' Abu Abdullah mengatakan mengenai tempat diatas; 'Khah adalah lebih sahih, namun beginilah Abu 'Awanah mengatakan, haj. Padahal haj adalah kesalahan tulis. Haj adalah nama tempat, sedang [Husyaim] mengatakan Khah (dengan huruf akhir Kha' bukan jim).'"},"6093":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ خَالِدِ بْنِ يَزِيدَ عَنْ سَعِيدِ بْنِ أَبِي هِلَالٍ عَنْ هِلَالِ بْنِ أُسَامَةَ أَنَّ أَبَا سَلَمَةَ بْنَ عَبْدِ الرَّحْمَنِ أَخْبَرَهُ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَدْعُو فِي الصَّلَاةِ اللَّهُمَّ أَنْجِ عَيَّاشَ بْنَ أَبِي رَبِيعَةَ وَسَلَمَةَ بْنَ هِشَامٍ وَالْوَلِيدَ بْنَ الْوَلِيدِ اللَّهُمَّ أَنْجِ الْمُسْتَضْعَفِينَ مِنْ الْمُؤْمِنِينَ اللَّهُمَّ اشْدُدْ وَطْأَتَكَ عَلَى مُضَرَ وَابْعَثْ عَلَيْهِمْ سِنِينَ كَسِنِي يُوسُفَ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari [Khalid bin Yazid] dari [Sa'id bin Abi Hilal] dari [Hilal bin Usamah], bahwasanya [Abu Salamah bin Abdurrahman] mengabarkan kepadanya dari [Abu Hurairah], bahwasanya Nabi shallallahu 'alaihi wasallam dalam shalatnya berdoa: \"Ya Allah, selamatkanlah 'Ayyasy bin Abi rabi'ah, Salamah bin Hisyam, Walid bin Al Walid, Ya Allah selamatkanlah orang-orang lemah dari kalangan orang-orang mukmin, ya Allah, kokohkanlah penyengsaraanmu terhadap Mudhar, dan kirimkanlah musim paceklik kepada mereka, sebagaimana paceklik yang menimpa Yusuf.\""},"6094":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ حَوْشَبٍ الطَّائِفِيُّ حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثٌ مَنْ كُنَّ فِيهِ وَجَدَ حَلَاوَةَ الْإِيمَانِ أَنْ يَكُونَ اللَّهُ وَرَسُولُهُ أَحَبَّ إِلَيْهِ مِمَّا سِوَاهُمَا وَأَنْ يُحِبَّ الْمَرْءَ لَا يُحِبُّهُ إِلَّا لِلَّهِ وَأَنْ يَكْرَهَ أَنْ يَعُودَ فِي الْكُفْرِ كَمَا يَكْرَهُ أَنْ يُقْذَفَ فِي النَّارِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Hausyab Ath Tha`ifi] telah menceritakan kepada kami [Abdul Wahhab] telah menceritakan kepada kami [Ayyub] dari [Abu Qilabah] dari [Anas] radliallahu 'anhu mengatakan, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ada tiga hal yang jika seseorang melaksanakannya, ia mendapat kemanisan iman, Allah dan rasul-NYA lebih ia cintai daripada selain keduanya, ia mencintai seseorang dengan tiada dorongan selain karena Allah, dan benci kembali kepada kekafiran sebagaimana kebenciannya untuk dilempar ke neraka.\""},"6095":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ سُلَيْمَانَ حَدَّثَنَا عَبَّادٌ عَنْ إِسْمَاعِيلَ سَمِعْتُ قَيْسًا سَمِعْتُ سَعِيدَ بْنَ زَيْدٍ يَقُولُلَقَدْ رَأَيْتُنِي وَإِنَّ عُمَرَ مُوثِقِي عَلَى الْإِسْلَامِ وَلَوْ انْقَضَّ أُحُدٌ مِمَّا فَعَلْتُمْ بِعُثْمَانَ كَانَ مَحْقُوقًا أَنْ يَنْقَضَّ","id":"Telah menceritakan kepada kami [Sa'id bin Sulaiman] telah menceritakan kepada kami [Abbad] dari [Isma'il] aku mendengar [Qais] aku mendengar [Sa'id bin Zaid] mengatakan; aku pernah bermimpi bahwa Umar adalah peneguhku terhadap Islam, dan sekiranya gunung Uhud runtuh karena perlakuan kalian terhadap Utsman, niscaya gunung itu pun runtuh.'"},"6096":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ إِسْمَاعِيلَ حَدَّثَنَا قَيْسٌ عَنْ خَبَّابِ بْنِ الْأَرَتِّ قَالَشَكَوْنَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ مُتَوَسِّدٌ بُرْدَةً لَهُ فِي ظِلِّ الْكَعْبَةِ فَقُلْنَا أَلَا تَسْتَنْصِرُ لَنَا أَلَا تَدْعُو لَنَا فَقَالَ قَدْ كَانَ مَنْ قَبْلَكُمْ يُؤْخَذُ الرَّجُلُ فَيُحْفَرُ لَهُ فِي الْأَرْضِ فَيُجْعَلُ فِيهَا فَيُجَاءُ بِالْمِنْشَارِ فَيُوضَعُ عَلَى رَأْسِهِ فَيُجْعَلُ نِصْفَيْنِ وَيُمْشَطُ بِأَمْشَاطِ الْحَدِيدِ مَا دُونَ لَحْمِهِ وَعَظْمِهِ فَمَا يَصُدُّهُ ذَلِكَ عَنْ دِينِهِ وَاللَّهِ لَيَتِمَّنَّ هَذَا الْأَمْرُ حَتَّى يَسِيرَ الرَّاكِبُ مِنْ صَنْعَاءَ إِلَى حَضْرَمَوْتَ لَا يَخَافُ إِلَّا اللَّهَ وَالذِّئْبَ عَلَى غَنَمِهِ وَلَكِنَّكُمْ تَسْتَعْجِلُونَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Isma'il] telah menceritakan kepada kami [Qais] dari [Khabbab bin Al Arat] mengatakan, kami pernah mengeluhkan penderitaan kepada Rasulullah Shallallahu'alaihiwasallam yang ketika itu beliau beralaskan kain panjangnya di naungan ka'bah. Maka kami mengadu; 'Tidakkah engkau meminta pertolongan untuk kami? Tidakkah engkau berdoa untuk kami? ' maka beliau bersabda; \"Sungguh sebelum kalian ada orang yang diringkus kemudian digalikan lubang baginya dan ia ditimbun disana, lantas didatangkan gergaji dan diletakkan di kepalanya, sehingga kepalanya terbelah menjadi dua, dan ada yang disisir dengan sisir besi sehingga memisahkan tulang dan dagingnya namun semua siksaan itu tidak memalingkannya dari agamanya, demi Allah, perkara ini akan sempurna sehingga seorang pengendara bisa berjalan dari Shan'a hingga Hadramaut, dan ia tidak khawatir selain kepada Allah dan srigala yang akan menerkam kambingnya, namun kalian ini orang yang suka tergesa-gesa.\""},"6097":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا اللَّيْثُ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَبَيْنَمَا نَحْنُ فِي الْمَسْجِدِ إِذْ خَرَجَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ انْطَلِقُوا إِلَى يَهُودَ فَخَرَجْنَا مَعَهُ حَتَّى جِئْنَا بَيْتَ الْمِدْرَاسِ فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَادَاهُمْ يَا مَعْشَرَ يَهُودَ أَسْلِمُوا تَسْلَمُوا فَقَالُوا قَدْ بَلَّغْتَ يَا أَبَا الْقَاسِمِ فَقَالَ ذَلِكَ أُرِيدُ ثُمَّ قَالَهَا الثَّانِيَةَ فَقَالُوا قَدْ بَلَّغْتَ يَا أَبَا الْقَاسِمِ ثُمَّ قَالَ الثَّالِثَةَ فَقَالَ اعْلَمُوا أَنَّ الْأَرْضَ لِلَّهِ وَرَسُولِهِ وَإِنِّي أُرِيدُ أَنْ أُجْلِيَكُمْ فَمَنْ وَجَدَ مِنْكُمْ بِمَالِهِ شَيْئًا فَلْيَبِعْهُ وَإِلَّا فَاعْلَمُوا أَنَّمَا الْأَرْضُ لِلَّهِ وَرَسُولِهِ","id":"Telah menceritakan kepada kami [Abdul Aziz bin Abdullah] telah menceritakan kepada kami [Al Laits] dari [Sa'id Al Maqburi] dari [ayahnya] dari [Abu Hurairah] radliallahu 'anhu; ketika kami di masjid, tiba-tiba Rasulullah shallallahu 'alaihi wasallam menemui kami dan berujar: \"Ayo kita pergi ke kaum yahudi, \" maka kami berangkat bersama beliau, hingga kami tiba di Baitil Midras, Nabi shallallahu 'alaihi wasallam berdiri dan menyeru mereka; \"Wahai sekalian kaum yahudi, masuklah ke dalam Islam, maka kalian akan selamat.\" 'Telah engkau sampaikan wahai Abul Qasim' Sambut mereka.\"Itulah yang kuinginkan sebenarnya\" Kata Nabi. Nabi mengulang ajakannya dua kali dan mereka memberi jawaban sama; 'Telah engkau sampaikan wahai Abul qasim.' Nabi mengajak mereka untuk kali ketiga, dan berujar kepada mereka: \"Ketahuilah, bahwasanya bumi ini adalah milik Allah dan rasul-NYA, dan saya ingin mengusir kalian, maka siapa diantara kalian yang mendapatkan sesuatu dengan hartanya, juallah, kalaulah tidak, ketahuilah bumi hanyalah milik Allah dan rasul-NYA.\""},"6098":{"ar":"حَدَّثَنَا يَحْيَى بْنُ قَزَعَةَ حَدَّثَنَا مَالِكٌ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَبْدِ الرَّحْمَنِ وَمُجَمِّعٍ ابْنَيْ يَزِيدَ بْنِ جَارِيَةَ الْأَنْصَارِيِّ عَنْ خَنْسَاءَ بِنْتِ خِذَامٍ الْأَنْصَارِيَّةِأَنَّ أَبَاهَا زَوَّجَهَا وَهِيَ ثَيِّبٌ فَكَرِهَتْ ذَلِكَ فَأَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَدَّ نِكَاحَهَا","id":"Telah menceritakan kepada kami [Yahya bin Qaza'ah] telah menceritakan kepada kami [Malik] dari ['Abdurrahman bin Al Qasim] dari [ayahnya] dari ['Abdurrahman] dan [Mujamma'], dua anak Yazid bin Jariyah Al Anshari, dari [Khansa' binti Khidzam Al Anshariyah]; bahwa ayahnya mengawinkannya -ketika itu ia janda-dengan lak-laki yang tidak disukainya, kemudian dia menemui Nabi shallallahu 'alaihi wasallam dan beliau membatalkan pernikahannya."},"6099":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ جُرَيْجٍ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ أَبِي عَمْرٍو هُوَ ذَكْوَانُ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقُلْتُ يَا رَسُولَ اللَّهِ يُسْتَأْمَرُ النِّسَاءُ فِي أَبْضَاعِهِنَّ قَالَ نَعَمْ قُلْتُ فَإِنَّ الْبِكْرَ تُسْتَأْمَرُ فَتَسْتَحْيِي فَتَسْكُتُ قَالَ سُكَاتُهَا إِذْنُهَا","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Ibnu Juraij] dari [Ibnu Abi Mulaikah] dari [Abu Amru] alias Dzakwan, dari [Aisyah] radliallahu 'anhuma mengatakan, saya berkata; 'ya Rasulullah, apakah wanita dimintai izin pada kemaluan mereka? ' Nabi menjawab: \"iya.\" Saya bertanya; 'sungguh gadis merasa malu lantas ia memilih diam jika dimintai persetujuannya.' Nabi shallallahu 'alaihi wasallam menjawab; \"jika ia diam, itulah tanda persetujuannya.\""},"6100":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ جَابِرٍ رَضِيَ اللَّهُ عَنْهُأَنَّ رَجُلًا مِنْ الْأَنْصَارِ دَبَّرَ مَمْلُوكًا وَلَمْ يَكُنْ لَهُ مَالٌ غَيْرُهُ فَبَلَغَ ذَلِكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَنْ يَشْتَرِيهِ مِنِّي فَاشْتَرَاهُ نُعَيْمُ بْنُ النَّحَّامِ بِثَمَانِ مِائَةِ دِرْهَمٍ قَالَ فَسَمِعْتُ جَابِرًا يَقُولُ عَبْدًا قِبْطِيًّا مَاتَ عَامَ أَوَّلَ","id":"Telah menceritakan kepada kami [Abu Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] dari [Amru bin Dinar] dari [Jabir] radliallahu 'anhu, ada seorang laki-laki anshar menjanjikan kemerdekaan budaknya (mudabbar) padahal ia tak punya harta selainnya. Berita ini sampai kepada Rasulullah shallallahu 'alaihi wasallam, maka beliau bertanya: \"Siapa mau membelinya dariku?\" Selanjutnya budak itu dibeli oleh Nu'aim bin Najjam seharga delapan ratus dirham. Kata Amru bin dinar, lalu kudengar Jabir mengatakan; 'budak qibthi yang meninggal di tahun pertama.'"},"6101":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ مَنْصُورٍ حَدَّثَنَا أَسْبَاطُ بْنُ مُحَمَّدٍ حَدَّثَنَا الشَّيْبَانِيُّ سُلَيْمَانُ بْنُ فَيْرُوزٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ الشَّيْبَانِيُّ وَحَدَّثَنِي عَطَاءٌ أَبُو الحَسَنِ السُّوَائِيُّ وَلَا أَظُنُّهُ إِلَّا ذَكَرَهُ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا يَحِلُّ لَكُمْ أَنْ تَرِثُوا النِّسَاءَ كَرْهًا }الْآيَةَ قَالَ كَانُوا إِذَا مَاتَ الرَّجُلُ كَانَ أَوْلِيَاؤُهُ أَحَقَّ بِامْرَأَتِهِ إِنْ شَاءَ بَعْضُهُمْ تَزَوَّجَهَا وَإِنْ شَاءُوا زَوَّجَهَا وَإِنْ شَاءُوا لَمْ يُزَوِّجْهَا فَهُمْ أَحَقُّ بِهَا مِنْ أَهْلِهَا فَنَزَلَتْ هَذِهِ الْآيَةُ فِي ذَلِكَ","id":"Telah menceritakan kepada kami [Husain bin Manshur] telah menceritakan kepada kami [Asbath bin Muhammad] telah menceritakan kepada kami [Asy Syaibani Sulaiman bin fairuz] dari [Ikrimah] dari [Ibnu 'Abbas], Asy Syaibani mengatakan, dan telah menceritakan kepadaku ['Atho' Abul hasan As suwa`i] dan setahuku dia tidak menyebutnya selain dari Ibnu 'Abbas radliallahu 'anhuma; 'Hai orang-orang yang beriman, tidak dihalalkan bagi kalian menguasai wanita secara paksa (QS.Annisa'; 19), dia berkata mengenai ayat ini; Dahulu jika seseorang meninggal, maka wali si laki-laki yang meninggal lah yang paling berhak terhadap isterinya, jika berkenan mereka kawini, atau mereka kawinkan dengan orang lain, atau mereka biarkan terkatung-katung, merekalah yang paling berhak terhadapnya daripada keluarga wanita itu sendiri, sehingga turunlah ayat ini yang menyelesaikan masalah itu."},"6102":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ حَدَّثَنَا شُعَيْبٌ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَاجَرَ إِبْرَاهِيمُ بِسَارَةَ دَخَلَ بِهَا قَرْيَةً فِيهَا مَلِكٌ مِنْ الْمُلُوكِ أَوْ جَبَّارٌ مِنْ الْجَبَابِرَةِ فَأَرْسَلَ إِلَيْهِ أَنْ أَرْسِلْ إِلَيَّ بِهَا فَأَرْسَلَ بِهَا فَقَامَ إِلَيْهَا فَقَامَتْ تَوَضَّأُ وَتُصَلِّي فَقَالَتْ اللَّهُمَّ إِنْ كُنْتُ آمَنْتُ بِكَ وَبِرَسُولِكَ فَلَا تُسَلِّطْ عَلَيَّ الْكَافِرَ فَغُطَّ حَتَّى رَكَضَ بِرِجْلِهِ","id":"Telah menceritakan kepada kami [Abul Yaman] telah menceritakan kepada kami [Syu'aib] telah menceritakan kepada kami [Abu Az Zanad] dari [Al A'raj] dari [Abu Hurairah] mengatakan, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ibrahim berhijrah bersama Sarah, kemudian mereka memasuki suatu desa yang dipimpin oleh seorang raja atau diktator. Raja mengutus seorang ajudan untuk menemui Ibrahim; 'Panggil Ibrahim untuk menghadapku bersama isterinya', lantas sang ajudan membawa isterinya kepada sang raja. Ketika raja berdiri menghadap Sarah, Sarah lantas berwudhu dan shalat dan memanjatkan doa; 'Ya Allah, jika aku beriman terhadap-Mu dan rasul-Mu, maka janganlah Engkau kuasakan seorang kafir kepada kami', ketika itu pula kaki sang raja terbenam ke dalam bumi hingga meronta-ronta dengan kakinya.\""},"6103":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ أَنَّ سَالِمًا أَخْبَرَهُ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمُسْلِمُ أَخُو الْمُسْلِمِ لَا يَظْلِمُهُ وَلَا يُسْلِمُهُ وَمَنْ كَانَ فِي حَاجَةِ أَخِيهِ كَانَ اللَّهُ فِي حَاجَتِهِ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari [Uqail] dari [Ibnu Syihab], bahwa [Salim] mengabarinya, bahwasanya [Abdullah bin Umar] radliallahu 'anhuma mengabarinya, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang muslim adalah saudara muslim lainnya, tidak menzhaliminya dan tidak menyerahkannya kepada musuh, barangsiapa yang memenuhi kebutuhan saudaranya, maka Allah akan memenuhi kebutuhannya.\""},"6104":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ حَدَّثَنَا سَعِيدُ بْنُ سُلَيْمَانَ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ أَبِي بَكْرِ بْنِ أَنَسٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْصُرْ أَخَاكَ ظَالِمًا أَوْ مَظْلُومًا فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ أَنْصُرُهُ إِذَا كَانَ مَظْلُومًا أَفَرَأَيْتَ إِذَا كَانَ ظَالِمًا كَيْفَ أَنْصُرُهُ قَالَ تَحْجُزُهُ أَوْ تَمْنَعُهُ مِنْ الظُّلْمِ فَإِنَّ ذَلِكَ نَصْرُهُ","id":"Telah menceritakan kepada kami [Muhammad bin Abdurrahim] telah menceritakan kepada kami [Sa'id bin Sulaiman] telah menceritakan kepada kami [Husyaim] Telah mengabarkan kepada kami [Ubaidullah bin Abi Bakr bin Anas] dari [Anas] radliallahu 'anhu mengatakan, Rasulullah shallallahu 'alaihi wasallam bersabda: \"'Tolonglah saudaramu baik ia zhalim atau dizhalimi.\" Ada seorang laki-laki bertanya; 'ya Rasulullah, saya maklum jika ia dizhalimi, namun bagaimana saya menolong padahal ia zhalim? ' Nabi menjawab; \"engkau mencegahnya atau menahannya dari kezhaliman, itulah cara menolongnya.\""},"6105":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ بْنِ وَقَّاصٍ قَالَ سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ يَخْطُبُ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَا أَيُّهَا النَّاسُ إِنَّمَا الْأَعْمَالُ بِالنِّيَّةِ وَإِنَّمَا لِامْرِئٍ مَا نَوَى فَمَنْ كَانَتْ هِجْرَتُهُ إِلَى اللَّهِ وَرَسُولِهِ فَهِجْرَتُهُ إِلَى اللَّهِ وَرَسُولِهِ وَمَنْ هَاجَرَ إِلَى دُنْيَا يُصِيبُهَا أَوْ امْرَأَةٍ يَتَزَوَّجُهَا فَهِجْرَتُهُ إِلَى مَا هَاجَرَ إِلَيْهِ","id":"Telah menceritakan kepada kami [Abu Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] dari [Yahya bin Sa'id] dari [Muhammad bin Ibrahim] dari [Alqomah bin Waqqash] mengatakan, aku mendengar [Umar bin Khaththab] radliallahu 'anhu berpidato, dia mengatakan, aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Hai manusia, hanyasanya amal itu tergantung niyatnya, dan setiap orang mendapatkan sesuai yang diniatkan, barangsiapa hijrahnya karena Allah dan rasul-Nya,, maka hijrahnya dihitung karena Allah dan rasul-Nya, barangsiapa hijrahnya karena dunia yang ingin diperolehnya, atau wanita yang ingin dinikahinya, maka hijrahnya sekedar mendapat yang diniatkan.\""},"6106":{"ar":"حَدَّثَنِي إِسْحَاقُ بْنُ نَصْرٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ هَمَّامٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَقْبَلُ اللَّهُ صَلَاةَ أَحَدِكُمْ إِذَا أَحْدَثَ حَتَّى يَتَوَضَّأَ","id":"Telah menceritakan kepadaku [Ishaq bin Nashr] telah menceritakan kepada kami [Abdurrazaq] dari [Ma'mar] dari [Hammam] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Allah tidak menerima shalat salah seorang diantara kalian jika berhadas hingga ia berwudhu.\""},"6107":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْأَنْصَارِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا ثُمَامَةُ بْنُ عَبْدِ اللَّهِ بْنِ أَنَسٍ أَنَّ أَنَسًا حَدَّثَهُأَنَّ أَبَا بَكْرٍ كَتَبَ لَهُ فَرِيضَةَ الصَّدَقَةِ الَّتِي فَرَضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا يُجْمَعُ بَيْنَ مُتَفَرِّقٍ وَلَا يُفَرَّقُ بَيْنَ مُجْتَمِعٍ خَشْيَةَ الصَّدَقَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah Al Anshari] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Tsumamah bin Abdullah bin Anas] bahwasanya [Anas] menceritakan kepadanya, bahwasanya Abu Bakar menuliskan kepadanya kewajiban sedekah sebagaimana Rasulullah Shallallahu'alaihiwasallam wajibkan, hewan ternak yang terpisah tidak boleh dihimpun dan hewan yang terhimpun tidak boleh dipisah, karena takut sedekah (zakat) nya."},"6108":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا إِسْمَاعِيلُ بْنُ جَعْفَرٍ عَنْ أَبِي سُهَيْلٍ عَنْ أَبِيهِ عَنْ طَلْحَةَ بْنِ عُبَيْدِ اللَّهِأَنَّ أَعْرَابِيًّا جَاءَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَائِرَ الرَّأْسِ فَقَالَ يَا رَسُولَ اللَّهِ أَخْبِرْنِي مَاذَا فَرَضَ اللَّهُ عَلَيَّ مِنْ الصَّلَاةِ فَقَالَ الصَّلَوَاتِ الْخَمْسَ إِلَّا أَنْ تَطَوَّعَ شَيْئًا فَقَالَ أَخْبِرْنِي بِمَا فَرَضَ اللَّهُ عَلَيَّ مِنْ الصِّيَامِ قَالَ شَهْرَ رَمَضَانَ إِلَّا أَنْ تَطَوَّعَ شَيْئًا قَالَ أَخْبِرْنِي بِمَا فَرَضَ اللَّهُ عَلَيَّ مِنْ الزَّكَاةِ قَالَ فَأَخْبَرَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَرَائِعَ الْإِسْلَامِ قَالَ وَالَّذِي أَكْرَمَكَ لَا أَتَطَوَّعُ شَيْئًا وَلَا أَنْقُصُ مِمَّا فَرَضَ اللَّهُ عَلَيَّ شَيْئًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْلَحَ إِنْ صَدَقَ أَوْ دَخَلَ الْجَنَّةَ إِنْ صَدَقَوَقَالَ بَعْضُ النَّاسِ فِي عِشْرِينَ وَمِائَةِ بَعِيرٍ حِقَّتَانِ فَإِنْ أَهْلَكَهَا مُتَعَمِّدًا أَوْ وَهَبَهَا أَوْ احْتَالَ فِيهَا فِرَارًا مِنْ الزَّكَاةِ فَلَا شَيْءَ عَلَيْهِ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Isma'il bin ja'far] dari [Abu Suhail] dari [ayahnya] dari [Thalhah bin Ubaidullah]; ada seorang arab badui menemui Rasulullah shallallahu 'alaihi wasallam dengan rambut acak-acakan, ia berkata; 'ya Rasulullah, beritahukanlah kepadaku shalat apakah yang Allah wajibkan atasku? ' Nabi menjawab: \"shalat lima waktu, kecuali jika engkau mau mengerjakan yang sunnah.\" Si arab badui bertanya lagi: 'Beritahukanlah kepadaku puasa apakah yang Allah wajibkan bagiku? ' Nabi menjawab: \"puasa bulan ramadhan, kecuali jika kamu ingin melaksanakan yang sunnah.\" Si arab badui bertanya; 'Beritahukanlah kepadaku, zakat apakah yang Allah wajibkan atasku? ' maka Rasulullah shallallahu 'alaihi wasallam memberitahukan kepadanya syariat-syariat Islam, dan arab badui tersebut mengatakan; 'Demi Dzat yang memuliakanmu, saya tidak akan melakukan yang sunnah, namun juga tak akan mengurangi sedikitpun yang telah Allah fardhukan atas diriku.' Maka Rasulullah bersabda; \"dia beruntung jika ia jujur atau dengan redaksi -ia masuk surga jika jujur.\" Penulis menuturkan; Sebagian orang mengatakan, bahwa seratus duapuluh unta zakatnya dua hiqqah, dan jika yang punya membelanjakannya secara sengaja, atau meng-hibahkannya atau mencari siasat terhadapnya dengan tujuan untuk tidak berzakat, maka yang demikian dia tak terkena dosa."},"6109":{"ar":"حَدَّثَنِي إِسْحَاقُ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ هَمَّامٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَكُونُ كَنْزُ أَحَدِكُمْ يَوْمَ الْقِيَامَةِ شُجَاعًا أَقْرَعَ يَفِرُّ مِنْهُ صَاحِبُهُ فَيَطْلُبُهُ وَيَقُولُ أَنَا كَنْزُكَ قَالَ وَاللَّهِ لَنْ يَزَالَ يَطْلُبُهُ حَتَّى يَبْسُطَ يَدَهُ فَيُلْقِمَهَا فَاهُ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا مَا رَبُّ النَّعَمِ لَمْ يُعْطِ حَقَّهَا تُسَلَّطُ عَلَيْهِ يَوْمَ الْقِيَامَةِ فَتَخْبِطُ وَجْهَهُ بِأَخْفَافِهَاوَقَالَ بَعْضُ النَّاسِ فِي رَجُلٍ لَهُ إِبِلٌ فَخَافَ أَنْ تَجِبَ عَلَيْهِ الصَّدَقَةُ فَبَاعَهَا بِإِبِلٍ مِثْلِهَا أَوْ بِغَنَمٍ أَوْ بِبَقَرٍ أَوْ بِدَرَاهِمَ فِرَارًا مِنْ الصَّدَقَةِ بِيَوْمٍ احْتِيَالًا فَلَا بَأْسَ عَلَيْهِ وَهُوَ يَقُولُ إِنْ زَكَّى إِبِلَهُ قَبْلَ أَنْ يَحُولَ الْحَوْلُ بِيَوْمٍ أَوْ بِسِتَّةٍ جَازَتْ عَنْهُ","id":"Telah menceritakan kepadaku [Ishaq] telah menceritakan kepada kami [Abdurrazzaq] telah menceritakan kepada kami [Ma'mar] dari [Hammam] dari [Abu Hurairah] radliallahu 'anhu mengatakan, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Harta salah seorang diantara kalian (jika tidak dizakati), maka pada hari kiamat menjadi ular yang menyeramkan, pemilik harta itu berusaha menyelamatkan diri namun si ular terus memburunya sambil mengatakan; 'aku adalah hartamu, ' Demi Allah, si ular itu tiada henti memburunya hingga orang yang mempunyai harta membentangkan tangannya dan dia melahapnya.\" Dan Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika pemilik unta tidak memberikan haknya, maka pada hari kiamat unta tersebut melawannya hingga menginjak-injak wajahnya dengan kuku kakinya.\" - Sebagian orang mengatakan bahwa jika seseorang yang mempunyai unta lantas khawatir terkena kewajiban zakat, lalu sehari sebelum haul tiba ia menjualnya dengan unta semisal atau kambing atau sapi, atau dirham dengan niat agar tidak terkena wajib zakat, maka tak ada dosa baginya. Dan dia mengatakan; jika ia menzakati untanya sehari sebelum haul tiba, atau enam hari sebelumnya, maka juga diperbolehkan."},"6110":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍ أَنَّهُقَالَ اسْتَفْتَى سَعْدُ بْنُ عُبَادَةَ الْأَنْصَارِيُّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نَذْرٍ كَانَ عَلَى أُمِّهِ تُوُفِّيَتْ قَبْلَ أَنْ تَقْ��ِيَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْضِهِ عَنْهَاوَقَالَ بَعْضُ النَّاسِ إِذَا بَلَغَتْ الْإِبِلُ عِشْرِينَ فَفِيهَا أَرْبَعُ شِيَاهٍ فَإِنْ وَهَبَهَا قَبْلَ الْحَوْلِ أَوْ بَاعَهَا فِرَارًا وَاحْتِيَالًا لِإِسْقَاطِ الزَّكَاةِ فَلَا شَيْءَ عَلَيْهِ وَكَذَلِكَ إِنْ أَتْلَفَهَا فَمَاتَ فَلَا شَيْءَ فِي مَالِهِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits] dari [Ibnu Syihab] dari [Ubaidullah bin Abdullah bin Utbah] dari [Ibnu Abbas] bahwasanya ia mengatakan, Sa'ad bin Ubadah Al Anshari pernah meminta fatwa Rasulullah Shallallahu'alaihiwasallam tentang nadzar ibunya yang meninggal sebelum menunaikan nadzarnya. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Penuhilah nadzarnya\". Sebagian orang mengatakan bahwa jika unta mencapai dua puluh ekor sehingga ia berkewajiban membayar zakat empat ekor kambing, lalu dia menghibahkan unta itu sebelum haul, atau menjualnya dengan niat atau siasat agar tidak terkena wajib zakat, maka tidak ada denda atasnya, demikian pula jika ia menyembunyikannya terus meninggal, maka tidak ada denda dalam hartanya."},"6111":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ قَالَ حَدَّثَنِي نَافِعٌ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الشِّغَارِقُلْتُ لِنَافِعٍ مَا الشِّغَارُ قَالَ يَنْكِحُ ابْنَةَ الرَّجُلِ وَيُنْكِحُهُ ابْنَتَهُ بِغَيْرِ صَدَاقٍ وَيَنْكِحُ أُخْتَ الرَّجُلِ وَيُنْكِحُهُ أُخْتَهُ بِغَيْرِ صَدَاقٍ وَقَالَ بَعْضُ النَّاسِ إِنْ احْتَالَ حَتَّى تَزَوَّجَ عَلَى الشِّغَارِ فَهُوَ جَائِزٌ وَالشَّرْطُ بَاطِلٌ وَقَالَ فِي الْمُتْعَةِ النِّكَاحُ فَاسِدٌ وَالشَّرْطُ بَاطِلٌ وَقَالَ بَعْضُهُمْ الْمُتْعَةُ وَالشِّغَارُ جَائِزٌ وَالشَّرْطُ بَاطِلٌ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ubaidullah] mengatakan, telah menceritakan kepadaku [Nafi'] dari ['Abdullah] radliallahu 'anhu, Rasulullah Shallallahu'alaihiwasallam melarang nikah syighar. Saya bertanya kepada Nafi'; 'Apa maksud syighar? ' Ia menjawab; 'mengawini anak perempuan seseorang lelaki dengan syarat lelaki tersebut dinikahkan dengan anak perempuannya tanpa mahar, atau menikahi saudara perempuan seorang lelaki dengan syarat lelaki tersebut menikahkannya dengan saudara perempuannya tanpa mahar.' Sebagian orang berpendapat; jika seseorang bersiasat sehingga ia nikah syighar, maka perkawinannya boleh dan syaratnya bathil. Dan ia berkata tentang nikah mut'ah; pernikahannya rusak dan syaratnya bathil. Sedang sebagian lain berpendapat bahwa nikah syighar boleh dan syaratnya bathil."},"6112":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ حَدَّثَنَا الزُّهْرِيُّ عَنْ الْحَسَنِ وَعَبْدِ اللَّهِ ابْنَيْ مُحَمَّدِ بْنِ عَلِيٍّ عَنْ أَبِيهِمَا أَنَّ عَلِيًّا رَضِيَ اللَّهُ عَنْهُقِيلَ لَهُ إِنَّ ابْنَ عَبَّاسٍ لَا يَرَى بِمُتْعَةِ النِّسَاءِ بَأْسًا فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْهَا يَوْمَ خَيْبَرَ وَعَنْ لُحُومِ الْحُمُرِ الْإِنْسِيَّةِوَقَالَ بَعْضُ النَّاسِ إِنْ احْتَالَ حَتَّى تَمَتَّعَ فَالنِّكَاحُ فَاسِدٌ وَقَالَ بَعْضُهُمْ النِّكَاحُ جَائِزٌ وَالشَّرْطُ بَاطِلٌ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Ubaidullah bin Umar] telah menceritakan kepada kami [Az Zuhri] dari [Al Hasan] dan [Abdullah], kedua anak Muhammad bin Ali, dari [ayah keduanya], bahwa di sampaikan kepada [Ali] radliallahu 'anhu; bahwa Ibnu Abbas menganggap nikah mut'ah tidak masalah, maka Ali berkata; 'Rasulullah telah melarangnya pada hari khaibar, dan beliau melarang daging keledai jinak.' Sebagian orang mengatakan; bahwa jika seseorang menyiasati sehingga nikah mut'ah, maka nikahnya rusak, sedang sebagian yang lain mengatakan nikahnya boleh dan syaratnya bathil."},"6113":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يُمْنَعُ فَضْلُ الْمَاءِ لِيُمْنَعَ بِهِ فَضْلُ الْكَلَإِ","id":"Telah menceritakan kepada kami [Isma'il] telah menceritakan kepada kami [Malik] dari [Abu Az Zanad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak boleh kelebihan air ditahan untuk menahan tumbuhnya rerumputan.\""},"6114":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ النَّجْشِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] dari [Malik] dari [Nafi'] dari [Ibnu Umar], Rasulullah Shallallahu'alaihiwasallam melarang (jual beli) najasy (penipuan)."},"6115":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَجُلًا ذَكَرَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ يُخْدَعُ فِي الْبُيُوعِ فَقَالَ إِذَا بَايَعْتَ فَقُلْ لَا خِلَابَةَ","id":"Telah menceritakan kepada kami [Isma'il] telah menceritakan kepada kami [Malik] dari [Abdullah bin Dinar] dari [Abdullah bin Umar] radliallahu 'anhuma; ada seorang laki-laki mengeluhkesahkan dirinya kepada Nabi shallallahu 'alaihi wasallam, karena dirinya sering ditipu dalam jual beli, maka beliau bersabda: \"Jika kamu jual-beli, katakan; 'Namun dengan syarat tak ada penipuan'.\""},"6116":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ حَدَّثَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ كَانَ عُرْوَةُ يُحَدِّثُ أَنَّهُ سَأَلَ عَائِشَةَ{ وَإِنْ خِفْتُمْ أَنْ لَا تُقْسِطُوا فِي الْيَتَامَى فَانْكِحُوا مَا طَابَ لَكُمْ مِنْ النِّسَاءِ }قَالَتْ هِيَ الْيَتِيمَةُ فِي حَجْرِ وَلِيِّهَا فَيَرْغَبُ فِي مَالِهَا وَجَمَالِهَا فَيُرِيدُ أَنْ يَتَزَوَّجَهَا بِأَدْنَى مِنْ سُنَّةِ نِسَائِهَا فَنُهُوا عَنْ نِكَاحِهِنَّ إِلَّا أَنْ يُقْسِطُوا لَهُنَّ فِي إِكْمَالِ الصَّدَاقِ ثُمَّ اسْتَفْتَى النَّاسُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدُ فَأَنْزَلَ اللَّهُ{ وَيَسْتَفْتُونَكَ فِي النِّسَاءِ }فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Abul Yaman] telah menceritakan kepada kami [Syu'aib] dari [Az Zuhri] mengatakan, [Urwah] menceritakan; ia bertanya [Aisyah] tentang ayat; 'Jika kalian khawatir tidak bisa berbuat adil terhadap yatimmu, maka nikahilah wanita yang baik-baik bagimu, dua, tiga, atau empat (QS. Annisa'; 3) dia mengatakan; 'yaitu yatim dalam asuhan walinya, dan si wali tersebut kurang menyukai kecantikan dan hartanya, namun tetap akan ia nikahi dengan syarat membayar mahar serendah-rendahnya yang menyalahi adat normal. Maka mereka dilarang menikahi anak-anak yatim tersebut kecuali jika berbuat adil dengan membayar mahar secara sempurna, lantas para sahabat bertanya kepada Rasulullah shallallahu 'alaihi wasallam di kemudian hari, maka Allah menurunkan ayat; 'Mereka meminta fatwa kepadamu,,, dan seterusnya (QS. Annisa' 127), kemudian dia menyebutkan hadits."},"6117":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِكُلِّ غَادِرٍ لِوَاءٌ يَوْمَ الْقِيَامَةِ يُعْرَفُ بِهِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Abdullah bin Dinar] dari [Abdullah bin Umar] radliallahu 'anhuma dari Nabi shallallahu 'alaihi wasallam bersabda: \"Setiap pengkhianat diberi bendera pada hari kiamat sebagai tanda pengenalnya.\""},"6118":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ عَنْ سُفْيَانَ عَنْ هِشَامٍ عَنْ عُرْوَةَ عَنْ زَيْنَبَ بِنْتِ أُمِّ سَلَمَةَ عَنْ أُمِّ سَلَمَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا أَنَا بَشَرٌ وَإِنَّكُمْ تَخْتَصِمُونَ إِلَيَّ وَلَعَلَّ بَعْضَكُمْ أَنْ يَكُونَ أَلْحَنَ بِحُجَّتِهِ مِنْ بَعْضٍ وَأَقْضِيَ لَهُ عَلَى نَحْوِ مَا أَسْمَعُ فَمَنْ قَضَيْتُ لَهُ مِنْ حَقِّ أَخِيهِ شَيْئًا فَلَا يَأْخُذْ فَإِنَّمَا أَقْطَعُ لَهُ قِطْعَةً مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] dari [Sufyan] dari [Hisyam] dari [Urwah] dari [Zainab binti Ummi Salamah] dari [Ummu Salamah] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Saya hanyalah manusia biasa, dan kalian mengadukan sengketa kepadaku, siapa tahu sebagian diantara kalian lebih pandai bersilat lidah dengan alasannya dari sebagian lain, sehingga aku memutuskan sebatas yang aku dengar, maka barangsiapa kuputuskan menang dengan mendzalimi hak saudaranya, janganlah ia mengambilnya, sebab aku akan mengambil sulutan api neraka baginya.\""},"6119":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُنْكَحُ الْبِكْرُ حَتَّى تُسْتَأْذَنَ وَلَا الثَّيِّبُ حَتَّى تُسْتَأْمَرَ فَقِيلَ يَا رَسُولَ اللَّهِ كَيْفَ إِذْنُهَا قَالَ إِذَا سَكَتَتْوَقَالَ بَعْضُ النَّاسِ إِنْ لَمْ تُسْتَأْذَنْ الْبِكْرُ وَلَمْ تَزَوَّجْ فَاحْتَالَ رَجُلٌ فَأَقَامَ شَاهِدَيْ زُورٍ أَنَّهُ تَزَوَّجَهَا بِرِضَاهَا فَأَثْبَتَ الْقَاضِي نِكَاحَهَا وَالزَّوْجُ يَعْلَمُ أَنَّ الشَّهَادَةَ بَاطِلَةٌ فَلَا بَأْسَ أَنْ يَطَأَهَا وَهُوَ تَزْوِيجٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Hisyam] telah menceritakan kepada kami [Yahya bin Abi Katsir] dari [Abu Salamah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, bersabda: \"Gadis tidak boleh dinikahi hingga dimintai izin, dan janda tidak bleh dinikahi hingga dimintai persetujuannya.\" Ada yang bertanya; 'ya Rasulullah, bagaimana tanda izinnya? ' Nabi menjawab: \"tandanya diam.\" Sebagian orang berpendapat; Jika seorang gadis belum dimintai izin, kemudian seseorang mencari siasat, kemudian dua orang saksi dusta bersaksi bahwa laki-laki tersebut telah menikahinya dengan kerelaannya, dan hakim memutuskannya secara resmi, dan suami tahu bahwa persaksiannya adalah dusta, maka yang demikian tidak mengapa untuk menyetubuhinya, dan termasuk pernikahan yang sah."},"6120":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ الْقَاسِمِأَنَّ امْرَأَةً مِنْ وَلَدِ جَعْفَرٍ تَخَوَّفَتْ أَنْ يُزَوِّجَهَا وَلِيُّهَا وَهِيَ كَارِهَةٌ فَأَرْسَلَتْ إِلَى شَيْخَيْنِ مِنْ الْأَنْصَارِ عَبْدِ الرَّحْمَنِ وَمُجَمِّعٍ ابْنَيْ جَارِيَةَ قَالَا فَلَا تَخْشَيْنَ فَإِنَّ خَنْسَاءَ بِنْتَ خِذَامٍ أَنْكَحَهَا أَبُوهَا وَهِيَ كَارِهَةٌ فَرَدَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَلِكَقَالَ سُفْيَانُ وَأَمَّا عَبْدُ الرَّحْمَنِ فَسَمِعْتُهُ يَقُولُ عَنْ أَبِيهِ إِنَّ خَنْسَاءَ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Al Qasim]; bahwa seorang wanita dari anak Ja'far merasa ketakutan (waswas) walinya menikahkannya sedang dia tidak suka, maka ia segera mengutus seseorang menemui dua syaikh dari kalangan anshar, [Abdurrahman] dan [Mujamma'], dua anak Jariyah. Maka keduanya berkata; janganlah khawatir, sebab Khansa` binti Khidzam pernah dinikahkan ayahnya sedang dia tidak suka, maka Nabi shallallahu 'alaihi wasallam menolak pernikahannya. [Sufyan] mengatakan; sedang [Abdurrahman] aku mendengarnya berkata; dari [ayahnya] dengan redaksi; Sesungguhnya Khansa'."},"6121":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُنْكَحُ الْأَيِّمُ حَتَّى تُسْتَأْمَرَ وَلَا تُنْكَحُ الْبِكْرُ حَتَّى تُسْتَأْذَنَ قَالُوا كَيْفَ إِذْنُهَا قَالَ أَنْ تَسْكُتَوَقَالَ بَعْضُ النَّاسِ إِنْ احْتَالَ إِنْسَانٌ بِشَاهِدَيْ زُورٍ عَلَى تَزْوِيجِ امْرَأَةٍ ثَيِّبٍ بِأَمْرِهَا فَأَثْبَتَ الْقَاضِي نِكَاحَهَا إِيَّاهُ وَالزَّوْجُ يَعْلَمُ أَنَّهُ لَمْ يَتَزَوَّجْهَا قَطُّ فَإِنَّهُ يَسَعُهُ هَذَا النِّكَاحُ وَلَا بَأْسَ بِالْمُقَامِ لَهُ مَعَهَا","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Syaiban] dari [Yahya] dari [Abu Salamah] dari [Abu Hurairah] mengatakan, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janda tidak boleh dinikahi hingga diajak musyawarah, dan gadis tidak boleh dinikahi hingga dimintai izin.\" Para sahabat bertanya; 'bagaimana tanda izinnya? ' Nabi menjawab; \"jika dia diam.\" Sebagian orang mengatakan; bahwa jika seseorang bersiasat dengan menghadirkan dua orang saksi palsu atas perkawinan seorang janda dengan mengatakan atas persetujuannya, kemudian hakim menetapkan pernikahannya, padahal suami tahu bahwa sebenarnya ia belum menikahinya sama sekali, maka pernikahannya tidak masalah, dan tidak apa tinggal bersama dengannya.'"},"6122":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ ذَكْوَانَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبِكْرُ تُسْتَأْذَنُ قُلْتُ إِنَّ الْبِكْرَ تَسْتَحْيِي قَالَ إِذْنُهَا صُمَاتُهَاوَقَالَ بَعْضُ النَّاسِ إِنْ هَوِيَ رَجُلٌ جَارِيَةً يَتِيمَةً أَوْ بِكْرًا فَأَبَتْ فَاحْتَالَ فَجَاءَ بِشَاهِدَيْ زُورٍ عَلَى أَنَّهُ تَزَوَّجَهَا فَأَدْرَكَتْ فَرَضِيَتْ الْيَتِيمَةُ فَقَبِلَ الْقَاضِي شَهَادَةَ الزُّورِ وَالزَّوْجُ يَعْلَمُ بِبُطْلَانِ ذَلِكَ حَلَّ لَهُ الْوَطْءُ","id":"Telah menceritakan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari [Ibnu Abi Mulaikah] dari [Dzakwan] dari [Aisyah] radliallahu 'anha mengatakan, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Gadis dimintai izinnya.\" Saya bertanya; 'Sesungguhnya gadis sering merasa malu untuk menyatakan persetujuannya.' Nabi menjawab; \"tanda izinnya adalah diam.\" Sebagian orang berpendapat bahwa; jika seorang laki-laki tertarik menikahi hamba sahaya yatim atau gadis, lantas anak yatim atau hamba sahaya tadi menolak, lalu si laki-laki mencari siasat dengan menghadirkan dua orang saksi bohong, dengan menyatakan bahwa si laki-laki tadi telah menikahinya dan si perempuan rela, kemudian hakim menerima kesaksian palsu tersebut dan suami mengetahui kebatilan kesaksiannya, maka boleh baginya menyetubuhinya."},"6123":{"ar":"حَدَّثَنَا عُبَيْدُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحِبُّ الْحَلْوَاءَ وَيُحِبُّ الْعَسَلَ وَكَانَ إِذَا صَلَّى الْعَصْرَ أَجَازَ عَلَى نِسَائِهِ فَيَدْنُو مِنْهُنَّ فَدَخَلَ عَلَى حَفْصَةَ فَاحْتَبَسَ عِنْدَهَا أَكْثَرَ مِمَّا كَانَ يَحْتَبِسُ فَسَأَلْتُ عَنْ ذَلِكَ فَقَالَ لِي أَهْدَتْ لَهَا امْرَأَةٌ مِنْ قَوْمِهَا عُكَّةَ عَسَلٍ فَسَقَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْهُ شَرْبَةً فَقُلْتُ أَمَا وَاللَّهِ لَنَحْتَالَنَّ لَهُ فَذَكَرْتُ ذَلِكَ لِسَوْدَةَ قُلْتُ إِذَا دَخَلَ عَلَيْكِ فَإِنَّهُ سَيَدْنُو مِنْكِ فَقُولِي لَهُ يَا رَسُولَ اللَّهِ أَكَلْتَ مَغَافِيرَ فَإِنَّهُ سَيَقُولُ لَا فَقُولِي لَهُ مَا هَذِهِ الرِّيحُ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَشْتَدُّ عَلَيْهِ أَنْ يُوجَدَ مِنْهُ الرِّيحُ فَإِنَّهُ سَيَقُولُ سَقَتْنِي حَفْصَةُ شَرْبَةَ عَسَلٍ فَقُولِي لَهُ جَرَسَتْ نَحْلُهُ الْعُرْفُطَ وَسَأَقُولُ ذَلِكِ وَقُولِيهِ أَنْتِ يَا صَفِيَّةُ فَلَمَّا دَخَلَ عَلَى سَوْدَةَ قُلْتُ تَقُولُ سَوْدَةُ وَالَّذِي لَا إِلَهَ إِلَّا هُوَ لَقَدْ كِدْتُ أَنْ أُبَادِرَهُ بِالَّذِي قُلْتِ لِي وَإِنَّهُ لَعَلَى الْبَابِ فَرَقًا مِنْكِ فَلَمَّا دَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ يَا رَسُولَ اللَّهِ أَكَلْتَ مَغَافِيرَ قَالَ لَا قُلْتُ فَمَا هَذِهِ الرِّيحُ قَالَ سَقَتْنِي حَفْصَةُ شَرْبَةَ عَسَلٍ قُلْتُ جَرَسَتْ نَحْلُهُ الْعُرْفُطَ فَلَمَّا دَخَلَ عَلَيَّ قُلْتُ لَهُ مِثْلَ ذَلِكَ وَدَخَلَ عَلَى صَفِيَّةَ فَقَالَتْ لَهُ مِثْلَ ذَلِكَ فَلَمَّا دَخَلَ عَلَى حَفْصَةَ قَالَتْ لَهُ يَا رَسُولَ اللَّهِ أَلَا أَسْقِيكَ مِنْهُ قَالَ لَا حَاجَةَ لِي بِهِ قَالَتْ تَقُولُ سَوْدَةُ سُبْحَانَ اللَّهِ لَقَدْ حَرَمْنَاهُ قَالَتْ قُلْتُ لَهَا اسْكُتِي","id":"Telah menceritakan kepada kami [Ubaid bin Isma'il] telah menceritakan kepada kami [Abu Usamah] dari [Hisyam] dari [ayahnya] dari [Aisyah], mengatakan; Rasulullah Shallallahu'alaihiwasallam sangat menyukai makanan yang manis-manis dan madu. Adalah kebiasaan beliau, jika beliau telah menunaikan shalat 'ashar, maka beliau melewati isteri-isterinya dan mendekati mereka. Maka Suatu kali beliau menemui Hafshah dan berada di sisinya lebih lama daripada kebiasaan beliau pada hari-hari normal. Maka segera aku tanyai beliau mengapa di rumah Hafshah sekian lama tidak seperti hari-hari biasanya. Beliau menjawab: \"Ada seorang wanita kaumnya menghadiahinya sekaleng madu, lantas ia memberinya minum kepada Rasulullah Shallallahu'alaihiwasallam.\" Maka aku mengatakan; 'Demi Allah, kami pasti akan mengerjai beliau.' Maka aku berkata kepada Saudah; 'jika Rasulullah menemuimu, dan ia mendekatimu, katakanlah kepadanya; 'ya Rasulullah, engkau makan buah mighfar? ' tentu beliau akan mengatakan; 'tidak', maka katakan kepadanya; 'lantas bau apa ini? ' Yang demikian karena Rasulullah shallallahu 'alaihi wasallam merasa risih jika didapati bau yang kurang menyedapkan dari tubuhnya. Maka beliau akan mengatakan; 'Hafshah telah memberiku minuman madu.' Maka katakanlah kepadanya; 'Rasa madu itu telah berubah karena ada sesuatu yang dimakan lebah! ' Dan aku akan mengatakan yang sedemikian, dan katakan begitu ya Shafiyah! ' Maka dikala Nabi shallallahu 'alaihi wasallam menemui Saudah, Saudah mengatakan; 'Demi Dzat yang tiada Tuhan selain Dia, nyaris aku terlebih dahulu bertanya kepada Nabi shallallahu 'alaihi wasallam dengan ucapan yang kau ucapkan padaku, dan Nabi sudah berada di pintu karena takut terhadapmu. Dikala Rasulullah shallallahu 'alaihi wasallam mendekat, saya mengatakan; 'ya Rasulullah, Benarkan, engkau telah makan buah mighfar? ' \"tidak\" Jawabnya. Maka aku katakan; 'lantas bau apa ini? ' Nabi menjawab; \"Hafshah telah memberi madu kepadaku.\" Saya mengatakan; 'rasa madu itu telah berubah karena ada tawon yang memakan sesuatu! ' Ketika beliau menemuiku, kukatakan yang demikian. Dan dikala beliau menemui Shafiyah, ia juga mengatakan yang sedemikian. Maka dikala beliau menemui Hafshah, Hafshah bertanya; 'ya Rasulullah, maukah aku beri minum madu? ' Nabi menjawab: \"Aku tidak butuh terhadapnya.\" Lantas Saudah mengatakan; 'Demi Allah, kita telah mengharamkan madu untuknya.' Aisyah berkata; kukatakan; 'diam kamu! '"},"6124":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ عَبْدِ اللَّهِ بْنِ عَامِرِ بْنِ رَبِيعَةَأَنَّ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ خَرَجَ إِلَى الشَّأْمِ فَلَمَّا جَاءَ بِسَرْغَ بَلَغَهُ أَنَّ الْوَبَاءَ وَقَعَ بِالشَّأْمِ فَأَخْبَرَهُ عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا سَمِعْتُمْ بِهِ بِأَرْضٍ فَلَا تَقْدَمُوا عَلَيْهِ وَإِذَا وَقَعَ بِأَرْضٍ وَأَنْتُمْ بِهَا فَلَا تَخْرُجُوا فِرَارًا مِنْهُ فَرَجَعَ عُمَرُ مِنْ سَرْغَوَعَنْ ابْنِ شِهَابٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ أَنَّ عُمَرَ إِنَّمَا انْصَرَفَ مِنْ حَدِيثِ عَبْدِ الرَّحْمَنِ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Ibnu Syihab] dari [Abdullah bin Amir bin Rabi'ah], Umar bin Khattab radliallahu 'anhu berangkat ke Syam. Ketika dia sampai di suatu kota yang bernama Saragh, dia mendengar berita bahwa wabah sedang menimpa Syam. Maka [Abdurrahman bin Auf] mengabarinya, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kalian mendengar wabah berada di suatu kawasan, janganlah kalian datang kesana, dan jika terjadi di suatu kawasan yang kalian diami, jangan kalian meninggalkannya.\" Spontan Umar meninggalkan kota Saragh. Dan dari [Ibnu Syihab] dari [Salim bin Abdullah], bahwasanya Umar pulang karena hadits Abdurrahman ini."},"6125":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ حَدَّثَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ حَدَّثَنَا عَامِرُ بْنُ سَعْدِ بْنِ أَبِي وَقَّاصٍ أَنَّهُ سَمِعَ أُسَامَةَ بْنَ زَيْدٍيُحَدِّثُ سَعْدًا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَكَرَ الْوَجَعَ فَقَالَ رِجْزٌ أَوْ عَذَابٌ عُذِّبَ بِهِ بَعْضُ الْأُمَمِ ثُمَّ بَقِيَ مِنْهُ بَقِيَّةٌ فَيَذْهَبُ الْمَرَّةَ وَيَأْتِي الْأُخْرَى فَمَنْ سَمِعَ بِهِ بِأَرْضٍ فَلَا يُقْدِمَنَّ عَلَيْهِ وَمَنْ كَانَ بِأَرْضٍ وَقَعَ بِهَا فَلَا يَخْرُجْ فِرَارًا مِنْهُ","id":"Telah menceritakan kepada kami [Abul yaman] telah menceritakan kepada kami [Syu'aib] dari [Az Zuhri] telah menceritakan kepada kami ['Amir bin Sa'd bin Abi Waqqash], ia mendengar [Usamah bin Zaid] menceritakan kepada Sa'd, bahwasanya Rasulullah shallallahu 'alaihi wasallam memperbincangkan suatu penyakit, beliau bersabda: \"Itu adalah sebagai hukuman dan siksaan yang pernah digunakan untuk menyiksa suatu kaum, kemudian masih ada yang tersisa dari penyakit tersbut, sehingga terkadang datang dan pergi, maka siapa mendengar suatu penyakit melanda sebuah negeri, jangan sesekali ia mendatanginya, dan barangsiapa di suatu negeri yang tengah dilanda penyakit, jangan ia mengungsi dengan niat menghindari penyakit itu.\""},"6126":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ أَيُّوبَ السَّخْتِيَانِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَائِدُ فِي هِبَتِهِ كَالْكَلْبِ يَعُودُ فِي قَيْئِهِ لَيْسَ لَنَا مَثَلُ السَّوْءِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Ayyub As Sakhtiyani] dari [Ikrimah] dari [Ibnu Abbas] radliallahu 'anhuma mengatakan, Nabi shallallahu 'alaihi wasallam bersabda: \"Orang yang menarik kembali pemberian, bagaikan anjing yang menyantap lagi muntahannya, yang kita tak mempunyai perumpamaan lebih buruk daripadanya.\""},"6127":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا هِشَامُ بْنُ يُوسُفَ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَإِنَّمَا جَعَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الشُّفْعَةَ فِي كُلِّ مَا لَمْ يُقْسَمْ فَإِذَا وَقَعَتْ الْحُدُودُ وَصُرِّفَتْ الطُّرُقُ فَلَا شُفْعَةَوَقَالَ بَعْضُ النَّاسِ الشُّفْعَةُ لِلْجِوَارِ ثُمَّ عَمَدَ إِلَى مَا شَدَّدَهُ فَأَبْطَلَهُ وَقَالَ إِنْ اشْتَرَى دَارًا فَخَافَ أَنْ يَأْخُذَ الْجَارُ بِالشُّفْعَةِ فَاشْتَرَى سَهْمًا مِنْ مِائَةِ سَهْمٍ ثُمَّ اشْتَرَى الْبَاقِيَ وَكَانَ لِلْجَارِ الشُّفْعَةُ فِي السَّهْمِ الْأَوَّلِ وَلَا شُفْعَةَ لَهُ فِي بَاقِي الدَّارِ وَلَهُ أَنْ يَحْتَالَ فِي ذَلِكَ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] telah menceritakan kepada kami [Hisyam bin Yusuf] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Abu Salamah] dari [Jabir bin Abdullah] mengatakan, 'hanyasanya Nabi shallallahu 'alaihi wasallam menetapkan syuf'ah untuk suatu yang belum dibagi, namun jika batas-batas tanah dan jalan pekarangan telah ditetapkan, tak ada syuf'ah lagi.' Sebagian orang berpendapat; 'bahwa syuf'ah bagi tetangga', kemudian dia berpegang dengan perkara yang dia perkuat, sehingga ia membatalkannya. Dan dia berkata; Jika seseorang membeli rumah dan khawatir tetangganya menguasainya dengan syuf'ah, maka dia membeli satu saham dari seratus saham yang ada, kemudian ia sendiri membeli saham sisanya, maka si tetangga hanya memperoleh syuf'ah pada satu saham yang pertama, dan tidak berhak syuf'ah pada saham rumah sisanya, dan dia boleh mensiasati hal itu."},"6128":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ إِبْرَاهِيمَ بْنِ مَيْسَرَةَ سَمِعْتُ عَمْرَو بْنَ الشَّرِيدِ قَالَجَاءَ الْمِسْوَرُ بْنُ مَخْرَمَةَ فَوَضَعَ يَدَهُ عَلَى مَنْكِبِي فَانْطَلَقْتُ مَعَهُ إِلَى سَعْدٍ فَقَالَ أَبُو رَافِعٍ لِلْمِسْوَرِ أَلَا تَأْمُرُ هَذَا أَنْ يَشْتَرِيَ مِنِّي بَيْتِي الَّذِي فِي دَارِي فَقَالَ لَا أَزِيدُهُ عَلَى أَرْبَعِ مِائَةٍ إِمَّا مُقَطَّعَةٍ وَإِمَّا مُنَجَّمَةٍ قَالَ أُعْطِيتُ خَمْسَ مِائَةٍ نَقْدًا فَمَنَعْتُهُ وَلَوْلَا أَنِّي سَمِعْتُ ��لنَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْجَارُ أَحَقُّ بِصَقَبِهِ مَا بِعْتُكَهُ أَوْ قَالَ مَا أَعْطَيْتُكَهُقُلْتُ لِسُفْيَانَ إِنَّ مَعْمَرًا لَمْ يَقُلْ هَكَذَا قَالَ لَكِنَّهُ قَالَ لِي هَكَذَا وَقَالَ بَعْضُ النَّاسِ إِذَا أَرَادَ أَنْ يَبِيعَ الشُّفْعَةَ فَلَهُ أَنْ يَحْتَالَ حَتَّى يُبْطِلَ الشُّفْعَةَ فَيَهَبَ الْبَائِعُ لِلْمُشْتَرِي الدَّارَ وَيَحُدُّهَا وَيَدْفَعُهَا إِلَيْهِ وَيُعَوِّضُهُ الْمُشْتَرِي أَلْفَ دِرْهَمٍ فَلَا يَكُونُ لِلشَّفِيعِ فِيهَا شُفْعَةٌ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Sufyan] dari [Ibrahim bin Maisarah] aku mendengar [Amru bin Syarid] mengatakan, Miswar bin makhramah datang dan meletakkan tangannya di pundakku. Kemudian aku berangkat bersamanya menuju ke Sa'd. Lantas [Abu Rafi'] mengatakan kepada Miswar; 'Tidakkah engkau suruh orang ini untuk membeli rumahku yang berada di pekaranganku? ' ia berkata; 'Saya tidak menambahnya melebihi empat ratus, baik secara kontan atau kredit.' Abu rafi' mengatakan; 'Aku telah diberi lima ratus secara kontan, namun aku menolaknya, kalaulah aku tidak mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Tetangga lebih berhak terhadap dinding tetangganya, \" niscaya aku tidak akan menjualnya kepadamu, -atau ia mengatakan dengan redaksi; 'niscaya tak akan memberikannya kepadamu'.- Saya berkata kepada Ma'mar; Ma'mar tidak mengatakan demikian, namun dia mengatakan kepadaku sedemikian dan mengatakan; Jika seseorang ingin menjual syuf'ah, maka ia boleh melakukan siasat sehingga membatalkan syuf'ah, dan penjual memberikan rumah kepada si pembeli, memberi batasan (waktu dan nilai) dan menyerahkannya kepada si pembeli, dan si pembeli menggantinya dengan seribu dirham, sehingga orang yang mempunyai syuf'ah tidak mempunyai syuf'ah lagi."},"6129":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ إِبْرَاهِيمَ بْنِ مَيْسَرَةَ عَنْ عَمْرِو بْنِ الشَّرِيدِ عَنْ أَبِي رَافِعٍأَنَّ سَعْدًا سَاوَمَهُ بَيْتًا بِأَرْبَعِ مِائَةِ مِثْقَالٍ فَقَالَ لَوْلَا أَنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْجَارُ أَحَقُّ بِصَقَبِهِ لَمَا أَعْطَيْتُكَوَقَالَ بَعْضُ النَّاسِ إِنْ اشْتَرَى نَصِيبَ دَارٍ فَأَرَادَ أَنْ يُبْطِلَ الشُّفْعَةَ وَهَبَ لِابْنِهِ الصَّغِيرِ وَلَا يَكُونُ عَلَيْهِ يَمِينٌ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Ibrahim bin Maisarah] dari [Amru bin Syarid] dari [Abu Rafi'], bahwasanya Sa'd pernah mengajukan penawaran rumah kepadanya seharga empat ratus mitsqal. Lantas Abu rafi' menjawab; 'Kalaulah aku tidak mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tetangga lebih berhak terhadap dindingnya, \" niscaya aku tidak menjualnya kepadamu. Dan sebagian orang berpendapat; Jika seseorang membeli bagian rumah, lantas ia ingin membatalkan syuf'ah, dan ia berikan kepada anak kecilnya, maka ia tak wajib bersumpah."},"6130":{"ar":"حَدَّثَنَا عُبَيْدُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ أَبِي حُمَيْدٍ السَّاعِدِيِّ قَالَاسْتَعْمَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا عَلَى صَدَقَاتِ بَنِي سُلَيْمٍ يُدْعَى ابْنَ الْلَّتَبِيَّةِ فَلَمَّا جَاءَ حَاسَبَهُ قَالَ هَذَا مَالُكُمْ وَهَذَا هَدِيَّةٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَهَلَّا جَلَسْتَ فِي بَيْتِ أَبِيكَ وَأُمِّكَ حَتَّى تَأْتِيَكَ هَدِيَّتُكَ إِنْ كُنْتَ صَادِقًا ثُمَّ خَطَبَنَا فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ أَمَّا بَعْدُ فَإِنِّي أَسْتَعْمِلُ الرَّجُلَ مِنْكُمْ عَلَى الْعَمَلِ مِمَّا وَلَّانِي اللَّهُ فَيَأْتِي فَيَقُولُ هَذَا مَالُكُمْ وَهَذَا هَدِيَّةٌ أُهْدِيَتْ لِي أَفَلَا جَلَسَ فِي بَيْتِ أَبِيهِ وَأُمِّهِ حَتَّى تَأْتِيَهُ هَدِيَّتُهُ وَاللَّهِ لَا يَأْخُذُ أَحَدٌ مِنْكُمْ شَيْئًا بِغَيْرِ حَقِّهِ إِلَّا لَقِيَ اللَّهَ يَحْمِلُهُ يَوْمَ الْقِيَامَةِ فَلَأَعْرِفَنَّ أَحَدًا مِنْكُمْ لَقِيَ اللَّهَ يَحْمِلُ بَعِيرًا لَهُ رُغَاءٌ أَوْ بَقَرَةً لَهَا خُوَارٌ أَوْ شَاةً تَيْعَرُ ثُمَّ رَفَعَ يَدَهُ حَتَّى رُئِيَ بَيَاضُ إِبْطِهِ يَقُولُ اللَّهُمَّ هَلْ بَلَّغْتُ بَصْرَ عَيْنِي وَسَمْعَ أُذُنِي","id":"Telah menceritakan kepada kami [Ubaid bin Isma'il], telah menceritakan kepada kami [Abu Usamah] dari [Hisyam] dari [ayahnya], dari [Abu Humaid As Sa'idi] mengatakan, Rasulullah Shallallahu'alaihiwasallam pernah mempekerjakan seorang laki-laki untuk mengelola zakat bani Sulaim yang sering dipanggil dengan nama Ibnu Al Latabiyah, tatkala dia datang, dia menghitungnya dan berkata; 'Ini adalah hartamu dan ini hadiah.' Spontan Rasulullah Shallallahu'alaihiwasallam berujar: \"kenapa kamu tidak duduk-duduk saja di rumah ayahmu atau ibumu sampai hadiahmu datang kepadamu jika kamu jujur.\" Kemudian beliau berpidato di hadapan kami, memuja dan memuji Allah terus bersabda: \"Amma ba'd. Sesungguhnya saya mempekerjakan salah seorang diantara kalian untuk mengumpulkan zakat yang telah Allah kuasakan kepadaku, lantas ia datang dan mengatakan; 'ini hartamu dan ini hadiah yang diberikan kepadaku, ' kenapa dia tidak duduk-duduk saja di rumah ayahnya atau ibunya sampai hadiahnya datang kepadanya? Demi Allah, tidaklah salah seorang diantara kalian mengambil sesuatu yang bukan haknya, selain ia menjumpai Allah pada hari kiamat dengan memikul hak itu, aku tahu salah seorang diantara kalian menjumpai Allah dengan memikul unta yang mendengus, atau sapi yang melenguh, atau kambing yang mengembik.\" Kemudian beliau mengangkat tangannya hingga terlihat putih ketiaknya seraya mengatakan: \"Ya Allah, bukankah aku telah menyampaikan apa yang kulihat dengan mataku dan kudengar dengan dua telingaku?\""},"6131":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ إِبْرَاهِيمَ بْنِ مَيْسَرَةَ عَنْ عَمْرِو بْنِ الشَّرِيدِ عَنْ أَبِي رَافِعٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْجَارُ أَحَقُّ بِصَقَبِهِوَقَالَ بَعْضُ النَّاسِ إِنْ اشْتَرَى دَارًا بِعِشْرِينَ أَلْفَ دِرْهَمٍ فَلَا بَأْسَ أَنْ يَحْتَالَ حَتَّى يَشْتَرِيَ الدَّارَ بِعِشْرِينَ أَلْفَ دِرْهَمٍ وَيَنْقُدَهُ تِسْعَةَ آلَافِ دِرْهَمٍ وَتِسْعَ مِائَةِ دِرْهَمٍ وَتِسْعَةً وَتِسْعِينَ وَيَنْقُدَهُ دِينَارًا بِمَا بَقِيَ مِنْ الْعِشْرِينَ الْأَلْفَ فَإِنْ طَلَبَ الشَّفِيعُ أَخَذَهَا بِعِشْرِينَ أَلْفَ دِرْهَمٍ وَإِلَّا فَلَا سَبِيلَ لَهُ عَلَى الدَّارِ فَإِنْ اسْتُحِقَّتْ الدَّارُ رَجَعَ الْمُشْتَرِي عَلَى الْبَائِعِ بِمَا دَفَعَ إِلَيْهِ وَهُوَ تِسْعَةُ آلَافِ دِرْهَمٍ وَتِسْعُ مِائَةٍ وَتِسْعَةٌ وَتِسْعُونَ دِرْهَمًا وَدِينَارٌ لِأَنَّ الْبَيْعَ حِينَ اسْتُحِقَّ انْتَقَضَ الصَّرْفُ فِي الدِّينَارِ فَإِنْ وَجَدَ بِهَذِهِ الدَّارِ عَيْبًا وَلَمْ تُسْتَحَقَّ فَإِنَّهُ يَرُدُّهَا عَلَيْهِ بِعِشْرِينَ أَلْفَ دِرْهَمٍ قَالَ فَأَجَازَ هَذَا الْخِدَاعَ بَيْنَ الْمُسْلِمِينَ وَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَبَيْعُ الْمُسْلِمِ لَا دَاءَ وَلَا خِبْثَةَ وَلَا غَائِلَةَ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Ibrahim bin Maisarah] dari [Amru bin Syarid] dari [Abu Rafi'] mengatakan, Nabi shallallahu 'alaihi wasallam bersabda: \"tetangga lebih berhak terhadap dinding rumahnya.\" Sebagian orang berpendapat; jika seseorang membeli rumah seharga dua puluh ribu dirham, tidak mengapa baginya untuk mencari siasat dengan cara membeli rumah dengan harga dua puluh ribu dirham, dan membayarkannya sembilan ribu sembilan ratus sembilan puluh sembilan dirham, dan ia membayarnya dengan satu dinar sebagai pembayaran sisa dua puluh ribu dirham. Lantas jika ada orang yang membelinya lagi (penjual pertama), maka ia (pembeli pertama) mengharuskan pembayaran dua puluh ribu dirham penuh, jika tidak, ia tidak berhak menempati rumah tersebut. Jika rumah diminta secara paksa, maka si pembeli pertama mengembalikan uang yang pernah dibayarkan yaitu sebanyak sembilan ribu sembilan ratus sembilan puluh sembilan dirham dirham dan satu dinar."},"6132":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ قَالَ حَدَّثَنِي إِبْرَاهِيمُ بْنُ مَيْسَرَةَ عَنْ عَمْرِو بْنِ الشَّرِيدِ أَنَّ أَبَا رَافِعٍسَاوَمَ سَعْدَ بْنَ مَالِكٍ بَيْتًا بِأَرْبَعِ مِائَةِ مِثْقَالٍ وَقَالَ لَوْلَا أَنِّي سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْجَارُ أَحَقُّ بِصَقَبِهِ مَا أَعْطَيْتُكَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Sufyan] mengatakan, Telah menceritakan kepadaku [Ibrahim bin Maisarah] dari [Amru bin Syarid], bahwasanya [Abu Rafi'] pernah mengajukan penawaran rumah keada Sa'd bin Malik seharga empat ratus mitsqal, dan ia mengatakan; 'Kalaulah aku tidak emndengar Nabi shallallahu 'alaihi wasallam bersabda: \"Tetangga lebih berhak teradap dindingnya\" niscaya tidak aku berikan kepadamu."},"6133":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ ح و حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ قَالَ الزُّهْرِيُّ فَأَخْبَرَنِي عُرْوَةُ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا أَنَّهَا قَالَتْأَوَّلُ مَا بُدِئَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْوَحْيِ الرُّؤْيَا الصَّادِقَةُ فِي النَّوْمِ فَكَانَ لَا يَرَى رُؤْيَا إِلَّا جَاءَتْ مِثْلَ فَلَقِ الصُّبْحِ فَكَانَ يَأْتِي حِرَاءً فَيَتَحَنَّثُ فِيهِ وَهُوَ التَّعَبُّدُ اللَّيَالِيَ ذَوَاتِ الْعَدَدِ وَيَتَزَوَّدُ لِذَلِكَ ثُمَّ يَرْجِعُ إِلَى خَدِيجَةَ فَتُزَوِّدُهُ لِمِثْلِهَا حَتَّى فَجِئَهُ الْحَقُّ وَهُوَ فِي غَارِ حِرَاءٍ فَجَاءَهُ الْمَلَكُ فِيهِ فَقَالَ اقْرَأْ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ مَا أَنَا بِقَارِئٍ فَأَخَذَنِي فَغَطَّنِي حَتَّى بَلَغَ مِنِّي الْجَهْدُ ثُمَّ أَرْسَلَنِي فَقَالَ اقْرَأْ فَقُلْتُ مَا أَنَا بِقَارِئٍ فَأَخَذَنِي فَغَطَّنِي الثَّانِيَةَ حَتَّى بَلَغَ مِنِّي الْجَهْدُ ثُمَّ أَرْسَلَنِي فَقَالَ اقْرَأْ فَقُلْتُ مَا أَنَا بِقَارِئٍ فَأَخَذَنِي فَغَطَّنِي الثَّالِثَةَ حَتَّى بَلَغَ مِنِّي الْجَهْدُ ثُمَّ أَرْسَلَنِي فَقَالَ{ اقْرَأْ بِاسْمِ رَبِّكَ الَّذِي خَلَقَ }حَتَّى بَلَغَ{ عَلَّمَ الْإِنْسَانَ مَا لَمْ يَعْلَمْ }فَرَجَعَ بِهَا تَرْجُفُ بَوَادِرُهُ حَتَّى دَخَلَ عَلَى خَدِيجَةَ فَقَالَ زَمِّلُونِي زَمِّلُونِي فَزَمَّلُوهُ حَتَّى ذَهَبَ عَنْهُ الرَّوْعُ فَقَالَ يَا خَدِيجَةُ مَا لِي وَأَخْبَرَهَا الْخَبَرَ وَقَالَ قَدْ خَشِيتُ عَلَى نَفْسِي فَقَالَتْ لَهُ كَلَّا أَبْشِرْ فَوَاللَّهِ لَا يُخْزِيكَ اللَّهُ أَبَدًا إِنَّكَ لَتَصِلُ الرَّحِمَ وَتَصْدُقُ الْحَدِيثَ وَتَحْمِلُ الْكَلَّ وَتَقْرِي الضَّيْفَ وَتُعِينُ عَلَى نَوَائِبِ الْحَقِّ ثُمَّ انْطَلَقَتْ بِهِ خَدِيجَةُ حَتَّى أَتَتْ بِهِ وَرَقَةَ بْنَ نَوْفَلِ بْنِ أَسَدِ بْنِ عَبْدِ الْعُزَّى بْنِ قُصَيٍّ وَهُوَ ابْنُ عَمِّ خَدِيجَةَ أَخُو أَبِيهَا وَكَانَ امْرَأً تَنَصَّرَ فِي الْجَاهِلِيَّةِ وَكَانَ يَكْتُبُ الْكِتَابَ الْعَرَبِيَّ فَيَكْتُبُ بِالْعَرَبِيَّةِ مِنْ الْإِنْجِيلِ مَا شَاءَ اللَّهُ أَنْ يَكْتُبَ وَكَانَ شَيْخًا كَبِيرًا قَدْ عَمِيَ فَقَالَتْ لَهُ خَدِيجَةُ أَيْ ابْنَ عَمِّ اسْمَعْ مِنْ ابْنِ أَخِيكَ فَقَالَ وَرَقَةُ ابْنَ أَخِي مَاذَا تَرَى فَأَخْبَرَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا رَأَى فَقَالَ وَرَقَةُ هَذَا النَّامُوسُ الَّذِي أُنْزِلَ عَلَى مُوسَى يَا لَيْتَنِي فِيهَا جَذَعًا أَكُونُ حَيًّا حِينَ يُخْرِجُكَ قَوْمُكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوَمُخْرِجِيَّ هُمْ فَقَالَ وَرَقَةُ نَعَمْ لَمْ يَأْتِ رَجُلٌ قَطُّ بِمِثْلِ مَا جِئْتَ بِهِ إِلَّا عُودِيَ وَإِنْ يُدْرِكْنِي يَوْمُكَ أَنْصُرْكَ نَصْرًا مُؤَزَّرًا ثُمَّ لَمْ يَنْشَبْ وَرَقَةُ أَنْ تُوُفِّيَ وَفَتَرَ الْوَحْيُ فَتْرَةً حَتَّى حَزِنَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيمَا بَلَغَنَا حُزْنًا غَدَا مِنْهُ مِرَارًا كَيْ يَتَرَدَّى مِنْ رُءُوسِ شَوَاهِقِ الْجِبَالِ فَكُلَّمَا أَوْفَى بِذِرْوَةِ جَبَلٍ لِكَيْ يُلْقِيَ مِنْهُ نَفْسَهُ تَبَدَّى لَهُ جِبْرِيلُ فَقَالَ يَا مُحَمَّدُ إِنَّكَ رَسُولُ اللَّهِ حَقًّا فَيَسْكُنُ لِذَلِكَ جَأْشُهُ وَتَقِرُّ نَفْسُهُ فَيَرْجِعُ فَإِذَا طَالَتْ عَلَيْهِ فَتْرَةُ الْوَحْيِ غَدَا لِمِثْلِ ذَلِكَ فَإِذَا أَوْفَى بِذِرْوَةِ جَبَلٍ تَبَدَّى لَهُ جِبْرِيلُ فَقَالَ لَهُ مِثْلَ ذَلِكَقَالَ ابْنُ عَبَّاسٍ{ فَالِقُ الْإِصْبَاحِ }ضَوْءُ الشَّمْسِ بِالنَّهَارِ وَضَوْءُ الْقَمَرِ بِاللَّيْلِ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari [Uqail] dari Ibnu Syihab -lewat jalur periwayatan lain-Dan Telah menceritakan kepadaku ['Abdullah bin Muhammad] telah menceritakan kepada kami ['Abdurrazaq] telah menceritakan kepada kami [Ma'mar], [Az Zuhri] mengatakan, telah menceritakan kepadaku [Urwah] dari [Aisyah] radliallahu 'anha, ia menceritakan; wahyu pertama-tama yang diturunkan kepada Rasulullah Shallallahu'alaihiwasallam adalah berupa mimpi yang baik ketika tidur, beliau tidak bermimpi selain datang seperti fajar subuh, dan beliau selalu pergi ke goa Hira bertahannus di sana, yaitu beribadah beberapa malam, dan beliau untuk hal tersebut berbekal, kemudian kembali kepada Khadijah agar dia dapat membekali beliau untuk keperluan seperti itu, sampai akhirnya beliau di kejutkan dengan al haq ketika beliau sedang berada di dalam goa Hira`, malaikat datang kepada beliau dan berujar; 'bacalah! ' Nabi shallallahu 'alaihi wasallam berkata kepadanya; \"maka aku menjawab; 'Saya tidak bisa membaca! ' Lalu dia mendekapku dan menutupiku hingga aku kepayahan. kemudian melepasku dan berkata; 'Bacalah! ' aku menjawab; 'Saya tidak bisa membaca! ' Ia mendekapku lagi dan menutupiku untuk kedua kalinya hingga aku kepayahan, kemudian melepasku lagi seraya mengatakan; 'Bacalah! ' saya menjawab; 'Saya tidak bisa membaca.' Maka ia mendekapku dan menutupiku untuk kali ketiganya hingga aku kepayahan, kemudian melepasku lagi dan mengatakan; 'IQRO' BISMI ROBBIKAL LADZII KHOLAQO sampai ayat 'ALLAMAL INSAANA MAA LAM YA'LAM, '\" kemudian beliau pulang dengan menggigil hingga menemui Khadijah dan berkata; \"Selimutilah aku, selimutilah aku!\" maka keluarganya pun menyelimuti beliau, sampai rasa ketakutan beliau menghilang, kemudian beliau berkata: \"ya Khadijah, apa yang terjadi pada diriku?\" beliau menceritakan peristiwa tersebut kepadanya dan berkata; \"Aku mengkhawatirkan diriku\" Maka Khadijah menjawab: 'Sekali-kali tidak, bergembiralah, demi Allah, Allah tidak akan menghinakanmu selama-lamanya, sebab engkau suka menyambung silaturrahim, berkata jujur, menghilangkan kesusahan serta menjamu tamu, serta membela kebenaran! ' Maka Khadijah pergi bersama beliau menemui Waraqah bin naufal bin Asad bin Abdul Uzza bin Qushshay, anak paman Khadijah, atau saudara ayahnya, ia adalah semasa jahiliyah beragama nashrani dan suka menulis kitab suci arabi, ia menulis injil arabi dengan kehendak Allah, dan dia seorang kakek yang cukup umur dan buta. Maka Khadijah berkata kepadanya; 'Wahai anak paman, dengarlah (apa yang dituturkan) anak saudaramu! ' Waraqah bertanya; 'Hai anak saudaraku, apa yang telah kau lihat? ' Maka Nabi shallallahu 'alaihi wasallam mengabarkan apa yang telah beliau lihat, spontan Waraqah mengatakan; 'Ini adalah Namus yang pernah diturunkan kepada Musa, duhai sekiranya ketika itu aku masih gagah perkasa dan masih hidup, ketika kaummu mengusirmu! ' \"Adakah kaumku akan mengusirku?\" Tanya Nabi shallallahu 'alaihi wasallam. Waraqah menjawab; 'Iya, tidak ada seorang pun yang membawa seperti yang kau bawa, melainkan ia akan dimusuhi. Jikalau aku temui hari-harimu, niscaya aku membelamu dengan gigih.' kemudian tak berselang lama Waraqah meninggal dan wahyu berhenti beberapa lama hingga Nabi shallallahu 'alaihi wasallam sedih. Berita yang sampai kepada kami, kesedihan yang beliau alami sedemikian rupa, hingga beliau beberapa kali ingin bunuh diri dengan cara menerjukan diri dari puncak gunung, setiap kali beliau naik puncak gunung untuk menerjunkan dirinya, Jibril menampakkan diri dan mengatakan; 'hai Muhammad, sesungguhnya engkau betul-betul Rasulullah! ' nasehat ini menjadikan hatinya lega dan jiwannya tenang dan pulang. Namun jika sekian lama wahyu tidak turun, jiwanya kembali terguncang, dan setiap kali ia naik puncak gunung untuk bunuh diri, Jibril menampakkan diri dan menasehati semisalnya. Ibnu Abbas mengatakan tentang ayat; 'Faaliqul ishbah' yaitu cahaya matahari ketika siang, dan cahaya bulan ketika malam."},"6134":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الرُّؤْيَا الْحَسَنَةُ مِنْ الرَّجُلِ الصَّالِحِ جُزْءٌ مِنْ سِتَّةٍ وَأَرْبَعِينَ جُزْءًا مِنْ النُّبُوَّةِ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Ishaq bin Abdullah bin Abi Thalhah] dari [Anas bin Malik], Rasulullah Shallallahu'alaihiwasallam bersabda: \"Mimpi baik yang berasal dari seorang yang shalih adalah satu bagian dari enam atau empat puluh bagian kenabian.\""},"6135":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا يَحْيَى هُوَ ابْنُ سَعِيدٍ قَالَ سَمِعْتُ أَبَا سَلَمَةَ قَالَ سَمِعْتُ أَبَا قَتَادَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الرُّؤْيَا الصَّادِقَةُ مِنْ اللَّهِ وَالْحُلْمُ مِنْ الشَّيْطَانِ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Yahya Ibnu Sa'id] mengatakan, aku pernah mendengar [Abu Salamah] mengatakan; Aku mendengar [Abu Qatadah] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Mimpi yang benar adalah dari Allah dan mimpi jelek berasal dari setan.\""},"6136":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا اللَّيْثُ حَدَّثَنِي ابْنُ الْهَادِ عَنْ عَبْدِ اللَّهِ بْنِ خَبَّابٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا رَأَى أَحَدُكُمْ رُؤْيَا يُحِبُّهَا فَإِنَّمَا هِيَ مِنْ اللَّهِ فَلْيَحْمَدْ اللَّهَ عَلَيْهَا وَلْيُحَدِّثْ بِهَا وَإِذَا رَأَى غَيْرَ ذَلِكَ مِمَّا يَكْرَهُ فَإِنَّمَا هِيَ مِنْ الشَّيْطَانِ فَلْيَسْتَعِذْ مِنْ شَرِّهَا وَلَا يَذْكُرْهَا لِأَحَدٍ فَإِنَّهَا لَا تَضُرُّهُ","id":"Telah menceritakan kepada kami [Abdullah bin Yuusf] telah menceritakan kepada kami [Al Laits] telah menceritakan kepada kami [Ibnul Al Had] dari [Abdullah bin Khabbab] dari [Abu Sa'id Al Khudri], ia mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang diantara kalian bermimpi yang ia sukai, sebenarnya mimpi tersebut berasal dari Allah, maka hendaklah ia memuji Allah karenanya dan ceritakanlah, adapun jika ia bermimpi selainnya yang tidak disukai, maka itu berasal dari setan, maka hendaklah ia meminta perlindungan dari keburukannya, dan jangan menceritakannya kepada orang lain, sehingga tidak membahayakannya.\""},"6137":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَحْيَى بْنِ أَبِي كَثِيرٍ وَأَثْنَى عَلَيْهِ خَيْرًا لَقِيتُهُ بِالْيَمَامَةِ عَنْ أَبِيهِ حَدَّثَنَا أَبُو سَلَمَةَ عَنْ أَبِي قَتَادَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الرُّؤْيَا الصَّالِحَةُ مِنْ اللَّهِ وَالْحُلْمُ مِنْ الشَّيْطَانِ فَإِذَا حَلَمَ فَلْيَتَعَوَّذْ مِنْهُ وَلْيَبْصُقْ عَنْ شِمَالِهِ فَإِنَّهَا لَا تَضُرُّهُوَعَنْ أَبِيهِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي قَتَادَةَ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abdullah bin Yahya bin Abi katsir] yang ia memujinya dengan baik, aku menemuinya di Yamamah dari [Ayahnya], telah menceritakan kepada kami [Abu Salamah] dari [Abu Qatadah] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Mimpi yang baik adalah berasal dari Allah dan mimpi buruk berasal dari setan, maka jika salah seorang diantara kalian bermimpi buruk, hendaklah meminta perlindungan kepada Allah karenanya dan meludah kesamping kirinya, sehingga mimpi buruknya tidak membahayakannya, \" dan dari [ayahnya], telah menceritakan kepada kami [Abdullah bin Abu Qatadah] dari [ayahnya] dari Nabi shallallahu 'alaihi wasallam semisalnya."},"6138":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ عُبَادَةَ بْنِ الصَّامِتِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رُؤْيَا الْمُؤْمِنِ جُزْءٌ مِنْ سِتَّةٍ وَأَرْبَعِينَ جُزْءًا مِنْ النُّبُوَّةِ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Anas bin Malik] dari [Ubadah bin Ash Shamit] dari Nabi shallallahu 'alaihi wasallam bersabda; \"mimpi seorang mukmin adalah satu bagian dari empat puluh enam bagian kenabian.\""},"6139":{"ar":"حَدَّثَنَا يَحْيَى بْنُ قَزَعَةَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رُؤْيَا الْمُؤْمِنِ جُزْءٌ مِنْ سِتَّةٍ وَأَرْبَعِينَ جُزْءًا مِنْ النُّبُوَّةِوَرَوَاهُ ثَابِتٌ وَحُمَيْدٌ وَإِسْحَاقُ بْنُ عَبْدِ اللَّهِ وَشُعَيْبٌ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Yahya bin Qaza'ah] telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Az Zuhri] dari [Sa'id bin Musayyab] dari [Abu Hurairah] radliallahu 'anhu, bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mimpi seorang mukmin adalah bagian dari enam atau empat puluh enam bagian kenabian.\" Dan hadits ini diriwayatkan oleh [Tsabit], [Humaid], [Ishaq bin Abdullah] dan [Syu'aib] dari [Anas] dari Nabi shallallahu 'alaihi wasallam."},"6140":{"ar":"حَدَّثَنِي إِبْرَاهِيمُ بْنُ حَمْزَةَ حَدَّثَنِي ابْنُ أَبِي حَازِمٍ وَالدَّرَاوَرْدِيُّ عَنْ يَزِيدَ عَنْ عَبْدِ اللَّهِ بْنِ خَبَّابٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الرُّؤْيَا الصَّالِحَةُ جُزْءٌ مِنْ سِتَّةٍ وَأَرْبَعِينَ جُزْءًا مِنْ النُّبُوَّةِ","id":"Telah menceritakan kepadaku [Ibrahim bin Hamzah] telah menceritakan kepadaku [Ibnu Abi Hazim] dan [Darawardi] dari [Yazid] dari ['Abdullah bin Khabbab] dari [Abu Sa'id Al Khudzri], ia mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Mimpi yang baik adalah bagian dari empat puluh enam kenabian.\""},"6141":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ حَدَّثَنِي سَعِيدُ بْنُ الْمُسَيَّبِ أَنَّ أَبَا هُرَيْرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَمْ يَبْقَ مِنْ النُّبُوَّةِ إِلَّا الْمُبَشِّرَاتُ قَالُوا وَمَا الْمُبَشِّرَاتُ قَالَ الرُّؤْيَا الصَّالِحَةُ","id":"Telah menceritakan kepada kami [Abul Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] telah menceritakan kepadaku [Sa'id bin Musayyab], bahwasanya [Abu Hurairah] menuturkan, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kenabian tidak ada lagi selain berita gembira, \" para sahabat bertanya; 'apa maksud kabar gembira? ' Nabi shallallahu 'alaihi wasallam menjawab; \"mimpi yang baik.\""},"6142":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُأَنَّ أُنَاسًا أُرُوا لَيْلَةَ الْقَدْرِ فِي السَّبْعِ الْأَوَاخِرِ وَأَنَّ أُنَاسًا أُرُوا أَنَّهَا فِي الْعَشْرِ الْأَوَاخِرِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْتَمِسُوهَا فِي السَّبْعِ الْأَوَاخِرِ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari [Uqail] dari [Ibnu Syihab] dari [Salim bin Abdullah] dari [Ibnu Umar] radliallahu 'anhu; ada beberapa orang yang diperlihatkan kepada mereka lailatul qadar pada tujuh malam terakhir, sedang sebagian yang lain diperlihatkan kepada mereka pada sepuluh malam terakhir, maka Nabi shallallahu 'alaihi wasallam bersabda: \"carilah pada tujuh malam terakhir.\""},"6143":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ حَدَّثَنَا جُوَيْرِيَةُ عَنْ مَالِكٍ عَنْ الزُّهْرِيِّ أَنَّ سَعِيدَ بْنَ الْمُسَيَّبِ وَأَبَا عُبَيْدٍ أَخْبَرَاهُ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ لَبِثْتُ فِي السِّجْنِ مَا لَبِثَ يُوسُفُ ثُمَّ أَتَانِي الدَّاعِي لَأَجَبْتُهُ","id":"Telah menceritakan kepada kami [Abdullah] telah menceritakan kepada kami [Juwairiyah] dari [Malik] dari [Az Zuhri], bahwasanya [Sa'id bin Musayyab] dan [Abu Ubaid] mengabarkan kepadanya dari [Abu Hurairah] radliallahu 'anhu mengatakan, Rasulullah Shallallahu'alaihiwasallam bersabda; \"kalaulah aku mendekam dalam penjara sekian lama sebagaimana Yusuf, kemudian seorang penyeru mendatangiku, niscaya kupenuhi panggilannya.\""},"6144":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا عَبْدُ اللَّهِ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ حَدَّثَنِي أَبُو سَلَمَةَ أَنَّ أَبَا هُرَيْرَةَ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ رَآنِي فِي الْمَنَامِ فَسَيَرَانِي فِي الْيَقَظَةِ وَلَا يَتَمَثَّلُ الشَّيْطَانُ بِيقَالَ أَبُو عَبْد اللَّهِ قَالَ ابْنُ سِيرِينَ إِذَا رَآهُ فِي صُورَتِهِ","id":"Telah menceritakan kepada kami ['Abdan] telah mengabarkan kepada kami [Abdullah] dari [Yunus] dari [Az Zuhri] telah menceritakan kepadaku [Abu Salamah], bahwasanya [Abu Hurairah] mengatakan, aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa melihatku dalam tidur, maka (seakan-akan) ia melihatku ketika terjaga, (karena) setan tidak bisa menyerupaiku.\" Abu Abdullah mengatakan, Ibnu Sirin mengatakan; 'Maksudnya jika melihat beliau dengan bentuk (asli) beliau.'"},"6145":{"ar":"حَدَّثَنَا مُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُخْتَارٍ حَدَّثَنَا ثَابِتٌ الْبُنَانِيُّ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ رَآنِي فِي الْمَنَامِ فَقَدْ رَآنِي فَإِنَّ الشَّيْطَانَ لَا يَتَخَيَّلُ بِي وَرُؤْيَا الْمُؤْمِنِ جُزْءٌ مِنْ سِتَّةٍ وَأَرْبَعِينَ جُزْءًا مِنْ النُّبُوَّةِ","id":"Telah menceritakan kepada kami [Mu'allaa bin Asad] telah menceritakan kepada kami ['Abdul 'Aziz bin Mukhtar] telah menceritakan kepada kami [Tsabit Al Bunani] dari [Anas] radliallahu 'anhu mengatakan, Nabi shallallahu 'alaihi wasallam bersabda: \"Siapa melihatku dalam mimpi, berarti ia telah melihatku, sebab setan tidak bisa menjelma sepertiku, dan mimpi seorang mukmin adalah sebagian dari empat puluh enam bagian kenabian.\""},"6146":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي جَعْفَرٍ أَخْبَرَنِي أَبُو سَلَمَةَ عَنْ أَبِي قَتَادَةَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الرُّؤْيَا الصَّالِحَةُ مِنْ اللَّهِ وَالْحُلْمُ مِنْ الشَّيْطَانِ فَمَنْ رَأَى شَيْئًا يَكْرَهُهُ فَلْيَنْفِثْ عَنْ شِمَالِهِ ثَلَاثًا وَلْيَتَعَوَّذْ مِنْ الشَّيْطَانِ فَإِنَّهَا لَا تَضُرُّهُ وَإِنَّ الشَّيْطَانَ لَا يَتَرَاءَى بِي","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari [Ubaidullah bin Abi Ja'far] telah mengabarkan kepadaku [Abu Salamah] dari [Abu Qatadah] mengatakan, Nabi Shallallahu'alaihiwasallam bersabda: \"Mimpi yang baik adalah berasal dari Allah, sedang mimpi yang buruk berasal dari setan, maka barangsiapa melihat sesuatu yang tidak disukainya, hendaklah ia meludah ke samping kirinya sebanyak tiga kali, dan mintalah perlindungan dari setan, sesungguhnya mimpinya tersebut tidak akan membahayakannya, dan setan tidak mungkin bisa menyerupaiku.\""},"6147":{"ar":"حَدَّثَنَا خَالِدُ بْنُ خَلِيٍّ حَدَّثَنَا مُحَمَّدُ بْنُ حَرْبٍ حَدَّثَنِي الزُّبَيْدِيُّ عَنْ الزُّهْرِيِّ قَالَ أَبُو سَلَمَةَ قَالَ أَبُو قَتَادَةَ رَضِيَ اللَّهُ عَنْهُقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ رَآنِي فَقَدْ رَأَى الْحَقَّتَابَعَهُ يُونُسُ وَابْنُ أَخِي الزُّهْرِيِّ","id":"Telah menceritakan kepada kami [Khalid bin Khali] telah menceritakan kepada kami [Muhammad bin Harb] telah menceritakan kepadaku [Az Zubaidi] dari [Az Zuhri], [Abu Salamah] mengatakan; [Abu Qatadah] radliallahu 'anhu mengatakan, Nabi Shallallahu'alaihiwasallam bersabda: \"Barangsiapa melihatku berarti telah melihat yang sebenarnya.\" Hadis ini dikuatkan oleh [Yunus] dan [Ibnu Akhi Az Zuhri]."},"6148":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا اللَّيْثُ حَدَّثَنِي ابْنُ الْهَادِ عَنْ عَبْدِ اللَّهِ بْنِ خَبَّابٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ رَآنِي فَقَدْ رَأَى الْحَقَّ فَإِنَّ الشَّيْطَانَ لَا يَتَكَوَّنُنِي","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] telah menceritakan kepada kami [Al Laits] telah menceritakan kepadaku [Ibnul Al Had] dari [Abdullah bin Khabbab] dari [Abu Sa'id Al Khudzri], ia mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa melihatku, berarti ia telah melihat yang sebenarnya, sebab setan tak bisa menjelma sepertiku.\""},"6149":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ الْمِقْدَامِ الْعِجْلِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ الطُّفَاوِيُّ حَدَّثَنَا أَيُّوبُ عَنْ مُحَمَّدٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُعْطِيتُ مَفَاتِيحَ الْكَلِمِ وَنُصِرْتُ بِالرُّعْبِ وَبَيْنَمَا أَنَا نَائِمٌ الْبَارِحَةَ إِذْ أُتِيتُ بِمَفَاتِيحِ خَزَائِنِ الْأَرْضِ حَتَّى وُضِعَتْ فِي يَدِي قَالَ أَبُو هُرَيْرَةَ فَذَهَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنْتُمْ تَنْتَقِلُونَهَا","id":"Telah menceritakan kepada kami [Ahmad bin Al Miqdam Al 'ijli] telah menceritakan kepada kami [Muhammad bin Abdurrahman Ath Thufawi] telah menceritakan kepada kami [Ayyub] dari [Muhammad] dari [Abu Hurairah] mengatakan, Nabi Shallallahu'alaihiwasallam bersabda: \"Aku diberi kunci-kunci al kalim, aku diberi pertolongan dengan ketakutan yang dihunjamkan kedalam dada musuh-musuhku, ketika aku tidur tadi malam, tiba-tiba aku diberi kunci-kunci perbendaharaan bumi hingga diletakkan dalam tanganku.\" Abu Hurairah mengatakan; 'Rasulullah Shallallahu'alaihiwasallam lantas pergi sedang kalian memindahkannya.' "},"6150":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أُرَانِي اللَّيْلَةَ عِنْدَ الْكَعْبَةِ فَرَأَيْتُ رَجُلًا آدَمَ كَأَحْسَنِ مَا أَنْتَ رَاءٍ مِنْ أُدْمِ الرِّجَالِ لَهُ لِمَّةٌ كَأَحْسَنِ مَا أَنْتَ رَاءٍ مِنْ اللِّمَمِ قَدْ رَجَّلَهَا تَقْطُرُ مَاءً مُتَّكِئًا عَلَى رَجُلَيْنِ أَوْ عَلَى عَوَاتِقِ رَجُلَيْنِ يَطُوفُ بِالْبَيْتِ فَسَأَلْتُ مَنْ هَذَا فَقِيلَ الْمَسِيحُ ابْنُ مَرْيَمَ ثُمَّ إِذَا أَنَا بِرَجُلٍ جَعْدٍ قَطَطٍ أَعْوَرِ الْعَيْنِ الْيُمْنَى كَأَنَّهَا عِنَبَةٌ طَافِيَةٌ فَسَأَلْتُ مَنْ هَذَا فَقِيلَ الْمَسِيحُ الدَّجَّالُ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Nafi'] dari ['Abdullah bin Umar] radliallahu 'anhuma, Rasulullah shallallahu 'alaihi wasallam bersabda: \"tadi malam aku diperlihatkan di dekat Ka'bah, aku melihat seorang laki-laki yang kulitnya kemerah-merahan dengan postur manusia paling rupawan yang pernah kamu lihat, rambutnya memanjang hingga sebahu dengan penampilan paling mengesankan, ia tengah menyisiri rambutnya yang meneteskan air, ia bersandaran diatas kedua kakinya, atau diatas tengkuk kedua kakinya, ia thawaf di baitullah, maka aku bertanya; 'Siapakah orang ini? ' Ada jawaban; 'ia adalah Isa bin maryam.' Kemudian tiba-tiba aku bersama seseorang yang rambutnya sangat keriting, matanya buta sebelah kanan seolah-olah buah anggur yang menjorok, maka aku bertanya; 'Siapakah orang ini? ' Ada jawaban; '(dia) al masih ad dajjal.\""},"6151":{"ar":"حَدَّثَنَا يَحْيَى حَدَّثَنَا اللَّيْثُ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ أَنَّ ابْنَ عَبَّاسٍ كَانَ يُحَدِّثُأَنَّ رَجُلًا أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي أُرِيتُ اللَّيْلَةَ فِي الْمَنَامِ وَسَاقَ الْحَدِيثَوَتَابَعَهُ سُلَيْمَانُ بْنُ كَثِيرٍ وَابْنُ أَخِي الزُّهْرِيِّ وَسُفْيَانُ بْنُ حُسَيْنٍ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ الزُّبَيْدِيُّ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ أَنَّ ابْنَ عَبَّاسٍ أَوْ أَبَا هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ شُعَيْبٌ وَإِسْحَاقُ بْنُ يَحْيَى عَنْ الزُّهْرِيِّ كَانَ أَبُو هُرَيْرَةَ يُحَدِّثُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ مَعْمَرٌ لَا يُسْنِدُهُ حَتَّى كَانَ بَعْدُ","id":"Telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Al Laits] dari [Yunus] dari [Ibnu Syihab] dari [Ubaidullah bin Abdullah], [Ibnu 'Abbas] bercerita; bahwa ada seseorang menemui Rasulullah shallallahu 'alaihi wasallam dan berujar; 'Semalam aku diperlihatkan dalam mimpi, ' lalu ia memaparkan hadits tersebut. Dan hadits ini dikuatkan oleh [Sulaiman bin Katsir], [Ibnu Akhi Az Zuhri] dan [Sufyan bin Husain] dari [Az Zuhri] dari [Ubaidullah] dari [Ibnu 'Abbas] dari Nabi shallallahu 'alaihi wasallam. Dan [Az Zubaidi] mengatakan dari [Az Zuhri] dari [Ubaidullah], bahwasa [Ibnu Abbas] atau [Abu Hurairah] dari Nabi Shallallahu'alaihiwasallam. Sedang [Syu'aib] dan [Ishaq bin Yahya] mengatakan dari [Az Zuhri] dari adalah [Abu Hurairah] menceritakan dari Nabi shallallahu 'alaihi wasallam, dan Ma'mar tidak menyandarkannya hingga waktu selanjutnya."},"6152":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍ يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْخُلُ عَلَى أُمِّ حَرَامٍ بِنْتِ مِلْحَانَ وَكَانَتْ تَحْتَ عُبَادَةَ بْنِ الصَّامِتِ فَدَخَلَ عَلَيْهَا يَوْمًا فَأَطْعَمَتْهُ وَجَعَلَتْ تَفْلِي رَأْسَهُ فَنَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ اسْتَيْقَظَ وَهُوَ يَضْحَكُ قَالَتْ فَقُلْتُ مَا يُضْحِكُكَ يَا رَسُولَ اللَّهِ قَالَ نَاسٌ مِنْ أُمَّتِي عُرِضُوا عَلَيَّ غُزَاةً فِي سَبِيلِ اللَّهِ يَرْكَبُونَ ثَبَجَ هَذَا الْبَحْرِ مُلُوكًا عَلَى الْأَسِرَّةِ أَوْ مِثْلَ الْمُلُوكِ عَلَى الْأَسِرَّةِ شَكَّ إِسْحَاقُ قَالَتْ فَقُلْتُ يَا رَسُولَ اللَّهِ ادْعُ اللَّهَ أَنْ يَجْعَلَنِي مِنْهُمْ فَدَعَا لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ وَضَعَ رَأْسَهُ ثُمَّ اسْتَيْقَظَ وَهُوَ يَضْحَكُ فَقُلْتُ مَا يُضْحِكُكَ يَا رَسُولَ اللَّهِ قَالَ نَاسٌ مِنْ أُمَّتِي عُرِضُوا عَلَيَّ غُزَاةً فِي سَبِيلِ اللَّهِ كَمَا قَالَ فِي الْأُولَى قَالَتْ فَقُلْتُ يَا رَسُولَ اللَّهِ ادْعُ اللَّهَ أَنْ يَجْعَلَنِي مِنْهُمْ قَالَ أَنْتِ مِنْ الْأَوَّلِينَ فَرَكِبَتْ الْبَحْرَ فِي زَمَانِ مُعَاوِيَةَ بْنِ أَبِي سُفْيَانَ فَصُرِعَتْ عَنْ دَابَّتِهَا حِينَ خَرَجَتْ مِنْ الْبَحْرِ فَهَلَكَتْ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf], Telah mengabarkan kepada kami [Malik] dari [Ishaq bin Abdullah bin Abu Thalhah], ia mendengar [Anas bin Malik] mengatakan, Rasulullah Shallallahu'alaihiwasallam Pernah menemui Ummu haram binti Milhan yang diperistiri oleh 'Ubadah bin Shamit. Suatu hari beliau shallallahu 'alaihi wasallam menemuinya, dan Ummu Haram memberinya makanan dan mencari kutu di kepalanya. kemudian Rasulullah shallallahu 'alaihi wasallam tertidur, lantas bangun dan tertawa. Kata Ummu Haram; saya bertanya; 'Apa yang menjadikanmu tertawa ya Rasulullah? ' Beliau menjawab: \"Sekian orang dari umatku diperlihatkan kepadaku dalam keadaan berperang fii sabiilillah, mereka mengarungi permukaan lautan sebagai raja-raja diatas permadani, -atau dengan redaksi- seperti raja-raja diatas permadani \"- Ishaq ragu kepastian redaksinya.- Kata Ummu haram; 'ya Rasulullah, doakanlah aku agar Allah menjadikan diriku diantara mereka? ' maka Rasulullah shallallahu 'alaihi wasallam mendoakan untuknya. Kemudian Rasulullah shallallahu 'alaihi wasallam meletakkan kepalanya, kemudian bangun dengan tertawa, maka aku(Ummu Haram) bertanya; 'Apa yang menjadikan dirimu tertawa ya Rasulullah? ' Nabi menjawab; \"ada beberapa manusia dari kalangan umatku menjadi pejuang fii sabilillah, \" dan seterusnya sebagaimana diatas. Ummu Haram berkata; 'ya Rasulullah, doakanlah aku agar Allah menjadikan diriku diantara mereka! ' Nabi bersabda: \"engkau termasuk rombongan pejuang yang pertama.\" Kemudian Ummu Haram mengarungi lautan di zaman pemerintahan Mu'awiyah bin Abu Sufyan, dan hewan tunggangannya terpeleset ketika keluar dari lautan, sehingga Ummu haram meninggal."},"6153":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عُفَيْرٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي خَارِجَةُ بْنُ زَيْدِ بْنِ ثَابِتٍ أَنَّ أُمَّ الْعَلَاءِامْرَأَةً مِنْ الْأَنْصَارِ بَايَعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَتْهُ أَنَّهُمْ اقْتَسَمُوا الْمُهَاجِرِينَ قُرْعَةً قَالَتْ فَطَارَ لَنَا عُثْمَانُ بْنُ مَظْعُونٍ وَأَنْزَلْنَاهُ فِي أَبْيَاتِنَا فَوَجِعَ وَجَعَهُ الَّذِي تُوُفِّيَ فِيهِ فَلَمَّا تُوُفِّيَ غُسِّلَ وَكُفِّنَ فِي أَثْوَابِهِ دَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ رَحْمَةُ اللَّهِ عَلَيْكَ أَبَا السَّائِبِ فَشَهَادَتِي عَلَيْكَ لَقَدْ أَكْرَمَكَ اللَّهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَا يُدْرِيكِ أَنَّ اللَّهَ أَكْرَمَهُ فَقُلْتُ بِأَبِي أَنْتَ يَا رَسُولَ اللَّهِ فَمَنْ يُكْرِمُهُ اللَّهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّا هُوَ فَوَاللَّهِ لَقَدْ جَاءَهُ الْيَقِينُ وَاللَّهِ إِنِّي لَأَرْجُو لَهُ الْخَيْرَ وَ وَاللَّهِ مَا أَدْرِي وَأَنَا رَسُولُ اللَّهِ مَاذَا يُفْعَلُ بِي فَقَالَتْ وَاللَّهِ لَا أُزَكِّي بَعْدَهُ أَحَدًا أَبَدًاحَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ بِهَذَا وَقَالَ مَا أَدْرِي مَا يُفْعَلُ بِهِ قَالَتْ وَأَحْزَنَنِي فَنِمْتُ فَرَأَيْتُ لِعُثْمَانَ عَيْنًا تَجْرِي فَأَخْبَرْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ذَلِكَ عَمَلُهُ","id":"Telah menceritakan kepada kami [Sa'id bin 'Ufair] telah menceritakan kepadaku [Al Laits] telah menceritakan kepada kami [Uqail] dari [Ibnu Syihab] telah mengabarkan kepadaku [Kharijah bin Zaid bin Tsabit], bahwa [Ummul 'Ala] seorang wanita anshar yang pernah berbai'at kepada Rasulullah Shallallahu'alaihiwasallam mengabarinya; bahwasanya para sahabat membagi-bagi kantong kulit kepada kaum muhajirin, tiba-tiba Utsman bin mazh'un bergegas menemui kami, dan kami tempatkan didalam rumah kami, kemudian ia sakit yang menyebabkan kematiannya. Tatkala ia meninggal, dia dimandikan dan dikafankan dalam kainnya, Rasulullah Shallallahu'alaihiwasallam masuk. Lantas saya bergumam; 'Kiranya rahmat Alalh terlimpah kepadamu hai Abu Saib, dan persaksianku terhadap dirimu, sungguh Allah telah memuliakanmu.' Rasulullah Shallallahu'alaihiwasallam bertanya: \"dari mana kamu tahu bahwa Allah telah memuliakannya?\" Saya menjawab; 'Dengan ayahku sebagai tebusanmu ya Rasulullah, siapakah yang dimuliakan Allah? ' Rasulullah bersabda; \"Adapun dia, demi Allah, kematian telah merenggutnya, demi Allah, sungguh aku berharap ia memperoleh kebaikan, dan demi Allah, saya tidak tahu bagaimana aku diperlakukan nanti sedang aku Rasulullah.\" Kata Ummul 'Ala; Demi Allah, saya sama sekali tidak akan mensucikan seseorang setelahnya selamanya.' Telah menceritakan kepada kami [Abul Yaman] Telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dengan isnad ini, dan ia mengatakan; \"Saya tidak tahu, bagaimana aku diperlakukan!\" kata Ummul 'Ala; hal itu menjadikanku sedih sehingga aku tidur dan aku bermimpi melihat 'Utsman mempunyai mata air yang mengalir, dan aku kabarkan kepada Rasulullah Shallallahu'alaihiwasallam, dan beliau bersabda: \"Itulah amalnya.\""},"6154":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ أَنَّ أَبَا قَتَادَةَ الْأَنْصَارِيَّوَكَانَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفُرْسَانِهِ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الرُّؤْيَا مِنْ اللَّهِ وَالْحُلْمُ مِنْ الشَّيْطَانِ فَإِذَا حَلَمَ أَحَدُكُمْ الْحُلُمَ يَكْرَهُهُ فَلْيَبْصُقْ عَنْ يَسَارِهِ وَلْيَسْتَعِذْ بِاللَّهِ مِنْهُ فَلَنْ يَضُرَّهُ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari [Uqail] dari [Ibnu Syihab] dari [Abu Salamah], bahwasanya [Qatadah Al Anshari] dan dia termasuk dari kalangan sahabat Nabi shallallahu 'alaihi wasallam dan pejuang penunggang kudanya, mengatakan; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mimpi yang baik adalah berasal dari Allah, sedang mimpi yang buruk berasal dari setan, maka jika salah seorang diantara kalian bermimpi yang tidak disukainya, hendaklah meludah ke sebelah kirinya dan meminta perlindungan kepada Allah, niscaya yang sedemikian itu tidak membahayaknnya.\""},"6155":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ أَخْبَرَنِي حَمْزَةُ بْنُ عَبْدِ اللَّهِ أَنَّ ابْنَ عُمَرَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ بَيْنَا أَنَا نَائِمٌ أُتِيتُ بِقَدَحِ لَبَنٍ فَشَرِبْتُ مِنْهُ حَتَّى إِنِّي لَأَرَى الرِّيَّ يَخْرُجُ مِنْ أَظْفَارِي ثُمَّ أَعْطَيْتُ فَضْلِي يَعْنِي عُمَرَ قَالُوا فَمَا أَوَّلْتَهُ يَا رَسُولَ اللَّهِ قَالَ الْعِلْمَ","id":"Telah menceritakan kepada kami ['Abdan] Telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Yunus] dari [Az Zuhri] telah mengabarkan kepadaku [Hamzah bin 'Abdullah], bahwasanya [Ibnu Umar] mengatakan, aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketika aku tertidur, aku diberi gelas susu, lantas aku minum sehingga kulihat sungai keluar dari kuku-kuku-ku, kemudian kelebihannya aku berikan kepada Umar.\" Para sahabat bertanya; 'Lantas bagaimana anda takwilkan ya Rasulullah? ' Nabi menjawab; \"itulah ilmu.\""},"6156":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ حَدَّثَنِي حَمْزَةُ بْنُ عَبْدِ اللَّهِ بْنِ عُمَرَ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَا أَنَا نَائِمٌ أُتِيتُ بِقَدَحِ لَبَنٍ فَشَرِبْتُ مِنْهُ حَتَّى إِنِّي لَأَرَى الرِّيَّ يَخْرُجُ مِنْ أَطْرَافِي فَأَعْطَيْتُ فَضْلِي عُمَرَ بْنَ الْخَطَّابِ فَقَالَ مَنْ حَوْلَهُ فَمَا أَوَّلْتَ ذَلِكَ يَا رَسُولَ اللَّهِ قَالَ الْعِلْمَ","id":"Telah menceritakan kepada kami ['Ali bin Abdullah] telah menceritakan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepada kami [Ayahku] dari [Abu Shalih] dari [Ibnu Syihab] telah menceritakan kepadaku [Hamzah bin Abdullah bin Umar], bahwasanya ia mendengar [Abdullah bin Umar] radliallahu 'anhuma mengatakan, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketika aku tidur, aku diberi segelas susu, lantas aku meminumnya hingga aku betul-betul melihat sungai dari ujung-ujung jari jemariku, lantas kuberikan kelebihannya kepada Umar bin Khattab.\" Maka para sahabat yang di sekitarnya berujar; 'bagaimana engkau takwilkan Ya Rasulullah? ' Beliau menjawab; \"seperti itulah ilmu.\""},"6157":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنِي أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ قَالَ حَدَّثَنِي أَبُو أُمَامَةَ بْنُ سَهْلٍ أَنَّهُ سَمِعَ أَبَا سَعِيدٍ الْخُدْرِيَّ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَمَا أَنَا نَائِمٌ رَأَيْتُ النَّاسَ يُعْرَضُونَ عَلَيَّ وَعَلَيْهِمْ قُمُصٌ مِنْهَا مَا يَبْلُغُ الثَّدْيَ وَمِنْهَا مَا يَبْلُغُ دُونَ ذَلِكَ وَمَرَّ عَلَيَّ عُمَرُ بْنُ الْخَطَّابِ وَعَلَيْهِ قَمِيصٌ يَجُرُّهُ قَالُوا مَا أَوَّلْتَهُ يَا رَسُولَ اللَّهِ قَالَ الدِّينَ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepadaku [Ayahku] dari [Shalih] dari [Ibnu Syihab] mengatakan, telah menceritakan kepadaku [Abu Umamah bin Sahal] bahwasanya ia mendengar [Abu Sa'id Al Khudzri] mengatakan; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketika aku tidur, aku melihat manusia diperlihatkan kepadaku sedang mereka memakai baju gamis, ada yang sampai ke dadanya, ada yang sampai lebih bawah daripada itu, dan Umar bin Khattab melewati dengan gamis yang ia seret.\" Para sahabat bertanya; 'Bagaimana anda menakwilkan? ' Rasulullah menjawab: \"Itulah agama!\""},"6158":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عُفَيْرٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي أَبُو أُمَامَةَ بْنُ سَهْلٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُ أَنَّهُ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ بَيْنَا أَنَا نَائِمٌ رَأَيْتُ النَّاسَ عُرِضُوا عَلَيَّ وَعَلَيْهِمْ قُمُصٌ فَمِنْهَا مَا يَبْلُغُ الثَّدْيَ وَمِنْهَا مَا يَبْلُغُ دُونَ ذَلِكَ وَعُرِضَ عَلَيَّ عُمَرُ بْنُ الْخَطَّابِ وَعَلَيْهِ قَمِيصٌ يَجْتَرُّهُ قَالُوا فَمَا أَوَّلْتَهُ يَا رَسُولَ اللَّهِ قَالَ الدِّينَ","id":"Telah menceritakan kepada kami [Sa'id bin 'Ufair] telah menceritakan kepadaku [Al Laits] telah menceritakan kepadaku [Uqail] dari [Ibnu Syihab] telah mengabarkan kepadaku [Abu Umamah bin Sahal] dari [Abu Sa'id Al Khudzri] radliallahu 'anhu mengatakan; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketika aku tidur, diperlihatkan manusia padaku dan mereka memakai gamis, diantaranya ada yang sampai putting susunya, ada yang dibawahnya, dan Umar diperlihatkan kepadaku sedang menyeret baju gamisnya.\" Para sahabat bertanya; 'bagaimana anda menakwilkan ya Rasulullah? ' Nabi menjawab; \"itulah agama.\""},"6159":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ الْجُعْفِيُّ حَدَّثَنَا حَرَمِيُّ بْنُ عُمَارَةَ حَدَّثَنَا قُرَّةُ بْنُ خَالِدٍ عَنْ مُحَمَّدِ بْنِ سِيرِينَ قَالَ قَالَ قَيْسُ بْنُ عُبَادٍكُنْتُ فِي حَلْقَةٍ فِيهَا سَعْدُ بْنُ مَالِكٍ وَابْنُ عُمَرَ فَمَرَّ عَبْدُ اللَّهِ بْنُ سَلَامٍ فَقَالُوا هَذَا رَجُلٌ مِنْ أَهْلِ الْجَنَّةِ فَقُلْتُ لَهُ إِنَّهُمْ قَالُوا كَذَا وَكَذَا قَالَ سُبْحَانَ اللَّهِ مَا كَانَ يَنْبَغِي لَهُمْ أَنْ يَقُولُوا مَا لَيْسَ لَهُمْ بِهِ عِلْمٌ إِنَّمَا رَأَيْتُ كَأَنَّمَا عَمُودٌ وُضِعَ فِي رَوْضَةٍ خَضْرَاءَ فَنُصِبَ فِيهَا وَفِي رَأْسِهَا عُرْوَةٌ وَفِي أَسْفَلِهَا مِنْصَفٌ وَالْمِنْصَفُ الْوَصِيفُ فَقِيلَ ارْقَهْ فَرَقِيتُهُ حَتَّى أَخَذْتُ بِالْعُرْوَةِ فَقَصَصْتُهَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمُوتُ عَبْدُ اللَّهِ وَهُوَ آخِذٌ بِالْعُرْوَةِ الْوُثْقَى","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad Al Ju'fi] telah menceritakan kepada kami [Harami bin Umarah] telah menceritakan kepada kami [Qurrah bin Khalid] dari [Muhammad bin Sirin] mengatakan, [Qais bin Ubad] mengatakan; aku berada di suatu halaqah yang disana terdapat Sa'd bin malik dan Ibnu Umar, lantas [Abdullah bin Salam] lewat, kemudian mereka mengatakan; 'Ini adalah seorang penghuni surga.' Maka saya katakan kepada Abdullah bahwa mereka telah mengatakan demikian dan demikian. Spontan Abdullah bin Salam mengatakan: 'Subhanallah, tak sepantasnya mereka mengucapkan suatu hal yang mereka tidak mempunyai pengetahuan tentangnya, hanyasanya aku bermimpi seolah-olah ada sebuah tiang yang diletakkan dalam sebuah kebun hijau, kemudian tiang itu ditegakkan disana sedang di ujung tongkat itu terdapat tali dan bagian bawahnya terdapat seorang pelayan, kemudian ada suatu suara yang terdengar; 'naikilah tiang tersebut! ' Maka aku menaikinya hingga aku berhasil mengambil tali. Kejadian ini aku kisahkan kepada Rasulullah Shallallahu'alaihiwasallam, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Abdullah bin Salam meninggal sedang ia memegang tali yang kokoh.\""},"6160":{"ar":"حَدَّثَنَا عُبَيْدُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُرِيتُكِ فِي الْمَنَامِ مَرَّتَيْنِ إِذَا رَجُلٌ يَحْمِلُكِ فِي سَرَقَةٍ مِنْ حَرِيرٍ فَيَقُولُ هَذِهِ امْرَأَتُكَ فَأَكْشِفُهَا فَإِذَا هِيَ أَنْتِ فَأَقُولُ إِنْ يَكُنْ هَذَا مِنْ عِنْدِ اللَّهِ يُمْضِهِ","id":"Telah menceritakan kepada kami [Ubaid bin Isma'il] telah menceritakan kepada kami [Abu Usamah] dari [Hisyam] dari [ayahnya] dari [Aisyah] radliallahu 'anha mengatakan, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kulihat engkau dalam mimpi dua kali, tak tahunya ada seseorang menggendongmu dengan sehelai kain sutera, dan berujar; 'Ini isterimu! ' maka aku singkap, tak tahunya adalah engkau, maka kukatakan; 'Kalaulah ini berasal dari Allah, lakukanlah! '\""},"6161":{"ar":"حَدَّثَنَا مُحَمَّدٌ أَخْبَرَنَا أَبُو مُعَاوِيَةَ أَخْبَرَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُرِيتُكِ قَبْلَ أَنْ أَتَزَوَّجَكِ مَرَّتَيْنِ رَأَيْتُ الْمَلَكَ يَحْمِلُكِ فِي سَرَقَةٍ مِنْ حَرِيرٍ فَقُلْتُ لَهُ اكْشِفْ فَكَشَفَ فَإِذَا هِيَ أَنْتِ فَقُلْتُ إِنْ يَكُنْ هَذَا مِنْ عِنْدِ اللَّهِ يُمْضِهِ ثُمَّ أُرِيتُكِ يَحْمِلُكِ فِي سَرَقَةٍ مِنْ حَرِيرٍ فَقُلْتُ اكْشِفْ فَكَشَفَ فَإِذَا هِيَ أَنْتِ فَقُلْتُ إِنْ يَكُ هَذَا مِنْ عِنْدِ اللَّهِ يُمْضِهِ","id":"Telah menceritakan kepada kami [Muhammad] telah mengabarkan kepada kami [Abu Mu'awiyah] telah mengabarkan kepada kami [Hisyam] dari [ayahnya] dari [Aisyah] mengatakan, Rasulullah shallallahu 'alaihi wasallam bersabda: \"aku melihatmu dalam mimpi sebelum aku menikahimu sebanyak dua kali, kulihat seorang malaikat menggendongmu dalam sebuah kain sutera, maka aku berujar; 'singkaplah kain ini! ' maka malaikat tersebut menyingkapnya, dan ternyata engkau. Maka aku katakan; 'Kalaulah ini benar-benar dari Allah, laksanakanlah! ' Kemudian engkau diperlihatkan dalam mimpiku, ada malaikat yang menggendongmu dalam sehelai kain sutera, maka aku berujar; 'singkaplah kainnya! ' malaikat pun menyingkapnya, dan ternyata engkau, maka kukatakan; 'Kalaulah ini dari Allah, laksanakanlah! '\""},"6162":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عُفَيْرٍ حَدَّثَنَا اللَّيْثُ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ أَنَّ أَبَا هُرَيْرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ بُعِثْتُ بِجَوَامِعِ الْكَلِمِ وَنُصِرْتُ بِالرُّعْبِ وَبَيْنَا أَنَا نَائِمٌ أُتِيتُ بِمَفَاتِيحِ خَزَائِنِ الْأَرْضِ فَوُضِعَتْ فِي يَدِيقَالَ أَبُو عَبْد اللَّهِ وَبَلَغَنِي أَنَّ جَوَامِعَ الْكَلِمِ أَنَّ اللَّهَ يَجْمَعُ الْأُمُورَ الْكَثِيرَةَ الَّتِي كَانَتْ تُكْتَبُ فِي الْكُتُبِ قَبْلَهُ فِي الْأَمْرِ الْوَاحِدِ وَالْأَمْرَيْنِ أَوْ نَحْوَ ذَلِكَ","id":"Telah menceritakan kepada kami [Sa'id bin 'Ufair] Telah menceritakan kepada kami [Al Laits] telah menceritakan kepadaku [Uqail] dari [Ibnu Syihab] telah mengabarkan kepadaku [Sa'id bin Musayyab], bahwasanya [Abu Hurairah] mengatakan, aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku diutus dengan membawa jawami' kalim, dan aku diberi pertolongan dengan rasa takut yang dihunjamkan dalam dada-dada musuhku, dan ketika aku tidur, aku diberi kunci-kunci perbendaharaan bumi, dan diletakkan pada kedua tanganku.\" Abu Abdullah mengatakan, dan sampai berita kepadaku bahwa makna jawami' kalim ialah, Allah menghimpun sekian banyak masalah yang pernah ditulis dalam kitab-kitab suci sebelumnya dalam satu masalah atau dua masalah, atau seperti itu. "},"6163":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا أَزْهَرُ عَنْ ابْنِ عَوْنٍ ح و حَدَّثَنِي خَلِيفَةُ حَدَّثَنَا مُعَاذٌ حَدَّثَنَا ابْنُ عَوْنٍ عَنْ مُحَمَّدٍ حَدَّثَنَا قَيْسُ بْنُ عُبَادٍ عَنْ عَبْدِ اللَّهِ بْنِ سَلَامٍ قَالَرَأَيْتُ كَأَنِّي فِي رَوْضَةٍ وَوَسَطَ الرَّوْضَةِ عَمُودٌ فِي أَعْلَى الْعَمُودِ عُرْوَةٌ فَقِيلَ لِي ارْقَهْ قُلْتُ لَا أَسْتَطِيعُ فَأَتَانِي وَصِيفٌ فَرَفَعَ ثِيَابِي فَرَقِيتُ فَاسْتَمْسَكْتُ بِالْعُرْوَةِ فَانْتَبَهْتُ وَأَنَا مُسْتَمْسِكٌ بِهَا فَقَصَصْتُهَا عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ تِلْكَ الرَّوْضَةُ رَوْضَةُ الْإِسْلَامِ وَذَلِكَ الْعَمُودُ عَمُودُ الْإِسْلَامِ وَتِلْكَ الْعُرْوَةُ عُرْوَةُ الْوُثْقَى لَا تَزَالُ مُسْتَمْسِكًا بِالْإِسْلَامِ حَتَّى تَمُوتَ","id":"Telah menceritakan kepadaku ['Abdullah bin Muhammad] telah menceritakan kepada kami [Azhar] dari [Ibnu Aun] -lewat jalur periwayatan lain-dan telah menceritakan kepadaku [Khalifah] telah menceritakan kepada kami [Mu'adz] telah menceritakan kepada kami [Ibnu 'Aun] dari [Muhammad] telah menceritakan kepada kami [Qais bin Ubbad] dari ['Abdullah bin Salam] mengatakan; di sebuah taman atau tengah-tengah taman seolah-olah aku melihat sebuah tiang yang bagian paling atas tiang terdapat tali, kemudian dikatakan kepadaku; 'naikilah! ' aku berkata; 'aku tidak bisa menaikinya! ' lantas seorang pelayan mendatangiku dan mengangkat pakaianku, dan aku dinaikkan, dan aku berpegang erat dengan tali tersebut. Tiba-tiba aku terbangun dalam kondisi masih berpegangan dengan tali itu. Kejadian mimpiku ini kukisahkan kepada Rasulullah Shallallahu'alaihiwasallam, dan beliau bersabda; \"Taman itu maksudnya taman Islam, dan tiang itu maksudnya tiang Islam, dan tali itu maksudnya tali yang kokoh, engkau senantiasa memegang teguh Islam, hingga engkau meninggal.\""},"6164":{"ar":"حَدَّثَنَا مُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا وُهَيْبٌ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَرَأَيْتُ فِي الْمَنَامِ كَأَنَّ فِي يَدِي سَرَقَةً مِنْ حَرِيرٍ لَا أَهْوِي بِهَا إِلَى مَكَانٍ فِي الْجَنَّةِ إِلَّا طَارَتْ بِي إِلَيْهِ فَقَصَصْتُهَا عَلَى حَفْصَةَ فَقَصَّتْهَا حَفْصَةُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ أَخَاكِ رَجُلٌ صَالِحٌ أَوْ قَالَ إِنَّ عَبْدَ اللَّهِ رَجُلٌ صَالِحٌ","id":"Telah menceritakan kepada kami [Mu'alla bin Asad] telah menceritakan kepada kami [Wuhaib] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhuma, mengatakan; aku bermimpi dalam tidur, seolah-olah di tanganku ada sehelai kain sutera, tidaklah aku berkeinginan menuju suatu tempat dalam surga dengan membawanya melainkan kain itu menerbangkan aku. Maka kukisahkan mimpiku kepada [Hafshah], dan Hafshah mengisahkan kepada Nabi shallallahu 'alaihi wasallam dan beliau bersabda: \"Saudaramu adalah laki-laki Shalih, \" atau beliau bersabda: \"Sesungguhnya Abdullah laki-laki Shalih.\""},"6165":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ صَبَّاحٍ حَدَّثَنَا مُعْتَمِرٌ سَمِعْتُ عَوْفًا حَدَّثَنَا مُحَمَّدُ بْنُ سِيرِينَ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اقْتَرَبَ الزَّمَانُ لَمْ تَكَدْ تَكْذِبُ رُؤْيَا الْمُؤْمِنِ وَرُؤْيَا الْمُؤْمِنِ جُزْءٌ مِنْ سِتَّةٍ وَأَرْبَعِينَ جُزْءًا مِنْ النُّبُوَّةِ وَمَا كَانَ مِنْ النُّبُوَّةِ فَإِنَّهُ لَا يَكْذِبُقَالَ مُحَمَّدٌ وَأَنَا أَقُولُ هَذِهِ قَالَ وَكَانَ يُقَالُ الرُّؤْيَا ثَلَاثٌ حَدِيثُ النَّفْسِ وَتَخْوِيفُ الشَّيْطَانِ وَبُشْرَى مِنْ اللَّهِ فَمَنْ رَأَى شَيْئًا يَكْرَهُهُ فَلَا يَقُصَّهُ عَلَى أَحَدٍ وَلْيَقُمْ فَلْيُصَلِّ قَالَ وَكَانَ يُكْرَهُ الْغُلُّ فِي النَّوْمِ وَكَانَ يُعْجِبُهُمْ الْقَيْدُ وَيُقَالُ الْقَيْدُ ثَبَاتٌ فِي الدِّينِ وَرَوَى قَتَادَةُ وَيُونُسُ وَهِشَامٌ وَأَبُو هِلَالٍ عَنْ ابْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَدْرَجَهُ بَعْضُهُمْ كُلَّهُ فِي الْحَدِيثِ وَحَدِيثُ عَوْفٍ أَبْيَنُ وَقَالَ يُونُسُ لَا أَحْسِبُهُ إِلَّا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْقَيْدِ قَالَ أَبُو عَبْد اللَّهِ لَا تَكُونُ الْأَغْلَالُ إِلَّا فِي الْأَعْنَاقِ","id":"Telah menceritakan kepada kami [Abdullah bin Shabbah] Telah menceritakan kepada kami [Mu'tamir] aku mendengar [Auf] telah menceritakan kepada kami [Muhammad bin Sirin] bahwasanya ia mendengar [Abu Hurairah] mengatakan, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika Zaman semakin mendekat, mimpi seorang mukmin nyaris tidak bohong, dan mimpi seorang mukmin adalah satu bagian dari empat puluh bagian kenabian, dan apa yang berasal dari kenabian tentu tidaklah bohong.\" Muhammad mengatakan; 'Dan aku katakan sedemikain ini.' Ia juga mengatakan; Ada berita bahwa mimpi ada tiga, sekedar bisikan jiwa, teror dari setan dan kabar gembira dari Allah, maka barangsiapa bermimpi suatu hal yang tak disukainya, jangan menceritakannya kepada seorang pun, hendaklah ia bangun dan mendirikan shalat. Juga Abu Hurairah berkata, Rasulullah juga membenci Al ghull saat tidur (tidur terus menerus) dan beliau terkagum-kagum terhadap keistiqomahan beragama, dan makna al qaid adalah keteguhan beragama. Sedang [Qatadah], [Yunus] dan [Hisyam] serta [Abu Hilal] meriwayatkan dari [Ibnu Sirin] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, dan sebagian mereka memudrajkan keseluruhan hadits ini, dan hadits Ibnu Auf lebih jelas. Sedang Yunus mengatakan; aku tidak mengira hadits tentang Qaid (keteguhan beragama) tersebut kecuali dari Nabi shallallahu 'alaihi wasallam. Dan Abu Abdullah mengatakan; Istilah aghlal (belenggu) tak terjadi selain untuk leher."},"6166":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ خَارِجَةَ بْنِ زَيْدِ بْنِ ثَابِتٍ عَنْ أُمِّ الْعَلَاءِوَهِيَ امْرَأَةٌ مِنْ نِسَائِهِمْ بَايَعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ طَارَ لَنَا عُثْمَانُ بْنُ مَظْعُونٍ فِي السُّكْنَى حِينَ اقْتَرَعَتْ الْأَنْصَارُ عَلَى سُكْنَى الْمُهَاجِرِينَ فَاشْتَكَى فَمَرَّضْنَاهُ حَتَّى تُوُفِّيَ ثُمَّ جَعَلْنَاهُ فِي أَثْوَابِهِ فَدَخَلَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ رَحْمَةُ اللَّهِ عَلَيْكَ أَبَا السَّائِبِ فَشَهَادَتِي عَلَيْكَ لَقَدْ أَكْرَمَكَ اللَّهُ قَالَ وَمَا يُدْرِيكِ قُلْتُ لَا أَدْرِي وَاللَّهِ قَالَ أَمَّا هُوَ فَقَدْ جَاءَهُ الْيَقِينُ إِنِّي لَأَرْجُو لَهُ الْخَيْرَ مِنْ اللَّهِ وَاللَّهِ مَا أَدْرِي وَأَنَا رَسُولُ اللَّهِ مَا يُفْعَلُ بِي وَلَا بِكُمْ قَالَتْ أُمُّ الْعَلَاءِ فَوَاللَّهِ لَا أُزَكِّي أَحَدًا بَعْدَهُ قَالَتْ وَرَأَيْتُ لِعُثْمَانَ فِي النَّوْمِ عَيْنًا تَجْرِي فَجِئْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ ذَلِكَ لَهُ فَقَالَ ذَاكِ عَمَلُهُ يَجْرِي لَهُ","id":"Telah menceritakan kepada kami ['Abdan] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Kharijah bin Zaid bin tsabit] dari [Ummul 'Alaa`] salah seorang sahabiyah yang pernah ikut berbaiat kepada Rasulullah Shallallahu'alaihiwasallam, mengatakan; Utsman bin mazh'un mendatangi kami dalam sebuah hunian ketika orang anshar membagi-bagi pembagian hunian kaum muhajirin, ia kemudian mengeluhkan sakitnya dan kami merawatnya hingga meninggal. Kemudian kami mengkafaninya dengan bajunya. Rasulullah Shallallahu'alaihiwasallam selanjutnya menemui kami, dan kami berujar; 'Semoga engkau hai Abu Sa`ib, mendapat rahmat Allah, kesaksianku terhadapmu, adalah betul-betul Allah telah memuliakanmu! ' Nabi bertanya; \"dari mana kamu tahu?\" Aku jawab; 'Saya tidak tahu.' Nabi bersabda; \"demi Allah sungguh ia telah menghadapi kematian, dan saya hanya berharap ia memperoleh kebaikan dari Allah, demi Allah, aku tidak tahu padahal aku adalah Rasulullah bagaimana nantinya aku diperlakukan, juga tidak tahu bagaimana kalian diperlakukan.\" Ummul 'Ala` berguman; 'Demi Allah, aku tidak akan mensucikan seseorang setelahnya'. Dia menuturkan kembali; 'dan aku bermimpi melihat Ustman bin mazh'un mempunyai sungai yang mengalir, kemudian aku mendatangi Rasulullah Shallallahu'alaihiwasallam, aku ceritakan mimpiku kepada beliau, dan beliau bersabda: \"Itu pertanda bahwa amalnya terus mengalir baginya.\""},"6167":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ بْنِ كَثِيرٍ حَدَّثَنَا شُعَيْبُ بْنُ حَرْبٍ حَدَّثَنَا صَخْرُ بْنُ جُوَيْرِيَةَ حَدَّثَنَا نَافِعٌ أَنَّ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا حَدَّثَهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَا أَنَا عَلَى بِئْرٍ أَنْزِعُ مِنْهَا إِذْ جَاءَ أَبُو بَكْرٍ وَعُمَرُ فَأَخَذَ أَبُو بَكْرٍ الدَّلْوَ فَنَزَعَ ذَنُوبًا أَوْ ذَنُوبَيْنِ وَفِي نَزْعِهِ ضَعْفٌ فَغَفَرَ اللَّهُ لَهُ ثُمَّ أَخَذَهَا عُمَرُ بْنُ الْخَطَّابِ مِنْ يَدِ أَبِي بَكْرٍ فَاسْتَحَالَتْ فِي يَدِهِ غَرْبًا فَلَمْ أَرَ عَبْقَرِيًّا مِنْ النَّاسِ يَفْرِي فَرْيَهُ حَتَّى ضَرَبَ النَّاسُ بِعَطَنٍ","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim bin Katsir] telah menceritakan kepada kami [Syu'aib bin Harb] telah menceritakan kepada kami [Shakhr bin Juwairiyah] telah menceritakan kepada kami [Nafi'], bahwasanya [Ibnu Umar] radliallahu 'anhuma menceritakan kepadanya dengan mengatakan; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketika aku berada di sebuah sumur sedang menarik ember, tiba-tiba Abu bakar dan Umar datang, kemudian Abu Bakar menarik seember atau dua ember dan dalam tarikannya terlihat ada kelemahan, Allah pun mengampuninya, kemudian Umar bin Khattab mengambil ember dari tangan Abu Bakar, tiba-tiba embernya berubah menjadi besar, tidak pernah aku melihat seorang jenius yang beramal serius (gigih) seperti kegigihannya, sehingga orang banyak bisa minum dengan kenyang.\""},"6168":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ عَنْ سَالِمٍ عَنْ أَبِيهِعَنْ رُؤْيَا النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أَبِي بَكْرٍ وَعُمَرَ قَالَ رَأَيْتُ النَّاسَ اجْتَمَعُوا فَقَامَ أَبُو بَكْرٍ فَنَزَعَ ذَنُوبًا أَوْ ذَنُوبَيْنِ وَفِي نَزْعِهِ ضَعْفٌ وَاللَّهُ يَغْفِرُ لَهُ ثُمَّ قَامَ ابْنُ الْخَطَّابِ فَاسْتَحَالَتْ غَرْبًا فَمَا رَأَيْتُ مِنْ النَّاسِ مَنْ يَفْرِي فَرْيَهُ حَتَّى ضَرَبَ النَّاسُ بِعَطَنٍ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus], telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Musa bin 'Uqbah] dari [Salim] dari [ayahnya] tentang mimpi Nabi shallallahu 'alaihi wasallam berkaitan dengan Abu Bakar dan Umar, beliau bersabda: \"aku melihat orang-orang berkumpul, kemudian Abu Bakar berdiri dan menarik ember atau dua ember dan dalam tarikannya ada kelemahan, Allah pun mengampuninya, kemudian Umar bin Khattab berdiri dan tiba-tiba ember tersebut berubah menjadi besar, aku tidak pernah melihat seorang jenius yang beramal serius (gigih) seperti kegigihannya, sehingga orang banyak bisa minum dengan kenyang.\""},"6169":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عُفَيْرٍ حَدَّثَنِي اللَّيْثُ قَالَ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي سَعِيدٌ أَنَّ أَبَا هُرَيْرَةَ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْنَا أَنَا نَائِمٌ رَأَيْتُنِي عَلَى قَلِيبٍ وَعَلَيْهَا دَلْوٌ فَنَزَعْتُ مِنْهَا مَا شَاءَ اللَّهُ ثُمَّ أَخَذَهَا ابْنُ أَبِي قُحَافَةَ فَنَزَعَ مِنْهَا ذَنُوبًا أَوْ ذَنُوبَيْنِ وَفِي نَزْعِهِ ضَعْفٌ وَاللَّهُ يَغْفِرُ لَهُ ثُمَّ اسْتَحَالَتْ غَرْبًا فَأَخَذَهَا عُمَرُ بْنُ الْخَطَّابِ فَلَمْ أَرَ عَبْقَرِيًّا مِنْ النَّاسِ يَنْزِعُ نَزْعَ عُمَرَ بْنِ الْخَطَّابِ حَتَّى ضَرَبَ النَّاسُ بِعَطَنٍ","id":"Telah menceritakan kepada kami [Sa'id bin Ufair] telah menceritakan kepadaku [Al Laits] mengatakan, telah menceritakan kepadaku ['Uqail] dari [Ibnu Syihab] telah mengabarkan kepadaku [Sa'id], bahwasanya [Abu Hurairah] mengabarinya, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketika aku tidur, aku bermimpi berada di sebuah sumur dan diatas ada sebuah ember, maka aku menariknya sekehendak Allah, kemudian Ibnu Abu Quhafah mengambilnya, dan menarik seember atau dua ember, dan dalam tarikannya terlihat ada kelemahan, Allah pun mengampuninya, kemudian embernya berubah menjadi besar, dan Umar bin Khattab mengambil ember, dan tidak pernah aku melihat seorang jenius yang beramal serius (gigih) seperti kegigihan Umar bin Al Khaththab, sehingga orang banyak bisa minum dengan kenyang.\""},"6170":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ هَمَّامٍ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَا أَنَا نَائِمٌ رَأَيْتُ أَنِّي عَلَى حَوْضٍ أَسْقِي النَّاسَ فَأَتَانِي أَبُو بَكْرٍ فَأَخَذَ الدَّلْوَ مِنْ يَدِي لِيُرِيحَنِي فَنَزَعَ ذَنُوبَيْنِ وَفِي نَزْعِهِ ضَعْفٌ وَاللَّهُ يَغْفِرُ لَهُ فَأَتَى ابْنُ الْخَطَّابِ فَأَخَذَ مِنْهُ فَلَمْ يَزَلْ يَنْزِعُ حَتَّى تَوَلَّى النَّاسُ وَالْحَوْضُ يَتَفَجَّرُ","id":"Telah menceritakan kepada kami [Ishaq bin Ibarhim] telah menceritakan kepada kami ['Abdurrazaq] dari [Ma'mar] dari [Hammam] bahwasanya ia mendengar [Abu Hurairah] radliallahu 'anhu mengatakan; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketika aku tidur, aku melihat diriku diatas telaga memberi minum kepada orang-orang, Abu Bakar mendatangiku dan mengambil ember dariku dengan tujuan agar aku bisa istirahat, ia menarik dua tarikan, dan dalam tarikannya ada kelemahan, Allah pun mengampuninya, lantas Umar bin Khattab datang dan mengambilnya, ia tiada henti menarik ember hingga manusia pulang dan telaga terus memancar.\""},"6171":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عُفَيْرٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ أَنَّ أَبَا هُرَيْرَةَ قَالَبَيْنَا نَحْنُ جُلُوسٌ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْنَا أَنَا نَائِمٌ رَأَيْتُنِي فِي الْجَنَّةِ فَإِذَا امْرَأَةٌ تَتَوَضَّأُ إِلَى جَانِبِ قَصْرٍ قُلْتُ لِمَنْ هَذَا الْقَصْرُ قَالُوا لِعُمَرَ بْنِ الْخَطَّابِ فَذَكَرْتُ غَيْرَتَهُ فَوَلَّيْتُ مُدْبِرًا قَالَ أَبُو هُرَيْرَةَ فَبَكَى عُمَرُ بْنُ الْخَطَّابِ ثُمَّ قَالَ أَعَلَيْكَ بِأَبِي أَنْتَ وَأُمِّي يَا رَسُولَ اللَّهِ أَغَارُ","id":"Telah menceritakan kepada kami [Sa'id bin 'Ufair] telah menceritakan kepadaku [Al Laits] telah menceritakan kepada kami ['Uqail] dari [Ibnu Syihab] mengatakan, telah mengabarkan kepadaku [Sa'id bin Musayyab], bahwasanya [Abu Hurairah] menuturkan; ketika kami duduk-duduk di dekat Rasulullah Shallallahu'alaihiwasallam, beliau mengatakan: \"ketika aku tidur, kulihat diriku dalam surga, tiba-tiba ada seorang wanita berwudhu disamping istana. Maka saya bertanya; 'milik siapa istana ini? ' Mereka menjawab; 'Milik Umar bin Khattab! ' maka aku ingat kecemburuannya, sehingga aku berbalik ke belakang.\" Kata Abu Hurairah; maka Umar spontan menangis lalu berujar; 'apakah kepadamu, bapak dan ibuku sebagai tebusanmu ya Rasulullah, aku cemburu? '"},"6172":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا مُعْتَمِرُ بْنُ سُلَيْمَانَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلْتُ الْجَنَّةَ فَإِذَا أَنَا بِقَصْرٍ مِنْ ذَهَبٍ فَقُلْتُ لِمَنْ هَذَا فَقَالُوا لِرَجُلٍ مِنْ قُرَيْشٍ فَمَا مَنَعَنِي أَنْ أَدْخُلَهُ يَا ابْنَ الْخَطَّابِ إِلَّا مَا أَعْلَمُ مِنْ غَيْرَتِكَ قَالَ وَعَلَيْكَ أَغَارُ يَا رَسُولَ اللَّهِ","id":"Telah menceritakan kepada kami ['Amru bin Ali], telah menceritakan kepada kami [Mu'tamir bin Sulaiman] telah menceritakan kepada kami ['Ubaidullah bin Umar] dari [Muhammad bin Al Munkadir] dari [Jabir bin Abdullah] mengatakan; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku masuk surga, tak tahunya aku berada di sebuah istana emas. Maka aku bertanya; 'Milik siapakah ini? ' Mereka menjawab; 'Milik seseorang dari Quraisy, ' dan tiada yang menghalangiku untuk memasukinya Hai Ibnul Khattab selain karena aku tahu kecemburuanmu.\" Maka Umar menjawab; 'apakah terhadapmu aku cemburu ya Rasulullah! '"},"6173":{"ar":"حَدَّثَنِي يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ أَنَّ أَبَا هُرَيْرَةَ قَالَبَيْنَمَا نَحْنُ جُلُوسٌ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْنَا أَنَا نَائِمٌ رَأَيْتُنِي فِي الْجَنَّةِ فَإِذَا امْرَأَةٌ تَتَوَضَّأُ إِلَى جَانِبِ قَصْرٍ فَقُلْتُ لِمَنْ هَذَا الْقَصْرُ فَقَالُوا لِعُمَرَ فَذَكَرْتُ غَيْرَتَهُ فَوَلَّيْتُ مُدْبِرًا فَبَكَى عُمَرُ وَقَالَ عَلَيْكَ بِأَبِي أَنْتَ وَأُمِّي يَا رَسُولَ اللَّهِ أَغَارُ","id":"Telah menceritakan kepadaku [Yahya bin Bukair], telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] telah mengabarkan kepadaku [Sa'id bin Musayyab], bahwasanya [Abu Hurairah] menuturkan; ketika kami duduk-duduk di sisi Rasulullah Shallallahu'alaihiwasallam, beliau bercerita: \"Ketika aku tidur, aku melihat diriku dalam sebuah taman, tak tahunya ada seorang wanita yang sedang berwudhu disamping istana. Maka saya bertanya; 'milik siapakah ini? ' Mereka menjawab; 'Milik Umar bin Khattab, ' aku teringat kecemburuannya, maka aku segera berbalik ke belakang.\" Umar spontan menangis dan mengatakan; 'apakah kepadamu, bapak dan ibuku sebagai tebusanmu ya Rasulullah, aku cemburu? '"},"6174":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ أَخْبَرَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ بْنِ عُمَرَ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَا أَنَا نَائِمٌ رَأَيْتُنِي أَطُوفُ بِالْكَعْبَةِ فَإِذَا رَجُلٌ آدَمُ سَبْطُ الشَّعَرِ بَيْنَ رَجُلَيْنِ يَنْطُفُ رَأْسُهُ مَاءً فَقُلْتُ مَنْ هَذَا قَالُوا ابْنُ مَرْيَمَ فَذَهَبْتُ أَلْتَفِتُ فَإِذَا رَجُلٌ أَحْمَرُ جَسِيمٌ جَعْدُ الرَّأْسِ أَعْوَرُ الْعَيْنِ الْيُمْنَى كَأَنَّ عَيْنَهُ عِنَبَةٌ طَافِيَةٌ قُلْتُ مَنْ هَذَا قَالُوا هَذَا الدَّجَّالُ أَقْرَبُ النَّاسِ بِهِ شَبَهًا ابْنُ قَطَنٍ وَابْنُ قَطَنٍ رَجُلٌ مِنْ بَنِي الْمُصْطَلِقِ مِنْ خُزَاعَةَ","id":"Telah menceritakan kepada kami [Abul Yaman] Telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] telah mengabarkan kepadaku [Salim bin Abdullah bin Umar], bahwasanya [Abdullah bin Umar] radliallahu 'anhuma mengatakan, Rasulullah Shallallahu'alaihiwasallam bersabda: \"ketika aku tidur, kulihat diriku thawaf di ka'bah, tiba-tiba ada seseorang yang kulitnya sawo matang, berambut lurus diantara dua orang, kepalanya meneteskan air, maka saya bertanya; 'Siapakah ini? ' Mereka menjawab; 'Ini Isa bin Maryam, ' kemudian aku menoleh, tiba-tiba ada seseorang yang kulitnya merah, berbadan besar, rambut kepalanya keriting, matanya buta sebelah kanan, matanya seolah-olah anggur yang menjorok, maka saya bertanya; 'Siapakah ini? ' Mereka menjawab; 'Ini dajjal, ' manusia yang paling mirip dengannya adalah Ibnu Qathan, \" dan Ibnu Qattan adalah seorang laki-laki dari Bani musthaliq dari Khuza'ah."},"6175":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي حَمْزَةُ بْنُ عَبْدِ اللَّهِ بْنِ عُمَرَ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ بَيْنَا أَنَا نَائِمٌ أُتِيتُ بِقَدَحِ لَبَنٍ فَشَرِبْتُ مِنْهُ حَتَّى إِنِّي لَأَرَى الرِّيَّ يَجْرِي ثُمَّ أَعْطَيْتُ فَضْلَهُ عُمَرَ قَالُوا فَمَا أَوَّلْتَهُ يَا رَسُولَ اللَّهِ قَالَ الْعِلْمُ","id":"Telah menceritakan kepada kami [Yahya bin Bukair], telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] telah mengabarkan kepadaku [Hamzah bin Abdullah bin Umar], [Abdullah bin Umar] mengatakan; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketika aku tidur, aku diberi segelas susu, maka aku meminumnya hingga sungguh aku melihat sungai mengalir, lantas kelebihannya kuberikan kepada Umar.\" Mereka bertanya; 'Bagaimana engkau takwilkan Ya Rasulullah? ' Nabi menjawab; \"Iilmu.\""},"6176":{"ar":"حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا عَفَّانُ بْنُ مُسْلِمٍ حَدَّثَنَا صَخْرُ بْنُ جُوَيْرِيَةَ حَدَّثَنَا نَافِعٌ أَنَّ ابْنَ عُمَرَ قَالَإِنَّ رِجَالًا مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانُوا يَرَوْنَ الرُّؤْيَا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَقُصُّونَهَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَقُولُ فِيهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا شَاءَ اللَّهُ وَأَنَا غُلَامٌ حَدِيثُ السِّنِّ وَبَيْتِي الْمَسْجِدُ قَبْلَ أَنْ أَنْكِحَ فَقُلْتُ فِي نَفْسِي لَوْ كَانَ فِي��َ خَيْرٌ لَرَأَيْتَ مِثْلَ مَا يَرَى هَؤُلَاءِ فَلَمَّا اضْطَجَعْتُ ذَاتَ لَيْلَةٍ قُلْتُ اللَّهُمَّ إِنْ كُنْتَ تَعْلَمُ فِيَّ خَيْرًا فَأَرِنِي رُؤْيَا فَبَيْنَمَا أَنَا كَذَلِكَ إِذْ جَاءَنِي مَلَكَانِ فِي يَدِ كُلِّ وَاحِدٍ مِنْهُمَا مِقْمَعَةٌ مِنْ حَدِيدٍ يُقْبِلَانِ بِي إِلَى جَهَنَّمَ وَأَنَا بَيْنَهُمَا أَدْعُو اللَّهَ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ جَهَنَّمَ ثُمَّ أُرَانِي لَقِيَنِي مَلَكٌ فِي يَدِهِ مِقْمَعَةٌ مِنْ حَدِيدٍ فَقَالَ لَنْ تُرَاعَ نِعْمَ الرَّجُلُ أَنْتَ لَوْ كُنْتَ تُكْثِرُ الصَّلَاةَ فَانْطَلَقُوا بِي حَتَّى وَقَفُوا بِي عَلَى شَفِيرِ جَهَنَّمَ فَإِذَا هِيَ مَطْوِيَّةٌ كَطَيِّ الْبِئْرِ لَهُ قُرُونٌ كَقَرْنِ الْبِئْرِ بَيْنَ كُلِّ قَرْنَيْنِ مَلَكٌ بِيَدِهِ مِقْمَعَةٌ مِنْ حَدِيدٍ وَأَرَى فِيهَا رِجَالًا مُعَلَّقِينَ بِالسَّلَاسِلِ رُءُوسُهُمْ أَسْفَلَهُمْ عَرَفْتُ فِيهَا رِجَالًا مِنْ قُرَيْشٍ فَانْصَرَفُوا بِي عَنْ ذَاتِ الْيَمِينِ فَقَصَصْتُهَا عَلَى حَفْصَةَ فَقَصَّتْهَا حَفْصَةُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ عَبْدَ اللَّهِ رَجُلٌ صَالِحٌ لَوْ كَانَ يُصَلِّي مِنْ اللَّيْلِفَقَالَ نَافِعٌ فَلَمْ يَزَلْ بَعْدَ ذَلِكَ يُكْثِرُ الصَّلَاةَ","id":"Telah mengabrkan kepadaku ['Ubaidullah bin Sa'id], Telah menceritakan kepada kami ['Affan bin Muslim] telah menceritakan kepada kami [Shakhr bin Juwairiyah] telah menceritakan kepada kami [Nafi'] bahwasanya [Ibnu Umar] mengatakan; dahulu sahabat-sahabat Rasulullah Shallallahu'alaihiwasallam jika bermimpi, mereka suka sekali mengisahkan mimpinya kepada Rasulullah Shallallahu'alaihiwasallam sehingga Rasulullah Shallallahu'alaihiwasallam menakwilkan mimpinya. Ketika itu umurku masih belia, sedang aku sering tinggal dimasjid, karena aku belum menikah. Maka aku berkata kepada diriku sendiri; 'kalaulah dirimu ada kebaikan, niscaya engkau berimimpi sebagaimana orang-orang bermimpi.' Suatu malam ketika aku berbaring, aku memanjatkan doa; 'Ya Allah, jika Engkau mengetahui pada diriku terdapat kebaikan, maka perlihatkanlah kepadaku dalam mimpi.' Ketika aku dalam kondisi (mimpi) seperti itu, tiba-tiba ada dua malaikat mendatangiku yang di tangan masing-masing memegang palu besi, keduanya membawaku ke jahannam sedang aku diantara keduanya tiada henti memanjatkan doa; 'Ya Allah, aku berlindung kepada-Mu dari jahannam, ' Kemudian aku diperlihatkan seorang malaikat menemuiku sedang di tangannya membawa palu besi seraya berujar; 'tidak usah khawatir, sebaik-baik manusia adalah engkau, jika engkau memperbanyak shalat.' Mereka kemudian membawaku hingga menghentikanku di tepi jahannam, ternyata jahannam tergulung seperti gulungan sumur, ia mempunyai emperan sebagaimana emperan sumur, yang diantara kedua emperannya terdapat malaikat yang di tangannya membawa palu besi. Dan kulihat disana ada beberapa orang bergelantungan di rantai-rantai, kepala mereka terjungkir dibawah mereka, aku tahu disana ada beberapa pemuka Quraisy. Kemudian mereka membawaku pergi dari sisi kanan. Maka akub ceritakan mimpiku itu kepada Hafshah, kemudian [Hafshah] menceritakanya kepada Rasulullah Shallallahu'alaihiwasallam, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Abdullah adalah seorang hamba yang shalih, asalkan shalat malam.\" Kata [Nafi']; 'semenjak itu Abdullah memperbanyak shalat.'"},"6177":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا هِشَامُ بْنُ يُوسُفَ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ قَالَكُنْتُ غُلَامًا شَابًّا عَزَبًا فِي عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكُنْتُ أَبِيتُ فِي الْمَسْجِدِ وَكَانَ مَنْ رَأَى مَنَامًا قَصَّهُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ اللَّهُمَّ إِنْ كَانَ لِي عِنْدكَ خَيْرٌ فَأَرِنِي مَنَامًا يُعَبِّرُهُ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنِمْتُ فَرَأَيْتُ مَلَكَيْنِ أَتَيَانِي فَانْطَلَقَا بِي فَلَقِيَهُمَا مَلَكٌ آخَرُ فَقَالَ لِي لَنْ تُرَاعَ إِنَّكَ رَجُلٌ صَالِحٌ فَانْطَلَقَا بِي إِلَى النَّارِ فَإِذَا هِيَ مَطْوِيَّةٌ كَطَيِّ الْبِئْرِ وَإِذَا فِيهَا نَاسٌ قَدْ عَرَفْتُ بَعْضَهُمْ فَأَخَذَا بِي ذَاتَ الْيَمِينِ فَلَمَّا أَصْبَحْتُ ذَكَرْتُ ذَلِكَ لِحَفْصَةَ فَزَعَمَتْ حَفْصَةُ أَنَّهَا قَصَّتْهَا عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ عَبْدَ اللَّهِ رَجُلٌ صَالِحٌ لَوْ كَانَ يُكْثِرُ الصَّلَاةَ مِنْ اللَّيْلِقَالَ الزُّهْرِيُّ وَكَانَ عَبْدُ اللَّهِ بَعْدَ ذَلِكَ يُكْثِرُ الصَّلَاةَ مِنْ اللَّيْلِ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] telah menceritakan kepada kami [Hisyam bin Yusuf] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Salim] dari [Ibnu Umar] mengatakan, aku anak muda lajang di masa Nabi shallallahu 'alaihi wasallam, dan aku tidur di masjid. Dahulu ada satu kebiasan, siapa yang bermimpi, maka ia menceritakan mimpinya kepada Nabi Shallallahu'alaihiwasallam. Maka aku panjatkan doa; 'Ya Allah, jikalau aku mempunyai kebaikan disisi-Mu, maka perlihatkanlah kepadaku dalam mimpi sehingga Rasulullah Shallallahu'alaihiwasallam dapat mentakwilkan mimpiku.' aku pun tertidur, dan kulihat dua malaikat mendatangiku dan membawaku. kemudian ada malaikat lain menemui keduanya dan berujar keadaku; 'jangan khawatir, sebab kamu laki-laki shalih.' Lantas kedua malaikat itu membawaku ke neraka, ternyata neraka itu digulung seperti gulungan sumur, dan disana ada sebagian orang yang kukenal, lantas keduanya menggandengku ke sebalah kanan. Di pagi hari aku ceritakan mimpiku kepada [Hafshah], dan Hafshah mengaku telah menceritakannya kepada Nabi shallallahu 'alaihi wasallam, maka Nabi bersabda: \"Abdullah adalah laki-laki shalih, sekiranya ia memperbanyak shalat malam.\" Kata Az Zuhri, setelah peristiwa itu, Abdullah memperbanyak shalat malam."},"6178":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ حَمْزَةَ بْنِ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ بَيْنَا أَنَا نَائِمٌ أُتِيتُ بِقَدَحِ لَبَنٍ فَشَرِبْتُ مِنْهُ ثُمَّ أَعْطَيْتُ فَضْلِي عُمَرَ بْنَ الْخَطَّابِ قَالُوا فَمَا أَوَّلْتَهُ يَا رَسُولَ اللَّهِ قَالَ الْعِلْمَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari [Hamzah bin Abdullah] dari [Abdullah bin Umar] radliallahu 'anhuma mengatakan, aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketika aku tidur, aku diberi segelas susu, lalu aku meminumnya, kemudian aku berikan sisanya kepada Umar bin khattab.\" Mereka bertanya; 'bagaimana engkau takwilkan mimpimu ya Rasulullah? ' Beliau menjawab; \"ilmu.\""},"6179":{"ar":"حَدَّثَنِي سَعِيدُ بْنُ مُحَمَّدٍ أَبُو عَبْدِ اللَّهِ الْجَرْمِيُّ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ عُبَيْدَةَ بْنِ نَشِيطٍ قَالَ قَالَ عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ سَأَلْتُ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاعَنْ رُؤْيَا رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الَّتِي ذَكَرَ فَقَالَ ابْنُ عَبَّاسٍ ذُكِرَ لِي أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْنَا أَنَا نَائِمٌ رَأَيْتُ أَنَّهُ وُضِعَ فِي يَدَيَّ سِوَارَانِ مِنْ ذَهَبٍ فَفُظِعْتُهُمَا وَكَرِهْتُهُمَا فَأُذِنَ لِي فَنَفَخْتُهُمَا فَطَارَا فَأَوَّلْتُهُمَا كَذَّابَيْنِ يَخْرُجَانِفَقَالَ عُبَيْدُ اللَّهِ أَحَدُهُمَا الْعَنْسِيُّ الَّذِي قَتَلَهُ فَيْرُوزٌ بِالْيَمَنِ وَالْآخَرُ مُسَيْلِمَةُ","id":"telah menceritakan kepadaku [Sa'id bin Muhammad Abu Abdullah Al Jarmi] telah menceritakan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepada kami [Ayahku] dari [Shalih] dari [Ibnu Ubaidah bin Nasyith] mengatakan, [Ubaidullah bin Abdullah] mengatakan; aku bertanya [Abdullah bin Abbas] radliallahu 'anhuma tentang mimpi Rasulullah Shallallahu'alaihiwasallam yang pernah beliau ceritakan. Ibnu Abbas mengatakan; aku pernah diceritai, bahwa Rasulullah Shallallahu'alaihiwasallam mengatakan; \"Ketika aku tidur, aku bermimpi bahwa ditanganku diletakkan dua gelang emas. Aku merasa jijik dan tidak suka terhadap kedua benda itu, kemudian aku di izinkan untuk meniupnya sehingga keduanya beterbangan. Kedua gelang itu kutakwilkan, aka muncul dua pendusta.\" Ubaidullah menjelaskan; salah satunya Al Aswad al 'Ansi yang dibunuh oleh Fairuz ad Dailami di Yaman, dan satunya lagi Musailamah Alkadzdzab."},"6180":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدٍ عَنْ جَدِّهِ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَىأُرَاهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رَأَيْتُ فِي الْمَنَامِ أَنِّي أُهَاجِرُ مِنْ مَكَّةَ إِلَى أَرْضٍ بِهَا نَخْلٌ فَذَهَبَ وَهَلِي إِلَى أَنَّهَا الْيَمَامَةُ أَوْ هَجَرٌ فَإِذَا هِيَ الْمَدِينَةُ يَثْرِبُ وَرَأَيْتُ فِيهَا بَقَرًا وَاللَّهِ خَيْرٌ فَإِذَا هُمْ الْمُؤْمِنُونَ يَوْمَ أُحُدٍ وَإِذَا الْخَيْرُ مَا جَاءَ اللَّهُ مِنْ الْخَيْرِ وَثَوَابِ الصِّدْقِ الَّذِي آتَانَا اللَّهُ بِهِ بَعْدَ يَوْمِ بَدْرٍ","id":"Telah menceritakan kepadaku [Muhammad bin Al 'Ala`] Telah menceritakan kepada kami [Abu Usamah] dari [Buraid] dari [kakeknya, Abu Burdah] dari [Abu Musa], setahuku ia dari Nabi shallallahu 'alaihi wasallam, beliau bersabda; \"Aku bermimpi bahwa aku hijrah dari Makkah ke suatu kawasan yang banyak pohon kurmanya. Awal perkiraanku, kawasan itu adalah Yamamah atau Hajar, ternyata itu adalah Madinah atau Yatsrib. Dan aku melihat disana ada sapi, demi Allah, yang bagus sekali. Dan ternyata mereka adalah orang-orang mukmin di hari Uhud. Dan kebaikan yang Allah datangkan serta pahala kejujuran adalah yang Allah berikan kepada kita setelah peperangan badar.\""},"6181":{"ar":"حَدَّثَنِي إِسْحَاقُ بْنُ إِبْرَاهِيمَ الْحَنْظَلِيُّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ قَالَ هَذَا مَا حَدَّثَنَا بِهِ أَبُو هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَحْنُ الْآخِرُونَ السَّابِقُونَ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَا أَنَا نَائِمٌ إِذْ أُوتِيتُ خَزَائِنَ الْأَرْضِ فَوُضِعَ فِي يَدَيَّ سِوَارَانِ مِنْ ذَهَبٍ فَكَبُرَا عَلَيَّ وَأَهَمَّانِي فَأُوحِيَ إِلَيَّ أَنْ انْفُخْهُمَا فَنَفَخْتُهُمَا فَطَارَا فَأَوَّلْتُهُمَا الْكَذَّابَيْنِ اللَّذَيْنِ أَنَا بَيْنَهُمَا صَاحِبَ صَنْعَاءَ وَصَاحِبَ الْيَمَامَةِ","id":"telah menceritakan kepadaku [Ishaq bin Ibrahim Al Hanzhali], Telah menceritakan kepada kami [Abdur Razaq] telah mengabarkan kepada kami [Ma'mar] dari [Hammam bin Munabbih] mengatakan, inilah yang [Abu Hurairah] ceritakan kepada kami dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Kita adalah orang yang datang terkemudian, namun kita adalah orang yang pertama-tama masuk surga, \" Lantas Rasulullah Shallallahu'alaihiwasallam bersabda lagi: \"Ketika aku tidur, aku diberi perbendaharaan bumi, lantas diletakkan di tanganku dua gelang emas. Keduanya betul betul menjadikanku resah dan sedih, lantas aku memperoleh wahyu agar aku meniupnya, keduanya pun terbang. Maka kutakwilkan bahwa aka ada dua pendusta yang aku berada diantara keduanya, pertama orang Shan'a (al-Aswad al 'Ansi), orang kedua orang Yamamah (Musailamah alkadzdzab).\""},"6182":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَبْدِ اللَّهِ حَدَّثَنِي أَخِي عَبْدُ الْحَمِيدِ عَنْ سُلَيْمَانَ بْنِ بِلَالٍ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رَأَيْتُ كَأَنَّ امْرَأَةً سَوْدَاءَ ثَائِرَةَ الرَّأْسِ خَرَجَتْ مِنْ الْمَدِينَةِ حَتَّى قَامَتْ بِمَهْيَعَةَ وَهِيَ الْجُحْفَةُ فَأَوَّلْتُ أَنَّ وَبَاءَ الْمَدِينَةِ نُقِلَ إِلَيْهَا","id":"telah menceritakan kepada kami [Isma'il bin Abdullah] telah menceritakan kepadaku [Saudaraku, Abdul Hamid] dari [Sulaiman bin Bilal] dari [Musa bin 'Uqbah] dari [Salim bin Abdullah] dari [ayahnya], bahwasanya Nabi shallallahu 'alaihi wasallam bersabda; \"Aku bermimpi melihat wanita hitam, rambutnya acaka-acakan keluar dari madinah hingga berdiri di Mahya'ah yaitu Juhfah, maka aku takwilkan bahwa wabah penyakit Madinah telah dipindahkan kesana.\""},"6183":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ حَدَّثَنَا فُضَيْلُ بْنُ سُلَيْمَانَ حَدَّثَنَا مُوسَى حَدَّثَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَافِي رُؤْيَا النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَدِينَةِ رَأَيْتُ امْرَأَةً سَوْدَاءَ ثَائِرَةَ الرَّأْسِ خَرَجَتْ مِنْ الْمَدِينَةِ حَتَّى نَزَلَتْ بِمَهْيَعَةَ فَتَأَوَّلْتُهَا أَنَّ وَبَاءَ الْمَدِينَةِ نُقِلَ إِلَى مَهْيَعَةَ وَهِيَ الْجُحْفَةُ","id":"Telah menceritakan kepada kami [Muhammad bin Abi Bakar Al Muqaddami] telah menceritakan kepada kami [Fudhail bin Sulaiman] telah menceritakan kepada kami [Musa] telah menceritakan kepadaku [Salim bin Abdullah] dari [Abdullah bin Umar] radliallahu 'anhuma tentang mimpi Nabi shallallahu 'alaihi wasallam di Madinah: \"aku melihat wanita hitam berambut acak-acakan keluar dari Madinah hingga singgah di Mahya'ah, maka aku takwilkan bahwa wabah di Madinah telah dipindahkan ke Mahya'ah, yaitu Juhfah.\""},"6184":{"ar":"حَدَّثَنِي إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنِي أَبُو بَكْرِ بْنُ أَبِي أُوَيْسٍ حَدَّثَنِي سُلَيْمَانُ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ سَالِمٍ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رَأَيْتُ امْرَأَةً سَوْدَاءَ ثَائِرَةَ الرَّأْسِ خَرَجَتْ مِنْ الْمَدِينَةِ حَتَّى قَامَتْ بِمَهْيَعَةَ فَأَوَّلْتُ أَنَّ وَبَاءَ الْمَدِينَةِ نُقِلَ إِلَى مَهْيَعَةَ وَهِيَ الْجُحْفَةُ","id":"Telah menceritakan kepadaku [Ibrahim bin Mundzir] telah menceritakan kepadaku [Abu Bakar bin Abi Uwais] telah menceritakan kepadaku [Sulaiman] dari [Musa bin 'Uqbah] dari [Salim] dari [Ayahnya], bahwasanya Nabi shallallahu 'alaihi wasallam bersabda; \"Aku (bermimpi) melihat seorang wanita hitam berambut acak-acakan keluar dari Madinah hingga berdiri di Mahya'ah, maka aku takwilkan bahwa wabah Madinah telah dipindahkan ke Mahya'ah yaitu Juhfah.\""},"6185":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي بُرْدَةَ عَنْ جَدِّهِ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى أُرَاهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رَأَيْتُ فِي رُؤْيَايَ أَنِّي هَزَزْتُ سَيْفًا فَانْقَطَعَ صَدْرُهُ فَإِذَا هُوَ مَا أُصِيبَ مِنْ الْمُؤْمِنِينَ يَوْمَ أُحُدٍ ثُمَّ هَزَزْتُهُ أُخْرَى فَعَادَ أَحْسَنَ مَا كَانَ فَإِذَا هُوَ مَا جَاءَ اللَّهُ بِهِ مِنْ الْفَتْحِ وَاجْتِمَاعِ الْمُؤْمِنِينَ","id":"Telah menceritakan kepada kami [Muhammad bin Al'ala] telah menceritakan kepada kami [Abu Usamah] dari [Buraid bin Abdullah bin Abi Burdah] dari [kakeknya, Abu Burdah] dari [Abu Musa], seingatku dia dari Nabi shallallahu 'alaihi wasallam bersabda; \"Pernah aku bermimpi menggerakkan pedang lantas bagian tengahnya terputus, itu berarti musibah kaum mukminin di hari Uhud, kemudian aku gerakkan sekali lagi, dan kali ini kembali lebih baik dari semula, maka itu berarti kemenangan yang Allah datangkan dan bersatu kembalinya kaum mukminin.\""},"6186":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ أَيُّوبَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ تَحَلَّمَ بِحُلْمٍ لَمْ يَرَهُ كُلِّفَ أَنْ يَعْقِدَ بَيْنَ شَعِيرَتَيْنِ وَلَنْ يَفْعَلَ وَمَنْ اسْتَمَعَ إِلَى حَدِيثِ قَوْمٍ وَهُمْ لَهُ كَارِهُونَ أَوْ يَفِرُّونَ مِنْهُ صُبَّ فِي أُذُنِهِ الْآنُكُ يَوْمَ الْقِيَامَةِ وَمَنْ صَوَّرَ صُورَةً عُذِّبَ وَكُلِّفَ أَنْ يَنْفُخَ فِيهَا وَلَيْسَ بِنَافِخٍقَالَ سُفْيَانُ وَصَلَهُ لَنا أَيُّوبُ وَقَالَ قُتَيْبَةُ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ عِكْرِمَةَ عَنْ أَبِي هُرَيْرَةَ قَوْلَهُ مَنْ كَذَبَ فِي رُؤْيَاهُ وَقَالَ شُعْبَةُ عَنْ أَبِي هَاشِمٍ الرُّمَّانِيِّ سَمِعْتُ عِكْرِمَةَ قَالَ أَبُو هُرَيْرَةَ قَوْلَهُ مَنْ صَوَّرَ صُورَةً وَمَنْ تَحَلَّمَ وَمَنْ اسْتَمَعَ حَدَّثَنَا إِسْحَاقُ حَدَّثَنَا خَالِدٌ عَنْ خَالِدٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ مَنْ اسْتَمَعَ وَمَنْ تَحَلَّمَ وَمَنْ صَوَّرَ نَحْوَهُ تَابَعَهُ هِشَامٌ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَوْلَهُ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Sufyan] dari [Ayyub] dari [Ikrimah] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam bersabda; \"Barangsiapa menyatakan diri bermimpi padahal tidak, ia dipaksa untuk menyatukan dua biji gandum dan ia tak akan bisa melakukannya, dan barangsiapa mencuri dengar pembicaraan suatu kaum padahal mereka tidak menyukai atau telah menyingkir untuk menghindarinya, maka telinganya akan dialiri cairan tembaga pada hari kiamat, barang siapa menggambar ia akan disiksa dan dipaksa untuk menghidupkannya padahal tidak mampu.\" [Sufyan] mengatakan; ['Ayyub] menyambungkannya kepada kami. Sedang [Qutaibah] mengatakan; telah menceritakan kepada kami [Abu 'Awanah] dari [Qatadah] dari ['Ikrimah] dari [Abu Hurairah] ucapannya tentang; 'Barangsiapa dusta dalam mimpinya'. Dan [Syu'bah] mengatakan; dari [Abu Hasyim Ar Rumani], aku mendengar [Ikrimah] berkata; [Abu Hurairah] dengan ucapannya; 'Barangsiapa menggambar, dan barangsiapa menyatakan bermimpi, dan barangsiapa mencuri dengar.' Telah menceritakan kepada kami [Ishaq] telah menceritakan kepada kami [Khalid] dari [Khalid] dari [Ikrimah] dari [Ibnu Abbas] mengatakan; \"Barangsiapa mencuri dengar, dan barangsiapa menyatakan bermimpi dan barangsiapa menggambar', hadits ini diikutsertakan penguatnya oleh [Hisyam] dari [Ikrimah] dari [Ibnu Abbas] dengan ucapan beliau."},"6187":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُسْلِمٍ حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ دِينَارٍ مَوْلَى ابْنِ عُمَرَ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ مِنْ أَفْرَى الْفِرَى أَنْ يُرِيَ عَيْنَيْهِ مَا لَمْ تَرَ","id":"Telah menceritakan kepada kami ['Ali bin Muslim] telah menceritakan kepada kami ['Abdush Shamad] telah menceritakan kepada kami ['Abdurrahman bin Abdullah bin Dinar], maula Ibnu Umar, dari [ayahnya] dari [Ibnu Umar], bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Diantara kebohongan yang paling bohong adalah menyatakan melihat (bermimpi) padahal tidak.\""},"6188":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ الرَّبِيعِ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ رَبِّهِ بْنِ سَعِيدٍ قَالَ سَمِعْتُ أَبَا سَلَمَةَ يَقُولُلَقَدْ كُنْتُ أَرَى الرُّؤْيَا فَتُمْرِضُنِي حَتَّى سَمِعْتُ أَبَا قَتَادَةَ يَقُولُ وَأَنَا كُنْتُ لَأَرَى الرُّؤْيَا تُمْرِضُنِي حَتَّى سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الرُّؤْيَا الْحَسَنَةُ مِنْ اللَّهِ فَإِذَا رَأَى أَحَدُكُمْ مَا يُحِبُّ فَلَا يُحَدِّثْ بِهِ إِلَّا مَنْ يُحِبُّ وَإِذَا رَأَى مَا يَكْرَهُ فَلْيَتَعَوَّذْ بِاللَّهِ مِنْ شَرِّهَا وَمِنْ شَرِّ الشَّيْطَانِ وَلْيَتْفِلْ ثَلَاثًا وَلَا يُحَدِّثْ بِهَا أَحَدًا فَإِنَّهَا لَنْ تَضُرَّهُ","id":"Telah menceritakan kepada kami [Sa'id bin Rabi'] telah menceritakan kepada kami [Syu'bah] dari ['Abdu Rabbihi bin Sa'id] mengatakan; aku mendengar [Abu Salamah] mengatakan; 'Pernah aku bermimpi sehingga menjadikan diriku sakit, hingga aku mendengar [Abu Qatadah] mengatakan; 'Sungguh aku juga pernah bermimpi yang menjadikan diriku sakit, hingga aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Mimpi yang baik adalah berasal dari Allah, maka jika salah seorang diantara kaian bermimpi yang disukainya, jangan menceritakannya selain kepada yang disukai, dan siapa yang bermimpi yang tidak disukainya, hendaklah meminta perlindungan kepada Allah dari kejahatannya dan dari kejahatan setan, dan hendaklah meludah tiga kali dan jangan menceritakannya kepada seorang pun, sebab yang demikian tidak membahayakannya.\""},"6189":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ حَمْزَةَ حَدَّثَنِي ابْنُ أَبِي حَازِمٍ وَالدَّرَاوَرْدِيُّ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ أُسَامَةَ بْنِ الْهَادِ اللَّيْثِيِّ عَنْ عَبْدِ اللَّهِ بْنِ خَبَّابٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا رَأَى أَحَدُكُمْ الرُّؤْيَا يُحِبُّهَا فَإِنَّهَا مِنْ اللَّهِ فَلْيَحْمَدْ اللَّهَ عَلَيْهَا وَلْيُحَدِّثْ بِهَا وَإِذَا رَأَى غَيْرَ ذَلِكَ مِمَّا يَكْرَهُ فَإِنَّمَا هِيَ مِنْ الشَّيْطَانِ فَلْيَسْتَعِذْ مِنْ شَرِّهَا وَلَا يَذْكُرْهَا لِأَحَدٍ فَإِنَّهَا لَنْ تَضُرَّهُ","id":"Telah menceritakan kepada kami [Ibrahim bin Hamzah] telah menceritakan kepadaku [Ibnu Abi Hazim] dan [Darawardi] dari [Yazid bin 'Abdullah bin Usamah bin Hadi Al Laitsi] dari [Abdullah bin Khabbab] dari [Abu Sa'id Al Khudzri], bahwasanya ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang diantara kalian bermimpi yang disukainya, maka itu berasal dari Allah, maka hendaklah ia memuji Allah karenanya, dan hendaklah menceritakannya, sebaliknya jika bermimpi selainnya ynag tidak disukainya, hanyasanya yang demikian itu berasal dari setan, maka hendaklah ia meminta perlindungan dari kejahatannya, dan jangan menceritakannya kepada seorang pun, sebab tidak akan membahayakannya.\""},"6190":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ أَنَّ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا كَانَ يُحَدِّثُأَنَّ رَجُلًا أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي رَأَيْتُ اللَّيْلَةَ فِي الْمَنَامِ ظُلَّةً تَنْطُفُ السَّمْنَ وَالْعَسَلَ فَأَرَى النَّاسَ يَتَكَفَّفُونَ مِنْهَا فَالْمُسْتَكْثِرُ وَالْمُسْتَقِلُّ وَإِذَا سَبَبٌ وَاصِلٌ مِنْ الْأَرْضِ إِلَى السَّمَاءِ فَأَرَاكَ أَخَذْتَ بِهِ فَعَلَوْتَ ثُمَّ أَخَذَ بِهِ رَجُلٌ آخَرُ فَعَلَا بِهِ ثُمَّ أَخَذَ بِهِ رَجُلٌ آخَرُ فَعَلَا بِهِ ثُمَّ أَخَذَ بِهِ رَجُلٌ آخَرُ فَانْقَطَعَ ثُمَّ وُصِلَ فَقَالَ أَبُو بَكْرٍ يَا رَسُولَ اللَّهِ بِأَبِي أَنْتَ وَاللَّهِ لَتَدَعَنِّي فَأَعْبُرَهَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اعْبُرْهَا قَالَ أَمَّا الظُّلَّةُ فَالْإِسْلَامُ وَأَمَّا الَّذِي يَنْطُفُ مِنْ الْعَسَلِ وَالسَّمْنِ فَالْقُرْآنُ حَلَاوَتُهُ تَنْطُفُ فَالْمُسْتَكْثِرُ مِنْ الْقُرْآنِ وَالْمُسْتَقِلُّ وَأَمَّا السَّبَبُ الْوَاصِلُ مِنْ السَّمَاءِ إِلَى الْأَرْضِ فَالْحَقُّ الَّذِي أَنْتَ عَلَيْهِ تَأْخُذُ بِهِ فَيُعْلِيكَ اللَّهُ ثُمَّ يَأْخُذُ بِهِ رَجُلٌ مِنْ بَعْدِكَ فَيَعْلُو بِهِ ثُمَّ يَأْخُذُ بِهِ رَجُلٌ آخَرُ فَيَعْلُو بِهِ ثُمَّ يَأْخُذُهُ رَجُلٌ آخَرُ فَيَنْقَطِعُ بِهِ ثُمَّ يُوَصَّلُ لَهُ فَيَعْلُو بِهِ فَأَخْبِرْنِي يَا رَسُولَ اللَّهِ بِأَبِي أَنْتَ أَصَبْتُ أَمْ أَخْطَأْتُ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَصَبْتَ بَعْضًا وَأَخْطَأْتَ بَعْضًا قَالَ فَوَاللَّهِ يَا رَسُولَ اللَّهِ لَتُحَدِّثَنِّي بِالَّذِي أَخْطَأْتُ قَالَ لَا تُقْسِمْ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari [Yunus] dari [Ibnu Syihab] dari [Ubaidullah bin Abdullah] bahwasanya [Ibnu Abbas] radliallahu 'anhuma menceritakan; Ada seorang laki-laki mendatangi Rasulullah Shallallahu'alaihiwasallam mengatakan; 'Tadi malam aku bermimpi melihat segumpal awan yang meneteskan minyak samin dan madu, lantas kulihat orang banyak memintanya, ada yang meminta banyak dan ada yang meminta sedikit, tiba-tiba ada tali yang menghubungkan antara langit dan bumi, kulihat engkau memegangnya kemudian engkau naik, kemudian ada orang lain memegangnya dan ia pergunakan untuk naik, kemudian ada orang yag mengambilnya dan dipergunakannya untuk naik namun tali terputus, kemudian tali tersambung.' Spontan Abu Bakar berujar; 'Wahai Rasulullah, ayah dan ibuku untuk tebusanmu, demi Allah, biarkan aku untuk mentakwilkannya! ' \"takwilkanlah\" Kata Rasulullah Shallallahu'alaihiwasallam. Abu Bakar mengatakan; 'Adapun awan, itulah Islam, adapun madu dan minyak samin yang menetes, itulah Alquran, karena alqur'an manisnya menetes, maka silahkan ada yang memperbanyak atau mempersedikit, adapun tali yang menghubungkan langit dan bumi adalah kebenaran yang engkau pegang teguh sekarang ini, yang karenanya Allah meninggikan kedudukanmu, kemudian ada seseorang sepeninggalmu mengambilnya dan ia pun menjadi tinggi kedudukannya, lantas ada orang lain yang mengambilnya dan terputus, kemudian tali itu tersambung kembali sehingga ia menjadi tinggi kedudukannya karenanya, maka beritahulah aku ya Rasulullah, ayah dan ibuku sebagai tebusanmu, saya benar ataukah salah? ' Nabi shallallahu 'alaihi wasallam menjawab: \"Engkau benar sebagian dan salah sebagian!\" Abu Bakar mengatakan; 'Demi Allah ya Rasulullah, tolong beritahukanlah kepadaku takwilku yang salah! ' Nabi menjawab: \"Janganlah engkau bersumpah!\""},"6191":{"ar":"حَدَّثَنِي مُؤَمَّلُ بْنُ هِشَامٍ أَبُو هِشَامٍ حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا عَوْفٌ حَدَّثَنَا أَبُو رَجَاءٍ حَدَّثَنَا سَمُرَةُ بْنُ جُنْدُبٍ رَضِيَ اللَّهُ عَنْهُ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِمَّا يُكْثِرُ أَنْ يَقُولَ لِأَصْحَابِهِ هَلْ رَأَى أَحَدٌ مِنْكُمْ مِنْ رُؤْيَا قَالَ فَيَقُصُّ عَلَيْهِ مَنْ شَاءَ اللَّهُ أَنْ يَقُصَّ وَإِنَّهُ قَالَ ذَاتَ غَدَاةٍ إِنَّهُ أَتَانِي اللَّيْلَةَ آتِيَانِ وَإِنَّهُمَا ابْتَعَثَانِي وَإِنَّهُمَا قَالَا لِي انْطَلِقْ وَإِنِّي انْطَلَقْتُ مَعَهُمَا وَإِنَّا أَتَيْنَا عَلَى رَجُلٍ مُضْطَجِعٍ وَإِذَا آخَرُ قَائِمٌ عَلَيْهِ بِصَخْرَةٍ وَإِذَا هُوَ يَهْوِي بِالصَّخْرَةِ لِرَأْسِهِ فَيَثْلَغُ رَأْسَهُ فَيَتَهَدْهَدُ الْحَجَرُ هَا هُنَا فَيَتْبَعُ الْحَجَرَ فَيَأْخُذُهُ فَلَا يَرْجِعُ إِلَيْهِ حَتَّى يَصِحَّ رَأْسُهُ كَمَا كَانَ ثُمَّ يَعُودُ عَلَيْهِ فَيَفْعَلُ بِهِ مِثْلَ مَا فَعَلَ الْمَرَّةَ الْأُولَى قَالَ قُلْتُ لَهُمَا سُبْحَانَ اللَّهِ مَا هَذَانِ قَالَ قَالَا لِي انْطَلِقْ انْطَلِقْ قَالَ فَانْطَلَقْنَا فَأَتَيْنَا عَلَى رَجُلٍ مُسْتَلْقٍ لِقَفَاهُ وَإِذَا آخَرُ قَائِمٌ عَلَيْهِ بِكَلُّوبٍ مِنْ حَدِيدٍ وَإِذَا هُوَ يَأْتِي أَحَدَ شِقَّيْ وَجْهِهِ فَيُشَرْشِرُ شِدْقَهُ إِلَى قَفَاهُ وَمَنْخِرَهُ إِلَى قَفَاهُ وَعَيْنَهُ إِلَى قَفَاهُ قَالَ وَرُبَّمَا قَالَ أَبُو رَجَاءٍ فَيَشُقُّ قَالَ ثُمَّ يَتَحَوَّلُ إِلَى الْجَانِبِ الْآخَرِ فَيَفْعَلُ بِهِ مِثْلَ مَا فَعَلَ بِالْجَانِبِ الْأَوَّلِ فَمَا يَفْرُغُ مِنْ ذَلِكَ الْجَانِبِ حَتَّى يَصِحَّ ذَلِكَ الْجَانِبُ كَمَا كَانَ ثُمَّ يَعُودُ عَلَيْهِ فَيَفْعَلُ مِثْلَ مَا فَعَلَ الْمَرَّةَ الْأُولَى قَالَ قُلْتُ سُبْحَانَ اللَّهِ مَا هَذَانِ قَالَ قَالَا لِي انْطَلِقْ انْطَلِقْ فَانْطَلَقْنَا فَأَتَيْنَا عَلَى مِثْلِ التَّنُّورِ قَالَ فَأَحْسِبُ أَنَّهُ كَانَ يَقُولُ فَإِذَا فِيهِ لَغَطٌ وَأَصْوَاتٌ قَالَ فَاطَّلَعْنَا فِيهِ فَإِذَا فِيهِ رِجَالٌ وَنِسَاءٌ عُرَاةٌ وَإِذَا هُمْ يَأْتِيهِمْ لَهَبٌ مِنْ أَسْفَلَ مِنْهُمْ فَإِذَا أَتَاهُمْ ذَلِكَ اللَّهَبُ ضَوْضَوْا قَالَ قُلْتُ لَهُمَا مَا هَؤُلَاءِ قَالَ قَالَا لِي انْطَلِقْ انْطَلِقْ قَالَ فَانْطَلَقْنَا فَأَتَيْنَا عَلَى نَهَرٍ حَسِبْتُ أَنَّهُ كَانَ يَقُولُ أَحْمَرَ مِثْلِ الدَّمِ وَإِذَا فِي النَّهَرِ رَجُلٌ سَابِحٌ يَسْبَحُ وَإِذَا عَلَى شَطِّ النَّهَرِ رَجُلٌ قَدْ جَمَعَ عِنْدَهُ حِجَارَةً كَثِيرَةً وَإِذَا ذَلِكَ السَّابِحُ يَسْبَحُ مَا يَسْبَحُ ثُمَّ يَأْتِي ذَلِكَ الَّذِي قَدْ جَمَعَ عِنْدَهُ الْحِجَارَةَ فَيَفْغَرُ لَهُ فَاهُ فَيُلْقِمُهُ حَجَرًا فَيَنْطَلِقُ يَسْبَحُ ثُمَّ يَرْجِعُ إِلَيْهِ كُلَّمَا رَجَعَ إِلَيْهِ فَغَرَ لَهُ فَاهُ فَأَلْقَمَهُ حَجَرًا قَالَ قُلْتُ لَهُمَا مَا هَذَانِ قَالَ قَالَا لِي انْطَلِقْ انْطَلِقْ قَالَ فَانْطَلَقْنَا فَأَتَيْنَا عَلَى رَجُلٍ كَرِيهِ الْمَرْآةِ كَأَكْرَهِ مَا أَنْتَ رَاءٍ رَجُلًا مَرْآةً وَإِذَا عِنْدَهُ نَارٌ يَحُشُّهَا وَيَسْعَى حَوْلَهَا قَالَ قُلْتُ لَهُمَا مَا هَذَا قَالَ قَالَا لِي انْطَلِقْ انْطَلِقْ فَانْطَلَقْنَا فَأَتَيْنَا عَلَى رَوْضَةٍ مُعْتَمَّةٍ فِيهَا مِنْ كُلِّ لَوْنِ الرَّبِيعِ وَإِذَا بَيْنَ ظَهْرَيْ الرَّوْضَةِ رَجُلٌ طَوِيلٌ لَا أَكَادُ أَرَى رَأْسَهُ طُولًا فِي السَّمَاءِ وَإِذَا حَوْلَ الرَّجُلِ مِنْ أَكْثَرِ وِلْدَانٍ رَأَيْتُهُمْ قَطُّ قَالَ قُلْتُ لَهُمَا مَا هَذَا مَا هَؤُلَاءِ قَالَ قَالَا لِي انْطَلِقْ انْطَلِقْ قَالَ فَانْطَلَقْنَا فَانْتَهَيْنَا إِلَى رَوْضَةٍ عَظِيمَةٍ لَمْ أَرَ رَوْضَةً قَطُّ أَعْظَمَ مِنْهَا وَلَا أَحْسَنَ قَالَ قَالَا لِي ارْقَ فِيهَا قَالَ فَارْتَقَيْنَا فِيهَا فَانْتَهَيْنَا إِلَى مَدِينَةٍ مَبْنِيَّةٍ بِلَبِنِ ذَهَبٍ وَلَبِنِ فِضَّةٍ فَأَتَيْنَا بَابَ الْمَدِينَةِ فَاسْتَفْتَحْنَا فَفُتِحَ لَنَا فَدَخَلْنَاهَا فَتَلَقَّانَا فِيهَا رِجَالٌ شَطْرٌ مِنْ خَلْقِهِمْ كَأَحْسَنِ مَا أَنْتَ رَاءٍ وَشَطْرٌ كَأَقْبَحِ مَا أَنْتَ رَاءٍ قَالَ قَالَا لَهُمْ اذْهَبُوا فَقَعُوا فِي ذَلِكَ النَّهَرِ قَالَ وَإِذَا نَهَرٌ مُعْتَرِضٌ يَجْرِي كَأَنَّ مَاءَهُ الْمَحْضُ فِي الْبَيَاضِ فَذَهَبُوا فَوَقَعُوا فِيهِ ثُمَّ رَجَعُوا إِلَيْنَا قَدْ ذَهَبَ ذَلِكَ السُّوءُ عَنْهُمْ فَصَارُوا فِي أَحْسَنِ صُورَةٍ قَالَ قَالَا لِي هَذِهِ جَنَّةُ عَدْنٍ وَهَذَاكَ مَنْزِلُكَ قَالَ فَسَمَا بَصَرِي صُعُدًا فَإِذَا قَصْرٌ مِثْلُ الرَّبَابَةِ الْبَيْضَاءِ قَالَ قَالَا لِي هَذَاكَ مَنْزِلُكَ قَالَ قُلْتُ لَهُمَا بَارَكَ اللَّهُ فِيكُمَا ذَرَانِي فَأَدْخُلَهُ قَالَا أَمَّا الْآنَ فَلَا وَأَنْتَ دَاخِلَهُ قَالَ قُلْتُ لَهُمَا فَإِنِّي قَدْ رَأَيْتُ مُنْذُ اللَّيْلَةِ عَجَبًا فَمَا هَذَا الَّذِي رَأَيْتُ قَالَ قَالَا لِي أَمَا إِنَّا سَنُخْبِرُكَ أَمَّا الرَّجُلُ الْأَوَّلُ الَّذِي أَتَيْتَ عَلَيْهِ يُثْلَغُ رَأْسُهُ بِالْحَجَرِ فَإِنَّهُ الرَّجُلُ يَأْخُذُ الْقُرْآنَ فَيَرْفُضُهُ وَيَنَامُ عَنْ الصَّلَاةِ الْمَكْتُوبَةِ وَأَمَّا الرَّجُلُ الَّذِي أَتَيْتَ عَلَيْهِ يُشَرْشَرُ شِدْقُهُ إِلَى قَفَاهُ وَمَنْخِرُهُ إِلَى قَفَاهُ وَعَيْنُهُ إِلَى قَفَاهُ فَإِنَّهُ الرَّجُلُ يَغْدُو مِنْ بَيْتِهِ فَيَكْذِبُ الْكَذْبَةَ تَبْلُغُ الْآفَاقَ وَأَمَّا الرِّجَالُ وَالنِّسَاءُ الْعُرَاةُ الَّذِينَ فِي مِثْلِ بِنَاءِ التَّنُّورِ فَإِنَّهُمْ الزُّنَاةُ وَالزَّوَانِي وَأَمَّا الرَّجُلُ الَّذِي أَتَيْتَ عَلَيْهِ يَسْبَحُ فِي النَّهَرِ وَيُلْقَمُ الْحَجَرَ فَإِنَّهُ آكِلُ الرِّبَا وَأَمَّا الرَّجُلُ الْكَرِيهُ الْمَرْآةِ الَّذِي عِنْدَ النَّارِ يَحُشُّهَا وَيَسْعَى حَوْلَهَا فَإِنَّهُ مَالِكٌ خَازِنُ جَهَنَّمَ وَأَمَّا الرَّجُلُ الطَّوِيلُ الَّذِي فِي الرَّوْضَةِ فَإِنَّهُ إِبْرَاهِيمُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَمَّا الْوِلْدَانُ الَّذِينَ حَوْلَهُ فَكُلُّ مَوْلُودٍ مَاتَ عَلَى الْفِطْرَةِ قَالَ فَقَالَ بَعْضُ الْمُسْلِمِينَ يَا رَسُولَ اللَّهِ وَأَوْلَادُ الْمُشْرِكِينَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَوْلَادُ الْمُشْرِكِينَ وَأَمَّا الْقَوْمُ الَّذِينَ كَانُوا شَطْرٌ مِنْهُمْ حَسَنًا وَشَطْرٌ قَبِيحًا فَإِنَّهُمْ قَوْمٌ خَلَطُوا عَمَلًا صَالِحًا وَآخَرَ سَيِّئًا تَجَاوَزَ اللَّهُ عَنْهُمْ","id":"Telah menceritakan kepadaku [Mu`ammal bin Hisyam Abu Hisyam] telah menceritakan kepada kami [Isma'il bin Ibrahim] telah menceritakan kepada kami ['Auf] telah menceritakan kepada kami [Abu Raja'] telah menceritakan kepada kami [Samurah bin Jundab] radliallahu 'anhu, Rasulullah Shallallahu'alaihiwasallam seringkali mengatakan kepada para sahabatnya; \"Apakah diantara kalian ada yang bermimpi?\" Kata Samurah; maka ada diantara mereka yang menceritakan kisahnya. Suatu saat ketika subuh, beliau berkata: \"Semalaman aku didatangi dua orang, keduanya mengajakku pergi dan berujar; 'Ayo kita berangkat! ' Aku pun berangkat bersama keduanya, dan kami mendatangi seseorang yang berbaring dan yang lain berdiri disampingnya dengan membawa batu besar, lalu ia menjatuhkan batu tersebut di kepalanya sehingga kepalanya pecah dan batu menggelinding disini. Orang tadi terus mengikuti batu dan mengambilnya, namun ketika dia belum kembali kepada yang dijatuhi, tetapi kepalanya telah kembali seperti sedia kala. Lantas orang tadi kembali menemuinya dan mengerjakan sebagaimana semula. Sayapun bertanya kepada dua orang yang membawaku; 'Subhanallah, mengapa kedua orang ini seperti ini? ' keduanya menjawab; 'Mari kita berangkat ke tempat lain dahulu! ' Kami pun berangkat, lantas kami mendatangi seseorang yang terlentang diatas kedua tengkuknya sedang ada orang lain yang berdiri di sampingnya sambil membawa pengait besi, ia memegang salah satu samping wajahnya dan memotong-motong dagunya hingga tengkuknya, dan tenggorokannya hingga tengkuknya, dan matanya hingga tengkuknya\" -Kata Auf, terkadang Abu Raja' menggunakan redaksi; 'lantas membelah-belah dagunya, bukan memotong- \"kemudian orang yang memotong berpindah ke sisi dagu lain dan memperlakukan korbannya sebagaimana ia lakukan pada sisi dagu pertama. Belum ia selesai memotong-mogong dagu kedua, maka dagu samping pertama kembali seperti semula, maka orang itu memperlakukannya sebagaimana semula. Maka saya bertanya; 'Subhanallah, kenapa dua orang ini? ' Namun kedua orang yang membawaku hanya berujar; 'Mari kita pindah ke tempat lain dulu! ' Maka kami berangkat, hingga kami mendatangi suatu tempat seperti tungku.\" Kata Abu Raja, seingatku Samurah mengatakan; \"Tungku tersebut mengeluarkan suara gemuruh.- Lantas kami melihat isinya, tak tahunya disana ada laki-laki dan wanita telanjang, mereka didatangi oleh sulut api dari bawah mereka, jika sulutan api mengenai mereka, mereka mengerang-ngerang. Maka saya bertanya kepada dua orang yang membawaku; 'apa sebenarnya dengan orang-orang ini? Namun kedua orang yang membawaku hanya berujar; 'Ayo kita berpindah ke tempat lain! ' Maka kami terus berangkat, dan kami mendatangi sebuah sungai.\" Dan setahuku Samurah mengatakan; 'sungai merah seperti darah-, \"tak tahunya di sungai ada laki-laki yang berenang, sedang ditepi sungai ada orang yang mengumpulkan banyak bebatuan, apabila yang berenang tadi sampai ke tepian sungai, ke tempat orang yang mengumpulkan bebatuan, maka ia membuka mulutnya dan orang yang di tepi tadi memasukkan batu ke mulutnya, lantas ia berenang kemudian kembali lagi, setiap kali ia kembali ke tepi, mulutnya membuka dan orang yang di tepi menyuapinya dengan batu itu. Saya bertanya kepada dua orang yang membawaku; 'kenapa dua orang ini? ' keduanya menjawab; 'Ayo kita pindah ke tempat lain dulu! ' Maka kami pun berangkat, lantas kami mendatangi seseorang yang wajahnya menyeramkan sebagaimana seseorang yang paling menyeramkan yang pernah kalian lihat. Dan di dekatnya terdapat api yang terus ia nyalakan dan dia berlari di sekitarnya. Saya bertanya kepada dua orang yang membawaku; 'mengapa orang ini? ' kedua orang yang membawaku berujar; 'Ayo kita pindah ke tempat lain dahulu! ' Lantas kami berangkat. Lalu kami mendatangi sebuah kebun yang secara merata berisi warna musim semi, diantara dua tepi kebun terdapat seseorang yang jangkung, yang nyaris aku belum pernah melihat manusia yang kepalanya memanjang di langit seperti itu, dan sekitar orang itu terdapat banyak anak-anak kecil yang pernah aku lihat. Saya bertanya; 'Apa ini sebenarnya, mereka ini siapa? ' kedua orang yang membawaku berujar; 'Ayo kita pindah ke tempat lain dulu! ' Kami pun berangkat melanjutkan perjalanan, hingga kami mendatangi sebuah kebun besar yang sebelumnya aku belum pernah melihat kebun lebih besar dan lebih indah daripadanya sama sekali, Keduanya berkata; 'Naiklah engkau! ' Kami pun naik, dan kami berakhir ke sebuah kota yang dibangun dari batu bata emas dan perak, lalu kami tiba di pintu kota. Kami minta di buka, maka pintu pun dibuka untuk kami, kami masuk dan kami disambut oleh beberapa orang yang separo tubuhnya seperti orang paling tampan yang pernah anda lihat, dan separohnya seperti manusia paling jelek yang pernah engkau lihat. Keduanya mengatakan kepada mereka; 'Pergilah kalian semua! ' Lantas mereka sampai di sebuah sungai. Tak tahunya sungai itu terbentang mengalir, airnya sangat putih bersih, mereka pun pergi dan mandi-mandi disana, kemudian kembali menemui kami dan kotorannya telah hilang di sungai tempat mereka mandi, sehingga mereka menjadi manusia paling tampan. Keduanya mengatakan kepadaku; 'Inilah surga Aden dan di sini hunianmu! ' lantas pandanganku menatap ke atas, tak tahunya ada sebuah istana seperti awan putih yang menyendiri. Keduanya berkata; 'Inilah hunianmu! ' Saya menjawab; 'Semoga Allah memberkati kalian berdua, sekarang biarkanlah aku untuk memasukinya! ' Keduanya menjawab; 'kalau sekarang jangan dulu, namun pasti engkau akan memasukinya! ' Saya mengatakan; 'Semenjak semalaman aku telah melihat peristiwa-peristiwa aneh nan mencengangkan, tolong kabarilah aku apa arti sebenarnya yang kulihat! ' Keduanya berujar; 'Sekarang baiklah kuberitakan kepadamu peristiwa-peristiwa itu! Adapun laki-laki pertama yang kamu datangi sedang kepalanya pecah dengan batu, itu adalah seseorang yang mempelajari alquran namun ia menolaknya, dan ia tidur sampai meninggalkan shalat wajib. Adapun orang yang kamu datangi membelah dagu kawannya hingga tengkuknya, tenggorokannya hingga dagunya, dan matanya hingga tengkuknya, itu adalah seseorang yang berangkat dari rumahnya lantas ia dusta, dan kedustaannya menembus cakrawala. Adapun laki-laki dan wanita yang telanjang dalam bangunan seperti tungku, mereka adalah laki-laki dan wanita pezina. Adapun laki-laki yang berenang dalam sungai dan disuapi batu besar, mereka adalah pemakan riba, adapun laki-laki yang raut mukanya menyeramkan di neraka sambil menyalakan api dan berlari-lari di sekitarnya, itu adalah Malik, penjaga Jahannam, adapun laki-laki jangkung dalam taman, ia adalah Ibrahim 'alaihissalam, adapun anak-anak di sekitarnya adalah bayi yang mati diatas fitrah.\" Lantas sebagian sahabat bertanya; 'ya Rasulullah, juga anak orang-orang musyrik? ' Rasulullah shallallahu 'alaihi wasallam bersabda: \"Juga anak-anak orang-orang musyrik! Adapun orang yang separoh berwajah tampan dan separohnya lagi jelek, mereka adalah orang yang mencampuradukkan amal shalih dan lainnya jelek, lantas Allah mengampuni kesalahannya.\""},"6192":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا بِشْرُ بْنُ السَّرِيِّ حَدَّثَنَا نَافِعُ بْنُ عُمَرَ عَنْ ابْنِ أَبِي مُلَيْكَةَ قَالَ قَالَتْ أَسْمَاءُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَنَا عَلَى حَوْضِي أَنْتَظِرُ مَنْ يَرِدُ عَلَيَّ فَيُؤْخَذُ بِنَاسٍ مِنْ دُونِي فَأَقُولُ أُمَّتِي فَيُقَالُ لَا تَدْرِي مَشَوْا عَلَى الْقَهْقَرَىقَالَ ابْنُ أَبِي مُلَيْكَةَ اللَّهُمَّ إِنَّا نَعُوذُ بِكَ أَنْ نَرْجِعَ عَلَى أَعْقَابِنَا أَوْ نُفْتَنَ","id":"Telah menceritakan kepada kami ['Ali bin Abdullah] Telah menceritakan kepada kami [Bisyir bin As Sari] telah menceritakan kepada kami [Nafi' bin Umar] dari [Ibnu Abi Mulaikah] mengatakan, [Asma'] mengatakan dari Nabi shallallahu 'alaihi wasallam; \"aku berada di telagaku menunggu-nunggu orang yang datang kepadaku, tiba-tiba orang di belakangku ditangkap dan dijauhkan dariku sehingga aku berteriak-teriak; 'Itu umatku, itu umatku! ' Tiba-tiba ada suara menjawab; 'Kamu tidak tahu! Mereka berjalan dengan melakukan bid'ah, maksiyat, dan dosa besar'.\" Ibnu Abi Mulaikah terus memanjatkan doa; Ya Allah, aku berlindung kepada-MU dari berbalik ke belakang atau terkena hantaman fitnah! "},"6193":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ مُغِيرَةَ عَنْ أَبِي وَائِلٍ قَالَ قَالَ عَبْدُ اللَّهِقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا فَرَطُكُمْ عَلَى الْحَوْضِ لَيُرْفَعَنَّ إِلَيَّ رِجَالٌ مِنْكُمْ حَتَّى إِذَا أَهْوَيْتُ لِأُنَاوِلَهُمْ اخْتُلِجُوا دُونِي فَأَقُولُ أَيْ رَبِّ أَصْحَابِي يَقُولُ لَا تَدْرِي مَا أَحْدَثُوا بَعْدَكَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Abu 'Awanah] dari [Mughirah] dari [Abu Wa`il] mengatakan ' [Abdullah] mengatakan, Nabi shallallahu 'alaihi wasallam bersabda; \"Aku adalah manusia pertama-tama diantara kalian yang menuju telaga, lantas diperlihatkan padaku beberapa orang diantara kalian, hingga jika aku ingin menggandeng mereka, tiba-tiba mereka ditangkap dan dijauhkan dariku, sehingga aku berteriak-teriak 'Ya rabbi, itu sahabatku, ya rabbi, itu sahabatku! ' Allah menjawab; kamu tidak tahu apa yang perbuat sepeninggalmu! '\""},"6194":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا يَعْقُوبُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي حَازِمٍ قَالَ سَمِعْتُ سَهْلَ بْنَ سَعْدٍ يَقُولُسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَنَا فَرَطُكُمْ عَلَى الْحَوْضِ فَمَنْ وَرَدَهُ شَرِبَ مِنْهُ وَمَنْ شَرِبَ مِنْهُ لَمْ يَظْمَأْ بَعْدَهُ أَبَدًا لَيَرِدُ عَلَيَّ أَقْوَامٌ أَعْرِفُهُمْ وَيَعْرِفُونِي ثُمَّ يُحَالُ بَيْنِي وَبَيْنَهُمْقَالَ أَبُو حَازِمٍ فَسَمِعَنِي النُّعْمَانُ بْنُ أَبِي عَيَّاشٍ وَأَنَا أُحَدِّثُهُمْ هَذَا فَقَالَ هَكَذَا سَمِعْتَ سَهْلًا فَقُلْتُ نَعَمْ قَالَ وَأَنَا أَشْهَدُ عَلَى أَبِي سَعِيدٍ الْخُدْرِيِّ لَسَمِعْتُهُ يَزِيدُ فِيهِ قَالَ إِنَّهُمْ مِنِّي فَيُقَالُ إِنَّكَ لَا تَدْرِي مَا بَدَّلُوا بَعْدَكَ فَأَقُولُ سُحْقًا سُحْقًا لِمَنْ بَدَّلَ بَعْدِي","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Ya'qub bin Abdurrahman] dari [Abu Hazim] mengatakan aku mendengar [Sahal bin Sa'd] mengatakan, aku mendengar Nabi Shallallahu'alaihiwasallam bersabda; \"Aku manusia pertama-tama diantara kalian yang menuju telaga, barangsiapa mendatanginya, maka tak akan haus selama-lamanya, sungguh beberapa orang menemuiku yang aku mengenal mereka dan juga mereka mengenalku, lantas tiba-tiba aku dan mereka terhalang.\" [Abu Hazim] mengatakan; dan [Nu'man bin Abi 'Ayyasy] mendengar aku ketika aku sedang menceritakan kepada mereka hadits ini, lantas ia bertanya kepadaku; 'kamu mendengar dari [Sahal] ' Kujawab; 'Iya.' Ia katakan; 'Dan saya bersaksi kepada [Abu Sa'id Al Khudzri], sungguh aku mendengarnya dengan tambahan redaksi; \"Mereka adalah dari ummatku' lantas ada suara yang menjawab; kamu tidak tahu perubahan yang mereka lakukan sepeninggalmu! Sehingga aku berkata; 'Celaka,, celaka bagi siapa saja yang mengganti agama sepeninggalku!\""},"6195":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ حَدَّثَنَا الْأَعْمَشُ حَدَّثَنَا زَيْدُ بْنُ وَهْبٍ سَمِعْتُ عَبْدَ اللَّهِ قَالَقَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّكُمْ سَتَرَوْنَ بَعْدِي أَثَرَةً وَأُمُورًا تُنْكِرُونَهَا قَالُوا فَمَا تَأْمُرُنَا يَا رَسُولَ اللَّهِ قَالَ أَدُّوا إِلَيْهِمْ حَقَّهُمْ وَسَلُوا اللَّهَ حَقَّكُمْ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya bin Sa'id Al Qaththan] telah menceritakan kepada kami [Al A'masy] telah menceritakan kepada kami [Zaid bin Wahab] aku mendengar [Abdullah] mengatakan; Rasulullah shallallahu 'alaihi wasallam bersabda kepada kami; \"Kalian akan menyaksikan sikap-sikap egois sepeninggalku, dan beberapa perkara yang kalian ingkari.\" Para sahabat bertanya; 'Lantas bagaimana anda menyuruh kami ya Rasulullah! ' Nabi menjawab; \"Tunaikanlah hak mereka dan mintalah kepada Allah hakmu!\""},"6196":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ الْجَعْدِ عَنْ أَبِي رَجَاءٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ كَرِهَ مِنْ أَمِيرِهِ شَيْئًا فَلْيَصْبِرْ فَإِنَّهُ مَنْ خَرَجَ مِنْ السُّلْطَانِ شِبْرًا مَاتَ مِيتَةً جَاهِلِيَّةً","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami ['Abdul warits] dari [Al Ja'd] dari [Abu Raja'] dari [Ibnu 'Abbas] dari Nabi shallallahu 'alaihi wasallam bersabda; \"Siapa yang tidak menyukai kebijakan amir (pemimpinnya) hendaklah bersabar, sebab siapapun yang keluar dari ketaatan kepada amir sejengkal, ia mati dalam jahiliyah.\""},"6197":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ الْجَعْدِ أَبِي عُثْمَانَ حَدَّثَنِي أَبُو رَجَاءٍ الْعُطَارِدِيُّ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ رَأَى مِنْ أَمِيرِهِ شَيْئًا يَكْرَهُهُ فَلْيَصْبِرْ عَلَيْهِ فَإِنَّهُ مَنْ فَارَقَ الْجَمَاعَةَ شِبْرًا فَمَاتَ إِلَّا مَاتَ مِيتَةً جَاهِلِيَّةً","id":"Telah menceritakan kepada kami [Abu Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] dari [Alja'd Abi Utsman] telah menceritakan kepadaku [Abu Raja' Al 'utharidi] mengtakan, aku mendengar [Ibnu Abbas] radliallahu 'anhuma dari Nabi Shallallahu'alaihiwasallam bersabda; \"Siapapun yang melihat sesuatu dari pemimpinnya yang tak disukainya, hendaklah ia bersabar terhadapnya, sebab siapa yang memisahkan diri sejengkal dari jama'ah, kecuali dia mati dalam jahiliyah.\""},"6198":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنِي ابْنُ وَهْبٍ عَنْ عَمْرٍو عَنْ بُكَيْرٍ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ جُنَادَةَ بْنِ أَبِي أُمَيَّةَ قَالَ دَخَلْنَا عَلَى عُبَادَةَ بْنِ الصَّامِتِوَهُوَ مَرِيضٌ قُلْنَا أَصْلَحَكَ اللَّهُ حَدِّثْ بِحَدِيثٍ يَنْفَعُكَ اللَّهُ بِهِ سَمِعْتَهُ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ دَعَانَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَايَعْنَاهُ فَقَالَ فِيمَا أَخَذَ عَلَيْنَا أَنْ بَايَعَنَا عَلَى السَّمْعِ وَالطَّاعَةِ فِي مَنْشَطِنَا وَمَكْرَهِنَا وَعُسْرِنَا وَيُسْرِنَا وَأَثَرَةً عَلَيْنَا وَأَنْ لَا نُنَازِعَ الْأَمْرَ أَهْلَهُ إِلَّا أَنْ تَرَوْا كُفْرًا بَوَاحًا عِنْدَكُمْ مِنْ اللَّهِ فِيهِ بُرْهَانٌ","id":"Telah menceritakan kepada kami [Isma'il] telah menceritakan kepadaku [Ibnu Wahb] dari [Amru] dari [Bukair] dari [Busr bin Sa'id] dari [Junadah bin Umayyah] mengatakan, kami berkunjung ke [Ubadah bin Shamit] yang ketika itu sedang sakit. Kami menyapa; 'semoga Allah menyembuhkanmu, ceritakan kepada kami sebuah Hadits, yang kiranya Allah memberimu manfaat karenanya, yang engkau dengar dari Nabi shallallahu 'alaihi wasallam! ' Ia menjawab; 'Nabi shallallahu 'alaihi wasallam memanggil kami sehingga kami berbaiat kepada beliau.' Ubadah melanjutkan; diantara janji yang beliau ambil dari kami adalah, agar kami berbaiat kepada beliau untuk senantiasa mendengar dan ta'at, saat giat mapun malas, dan saat kesulitan maupun kesusahan, lebih mementingkan urusan bersama, serta agar kami tidak mencabut urusan dari ahlinya kecuali jika kalian melihat kekufuran yang terang-terangan, yang pada kalian mempunyai alasan yang jelas dari Allah.'"},"6199":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَرْعَرَةَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ أُسَيْدِ بْنِ حُضَيْرٍأَنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ اسْتَعْمَلْتَ فُلَانًا وَلَمْ تَسْتَعْمِلْنِي قَالَ إِنَّكُمْ سَتَرَوْنَ بَعْدِي أَثَرَةً فَاصْبِرُوا حَتَّى تَلْقَوْنِي","id":"Telah menceritakan kepada kami [Muhammad bin 'Ar'arah] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Anas bin Malik] dari [Usaid bin Hudhair], ada seseorang yang menemui Nabi shallallahu 'alaihi wasallam dan berujar; 'Wahai Rasulullah, engkau mempekerjakan si fulan namun engkau tidak mempekerjakan aku? ' maka Nabi menjawab; \"kalian sepeninggalku akan melihat sifat-sifat egoisme, maka bersabarlah hingga kalian menemuiku.\""},"6200":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا عَمْرُو بْنُ يَحْيَى بْنِ سَعِيدِ بْنِ عَمْرِو بْنِ سَعِيدٍ قَالَ أَخْبَرَنِي جَدِّي قَالَ كُنْتُ جَالِسًا مَعَ أَبِي هُرَيْرَةَفِي مَسْجِدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْمَدِينَةِ وَمَعَنَا مَرْوَانُ قَالَ أَبُو هُرَيْرَةَ سَمِعْتُ الصَّادِقَ الْمَصْدُوقَ يَقُولُ هَلَكَةُ أُمَّتِي عَلَى يَدَيْ غِلْمَةٍ مِنْ قُرَيْشٍ فَقَالَ مَرْوَانُ لَعْنَةُ اللَّهِ عَلَيْهِمْ غِلْمَةً فَقَالَ أَبُو هُرَيْرَةَ لَوْ شِئْتُ أَنْ أَقُولَ بَنِي فُلَانٍ وَبَنِي فُلَانٍ لَفَعَلْتُ فَكُنْتُ أَخْرُجُ مَعَ جَدِّي إِلَى بَنِي مَرْوَانَ حِينَ مُلِّكُوا بِالشَّأْمِ فَإِذَا رَآهُمْ غِلْمَانًا أَحْدَاثًا قَالَ لَنَا عَسَى هَؤُلَاءِ أَنْ يَكُونُوا مِنْهُمْ قُلْنَا أَنْتَ أَعْلَمُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Amru bin Yahya bin Sa'id bin Amru bin Sa'id] mengatakan, telah mengabarkan kepadaku [ayahku] mengatakan, pernah aku duduk bersama [Abu Hurairah] di masjid Nabi shallallahu 'alaihi wasallam di Madinah. Pada saat itu kami juga bersama Marwan. Abu Hurairah mengatakan; 'Aku mendengar seorang yang jujur menyampaikan, dan berita yang dibawanya adalah benar (Muhammad) mengatakan: \"Kebinasaan umatku di tangan anak-anak muda Qurays.\" Spontan Marwan berseru; 'Kiranya laknat Allah tertimpa kepada mereka, anak-anak muda itu! ' Lantas Abu Hurairah mengatakan 'Kalau aku berkenan mengatakan bani fulan, bani fulan, niscaya kulakukan! ' Kemudian aku keluar (mengadakan perjalanan) bersama kakekku ke bani marwan ketika menjadi raja-raja Syam, dan jika ia melihat mereka, mereka adalah anak-anak muda yang masih belia, ia mengatakan kepada kami; 'bisa jadi mereka itu adalah diantara mereka itu (yang disebutkan dalam sabda Nabi).' Maka kami menjawab; 'Engkau lebih tahu! '"},"6201":{"ar":"حَدَّثَنَا مَالِكُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا ابْنُ عُيَيْنَةَ أَنَّهُ سَمِعَ الزُّهْرِيَّ عَنْ عُرْوَةَ عَنْ زَيْنَبَ بِنْتِ أُمِّ سَلَمَةَ عَنْ أُمِّ حَبِيبَةَ عَنْ زَيْنَبَ بِنْتِ جَحْشٍ رَضِيَ اللَّهُ عَنْهُنَّ أَنَّهَا قَالَتْاسْتَيْقَظَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ النَّوْمِ مُحْمَرًّا وَجْهُهُ يَقُولُ لَا إِلَهَ إِلَّا اللَّهُ وَيْلٌ لِلْعَرَبِ مِنْ شَرٍّ قَدْ اقْتَرَبَ فُتِحَ الْيَوْمَ مِنْ رَدْمِ يَأْجُوجَ وَمَأْجُوجَ مِثْلُ هَذِهِ وَعَقَدَ سُفْيَانُ تِسْعِينَ أَوْ مِائَةً قِيلَ أَنَهْلِكُ وَفِينَا الصَّالِحُونَ قَالَ نَعَمْ إِذَا كَثُرَ الْخَبَثُ","id":"Telah menceritakan kepada kami [Malik bin Isma'il] telah menceritakan kepada kami [Ibnu 'Uyainah], bahwasanya ia mendengar [Az Zuhri] dari ['Urwah] dari [Zainab binti Ummu Salamah] dari [Ummu Habibah] dari [Zainab binti Jahsy] rdhiyallahu'anhuna, ia mengatakan; Nabi shallallahu 'alaihi wasallam bangun tidur dalam keadaan wajahnya memerah seraya mengucapkan: \"laa-ilaaha-illallah, celaka bangsa arab karena keburukan yang telah dekat, hari ini telah dibuka benteng Ya'juj dan Ma'juj seperti ini\" --Sedang Sufyan menyatakan secara pasti jumlahnya yaitu sembilan puluh atau seratus-maka beliau di tanya; 'Apakah kita juga akan binasa sedang diantara kita masih ada orang-orang yang shalih? ' Nabi menjawab; \"Iya, jika kejahatan telah mewabah.\""},"6202":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ ح و حَدَّثَنِي مَحْمُودٌ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ أُسَامَةَ بْنِ زَيْدٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَأَشْرَفَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى أُطُمٍ مِنْ آطَامِ الْمَدِينَةِ فَقَالَ هَلْ تَرَوْنَ مَا أَرَى قَالُوا لَا قَالَ فَإِنِّي لَأَرَى الْفِتَنَ تَقَعُ خِلَالَ بُيُوتِكُمْ كَوَقْعِ الْقَطْرِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Az Zuhri] -lewat jalur periwayatan lain-Dan telah menceritakan kepadaku [Mahmud] telah mengabarkan kepadaku ['Abdurrazzaq] Telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Urwah] dari [Usamah bin Zaid] radliallahu 'anhuma, mengatakan; Pernah Nabi shallallahu 'alaihi wasallam menaiki sebuah benteng Madinah lantas mengatakan; \"apakah kalian melihat yang kulihat?\" Mereka menjawab; 'Tidak.' Beliau bersabda: \"Sungguh aku melihat fitnah telah terjadi ditengah-tengah rumah kalian sebagaimana hujan turun.\""},"6203":{"ar":"حَدَّثَنَا عَيَّاشُ بْنُ الْوَلِيدِ أَخْبَرَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَتَقَارَبُ الزَّمَانُ وَيَنْقُصُ الْعَمَلُ وَيُلْقَى الشُّحُّ وَتَظْهَرُ الْفِتَنُ وَيَكْثُرُ الْهَرْجُ قَالُوا يَا رَسُولَ اللَّهِ أَيُّمَ هُوَ قَالَ الْقَتْلُ الْقَتْلُوَقَالَ شُعَيْبٌ وَيُونُسُ وَاللَّيْثُ وَابْنُ أَخِي الزُّهْرِيِّ عَنْ الزُّهْرِيِّ عَنْ حُمَيْدٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami ['Ayyasy bin Al Walid] Telah mengabarkan kepada kami ['Abdul A'la] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Sa'id] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam bersabda (tentang tanda-tanda kiamat); \"Jaman terasa ringkas, amal shalih berkurang, kebakhilan merajalela, fitnah (maksiat) dinyatakan secara terang-terangan, dan banyak al haraj.\" Para sahabat bertanya; 'Ya Rasulullah, apa maksud istilah al haraj? ' Nabi menjawab \"Pembunuhan-pembunuhan.\" Sedang [Syu'aib], [Yunus], dan [Al Laits], serta [anak Saudaraku, Az Zuhri], mengatakan dari [Az Zuhri] dari [Humaid] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam."},"6204":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ قَالَ كُنْتُ مَعَ عَبْدِ اللَّهِ وَأَبِي مُوسَى فَقَالَاقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ بَيْنَ يَدَيْ السَّاعَةِ لَأَيَّامًا يَنْزِلُ فِيهَا الْجَهْلُ وَيُرْفَعُ فِيهَا الْعِلْمُ وَيَكْثُرُ فِيهَا الْهَرْجُ وَالْهَرْجُ الْقَتْلُ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami ['Ubaidullah bin Musa] dari [Al A'masy] dari [Syaqiq] mengatakan; aku bersama [Abdullah] dan [Abu Musa], keduanya mengatakan; Nabi Shallallahu'alaihiwasallam bersabda; \"Menjelang kiamat terjadi, terdapat hari-hari yang ketika itu banyak kebodohan, ilmu diangkat, dan banyak alharaj, alharaj adalah pembunuhan.\""},"6205":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ حَدَّثَنَا شَقِيقٌ قَالَجَلَسَ عَبْدُ اللَّهِ وَأَبُو مُوسَى فَتَحَدَّثَا فَقَالَ أَبُو مُوسَى قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ بَيْنَ يَدَيْ السَّاعَةِ أَيَّامًا يُرْفَعُ فِيهَا الْعِلْمُ وَيَنْزِلُ فِيهَا الْجَهْلُ وَيَكْثُرُ فِيهَا الْهَرْجُ وَالْهَرْجُ الْقَتْلُحَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ قَالَ إِنِّي لَجَالِسٌ مَعَ عَبْدِ اللَّهِ وَأَبِي مُوسَى رَضِيَ اللَّهُ عَنْهُمَا فَقَالَ أَبُو مُوسَى سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ وَالْهَرْجُ بِلِسَانِ الْحَبَشَةِ الْقَتْلُ","id":"Telah menceritakan kepada kami [Umar bin Al Hafsh] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Al A'masy] telah menceritakan kepada kami [Syaqiq] mengatakan, Abdullah dan Abu Musa duduk berbincang-bincang. [Abu Musa] menuturkan; Nabi Shallallahu'alaihiwasallam bersabda; \"Menjelang kiamat terjadi, ada hari-hari yang ketika ilmu diangkat, kebodohan merajalela, banyak alharaj, alharaj adalah pembunuhan.\" Telah menceritakan kepada kami [Qutaibah] Telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Wa`il] mengatakan, Aku duduk bersama 'Abdullah dan Abu Musa radliallahu 'anhuma, lantas [Abu Musa] menuturkan; Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda, seperti hadits diatas, dan alharaj menurut dialek orang Habsyi (Ethiopia) maknanya adalah pembunuhan."},"6206":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ وَاصِلٍ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ وَأَحْسِبُهُ رَفَعَهُ قَالَبَيْنَ يَدَيْ السَّاعَةِ أَيَّامُ الْهَرْجِ يَزُولُ فِيهَا الْعِلْمُ وَيَظْهَرُ فِيهَا الْجَهْلُقَالَ أَبُو مُوسَى وَالْهَرْجُ الْقَتْلُ بِلِسَانِ الْحَبَشَةِ وَقَالَ أَبُو عَوَانَةَ عَنْ عَاصِمٍ عَنْ أَبِي وَائِلٍ عَنْ الْأَشْعَرِيِّ أَنَّهُ قَالَ لِعَبْدِ اللَّهِ تَعْلَمُ الْأَيَّامَ الَّتِي ذَكَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيَّامَ الْهَرْجِ نَحْوَهُ قَالَ ابْنُ مَسْعُودٍ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مِنْ شِرَارِ النَّاسِ مَنْ تُدْرِكْهُمْ السَّاعَةُ وَهُمْ أَحْيَاءٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Washil] dari [Abu Wa`il] dari [Abdullah] dan setahu saya dia memarfukkannya, mengatakan; \"Menjelang kiamat tiba, terdapat hari-hari Alharaj, ketika itu ilmu lenyap, kebodohan merajalela.\" [Abu Musa] mengatakan alharaj maknanya adalah pembunuhan, istilah ini adalah istilah orang Habsyi (Ethiopia). Sedang [Abu 'Awanah] mengatakan, dari ['Ashim] dari [Abu Wail] dari [Al Asy'ari] bahwasanya ia berkata kepada 'Abdullah 'Kamu tahu hari-hari yang disebut Nabi shallallahu 'alaihi wasallam tentang hari-hari al haraj (pembunuhan)? ' semisal hadits diatas. Sedang [Ibnu Mas'ud] mengatakan, aku mendengar Nabi shallallahu 'alaihi wasallam bersabda; \"Manusia yang paling jelek adalah manusia yang mendapati hari kiamat ketika dia masih hidup.\""},"6207":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّبَيْرِ بْنِ عَدِيٍّ قَالَ أَتَيْنَا أَنَسَ بْنَ مَالِكٍفَشَكَوْنَا إِلَيْهِ مَا نَلْقَى مِنْ الْحَجَّاجِ فَقَالَ اصْبِرُوا فَإِنَّهُ لَا يَأْتِي عَلَيْكُمْ زَمَانٌ إِلَّا الَّذِي بَعْدَهُ شَرٌّ مِنْهُ حَتَّى تَلْقَوْا رَبَّكُمْ سَمِعْتُهُ مِنْ نَبِيِّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Zubair bin 'Adi] mengatakan, pernah kami mendatangi [Anas bin Malik], kemudian kami mengutarakan kepadanya keluh kesah kami tentang ulah para jamaah haji. Maka dia menjawab; 'Bersabarlah, sebab tidaklah kalian menjalalni suatu zaman, melainkan sesudahnya lebih buruk daripadanya, sampai kalian menjumpai rabb kalian. Aku mendengar hadit ini dari Nabi kalian Shallallahu'alaihiwasallam.'"},"6208":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ ح و حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنِي أَخِي عَنْ سُلَيْمَانَ بْنِ بِلَالٍ عَنْ مُحَمَّدِ بْنِ أَبِي عَتِيقٍ عَنْ ابْنِ شِهَابٍ عَنْ هِنْدٍ بِنْتِ الْحَارِثِ الْفِرَاسِيَّةِ أَنَّ أُمَّ سَلَمَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْاسْتَيْقَظَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةً فَزِعًا يَقُولُ سُبْحَانَ اللَّهِ مَاذَا أَنْزَلَ اللَّهُ مِنْ الْخَزَائِنِ وَمَاذَا أُنْزِلَ مِنْ الْفِتَنِ مَنْ يُوقِظُ صَوَاحِبَ الْحُجُرَاتِ يُرِيدُ أَزْوَاجَهُ لِكَيْ يُصَلِّينَ رُبَّ كَاسِيَةٍ فِي الدُّنْيَا عَارِيَةٍ فِي الْآخِرَةِ","id":"Telah menceritakan kepada kami [Abul Yaman] Telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] -lewat jalur periwayatan lain- Dan Telah menceritakan kepada kami [Ismail] telah menceritakan kepadaku [Saudaraku] dari [Sulaiman bin Bilal] dari [Muhammad bin Abi 'Utaiq] dari [Ibnu Syihab] dari [Hindun binti Al Harits Al Firasiyyah], bahwasanya [Ummu Salamah isteri Nabi] shallallahu 'alaihi wasallam mengatakan; Suatu malam Rasulullah bangun dengan agak gusar dan mengucapkan: \"Subhanallah, perbendaharaan apa lagi yang Allah turunkan? dan fitnah apa lagi yang Allah turunkan? Siapa yang mau membangunkan penghuni kamar-kamar (maksudnya isterinya) untuk shalat? Betapa banyak orang berpakaian di dunia namun di akherat telanjang.\""},"6209":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ حَمَلَ عَلَيْنَا السِّلَاحَ فَلَيْسَ مِنَّا","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah mengabarkan kepada kami [Malik] dari [Nafi'] dari [Abdullah bin Umar] radliallahu 'anhuma, bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menghunus pedang kepada kami, ia bukan golongan kami.\""},"6210":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَىعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ حَمَلَ عَلَيْنَا السِّلَاحَ فَلَيْسَ مِنَّا","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`] Telah menceritakan kepada kami [Abu Usamah] dari [Buraid] dari [Abu Burdah] dari [Abu Musa] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menghunuskan pedangnya kepada kami, ia bukan golongan kami.\""},"6211":{"ar":"حَدَّثَنَا مُحَمَّدٌ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ هَمَّامٍ سَمِعْتُ أَبَا هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يُشِيرُ أَحَدُكُمْ عَلَى أَخِيهِ بِالسِّلَاحِ فَإِنَّهُ لَا يَدْرِي لَعَلَّ الشَّيْطَانَ يَنْزِعُ فِي يَدِهِ فَيَقَعُ فِي حُفْرَةٍ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Muhammad] Telah mengabarkan kepada kami [Abdurrazaq] dai [Ma'mar] dari [Hammam], aku mendengar [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah salah seorang diantara kalian mengarahkan pedangnya kepada kawannya, sebab siapa tahu setan menariknya dari tangannya lantas ia terjerumus dalam lubang neraka.\""},"6212":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ قُلْتُ لِعَمْرٍو يَا أَبَا مُحَمَّدٍ سَمِعْتَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُمَرَّ رَجُلٌ بِسِهَامٍ فِي الْمَسْجِدِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمْسِكْ بِنِصَالِهَا قَالَ نَعَمْ","id":"Telah menceritakan kepada kami ['Ali bin Abdullah] telah menceritakan kepada kami [Sufyan] mengatakan, aku bertanya kepada [Amru]; hai Abu Muhammad apakah engkau mendengar [Jabir bin Abdullah] mengatakan; 'Ada seorang laki-laki lewat dengan membawa anak panah di masjid, lantas Rasulullah Shallallahu'alaihiwasallam menegur orang itu: \"Tutuplah mata anak panahnya!\" Lantas Amru menjawab; 'Iya, benar.'"},"6213":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ جَابِرٍأَنَّ رَجُلًا مَرَّ فِي الْمَسْجِدِ بِأَسْهُمٍ قَدْ أَبْدَى نُصُولَهَا فَأُمِرَ أَنْ يَأْخُذَ بِنُصُولِهَا لَا يَخْدِشُ مُسْلِمًا","id":"Telah menceritakan kepada kami [Abu Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] dari ['Amru bin Dinar] dari [Jabir], ada seorang laki-laki lewat di masjid dengan anak panah yang nampakkan mata anak panahnya, lantas ia diperintahkan untuk menutup mata panahnya agar tidak melukai kaum muslimin."},"6214":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَىعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا مَرَّ أَحَدُكُمْ فِي مَسْجِدِنَا أَوْ فِي سُوقِنَا وَمَعَهُ نَبْلٌ فَلْيُمْسِكْ عَلَى نِصَالِهَا أَوْ قَالَ فَلْيَقْبِضْ بِكَفِّهِ أَنْ يُصِيبَ أَحَدًا مِنْ الْمُسْلِمِينَ مِنْهَا شَيْءٌ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`] telah menceritakan kepada kami [Abu Usamah] dari [Buraid] dari [Abu Burdah] dari [Abu Musa] dari Nabi shallallahu 'alaihi wasallam bersabda; \"Jika salah seorang diantara kalian melewati masjid kami, atau pasar kami, sedang ia membawa anak panah, hendaklah ia pegang (ia tutup) mata anak panahnya\" -atau ia mengatakan dengan redaksi; hendaklah ia pegang dengan tangannya- sebab dikhawatirkan kaum muslimin terlukai daripadanya.\""},"6215":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنِي أَبِي حَدَّثَنَا الْأَعْمَشُ حَدَّثَنَا شَقِيقٌ قَالَ قَالَ عَبْدُ اللَّهِقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سِبَابُ الْمُسْلِمِ فُسُوقٌ وَقِتَالُهُ كُفْرٌ","id":"Telah menceritakan kepada kami ['Umar bin Hafsh] telah menceritakan kepadaku [Ayahku] Telah menceritakan kepada kami [Al A'masy] Telah menceritakan kepada kami [Syaqiq] mengatakan; [Abdullah] mengatakan, Nabi Shallallahu'alaihiwasallam bersabda; \"Mencela orang muslim adalah kefasikan, dan memeranginya adalah kekufuran.\""},"6216":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا شُعْبَةُ أَخْبَرَنِي وَاقِدُ بْنُ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَ أَنَّهُسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَرْجِعُوا بَعْدِي كُفَّارًا يَضْرِبُ بَعْضُكُمْ رِقَابَ بَعْضٍ","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] Telah menceritakan kepada kami [Syu'bah] Telah mengabarkan kepada kami [Waqid bin Muhammad] dari [ayahnya] dari [Ibnu Umar], bahwasanya ia mendengar Nabi Shallallahu'alaihiwasallam bersabda; \"Janganlah kalian sepeninggalku kembali kepada kekafiran, sebagian kalian memenggal leher sebagian yang lainnya\"."},"6217":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى حَدَّثَنَا قُرَّةُ بْنُ خَالِدٍ حَدَّثَنَا ابْنُ سِيرِينَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ عَنْ أَبِي بَكْرَةَ وَعَنْ رَجُلٍ آخَرَ هُوَ أَفْضَلُ فِي نَفْسِي مِنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ عَنْ أَبِي بَكْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطَبَ النَّاسَ فَقَالَ أَلَا تَدْرُونَ أَيُّ يَوْمٍ هَذَا قَالُوا اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ حَتَّى ظَنَنَّا أَنَّهُ سَيُسَمِّيهِ بِغَيْرِ اسْمِهِ فَقَالَ أَلَيْسَ بِيَوْمِ النَّحْرِ قُلْنَا بَلَى يَا رَسُولَ اللَّهِ قَالَ أَيُّ بَلَدٍ هَذَا أَلَيْسَتْ بِالْبَلْدَةِ الْحَرَامِ قُلْنَا بَلَى يَا رَسُولَ اللَّهِ قَالَ فَإِنَّ دِمَاءَكُمْ وَأَمْوَالَكُمْ وَأَعْرَاضَكُمْ وَأَبْشَارَكُمْ عَلَيْكُمْ حَرَامٌ كَحُرْمَةِ يَوْمِكُمْ هَذَا فِي شَهْرِكُمْ هَذَا فِي بَلَدِكُمْ هَذَا أَلَا هَلْ بَلَّغْتُ قُلْنَا نَعَمْ قَالَ اللَّهُمَّ اشْهَدْ فَلْيُبَلِّغْ الشَّاهِدُ الْغَائِبَ فَإِنَّهُ رُبَّ مُبَلِّغٍ يُبَلِّغُهُ لِمَنْ هُوَ أَوْعَى لَهُ فَكَانَ كَذَلِكَ قَالَ لَا تَرْجِعُوا بَعْدِي كُفَّارًا يَضْرِبُ بَعْضُكُمْ رِقَابَ بَعْضٍ فَلَمَّا كَانَ يَوْمُ حُرِّقَ ابْنُ الْحَضْرَمِيِّ حِينَ حَرَّقَهُ جَارِيَةُ بْنُ قُدَامَةَ قَالَ أَشْرِفُوا عَلَى أَبِي بَكْرَةَ فَقَالُوا هَذَا أَبُو بَكْرَةَ يَرَاكَ قَالَ عَبْدُ الرَّحْمَنِ فَحَدَّثَتْنِي أُمِّي عَنْ أَبِي بَكْرَةَ أَنَّهُ قَالَ لَوْ دَخَلُوا عَلَيَّ مَا بَهَشْتُ بِقَصَبَةٍ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Qurrah bin Khalid] telah menceritakan kepada kami [Ibnu Sirin] dari [Abdurrahman bin Abi Bakrah] dari [Abu Bakrah] dan dari seorang lainnya yang dia lebih utama menurutku daripada Abdurrahman bin Abi Bakrah, dari Abu bakrah, Bahwasanya Rasulullah shallallahu 'alaihi wasallam berpidato di hadapan sahabat dan bertanya: \"Tahukah kalian hari apa ini?\" 'Allah dan Rasul-Nya lebih tahu' Jawab mereka. Kata Abu Bakrah; Hingga kami ketika itu menyangka bahwa Nabi menamakannya dengan nama lain. Kemudian Nabi bertutur: \"Bukankah sekarang hari nahar (korban)?\" Kami menjawab; 'betul Ya Rasulullah!.' Rasulullah bertanya: \"Negeri manakah ini, bukankah negeri haram?\" 'Benar ya Rasulullah' Jawab kami. Rasulullah Shallallahu'alaihiwasallam bersabda: \"Sesungguhnya darah kalian, harta kalian, kehormatan kalian, dan kulit kalian adalah haram sebagaimana kehormatan hari kalian ini, dalam bulan kalian ini, dan negeri kalian ini, bukankah telah kusampaikan?\" 'Betul' Jawab kami. Nabi melanjutkan: \"Ya Allah, saksikanlah, hendaklah yang hadir menyampaikan berita ini kepada yang tidak hadir, berapa banyak orang yang menyampaikan berita kepada orang yang lebih paham.\" Selanjutnya beliau sampaikan pula sabdanya: \"Janganlah kalian menjadi kafir sepeninggalku, sebagian kalian memenggal leher sebagian lainnya.\" Dan dikala Ibnul khadrami dibakar oleh seorang hamba sahaya Ibnu Qudamah, Abdurrahman mengatakan; 'Tolong kalian lihat Abu bakrah dari tempat yang tinggi! ' lantas mereka mengatakan 'Ini Abu Bakrah melihatmu hai hamba sahaya! ' Abdurrahman berkata; 'ibuku menceritakan kepadaku dari Abu Bakrah, bahwasanya ia mengatakan; 'Kalaulah mereka menemuiku, aku pun tidak akan menohok mereka dengan tongkatku ini.'"},"6218":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ إِشْكَابٍ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ أَبِيهِ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَرْتَدُّوا بَعْدِي كُفَّارًا يَضْرِبُ بَعْضُكُمْ رِقَابَ بَعْضٍ","id":"Telah menceritakan kepada kami [Ahmad bin Isykab] telah menceritakan kepada kami [Muhammad bin Fudhail] dari [ayahnya] dari [Ikrimah] dari [Ibnu 'Abbas] radliallahu 'anhuma, ia mengatakan; Nabi Shallallahu'alaihiwasallam bersabda; \"Jangan kalian murtad sepeninggalku, sebagian kalian memenggal leher sebagian yang lainnya.\""},"6219":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ عَلِيِّ بْنِ مُدْرِكٍ سَمِعْتُ أَبَا زُرْعَةَ بْنَ عَمْرِو بْنِ جَرِيرٍ عَنْ جَدِّهِ جَرِيرٍ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ اسْتَنْصِتْ النَّاسَ ثُمَّ قَالَ لَا تَرْجِعُوا بَعْدِي كُفَّارًا يَضْرِبُ بَعْضُكُمْ رِقَابَ بَعْضٍ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Syu'bah] dari ['Ali bin Mudrik] aku mendengar [Abu Zur'ah bin 'Amru bin Jarir] dari [kakeknya, Jarir] mengatakan, Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku pada haji wada': \"suruhlah orang-orang diam, \" kemudian beliau bersabda: \"Janganlah kalian sepeninggalku menjadi kafir, sebagian kalian memenggal leher sebagian yang lainnya.\""},"6220":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدِ اللَّهِ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ أَبِيهِ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ ح قَالَ إِبْرَاهِيمُ وَحَدَّثَنِي صَالِحُ بْنُ كَيْسَانَ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَتَكُونُ فِتَنٌ الْقَاعِدُ فِيهَا خَيْرٌ مِنْ الْقَائِمِ وَالْقَائِمُ فِيهَا خَيْرٌ مِنْ الْمَاشِي وَالْمَاشِي فِيهَا خَيْرٌ مِنْ السَّاعِي مَنْ تَشَرَّفَ لَهَا تَسْتَشْرِفْهُ فَمَنْ وَجَدَ مِنْهَا مَلْجَأً أَوْ مَعَاذًا فَلْيَعُذْ بِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Ubaidullah] telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [ayahnya] dari [Abu Salamah bin Abdurrahman] dari [Abu Hurairah] -lewat jalur periwayatan lain- [Ibrahim] mengatakan, dan telah menceritakan kepada kami [Shalih bin Kisan] dari [Ibnu Syihab] dari [Sa'id bin Musayyab] dari [Abu Hurairah] menuturkan; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan terjadi fitnah, ketika itu yang duduk lebih baik daripada yang berdiri, yang berdiri lebih baik daripada yang berjalan, yang berjalan lebih baik daripada yang berlari, barangsiapa berusaha menghadapi fitnah itu, justru fitnah itu akan mempengaruhinya, maka barangsiapa mendapat tempat berlindung atau base camp pertahanan, hendaklah ia berlindung diri di tempat itu.\""},"6221":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ أَخْبَرَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ أَبَا هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَتَكُونُ فِتَنٌ الْقَاعِدُ فِيهَا خَيْرٌ مِنْ الْقَائِمِ وَالْقَائِمُ خَيْرٌ مِنْ الْمَاشِي وَالْمَاشِي فِيهَا خَيْرٌ مِنْ السَّاعِي مَنْ تَشَرَّفَ لَهَا تَسْتَشْرِفْهُ فَمَنْ وَجَدَ مَلْجَأً أَوْ مَعَاذًا فَلْيَعُذْ بِهِ","id":"Telah menceritakan kepada kami [Abul Yaman] Telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] telah mengabarkan kepadaku [Abu Salamah bin Abdurrahman], bahwasanya [Abu Hurairah] mengatakan, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan terjadi fitnah, orang yang duduk pada saat itu lebih baik daripada orang yang berdiri, orang yang berdiri lebih baik daripada orang yang berjalan, orang yang berjalan lebih daripada yang berlari, barangsiapa berusaha menghadapi fitnah itu, justru fitnah itu akan mempengaruhinya, maka barangsiapa mendapat tempat berlindung atau base camp pertahanan, hendaklah ia berlindung diri di tempat itu.\""},"6222":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الْوَهَّابِ حَدَّثَنَا حَمَّادٌ عَنْ رَجُلٍ لَمْ يُسَمِّهِ عَنْ الْحَسَنِ قَالَ خَرَجْتُ بِسِلَاحِي لَيَالِيَ الْفِتْنَةِ فَاسْتَقْبَلَنِي أَبُو بَكْرَةَ فَقَالَأَيْنَ تُرِيدُ قُلْتُ أُرِيدُ نُصْرَةَ ابْنِ عَمِّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا تَوَاجَهَ الْمُسْلِمَانِ بِسَيْفَيْهِمَا فَكِلَاهُمَا مِنْ أَهْلِ النَّارِ قِيلَ فَهَذَا الْقَاتِلُ فَمَا بَالُ الْمَقْتُولِ قَالَ إِنَّهُ أَرَادَ قَتْلَ صَاحِبِهِقَالَ حَمَّادُ بْنُ زَيْدٍ فَذَكَرْتُ هَذَا الْحَدِيثَ لِأَيُّوبَ وَيُونُسَ بْنِ عُبَيْدٍ وَأَنَا أُرِيدُ أَنْ يُحَدِّثَانِي بِهِ فَقَالَا إِنَّمَا رَوَى هَذَا الحَدِيثَ الْحَسَنُ عَنْ الْأَحْنَفِ بْنِ قَيْسٍ عَنْ أَبِي بَكْرَةَ حَدَّثَنَا سُلَيْمَانُ حَدَّثَنَا حَمَّادٌ بِهَذَا وَقَالَ مُؤَمَّلٌ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا أَيُّوبُ وَيُونُسُ وَهِشَامٌ وَمُعَلَّى بْنُ زِيَادٍ عَنْ الْحَسَنِ عَنْ الْأَحْنَفِ عَنْ أَبِي بَكْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَوَاهُ مَعْمَرٌ عَنْ أَيُّوبَ وَرَوَاهُ بَكَّارُ بْنُ عَبْدِ الْعَزِيزِ عَنْ أَبِيهِ عَنْ أَبِي بَكْرَةَ وَقَالَ غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ أَبِي بَكْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يَرْفَعْهُ سُفْيَانُ عَنْ مَنْصُورٍ","id":"Telah menceritakan kepada kami ['Abdullah bin Abdul Wahhab], telah menceritakan kepada kami [Hammad] dari [seseorang yang tidak dia sebutkan namanya] dari [Al Hasan] mengatakan, Aku keluar dengan membawa senjataku di malam-malam terjadi fitnah, maka [Abu Bakrah] menemuiku dengan bertanya; 'mau kemana kamu? ' aku menjawab; 'Aku ingin menolong keponakan Rasulullah Shallallahu'alaihiwasallam' (maksudnya 'Ali). Abu Bakrah berkata, Rasulullah Shallallahu'alaihiwasallam bersabda; \"Jika dua muslim berhadap-hadapan dengan kedua pedangnya, maka keduanya sama-sama masuk neraka.\" Maka ada yang bertanya; 'kalau yang membunuh sudah maklum, lantas apa dosa yang dibunuh? ' Nabi shallallahu 'alaihi wasallam menjawab: \"Ia juga berkehendak membunuh saudaranya.\" [Hammad bin Zaid] berkata; maka hadits ini kusampaikan kepada [Ayyub] dan [Yunus bin Ubaid], dan aku ingin keduanya menceritakan kepadaku (jalur periwayatan) hadits ini, maka keduanya mengatakan; 'Hadits ini diriwayatkan oleh [Al Hasan] dari [Ahnaf bin Qais] dari [Abu Bakrah]. Telah menceritakan kepada kami [Sulaiman] telah menceritakan kepada kami [Hammad] tentang hal itu. [Mu'ammal] berkata; telah menceritakan kepada kami [Hammad bin Zaid] telah menceritakan kepada kami [Ayyub], [Yunus bin Ubaid], [Hisyam] dan [Mu'ala bin Zaid] dari [Al Hasan] dari [Ahnaf] dari [Abu Bakrah] dari Nabi shallallahu 'alaihi wasallam, dan diriwayatkan oleh [Ma'mar] dari [Ayyub], dan diriwayatkan oleh [Bakkar bin Abdul aziz] dari [ayahnya] dari [Abu Bakrah] dan [Ghundar] mengatakan; telah menceritakan kepada kami [Syu'bah] dari [Manshur] dari [Rib'i bin Hirasy] dari [Abu Bakrah] dari Nabi shallallahu 'alaihi wasallam, dan [Sufyan] tidak memarfu'kannya dari [Manshur]."},"6223":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا ابْنُ جَابِرٍ حَدَّثَنِي بُسْرُ بْنُ عُبَيْدِ اللَّهِ الْحَضْرَمِيُّ أَنَّهُ سَمِعَ أَبَا إِدْرِيسَ الْخَوْلَانِيَّ أَنَّهُ سَمِعَ حُذَيْفَةَ بْنَ الْيَمَانِ يَقُولُكَانَ النَّاسُ يَسْأَلُونَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْخَيْرِ وَكُنْتُ أَسْأَلُهُ عَنْ الشَّرِّ مَخَافَةَ أَنْ يُدْرِكَنِي فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّا كُنَّا فِي جَاهِلِيَّةٍ وَشَرٍّ فَجَاءَنَا اللَّهُ بِهَذَا الْخَيْرِ فَهَلْ بَعْدَ هَذَا الْخَيْرِ مِنْ شَرٍّ قَالَ نَعَمْ قُلْتُ وَهَلْ بَعْدَ ذَلِكَ الشَّرِّ مِنْ خَيْرٍ قَالَ نَعَمْ وَفِيهِ دَخَنٌ قُلْتُ وَمَا دَخَنُهُ قَالَ قَوْمٌ يَهْدُونَ بِغَيْرِ هَدْيِي تَعْرِفُ مِنْهُمْ وَتُنْكِرُ قُلْتُ فَهَلْ بَعْدَ ذَلِكَ الْخَيْرِ مِنْ شَرٍّ قَالَ نَعَمْ دُعَاةٌ عَلَى أَبْوَابِ جَهَنَّمَ مَنْ أَجَابَهُمْ إِلَيْهَا قَذَفُوهُ فِيهَا قُلْتُ يَا رَسُولَ اللَّهِ صِفْهُمْ لَنَا قَالَ هُمْ مِنْ جِلْدَتِنَا وَيَتَكَلَّمُونَ بِأَلْسِنَتِنَا قُلْتُ فَمَا تَأْمُرُنِي إِنْ أَدْرَكَنِي ذَلِكَ قَالَ تَلْزَمُ جَمَاعَةَ الْمُسْلِمِينَ وَإِمَامَهُمْ قُلْتُ فَإِنْ لَمْ يَكُنْ لَهُمْ جَمَاعَةٌ وَلَا إِمَامٌ قَالَ فَاعْتَزِلْ تِلْكَ الْفِرَقَ كُلَّهَا وَلَوْ أَنْ تَعَضَّ بِأَصْلِ شَجَرَةٍ حَتَّى يُدْرِكَكَ الْمَوْتُ وَأَنْتَ عَلَى ذَلِكَ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Ibnu Jabir] telah menceritakan kepadaku [Busr bin Ubaidullah Al Khadrami], ia mendengar [Abu Idris alkhaulani], ia mendengar [Khudzaifah Ibnul yaman] mengatakan; Orang-orang bertanya Rasulullah Shallallahu'alaihiwasallam tentang kebaikan sedang aku bertanya beliau tentang keburukan karena khawatir jangan-jangan aku terkena keburukan itu sendiri. Maka aku bertanya 'Hai Rasulullah, dahulu kami dalam kejahiliyahan dan keburukan, lantas Allah membawa kebaikan ini, maka apakah setelah kebaikan ini ada keburukan lagi? Nabi menjawab 'Tentu'. Saya bertanya 'Apakah sesudah keburukan itu ada kebaikan lagi? 'Tentu' Jawab beliau, dan ketika itu ada kotoran, kekurangan dan perselisihan. Saya bertanya 'Apa yang anda maksud kotoran, kekurangan dan perselisihan itu? Nabi menjawab 'Yaitu sebuah kaum yang menanamkan pedoman bukan dengan pedomanku, engkau kenal mereka namun pada saat yang sama engkau juga mengingkarinya. Saya bertanya 'Adakah steelah kebaikan itu ada keburukan? Nabi menjawab 'O iya,,,,, ketika itu ada penyeru-penyeru menuju pintu jahannam, siapa yang memenuhi seruan mereka, mereka akan menghempaskan orang itu ke pintu-pintu itu. Aku bertanya 'Ya Rasulullah, tolong beritahukanlah kami tentang ciri-ciri mereka! Nabi menjawab; Mereka adalah seperti kulit kita ini, juga berbicara dengan bahasa kita. Saya bertanya 'Lantas apa yang anda perintahkan kepada kami ketika kami menemui hari-hari seperti itu? Nabi menjawab; Hendaklah kamu selalu bersama jamaah muslimin dan imam mereka! Aku bertanya; kalau tidak ada jamaah muslimin dan imam bagaimana? Nabi menjawab; hendaklah kau jauhi seluruh firqah (kelompok-kelompok) itu, sekalipun kau gigit akar-akar pohon hingga kematian merenggutmu kamu harus tetap seperti itu."},"6224":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا حَيْوَةُ وَغَيْرُهُ قَالَ حَدَّثَنَا أَبُو الْأَسْوَدِ وَقَالَ اللَّيْثُ عَنْ أَبِي الْأَسْوَدِ قَالَقُطِعَ عَلَى أَهْلِ الْمَدِينَةِ بَعْثٌ فَاكْتُتِبْتُ فِيهِ فَلَقِيتُ عِكْرِمَةَ فَأَخْبَرْتُهُ فَنَهَانِي أَشَدَّ النَّهْيِ ثُمَّ قَالَ أَخْبَرَنِي ابْنُ عَبَّاسٍ أَنَّ أُنَاسًا مِنْ الْمُسْلِمِينَ كَانُوا مَعَ الْمُشْرِكِينَ يُكَثِّرُونَ سَوَادَ الْمُشْرِكِينَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَأْتِي السَّهْمُ فَيُرْمَى فَيُصِيبُ أَحَدَهُمْ فَيَقْتُلُهُ أَوْ يَضْرِبُهُ فَيَقْتُلُهُ فَأَنْزَلَ اللَّهُ تَعَالَى{ إِنَّ الَّذِينَ تَوَفَّاهُمْ الْمَلَائِكَةُ ظَالِمِي أَنْفُسِهِمْ }","id":"Telah menceritakan kepada kami ['Abdullah bin Yazid] telah menceritakan kepada kami [Haiwa] dan lainnya mengatakan, telah menceritakan kepada kami [Abul Aswad] dan [Al Laits] mengatakan dari [Abul aswad] mengatakan 'Ada sekelompok tentara dibentuk untuk menyerang penduduk Madinah (muslimin) dan namaku diikutsertakan dalam daftar. Selanjutnya aku bertemu ['Ikrimah] dan kuutarakan nasibku, lantas dia melarangku secara serius kemudian mengatakan, [Ibnu Abbas] mengabariku bahwa beberapa orang muslimin ikut serta pasukan musyrik sekedar untuk menambah jumlah pasukan demi melawan Rasulullah Shallallahu'alaihiwasallam, lantas sebagain mereka terkena anak panah sehingga meninggal, dan sebagian mereka terkena luka senjata sehingga tewas, maka Allah menurunkan ayat sebagai jawaban nasib mereka; Sesungguhnya orang-orang yang diwafatkan Allah dalam keadaan menganiaya diri mereka sendiri, \" dan seterusnya sampai akhir ayat QS.Annisa 97."},"6225":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ حَدَّثَنَا الْأَعْمَشُ عَنْ زَيْدِ بْنِ وَهْبٍ حَدَّثَنَا حُذَيْفَةُ قَالَحَدَّثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدِيثَيْنِ رَأَيْتُ أَحَدَهُمَا وَأَنَا أَنْتَظِرُ الْآخَرَ حَدَّثَنَا أَنَّ الْأَمَانَةَ نَزَلَتْ فِي جَذْرِ قُلُوبِ الرِّجَالِ ثُمَّ عَلِمُوا مِنْ الْقُرْآنِ ثُمَّ عَلِمُوا مِنْ السُّنَّةِ وَحَدَّثَنَا عَنْ رَفْعِهَا قَالَ يَنَامُ الرَّجُلُ النَّوْمَةَ فَتُقْبَضُ الْأَمَانَةُ مِنْ قَلْبِهِ فَيَظَلُّ أَثَرُهَا مِثْلَ أَثَرِ الْوَكْتِ ثُمَّ يَنَامُ النَّوْمَةَ فَتُقْبَضُ فَيَبْقَى فِيهَا أَثَرُهَا مِثْلَ أَثَرِ الْمَجْلِ كَجَمْرٍ دَحْرَجْتَهُ عَلَى رِجْلِكَ فَنَفِطَ فَتَرَاهُ مُنْتَبِرًا وَلَيْسَ فِيهِ شَيْءٌ وَيُصْبِحُ النَّاسُ يَتَبَايَعُونَ فَلَا يَكَادُ أَحَدٌ يُؤَدِّي الْأَمَانَةَ فَيُقَالُ إِنَّ فِي بَنِي فُلَانٍ رَجُلًا أَمِينًا وَيُقَالُ لِلرَّجُلِ مَا أَعْقَلَهُ وَمَا أَظْرَفَهُ وَمَا أَجْلَدَهُ وَمَا فِي قَلْبِهِ مِثْقَالُ حَبَّةِ خَرْدَلٍ مِنْ إِيمَانٍ وَلَقَدْ أَتَى عَلَيَّ زَمَانٌ وَلَا أُبَالِي أَيُّكُمْ بَايَعْتُ لَئِنْ كَانَ مُسْلِمًا رَدَّهُ عَلَيَّ الْإِسْلَامُ وَإِنْ كَانَ نَصْرَانِيًّا رَدَّهُ عَلَيَّ سَاعِيهِ وَأَمَّا الْيَوْمَ فَمَا كُنْتُ أُبَايِعُ إِلَّا فُلَانًا وَفُلَانًا","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] Telah mengabarkan kepada kami [Sufyan] telah menceritakan kepada kami [Al A'masy] dari [Zaid bin Wahb] telah menceritakan kepada kami [Khudzaifah] mengatakan, telah menceritakan kepada kami Rasulullah Shallallahu'alaihiwasallam dua Hadits, satunya sudah saya lihat sendiri dan satunya aku sedang menunggu-nunggu, beliau menceritakan kepada kami: \"bahwa Amanat mula-mula turun pada relung hati orang-orang, lantas mereka paham terhadap alquran dan paham terhadap sunnah.\" Khudzaifah menceritakan kepada kami kemarfu'annya, Nabi bersabda; \"seseorang tertidur nyenyak kemudian amanat dicerabut dari hatinya, dan masih ada bekasnya seperti bekas yang kecil, kemudian dia tidur lagi dan amanat dicerabut darinya sehingga bekasnya seperti kutu di tangan, sepeti bara yang kau gelindingkan di kakimu sehingga ia memar (beram-beram), maka engkau melihatnya beram-beram (memar) padahal sebenarnya tidak terjadi apa-apa, dan manusia secara beruntun melakukan baiat dan nyaris tak seorang pun menunaikan amanat dengan baik, dan ada berita bahwa di bani fulan ada seseorang yang dapat di percaya, kemudian dikatakan kepada tersebut; 'alangkah cerdasnya dia, alangkah bijaknya dia, alangkah pemberaninya dia, ' padahal tidak ada seberat biji gandum pun iman di dalam hatinya, pernah datang suatu masa kepadaku yang ketika itu aku tak peduli siapa diantara kalian yang aku baiat, kalaulah ia muslim, maka keIslamannya akan mengembalikannya kepadaku, dan kalaulah nasrani, penarik pajaknya akan mengembalikannya kepadaku, namun hari ini aku tidak membaiat selain fulan dan fulan.\""},"6226":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا حَاتِمٌ عَنْ يَزِيدَ بْنِ أَبِي عُبَيْدٍ عَنْ سَلَمَةَ بْنِ الْأَكْوَعِأَنَّهُ دَخَلَ عَلَى الْحَجَّاجِ فَقَالَ يَا ابْنَ الْأَكْوَعِ ارْتَدَدْتَ عَلَى عَقِبَيْكَ تَعَرَّبْتَ قَالَ لَا وَلَكِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَذِنَ لِي فِي الْبَدْوِوَعَنْ يَزِيدَ بْنِ أَبِي عُبَيْدٍ قَالَ لَمَّا قُتِلَ عُثْمَانُ بْنُ عَفَّانَ خَرَجَ سَلَمَةُ بْنُ الْأَكْوَعِ إِلَى الرَّبَذَةِ وَتَزَوَّجَ هُنَاكَ امْرَأَةً وَوَلَدَتْ لَهُ أَوْلَادًا فَلَمْ يَزَلْ بِهَا حَتَّى قَبْلَ أَنْ يَمُوتَ بِلَيَالٍ فَنَزَلَ الْمَدِينَةَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] Telah menceritakan kepada kami [Hatim] dari [Yazid bin Abi Ubaid] dari [Salamah bin Al Akwa'] bahwasanya ia menemui Al Hajjaj, maka Al Hajjaj berujar; 'Hai Ibnul akwa', apakah engkau berbalik ke belakang dengan cara pindah ke pelosok pedesaan? ' Ibnul akwa' menjawab; 'tidak, namun Rasulullah Shallallahu'alaihiwasallam telah memberiku izin (untuk tinggal) di pelosok pedesaan.\" Dan dari [Yazid bin Abi Ubaid] mengatakan, tatkala Utsman bin Affan terbunuh, Salamah bin Al Akwa' pergi mengucilkan diri ke Rabdzah dan menikahi wanita disana sampai melahirkan beberapa anak, dan dia terus bermukim di sana sampai beberapa malam sebelum meninggalnya, kemudian tinggal di Madinah."},"6227":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي صَعْصَعَةَ عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُ أَنَّهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوشِكُ أَنْ يَكُونَ خَيْرَ مَالِ الْمُسْلِمِ غَنَمٌ يَتْبَعُ بِهَا شَعَفَ الْجِبَالِ وَمَوَاقِعَ الْقَطْرِ يَفِرُّ بِدِينِهِ مِنْ الْفِتَنِ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah mengabarkan kepada kami [Malik] dari [Abdurrahman bin Abdullah bin Abi Sha'Sha'ah] dari [ayahnya] dari [Abu Sa'id Al Khudzri] radliallahu 'anhu, bahwasanya ia menuturkan, Rasulullah shallallahu 'alaihi wasallam bersabda: \"tak lama lagi sebaik-baik harta seorang muslim adalah kambing yang ia gembalakan di lereng-lereng gunung dan tempat-tempat hujan turun, ia lari untuk menyelamatkan agamanya dari gelombang fitnah.\""},"6228":{"ar":"حَدَّثَنَا مُعَاذُ بْنُ فَضَالَةَ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَسَأَلُوا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى أَحْفَوْهُ بِالْمَسْأَلَةِ فَصَعِدَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ يَوْمٍ الْمِنْبَرَ فَقَالَ لَا تَسْأَلُونِي عَنْ شَيْءٍ إِلَّا بَيَّنْتُ لَكُمْ فَجَعَلْتُ أَنْظُرُ يَمِينًا وَشِمَالًا فَإِذَا كُلُّ رَجُلٍ لَافٌّ رَأْسَهُ فِي ثَوْبِهِ يَبْكِي فَأَنْشَأَ رَجُلٌ كَانَ إِذَا لَاحَى يُدْعَى إِلَى غَيْرِ أَبِيهِ فَقَالَ يَا نَبِيَّ اللَّهِ مَنْ أَبِي فَقَالَ أَبُوكَ حُذَافَةُ ثُمَّ أَنْشَأَ عُمَرُ فَقَالَ رَضِينَا بِاللَّهِ رَبًّا وَبِالْإِسْلَامِ دِينًا وَبِمُحَمَّدٍ رَسُولًا نَعُوذُ بِاللَّهِ مِنْ سُوءِ الْفِتَنِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا رَأَيْتُ فِي الْخَيْرِ وَالشَّرِّ كَالْيَوْمِ قَطُّ إِنَّهُ صُوِّرَتْ لِي الْجَنَّةُ وَالنَّارُ حَتَّى رَأَيْتُهُمَا دُونَ الْحَائِطِ فَكَانَ قَتَادَةُ يَذْكُرُ هَذَا الْحَدِيثَ عِنْدَ هَذِهِ الْآيَةِ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَسْأَلُوا عَنْ أَشْيَاءَ إِنْ تُبْدَ لَكُمْ تَسُؤْكُمْ }وَقَالَ عَبَّاسٌ النَّرْسِيُّ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا سَعِيدٌ حَدَّثَنَا قَتَادَةُ أَنَّ أَنَسًا حَدَّثَهُمْ أَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا وَقَالَ كُلُّ رَجُلٍ لَافًّا رَأْسَهُ فِي ثَوْبِهِ يَبْكِي وَقَالَ عَائِذًا بِاللَّهِ مِنْ سُوءِ الْفِتَنِ أَوْ قَالَ أَعُوذُ بِاللَّهِ مِنْ سَوْأَى الْفِتَنِ و قَالَ لِي خَلِيفَةُ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا سَعِيدٌ وَمُعْتَمِرٌ عَنْ أَبِيهِ عَنْ قَتَادَةَ أَنَّ أَنَسًا حَدَّثَهُمْ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا وَقَالَ عَائِذًا بِاللَّهِ مِنْ شَرِّ الْفِتَنِ","id":"Telah menceritakan kepada kami [Mu'adz bin Fadhalah] telah menceritakan kepada kami [Hisyam] dari [Qotadah] dari [Anas] radliallahu 'anhu mengatakan, para sahabat banyak bertanya kepada Nabi shallallahu 'alaihi wasallam sehingga mereka setengah memaksa dengan pertanyaan-pertanyaan. Maka Nabi shallallahu 'alaihi wasallam suatu hari naik ke mimbar dan bersabda: \"Tidaklah kalian bertanya kepadaku mengenai sesuatu, selain kujelaskan kepada kalian, \" lantas aku melihat ke kanan-kiri, tak tahunya setiap orang membungkus kepalanya di pakaiannya sambil menangis, muncullah seseorang yang jika berdebat dia dipanggil dengan nasab selain ayahnya, orang itu berujar; 'Wahai Nabiyullah siapakah ayahku? ' Nabi menjawab: \"ayahmu adalah Hudzafah.\" Kontan Umar bergegas mengucapkan; 'RADHIINA BILLAHI RABBAN WABIL ISLAAMI DIINAN WABI MUHAMMADIN RASUULAN NA'UUDZU BILLAH MIN SUUIL FITANI (Kami ridha Allah sebagai rabb, Islam sebagai agama, dan Muhammad sebagai utusan, kami berlindung kepada Allah dari keburukan fitnah), \" Nabi shallallahu 'alaihi wasallam bersabda; \"Sama sekali belum pernah kulihat keburukan dan kebaikan seperti hari ini, sebab hari ini surga dan neraka digambarkan kepadaku sehingga aku melihat kedua-duanya dibalik dinding ini.\" Dan Qatadah selalu menyebutkan hadits ini berkaitan dengan ayat: 'Wahai orang-orang yang beriman, janganlah kalian bertanya tentang sesuatu yang sekiranya diungkapkan kepada kalian, justru malah menyusahkan kalian (QS. Almaidah; 101). [Abbas An Narsi] mengatakan, Telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Sa'id] telah menceritakan kepada kami [Qotadah], bahwasanya [Anas] menceritakan kepada mereka; bahwa Nabiyullah Shallallahu'alaihiwasallam besabda masalah ini dengan redaksi: Setiap orang membungkus kepalanya dalam bajunya sambil menangis, dan ia mengatakan dengan redaksi: 'aaidzan billah min suu'il fitan (aku berlindung kepada Allah dari keburukan fitnah) atau ia mengatakan; 'a'uudzu billah min sau`atil fitan (Saya berlindung kepada Allah dari keburukan-keburukan fitnah). Sedang [Khalifah] mengatakan kepadaku Telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Sa'id] dan [Mu'tamir] dari [ayahnya] dari [Qotadah], bahwasanya [Anas] menceritakan kepada mereka, dari Nabi shallallahu 'alaihi wasallam dengan Hadits ini dan dia mengatakan dengan redaksi; 'aaidzan billah min syarril fitan (berlindung kepada Allah dari keburukan fitnah)."},"6229":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا هِشَامُ بْنُ يُوسُفَ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَامَ إِلَى جَنْبِ الْمِنْبَرِ فَقَالَ الْفِتْنَةُ هَا هُنَا الْفِتْنَةُ هَا هُنَا مِنْ حَيْثُ يَطْلُعُ قَرْنُ الشَّيْطَانِ أَوْ قَالَ قَرْنُ الشَّمْسِ","id":"telah menceritakan kepadaku [Abdullah bin Muhammad] telah menceritakan kepada kami [Hisyam bin Yusuf] dari [Ma'mar] dari [Az Zuhri] dari [Salim] dari [ayahnya] dari Nabi shallallahu 'alaihi wasallam, bahwasanya beliau berdiri ke samping minbar dan bersabda: \"Fitnah muncul disini, fitnah muncul disini, (yaitu) dimana tempat tanduk setan muncul, \" atau beliau mengatakan: \"tanduk matahari.\""},"6230":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ مُسْتَقْبِلٌ الْمَشْرِقَ يَقُولُ أَلَا إِنَّ الْفِتْنَةَ هَا هُنَا مِنْ حَيْثُ يَطْلُعُ قَرْنُ الشَّيْطَانِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits] dari [Nafi'] dari [Ibnu 'Umar] radliallahu 'anhuma, ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda yang ketika itu beliau menghadap timur: \"Ketahuilah, bahawasanya fitnah muncul dari sini, yaitu tempat tanduk setan muncul.\""},"6231":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَزْهَرُ بْنُ سَعْدٍ عَنْ ابْنِ عَوْنٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَذَكَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ بَارِكْ لَنَا فِي شَأْمِنَا اللَّهُمَّ بَارِكْ لَنَا فِي يَمَنِنَا قَالُوا يَا رَسُولَ اللَّهِ وَفِي نَجْدِنَا قَالَ اللَّهُمَّ بَارِكْ لَنَا فِي شَأْمِنَا اللَّهُمَّ بَارِكْ لَنَا فِي يَمَنِنَا قَالُوا يَا رَسُولَ اللَّهِ وَفِي نَجْدِنَا فَأَظُنُّهُ قَالَ فِي الثَّالِثَةِ هُنَاكَ الزَّلَازِلُ وَالْفِتَنُ وَبِهَا يَطْلُعُ قَرْنُ الشَّيْطَانِ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Azhar bin Sa'd] dari [Ibnu 'Aun] dari [Nafi'] dari [Ibnu Umar] mengatakan, Nabi shallallahu 'alaihi wasallam pernah memanjatkan doa; \"Ya Allah, berilah kami barakah dalam Syam kami, ya Allah, berilah kami barakah dalam Yaman kami.\" Para sahabat berkata; 'ya Rasulullah, dan juga dalam Nejed kami! ' Rasulullah Shallallahu'alaihiwasallam membaca doa: \"Ya Allah, berilah kami barakah dalam Syam kami, ya Allah, berilah kami barakah dalam Yaman kami.\" Para sahabat berkata; 'Ya Rasulullah, juga dalam Nejed kami! ' dan seingatku, pada kali ketiga, beliau bersabda; \"Disanalah muncul keguncangan dan fitnah, dan disanalah tanduk setan muncul.\""},"6232":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ شَاهِينَ الْوَاسِطِيُّ حَدَّثَنَا خَالِدٌ عَنْ بَيَانٍ عَنْ وَبَرَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ خَرَجَ عَلَيْنَا عَبْدُ اللَّهِ بْنُ عُمَرَفَرَجَوْنَا أَنْ يُحَدِّثَنَا حَدِيثًا حَسَنًا قَالَ فَبَادَرَنَا إِلَيْهِ رَجُلٌ فَقَالَ يَا أَبَا عَبْدِ الرَّحْمَنِ حَدِّثْنَا عَنْ الْقِتَالِ فِي الْفِتْنَةِ وَاللَّهُ يَقُولُ{ وَقَاتِلُوهُمْ حَتَّى لَا تَكُونَ فِتْنَةٌ }فَقَالَ هَلْ تَدْرِي مَا الْفِتْنَةُ ثَكِلَتْكَ أُمُّكَ إِنَّمَا كَانَ مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقَاتِلُ الْمُشْرِكِينَ وَكَانَ الدُّخُولُ فِي دِينِهِمْ فِتْنَةً وَلَيْسَ كَقِتَالِكُمْ عَلَى الْمُلْكِ","id":"Telah menceritakan kepada kami [Ishaq bin Syahin Al Wasithi] telah menceritakan kepada kami [Khalid] dari [Bayan] dari [Wabarah bin Abdurrahman] dari [Sa'id bin Jubair] mengatakan, [Abdullah bin Umar] menemui kami, kami sangat berharap agar ia menceritakan kepada kami sebuah pembicaraan yang baik. Tiba-tiba ada seorang laki-laki yang mendahului kami menemuinya dan berujar; 'ya Abu Abdurrahman, ceritakanlah kepada kami sebuah cerita tentang peperangan dalam fitnah yang telah Allah firmankan: 'Dan perangilah mereka hingga tak ada lagi fitnah di muka bumi' (QS. Albaqarah; 193). Maka Abdullah bin Umar bertanya; 'Apakah kamu tahu apa fitnah itu, duhai malangnya ibumu kehilangan dirimu, Dahulu Muhammad Shallallahu'alaihiwasallam memerangi orang-orang musyrik dan siapa saja yang memasuki agama mereka (pindah agama) itulah yang dimaksud fitnah, dan fitnah maksudnya bukanlah peperangan kalian terhadap para raja (penguasa)."},"6233":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ حَدَّثَنَا شَقِيقٌ سَمِعْتُ حُذَيْفَةَ يَقُولُبَيْنَا نَحْنُ جُلُوسٌ عِنْدَ عُمَرَ إِذْ قَالَ أَيُّكُمْ يَحْفَظُ قَوْلَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْفِتْنَةِ قَالَ فِتْنَةُ الرَّجُلِ فِي أَهْلِهِ وَمَالِهِ وَوَلَدِهِ وَجَارِهِ تُكَفِّرُهَا الصَّلَاةُ وَالصَّدَقَةُ وَالْأَمْرُ بِالْمَعْرُوفِ وَالنَّهْيُ عَنْ الْمُنْكَرِ قَالَ لَيْسَ عَنْ هَذَا أَسْأَلُكَ وَلَكِنْ الَّتِي تَمُوجُ كَمَوْجِ الْبَحْرِ قَالَ لَيْسَ عَلَيْكَ مِنْهَا بَأْسٌ يَا أَمِيرَ الْمُؤْمِنِينَ إِنَّ بَيْنَكَ وَبَيْنَهَا بَابًا مُغْلَقًا قَالَ عُمَرُ أَيُكْسَرُ الْبَابُ أَمْ يُفْتَحُ قَالَ بَلْ يُكْسَرُ قَالَ عُمَرُ إِذًا لَا يُغْلَقَ أَبَدًا قُلْتُ أَجَلْ قُلْنَا لِحُذَيْفَةَ أَكَانَ عُمَرُ يَعْلَمُ الْبَابَ قَالَ نَعَمْ كَمَا يَعْلَمُ أَنَّ دُونَ غَدٍ لَيْلَةً وَذَلِكَ أَنِّي حَدَّثْتُهُ حَدِيثًا لَيْسَ بِالْأَغَالِيطِ فَهِبْنَا أَنْ نَسْأَلَهُ مَنْ الْبَابُ فَأَمَرْنَا مَسْرُوقًا فَسَأَلَهُ فَقَالَ مَنْ الْبَابُ قَالَ عُمَرُ","id":"Telah menceritakan kepada kami [Umar bin Hafsh bin Ghiyats] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Al A'masy] telah menceritakan kepada kami [Syaqiq] Aku mendengar [Khudzaifah] menuturkan; ketika kami duduk-duduk bersama Umar, tiba-tiba ia bertanya; 'Siapa diantara kalian yang menghapal sabda Nabi shallallahu 'alaihi wasallam tentang fitnah? ' maka Khudzaifah menjawab; 'Fitnah seseorang di keluarganya, hartanya dan anaknya serta tetangganya bisa terhapus oleh shalat, sedekah, dan amar ma'ruf nahyi mungkar.' Umar berkata; 'Bukan tentang ini yang aku tanyakan kepadamuakan tetapi tentang (fitnah) yang bergelombang seperti gelombang lautan.' Khudzaifah berkata; 'kamu tidak terkena dampaknya dari fitnah itu ya amirul mukminin, sebab antara kamu dan fitnah itu terdapat pintu tertutup.' Umar bertanya; 'Apakah pintunya dipecahkan atau dibuka? ' Khudzaifah menjawab; 'bahkan di pecahkan.' Maka Umar berkata; 'kalau begitu tidak ditutup selama-lamanya.' aku menjawab; 'Betul.' Saya bertanya kepada Khudzaifah; 'Apakah Umar mengetahui pintu itu? ' Khudzaifah menjawab; 'Ya, sebagaimana ia mengetahui bahwa setelah esok ada malam, yang demikian itu karena aku menceritakan Hadits kepadanya dengan tanpa kekeliruan, maka kami khawatir untuk menanyakan kepada Umar siapa pintu sebenarnya.' lalu kami perintahkan kepada Masruq untuk bertanya kepada Khudzaifah; (siapakah pintu itu), Khudzaifah menjawab; 'Umar.'"},"6234":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ أَخْبَرَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شَرِيكِ بْنِ عَبْدِ اللَّهِ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّ قَالَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا إِلَى حَائِطٍ مِنْ حَوَائِطِ الْمَدِينَةِ لِحَاجَتِهِ وَخَرَجْتُ فِي إِثْرِهِ فَلَمَّا دَخَلَ الْحَائِطَ جَلَسْتُ عَلَى بَابِهِ وَقُلْتُ لَأَكُونَنَّ الْيَوْمَ بَوَّابَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يَأْمُرْنِي فَذَهَبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَضَى حَاجَتَهُ وَجَلَسَ عَلَى قُفِّ الْبِئْرِ فَكَشَفَ عَنْ سَاقَيْهِ وَدَلَّاهُمَا فِي الْبِئْرِ فَجَاءَ أَبُو بَكْرٍ يَسْتَأْذِنُ عَلَيْهِ لِيَدْخُلَ فَقُلْتُ كَمَا أَنْتَ حَتَّى أَسْتَأْذِنَ لَكَ فَوَقَفَ فَجِئْتُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا نَبِيَّ اللَّهِ أَبُو بَكْرٍ يَسْتَأْذِنُ عَلَيْكَ قَالَ ائْذَنْ لَهُ وَبَشِّرْهُ بِالْجَنَّةِ فَدَخَلَ فَجَاءَ عَنْ يَمِينِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَشَفَ عَنْ سَاقَيْهِ وَدَلَّاهُمَا فِي الْبِئْرِ فَجَاءَ عُمَرُ فَقُلْتُ كَمَا أَنْتَ حَتَّى أَسْتَأْذِنَ لَكَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ائْذَنْ لَهُ وَبَشِّرْهُ بِالْجَنَّةِ فَجَاءَ عَنْ يَسَارِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَشَفَ عَنْ سَاقَيْهِ فَدَلَّاهُمَا فِي الْبِئْرِ فَامْتَلَأَ الْقُفُّ فَلَمْ يَكُنْ فِيهِ مَجْلِسٌ ثُمَّ جَاءَ عُثْمَانُ فَقُلْتُ كَمَا أَنْتَ حَتَّى أَسْتَأْذِنَ لَكَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ائْذَنْ لَهُ وَبَشِّرْهُ بِالْجَنَّةِ مَعَهَا بَلَاءٌ يُصِيبُهُ فَدَخَلَ فَلَمْ يَجِدْ مَعَهُمْ مَجْلِسًا فَتَحَوَّلَ حَتَّى جَاءَ مُقَابِلَهُمْ عَلَى شَفَةِ الْبِئْرِ فَكَشَفَ عَنْ سَاقَيْهِ ثُمَّ دَلَّاهُمَا فِي الْبِئْرِ فَجَعَلْتُ أَتَمَنَّى أَخًا لِي وَأَدْعُو اللَّهَ أَنْ يَأْتِيَقَالَ ابْنُ الْمُسَيَّبِ فَتَأَوَّلْتُ ذَلِكَ قُبُورَهُمْ اجْتَمَعَتْ هَا هُنَا وَانْفَرَدَ عُثْمَانُ","id":"Telah menceritakan kepada kami [Sa'id bin Abu Maryam] Telah mengabarkan kepada kami [Muhammad bin Ja'far] dari [Syarik bin Abdullah] dari [Sa'id bin Al Musayyab] dari [Abu Musa Al Asy'ari] menuturkan, Nabi shallallahu 'alaihi wasallam suatu hari keluar ke sebuah kebun Madinah untuk suatu keperluannya, dan aku mengikuti di belakang beliau. Tatkala beliau masuk kebun, aku duduk di pintunya dan kukatakan dalam hati; 'Hari ini aku menjadi penjaga pintu Nabi shallallahu 'alaihi wasallam sekalipun beliau tidak memerintahkanku.' Nabi shallallahu 'alaihi wasallam terus pergi dan menuntaskan hajatnya, beliau duduk diatas emper sumur dan menyingkap kedua betisnya dan memasukkan keduanya ke dalam sumur (kolam). Abu Bakar datang dan meminta izin kepada beliau untuk masuk, maka aku berkata; 'kamu tetap di tempatmu sampai aku meminta izin untukmu! ' Abu bakar pun berhenti hingga aku menemui Nabi shallallahu 'alaihi wasallam dan kukatakan; 'ya Nabiyullah, Abu Bakar memintamu izin kepadamu.' Nabi menjawab: \"berilah dia izin, dan berilah kabar gembira kepadanya dengan surga!\" Abu bakar pun masuk kebun dan datang dari sebelah kanan Nabi shallallahu 'alaihi wasallam. Lalu ia menyingkap kedua betisnya dan masukkannya kedalam sumur (kolam). Kemudian datanglah Umar, maka aku berkata; 'kamu tetap di tempatmu sampai aku meminta izin untukmu! ' Nabi shallallahu 'alaihi wasallam lantas berkata; \"Berilah dia izin, dan berilah kabar gembira dengan surga, \" maka dia pun datang dari sebelah kiri Nabi shallallahu 'alaihi wasallam dan menyingkap kedua betisnya kemudian memasukkannya kedalam sumur, maka emperan sumur telah menjadi sesak, sehingga tak ada lagi ruangan sumur yang luang. Kemudian datanglah Utsman, maka aku katakan 'kamu tetap di tempatmu sampai aku meminta izin untukmu! ' Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Berilah dia izin, dan berilah kabar gembira dengan surga, dan bersama surga itu terdapat malapetaka yang akan menimpanya.\" Utsman pun masuk tetapi dia tidak menemukan tempat duduk bersama mereka maka dia pun berputar sehingga datang dari arah depan mereka di mulut sumur (kolam), kemudian dia menyingkap kedua betisnya dan memasukkan kedua kakinya kedalam sumur. Maka aku berkhayal saudaraku, dan aku berdoa kepada Allah agar cepat-cepat datang. Ibnul Musayyab berkata; 'maka aku takwilkan dari peristiwa itu, kuburan mereka akan menyatu disini, sedang kuburan Utsman akan tersendiri."},"6235":{"ar":"حَدَّثَنِي بِشْرُ بْنُ خَالِدٍ أَخْبَرَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ سَمِعْتُ أَبَا وَائِلٍ قَالَ قِيلَ لِأُسَامَةَأَلَا تُكَلِّمُ هَذَا قَالَ قَدْ كَلَّمْتُهُ مَا دُونَ أَنْ أَفْتَحَ بَابًا أَكُونُ أَوَّلَ مَنْ يَفْتَحُهُ وَمَا أَنَا بِالَّذِي أَقُولُ لِرَجُلٍ بَعْدَ أَنْ يَكُونَ أَمِيرًا عَلَى رَجُلَيْنِ أَنْتَ خَيْرٌ بَعْدَ مَا سَمِعْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يُجَاءُ بِرَجُلٍ فَيُطْرَحُ فِي النَّارِ فَيَطْحَنُ فِيهَا كَطَحْنِ الْحِمَارِ بِرَحَاهُ فَيُطِيفُ بِهِ أَهْلُ النَّارِ فَيَقُولُونَ أَيْ فُلَانُ أَلَسْتَ كُنْتَ تَأْمُرُ بِالْمَعْرُوفِ وَتَنْهَى عَنْ الْمُنْكَرِ فَيَقُولُ إِنِّي كُنْتُ آمُرُ بِالْمَعْرُوفِ وَلَا أَفْعَلُهُ وَأَنْهَى عَنْ الْمُنْكَرِ وَأَفْعَلُهُ","id":"Telah menceritakan kepadaku [Bisyr bin Khalid] Telah menceritakan kepada kami [Muhammad bin Ja'far] dari [Syu'bah] dari [Sulaiman], aku mendengar [Abu Wa`il] berkata, pernah ditanyakan kepada [Usamah]; 'kenapa engkau tidak mengajak bicara orang ini? ' Usamah menjawab; 'Aku telah mengajak biacara orang itu, dan sekarang aku tidak mau membuka pembicaraan yang aku menjadi orang pertama-tama yang membukanya, dan aku tidak akan mengatakan kepada seseorang yang telah menjadi pemimpin terhadap dua orang; 'Engkau lebih baik', setelah aku mendengar dari Rasulullah Shallallahu'alaihiwasallam bersabda; \"akan didatangkan seseorang, kemudian dia dilempar ke dalam neraka, lantas disana ia berputar-putar sebagaimana keledai menarik alat penggilingan, maka penghuni neraka mengelilingi orang tersebut dan bertanya; 'Hai fulan, bukankah kamu dahulu pernah memerintahkan kebaikan dan melarang kemungkaran? ' Ia menjawab; 'ya, saya dahulu memerintah kebaikan, namun aku tidak mengerjakannya, dan aku melarang kemungkaran, namun justru aku melakkannya.'\""},"6236":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ الْهَيْثَمِ حَدَّثَنَا عَوْفٌ عَنْ الْحَسَنِ عَنْ أَبِي بَكْرَةَ قَالَلَقَدْ نَفَعَنِي اللَّهُ بِكَلِمَةٍ أَيَّامَ الْجَمَلِ لَمَّا بَلَغَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ فَارِسًا مَلَّكُوا ابْنَةَ كِسْرَى قَالَ لَنْ يُفْلِحَ قَوْمٌ وَلَّوْا أَمْرَهُمْ امْرَأَةً","id":"Telah menceritakan kepada kami [Utsman bin Al Haitsam] telah menceritakan kepada kami ['Auf] dari [Al Hasan] dari [Abu Bakrah] mengatakan; Dikala berlangsung hari-hari perang jamal, aku telah memperoleh pelajaran dari pesan baginda Nabi, tepatnya ketika beliau Shallallahu'alaihiwasallam tahu kerajaan Persia mengangkat anak perempuan Kisra sebagai raja, beliau langsung bersabda: \"Tak akan baik keadaan sebuah kaum yang mengangkat wanita sebagai pemimpin urusan mereka.\""},"6237":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ حَدَّثَنَا أَبُو حَصِينٍ حَدَّثَنَا أَبُو مَرْيَمَ عَبْدُ اللَّهِ بْنُ زِيَادٍ الْأَسَدِيُّ قَالَلَمَّا سَارَ طَلْحَةُ وَالزُّبَيْرُ وَعَائِشَةُ إِلَى الْبَصْرَةِ بَعَثَ عَلِيٌّ عَمَّارَ بْنَ يَاسِرٍ وَحَسَنَ بْنَ عَلِيٍّ فَقَدِمَا عَلَيْنَا الْكُوفَةَ فَصَعِدَا الْمِنْبَرَ فَكَانَ الْحَسَنُ بْنُ عَلِيٍّ فَوْقَ الْمِنْبَرِ فِي أَعْلَاهُ وَقَامَ عَمَّارٌ أَسْفَلَ مِنْ الْحَسَنِ فَاجْتَمَعْنَا إِلَيْهِ فَسَمِعْتُ عَمَّارًا يَقُولُ إِنَّ عَائِشَةَ قَدْ سَارَتْ إِلَى الْبَصْرَةِ وَ وَاللَّهِ إِنَّهَا لَزَوْجَةُ نَبِيِّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الدُّنْيَا وَالْآخِرَةِ وَلَكِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى ابْتَلَاكُمْ لِيَعْلَمَ إِيَّاهُ تُطِيعُونَ أَمْ هِيَ","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] telah menceritakan kepada kami [Yahya bin Adam] telah menceritakan kepada kami [Abu Bakar bin 'Iyyasy] telah menceritakan kepada kami [Abu Hashin] telah menceritakan kepada kami [Abu Maryam Abdullah bin Ziyad Al Asadi] menuturkan; Tatkala Thalhah, Zubair dan 'Aisyah berangkat ke Bashrah, Ali mengutus 'Ammar bin Yasir dan Hasan bin Ali mendatangi Kami di Kufah, lantas keduanya naik minbar. Ketika itu Al Hasan bin Ali diatas minbar di tangga paling atas, sedang Ammar berdiri dibawah Al Hasan, kami berkumpul di sekelilingnya, dan aku mendengar ['Ammar] mengatakan; 'Aisyah tengah berangkat ke Bashrah, demi Allah, ia adalah isteri Nabi kalian (Shallallahu'alaihiwasallam) di dunia dan di akherat, namun Allah Tabaraka wata'ala menguji kalian agar Dia mengetahui, apakah kalian taat kepada-NYA atau kepada Aisyah.'"},"6238":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا ابْنُ أَبِي غَنِيَّةَ عَنْ الْحَكَمِ عَنْ أَبِي وَائِلٍ قَامَ عَمَّارٌعَلَى مِنْبَرِ الْكُوفَةِ فَذَكَرَ عَائِشَةَ وَذَكَرَ مَسِيرَهَا وَقَالَ إِنَّهَا زَوْجَةُ نَبِيِّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الدُّنْيَا وَالْآخِرَةِ وَلَكِنَّهَا مِمَّا ابْتُلِيتُمْ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Ibnu Abi Ghaniyyah] dari [Al Hakam] dari [Abu Wa`il]; ['Ammar] berdiri diatas minbar Kufah, lantas ia menyebut Aisyah dan keberangkatannya, dan ia berkta; 'Ia adalah isteri Nabi kalian (shallallahu 'alaihi wasallam) di dunia dan akherat, namun ia adalah diantara perkara yang kalian diuji dengannya.'"},"6239":{"ar":"حَدَّثَنَا بَدَلُ بْنُ الْمُحَبَّرِ حَدَّثَنَا شُعْبَةُ أَخْبَرَنِي عَمْرٌو سَمِعْتُ أَبَا وَائِلٍ يَقُولُدَخَلَ أَبُو مُوسَى وَأَبُو مَسْعُودٍ عَلَى عَمَّارٍ حَيْثُ بَعَثَهُ عَلِيٌّ إِلَى أَهْلِ الْكُوفَةِ يَسْتَنْفِرُهُمْ فَقَالَا مَا رَأَيْنَاكَ أَتَيْتَ أَمْرًا أَكْرَهَ عِنْدَنَا مِنْ إِسْرَاعِكَ فِي هَذَا الْأَمْرِ مُنْذُ أَسْلَمْتَ فَقَالَ عَمَّارٌ مَا رَأَيْتُ مِنْكُمَا مُنْذُ أَسْلَمْتُمَا أَمْرًا أَكْرَهَ عِنْدِي مِنْ إِبْطَائِكُمَا عَنْ هَذَا الْأَمْرِ وَكَسَاهُمَا حُلَّةً حُلَّةً ثُمَّ رَاحُوا إِلَى الْمَسْجِدِ","id":"Telah menceritakan kepada kami [Badal bin Al Muhabbar] telah menceritakan kepada kami [Syu'bah] telah mengabarkan kepada kami ['Amru] aku mendengar [Abu Wa`il] mengatakan; [Abu Musa] dan [Abu Mas'ud] menemui ['Ammar] ketika ia diutus Ali ke Kufah untuk mengajak masyarakat Kufah ikut dalam barisannya, lantas keduanya mengatakan kepada Ammar; 'Kami belum pernah melihatmu melakukan sesuatu yang lebih kami benci daripada kesegeraanmu dalam masalah ini semenjak kamu masuk Islam.' 'Ammar lantas menjawab; 'Dan Saya belum pernah melihat kamu berdua melakukan sesuatu yang lebih saya benci daripada keterlambatan kalian mengikuti urusan ini, ' lantas Ammar memberi keduanya masing-masing satu pakaian, kemudian mereka bertiga pergi ke masjid."},"6240":{"ar":"حَدَّثَنَا عَبْدَانُ عَنْ أَبِي حَمْزَةَ عَنْ الْأَعْمَشِ عَنْ شَقِيقِ بْنِ سَلَمَةَكُنْتُ جَالِسًا مَعَ أَبِي مَسْعُودٍ وَأَبِي مُوسَى وَعَمَّارٍ فَقَالَ أَبُو مَسْعُودٍ مَا مِنْ أَصْحَابِكَ أَحَدٌ إِلَّا لَوْ شِئْتُ لَقُلْتُ فِيهِ غَيْرَكَ وَمَا رَأَيْتُ مِنْكَ شَيْئًا مُنْذُ صَحِبْتَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْيَبَ عِنْدِي مِنْ اسْتِسْرَاعِكَ فِي هَذَا الْأَمْرِ قَالَ عَمَّارٌ يَا أَبَا مَسْعُودٍ وَمَا رَأَيْتُ مِنْكَ وَلَا مِنْ صَاحِبِكَ هَذَا شَيْئًا مُنْذُ صَحِبْتُمَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْيَبَ عِنْدِي مِنْ إِبْطَائِكُمَا فِي هَذَا الْأَمْرِ فَقَالَ أَبُو مَسْعُودٍ وَكَانَ مُوسِرًا يَا غُلَامُ هَاتِ حُلَّتَيْنِ فَأَعْطَى إِحْدَاهُمَا أَبَا مُوسَى وَالْأُخْرَى عَمَّارًا وَقَالَ رُوحَا فِيهِ إِلَى الْجُمُعَةِ","id":"Telah menceritakan kepada kami ['Abdan] dari [Abu Hamzah] dari [Al A'masy] dari [Syaqiq bin Salamah], aku pernah duduk bersama [Abu mas'ud] dan [Abu Musa] dan ['Ammar], Abu Mas'ud berkata; 'Tak ada seorangpun dari sahabatmu yang jika aku berkenan pasti aku berkomentar tentangnya kecuali kamu, dan belum pernah kulihat sesuatu darimu yang lebih tercela bagiku semenjak kamu bersahabat dengan Nabi shallallahu 'alaihi wasallam daripada kesegeraanmu ikut serta masalah ini.' Ammar menjawab; 'Wahai Abu mas'ud, dan aku tidak pernah melihat sesuatu darimu dan juga dari para sahabatmu sesuatu yang lebih tercela bagiku semenjak engkau bersahabat dengan Nabi shallallahu 'alaihi wasallam selain keterlambatanmu ikut serta dalam masalah ini.' Lantas Abu mas'ud mengatakan -yang ketika itu ia lapang rezekinya-; 'hai anak kecil, tolong ambilkan dua pakaian untuk kedua orang ini, ' satunya untuk Abu Musa, dan satunya untuk Ammar, lantas ia berujar; 'Berangkatlah kalian berdua untuk melaksanakan shalat jum'at.'"},"6241":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُثْمَانَ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ أَخْبَرَنِي حَمْزَةُ بْنُ عَبْدِ اللَّهِ بْنِ عُمَرَ أَنَّهُ سَمِعَ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَنْزَلَ اللَّهُ بِقَوْمٍ عَذَابًا أَصَابَ الْعَذَابُ مَنْ كَانَ فِيهِمْ ثُمَّ بُعِثُوا عَلَى أَعْمَالِهِمْ","id":"Telah menceritakan kepada kami [Abdullah bin Utsman], Telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Yunus] dari [Az Zuhri] telah mengabarkan kepada kami [Hamzah bin Abdullah bin Umar], ia mendengar [Ibnu Umar] radliallahu 'anhuma mengatakan, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika Allah menurunkan adzab, maka adzab itu akan mengenai siapa saja yang berada ditengah-tengah mereka, lantas mereka dihisab sesuai amalan mereka.\""},"6242":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا إِسْرَائِيلُ أَبُو مُوسَىوَلَقِيتُهُ بِالْكُوفَةِ وَجَاءَ إِلَى ابْنِ شُبْرُمَةَ فَقَالَ أَدْخِلْنِي عَلَى عِيسَى فَأَعِظَهُ فَكَأَنَّ ابْنَ شُبْرُمَةَ خَافَ عَلَيْهِ فَلَمْ يَفْعَلْ قَالَ حَدَّثَنَا الْحَسَنُ قَالَ لَمَّا سَارَ الْحَسَنُ بْنُ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُمَا إِلَى مُعَاوِيَةَ بِالْكَتَائِبِ قَالَ عَمْرُو بْنُ الْعَاصِ لِمُعَاوِيَةَ أَرَى كَتِيبَةً لَا تُوَلِّي حَتَّى تُدْبِرَ أُخْرَاهَا قَالَ مُعَاوِيَةُ مَنْ لِذَرَارِيِّ الْمُسْلِمِينَ فَقَالَ أَنَا فَقَالَ عَبْدُ اللَّهِ بْنُ عَامِرٍ وَعَبْدُ الرَّحْمَنِ بْنُ سَمُرَةَ نَلْقَاهُ فَنَقُولُ لَهُ الصُّلْحَ قَالَ الْحَسَنُ وَلَقَدْ سَمِعْتُ أَبَا بَكْرَةَ قَالَ بَيْنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ جَاءَ الْحَسَنُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ابْنِي هَذَا سَيِّدٌ وَلَعَلَّ اللَّهَ أَنْ يُصْلِحَ بِهِ بَيْنَ فِئَتَيْنِ مِنْ الْمُسْلِمِينَ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Isra'il Abu Musa] dan aku menemuinya di Kufah, lantas Israil Abu Musa menemui Ibnu Syubrumah dan mengatakan; 'pertemukanlah aku dengan Isa sehingga aku bisa menasehatinya, ' namun seolah-olah Ibnu Syubrumah takut keadanya sehingga tidak dilakukannya. Dia menjelaskan; telah menceritakan kepada kami [Al Hasan] ia menuturkan; tatkala Al Hasan bin Ali radliallahu 'anhuma berangkat menemui Mu'awiyah dengan pasukannya, 'Amru bin 'Ash berkata kepada mu'awiyah; 'Aku melihat pasukan yang tak akan melarikan diri hingga pasukan musuhnya yang justru terpukul mundur.' Kata Mu'awiyah; 'Lantas siapa nanti yang akan mengurus anak-anak kaum muslimin? ' 'Saya' Jawab Amru bin 'ash. Abdullah bin Amir dan Abdurrahman bin Samurah mengatakan; 'Lebih baik kita menemuinya, dan kita katakan kepadanya; 'Mari kita berdamai, ' Al Hasan berkata; telah kudengar [Abu Bakrah] mengatakan; Ketika Nabi shallallahu 'alaihi wasallam berkhutbah, Al Hasan datang, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Anakku ini adalah penghulu, dan mudah-mudahan Allah mendamaikan dua kubu kaum muslimin yang bersengketa melalui dia.\""},"6243":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ قَالَ عَمْرٌو أَخْبَرَنِي مُحَمَّدُ بْنُ عَلِيٍّ أَنَّ حَرْمَلَةَ مَوْلَى أُسَامَةَ أَخْبَرَهُ قَالَ عَمْرٌو قَدْ رَأَيْتُ حَرْمَلَةَ قَالَ أَرْسَلَنِي أُسَامَةُإِلَى عَلِيٍّ وَقَالَ إِنَّهُ سَيَسْأَلُكَ الْآنَ فَيَقُولُ مَا خَلَّفَ صَاحِبَكَ فَقُلْ لَهُ يَقُولُ لَكَ لَوْ كُنْتَ فِي شِدْقِ الْأَسَدِ لَأَحْبَبْتُ أَنْ أَكُونَ مَعَكَ فِيهِ وَلَكِنَّ هَذَا أَمْرٌ لَمْ أَرَهُ فَلَمْ يُعْطِنِي شَيْئًا فَذَهَبْتُ إِلَى حَسَنٍ وَحُسَيْنٍ وَابْنِ جَعْفَرٍ فَأَوْقَرُوا لِي رَاحِلَتِي","id":"Telah menceritakan kepada kami ['Ali bin Abdullah] telah menceritakan kepada kami [Sufyan] mengatakan, ['Amru] mengatakan, Telah mengabarkan kepadaku [Muhammad bin Ali], bahwasanya [Harmalah] maula Usamah mengabarkan kepadanya. 'Amru berkata; aku pernah melihat Harmalah mengatakan; [Usamah] mengutusku menemui Ali, dan dia mengatakan; 'Sesungguhnya Ali pasti akan bertanya kepadamu sekarang, dia berkata; 'Apa yang menyebabkan kawanmu tidak berangkat bersama aku? ' maka katakan kepadanya; 'kalaulah aku dalam mulut singa, niscaya aku ingin bersamamu, namun ini adalah sebuah masalah yang belum pernah kulihat sama sekali sebelumnya.' Ali tidak memberiku perbekalan apa-apa, karenanya aku pun pergi ke Al Hasan dan Al Husain serta Ibnu Ja'far, dan mereka memberi perbekalan-perbekalan diatas kendaraanku."},"6244":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ نَافِعٍ قَالَلَمَّا خَلَعَ أَهْلُ الْمَدِينَةِ يَزِيدَ بْنَ مُعَاوِيَةَ جَمَعَ ابْنُ عُمَرَ حَشَمَهُ وَوَلَدَهُ فَقَالَ إِنِّي سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يُنْصَبُ لِكُلِّ غَادِرٍ لِوَاءٌ يَوْمَ الْقِيَامَةِ وَإِنَّا قَدْ بَايَعْنَا هَذَا الرَّجُلَ عَلَى بَيْعِ اللَّهِ وَرَسُولِهِ وَإِنِّي لَا أَعْلَمُ غَدْرًا أَعْظَمَ مِنْ أَنْ يُبَايَعَ رَجُلٌ عَلَى بَيْعِ اللَّهِ وَرَسُولِهِ ثُمَّ يُنْصَبُ لَهُ الْقِتَالُ وَإِنِّي لَا أَعْلَمُ أَحَدًا مِنْكُمْ خَلَعَهُ وَلَا بَايَعَ فِي هَذَا الْأَمْرِ إِلَّا كَانَتْ الْفَيْصَلَ بَيْنِي وَبَيْنَهُ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Nafi'] mengatakan, dikala Penduduk Madinah memecat Yazid bin Mu'awiyah, [Ibnu Umar] mengumpulkan kerabat dan anak-anaknya lantas mengatakan; Saya mendengar Nabi shallallahu 'alaihi wasallam bersabda; \"Setiap pengkhianat diberi bendera pada hari kiamat, dan saya telah membaiat orang ini untuk berjanji setia kepada Allah dan rasul-NYA, dan saya tidak tahu pengkhianatan lebih besar daripada seseorang yang dibai'at untuk berjanji setia kepada Allah dan rasul-Nya kemudian ia diberi bendera untuk perang, dan aku tidak tahu salah seorang diantara kalian jika melepaskan baiatnya, atau tidak pula ia berbaiat dalam urusan ini, melainkan antara aku dan dia ada batas pemisah.\""},"6245":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا أَبُو شِهَابٍ عَنْ عَوْفٍ عَنْ أَبِي الْمِنْهَالِ قَالَلَمَّا كَانَ ابْنُ زِيَادٍ وَمَرْوَانُ بِالشَّأْمِ وَوَثَبَ ابْنُ الزُّبَيْرِ بِمَكَّةَ وَوَثَبَ الْقُرَّاءُ بِالْبَصْرَةِ فَانْطَلَقْتُ مَعَ أَبِي إِلَى أَبِي بَرْزَةَ الْأَسْلَمِيِّ حَتَّى دَخَلْنَا عَلَيْهِ فِي دَارِهِ وَهُوَ جَالِسٌ فِي ظِلِّ عُلِّيَّةٍ لَهُ مِنْ قَصَبٍ فَجَلَسْنَا إِلَيْهِ فَأَنْشَأَ أَبِي يَسْتَطْعِمُهُ الْحَدِيثَ فَقَالَ يَا أَبَا بَرْزَةَ أَلَا تَرَى مَا وَقَعَ فِيهِ النَّاسُ فَأَوَّلُ شَيْءٍ سَمِعْتُهُ تَكَلَّمَ بِهِ إِنِّي احْتَسَبْتُ عِنْدَ اللَّهِ أَنِّي أَصْبَحْتُ سَاخِطًا عَلَى أَحْيَاءِ قُرَيْشٍ إِنَّكُمْ يَا مَعْشَرَ الْعَرَبِ كُنْتُمْ عَلَى الْحَالِ الَّذِي عَلِمْتُمْ مِنْ الذِّلَّةِ وَالْقِلَّةِ وَالضَّلَالَةِ وَإِنَّ اللَّهَ أَنْقَذَكُمْ بِالْإِسْلَامِ وَبِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى بَلَغَ بِكُمْ مَا تَرَوْنَ وَهَذِهِ الدُّنْيَا الَّتِي أَفْسَدَتْ بَيْنَكُمْ إِنَّ ذَاكَ الَّذِي بِالشَّأْمِ وَاللَّهِ إِنْ يُقَاتِلُ إِلَّا عَلَى الدُّنْيَا وَإِنَّ هَؤُلَاءِ الَّذِينَ بَيْنَ أَظْهُرِكُمْ وَاللَّهِ إِنْ يُقَاتِلُونَ إِلَّا عَلَى الدُّنْيَا وَإِنْ ذَاكَ الَّذِي بِمَكَّةَ وَاللَّهِ إِنْ يُقَاتِلُ إِلَّا عَلَى الدُّنْيَا","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Abu Syihab] dari ['Auf] dari [Abu Minhal] mengatakan, tatkala Ibnu Ziyad dan Marwan di Syam, dan Ibnu Zubair membelot di Makkah, dan Al qurra' membelot di Bashrah, Aku berangkat bersama ayahku ke [Abu Barzah Al Aslami] hingga kami menemuinya di rumahnya sedang duduk di tempat tinggi yang terbuat dari kayu, kami pun duduk bersamanya, ayahku lantas meminta petuah-petuah Hadits seraya mengatakan; 'Wahai Abu Barzah, bukankah telah kau lihat sendiri kemelut yang melanda manusia? ' yang pertama-tama kudengar dari yang diucapkannya ialah; 'Saya semata-mata mengharap pahala disisi Allah, sungguh saya sangat marah kepada orang quraisy, sesungguhnya kalian wahai segenap bangsa arab, dahulu keadaan kalian seperti telah kau kenal sendiri sedemikian hina, minoritas dan sesat, kemudian Allah menyelamatkan kalian dengan Islam dan Muhammad Shallallahu'alaihiwasallam hingga kalian memperoleh seperti yang kalian lihat sendiri. Dan inilah dunia yang merusak diantara kalian. Dan sesungguhnya yang terjadi di Syam, demi Allah, tidaklah mereka berperang selain karena duniawi, dan mereka yang berada ditengah-tengah kalian, demi Allah mereka juga tidak berperang selain karena duniawi, dan mereka yang berada di Makkah, demi Allah, mereka tidak berperang selain karena duniawi.'"},"6246":{"ar":"حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ حَدَّثَنَا شُعْبَةُ عَنْ وَاصِلٍ الْأَحْدَبِ عَنْ أَبِي وَائِلٍ عَنْ حُذَيْفَةَ بْنِ الْيَمَانِ قَالَإِنَّ الْمُنَافِقِينَ الْيَوْمَ شَرٌّ مِنْهُمْ عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانُوا يَوْمَئِذٍ يُسِرُّونَ وَالْيَوْمَ يَجْهَرُونَ","id":"Telah menceritakan kepada kami [Adam bin Abi Iyas] telah menceritakan kepada kami [Syu'bah] dari [Washil Al Ahdab] dari [Abu Wa`il] dari [Khudzaifah bin Yaman] mengatakan; 'kaum munafikin hari ini jauh lebih buruk daripada mereka yang hidup di masa Nabi shallallahu 'alaihi wasallam, sebab dahulu mereka sembunyi-sembunyi, namun sekarang mereka lakukan secara terang-terangan.'"},"6247":{"ar":"حَدَّثَنَا خَلَّادٌ حَدَّثَنَا مِسْعَرٌ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ أَبِي الشَّعْثَاءِ عَنْ حُذَيْفَةَ قَالَإِنَّمَا كَانَ النِّفَاقُ عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَّا الْيَوْمَ فَإِنَّمَا هُوَ الْكُفْرُ بَعْدَ الْإِيمَانِ","id":"Telah menceritakan kepada kami [Khallad] telah menceritakan kepada kami [Mis'ar] dari [Habib bin Abi Tsabit] dari [Abu Sya'sya`] dari [Khudzaifah] mengatakan; 'Kemunafikan itu terjadi dimasa Nabi shallallahu 'alaihi wasallam, adapun yang terjadi hari ini adalah kekufuran setelah keimanan.'"},"6248":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنِي مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَقُومُ السَّاعَةُ حَتَّى يَمُرَّ الرَّجُلُ بِقَبْرِ الرَّجُلِ فَيَقُولُ يَا لَيْتَنِي مَكَانَهُ","id":"Telah menceritakan kepada kami [Isma'il] telah menceritakan kepadaku [Malik] dari [Abu Zanad] dari [Al A'raj] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Hari kiamat tidak akan terjadi sehingga seseorang melewati kuburan seseorang, lantas mengatakan; 'duhai sekiranya aku menggantikan dia.'\""},"6249":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ قَالَ سَعِيدُ بْنُ الْمُسَيَّبِ أَخْبَرَنِي أَبُو هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَقُومُ السَّاعَةُ حَتَّى تَضْطَرِبَ أَلَيَاتُ نِسَاءِ دَوْسٍ عَلَى ذِي الْخَلَصَةِ وَذُو الْخَلَصَةِ طَاغِيَةُ دَوْسٍ الَّتِي كَانُوا يَعْبُدُونَ فِي الْجَاهِلِيَّةِ","id":"Telah menceritakan kepada kami [Abul Yaman] Telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] mengatakan, [Said bin Al Musayyab] mengatakan, telah mengabarkan kepadaku [Abu Hurairah] radliallahu 'anhu, bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hari kiamat tidak akan tiba sehingga pantat-pantat wanita daus berjoget pada Dzul khulashah, dan Dzul khulashah ialah thaghut suku Daus yang mereka sembah di masa jahiliyah.\""},"6250":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنِي سُلَيْمَانُ عَنْ ثَوْرٍ عَنْ أَبِي الْغَيْثِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَقُومُ السَّاعَةُ حَتَّى يَخْرُجَ رَجُلٌ مِنْ قَحْطَانَ يَسُوقُ النَّاسَ بِعَصَاهُ","id":"Telah menceritakan kepada kami [Abdul Aziz bin Abdullah], telah menceritakan kepadaku [Sulaiman] dari [Tsaur] dari [Abul Ghaits] dari [Abu Hurairah], bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hari kiamat tidak akan tiba hingga seseorang dari kabilah Qahthan menggiring manusia dengan tongkatnya.\""},"6251":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ سَعِيدُ بْنُ الْمُسَيَّبِ أَخْبَرَنِي أَبُو هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَقُومُ السَّاعَةُ حَتَّى تَخْرُجَ نَارٌ مِنْ أَرْضِ الْحِجَازِ تُضِيءُ أَعْنَاقَ الْإِبِلِ بِبُصْرَى","id":"Telah menceritakan kepada kami [Abul yaman] Telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri]; [Sa'id bin Al Musayyab] mengatakan, telah mengabarkan kepadaku [Abu Hurairah] bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hari kiamat tidak akan tiba hingga api keluar dari tanah Hejaz yang bisa menyinari tengkuk unta di Bushra.\""},"6252":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ الْكِنْدِيُّ حَدَّثَنَا عُقْبَةُ بْنُ خَالِدٍ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ خُبَيْبِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ جَدِّهِ حَفْصِ بْنِ عَاصِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوشِكُ الْفُرَاتُ أَنْ يَحْسِرَ عَنْ كَنْزٍ مِنْ ذَهَبٍ فَمَنْ حَضَرَهُ فَلَا يَأْخُذْ مِنْهُ شَيْئًاقَالَ عُقْبَةُ وَحَدَّثَنَا عُبَيْدُ اللَّهِ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ إِلَّا أَنَّهُ قَالَ يَحْسِرُ عَنْ جَبَلٍ مِنْ ذَهَبٍ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id Al Kindi] telah menceritakan kepada kami ['Uqbah bin Khalid] telah menceritakan kepada kami [Ubaidullah] dari [Khubaib bin Abdurrahman] dari [Kakeknya, Hafsh bin 'Ashim] dari [Abu Hurairah] mengatakan, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak lama lagi Eufrat tersingkap perbendaharaan-perbendaharaan emasnya, maka barangsiapa mendatanginya, jangan ia mengambilnya sedikitpun.\" Kata [Uqbah]; telah menceritakan kepada kami [Ubaidullah] telah menceritakan kepada kami [Abu Az Zanad] dari [Al A'raj] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam semisal hadits diatas, hanyasanya dia mengatakan dengan redaksi; \"tersingkap gunung emas.\""},"6253":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ حَدَّثَنَا مَعْبَدٌ سَمِعْتُ حَارِثَةَ بْنَ وَهْبٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ تَصَدَّقُوا فَسَيَأْتِي عَلَى النَّاسِ زَمَانٌ يَمْشِي الرَّجُلُ بِصَدَقَتِهِ فَلَا يَجِدُ مَنْ يَقْبَلُهَاقَالَ مُسَدَّدٌ حَارِثَةُ أَخُو عُبَيْدِ اللَّهِ بْنِ عُمَرَ لِأُمِّهِ قَالَهُ أَبُو عَبْدِ اللَّهِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Syu'bah] telah menceritakan kepada kami [Ma'bad] aku mendengar [Haritsah bin Wahb] mengatakan; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bersedekahlah kalian, sebab akan Datang kepada manusia suatu zaman yang ketika itu seseorang berjalan membawa sedekahnya namun dia tidak menemukan seseorang yang mau menerima sedekahnya.\" Kata Musaddad, Haritsah adalah saudara Ubaidullah bin Umar seibu, demikian Abu Abdullah mengatakan."},"6254":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَقُومُ السَّاعَةُ حَتَّى تَقْتَتِلَ فِئَتَانِ عَظِيمَتَانِ يَكُونُ بَيْنَهُمَا مَقْتَلَةٌ عَظِيمَةٌ دَعْوَتُهُمَا وَاحِدَةٌ وَحَتَّى يُبْعَثَ دَجَّالُونَ كَذَّابُونَ قَرِيبٌ مِنْ ثَلَاثِينَ كُلُّهُمْ يَزْعُمُ أَنَّهُ رَسُولُ اللَّهِ وَحَتَّى يُقْبَضَ الْعِلْمُ وَتَكْثُرَ الزَّلَازِلُ وَيَتَقَارَبَ الزَّمَانُ وَتَظْهَرَ الْفِتَنُ وَيَكْثُرَ الْهَرْجُ وَهُوَ الْقَتْلُ وَحَتَّى يَكْثُرَ فِيكُمْ الْمَالُ فَيَفِيضَ حَتَّى يُهِمَّ رَبَّ الْمَالِ مَنْ يَقْبَلُ صَدَقَتَهُ وَحَتَّى يَعْرِضَهُ عَلَيْهِ فَيَقُولَ الَّذِي يَعْرِضُهُ عَلَيْهِ لَا أَرَبَ لِي بِهِ وَحَتَّى يَتَطَاوَلَ النَّاسُ فِي الْبُنْيَانِ وَحَتَّى يَمُرَّ الرَّجُلُ بِقَبْرِ الرَّجُلِ فَيَقُولُ يَا لَيْتَنِي مَكَانَهُ وَحَتَّى تَطْلُعَ الشَّمْسُ مِنْ مَغْرِبِهَا فَإِذَا طَلَعَتْ وَرَآهَا النَّاسُ يَعْنِي آمَنُوا أَجْمَعُونَ فَذَلِكَ حِينَ{ لَا يَنْفَعُ نَفْسًا إِيمَانُهَا لَمْ تَكُنْ آمَنَتْ مِنْ قَبْلُ أَوْ كَسَبَتْ فِي إِيمَانِهَا خَيْرًا }وَلَتَقُومَنَّ السَّاعَةُ وَقَدْ نَشَرَ الرَّجُلَانِ ثَوْبَهُمَا بَيْنَهُمَا فَلَا يَتَبَايَعَانِهِ وَلَا يَطْوِيَانِهِ وَلَتَقُومَنَّ السَّاعَةُ وَقَدْ انْصَرَفَ الرَّجُلُ بِلَبَنِ لِقْحَتِهِ فَلَا يَطْعَمُهُ وَلَتَقُومَنَّ السَّاعَةُ وَهُوَ يُلِيطُ حَوْضَهُ فَلَا يَسْقِي فِيهِ وَلَتَقُومَنَّ السَّاعَةُ وَقَدْ رَفَعَ أُكْلَتَهُ إِلَى فِيهِ فَلَا يَطْعَمُهَا","id":"Telah menceritakan kepada kami [Abul Yaman] Telah mengabarkan kepada kami [Syu'aib] telah menceritakan kepada kami [Abu Az Zanad] dari ['Abdurrahman] dari [Abu Hurairah], bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hari kiamat tidak akan terjadi sehingga dua kelompok besar terjadi pembunuhan besar-besaran padahal ajakan keduanya satu, hingga muncul para pendusta yang kurang lebihnya tiga puluh, kesemuanya mengaku ia utusan Allah, hingga ilmu diangkat, banyak keguncangan, zaman terasa singkat, fitnah muncul dimana-mana, dan banyak alharaj, yaitu pembunuhan, hingga ditengah-tengah kalian harta melimpah ruah dan berlebihan, sehingga pemilik harta mencari-cari orang yang mau menerima sedekahnya, sampai ia menawar-nawarkan sedekahnya, namun orang yang ditawari mengelak seraya mengatakan ' Aku tak butuh sedekahmu', sehingga manusia berlomba-lomba meninggikan bangunan, sehingga seseorang melewati kuburan seseorang dan mengatakan; 'Aduhai sekiranya aku menggantikannya', hingga matahari terbit dari sebelah barat, padahal jika matahari telah terbit dari sebelah barat dan manusia melihatnya, mereka semua beriman, pada saat itulah sebagaimana ayat; 'Ketika itu tidak bermanfaat lagi bagi seseorang keimanannya, yang ia belum beriman sebelumnya atau belum mengerjakan kebaikan dengan keimanannya.\" (QS. Al an'am 158), dan hari kiamat terjadi ketika dua orang telah menyerahkan kedua bajunya tetapi keduanya tidak jadi melakukan jual beli, keduanya tidak jadi melipatnya, dan hari kiamat terjadi sedang seseorang telah pulang membawa susu sapinya tetapi tidak jadi ia meminumnya, dan hari kiamat terjadi ketika seseorang memperbaiki kolam (tempat minum) nya tetai dia tak jadi meminumnya, dan hari kiamat terjadi sedang seseorang telah mengangkat suapannya tetapi dia tidak jadi menyantapnya.\""},"6255":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنِي قَيْسٌ قَالَ قَالَ لِي الْمُغِيرَةُ بْنُ شُعْبَةَمَا سَأَلَ أَحَدٌ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الدَّجَّالِ أَكْثَرَ مَا سَأَلْتُهُ وَإِنَّهُ قَالَ لِي مَا يَضُرُّكَ مِنْهُ قُلْتُ لِأَنَّهُمْ يَقُولُونَ إِنَّ مَعَهُ جَبَلَ خُبْزٍ وَنَهَرَ مَاءٍ قَالَ هُوَ أَهْوَنُ عَلَى اللَّهِ مِنْ ذَلِكَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Isma'il] telah menceritakan kepadaku [Qais] mengatakan, [Mughirah bin Syu'bah] mengatakan kepadaku; Tak seorangpun yang lebih banyak bertanya kepada Nabi shallallahu 'alaihi wasallam tentang Dajjal daripadaku, dan beliau bersabda kepadaku: \"Dia tidak membahayakanmu', Saya katakan; 'Yang demikian karena orang-orang mengatakan bahwa Dajjal membawa gunung roti dan sungai yang berair.' Nabi bersabda: \"Itu semua bagi Allah lebih sepele.\""},"6256":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا أَيُّوبُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأُرَاهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَعْوَرُ عَيْنِ الْيُمْنَى كَأَنَّهَا عِنَبَةٌ طَافِيَةٌ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Ayyub] dari [Nafi'] dari [Ibnu 'Umar], seingatku dia dari Nabi shallallahu 'alaihi wasallam bersabda; \"Dajjal buta matanya sebelah kanan, seolah-olah matanya buah anggur yang menjorok.\""},"6257":{"ar":"حَدَّثَنَا سَعْدُ بْنُ حَفْصٍ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَجِيءُ الدَّجَّالُ حَتَّى يَنْزِلَ فِي نَاحِيَةِ الْمَدِينَةِ ثُمَّ تَرْجُفُ الْمَدِينَةُ ثَلَاثَ رَجَفَاتٍ فَيَخْرُجُ إِلَيْهِ كُلُّ كَافِرٍ وَمُنَافِقٍ","id":"Telah menceritakan kepada kami [Sa'ad bin Hafsh] telah menceritakan kepada kami [Syaiban] dari [Yahya] dari [Ishaq bin Abdullah bin Abi Thalhah] dari [Anas bin Malik] mengatakan, Nabi shallallahu 'alaihi wasallam bersabda; \"Dajjal datang hingga singgah di pinggiran Madinah kemudian Madinah guncang tiga kali, sehingga setiap kafir dan munafik menemuinya.\""},"6258":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ أَبِيهِ عَنْ جَدِّهِ عَنْ أَبِي بَكْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَدْخُلُ الْمَدِينَةَ رُعْبُ الْمَسِيحِ الدَّجَّالِ وَلَهَا يَوْمَئِذٍ سَبْعَةُ أَبْوَابٍ عَلَى كُلِّ بَابٍ مَلَكَانِ","id":"Telah menceritakan kepada kami ['Abdul 'Aziz bin Abdullah] telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [ayahnya] dari [kakeknya] dari [Abu Bakrah] dari Nabi shallallahu 'alaihi wasallam bersabda; \"Kemelut al Masih ad dajjal tak akan memasuki Madinah, sebab ketika itu Madinah mempunyai tujuh pintu yang setiap pintu dijaga oleh dua malaikat.\""},"6259":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ حَدَّثَنَا مِسْعَرٌ حَدَّثَنَا سَعْدُ بْنُ إِبْرَاهِيمَ عَنْ أَبِيهِ عَنْ أَبِي بَكْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَدْخُلُ الْمَدِينَةَ رُعْبُ الْمَسِيحِ لَهَا يَوْمَئِذٍ سَبْعَةُ أَبْوَابٍ عَلَى كُلِّ بَابٍ مَلَكَانِقَالَ وَقَالَ ابْنُ إِسْحَاقَ عَنْ صَالِحِ بْنِ إِبْرَاهِيمَ عَنْ أَبِيهِ قَالَ قَدِمْتُ الْبَصْرَةَ فَقَالَ لِي أَبُو بَكْرَةَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Muhammad bin Bisyr] telah menceritakan kepada kami [Mis'ar] telah menceritakan kepada kami [Sa'd bin Ibrahim] dari [ayahnya] dari [Abu Bakrah] dari Nabi shallallahu 'alaihi wasallam bersabda; \"Kemelut al masih ad dajjal tak akan memasuki Madinah, sebab ketika itu Madinah mempunyai tujuh pintu yang setiap pintunya dijaga oleh dua malaikat.\" Dia berkata, [Ibnu Ishaq] mengatakan dari [Salih bin Ibrahim] dari [ayahnya] mengatakan, aku mendatangi Bashrah lantas [Abu Bakrah] mengatakan kepadaku; aku dengar Nabi shallallahu 'alaihi wasallam bersabda sama dengan Hadits ini."},"6260":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا إِبْرَاهِيمُ عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي النَّاسِ فَأَثْنَى عَلَى اللَّهِ بِمَا هُوَ أَهْلُهُ ثُمَّ ذَكَرَ الدَّجَّالَ فَقَالَ إِنِّي لَأُنْذِرُكُمُوهُ وَمَا مِنْ نَبِيٍّ إِلَّا وَقَدْ أَنْذَرَهُ قَوْمَهُ وَلَكِنِّي سَأَقُولُ لَكُمْ فِيهِ قَوْلًا لَمْ يَقُلْهُ نَبِيٌّ لِقَوْمِهِ إِنَّهُ أَعْوَرُ وَإِنَّ اللَّهَ لَيْسَ بِأَعْوَرَ","id":"Telah menceritakan kepada kami [Abdul 'Aziz bin Abdullah], Telah menceritakan kepada kami [Ibrahim] dari [Shalih] dari [Ibnu Syihab] dari [Salim bin Abdullah] bahwasanya [Abdullah bin Umar] radliallahu 'anhu mengatakan, Rasulullah Shallallahu'alaihiwasallam berdiri di tengah-tengah para sahabat lantas memuji Allah dengan pujian selayaknya bagi-Nya, kemudian beliau menyebut-nyebut dajjal dan mengatakan; \"Sungguh saya mengingatkan kalian tentang dajjal, dan tidak ada seorang pun Nabi melainkan telah mengingatkan kaumnya tentang dajjal, dan akan saya jelaskan kepada kalian tentangnya suatu hal yang belum pernah dijelaskan oleh seorang Nabi shallallahu 'alaihi wasallam pun kepada kaumnya, sesungguhnya dajjal itu buta sebelah sedang Allah tidak buta sebelah.\""},"6261":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْنَا أَنَا نَائِمٌ أَطُوفُ بِالْكَعْبَةِ فَإِذَا رَجُلٌ آدَمُ سَبْطُ الشَّعَرِ يَنْطُفُ أَوْ يُهَرَاقُ رَأْسُهُ مَاءً قُلْتُ مَنْ هَذَا قَالُوا ابْنُ مَرْيَمَ ثُمَّ ذَهَبْتُ أَلْتَفِتُ فَإِذَا رَجُلٌ جَسِيمٌ أَحْمَرُ جَعْدُ الرَّأْسِ أَعْوَرُ الْعَيْنِ كَأَنَّ عَيْنَهُ عِنَبَةٌ طَافِيَةٌ قَالُوا هَذَا الدَّجَّالُ أَقْرَبُ النَّاسِ بِهِ شَبَهًا ابْنُ قَطَنٍ رَجُلٌ مِنْ خُزَاعَةَ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari [Salim] dari ['Abdullah bin Umar], bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketika aku tidur, aku bermimpi thawaf di ka'bah, tak tahunya ada seseorang yang rambutnya lurus, kepalanya meneteskan atau mengalirkan air. Maka saya bertanya; 'siapakah ini? ' Mereka mengatakan; 'Ini Isa bin maryam'. Kemudian aku menoleh, tak tahunya ada seseorang yang berbadan besar, warnanya kemerah-merahan, rambutnya keriting, matanya buta sebelah kanan, seolah-olah matanya anggur yang menjorok. Mereka menjelaskan; 'Sedang ini adalah dajjal, manusia yang paling mirip dengannya adalah Ibnu Qaththan, laki-laki dari bani Khuza'ah.'\""},"6262":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْتَعِيذُ فِي صَلَاتِهِ مِنْ فِتْنَةِ الدَّجَّالِ","id":"Telah menceritakan kepada kami ['Abdul Aziz bin Abdullah], telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Shalih] dari [Ibnu Syihab] dari ['Urwah], bahwasanya ['Aisyah] radliallahu 'anha mengatakan; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam selalu meminta perlindungan dari fitnah dajjal dalam shalatnya.\""},"6263":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنِي أَبِي عَنْ شُعْبَةَ عَنْ عَبْدِ الْمَلِكِ عَنْ رِبْعِيٍّ عَنْ حُذَيْفَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي الدَّجَّالِ إِنَّ مَعَهُ مَاءً وَنَارًا فَنَارُهُ مَاءٌ بَارِدٌ وَمَاؤُهُ نَارٌقَالَ أَبُو مَسْعُودٍ أَنَا سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami ['Abdan] telah mengabarkan kepadaku [Ayahku] dari [Syu'bah] dari ['Abdul Malik] dari [Rib'i] dari [Khudzaifah] dari Nabi shallallahu 'alaihi wasallam bersabda tentang dajjal; \"Ia membawa air dan api, yang kelihatan api adalah air dingin, dan yang kelihatan air adalah api.\" Dan [Abu Mas'ud] mengatakan; aku mendengarnya dari Rasulullah shallallahu 'alaihi wasallam."},"6264":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا بُعِثَ نَبِيٌّ إِلَّا أَنْذَرَ أُمَّتَهُ الْأَعْوَرَ الْكَذَّابَ أَلَا إِنَّهُ أَعْوَرُ وَإِنَّ رَبَّكُمْ لَيْسَ بِأَعْوَرَ وَإِنَّ بَيْنَ عَيْنَيْهِ مَكْتُوبٌ كَافِرٌفِيهِ أَبُو هُرَيْرَةَ وَابْنُ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Syu'bah] dari [Qotadah] dari [Anas] radliallahu 'anhu mengatakan, Nabi shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang Nabi pun diutus selain telah memperingatkan kaumnya terhadap yang buta sebelah dan pendusta, ketahuilah bahwasanya dajjal itu buta sebelah, sedang rabb kalian tidak buta sebelah, tertulis diantara kedua matanya KAFIR.\" Tentang Hadits ini, juga ada riwayat dari Abu Hurairah dan Ibnu Abbas dari Nabi shallallahu 'alaihi wasallam."},"6265":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ أَنَّ أَبَا سَعِيدٍ قَالَحَدَّثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا حَدِيثًا طَوِيلًا عَنْ الدَّجَّالِ فَكَانَ فِيمَا يُحَدِّثُنَا بِهِ أَنَّهُ قَالَ يَأْتِي الدَّجَّالُ وَهُوَ مُحَرَّمٌ عَلَيْهِ أَنْ يَدْخُلَ نِقَابَ الْمَدِينَةِ فَيَنْزِلُ بَعْضَ السِّبَاخِ الَّتِي تَلِي الْمَدِينَةَ فَيَخْرُجُ إِلَيْهِ يَوْمَئِذٍ رَجُلٌ وَهُوَ خَيْرُ النَّاسِ أَوْ مِنْ خِيَارِ النَّاسِ فَيَقُولُ أَشْهَدُ أَنَّكَ الدَّجَّالُ الَّذِي حَدَّثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدِيثَهُ فَيَقُولُ الدَّجَّالُ أَرَأَيْتُمْ إِنْ قَتَلْتُ هَذَا ثُمَّ أَحْيَيْتُهُ هَلْ تَشُكُّونَ فِي الْأَمْرِ فَيَقُولُونَ لَا فَيَقْتُلُهُ ثُمَّ يُحْيِيهِ فَيَقُولُ وَاللَّهِ مَا كُنْتُ فِيكَ أَشَدَّ بَصِيرَةً مِنِّي الْيَوْمَ فَيُرِيدُ الدَّجَّالُ أَنْ يَقْتُلَهُ فَلَا يُسَلَّطُ عَلَيْهِ","id":"Telah menceritakan kepada kami [Abul Yaman] Telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] Telah mengabarkan kepada kami ['Ubaidullah bin Abdullah bin Utbah bin Mas'ud], bahwasanya [Abu Sa'id] mengatakan, Suatu hari Rasulullah Shallallahu'alaihiwasallam menceritakan kepada kami suatu Hadits panjang tentang dajjal, diantara yang beliau ceritakan kepada kami saat itu ialah, beliau bersabda: \"dajjal datang dan diharamkan masuk jalan Madinah, lantas ia singgah di lokasi yang tak ada tetumbuhan dekat Madinah, kemudian ada seseorang yang mendatanginya yang ia adalah sebaik-baik manusia atau diantara manusia terbaik, dia berkata; 'saya bersaksi bahwa engkau adalah dajjal, yang Rasulullah Shallallahu'alaihiwasallam telah ceritakan kepada kami.' Kemudian dajjal mengatakan; 'Apa pendapat kalian jika aku membunuh orang ini lantas aku menghidupkannya, apakah kalian masih ragu terhadap perkara ini? ' Mereka menjawab; 'tidak'. Maka Dajjal membunuh orang tersebut kemudian menghidupkannya, namun orang tersebut tiba-tiba mengatakan; 'Ketahuilah bahwa hari ini, kewaspadaanku terhadap diriku tidak sebesar kewaspadaanku terhadapmu! ' Lantas dajjal ingin membunuh orang itu, namun ia tak bisa lagi menguasainya.\""},"6266":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ نُعَيْمِ بْنِ عَبْدِ اللَّهِ الْمُجْمِرِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى أَنْقَابِ الْمَدِينَةِ مَلَائِكَةٌ لَا يَدْخُلُهَا الطَّاعُونُ وَلَا الدَّجَّالُ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Nu'aim bin Abdullah Al Mujmir] dari [Abu Hurairah] menuturkan; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jalan-jalan Madinah dijaga oleh para malaikat, sehingga kota itu tidak bisa dimasuki wabah tha'un ataupun dajjal.\""},"6267":{"ar":"حَدَّثَنِي يَحْيَى بْنُ مُوسَى حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمَدِينَةُ يَأْتِيهَا الدَّجَّالُ فَيَجِدُ الْمَلَائِكَةَ يَحْرُسُونَهَا فَلَا يَقْرَبُهَا الدَّجَّالُ قَالَ وَلَا الطَّاعُونُ إِنْ شَاءَ اللَّهُ","id":"telah menceritakan kepadaku [Yahya bin Musa] telah menceritakan kepada kami [Yazid bin harun] telah mengabarkan kepada kami [Syu'bah] dari [Qotadah] dari [Anas bin Malik] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Madinah akan didatangi Dajjal, namun ia mendapati para malaikat yang menjaganya sehingga Dajjal tak bisa mendekatinya.\" kata Anas; \"tidak pula penyakit Tha'un insya Allah.\""},"6268":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ ح و حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنِي أَخِي عَنْ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ أَبِي عَتِيقٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ أَنَّ زَيْنَبَ بِنْتَ أَبِي سَلَمَةَ حَدَّثَتْهُ عَنْ أُمِّ حَبِيبَةَ بِنْتِ أَبِي سُفْيَانَ عَنْ زَيْنَبَ بِنْتِ جَحْشٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيْهَا يَوْمًا فَزِعًا يَقُولُ لَا إِلَهَ إِلَّا اللَّهُ وَيْلٌ لِلْعَرَبِ مِنْ شَرٍّ قَدْ اقْتَرَبَ فُتِحَ الْيَوْمَ مِنْ رَدْمِ يَأْجُوجَ وَمَأْجُوجَ مِثْلُ هَذِهِ وَحَلَّقَ بِإِصْبَعَيْهِ الْإِبْهَامِ وَالَّتِي تَلِيهَا قَالَتْ زَيْنَبُ بِنْتُ جَحْشٍ فَقُلْتُ يَا رَسُولَ اللَّهِ أَفَنَهْلِكُ وَفِينَا الصَّالِحُونَ قَالَ نَعَمْ إِذَا كَثُرَ الْخُبْثُ","id":"Telah menceritakan kepada kami [Abul Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] -lewat jalur periwayatan lain-- telah menceritakan kepada kami [Ismail] telah menceritakan kepadaku [Saudaraku] dari [Sulaiman] dari [Muhammad bin Abu 'Atiq] dari [Ibnu syihab] dari ['Urwah bin Zubair], bahwasanya [Zainab binti Abu Salamah] menceritakan kepadanya dari [Ummi habibah binti Sufyan], dari [Zainab binti Jahsy], Rasulullah Shallallahu'alaihiwasallam suatu hari menemuinya dengan gusar seraya mengatakan: \"Celaka bangsa arab dari keburukan yang telah dekat, hari ini telah dibuka benteng ya'juj dan Ma'juj seperti ini, \" seraya beliau melingkarkan kedua jarinya, telunjuk dan jempol. Zainab binti Jahsy mengatakan, maka aku bertanya; 'Apakah kita akan juga dibinasakan padahal ditengah-tengah kami masih ada orang-orang shalih? ' Nabi menjawab: \"Iya, jika kejahatan telah merajalela.\""},"6269":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا ابْنُ طَاوُسٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُفْتَحُ الرَّدْمُ رَدْمُ يَأْجُوجَ وَمَأْجُوجَ مِثْلُ هَذِهِ وَعَقَدَ وُهَيْبٌ تِسْعِينَ","id":"Telah menceritakan kepada kami [Musa bin Ismail] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Ibnu Thawus] dari [ayahnya] dari [Abu Hurairah] radliallahu 'anhu, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Benteng ya'juj dan ma'juj dibuka seperti ini.\" Wuhaib mengilustrasikan jarinya dengan membentuk sembilan puluh."},"6270":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا عَبْدُ اللَّهِ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ أَخْبَرَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَطَاعَنِي فَقَدْ أَطَاعَ اللَّهَ وَمَنْ عَصَانِي فَقَدْ عَصَى اللَّهَ وَمَنْ أَطَاعَ أَمِيرِي فَقَدْ أَطَاعَنِي وَمَنْ عَصَى أَمِيرِي فَقَدْ عَصَانِي","id":"Telah menceritakan kepada kami [Abdan] telah mengabarkan kepada kami [Abdullah] dari [Yunus] dari [Al Karmani] telah mengabarkan kepadaku [Abu Salamah bin Abdurrahman], ia mendengar [Abu Hurairah] radliallahu 'anhu berkata, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang mentaatiku berarti ia mentaati Allah, sebaliknya barangsiapa membangkang terhadapku, ia membangkang Allah, dan barangsiapa mentaatiku amirku berarti ia mentaatiku, dan barangsiapa membangkang amirku, berarti ia membangkang terhadapku.\""},"6271":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنِي مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَلَا كُلُّكُمْ رَاعٍ وَكُلُّكُمْ مَسْئُولٌ عَنْ رَعِيَّتِهِ فَالْإِمَامُ الَّذِي عَلَى النَّاسِ رَاعٍ وَهُوَ مَسْئُولٌ عَنْ رَعِيَّتِهِ وَالرَّجُلُ رَاعٍ عَلَى أَهْلِ بَيْتِهِ وَهُوَ مَسْئُولٌ عَنْ رَعِيَّتِهِ وَالْمَرْأَةُ رَاعِيَةٌ عَلَى أَهْلِ بَيْتِ زَوْجِهَا وَوَلَدِهِ وَهِيَ مَسْئُولَةٌ عَنْهُمْ وَعَبْدُ الرَّجُلِ رَاعٍ عَلَى مَالِ سَيِّدِهِ وَهُوَ مَسْئُولٌ عَنْهُ أَلَا فَكُلُّكُمْ رَاعٍ وَكُلُّكُمْ مَسْئُولٌ عَنْ رَعِيَّتِهِ","id":"Telah menceritakan kepada kami [Ismail] Telah menceritakan kepadaku [Malik] dari [Abdullah bin Dinar] dari [Abdullah bin Umar] radliallahu 'anhuma, Rasulullah shallallahu 'alaihi wasallam bersabda: \"ketahuilah Setiap kalian adalah pemimpin, dan setiap kalian akan dimintai pertanggungjawabannya atas yang di pimpin, penguasa yang memimpin rakyat banyak dia akan dimintai pertanggungjawaban atas yang dipimpinnya, setiap kepala keluarga adalah pemimpin anggota keluarganya dan dia dimintai pertanggungjawaban atas yang dipimpinnya, dan isteri pemimpin terhadap keluarga rumah suaminya dan juga anak-anaknya, dan dia akan dimintai pertanggungjawabannya terhadap mereka, dan budak seseorang juga pemimpin terhadap harta tuannya dan akan dimintai pertanggungjawaban terhadapnya, ketahuilah, setiap kalian adalah bertanggung jawab atas yang dipimpinnya.\""},"6272":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ كَانَ مُحَمَّدُ بْنُ جُبَيْرِ بْنِ مُطْعِمٍ يُحَدِّثُ أَنَّهُ بَلَغَ مُعَاوِيَةَوَهُوَ عِنْدَهُ فِي وَفْدٍ مِنْ قُرَيْشٍ أَنَّ عَبْدَ اللَّهِ بْنَ عَمْرٍو يُحَدِّثُ أَنَّهُ سَيَكُونُ مَلِكٌ مِنْ قَحْطَانَ فَغَضِبَ فَقَامَ فَأَثْنَى عَلَى اللَّهِ بِمَا هُوَ أَهْلُهُ ثُمَّ قَالَ أَمَّا بَعْدُ فَإِنَّهُ بَلَغَنِي أَنَّ رِجَالًا مِنْكُمْ يُحَدِّثُونَ أَحَادِيثَ لَيْسَتْ فِي كِتَابِ اللَّهِ وَلَا تُوثَرُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأُولَئِكَ جُهَّالُكُمْ فَإِيَّاكُمْ وَالْأَمَانِيَّ الَّتِي تُضِلُّ أَهْلَهَا فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ هَذَا الْأَمْرَ فِي قُرَيْشٍ لَا يُعَادِيهِمْ أَحَدٌ إِلَّا كَبَّهُ اللَّهُ فِي النَّارِ عَلَى وَجْهِهِ مَا أَقَامُوا الدِّينَتَابَعَهُ نُعَيْمٌ عَنْ ابْنِ الْمُبَارَكِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ مُحَمَّدِ بْنِ جُبَيْرٍ","id":"Telah menceritakan kepada kami [Abul Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] mengatakan, [Muhammad bin Jubair] menceritakan, [Mu'awiyah] mendapat informasi -ketika itu Jubair berada disampingnya-saat berada dalam rombongan quraisy, bahwa Abdullah bin Amru menceritakan, bahwa dirinya akan menjadi raja Qahthan. Spontan Mu'awiyah murka, ia berdiri dan memanjatkan puji-pujian kepada Allah dengan pujian semestinya, kemudian mengatakan; 'Amma ba'd. Telah sampai berita kepadaku bahwa beberapa orang diantara kalian menceritakan hadist yang tidak terdapat dalam kitabullah dan tidak pula berasal dari Rasulullah Shallallahu'alaihiwasallam, mereka itu adalah orang-orang jahil kalian, jauhilah olehmu angan-angan yang menyesatkan pemiliknya, sebab aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"'Kepemimpinan ini tetap berada di quraisy, tidaklah seseorang memusuhi mereka, selain Allah menelungkupkannya dalam neraka diatas wajahnya, selama mereka menegakkan agama.\" hadist ini dikuatkan oleh [Nu'aim] dari [Ibnul Mubarak] dari [Ma'mar] dari [Az Zuhri] dari [Muhammad Ibnu Jubair]."},"6273":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا عَاصِمُ بْنُ مُحَمَّدٍ سَمِعْتُ أَبِي يَقُولُ قَالَ ابْنُ عُمَرَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَزَالُ هَذَا الْأَمْرُ فِي قُرَيْشٍ مَا بَقِيَ مِنْهُمْ اثْنَانِ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami ['Ashim bin Muhammad], aku mendengar [Ayahku] mengatakan; [Ibnu Umar] mengatakan, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Urusan kepemimpinan ini berada di quraisy, sekalipun mereka tinggal dua.\""},"6274":{"ar":"حَدَّثَنَا شِهَابُ بْنُ عَبَّادٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ حُمَيْدٍ عَنْ إِسْمَاعِيلَ عَنْ قَيْسٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا حَسَدَ إِلَّا فِي اثْنَتَيْنِ رَجُلٌ آتَاهُ اللَّهُ مَالًا فَسَلَّطَهُ عَلَى هَلَكَتِهِ فِي الْحَقِّ وَآخَرُ آتَاهُ اللَّهُ حِكْمَةً فَهُوَ يَقْضِي بِهَا وَيُعَلِّمُهَا","id":"Telah menceritakan kepada kami [Syihab bin Ibad] telah menceritakan kepada kami [Ibrahim bin Humaid] dari [Ismail] dari [Qais] dari [Abdullah] mengatakan, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak diperbolehkan iri kecuali dalam dua hal, seseorang yang Allah memberinya harta, lantas ia belanjakan untuk al haq, dan seseorang yang Allah beri hikmah, kemudian ia pergunakan untuk memutuskan hukum dan ia ajarkan.\""},"6275":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ عَنْ أَبِي التَّيَّاحِ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْمَعُوا وَأَطِيعُوا وَإِنْ اسْتُعْمِلَ عَلَيْكُمْ عَبْدٌ حَبَشِيٌّ كَأَنَّ رَأْسَهُ زَبِيبَةٌ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Syu'bah] dari [Abu tayyah] dari [Anas bin Malik] radliallahu 'anhu mengatakan, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dengarlah dan taatilah sekalipun yang memimpin kalian adalah seorang budak habsyi, seolah-olah kepalanya gimbal.\""},"6276":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادٌ عَنْ الْجَعْدِ عَنْ أَبِي رَجَاءٍ عَنْ ابْنِ عَبَّاسٍ يَرْوِيهِ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ رَأَى مِنْ أَمِيرِهِ شَيْئًا فَكَرِهَهُ فَلْيَصْبِرْ فَإِنَّهُ لَيْسَ أَحَدٌ يُفَارِقُ الْجَمَاعَةَ شِبْرًا فَيَمُوتُ إِلَّا مَاتَ مِيتَةً جَاهِلِيَّةً","id":"Telah menceritakan kepada kami [Sulaiman bin harb] telah menceritakan kepada kami [Hammad] dari [Al Ja'd] dari [Abu Raja'] dari [Ibnu 'Abbas] yang ia riwayatkan, mengatakan, Nabi shallallahu 'alaihi wasallam bersabda; \"Siapa yang melihat dari amirnya sesuatu yang tidak disukainya, hendaklah ia bersabar, sebab tidaklah seseorang meninggalkan jama'ah sejauh sejengkal, lantas ia meninggal dunia, melainkan ia mati jahiliyah.\""},"6277":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ حَدَّثَنِي نَافِعٌ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ السَّمْعُ وَالطَّاعَةُ عَلَى الْمَرْءِ الْمُسْلِمِ فِيمَا أَحَبَّ وَكَرِهَ مَا لَمْ يُؤْمَرْ بِمَعْصِيَةٍ فَإِذَا أُمِرَ بِمَعْصِيَةٍ فَلَا سَمْعَ وَلَا طَاعَةَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya bin Sa'id] dari ['Ubaidullah] Telah menceritakan kepadaku [Nafi'] dari [Abdullah] radliallahu 'anhu, dari Nabi shallallahu 'alaihi wasallam bersabda: \"mendengar dan taat adalah wajib bagi setiap muslim, baik yang ia sukai maupun yang tidak ia sukai, selama ia tidak diperintahkan melakukan kemaksiatan, adapun jika ia diperintahkan melakukan maksiat, maka tidak ada hak mendengar dan menaati.\""},"6278":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ حَدَّثَنَا سَعْدُ بْنُ عُبَيْدَةَ عَنْ أَبِي عَبْدِ الرَّحْمَنِ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَبَعَثَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَرِيَّةً وَأَمَّرَ عَلَيْهِمْ رَجُلًا مِنْ الْأَنْصَارِ وَأَمَرَهُمْ أَنْ يُطِيعُوهُ فَغَضِبَ عَلَيْهِمْ وَقَالَ أَلَيْسَ قَدْ أَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تُطِيعُونِي قَالُوا بَلَى قَالَ قَدْ عَزَمْتُ عَلَيْكُمْ لَمَا جَمَعْتُمْ حَطَبًا وَأَوْقَدْتُمْ نَارًا ثُمَّ دَخَلْتُمْ فِيهَا فَجَمَعُوا حَطَبًا فَأَوْقَدُوا نَارًا فَلَمَّا هَمُّوا بِالدُّخُولِ فَقَامَ يَنْظُرُ بَعْضُهُمْ إِلَى بَعْضٍ قَالَ بَعْضُهُمْ إِنَّمَا تَبِعْنَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِرَارًا مِنْ النَّارِ أَفَنَدْخُلُهَا فَبَيْنَمَا هُمْ كَذَلِكَ إِذْ خَمَدَتْ النَّارُ وَسَكَنَ غَضَبُهُ فَذُكِرَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَوْ دَخَلُوهَا مَا خَرَجُوا مِنْهَا أَبَدًا إِنَّمَا الطَّاعَةُ فِي الْمَعْرُوفِ","id":"Telah menceritakan kepada kami ['Umar bin hafs bin Ghiyats] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Al A'masy] telah menceritakan kepada kami [Sa'd bin Ubaidah] dari [Abu Abdurrahman] dari ['Ali] radliallahu 'anhu mengatakan, Nabi shallallahu 'alaihi wasallam mengutus sebuah ekspedisi dan mengangkat sahabat anshar sebagai pemimpin mereka, dan beliau perintahkan mereka untuk menaatinya. Selanjutnya sahabat anshar marah dan mengatakan; \"Bukankah Rasulullah Shallallahu'alaihiwasallam telah memerintahkan kaian untuk mentaatiku?\" 'Ya' Jawab mereka. Sahabat anshar meneruskan; \"Karena itu, aku ingin jika kalian mengumpulkan kayu bakar dan menyalakan api, kemudian kalian masuk kedalamnya.\" Mereka pun mengumpulkan kayu bakar dan menyalakan api. Tatkala mereka ingin memasukinya, satu sama lain saling memandang. Sebagian mengatakan; 'bukankah kita ikut Nabi shallallahu 'alaihi wasallam untuk menjauhkan diri dari api, apakah (sekarang) kita ingin memasukinya? ' Tatkala mereka dalam keadaan seperti itu, tiba-tiba api padam dan kemarahannya mereda. Maka hal ini disampaikan kepada Nabi shallallahu 'alaihi wasallam lantas Nabi mengatakan; \"Kalaulah mereka memasukinya, niscaya mereka tidak bisa keluar dari api tersebut selama-lamanya\"."},"6279":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ عَنْ الْحَسَنِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَمُرَةَ قَالَقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَبْدَ الرَّحْمَنِ بْنَ سَمُرَةَ لَا تَسْأَلْ الْإِمَارَةَ فَإِنَّكَ إِنْ أُعْطِيتَهَا عَنْ مَسْأَلَةٍ وُكِلْتَ إِلَيْهَا وَإِنْ أُعْطِيتَهَا عَنْ غَيْرِ مَسْأَلَةٍ أُعِنْتَ عَلَيْهَا وَإِذَا حَلَفْتَ عَلَى يَمِينٍ فَرَأَيْتَ غَيْرَهَا خَيْرًا مِنْهَا فَكَفِّرْ عَنْ يَمِينِكَ وَأْتِ الَّذِي هُوَ خَيْرٌ","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Jarir bin Hazim] dari [Al Hasan] dari [Abdurrahman bin Samurah] mengatakan, Nabi shallallahu 'alaihi wasallam berkata kepadaku: \"Wahai Abdurrahman bin Samurah, janganlah kamu meminta jabatan, sebab jika kamu diberi jabatan dengan tanpa meminta, maka kamu akan ditolong, dan jika kamu diberinya karena meminta, maka kamu akan ditelantarkan, dan jika kamu bersumpah, lantas kamu lihat ada suatu yang lebih baik, maka bayarlah kafarat sumpahmu dan lakukanlah yang lebih baik.\""},"6280":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا يُونُسُ عَنْ الْحَسَنِ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ سَمُرَةَ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَبْدَ الرَّحْمَنِ بْنَ سَمُرَةَ لَا تَسْأَلْ الْإِمَارَةَ فَإِنْ أُعْطِيتَهَا عَنْ مَسْأَلَةٍ وُكِلْتَ إِلَيْهَا وَإِنْ أُعْطِيتَهَا عَنْ غَيْرِ مَسْأَلَةٍ أُعِنْتَ عَلَيْهَا وَإِذَا حَلَفْتَ عَلَى يَمِينٍ فَرَأَيْتَ غَيْرَهَا خَيْرًا مِنْهَا فَأْتِ الَّذِي هُوَ خَيْرٌ وَكَفِّرْ عَنْ يَمِينِكَ","id":"Telah menceritakan kepada kami [Abu Ma'mar] telah menceritakan kepada kami ['Abdl Warits] telah menceritakan kepada kami [Yunus] dari [Al Hasan] mengatkan telah menceritakan kepadaku [Abdurrahman bin Samurah] mengatakan, Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Wahai Abdurrahman bin Samurah, janganlah kamu meminta jabatan, sebab jika kamu diberi jabatan dengan meminta, maka kamu akan ditelantarkan, dan jika kamu diberi dengan tanpa meminta, maka kamu akan diotolong, dan jika kamu melakukan suatu sumpah, lantas kau lihat selainnya lebih baik, maka lakukanlah yang lebih baik dan bayarlah kafarat sumpahmu.\""},"6281":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّكُمْ سَتَحْرِصُونَ عَلَى الْإِمَارَةِ وَسَتَكُونُ نَدَامَةً يَوْمَ الْقِيَامَةِ فَنِعْمَ الْمُرْضِعَةُ وَبِئْسَتْ الْفَاطِمَةُوَقَالَ مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ حُمْرَانَ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ عُمَرَ بْنِ الْحَكَمِ عَنْ أَبِي هُرَيْرَةَ قَوْلَهُ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Ibnu Abu Dzi'b] dari [Sa'id Al Maqburi] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"kalian akan rakus terhadap jabatan, padahal jabatan itu akan menjadi penyesalan dihari kiamat, ia adalah seenak-enak penyusuan dan segetir-getir penyapihan.\" [Muhamad bin Basyar] berkata; telah menceritakan kepada kami [Abdullah bin Humran] telah menceritakan kepada kami [Abdul Hamid bin Ja'far] dari [Sa'id Al Maqburi] dari [Umar bin Al Hakam] dari [Abu Hurairah] seperti diatas. "},"6282":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى رَضِيَ اللَّهُ عَنْهُ قَالَدَخَلْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا وَرَجُلَانِ مِنْ قَوْمِي فَقَالَ أَحَدُ الرَّجُلَيْنِ أَمِّرْنَا يَا رَسُولَ اللَّهِ وَقَالَ الْآخَرُ مِثْلَهُ فَقَالَ إِنَّا لَا نُوَلِّي هَذَا مَنْ سَأَلَهُ وَلَا مَنْ حَرَصَ عَلَيْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`] telah menceritakan kepada kami [Abu Usamah] dari [Buraid] dari [Abu Burdah] dari [Abu Musa] radliallahu 'anhu mengatakan; aku menemui Nabi shallallahu 'alaihi wasallam bersama dua orang kaumku, lantas satu diantara kedua orang itu mengatakan; 'Jadikanlah kami pejabat ya Rasulullah? ' orang kedua juga mengatakan yang sama. Secara spontan Rasulullah Shallallahu'alaihiwasallam bersabda; \"Kami tidak akan memberikan jabatan ini kepada orang yang memintanya, tidak juga kepada orang yang ambisi terhadapnya.\""},"6283":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا أَبُو الْأَشْهَبِ عَنْ الْحَسَنِأَنَّ عُبَيْدَ اللَّهِ بْنَ زِيَادٍ عَادَ مَعْقِلَ بْنَ يَسَارٍ فِي مَرَضِهِ الَّذِي مَاتَ فِيهِ فَقَالَ لَهُ مَعْقِلٌ إِنِّي مُحَدِّثُكَ حَدِيثًا سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ عَبْدٍ اسْتَرْعَاهُ اللَّهُ رَعِيَّةً فَلَمْ يَحُطْهَا بِنَصِيحَةٍ إِلَّا لَمْ يَجِدْ رَائِحَةَ الْجَنَّةِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Abul Asyhab] dari [Al Hasan], bahwasanya Abdullah bin Ziyad mengunjungi Ma'qil bin yasar ketika sakitnya yang menjadikan kematiannya, lantas [Ma'qil] mengatakan kepadanya; 'Saya sampaikan hadist kepadamu yang aku dengar dari Rasulullah Shallallahu'alaihiwasallam, aku mendengar Nabi shallallahu 'alaihi wasallam bersabda; \"Tidaklah seorang hamba yang Allah beri amanat kepemimpinan, namun dia tidak menindaklanjutinya dengan baik, selain tak bakalan mendapat bau surga.\""},"6284":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ مَنْصُورٍ أَخْبَرَنَا حُسَيْنٌ الْجُعْفِيُّ قَالَ زَائِدَةُ ذَكَرَهُ عَنْ هِشَامٍ عَنْ الْحَسَنِ قَالَأَتَيْنَا مَعْقِلَ بْنَ يَسَارٍ نَعُودُهُ فَدَخَلَ عَلَيْنَا عُبَيْدُ اللَّهِ فَقَالَ لَهُ مَعْقِلٌ أُحَدِّثُكَ حَدِيثًا سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا مِنْ وَالٍ يَلِي رَعِيَّةً مِنْ الْمُسْلِمِينَ فَيَمُوتُ وَهُوَ غَاشٌّ لَهُمْ إِلَّا حَرَّمَ اللَّهُ عَلَيْهِ الْجَنَّةَ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] Telah mengabarkan kepada kami [Husain Al Ju'fi], [Zaidah] mengatakan, bahwa ia menyebutkannya dari [Hisyam] dari [Al Hasan] mengatakan, kami mendatangi Ma'qil bin Yasar, lantas Ubaidullah menemui kami, lantas [Ma'qil] berujar kepadanya; Saya ceritakan hadist kepadamu yang aku mendengarnya dari Rasulullah Shallallahu'alaihiwasallam, beliau bersabda; \"Tidaklah seorang pemimpin memimpin masyarakat muslimin, lantas dia meninggal dalam keadaan menipu mereka, selain Allah mengharamkan surge baginya.\""},"6285":{"ar":"حَدَّثَنَا إِسْحَاقُ الْوَاسِطِيُّ حَدَّثَنَا خَالِدٌ عَنْ الْجُرَيْرِيِّ عَنْ طَرِيفٍ أَبِي تَمِيمَةَ قَالَشَهِدْتُ صَفْوَانَ وَجُنْدَبًا وَأَصْحَابَهُ وَهُوَ يُوصِيهِمْ فَقَالُوا هَلْ سَمِعْتَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْئًا قَالَ سَمِعْتُهُ يَقُولُ مَنْ سَمَّعَ سَمَّعَ اللَّهُ بِهِ يَوْمَ الْقِيَامَةِ قَالَ وَمَنْ يُشَاقِقْ يَشْقُقْ اللَّهُ عَلَيْهِ يَوْمَ الْقِيَامَةِ فَقَالُوا أَوْصِنَا فَقَالَ إِنَّ أَوَّلَ مَا يُنْتِنُ مِنْ الْإِنْسَانِ بَطْنُهُ فَمَنْ اسْتَطَاعَ أَنْ لَا يَأْكُلَ إِلَّا طَيِّبًا فَلْيَفْعَلْ وَمَنْ اسْتَطَاعَ أَنْ لَا يُحَالَ بَيْنَهُ وَبَيْنَ الْجَنَّةِ بِمِلْءِ كَفِّهِ مِنْ دَمٍ أَهْرَاقَهُ فَلْيَفْعَلْقُلْتُ لِأَبِي عَبْدِ اللَّهِ مَنْ يَقُولُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جُنْدَبٌ قَالَ نَعَمْ جُنْدَبٌ","id":"Telah menceritakan kepada kami [Ishaq Al Wasithi] telah menceritakan kepada kami [Khalid] dari [Al Jurairi] dari [Tharif Abu Tamimah] mengatakan, aku menghadiri Shafwan dan [Jundab] serta sahabat-sahabatnya ketika Jundab memberi wasiat kepada mereka, lantas mereka bertanya; 'Apakah kau mendengar sesuatu dari Rasulullah Shallallahu'alaihiwasallam? ' Ia menjawab; aku mendengar beliau bersabda: \"Barangsiapa beramal karena sum'ah (ingin didengar), maka Allah menjadikannya dikenal suka bersum'ah pada hari kiamat, dan barangsiapa menyusahkan (manusia), maka Allah juga bakalan menyusahkannya pada hari kiamat.\" mereka berkata; \"Wasiatilah kami!\" ia berkata; 'Yang pertama-tama membusuk dari tubuh manusia adalah perut, maka barangsiapa yang mampu untuk tidak menyantap selain yang baik, lakukanlah, dan barangsiapa tidak ingin dihalangi antara dirinya dan surga karena segenggam darah yang ia tumpahkan, lakukanlah.' Saya bertanya kepada Abu Abdillah; 'Siapa yang mengatakan aku mendengar Rasulullah Shallallahu'alaihiwasallam, apakah Jundab? ' ia menjawab; \"Iya, Jundab.\""},"6286":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَبَيْنَمَا أَنَا وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَارِجَانِ مِنْ الْمَسْجِدِ فَلَقِيَنَا رَجُلٌ عِنْدَ سُدَّةِ الْمَسْجِدِ فَقَالَ يَا رَسُولَ اللَّهِ مَتَى السَّاعَةُ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَعْدَدْتَ لَهَا فَكَأَنَّ الرَّجُلَ اسْتَكَانَ ثُمَّ قَالَ يَا رَسُولَ اللَّهِ مَا أَعْدَدْتُ لَهَا كَبِيرَ صِيَامٍ وَلَا صَلَاةٍ وَلَا صَدَقَةٍ وَلَكِنِّي أُحِبُّ اللَّهَ وَرَسُولَهُ قَالَ أَنْتَ مَعَ مَنْ أَحْبَبْتَ","id":"Telah menceritakan kepada kami [Ustman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Salim bin Abul Ja'd] telah menceritakan kepada kami [Anas bin Malik] radliallahu 'anhu, ia mengatakan, ketika aku dan Nabi shallallahu 'alaihi wasallam keluar dari masjid, kami menemui seseorang di gerbang masjid dan ia bertanya; 'Ya Rasulullah, kapan hari kiamat tiba? ' Nabi shallallahu 'alaihi wasallam menjawab; \"apa yang telah kau persiapkan?\" Rupanya orang tadi berusaha menenangkan diri lantas mengatakan; 'Ya Rasulullah, saya tidak mempersiapkannya dengan banyak puasa, banyak shalat dan banyak sedekah, hanya aku cinta Allah dan rasul-NYA, ' maka Nabi bersabda; 'Engkau bersama orang yang kau cintai'."},"6287":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ مَنْصُورٍ أَخْبَرَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا ثَابِتٌ الْبُنَانِيُّ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍيَقُولُ لِامْرَأَةٍ مِنْ أَهْلِهِ تَعْرِفِينَ فُلَانَةَ قَالَتْ نَعَمْ قَالَ فَإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِهَا وَهِيَ تَبْكِي عِنْدَ قَبْرٍ فَقَالَ اتَّقِي اللَّهَ وَاصْبِرِي فَقَالَتْ إِلَيْكَ عَنِّي فَإِنَّكَ خِلْوٌ مِنْ مُصِيبَتِي قَالَ فَجَاوَزَهَا وَمَضَى فَمَرَّ بِهَا رَجُلٌ فَقَالَ مَا قَالَ لَكِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ مَا عَرَفْتُهُ قَالَ إِنَّهُ لَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَجَاءَتْ إِلَى بَابِهِ فَلَمْ تَجِدْ عَلَيْهِ بَوَّابًا فَقَالَتْ يَا رَسُولَ اللَّهِ وَاللَّهِ مَا عَرَفْتُكَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الصَّبْرَ عِنْدَ أَوَّلِ صَدْمَةٍ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] Telah mengabarkan kepada kami [Abdushshamad] Telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Tsabit Al Bunani] mengatakan, aku mendengar [Anas bin Malik] berkata kepada seorang wanita dari keluarganya; 'Apakah kamu kenal si wanita A? ' 'Tahu' Jawabnya. Anas melanjutkan; sesungguhnya Nabi shallallahu 'alaihi wasallam pernah melewati wanita itu saat ia menangis di suatu kuburan, lantas beliau menasehatinya: 'Bertakwalah kepada Allah, dan bersabarlah! ' Si wanita itu malah menjawab; 'Sana kau menjauh, sebab kamu tidak mengalami seperti musibahku ini! ' Kata Anas, Nabi pun segera menjauh dan pergi. Lantas ada seseorang yang melewati wanita itu seraya mengatakan; 'Apa yang disabdakan Rasulullah kepadamu? ' Si wanita tadi menjawab; 'Saya tidak tahu kalau orang tadi Rasulullah.' laki-laki itu mengatakan; \"Orang tadi itu Rasulullah.!\" Anas berkata; si wanita terus datang ke pintu rumah Nabi dan ia tidak menemukan seorang penjaga pintunya, lantas mengatakan; 'Wahai Rasulullah, Demi Allah, aku mengenalmu! ' Lantas Nabi shallallahu 'alaihi wasallam bersabda; \"Kesabaran itu terlihat pada saat pertama kali benturan.\""},"6288":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ خَالِدٍ الذُّهْلِيُّ حَدَّثَنَا الْأَنْصَارِيُّ مُحَمَّدُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي أَبِي عَنْ ثُمَامَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَإِنَّ قَيْسَ بْنَ سَعْدٍ كَانَ يَكُونُ بَيْنَ يَدَيْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَنْزِلَةِ صَاحِبِ الشُّرَطِ مِنْ الْأَمِيرِ","id":"Telah menceritakan kepada kami [Muhammad bin Khalid Adz Dzuhli] telah menceritakan kepada kami [Al Anshari, Muhammad bin Abdullah] mengatakan; telah menceritakan kepadaku [Ayahku] dari [Tsumamah] dari [Anas bin Malik], ia mengatakan, bahwasa Qais bin Sa'd pernah di hadapan Nabi shallallahu 'alaihi wasallam seperti halnya seorang ajudan dengan pemimpin."},"6289":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى هُوَ الْقَطَّانُ عَنْ قُرَّةَ بْنِ خَالِدٍ حَدَّثَنِي حُمَيْدُ بْنُ هِلَالٍ حَدَّثَنَا أَبُو بُرْدَةَ عَنْ أَبِي مُوسَىأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَهُ وَأَتْبَعَهُ بِمُعَاذٍ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya alias Al Qaththan] dari [Qurrah bin Khalid] telah menceritakan kepadaku [Humaid bin Hilal] dari [Abu Burdah] dari [Abu Musa], bahwasanya Nabi shallallahu 'alaihi wasallam pernah mengutusnya kemudian mengutus Mu'adz sebagai penyusulnya."},"6290":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ الصَّبَّاحِ حَدَّثَنَا مَحْبُوبُ بْنُ الْحَسَنِ حَدَّثَنَا خَالِدٌ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَىأَنَّ رَجُلًا أَسْلَمَ ثُمَّ تَهَوَّدَ فَأَتَى مُعَاذُ بْنُ جَبَلٍ وَهُوَ عِنْدَ أَبِي مُوسَى فَقَالَ مَا لِهَذَا قَالَ أَسْلَمَ ثُمَّ تَهَوَّدَ قَالَ لَا أَجْلِسُ حَتَّى أَقْتُلَهُ قَضَاءُ اللَّهِ وَرَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepadaku [Abdullah bin Shabah] telah menceritakan kepada kami [Mahbub bin Al Hasan] telah menceritakan kepada kami [Khalid] dari [Humaid bin Hilal] dari [Abu Burdah] dari [Abu Musa], ada seorang laki-laki masuk Islam kemudian masuk agama yahudi, lantas ia mendatangi Mu'adz bin Jabal yang ketika itu ia berada di dekat Abu Musa, maka Abu Musa bertanya: 'Memangnya kenapa orang ini? ' Mu'adz bin Jabal menjawab: 'orang ini masuk Islam, namun kemudian masuk agama yahudi.\" Spontan Abu Musa mengatakan; \"saya tidak sudi duduk hingga aku membunuhnya sebagai ketetapan Allah dan rasul-Nya Shallallahu'alaihiwasallam."},"6291":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عُمَيْرٍ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ أَبِي بَكْرَةَ قَالَ كَتَبَ أَبُو بَكْرَةَإِلَى ابْنِهِ وَكَانَ بِسِجِسْتَانَ بِأَنْ لَا تَقْضِيَ بَيْنَ اثْنَيْنِ وَأَنْتَ غَضْبَانُ فَإِنِّي سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَقْضِيَنَّ حَكَمٌ بَيْنَ اثْنَيْنِ وَهُوَ غَضْبَانُ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] Telah menceritakan kepada kami [Abdul Malik bin Umair], aku mendengar [Abdurrahman bin Abu Bakrah] mengatakan, [Abu Bakrah] menulis surat untuk anaknya yang ketika itu berada di Sijistan yang isinya; 'Jangan engkau mengadili diantara dua orang ketika engkau marah, sebab aku mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Seorang hakim dilarang memutuskan antara dua orang ketika marah.\""},"6292":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا إِسْمَاعِيلُ بْنُ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ أَبِي مَسْعُودٍ الْأَنْصَارِيِّ قَالَجَاءَ رَجُلٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي وَاللَّهِ لَأَتَأَخَّرُ عَنْ صَلَاةِ الْغَدَاةِ مِنْ أَجْلِ فُلَانٍ مِمَّا يُطِيلُ بِنَا فِيهَا قَالَ فَمَا رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَطُّ أَشَدَّ غَضَبًا فِي مَوْعِظَةٍ مِنْهُ يَوْمَئِذٍ ثُمَّ قَالَ يَا أَيُّهَا النَّاسُ إِنَّ مِنْكُمْ مُنَفِّرِينَ فَأَيُّكُمْ مَا صَلَّى بِالنَّاسِ فَلْيُوجِزْ فَإِنَّ فِيهِمْ الْكَبِيرَ وَالضَّعِيفَ وَذَا الْحَاجَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil] Telah mengabarkan kepada kami [Abdullah] Telah mengabarkan kepada kami [Ismail bin Abu Khalid] dari [Qais bin Abu hazim] dari [Abu Mas'ud Al Anshari] mengatakan, seorang laki-laki menemui Rasulullah Shallallahu'alaihiwasallam dan berujar; \"Hai Rasulullah, Demi Allah, sungguh saya memperlambat-lambatkan diri dari shalat subuh karena si fulan yang menjadi imam, ia selalu memanjangkan bacaan shalatnya jika shalat bersama kami.\" Abu mas'ud Kata; belum pernah kulihat Nabi shallallahu 'alaihi wasallam sedemikian marahnya seperti ketika beliau menasehatinya. Lantas Nabi menegur; \"Hai manusia, diantara kalian ada yang menjadikan orang lain menjauhkan diri dari (masjid dan ibadah), siapa diantara kalian mengimami orang-orang, lakukanlah secara ringkas (sederhana), sebab disana ada orang-orang tua, orang lemah dan orang yang mempunyai keperluan.\""},"6293":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي يَعْقُوبَ الْكَرْمَانِيُّ حَدَّثَنَا حَسَّانُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا يُونُسُ قَالَ حَدَّثَنَا مُحَمَّدٌ هُوَ الزُّهْرِيُّ أَخْبَرَنِي سَالِمٌ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ أَخْبَرَهُأَنَّهُ طَلَّقَ امْرَأَتَهُ وَهِيَ حَائِضٌ فَذَكَرَ عُمَرُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَغَيَّظَ عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ لِيُرَاجِعْهَا ثُمَّ لِيُمْسِكْهَا حَتَّى تَطْهُرَ ثُمَّ تَحِيضَ فَتَطْهُرَ فَإِنْ بَدَا لَهُ أَنْ يُطَلِّقَهَا فَلْيُطَلِّقْهَا","id":"Telah menceritakan kepada kami [Muhammad bin Abu Ya'qub Al Karmani] telah menceritakan kepada kami [Hassan bin Ibrahim] telah menceritakan kepada kami [Yunus] mengatakan, telah menceritakan kepada kami [Muhammad yaitu Az Zuhri] telah mengabarkan kepadaku [Salim], bahwasanya [Abdullah bin Umar] mengabarkan kepadanya, ia pernah menceraikan isterinya ketika haidh, lantas Umar melaporkan kasusnya kepada Nabi shallallahu 'alaihi wasallam, Rasulullah Shallallahu'alaihiwasallam pun sedemikian marah karenanya kemudian bersabda: \"Suruhlah dia merujuknya, kemudian mempertahankannya hingga suci, kemudian haidh lagi, kemudian suci, lantas jika ia berkehendak menceriakannya, ceraikanlah!\""},"6294":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ حَدَّثَنِي عُرْوَةُ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْجَاءَتْ هِنْدٌ بِنْتُ عُتْبَةَ بْنِ رَبِيعَةَ فَقَالَتْ يَا رَسُولَ اللَّهِ وَاللَّهِ مَا كَانَ عَلَى ظَهْرِ الْأَرْضِ أَهْلُ خِبَاءٍ أَحَبَّ إِلَيَّ أَنْ يَذِلُّوا مِنْ أَهْلِ خِبَائِكَ وَمَا أَصْبَحَ الْيَوْمَ عَلَى ظَهْرِ الْأَرْضِ أَهْلُ خِبَاءٍ أَحَبَّ إِلَيَّ أَنْ يَعِزُّوا مِنْ أَهْلِ خِبَائِكَ ثُمَّ قَالَتْ إِنَّ أَبَا سُفْيَانَ رَجُلٌ مِسِّيكٌ فَهَلْ عَلَيَّ مِنْ حَرَجٍ أَنْ أُطْعِمَ مِنْ الَّذِي لَهُ عِيَالَنَا قَالَ لَهَا لَا حَرَجَ عَلَيْكِ أَنْ تُطْعِمِيهِمْ مِنْ مَعْرُوفٍ","id":"Telah menceritakan kepada kami [Abul Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] telah mengabarkan kepada kami ['Urwah] bahwasanya [Aisyah] radliallahu 'anha mengatakan, Hindun binti Utbah bin Rabi'ah datang dan berujar; 'Wahai Rasulullah, dahulu tidak ada penghuni rumah diatas bumi yang lebih saya sukai untuk dihinakan selain penghuni rumahmu, kebalikannya sekarang, tidak ada penghuni rumah diatas bumi yang lebih saya sukai untuk dimuliakan selain penghuni rumahmu, ' kemudian Hindun binti Utbah mengatakan; 'Sesungguhnya abu Sufyan orangnya sangat pelit, apakah saya berdosa jika memberi makan orang-orang yang menjadi tanggungan kami (dengan mengambil hartanya tanpa sepengetahuannya?) ' Nabi menjawab: \"tidak masalah kau memberi makanan untuk mereka, asalkan dengan ma'ruf (cara wajar).\""},"6295":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَلَمَّا أَرَادَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَكْتُبَ إِلَى الرُّومِ قَالُوا إِنَّهُمْ لَا يَقْرَءُونَ كِتَابًا إِلَّا مَخْتُومًا فَاتَّخَذَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَاتَمًا مِنْ فِضَّةٍ كَأَنِّي أَنْظُرُ إِلَى وَبِيصِهِ وَنَقْشُهُ مُحَمَّدٌ رَسُولُ اللَّهِ","id":"Telah menceritakan kepadaku [Muhammad bin Basyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] mengatakan, aku mendengar [Qatadah] dari [Anas bin Malik] mengatakan, Dikala Nabi shallallahu 'alaihi wasallam ingin berkirim surat kepada Romawi, mereka ternyata manusia yang tak mau membaca surat selain harus berstempel, maka Nabi shallallahu 'alaihi wasallam membuat stempel dari perak, seolah-olah aku melihat kilauannya dan ukirannya bertuliskan MUHAMMAD RASULULLAH."},"6296":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ أَخْبَرَنِي السَّائِبُ بْنُ يَزِيدَ ابْنُ أُخْتِ نَمِرٍ أَنَّ حُوَيْطِبَ بْنَ عَبْدِ الْعُزَّى أَخْبَرَهُ أَنَّ عَبْدَ اللَّهِ بْنَ السَّعْدِيِّ أَخْبَرَهُ أَنَّهُ قَدِمَ عَلَى عُمَرَفِي خِلَافَتِهِ فَقَالَ لَهُ عُمَرُ أَلَمْ أُحَدَّثْ أَنَّكَ تَلِيَ مِنْ أَعْمَالِ النَّاسِ أَعْمَالًا فَإِذَا أُعْطِيتَ الْعُمَالَةَ كَرِهْتَهَا فَقُلْتُ بَلَى فَقَالَ عُمَرُ فَمَا تُرِيدُ إِلَى ذَلِكَ قُلْتُ إِنَّ لِي أَفْرَاسًا وَأَعْبُدًا وَأَنَا بِخَيْرٍ وَأُرِيدُ أَنْ تَكُونَ عُمَالَتِي صَدَقَةً عَلَى الْمُسْلِمِينَ قَالَ عُمَرُ لَا تَفْعَلْ فَإِنِّي كُنْتُ أَرَدْتُ الَّذِي أَرَدْتَ فَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعْطِينِي الْعَطَاءَ فَأَقُولُ أَعْطِهِ أَفْقَرَ إِلَيْهِ مِنِّي حَتَّى أَعْطَانِي مَرَّةً مَالًا فَقُلْتُ أَعْطِهِ أَفْقَرَ إِلَيْهِ مِنِّي فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُذْهُ فَتَمَوَّلْهُ وَتَصَدَّقْ بِهِ فَمَا جَاءَكَ مِنْ هَذَا الْمَالِ وَأَنْتَ غَيْرُ مُشْرِفٍ وَلَا سَائِلٍ فَخُذْهُ وَإِلَّا فَلَا تُتْبِعْهُ نَفْسَكَوَعَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ قَالَ سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ يَقُولُ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعْطِينِي الْعَطَاءَ فَأَقُولُ أَعْطِهِ أَفْقَرَ إِلَيْهِ مِنِّي حَتَّى أَعْطَانِي مَرَّةً مَالًا فَقُلْتُ أَعْطِهِ مَنْ هُوَ أَفْقَرُ إِلَيْهِ مِنِّي فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُذْهُ فَتَمَوَّلْهُ وَتَصَدَّقْ بِهِ فَمَا جَاءَكَ مِنْ هَذَا الْمَالِ وَأَنْتَ غَيْرُ مُشْرِفٍ وَلَا سَائِلٍ فَخُذْهُ وَمَالَا فَلَا تُتْبِعْهُ نَفْسَكَ","id":"Telah menceritakan kepada kami [Abul Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] telah mengabarkan kepadaku [As Sa'ib bin Yazid bin Ukhti Namir], bahwa [Khuwaitib bin Abdul 'uzza] mengabarkan kepadanya, bahwa [Abdullah bin As Sa'di] mengabarkan kepadanya, ia pernah mendatangi Umar dimasa-masa pemerintahannya. [Umar] lantas berujar; \"Benarkan berita yang sampai kepadaku bahwa engkau mengurus urusan-urusan sosial, namun jika engkau diberi pesangon (uang lelah) engkau tidak menyukainya?\" Saya jawab \"Iya\". Umar lantas mengatakan; \"lalu maumu apa?\" Saya menjawab; \"Saya sudah punya kuda sekian banyak, demikian pula budak ada beberapa, dan aku dalam keadaan baik (mapan secara ekonomi), maka aku niati kerjaku ini sebagai sedekah (amal cuma-cuma) untuk kaum muslimin.\" Umar spontan mengatakan: 'jangan kau lakukan, saya sebenarnya juga ingin seperti kehendakmu, namun Rasulullah Shallallahu'alaihiwasallam juga memberiku pemberian, tetapi saya katakan; 'Coba berikan saja pemberian itu kepada orang yang lebih membutuhkan daripada aku! ' Kemudian hari, Nabi juga memberi pemberian yang sama kemudian aku katakan; 'Tolong berikan kepada orang yang lebih membutuhkan daripada aku! ' Lantas Nabi shallallahu 'alaihi wasallam bersabda; \"Ambil saja, kembangkan harta ini, dan jadikanlah untuk bersedekah, harta ini yang datang kepadamu dengan cara yang tidak berlebihan dan engkau sendiri tidak meminta, maka ambil saja, dan terhadap harta, janganlah nafsumu kau perturutkan terhadapnya!\" Dan dari [Az Zuhri] berkata; telah menceritakan kepadaku [Salim bin Abdullah] bahwa [Abdullah bin Umar] berkata; saya telah mendengar [Umar bin Khattab] berkata; Nabi shallallahu 'alaihi wasallam memberikan suatu pemberian kepadaku, lalu saya berkata; Berikan kepada orang yang lebih fakir daripadaku, sehingga pada suatu saat beliau memberi lagi dan saya jawab sebagaimana sebelumnya. Lantas Nabi shallallahu 'alaihi wasallam bersabda: \"Ambillah! kembangkan harta ini, dan jadikanlah untuk bersedekah, harta ini yang datang kepadamu dengan cara yang tidak berlebihan dan engkau sendiri tidak meminta, maka ambil saja, dan terhadap harta, janganlah nafsumu kau perturutkan terhadapnya!\""},"6297":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ الزُّهْرِيُّ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَشَهِدْتُ الْمُتَلَاعِنَيْنِ وَأَنَا ابْنُ خَمْسَ عَشْرَةَ سَنَةً وَفُرِّقَ بَيْنَهُمَا","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Sufyan], [Az Zuhri] mengatakan dari [Sahal bin Sa'd], ia mengatakan; aku pernah menyaksikan dua orang yang melakukan li'an ketika umurku masih lima belas tahun, maka kedua orang itu diceraikan. "},"6298":{"ar":"حَدَّثَنَا يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي ابْنُ شِهَابٍ عَنْ سَهْلٍ أَخِي بَنِي سَاعِدَةَأَنَّ رَجُلًا مِنْ الْأَنْصَارِ جَاءَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَرَأَيْتَ رَجُلًا وَجَدَ مَعَ امْرَأَتِهِ رَجُلًا أَيَقْتُلُهُ فَتَلَاعَنَا فِي الْمَسْجِدِ وَأَنَا شَاهِدٌ","id":"Telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Abdurrazaq] Telah mengabarkan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku [Ibnu Syihab] dari [Sahal saudara Bani Sa'idah], seorang laki-laki anshar menemui Nabi shallallahu 'alaihi wasallam dan berujar; \"bagaimana pendapat anda sekiranya seseorang menemukan laki-laki lain bersama isterinya? Bolehkah ia membunuhnya?\" Suami-isteri itu kemudian sama-sama meli'an dan aku menyaksikan."},"6299":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنِي اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ وَسَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَأَتَى رَجُلٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي الْمَسْجِدِ فَنَادَاهُ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي زَنَيْتُ فَأَعْرَضَ عَنْهُ فَلَمَّا شَهِدَ عَلَى نَفْسِهِ أَرْبَعًا قَالَ أَبِكَ جُنُونٌ قَالَ لَا قَالَ اذْهَبُوا بِهِ فَارْجُمُوهُقَالَ ابْنُ شِهَابٍ فَأَخْبَرَنِي مَنْ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ قَالَ كُنْتُ فِيمَنْ رَجَمَهُ بِالْمُصَلَّى رَوَاهُ يُونُسُ وَمَعْمَرٌ وَابْنُ جُرَيْجٍ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الرَّجْمِ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepadaku [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari [Abu Salamah] dan [Sa'id bin Musayyab] dari [Abu Hurairah] mengatakan; Seorang laki-laki menemui Rasulullah Shallallahu'alaihiwasallam ketika beliau di masjid. Orang itu memanggil beliau seraya mengatakan; 'Hai Rasulullah, saya telah berzina! ' tetapi Rasulullah berpaling darinya. Tatkala kesaksiannya sampai empat kali, Nabi bertanya: \"Mungkin engkau gila?\" \"TIDAK\" Jawabnya. Lantas Nabi bersabda: \"Bawalah orang ini, dan rajamlah!\" [Ibnu Syihab] mengatakan, dan telah menceritakan kepadaku [orang yang] mendengar [Jabir bin Abdullah] mengatakan; 'Aku termasuk diantara yang merajamnya di tanah lapang.' [Yunus], [Ma'mar] dan [Ibnu Juraij] meriwayatkannya dari [Az Zuhri] dari [Abu Salamah] dari [Jabir] dari Nabi shallallahu 'alaihi wasallam."},"6300":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ زَيْنَبَ بِنْتِ أَبِي سَلَمَةَ عَنْ أُمِّ سَلَمَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا أَنَا بَشَرٌ وَإِنَّكُمْ تَخْتَصِمُونَ إِلَيَّ وَلَعَلَّ بَعْضَكُمْ أَنْ يَكُونَ أَلْحَنَ بِحُجَّتِهِ مِنْ بَعْضٍ فَأَقْضِي عَلَى نَحْوِ مَا أَسْمَعُ فَمَنْ قَضَيْتُ لَهُ مِنْ حَقِّ أَخِيهِ شَيْئًا فَلَا يَأْخُذْهُ فَإِنَّمَا أَقْطَعُ لَهُ قِطْعَةً مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Hisyam] dari [ayahnya] dari [Zainab binti Abu Salamah] dari [Ummu Salamah] radliallahu 'anha, Rasulullah Shallallahu'alaihiwasallam bersabda; \"Saya hanyalah manusia biasa, dan kalian seringkali mengadukan sengketa kepadaku, bisa jadi sebagian diantara kalian lebih pandai bersilat lidah daripada lainnya sehingga aku putuskan seperti yang kudengar, maka barangsiapa yang kuputuskan menang dengan menganiaya hak saudaranya, janganlah ia mengambilnya, sebab sama artinya aku ambilkan sundutan api baginya.\""},"6301":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ يَحْيَى عَنْ عُمَرَ بْنِ كَثِيرٍ عَنْ أَبِي مُحَمَّدٍ مَوْلَى أَبِي قَتَادَةَ أَنَّ أَبَا قَتَادَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ حُنَيْنٍ مَنْ لَهُ بَيِّنَةٌ عَلَى قَتِيلٍ قَتَلَهُ فَلَهُ سَلَبُهُ فَقُمْتُ لِأَلْتَمِسَ بَيِّنَةً عَلَى قَتِيلِي فَلَمْ أَرَ أَحَدًا يَشْهَدُ لِي فَجَلَسْتُ ثُمَّ بَدَا لِي فَذَكَرْتُ أَمْرَهُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَجُلٌ مِنْ جُلَسَائِهِ سِلَاحُ هَذَا الْقَتِيلِ الَّذِي يَذْكُرُ عِنْدِي قَالَ فَأَرْضِهِ مِنْهُ فَقَالَ أَبُو بَكْرٍ كَلَّا لَا يُعْطِهِ أُصَيْبِغَ مِنْ قُرَيْشٍ وَيَدَعَ أَسَدًا مِنْ أُسْدِ اللَّهِ يُقَاتِلُ عَنْ اللَّهِ وَرَسُولِهِ قَالَ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَدَّاهُ إِلَيَّ فَاشْتَرَيْتُ مِنْهُ خِرَافًا فَكَانَ أَوَّلَ مَالٍ تَأَثَّلْتُهُقَالَ لِي عَبْدُ اللَّهِ عَنْ اللَّيْثِ فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَدَّاهُ إِلَيَّ وَقَالَ أَهْلُ الْحِجَازِ الْحَاكِمُ لَا يَقْضِي بِعِلْمِهِ شَهِدَ بِذَلِكَ فِي وِلَايَتِهِ أَوْ قَبْلَهَا وَلَوْ أَقَرَّ خَصْمٌ عِنْدَهُ لِآخَرَ بِحَقٍّ فِي مَجْلِسِ الْقَضَاءِ فَإِنَّهُ لَا يَقْضِي عَلَيْهِ فِي قَوْلِ بَعْضِهِمْ حَتَّى يَدْعُوَ بِشَاهِدَيْنِ فَيُحْضِرَهُمَا إِقْرَارَهُ وَقَالَ بَعْضُ أَهْلِ الْعِرَاقِ مَا سَمِعَ أَوْ رَآهُ فِي مَجْلِسِ الْقَضَاءِ قَضَى بِهِ وَمَا كَانَ فِي غَيْرِهِ لَمْ يَقْضِ إِلَّا بِشَاهِدَيْنِ وَقَالَ آخَرُونَ مِنْهُمْ بَلْ يَقْضِي بِهِ لِأَنَّهُ مُؤْتَمَنٌ وَإِنَّمَا يُرَادُ مِنْ الشَّهَادَةِ مَعْرِفَةُ الْحَقِّ فَعِلْمُهُ أَكْثَرُ مِنْ الشَّهَادَةِ وَقَالَ بَعْضُهُمْ يَقْضِي بِعِلْمِهِ فِي الْأَمْوَالِ وَلَا يَقْضِي فِي غَيْرِهَا وَقَالَ الْقَاسِمُ لَا يَنْبَغِي لِلْحَاكِمِ أَنْ يُمْضِيَ قَضَاءً بِعِلْمِهِ دُونَ عِلْمِ غَيْرِهِ مَعَ أَنَّ عِلْمَهُ أَكْثَرُ مِنْ شَهَادَةِ غَيْرِهِ وَلَكِنَّ فِيهِ تَعَرُّضًا لِتُهَمَةِ نَفْسِهِ عِنْدَ الْمُسْلِمِينَ وَإِيقَاعًا لَهُمْ فِي الظُّنُونِ وَقَدْ كَرِهَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظَّنَّ فَقَالَ إِنَّمَا هَذِهِ صَفِيَّةُ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits bin Sa'd] dari [Yahya] dari ['Umar bin katsir] dari [Abu Muhammad, maula Abu Qatadah] mengatakan, Rasulullah shallallahu 'alaihi wasallam bersabda pada perang Hunain: \"Barangsiapa mempunyai bukti atas korban yang dibunuh dalam perang, maka ia mendapat harta rampasan yang dibawanya.\" maka aku (Abu Qatadah) langsung berdiri untuk mencari bukti-bukti atas musuh yang telah kubunuh, ternyata tidak aku temukan seorang pun yang menyaksikan pembunuhanku. Maka aku duduk, dan aku punya inisiatif untuk mengadukan persoalanku kepada Rasulullah Shallallahu'alaihi wa sallam. Lantas seorang teman duduknya mengatakan: 'Senjata orang yang dibunuh yang selalu disebut-sebut oleh [Abu Qatadah] itu ada padaku? ' Orang tadi meneruskan; 'Tolong suruhlah Abu Qatadah merelakannya untukku! ' Maka Abu Bakar menyela; 'Sekali-kali tidak, tidak mungkin Rasulullah Shallallahu'alaihi wa sallam memberikan rampasan itu untuk kamu si burung pipit, dan ia tinggalkan salah satu singa Allah (maksudnya Abu Qatadah) yang ia berperang untuk Allah dan rasul-Nya.' Lantas Rasulullah Shallallahu'alaihiwasallam memberikan rampasan itu untukku, dan selanjutnya kubelikan seekor gibas. Dan itulah harta pertama-tama yang kukembangkan. [Abdullah] mengatakan kepadaku, dari [Al Laits], lantas Nabi shallallahu 'alaihi wasallam berdiri dan memberikannya untukku. Ulama Hejaz berpendapat; Seorang hakim tak berhak memutuskan keputusan hanya dengan sepengetahuannya yang ia persaksikan ketika melakukan sidang atau sebelumnya, sekalipun yang digugat mengakui bahwa hak memang milik lawan sengketanya di majlis sidang. Sebagian mereka berkomentar bahwa ia tak berhak memutuskannya hingga memanggil dua orang saksi yang kemudian si hakim mengungkapkan keputusannya. Sedang ulama Irak berpendapat, apa yang ia dengar atau yang ia lihat di majlis sidang, hakim memutuskan dengannya, adapun jika di luar majlis sidang, ia tidak boleh memutuskan selain dengan memanggil dua orang saksi. Sedang kelompok lain dari mereka berpendapat 'Sekalipun diluar sidang, tetap ia putuskan (dengan tanpa memanggil dua orang saksi), sebab hakim adalah orang yang terpercaya, dan maksud persaksian adalah sekedar untuk mengetahui kebenaran, padahal ilmu sang hakim jauh lebih banyak daripada persaksian lainnya, namun yang demikian membuka dirinya menjadi sasaran tuduhan di kalangan muslimin dan menjerumuskan mereka dalam prasangka, (padahal Nabi Shallallahu 'alaihi sangat tidak menyukai prasangka, sebagaimana prasangka buruk kedua sahabatnya ketika nabi shallallahu 'alaihi wasallam berjalan dengan seorang perempuan, lantas nabi langsung memangkas prasangka keduanya dengan mengatakan: \"ketahuilah, wanita itu Shafiyyah, (isteriku).\""},"6302":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ الْأُوَيْسِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ عَلِيِّ بْنِ حُسَيْنٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَتْهُ صَفِيَّةُ بِنْتُ حُيَيٍّ فَلَمَّا رَجَعَتْ انْطَلَقَ مَعَهَا فَمَرَّ بِهِ رَجُلَانِ مِنْ الْأَنْصَارِ فَدَعَاهُمَا فَقَالَ إِنَّمَا هِيَ صَفِيَّةُ قَالَا سُبْحَانَ اللَّهِ قَالَ إِنَّ الشَّيْطَانَ يَجْرِي مِنْ ابْنِ آدَمَ مَجْرَى الدَّمِرَوَاهُ شُعَيْبٌ وَابْنُ مُسَافِرٍ وَابْنُ أَبِي عَتِيقٍ وَإِسْحَاقُ بْنُ يَحْيَى عَنْ الزُّهْرِيِّ عَنْ عَلِيٍّ يَعْنِي ابْنَ حُسَيْنٍ عَنْ صَفِيَّةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abdul 'Aziz bin Abdullah Al Uwaisi] telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Ibnu Syihab] dari ['Ali bin Husain], Nabi shallallahu 'alaihi wasallam kedatangan Shafiyyah bin Huyyai, tatkala Shafiyyah pulang, Beliau pulang bersamanya, lantas ada dua laki-laki Anshar melewati beliau, maka beliau panggil dua laki-laki itu dan mengatakan: \"Hanyasanya ia Shafiyyah binti Huyyai.\" Maka kedua laki-laki tadi mengucapkan \"SUBHANAALLAH\". Nabi mengatakan 'sesungguhnya setan mengalir dalam anak adam dalam aliran darahnya. hadist ini diriwayatkan oleh [Syu'aib], [Ibnu Musafir], [Ibnu 'Atiq], dan [Ishaq bin Yahya] dari [Az Zuhri] dari [Ali maksudnya Ali bin Husain] dari [Shafiyyah] dari Nabi shallallahu 'alaihi wasallam."},"6303":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا الْعَقَدِيُّ حَدَّثَنَا شُعْبَةُ عَنْ سَعِيدِ بْنِ أَبِي بُرْدَةَ قَالَ سَمِعْتُ أَبِي قَالَبَعَثَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبِي وَمُعَاذَ بْنَ جَبَلٍ إِلَى الْيَمَنِ فَقَالَ يَسِّرَا وَلَا تُعَسِّرَا وَبَشِّرَا وَلَا تُنَفِّرَا وَتَطَاوَعَا فَقَالَ لَهُ أَبُو مُوسَى إِنَّهُ يُصْنَعُ بِأَرْضِنَا الْبِتْعُ فَقَالَ كُلُّ مُسْكِرٍ حَرَامٌوَقَالَ النَّضْرُ وَأَبُو دَاوُدَ وَيَزِيدُ بْنُ هَارُونَ وَوَكِيعٌ عَنْ شُعْبَةَ عَنْ سَعِيدِ بْنِ أَبِي بُرْدَةَ عَنْ أَبِيهِ عَنْ جَدِّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Al 'Aqdi] telah menceritakan kepada kami [Syu'bah] dari [Sa'id bin Abu Burdah] mengatakan, aku mendengar [Ayahku] mengatakan; Nabi shallallahu 'alaihi wasallam mengutus ayahku dan Mu'adz bin Jabal ke Yaman, Nabi berpesan: \"Hendaknya kalian berdua mempermudah, jangan mempersulit, memberi kabar gembira, tidak menjadikan orang menjauh, dan bersatu padulah!\" Lantas Abu Musa mengatakan kepadanya; \"Di daerah kami sering dibuat fermentasi kurma (Albit'u).\" Mu'adz menjawab; \"setiap yang memabukkan adalah haram.\" Sedang [Abu Nadhr], [Abu Daud], [Yazid bin harun] dan [Waki'] mengatakan dari [Syu'bah] dari [Sa'id bin Abu Burdah] dari [ayahnya] dari [kakeknya], dari Nabi shallallahu 'alaihi wasallam."},"6304":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سُفْيَانَ حَدَّثَنِي مَنْصُورٌ عَنْ أَبِي وَائِلٍ عَنْ أَبِي مُوسَىعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فُكُّوا الْعَانِيَ وَأَجِيبُوا الدَّاعِيَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sufyan] telah menceritakan kepadaku [Manshur] dari [Abu Wa`il] dari [Abu Musa] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Bebaskanlah para tawanan, dan penuhilah orang yang mengundang.\""},"6305":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ أَنَّهُ سَمِعَ عُرْوَةَ أَخْبَرَنَا أَبُو حُمَيْدٍ السَّاعِدِيُّ قَالَاسْتَعْمَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا مِنْ بَنِي أَسْدٍ يُقَالُ لَهُ ابْنُ الْأُتَبِيَّةِ عَلَى صَدَقَةٍ فَلَمَّا قَدِمَ قَالَ هَذَا لَكُمْ وَهَذَا أُهْدِيَ لِي فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمِنْبَرِ قَالَ سُفْيَانُ أَيْضًا فَصَعِدَ الْمِنْبَرَ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ مَا بَالُ الْعَامِلِ نَبْعَثُهُ فَيَأْتِي يَقُولُ هَذَا لَكَ وَهَذَا لِي فَهَلَّا جَلَسَ فِي بَيْتِ أَبِيهِ وَأُمِّهِ فَيَنْظُرُ أَيُهْدَى لَهُ أَمْ لَا وَالَّذِي نَفْسِي بِيَدِهِ لَا يَأْتِي بِشَيْءٍ إِلَّا جَاءَ بِهِ يَوْمَ الْقِيَامَةِ يَحْمِلُهُ عَلَى رَقَبَتِهِ إِنْ كَانَ بَعِيرًا لَهُ رُغَاءٌ أَوْ بَقَرَةً لَهَا خُوَارٌ أَوْ شَاةً تَيْعَرُ ثُمَّ رَفَعَ يَدَيْهِ حَتَّى رَأَيْنَا عُفْرَتَيْ إِبْطَيْهِ أَلَا هَلْ بَلَّغْتُ ثَلَاثًاقَالَ سُفْيَانُ قَصَّهُ عَلَيْنَا الزُّهْرِيُّ وَزَادَ هِشَامٌ عَنْ أَبِيهِ عَنْ أَبِي حُمَيْدٍ قَالَ سَمِعَ أُذُنَايَ وَأَبْصَرَتْهُ عَيْنِي وَسَلُوا زَيْدَ بْنَ ثَابِتٍ فَإِنَّهُ سَمِعَهُ مَعِي وَلَمْ يَقُلْ الزُّهْرِيُّ سَمِعَ أُذُنِي{ خُوَارٌ }صَوْتٌ وَالْجُؤَارُ مِنْ{ تَجْأَرُونَ }كَصَوْتِ الْبَقَرَةِ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Sufyan] dari [Az Zuhri], ia mendengar ['Urwah] telah mengabarkan kepada kami, [Abu Humaid assa'idi] mengtakan, Pernah Nabi shallallahu 'alaihi wasallam mempekerjakan seseorang dari bani Asad yang namanya Ibnul Utbiyah untuk menggalang dana sedekah. Orang itu datang sambil mengatakan; \"Ini bagimu, dan ini hadiah bagiku.\" Secara spontan Nabi shallallahu 'alaihi wasallam berdiri diatas minbar -sedang Sufyan mengatakan dengan redaksi; 'naik minbar-, beliau memuja dan memuji Allah kemudian bersabda; \"ada apa dengan seorang amil zakat yang kami utus, lalu ia datang dengan mengatakan; ini untukmu dan ini hadiah untukku! Cabalah ia duduk saja di rumah ayahnya atau rumah ibunya, dan cermatilah, apakah ia menerima hadiah ataukah tidak? Demi Dzat yang jiwaku berada di tangan-NYA, tidaklah seorang amil zakat membawa sesuatu dari harta zakat, selain ia memikulnya pada hari kiamat diatas tengkuknya, jikalau unta, maka unta itu mendengus, dan jika sapi, ia melenguh, dan jika kambing, ia mengembik, \" kemudian beliau mengangkat kedua tangannya sehingga kami melihat putih kedua ketiaknya seraya mengatakan: \" ketahuilah, bukankah telah kusampaikan?\" (beliau mengulang-ulanginya tiga kali). Sedang [Sufyan] mengatakan; [Az Zuhri] telah mengisahkannya kepada kami, dan [Hisyam] menambahkan dari [ayahnya] dari [Abu Humaid] mengatakan; 'kedua telingaku mendengar dan mataku melihatnya, ' dan mereka menanyakan kepada Zaid bin Tsabit bahwasanya ia mendengarnya bersamaku, sedang Az Zuhri tidak mengatakan; 'telingaku mendengar lenguh'."},"6306":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ صَالِحٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي ابْنُ جُرَيْجٍ أَنَّ نَافِعًا أَخْبَرَهُ أَنَّ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا أَخْبَرَهُ قَالَكَانَ سَالِمٌ مَوْلَى أَبِي حُذَيْفَةَ يَؤُمُّ الْمُهَاجِرِينَ الْأَوَّلِينَ وَأَصْحَابَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَسْجِدِ قُبَاءٍ فِيهِمْ أَبُو بَكْرٍ وَعُمَرُ وَأَبُو سَلَمَةَ وَزَيْدٌ وَعَامِرُ بْنُ رَبِيعَةَ","id":"Telah menceritakan kepada kami [Ustman bin Shalih] telah menceritakan kepada kami [Abdullah bin Wahb] telah mengabarkan kepadaku [Ibnu Juraij], bahwasanya [Nafi'] mengabarinya, bahwa [Ibnu Umar] radliallahu 'anhuma mengabarinya, Salim maula Abu hudzaifah pernah mengimami orang-orang muhajirin kalangan pertama dan sahabat Nabi shallallahu 'alaihi wasallam di masjid, padahal ditengah-tengah mereka ada Abu bakar, Umar, Abu Salamah, Zaid, dan Amir bin Rabi'ah."},"6307":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ أَبِي أُوَيْسٍ حَدَّثَنِي إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ عَنْ عَمِّهِ مُوسَى بْنِ عُقْبَةَ قَالَ ابْنُ شِهَابٍ حَدَّثَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ مَرْوَانَ بْنَ الْحَكَمِ وَالْمِسْوَرَ بْنَ مَخْرَمَةَ أَخْبَرَاهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ حِينَ أَذِنَ لَهُمْ الْمُسْلِمُونَ فِي عِتْقِ سَبْيِ هَوَازِنَ إِنِّي لَا أَدْرِي مَنْ أَذِنَ مِنْكُمْ مِمَّنْ لَمْ يَأْذَنْ فَارْجِعُوا حَتَّى يَرْفَعَ إِلَيْنَا عُرَفَاؤُكُمْ أَمْرَكُمْ فَرَجَعَ النَّاسُ فَكَلَّمَهُمْ عُرَفَاؤُهُمْ فَرَجَعُوا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرُوهُ أَنَّ النَّاسَ قَدْ طَيَّبُوا وَأَذِنُوا","id":"Telah menceritakan kepada kami [Ismail bin Abu uwais] telah menceritakan kepadaku [Ismail bin Ibrahim] dari [pamannya, Musa bin 'Uqbah], [Ibnu Syihab] mengatakan, telah menceritakan kepadaku [Urwah bin Zubair] bahwasanya [Marwan bin Hakam] dan [Miswar bin mahkramah] keduanya mengabarkan kepadanya, bahwa Rasulullah Shallallahu'alaihiwasallam bersabda ketika sebagian kaum muslimin mengizinkan tawanan Hawazin dibebaskan; \"Saya tidak tahu siapa diantara kaian yang mengizinkan dan siapa yang tidak, maka kembalilah kalian hingga orang-orang yang cerdik diantara kalian mengadukan kepadaku.\" Lantas para sahabat kembali dan orang-orang cendekia mereka mengajak dialog internal, lantas mereka kembali menemui Rasulullah Shallallahu'alaihiwasallam dan memberitahukan kepada beliau bahwa semua sahabat lega dan mengizinkan."},"6308":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا عَاصِمُ بْنُ مُحَمَّدِ بْنِ زَيْدِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ أَبِيهِ قَالَ أُنَاسٌ لِابْنِ عُمَرَإِنَّا نَدْخُلُ عَلَى سُلْطَانِنَا فَنَقُولُ لَهُمْ خِلَافَ مَا نَتَكَلَّمُ إِذَا خَرَجْنَا مِنْ عِنْدِهِمْ قَالَ كُنَّا نَعُدُّهَا نِفَاقًا","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami ['Ashim bin Muhammad bin Zaid bin Abdullah bin Umar] dari [ayahnya], Beberapa orang berkata kepada Ibnu Umar; 'dahulu jika kami menemui penguasa kami, kami mengatakan sesuatu yang menyelisihi pembicaraan kami ketika kami telah meninggalkannya.' Maka [Ibnu Umar] berkata; \"yang demikian kami anggap suatu kemunafikan.\""},"6309":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ عِرَاكٍ عَنْ أَبِي هُرَيْرَةَ أَنَّهُسَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ شَرَّ النَّاسِ ذُو الْوَجْهَيْنِ الَّذِي يَأْتِي هَؤُلَاءِ بِوَجْهٍ وَهَؤُلَاءِ بِوَجْهٍ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abu Hubaib] dari [Irak] dari [Abu Hurairah], ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Manusia yang paling buruk adalah yang bermuka dua (OPORTUNIS), yang mendatangi kaum dengan muka tertentu dan mendatangi lainnya dengan muka yang lain.\""},"6310":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ هِنْدًا قَالَتْ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَبَا سُفْيَانَ رَجُلٌ شَحِيحٌ فَأَحْتَاجُ أَنْ آخُذَ مِنْ مَالِهِ قَالَ خُذِي مَا يَكْفِيكِ وَوَلَدَكِ بِالْمَعْرُوفِ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] Telah mengabarkan kepada kami [Sufyan] dari [Hisyam] dari [ayahnya] dari [Aisyah] radliallahu 'anha, Hindun binti Utbah berkata kepada Nabi shallallahu 'alaihi wasallam; \"Abu Sufyan itu orangnya sangat pelit, maka aku perlu mengambil hartanya (tanpa sepengetahuannya)!\" Nabi menjawab: \"ambillah yang mencukupimu dan anak-anakmu dengan cara yang ma'ruf (wajar)!\""},"6311":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ زَيْنَبَ بِنْتَ أَبِي سَلَمَةَ أَخْبَرَتْهُ أَنَّ أُمَّ سَلَمَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَتْهَاعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ سَمِعَ خُصُومَةً بِبَابِ حُجْرَتِهِ فَخَرَجَ إِلَيْهِمْ فَقَالَ إِنَّمَا أَنَا بَشَرٌ وَإِنَّهُ يَأْتِينِي الْخَصْمُ فَلَعَلَّ بَعْضَكُمْ أَنْ يَكُونَ أَبْلَغَ مِنْ بَعْضٍ فَأَحْسِبُ أَنَّهُ صَادِقٌ فَأَقْضِي لَهُ بِذَلِكَ فَمَنْ قَضَيْتُ لَهُ بِحَقِّ مُسْلِمٍ فَإِنَّمَا هِيَ قِطْعَةٌ مِنْ النَّارِ فَلْيَأْخُذْهَا أَوْ لِيَتْرُكْهَا","id":"Telah menceritakan kepada kami [Abdul Aziz bin Abdullah] telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Salih] dari [Ibnu Syihab] mengatakan, [Urwah bin Zubair] mengabarkan kepadaku, bahwasanya [Zainab binti Abu Salamah] mengabarkan kepadanya, bahwa [Ummu Salamah isteri Nabi shallallahu 'alaihi wasallam] mengabarinya dari Rasulullah shallallahu 'alaihi wasallam; Beliau mendengar pertengkaran di pintu kamarnya, spontan beliau keluar menemui mereka dan mengatakan; \"Saya hanyalah manusia biasa seperti kalian, dan aku mendapatkan pengaduan, siapa tahu diantara kalian lebih pandai bersilat lidah daripada yang lain, sehingga aku menyangka dirinya benar (padahal tidak), lalu aku putuskan untuknya, maka barangsiapa kuputuskan menang dengan melanggar hak saudaranya semuslim, sama artinya aku mengambilkan suluh api baginya, maka silahkan ia ambil atau ia tinggalkan!\""},"6312":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهَا قَالَتْكَانَ عُتْبَةُ بْنُ أَبِي وَقَّاصٍ عَهِدَ إِلَى أَخِيهِ سَعْدِ بْنِ أَبِي وَقَّاصٍ أَنَّ ابْنَ وَلِيدَةِ زَمْعَةَ مِنِّي فَاقْبِضْهُ إِلَيْكَ فَلَمَّا كَانَ عَامُ الْفَتْحِ أَخَذَهُ سَعْدٌ فَقَالَ ابْنُ أَخِي قَدْ كَانَ عَهِدَ إِلَيَّ فِيهِ فَقَامَ إِلَيْهِ عَبْدُ بْنُ زَمْعَةَ فَقَالَ أَخِي وَابْنُ وَلِيدَةِ أَبِي وُلِدَ عَلَى فِرَاشِهِ فَتَسَاوَقَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ سَعْدٌ يَا رَسُولَ اللَّهِ ابْنُ أَخِي كَانَ عَهِدَ إِلَيَّ فِيهِ وَقَالَ عَبْدُ بْنُ زَمْعَةَ أَخِي وَابْنُ وَلِيدَةِ أَبِي وُلِدَ عَلَى فِرَاشِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ لَكَ يَا عَبْدُ بْنَ زَمْعَةَ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوَلَدُ لِلْفِرَاشِ وَلِلْعَاهِرِ الْحَجَرُ ثُمَّ قَالَ لِسَوْدَةَ بِنْتِ زَمْعَةَ احْتَجِبِي مِنْهُ لِمَا رَأَى مِنْ شَبَهِهِ بِعُتْبَةَ فَمَا رَآهَا حَتَّى لَقِيَ اللَّهَ تَعَالَى","id":"Telah menceritakan kepada kami [Ismail] mengatakan, telah menceritakan kepadaku [Malik] dari [Ibnu Syihab] dari ['Urwah bin Zubair] dari [Aisyah, isteri Nabi shallallahu 'alaihi wasallam] mengatakan, Utbah bin Abu Waqqash melimpahkan kuasa kepada saudaranya, Sa'd bin Abu waqqash yang isinya; 'anak laki-laki dari budak perempuan Zam'ah adalah bagian dariku (anakku), maka tolong ambillah.' Tatkala penaklukan Mekah, maka Sa'd mengambilnya dengan mengatakan; 'Ini adalah anak laki-laki saudaraku, ia telah melimpahkan urusan tentangnya kepadaku.' Spontan Abd bin Zam'ah berdiri menghadapinya seraya berujar; 'Bahkan ia adalah saudaraku dan anak laki-laki dari hamba sahaya ayahku, ia dilahirkan di kasurnya, ' keduanya lantas melaporkan kasusnya kepada Rasulullah Shallallahu'alaihiwasallam. Sa'd bin Abu Waqqash kemudian mengatakan; 'Hai Rasulullah, ia adalah anak laki-laki saudaraku yang telah ia limpahkan wewenangnya kepadaku.' Abd bin Zam'ah tak mau kalah seraya mengatakan; 'Bahkan ia adalah saudaraku, dan anak laki-laki dari hamba sahaya ayahku, ia dilahirkan di kasurnya.' Lantas Rasulullah Shallallahu'alaihiwasallam bersabda; \"dia milkmu wahai Abd bin Zam'ah, \" kemudian Rasulullah Shallallahu'alaihiwasallam bersabda: \"Anak adalah pemilik ranjang, dan pezina harus dihukum dengan batu (rajam), \" kemudian beliau bersabda kepada Saudah binti Zam'ah: \"Berhijablah engkau daripadanya!\" karena ada kemiripannya dengan Utbah, sehingga anak laki-laki dari hamba sahaya Zam'ah itu tidak melihat Saudah selama-lamanya."},"6313":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ نَصْرٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا سُفْيَانُ عَنْ مَنْصُورٍ وَالْأَعْمَشِ عَنْ أَبِي وَائِلٍ قَالَ قَالَ عَبْدُ اللَّهِقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَحْلِفُ عَلَى يَمِينِ صَبْرٍ يَقْتَطِعُ مَالًا وَهُوَ فِيهَا فَاجِرٌ إِلَّا لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُ فَأَنْزَلَ اللَّهُ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا }الْآيَةَفَجَاءَ الْأَشْعَثُ وَعَبْدُ اللَّهِ يُحَدِّثُهُمْ فَقَالَ فِيَّ نَزَلَتْ وَفِي رَجُلٍ خَاصَمْتُهُ فِي بِئْرٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَكَ بَيِّنَةٌ قُلْتُ لَا قَالَ فَلْيَحْلِفْ قُلْتُ إِذًا يَحْلِفُ فَنَزَلَتْ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ }الْآيَةَ","id":"Telah menceritakan kepada kami [Ishaq bin Nashr] telah menceritakan kepada kami [Abdurrazaq] Telah mengabarkan kepada kami [Sufyan] dari [Manshur] dan [Al A'masy] dari [Abu Wa'il] mengatakan, [Abdullah] mengatakan, Nabi shallallahu 'alaihi wasallam bersabda; \"Tidaklah seseorang bersumpah dusta dengan tujuan merampas harta orang lain dan dia bertindak zhalim dengan sumpahnya itu, kecuali ia akan bertemu Allah dan Allah dalam keadaan murka terhadapnya, \" kemudian Allah menurunkan ayat 'Sesungguhnya orang-orang yang membeli janji Allah dan sumpah mereka dengan harga yang sedikit' (QS. Ali'Imran.77), kemudian [Al Asy'ats] datang ketika [Abdullah] sedang menceritakan kepada mereka, dan mengatakan; sebenarnya ayat itu diturunkan kepada saya dan seseorang yang kuajak bersengketa tentang sebuah sumur, kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"apa kamu punya bukti?\" \"TIDAK\" Jawabku. Nabi bersabda: \"kalau begitu, suruhlah lawan sengketamu bersumpah!\" maka Abdullah mengatakan; 'Kalau bukti sekedar sumpah, tentu dia akan bersumpah. Lantas turunlah ayat: 'Sesungguhnya orang-orang yang membeli janji Allah dan sumpah mereka dengan harga yang sedikit….sampai akhir ayat ' (QS. Ali'Imran.77) "},"6314":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ زَيْنَبَ بِنْتَ أَبِي سَلَمَةَ أَخْبَرَتْهُ عَنْ أُمِّهَا أُمِّ سَلَمَةَ قَالَتْسَمِعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَلَبَةَ خِصَامٍ عِنْدَ بَابِهِ فَخَرَجَ عَلَيْهِمْ فَقَالَ إِنَّمَا أَنَا بَشَرٌ وَإِنَّهُ يَأْتِينِي الْخَصْمُ فَلَعَلَّ بَعْضًا أَنْ يَكُونَ أَبْلَغَ مِنْ بَعْضٍ أَقْضِي لَهُ بِذَلِكَ وَأَحْسِبُ أَنَّهُ صَادِقٌ فَمَنْ قَضَيْتُ لَهُ بِحَقِّ مُسْلِمٍ فَإِنَّمَا هِيَ قِطْعَةٌ مِنْ النَّارِ فَلْيَأْخُذْهَا أَوْ لِيَدَعْهَا","id":"Telah menceritakan kepada kami [Abul Yaman] Telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] telah mengabarkan kepadaku [Urwah bin Zubair] bahwasanya [Zainab binti Abu Salamah] mengabarkannya dari ibunya, [Ummu Salamah] mengatakan; Pernah Nabi shallallahu 'alaihi wasallam mendengar gaduh percekcokan di pintunya, lantas beliau menemui mereka dengan mengatakan; \"Saya hanyalah manusia biasa seperti kalian, dan sengketa diadukan kepadaku, dan bisa jadi diantara kalian ada yang lebih pandai bersilat lidah daripada yang lain sehingga aku memenangkannya dan aku mengira dirinya yang benar, maka siapa yang kumenangkan dengan melanggar hak muslim lainnya, itu adalah sundutan api, silahkan ia mengambil atau tinggalkan!\""},"6315":{"ar":"حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا سَلَمَةُ بْنُ كُهَيْلٍ عَنْ عَطَاءٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَبَلَغَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ رَجُلًا مِنْ أَصْحَابِهِ أَعْتَقَ غُلَامًا لَهُ عَنْ دُبُرٍ لَمْ يَكُنْ لَهُ مَالٌ غَيْرَهُ فَبَاعَهُ بِثَمَا��ِ مِائَةِ دِرْهَمٍ ثُمَّ أَرْسَلَ بِثَمَنِهِ إِلَيْهِ","id":"Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [Muhammad bin Bisyr] telah menceritakan kepada kami [Ismail] telah menceritakan kepada kami [Salamah bin Kuhail] dari ['Atho`] dari [Jabir bin Abdullah] mengatakan, Nabi Shallallahu'alaihiwasallam mendengar informasi ada seorang sahabat membebaskan budaknya dengan cara mudabbar, padahal ia tidak punya harta selainnya, lantas Nabi membelinya seharga delapan ratus dirham, kemudian beliau kirimkan hasilnya kepadanya. "},"6316":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُسْلِمٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دِينَارٍ قَالَ سَمِعْتُ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْثًا وَأَمَّرَ عَلَيْهِمْ أُسَامَةَ بْنَ زَيْدٍ فَطُعِنَ فِي إِمَارَتِهِ وَقَالَ إِنْ تَطْعَنُوا فِي إِمَارَتِهِ فَقَدْ كُنْتُمْ تَطْعَنُونَ فِي إِمَارَةِ أَبِيهِ مِنْ قَبْلِهِ وَايْمُ اللَّهِ إِنْ كَانَ لَخَلِيقًا لِلْإِمْرَةِ وَإِنْ كَانَ لَمِنْ أَحَبِّ النَّاسِ إِلَيَّ وَإِنَّ هَذَا لَمِنْ أَحَبِّ النَّاسِ إِلَيَّ بَعْدَهُ","id":"Telah menceritakan kepada kami [Musa bin ismail] telah menceritakan kepada kami [Abdul Aziz bin Muslim] telah menceritakan kepada kami [Abdullah bin dinar] mengatakan, aku mendengar [Ibnu Umar] radliallahu 'anhuma mengatakan; Rasulullah Shallallahu'alaihiwasallam mengutus sebuah ekspedisi dan mengangkat Usamah bin Zaid sebagai panglimanya, kemudian kepemimpinannya dicela habis-habisan oleh para sahabat ketika itu, maka Nabi langsung menegur; \"Jikalau kalian mencela kepemimpinanya, dahulu kalian juga mencela kepemimpinan bapaknya, demi Allah, dia sangat ideal memegang kepemimpinan, dan sungguh ayahnya (Zaid bin haritsah) termasuk manusia yang paling kucintai, dan dia (Usamah bin Zaid) termasuk manusia yang paling kucintai sepeninggalnya.\""},"6317":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ ابْنِ جُرَيْجٍ سَمِعْتُ ابْنَ أَبِي مُلَيْكَةَ يُحَدِّثُ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبْغَضُ الرِّجَالِ إِلَى اللَّهِ الْأَلَدُّ الْخَصِمُ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ibnu Juraij], aku mendengar [Ibnu Abu Mulaikah] menceritakan dari [Aisyah] radliallahu 'anha, ia mengatakan; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Manusia yang paling dibenci Allah adalah yang keras kepala dan suka membantah.\""},"6318":{"ar":"حَدَّثَنَا مَحْمُودٌ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ بَعَثَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَالِدًا ح و حَدَّثَنِي أَبُو عَبْدِ اللَّهِ نُعَيْمُ بْنُ حَمَّادٍ حَدَّثَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَبَعَثَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَالِدَ بْنَ الْوَلِيدِ إِلَى بَنِي جَذِيمَةَ فَلَمْ يُحْسِنُوا أَنْ يَقُولُوا أَسْلَمْنَا فَقَالُوا صَبَأْنَا صَبَأْنَا فَجَعَلَ خَالِدٌ يَقْتُلُ وَيَأْسِرُ وَدَفَعَ إِلَى كُلِّ رَجُلٍ مِنَّا أَسِيرَهُ فَأَمَرَ كُلَّ رَجُلٍ مِنَّا أَنْ يَقْتُلَ أَسِيرَهُ فَقُلْتُ وَاللَّهِ لَا أَقْتُلُ أَسِيرِي وَلَا يَقْتُلُ رَجُلٌ مِنْ أَصْحَابِي أَسِيرَهُ فَذَكَرْنَا ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اللَّهُمَّ إِنِّي أَبْرَأُ إِلَيْكَ مِمَّا صَنَعَ خَالِدُ بْنُ الْوَلِيدِ مَرَّتَيْنِ","id":"Telah menceritakan kepada kami [Mahmud] telah menceritakan kepada kami [Abdurrazaq] Telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Salim] dari [Ibnu Umar], Nabi shallallahu 'alaihi wasallam mengutus Khalid -lewat jalur periwayatan lain-Dan telah menceritakan kepadaku [Abu Abdullah Nu'aim bin Hammad] telah menceritakan kepada kami [Abdullah] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Salim] dari [Ayahnya], mengatakan, Nabi shallallahu 'alaihi wasallam mengutus Khalid bin Al Walid ke Bani Judzaimah yang lidah mereka belum fasih mengucapkan ASLAMNAA (kami masuk Islam), sehingga mereka ucapkan; 'ASHBA'NA' (yang arti secara harfiah kami menganut agama shabiiyah, padahal maksud mereka ASLAMNA), sehingga Khalid terus membunuh dan menawan dan menyerahkan tawanannya kepada masing-maing kami, dan menyuruh masing-masing kami untuk membunuhnya, maka kukatakan; 'demi Allah, saya tak akan membunuh tawananku, ' dan tak seorang pun sahabatku membunuh tawanannya. Maka kasus ini kulaporkan kepada Nabi shallallahu 'alaihi wasallam dan beliau berujar; \"ya Allah, sesungguhnya aku berlepas diri kepadamu dari apa yang dilakukan Khalid bin Walid\" (beliau ulangi ucapannya dua kali)."},"6319":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادٌ حَدَّثَنَا أَبُو حَازِمٍ الْمَدَنِيُّ عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّ قَالَكَانَ قِتَالٌ بَيْنَ بَنِي عَمْرٍو فَبَلَغَ ذَلِكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى الظُّهْرَ ثُمَّ أَتَاهُمْ يُصْلِحُ بَيْنَهُمْ فَلَمَّا حَضَرَتْ صَلَاةُ الْعَصْرِ فَأَذَّنَ بِلَالٌ وَأَقَامَ وَأَمَرَ أَبَا بَكْرٍ فَتَقَدَّمَ وَجَاءَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ فِي الصَّلَاةِ فَشَقَّ النَّاسَ حَتَّى قَامَ خَلْفَ أَبِي بَكْرٍ فَتَقَدَّمَ فِي الصَّفِّ الَّذِي يَلِيهِ قَالَ وَصَفَّحَ الْقَوْمُ وَكَانَ أَبُو بَكْرٍ إِذَا دَخَلَ فِي الصَّلَاةِ لَمْ يَلْتَفِتْ حَتَّى يَفْرُغَ فَلَمَّا رَأَى التَّصْفِيحَ لَا يُمْسَكُ عَلَيْهِ الْتَفَتَ فَرَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَلْفَهُ فَأَوْمَأَ إِلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِهِ أَنْ امْضِهْ وَأَوْمَأَ بِيَدِهِ هَكَذَا وَلَبِثَ أَبُو بَكْرٍ هُنَيَّةً يَحْمَدُ اللَّهَ عَلَى قَوْلِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ مَشَى الْقَهْقَرَى فَلَمَّا رَأَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَلِكَ تَقَدَّمَ فَصَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالنَّاسِ فَلَمَّا قَضَى صَلَاتَهُ قَالَ يَا أَبَا بَكْرٍ مَا مَنَعَكَ إِذْ أَوْمَأْتُ إِلَيْكَ أَنْ لَا تَكُونَ مَضَيْتَ قَالَ لَمْ يَكُنْ لِابْنِ أَبِي قُحَافَةَ أَنْ يَؤُمَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ لِلْقَوْمِ إِذَا رَابَكُمْ أَمْرٌ فَلْيُسَبِّحْ الرِّجَالُ وَلْيُصَفِّحْ النِّسَاءُ","id":"Telah menceritakan kepada kami [Abu Nu'man] telah menceritakan kepada kami [Hammad] telah menceritakan kepada kami [Abu Hazim Al Madani] dari [Sahal bin Sa'd As Sa'idi] mengatakan; ketika terjadi peperangan antara bani 'Amru, berita ini sampai kepada Nabi Shallallahu'alaihiwasallam, maka beliau shalat zhuhur kemudian mendatangi mereka untuk mendamaikan sesama mereka. Tatkala tiba shalat ashar, Bilal mengumandangkan adzan dan iqamat. Lantas beliau perintahkan Abu bakar untuk mengimami orang-orang. Ia pun maju mengimami. Selanjutnya Nabi shallallahu 'alaihi wasallam datang sedang Abu Bakar tengah mengimami. Nabi menerobos barisan hingga berdiri di belakang Abu Bakar, dan terus melaju hingga tepat di shaff (barisan) setelah Abu Bakar. Kata Sahal, saat itulah para sahabat menepukkan tangan kanannya diatas punggung lengan kiri (tashfiih) sebagai pertanda Rasul di belakangnya. Adalah kebiasaan Abu bakar jika telah menunaikan shalat, ia tidak menolah-noleh hingga selesai, maka tatkala beliau melihat tashfih terus dilakukan tanpa henti, dia menoleh dan melihat Nabi shallallahu 'alaihi wasallam berada di belakangnya. Nabi shallallahu 'alaihi wasallam memberi isyarat kepadanya agar meneruskan shalatnya dengan tangannya dan mengisyaratkan dengan tangannya sedemikian. Abu Bakar meneruskan shalat beberapa saat, memuji Allah atas ucapan Nabi shallallahu 'alaihi wasallam, kemudian dia berjalan mundur, dikala Nabi shallallahu 'alaihi wasallam melihat yang demikian, Nabi maju dan mengimami orang-orang. Selesai beliau menunaikan shalatnya, beliau mengatakan: \"Hai Abu bakar, apa yang menghalangimu ketika aku memberi isyarat kepadamu, namun engkau malah tidak melanjutkannya?\" Abu bakar menjawab; \"Tidak pantas bagi Ibnu Abu Quhafah mengimami Nabi shallallahu 'alaihi wasallam.\" Kemudian Nabi bersabda kepada para sahabat: \"Jika kalian ragu ketika shalat, hendaklah yang laki-laki mengucapkan tasbih, sedang jika perempuan menepukkan tangan (tashfiih).\""},"6320":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدِ اللَّهِ أَبُو ثَابِتٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ بْنِ السَّبَّاقِ عَنْ زَيْدِ بْنِ ثَابِتٍ قَالَبَعَثَ إِلَيَّ أَبُو بَكْرٍ لِمَقْتَلِ أَهْلِ الْيَمَامَةِ وَعِنْدَهُ عُمَرُ فَقَالَ أَبُو بَكْرٍ إِنَّ عُمَرَ أَتَانِي فَقَالَ إِنَّ الْقَتْلَ قَدْ اسْتَحَرَّ يَوْمَ الْيَمَامَةِ بِقُرَّاءِ الْقُرْآنِ وَإِنِّي أَخْشَى أَنْ يَسْتَحِرَّ الْقَتْلُ بِقُرَّاءِ الْقُرْآنِ فِي الْمَوَاطِنِ كُلِّهَا فَيَذْهَبَ قُرْآنٌ كَثِيرٌ وَإِنِّي أَرَى أَنْ تَأْمُرَ بِجَمْعِ الْقُرْآنِ قُلْتُ كَيْفَ أَفْعَلُ شَيْئًا لَمْ يَفْعَلْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ عُمَرُ هُوَ وَاللَّهِ خَيْرٌ فَلَمْ يَزَلْ عُمَرُ يُرَاجِعُنِي فِي ذَلِكَ حَتَّى شَرَحَ اللَّهُ صَدْرِي لِلَّذِي شَرَحَ لَهُ صَدْرَ عُمَرَ وَرَأَيْتُ فِي ذَلِكَ الَّذِي رَأَى عُمَرُ قَالَ زَيْدٌ قَالَ أَبُو بَكْرٍ وَإِنَّكَ رَجُلٌ شَابٌّ عَاقِلٌ لَا نَتَّهِمُكَ قَدْ كُنْتَ تَكْتُبُ الْوَحْيَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَتَبَّعْ الْقُرْآنَ فَاجْمَعْهُ قَالَ زَيْدٌ فَوَاللَّهِ لَوْ كَلَّفَنِي نَقْلَ جَبَلٍ مِنْ الْجِبَالِ مَا كَانَ بِأَثْقَلَ عَلَيَّ مِمَّا كَلَّفَنِي مِنْ جَمْعِ الْقُرْآنِ قُلْتُ كَيْفَ تَفْعَلَانِ شَيْئًا لَمْ يَفْعَلْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو بَكْرٍ هُوَ وَاللَّهِ خَيْرٌ فَلَمْ يَزَلْ يَحُثُّ مُرَاجَعَتِي حَتَّى شَرَحَ اللَّهُ صَدْرِي لِلَّذِي شَرَحَ اللَّهُ لَهُ صَدْرَ أَبِي بَكْرٍ وَعُمَرَ وَرَأَيْتُ فِي ذَلِكَ الَّذِي رَأَيَا فَتَتَبَّعْتُ الْقُرْآنَ أَجْمَعُهُ مِنْ الْعُسُبِ وَالرِّقَاعِ وَاللِّخَافِ وَصُدُورِ الرِّجَالِ فَوَجَدْتُ فِي آخِرِ سُورَةِ التَّوْبَةِ{ لَقَدْ جَاءَكُمْ رَسُولٌ مِنْ أَنْفُسِكُمْ }إِلَى آخِرِهَا مَعَ خُزَيْمَةَ أَوْ أَبِي خُزَيْمَةَ فَأَلْحَقْتُهَا فِي سُورَتِهَا وَكَانَتْ الصُّحُفُ عِنْدَ أَبِي بَكْرٍ حَيَاتَهُ حَتَّى تَوَفَّاهُ اللَّهُ عَزَّ وَجَلَّ ثُمَّ عِنْدَ عُمَرَ حَيَاتَهُ حَتَّى تَوَفَّاهُ اللَّهُ ثُمَّ عِنْدَ حَفْصَةَ بِنْتِ عُمَرَقَالَ مُحَمَّدُ بْنُ عُبَيْدِ اللَّهِ اللِّخَافُ يَعْنِي الْخَزَفَ","id":"Telah menceritakan kepada kami [Muhammad bin Ubaidullah] Abu Tsabit, telah menceritakan kepada kami [Ibrahim bin sa'd] dari [Ibnu Syihab] dari [Ubaid bin Sibaq] dari [Zaid bin tsabit] mengatakan, Abu bakar mengutus seseorang menemuiku karena banyaknya korban yang gugur pada perang Yamamah, ketika itu Abu bakar bersama Umar. Abu Bakar berkata; 'Umar mendatangiku dan mengatakan; 'Korban perang telah meluas pada perang yamamah hingga merenggut qurra` (penghafal) alquran, dan saya khawatir jangan-jangan dengan meninggalnya qurra` alquran di banyak tempat, mengakibatkan sekian banyak ayat quran akan menghilang, dan saya berpendapat jika engkau perintahkan untuk mengumpulkan alquran.' Maka Saya menjawab; 'bagaimana aku lakukan sesuatu yang belum pernah Rasulullah lakukan? ' Umar kontan mengemukakan pendapatnya; 'Demi Allah, ini adalah suatu kebaikan, ' Umar tiada henti-hentinya mendorongku untuk melakukan pekerjaan ini, hingga Allah melapangkan dadaku untuk melakukan pekerjaan yang dada Umar telah lebih dahulu dilapangkan terhadapnya, dan aku sependapat dengan pendapat Umar.' Zaid mengatakan, Abu Bakar berkata; 'Sungguh engkau adalah laki-laki yang masih muda, cerdas, dan kami sama sekali tidak menyangsikan kemampuanmu, sebab engkau sudah terbiasa menulis wahyu untuk Rasulullah. Maka susurilah alquran (yang masih terpencar-pencar) dan kumpulkanlah.' Maka Zaid menjawab; \"Demi Allah, sekiranya Abu bakar menugasiku untuk memindahkan sebuah gunung, itu tidak lebih berat bagiku daripada menugasiku untuk menghimpun alquran. Maka aku berkata; 'Bagaimana mungkin anda berdua melakukan sesuatu yang tidak pernah di lakukan Rasulullah Shallallahu'alaihiwasallam? ' Abu Bakar menjawab; 'demi Alllah, pekerjaan ini adalah kebaikan.' Tiada henti-hentinya Abu Bakar memotivasi pertimbanganku hingga Allah melapangkan dadaku untuk melakukan suatu hal yang Allah telah melapangkan dada Abu Bakar dan Umar untuk melakukannya. Dan aku sependapat dengan keduanya, maka kutelusuri alquran yang terpencar-pencar dan kuhimpun dari pelepah, kulit, tembikar, tulang dan dada para penghapal, dan kutemukan di akhir surat at taubah ayat yang berbunyi; 'Telah datang kepada kalian seorang rasul dari jenis kamu sendiri,,,, hingga akhir ayat (QS. Attaubah 128) bersama Khuzaimah atau Abu Khuzaemah, sehingga aku masukkan dalam suratnya. Kemudian shuhuf (manuskrip pencatatan asli alquran) ini berada di Abu Bakar ketika hidupnya sampai Allah mewafatkannya, kemudian keberadaan shuhuf ini pada Umar 'azza wajalla semasa hidupnya sampai Allah mewafatkannya, kemudian pada Hafshah binti Umar.' Muhammad bin Ubaidullah mengatakan; maksud al likhaf ialah tembikar (tanah liat yang dibakar)."},"6321":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ أَبِي لَيْلَى ح حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنِي مَالِكٌ عَنْ أَبِي لَيْلَى بْنِ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ سَهْلٍ عَنْ سَهْلِ بْنِ أَبِي حَثْمَةَ أَنَّهُ أَخْبَرَهُهُوَ وَرِجَالٌ مِنْ كُبَرَاءِ قَوْمِهِ أَنَّ عَبْدَ اللَّهِ بْنَ سَهْلٍ وَمُحَيِّصَةَ خَرَجَا إِلَى خَيْبَرَ مِنْ جَهْدٍ أَصَابَهُمْ فَأُخْبِرَ مُحَيِّصَةُ أَنَّ عَبْدَ اللَّهِ قُتِلَ وَطُرِحَ فِي فَقِيرٍ أَوْ عَيْنٍ فَأَتَى يَهُودَ فَقَالَ أَنْتُمْ وَاللَّهِ قَتَلْتُمُوهُ قَالُوا مَا قَتَلْنَاهُ وَاللَّهِ ثُمَّ أَقْبَلَ حَتَّى قَدِمَ عَلَى قَوْمِهِ فَذَكَرَ لَهُمْ وَأَقْبَلَ هُوَ وَأَخُوهُ حُوَيِّصَةُ وَهُوَ أَكْبَرُ مِنْهُ وَعَبْدُ الرَّحْمَنِ بْنُ سَهْلٍ فَذَهَبَ لِيَتَكَلَّمَ وَهُوَ الَّذِي كَانَ بِخَيْبَرَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِمُحَيِّصَةَ كَبِّرْ كَبِّرْ يُرِيدُ السِّنَّ فَتَكَلَّمَ حُوَيِّصَةُ ثُمَّ تَكَلَّمَ مُحَيِّصَةُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِمَّا أَنْ يَدُوا صَاحِبَكُمْ وَإِمَّا أَنْ يُؤْذِنُوا بِحَرْبٍ فَكَتَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَيْهِمْ بِهِ فَكُتِبَ مَا قَتَلْنَاهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِحُوَيِّصَةَ وَمُحَيِّصَةَ وَعَبْدِ الرَّحْمَنِ أَتَحْلِفُونَ وَتَسْتَحِقُّونَ دَمَ صَاحِبِكُمْ قَالُوا لَا قَالَ أَفَتَحْلِفُ لَكُمْ يَهُودُ قَالُوا لَيْسُوا بِمُسْلِمِينَ فَوَدَاهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ عِنْدِهِ مِائَةَ نَاقَةٍ حَتَّى أُدْخِلَتْ الدَّارَ قَالَ سَهْلٌ فَرَكَضَتْنِي مِنْهَا نَاقَةٌ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah mengabarkan kepada kami [Malik] dari [Abu Laila] -lewat jalur periwayatan lain-Telah menceritakan kepada kami [Ismail] telah menceritakan kepadaku [Malik] dari [Abu Laila bin Abdullah bin Abduurrahman bin Sahal bin Abu Khatsmah], ia dan beberapa pemuka kaumnya mengabarinya, bahwa Abdullah bin Sahal dan Muhayshah berangkat ke Khaibar karena musim paceklik yang menimpa mereka, lantas Muhayshah diberi kabar bahwa Abdullah terbunuh dan di hempaskan begitu saja di sebuah mata air. Maka ia datangi kaum yahudi dan mengatakan; 'Hei, kalianlah -demi Allah- yang telah membunuhnya! ' Mereka menjawab; 'Kami tidak membunuhnya, demi Allah.' Kemudian Muhayshah pulang hingga ia temui kaumnya dan ia ceritakan kasusnya kepada mereka. Ia temui kaumnya bersama saudaranya, Huwaysah yang usianya lebih tua daripadanya, dan Abdurrahman bin Sahal. Muhayshah kontan ingin bicara -karena dialah yang pergi ke Khaibar--, namun Nabi shallallahu 'alaihi wasallam menegur Muhayshah; \"hendaklah yang lebih tua, hendaklah yang lebih tua\" yang beliau maksudkan adalah umurnya. Maka Huwayshah -kakak Muhaysah-berbicara, kemudian baru diteruskan oleh Muhayshah. Lantas Rasulullah shallallahu 'alaihi wasallam bersabda: \"Adakah mereka ingin membayar diyat sahabat kalian ataukah mereka ingin mengumumkan perang?\" lantas Rasulullah Shallallahu'alaihiwasallam berkirim surat kepada mereka, dan mereka pun memberi balasan bahwa; 'kami tidak membunuhnya.' Lantas Rasulullah Shallallahu'alaihiwasallam berkata kepada Muhayshah, Huwayshah, dan Abdurrahman bin Sahal; \"Bagaimana kalau kalian bersumpah dan berhak menuntut darah kawan kalian?\" mereka menjawab; 'tidak'. Nabi lantas mengatakan; \"bagaimana kalau kaum yahudi itu yang bersumpah untuk kalian?\" Mereka menjawab; \"mereka bukan muslimin.\" Selanjutnya malahan Rasulullah Shallallahu'alaihiwasallam yang membayar diyatnya dari miliknya sendiri sebanyak seratus ekor unta hingga dimasukkan kekandang. [Sahal] berkata; 'seekor diantaranya ada yang menyepakku.'"},"6322":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ حَدَّثَنَا الزُّهْرِيُّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي هُرَيْرَةَ وَزَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ قَالَاجَاءَ أَعْرَابِيٌّ فَقَالَ يَا رَسُولَ اللَّهِ اقْضِ بَيْنَنَا بِكِتَابِ اللَّهِ فَقَامَ خَصْمُهُ فَقَالَ صَدَقَ فَاقْضِ بَيْنَنَا بِكِتَابِ اللَّهِ فَقَالَ الْأَعْرَابِيُّ إِنَّ ابْنِي كَانَ عَسِيفًا عَلَى هَذَا فَزَنَى بِامْرَأَتِهِ فَقَالُوا لِي عَلَى ابْنِكَ الرَّجْمُ فَفَدَيْتُ ابْنِي مِنْهُ بِمِائَةٍ مِنْ الْغَنَمِ وَوَلِيدَةٍ ثُمَّ سَأَلْتُ أَهْلَ الْعِلْمِ فَقَالُوا إِنَّمَا عَلَى ابْنِكَ جَلْدُ مِائَةٍ وَتَغْرِيبُ عَامٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَأَقْضِيَنَّ بَيْنَكُمَا بِكِتَابِ اللَّهِ أَمَّا الْوَلِيدَةُ وَالْغَنَمُ فَرَدٌّ عَلَيْكَ وَعَلَى ابْنِكَ جَلْدُ مِائَةٍ وَتَغْرِيبُ عَامٍ وَأَمَّا أَنْتَ يَا أُنَيْسُ لِرَجُلٍ فَاغْدُ عَلَى امْرَأَةِ هَذَا فَارْجُمْهَا فَغَدَا عَ��َيْهَا أُنَيْسٌ فَرَجَمَهَا","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Ibnu Abu Dzi'b] telah menceritakan kepada kami [Az Zuhri] dari [Ubaidullah bin Abdillah] dari [Abu Hurairah] dan [Zaid bin Khalid Al Juhani] mengatakan, seorang arab badui (nomade) datang dan mengatakan; 'Ya Rasulullah, putuskanlah diantara kami dengan kitabullah! ' Lantas berdirilah lawan sengketanya seraya berujar; 'ia benar, putuskanlah antara kami dengan kitabullah.' Si arab nomade (pedusunan) lantas mengatakan; 'Anakku adalah pekerja orang ini, lantas ia berzina dengan isterinya, lalu mereka mengatakan, 'Anak laki-lakimu harus dirajam! ' Maka kutebus anakku dengan seratus ekor kambing dan seorang hamba sahaya, kemudian aku bertanya kepada ahlul 'ilmi, dan mereka mengatakan; 'anakmu harus didera seratus kali dan diasingkan selama setahun.' Kontan Nabi shallallahu 'alaihi wasallam bersabda; \"Sungguh akan kuputuskan kalian berdua dengan kitabullah, adapun hamba sahaya dan kambing harus dikembalikan kepadamu, dan anak laki-laki didera seratus kali dan diasingkan selama setahun, adapun engkau wahai Unais (lengkapnya Unais Al Aslami), temuilah si wanita dan rajamlah!\" Unais bersegera menemui si wanita dan merajamnya."},"6323":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ أَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ أَخْبَرَهُ أَنَّ أَبَا سُفْيَانَ بْنَ حَرْبٍ أَخْبَرَهُأَنَّ هِرَقْلَ أَرْسَلَ إِلَيْهِ فِي رَكْبٍ مِنْ قُرَيْشٍ ثُمَّ قَالَ لِتَرْجُمَانِهِ قُلْ لَهُمْ إِنِّي سَائِلٌ هَذَا فَإِنْ كَذَبَنِي فَكَذِّبُوهُ فَذَكَرَ الْحَدِيثَ فَقَالَ لِلتُّرْجُمَانِ قُلْ لَهُ إِنْ كَانَ مَا تَقُولُ حَقًّا فَسَيَمْلِكُ مَوْضِعَ قَدَمَيَّ هَاتَيْنِ","id":"Telah menceritakan kepada kami [Abul Yaman] Telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] telah mengabarkan kepadaku [Ubaidullah bin Abdullah], bahwasanya [Abdullah bin Abbas] mengabarkannya, [Abu Sufyan bin Harb] mengabarkannya, bahwa Heraqlius mengutus seorang utusan kepadanya ketika ia bersama rombongan Quraisy, kemudian mengatakan kepada juru terjemahnya; 'Katakan kepada mereka bahwa aku akan bertanya kepada orang ini (Abu Sufyan), jika dia mendustaiku maka dustakanlah dia, ' lalu Abu Sufyan mengemukakan pembicaraannya,, kemudian Heraklius berkata kepada juru bicaranya; 'katakan kepadanya (Abu Sufyan), sekiranya apa yang kamu katakan benar, niscaya dia (Muhammad) akan menguasai hingga kedua telapak kakiku ini.'"},"6324":{"ar":"حَدَّثَنَا مُحَمَّدٌ أَخْبَرَنَا عَبْدَةُ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ أَبِي حُمَيْدٍ السَّاعِدِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَعْمَلَ ابْنَ الْأُتَبِيَّةِ عَلَى صَدَقَاتِ بَنِي سُلَيْمٍ فَلَمَّا جَاءَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَحَاسَبَهُ قَالَ هَذَا الَّذِي لَكُمْ وَهَذِهِ هَدِيَّةٌ أُهْدِيَتْ لِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَهَلَّا جَلَسْتَ فِي بَيْتِ أَبِيكَ وَبَيْتِ أُمِّكَ حَتَّى تَأْتِيَكَ هَدِيَّتُكَ إِنْ كُنْتَ صَادِقًا ثُمَّ قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَطَبَ النَّاسَ وَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ أَمَّا بَعْدُ فَإِنِّي أَسْتَعْمِلُ رِجَالًا مِنْكُمْ عَلَى أُمُورٍ مِمَّا وَلَّانِي اللَّهُ فَيَأْتِي أَحَدُكُمْ فَيَقُولُ هَذَا لَكُمْ وَهَذِهِ هَدِيَّةٌ أُهْدِيَتْ لِي فَهَلَّا جَلَسَ فِي بَيْتِ أَبِيهِ وَبَيْتِ أُمِّهِ حَتَّى تَأْتِيَهُ هَدِيَّتُهُ إِنْ كَانَ صَادِقًا فَوَاللَّهِ لَا يَأْخُذُ أَحَدُكُمْ مِنْهَا شَيْئًا قَالَ هِشَامٌ بِغَيْرِ حَقِّهِ إِلَّا جَاءَ اللَّهَ يَحْمِلُهُ يَوْمَ الْقِيَامَةِ أَلَا فَلَأَعْرِفَنَّ مَا جَاءَ اللَّهَ رَجُلٌ بِبَعِيرٍ لَهُ رُغَاءٌ أَوْ بِبَقَرَةٍ لَهَا خُوَارٌ أَوْ شَاةٍ تَيْعَرُ ثُمَّ رَفَعَ يَدَيْهِ حَتَّى رَأَيْتُ بَيَاضَ إِبْطَيْهِ أَلَا هَلْ بَلَّغْتُ","id":"Telah menceritakan kepada kami [Muhammad] Telah mengabarkan kepada kami ['Abdah] telah menceritakan kepada kami [Hisyam bin Urwah] dari [ayahnya] dari [Abu humaid as Sa'idi], bahwa Nabi shallallahu 'alaihi wasallam pernah mempekerjakan Ibnul Atabiyah untuk menghimpun sedekah bani Sulaim. Tatkala ia mendatangi Rasulullah shallallahu 'alaihi wasallam dan Rasulullah mengevaluasinya, ia mengatakan; 'Ini bagian untukmu dan ini hadiah untukku.' Spontan Rasulullah Shallallahu'alaihiwasallam bersabda: \"tidakkah jika engkau duduk saja di rumah ayahmu dan rumah ibumu, maka apakah akan datang hadiahmu kepadamu jika memang engkau jujur.\" kemudian Rasulullah Shallallahu'alaihiwasallam berdiri dan berpidato kepada manusia, beliau memuja dan memuji Allah, kemudian mengatakan: 'Amma ba'du. Sesungguhnya saya mempekerjakan beberapa orang diantara kalian untuk urusan yang Allah menguasakannya kepada saya, lantas salah seorang diantara kalian mengatakan ini bagian untukmu dan ini hadiah untukku. tidakkah jika dia duduk saja di rumah ayahnya dan rumah ibunya, maka apakah akan datang hadiahnya kepadanya jika memang dia juju… Demi Allah, tidaklah salah seorang diantara kalian mengambil sesuatu yang bukan haknya, melainkan ia menghadap Allah dengan memikul barang yang diambilnya, ketahuilah, aku tahu ada seseorang yang menghadap Allah dengan memikul untanya yang mendengus, ada yang memikul sapinya yang melenguh, ada yang memikul kambingnya yang mengembik.\" kemudian beliau mengangkat kedua tangannya sehingga terlihat putih kedua ketiaknya."},"6325":{"ar":"حَدَّثَنَا أَصْبَغُ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا بَعَثَ اللَّهُ مِنْ نَبِيٍّ وَلَا اسْتَخْلَفَ مِنْ خَلِيفَةٍ إِلَّا كَانَتْ لَهُ بِطَانَتَانِ بِطَانَةٌ تَأْمُرُهُ بِالْمَعْرُوفِ وَتَحُضُّهُ عَلَيْهِ وَبِطَانَةٌ تَأْمُرُهُ بِالشَّرِّ وَتَحُضُّهُ عَلَيْهِ فَالْمَعْصُومُ مَنْ عَصَمَ اللَّهُ تَعَالَىوَقَالَ سُلَيْمَانُ عَنْ يَحْيَى أَخْبَرَنِي ابْنُ شِهَابٍ بِهَذَا وَعَنْ ابْنِ أَبِي عَتِيقٍ وَمُوسَى عَنْ ابْنِ شِهَابٍ مِثْلَهُ وَقَالَ شُعَيْبٌ عَنْ الزُّهْرِيِّ حَدَّثَنِي أَبُو سَلَمَةَ عَنْ أَبِي سَعِيدٍ قَوْلَهُ وَقَالَ الْأَوْزَاعِيُّ وَمُعَاوِيَةُ بْنُ سَلَّامٍ حَدَّثَنِي الزُّهْرِيُّ حَدَّثَنِي أَبُو سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ ابْنُ أَبِي حُسَيْنٍ وَسَعِيدُ بْنُ زِيَادٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي سَعِيدٍ قَوْلَهُ وَقَالَ عُبَيْدُ اللَّهِ بْنُ أَبِي جَعْفَرٍ حَدَّثَنِي صَفْوَانُ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي أَيُّوبَ قَالَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ashbagh] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Abu Salamah] dari [Abu Sa'id Al Khudri] dari Nabi shallallahu 'alaihi wasallam bersabda; \"Tidaklah Allah mengutus seorang Nabi atau mengangkat seorang khalifah selain ia mempunyai dua kubu, kubu yang memerintahkannya kebaikan dan memotivasinya, dan kubu yang menyuruhnya berbuat keburukan dan mendorongnya, maka orang yang terjaga adalah yang dijaga Allah ta'ala.\" [Sulaiman] mengatakan dari [Yahya] telah mengabarkan kepadaku [Ibnu Syihab] dengan hadist ini, dan dari [Ibnu Abu 'Atiq] dan [Musa] dari [Ibnu Syihab] hadits yang sama, sedang [Syu'aib] mengatakan dari [Az Zuhri] telah menceritakan kepadaku [Abu Salamah] dari [Abu Sa'id]... seperti hadits diatas. Sedang [Al Auza'i] dan [Mu'awiyah bin Salam] mengatakan, telah menceritakan kepadaku [Az Zuhri] telah menceritakan kepadaku [Abu Salamah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam. Sedang [Ibnu Abu Husain] dan [Sa'id bin Ziyad] mengatakan, dari [Abu Salamah] dari [Abu Sa'id],,, seperti hadits diatas,, dan [Ubaidullah bin Abu Ja'far] telah menceritakan kepadaku [Shafwan] dari [Abu Salamah] dari [Abu Ayyub] mengatakan; aku mendengar Nabi shallallahu 'alaihi wasallam."},"6326":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنِي مَالِكٌ عَنْ يَحْيَى بْنِ سَعِيدٍ قَالَ أَخْبَرَنِي عُبَادَةُ بْنُ الْوَلِيدِ أَخْبَرَنِي أَبِي عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَبَايَعْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى السَّمْعِ وَالطَّاعَةِ فِي الْمَنْشَطِ وَالْمَكْرَهِ وَأَنْ لَا نُنَازِعَ الْأَمْرَ أَهْلَهُ وَأَنْ نَقُومَ أَوْ نَقُولَ بِالْحَقِّ حَيْثُمَا كُنَّا لَا نَخَافُ فِي اللَّهِ لَوْمَةَ لَائِمٍ","id":"Telah menceritakan kepada kami [Ismail] telah menceritakan kepadaku [Malik] dari [Yahya bin Sa'id] mengatakan, telah mengabarkan kepadaku ['Ubadah bin Al Walid] telah mengabarkan kepadaku [Ayahku] dari [Ubadah bin Ash Shamit] mengatakan; 'kami berbai'at kepada Rasulullah Shallallahu'alaihiwasallam untuk mendengar dan taat, baik ketika giat (semangat) maupun malas, dan untuk tidak menggulingkan kekuasaan dari orang yang berwenang terhadapnya, dan mendirikan serta mengucapkan kebenaran dimana saja kami berada, kami tidak khawatir dijalan Allah terhadap celaan orang yag mencela.'"},"6327":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَدَاةٍ بَارِدَةٍ وَالْمُهَاجِرُونَ وَالْأَنْصَارُ يَحْفِرُونَ الْخَنْدَقَ فَقَالَ اللَّهُمَّ إِنَّ الْخَيْرَ خَيْرُ الْآخِرَهْفَاغْفِرْ لِلْأَنْصَارِ وَالْمُهَاجِرَهْفَأَجَابُوا نَحْنُ الَّذِينَ بَايَعُوا مُحَمَّدَاعَلَى الْجِهَادِ مَا بَقِينَا أَبَدَا","id":"Telah menceritakan kepada kami ['Amru bin Ali] telah menceritakan kepada kami [Khalid bin Al Harits] telah menceritakan kepada kami [Humaid] dari [Anas] radliallahu 'anhu; Nabi shallallahu 'alaihi wasallam berangkat di suatu pagi yang dingin sedang kaum muhajirin dan anshar sedang menggali Khandaq (parit), lantas Nabi melantunkan sebuah bait syair; \"Ya Allah, sesungguhnya kebaikan sejati adalah kebaikan akhirat, maka ampunilah kaum anshar dan muhajir.\" Serta merta para shahabat menyahut dengan bait syair; \"Kita adalah yang berbai'at kepada Muhammad untuk jihad sepanjang hayat.\""},"6328":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَكُنَّا إِذَا بَايَعْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى السَّمْعِ وَالطَّاعَةِ يَقُولُ لَنَا فِيمَا اسْتَطَعْتُمْ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah mengabarkan kepada kami [Malik] dari [Abdullah bin Dinar] dari [Abdullah bin Umar] radliallahu 'anhuma mengatakan; kami ketika berbai'at kepada Rasulullah Shallallahu'alaihiwasallam untuk mendengar dan taat, beliau mengatakan kepada kami; \"Semaksimal kemampuan kalian.\""},"6329":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دِينَارٍ قَالَ شَهِدْتُ ابْنَ عُمَرَحَيْثُ اجْتَمَعَ النَّاسُ عَلَى عَبْدِ الْمَلِكِ قَالَ كَتَبَ إِنِّي أُقِرُّ بِالسَّمْعِ وَالطَّاعَةِ لِعَبْدِ اللَّهِ عَبْدِ الْمَلِكِ أَمِيرِ الْمُؤْمِنِينَ عَلَى سُنَّةِ اللَّهِ وَسُنَّةِ رَسُولِهِ مَا اسْتَطَعْتُ وَإِنَّ بَنِيَّ قَدْ أَقَرُّوا بِمِثْلِ ذَلِكَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Sufyan] telah menceritakan kepada kami [Abdullah bin Dinar] mengatakan, aku pernah menyaksikan [Ibnu Umar] ketika orang-orang berkumpul kepada Abdul Malik, ia mengatakan dengan menulis; \"Saya ikrarkan untuk senantiasa mendengar dan taat terhadap hamba Allah Abdul Malik amirul mukminin diatas sunnatullah dan sunnah rasul-NYA semaksimal kemampuanku, dan anak-anakku mengikrarkan yang sedemikian ini.\""},"6330":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا سَيَّارٌ عَنْ الشَّعْبِيِّ عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِ قَالَبَايَعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى السَّمْعِ وَالطَّاعَةِ فَلَقَّنَنِي فِيمَا اسْتَطَعْتُ وَالنُّصْحِ لِكُلِّ مُسْلِمٍ","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Sayyar] dari [Ay Sya'bi] dari [Jarir bin Abdullah], mengatakan; aku berbaiat kepada Nabi shallallahu 'alaihi wasallam untuk mendengar dan taat, lantas beliau menemui aku seraya mengatakan; \"Semaksimal kemampuanmu dan untuk menasehati sesama muslim\""},"6331":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ دِينَارٍ قَالَلَمَّا بَايَعَ النَّاسُ عَبْدَ الْمَلِكِ كَتَبَ إِلَيْهِ عَبْدُ اللَّهِ بْنُ عُمَرَ إِلَى عَبْدِ اللَّهِ عَبْدِ الْمَلِكِ أَمِيرِ الْمُؤْمِنِينَ إِنِّي أُقِرُّ بِالسَّمْعِ وَالطَّاعَةِ لِعَبْدِ اللَّهِ عَبْدِ الْمَلِكِ أَمِيرِ الْمُؤْمِنِينَ عَلَى سُنَّةِ اللَّهِ وَسُنَّةِ رَسُولِهِ فِيمَا اسْتَطَعْتُ وَإِنَّ بَنِيَّ قَدْ أَقَرُّوا بِذَلِكَ","id":"Telah menceritakan kepada kami ['Amru bin Ali] telah menceritakan kepada kami [Yahya] dari [Sufyan] mengatakan, telah menceritakan kepadaku [Abdullah bin Dinar] mengatakan, ketika orang-orang berbai'at kepada Abdul Malik, [Abdullah bin Umar] berkirim surat; \"kepada hamba Allah, Abdul Malik amirul mukminin, aku berikrar untuk mendengar dan taat kepada hamba Allah amirul mukmin diatas sunnatullah dan sunnah rasul-NYA semaksimal kemampuanku dan sesungguhnya anak-anakku telah mengikrarkan yang demikian.\" "},"6332":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا حَاتِمٌ عَنْ يَزِيدَ بْنِ أَبِي عُبَيْدٍ قَالَ قُلْتُ لِسَلَمَةَعَلَى أَيِّ شَيْءٍ بَايَعْتُمْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْحُدَيْبِيَةِ قَالَ عَلَى الْمَوْتِ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] telah menceritakan kepada kami [Hatim] dari [Yazid bin Abu Ubaid] mengatakan, saya bertanya kepada [Salamah]; Untuk apa kalian berbaiat kepada Nabi shallallahu 'alaihi wasallam dihari Hudaibiyah? ia menjawab; untuk menyongsong kematian."},"6333":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ أَسْمَاءَ حَدَّثَنَا جُوَيْرِيَةُ عَنْ مَالِكٍ عَنْ الزُّهْرِيِّ أَنَّ حُمَيْدَ بْنَ عَبْدِ الرَّحْمَنِ أَخْبَرَهُ أَنَّ الْمِسْوَرَ بْنَ مَخْرَمَةَ أَخْبَرَهُأَنَّ الرَّهْطَ الَّذِينَ وَلَّاهُمْ عُمَرُ اجْتَمَعُوا فَتَشَاوَرُوا فَقَالَ لَهُمْ عَبْدُ الرَّحْمَنِ لَسْتُ بِالَّذِي أُنَافِسُكُمْ عَلَى هَذَا الْأَمْرِ وَلَكِنَّكُمْ إِنْ شِئْتُمْ اخْتَرْتُ لَكُمْ مِنْكُمْ فَجَعَلُوا ذَلِكَ إِلَى عَبْدِ الرَّحْمَنِ فَلَمَّا وَلَّوْا عَبْدَ الرَّحْمَنِ أَمْرَهُمْ فَمَالَ النَّاسُ عَلَى عَبْدِ الرَّحْمَنِ حَتَّى مَا أَرَى أَحَدًا مِنْ النَّاسِ يَتْبَعُ أُولَئِكَ الرَّهْطَ وَلَا يَطَأُ عَقِبَهُ وَمَالَ النَّاسُ عَلَى عَبْدِ الرَّحْمَنِ يُشَاوِرُونَهُ تِلْكَ اللَّيَالِي حَتَّى إِذَا كَانَتْ اللَّيْلَةُ الَّتِي أَصْبَحْنَا مِنْهَا فَبَايَعْنَا عُثْمَانَ قَالَ الْمِسْوَرُ طَرَقَنِي عَبْدُ الرَّحْمَنِ بَعْدَ هَجْعٍ مِنْ اللَّيْلِ فَضَرَبَ الْبَابَ حَتَّى اسْتَيْقَظْتُ فَقَالَ أَرَاكَ نَائِمًا فَوَاللَّهِ مَا اكْتَحَلْتُ هَذِهِ اللَّيْلَةَ بِكَبِيرِ نَوْمٍ انْطَلِقْ فَادْعُ الزُّبَيْرَ وَسَعْدًا فَدَعَوْتُهُمَا لَهُ فَشَاوَرَهُمَا ثُمَّ دَعَانِي فَقَالَ ادْعُ لِي عَلِيًّا فَدَعَوْتُهُ فَنَاجَاهُ حَتَّى ابْهَارَّ اللَّيْلُ ثُمَّ قَامَ عَلِيٌّ مِنْ عِنْدِهِ وَهُوَ عَلَى طَمَعٍ وَقَدْ كَانَ عَبْدُ الرَّحْمَنِ يَخْشَى مِنْ عَلِيٍّ شَيْئًا ثُمَّ قَالَ ادْعُ لِي عُثْمَانَ فَدَعَوْتُهُ فَنَاجَاهُ حَتَّى فَرَّقَ بَيْنَهُمَا الْمُؤَذِّنُ بِالصُّبْحِ فَلَمَّا صَلَّى لِلنَّاسِ الصُّبْحَ وَاجْتَمَعَ أُولَئِكَ الرَّهْطُ عِنْدَ الْمِنْبَرِ فَأَرْسَلَ إِلَى مَنْ كَانَ حَاضِرًا مِنْ الْمُهَاجِرِينَ وَالْأَنْصَارِ وَأَرْسَلَ إِلَى أُمَرَاءِ الْأَجْنَادِ وَكَانُوا وَافَوْا تِلْكَ الْحَجَّةَ مَعَ عُمَرَ فَلَمَّا اجْتَمَعُوا تَشَهَّدَ عَبْدُ الرَّحْمَنِ ثُمَّ قَالَ أَمَّا بَعْدُ يَا عَلِيُّ إِنِّي قَدْ نَظَرْتُ فِي أَمْرِ النَّاسِ فَلَمْ أَرَهُمْ يَعْدِلُونَ بِعُثْمَانَ فَلَا تَجْعَلَنَّ عَلَى نَفْسِكَ سَبِيلًا فَقَالَ أُبَايِعُكَ عَلَى سُنَّةِ اللَّهِ وَرَسُولِهِ وَالْخَلِيفَتَيْنِ مِنْ بَعْدِهِ فَبَايَعَهُ عَبْدُ الرَّحْمَنِ وَبَايَعَهُ النَّاسُ الْمُهَاجِرُونَ وَالْأَنْصَارُ وَأُمَرَاءُ الْأَجْنَادِ وَالْمُسْلِمُونَ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad bin Asma`], telah menceritakan kepada kami [Juwairiyah] dari [Malik] dari [Az Zuhri], bahwa [Humaid bin Abdurrahman] mengabarinya, bahwa [Miswar bin Makhramah] mengabarinya; beberapa orang yang diserahi Umar untuk memegang mandat berkumpul dan bermusyawarah. Abdurrahman berkata kepada mereka; 'aku bukan bermaksud menyaingi kalian dalam masalah ini, namun jika kalian berkenan saya akan memilih (seorang pemimpin) untuk kalian dari kalian sendiri, ' maka mereka limpahkan wewenang itu kepada Abdurrahman. Ketika mereka sudah menguasakan urusannya kepada Abdurrahman, dan orang-orang menjadi simpati kepada Abdurrahman sehingga aku tidak melihat seorang pun mengikuti yang lain, dan tidak pula melangkahi kebijakan Abdurrahman, dan semua manusia sudah simpati kepada Abdurrahman, mereka memusyawarahkan kekuasaan itu beberapa malam, hingga setelah tiba malam yang pagi harinya kami berbaiat kepada Ustman. -Miswar melanjutkan; - Abdurrahman mengetukku setelah malam kian larut, ia mengetuk pintu hingga aku bangun, dan ia mengatakan; 'Kulihat dirimu tidur? Demi Allah, malam ini aku tidak bisa tidur nyenyak, tolong bertolaklah dan panggilah Zubair dan Sa'd, ' maka aku memanggil keduanya agar bertemu Abdurrahman, Abdurrahman kemudian mengajak keduanya bermusyawarah, kemudian ia memanggilku lagi dan berujar; 'Tolong panggillah Ali agar menemuiku! ' serta merta aku memanggilnya, dan Abdurrahman melakukan pertemuan empat mata dengannya hingga muadzin subuh memisahkan pertemuannya. Tatkala dia selesai shalat subuh, dan beberapa pemuka itu telah berkumpul di minbar, Abdurrahman mengutus utusan kepada hadirin dari muhajirin dan anshar, juga kepada para petinggi militer, yang ketika itu mereka bersama-sama haji bersama Umar. Dikala mereka telah berkumpul, Abdurrahman menyatakan kesaksian dan berujar; 'Amma ba'd. Wahai Ali, saya telah mencermati masalah manusia, dan tak kulihat mereka berpaling dari Ustman, maka janganlah engkau mencari-cari alasan terhadap dirimu.' Abdurrahman kemudian mengucapkan; 'Saya berbai'at kepadamu diatas sunnatullah dan sunnah rasul-Nya serta dua khalifah sepeninggalnya.' Selanjutnya Abdurrahman berbaiat kepadanya yang diikuti sahabat muhajirin dan anshar, para pejabat tinggi militer dan muslimin secara umum. "},"6334":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ عَنْ يَزِيدَ بْنِ أَبِي عُبَيْدٍ عَنْ سَلَمَةَ قَالَبَايَعْنَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَحْتَ الشَّجَرَةِ فَقَالَ لِي يَا سَلَمَةُ أَلَا تُبَايِعُ قُلْتُ يَا رَسُولَ اللَّهِ قَدْ بَايَعْتُ فِي الْأَوَّلِ قَالَ وَفِي الثَّانِي","id":"Telah menceritakan kepada kami [Abu 'Ashim] dari [Yazid bin Abu 'Ubaid] dari [Salamah] mengatakan, Kami berbaiat kepada Nabi shallallahu 'alaihi wasallam dibawah pohon, lantas Nabi mengatakan: \"Hai Salamah, tidakkah engkau berbaiat?\" 'Saya sudah pada baiat yang pertama ya Rasulullah' Jawabku. Maka Rasulullah menjawab: \"lakukanlah juga pada baiat yang kedua!\""},"6335":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ أَعْرَابِيًّا بَايَعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْإِسْلَامِ فَأَصَابَهُ وَعْكٌ فَقَالَ أَقِلْنِي بَيْعَتِي فَأَبَى ثُمَّ جَاءَهُ فَقَالَ أَقِلْنِي بَيْعَتِي فَأَبَى فَخَرَجَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةُ كَالْكِيرِ تَنْفِي خَبَثَهَا وَيَنْصَعُ طِيبُهَا","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Muhammad bin Al Munkadir] dari [Jabir bin Abdullah] radliallahu 'anhuma, ada seorang arab nomade (primitive) berbaiat kepada Rasulullah Shallallahu'alaihiwasallam untuk Islam, kemudian ia terkena demam, sehingga ia berujar: \"lepaskanlah baiatku\" Namun beliau enggan. Si arab badui datang kepada beliau lagi dan mengatakan; 'lepaskanlah baiatku! ' Namun Nabi enggan, sehingga arab badui tadi keluar. Maka Rasulullah Shallallahu'alaihiwasallam bersabda: \"Sesungguhnya kota Madinah ini bagaikan mesin pemanggang besi yang menghilangkan kotorannya dan menyaring yang baik.\""},"6336":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا سَعِيدٌ هُوَ ابْنُ أَبِي أَيُّوبَ قَالَ حَدَّثَنِي أَبُو عَقِيلٍ زُهْرَةُ بْنُ مَعْبَدٍ عَنْ جَدِّهِ عَبْدِ اللَّهِ بْنِ هِشَامٍوَكَانَ قَدْ أَدْرَكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَذَهَبَتْ بِهِ أُمُّهُ زَيْنَبُ بِنْتُ حُمَيْدٍ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ بَايِعْهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ صَغِيرٌ فَمَسَحَ رَأْسَهُ وَدَعَا لَهُ وَكَانَ يُضَحِّي بِالشَّاةِ الْوَاحِدَةِ عَنْ جَمِيعِ أَهْلِهِ","id":"Telah menceritakan kepada kami ['Ali bin Abdullah] telah menceritakan kepada kami [Abdullah bin Yazid] telah menceritakan kepada kami [Sa'id, alias Ibnu Abu Ayyub] mengatakan; telah menceritakan kepadaku [Abu Uqail Zuhraj bin ma'bad] dari [kakeknya, Abdullah bin Hisyam], yang mana dia pernah bertemu Nabi shallallahu 'alaihi wasallam, ibunya, Zainab binti Muhammad, pernah membawanya kepada Rasulullah Shallallahu'alaihiwasallam dan berujar; 'Wahai Rasulullah, tolong bai'atlah dia.' Lantas Nabi shallallahu 'alaihi wasallam bersabda: \"dia masih kecil!\" Maka Nabi mengusap kepalanya dan menyembelihkan satu kambing untuk semua keluarganya."},"6337":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ أَعْرَابِيًّا بَايَعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْإِسْلَامِ فَأَصَابَ الْأَعْرَابِيَّ وَعْكٌ بِالْمَدِينَةِ فَأَتَى الْأَعْرَابِيُّ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَقِلْنِي بَيْعَتِي فَأَبَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ جَاءَهُ فَقَالَ أَقِلْنِي بَيْعَتِي فَأَبَى ثُمَّ جَاءَهُ فَقَالَ أَقِلْنِي بَيْعَتِي فَأَبَى فَخَرَجَ الْأَعْرَابِيُّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا الْمَدِينَةُ كَالْكِيرِ تَنْفِي خَبَثَهَا وَيَنْصَعُ طِيبُهَا","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah mengabarkan kepada kami [Malik] dari [Muhammad bin Al Munkadir] dari [Jabir bin Abdullah], seorang arab nomade (primitive) berbaiat kepada Rasulullah Shallallahu'alaihiwasallam untuk Islam, kemudian si arab badui ini terkena demam di Madinah. Ia kemudian menghadap Rasulullah Shallallahu'alaihiwasallam dan berujar; \"Wahai Rasulullah, tolong cabutlah baiatku.' Namun Rasulullah Shallallahu'alaihiwasallam enggan. Kemudian si Arab badui datang untuk kali ketiganya dan berujar; \"cabutlah baiatku!\" Namun Nabi enggan, kemudian si arab badui datang lagi dan mengatakan; \"tolong cabutlah baiatku!\" Nabi tetap enggan, sehingga arab badui keluar dengan tangan hampa. Lantas Rasulullah Shallallahu'alaihiwasallam berujar: \"Sungguh Madinah ini bagaikan mesin pemanggang api yang menghilangkan kotoran dan menyaring yang baik saja.\""},"6338":{"ar":"حَدَّثَنَا عَبْدَانُ عَنْ أَبِي حَمْزَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَةٌ لَا يُكَلِّمُهُمْ اللَّهُ يَوْمَ الْقِيَامَةِ وَلَا يُزَكِّيهِمْ وَلَهُمْ عَذَابٌ أَلِيمٌ رَجُلٌ عَلَى فَضْلِ مَاءٍ بِالطَّرِيقِ يَمْنَعُ مِنْهُ ابْنَ السَّبِيلِ وَرَجُلٌ بَايَعَ إِمَامًا لَا يُبَايِعُهُ إِلَّا لِدُنْيَاهُ إِنْ أَعْطَاهُ مَا يُرِيدُ وَفَى لَهُ وَإِلَّا لَمْ يَفِ لَهُ وَرَجُلٌ يُبَايِعُ رَجُلًا بِسِلْعَةٍ بَعْدَ الْعَصْرِ فَحَلَفَ بِاللَّهِ لَقَدْ أُعْطِيَ بِهَا كَذَا وَكَذَا فَصَدَّقَهُ فَأَخَذَهَا وَلَمْ يُعْطَ بِهَا","id":"Telah menceritakan kepada kami ['Abdan] dari [Abu hamzah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] mengatakan, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ada tiga orang yang Allah tidak mengajak bicara pada hari kiamat, tidak menyucikan mereka dan bagi mereka siksa yang pedih, seseorang yang terus membiarkan kelebihan air di jalan untuk mencegah ibnus sabil, dan seseorang yang berbaiat kepada imam, yang ia tidak berbaiat kepadanya selain untuk duniawi, jika imam memberi yang diinginkannya maka ia memenuhinya, namun jika tidak, ia tidak menunaikannya, dan seseorang yang melakukan transaksi jual beli dengan seseorang setelah `ashr, lantas si pembeli bersumpah dengan nama Allah, bahwa ia pernah membeli dengan harga sekian-sekian dan itu diberikan, lantas si penjual memberikannya (membenarkannya), sehingga si pembeli bisa mengambilnya padahal sebenarnya dengan harga tawarannya tak bisa mendapat barang.\""},"6339":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ ح وَقَالَ اللَّيْثُ حَدَّثَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي أَبُو إِدْرِيسَ الْخَوْلَانِيُّ أَنَّهُ سَمِعَ عُبَادَةَ بْنَ الصَّامِتِ يَقُولُقَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ فِي مَجْلِسٍ تُبَايِعُونِي عَلَى أَنْ لَا تُشْرِكُوا بِاللَّهِ شَيْئًا وَلَا تَسْرِقُوا وَلَا تَزْنُوا وَلَا تَقْتُلُوا أَوْلَادَكُمْ وَلَا تَأْتُوا بِبُهْتَانٍ تَفْتَرُونَهُ بَيْنَ أَيْدِيكُمْ وَأَرْجُلِكُمْ وَلَا تَعْصُوا فِي مَعْرُوفٍ فَمَنْ وَفَى مِنْكُمْ فَأَجْرُهُ عَلَى اللَّهِ وَمَنْ أَصَابَ مِنْ ذَلِكَ شَيْئًا فَعُوقِبَ فِي الدُّنْيَا فَهُوَ كَفَّارَةٌ لَهُ وَمَنْ أَصَابَ مِنْ ذَلِكَ شَيْئًا فَسَتَرَهُ اللَّهُ فَأَمْرُهُ إِلَى اللَّهِ إِنْ شَاءَ عَاقَبَهُ وَإِنْ شَاءَ عَفَا عَنْهُ فَبَايَعْنَاهُ عَلَى ذَلِكَ","id":"Telah menceritakan kepada kami [Abul Yaman] Telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] -lewat jalur periwayatan lain- [Al Laits] mengatakan; telah menceritakan kepadaku [Yunus] dari [Ibnu Syihab] telah mengabarkan kepada kami [Abu Idris Al Khaulani], ia mendengar [Ubadah bin Shamit] mengatakan, Rasulullah Shallallahu'alaihiwasallam berujar kepada kami yang ketika itu kami berada dalam sebuah majlis; \"Kalian berbaiat kepadaku untuk tidak menyekutukan Allah dengan sesuatu apapun, tidak mencuri, tidak berzina, tidak membunuh anak-anak kalian dan tidak mengadakan kebohongan yang kalian ada-adakan diantara tangan dan kaki kalian, dan untuk tidak membangkang yang ma'ruf, maka siapa diantara kalian memenuhi baiatnya, maka ganjarannya disisi Allah, dan barangsiapa yang melanggar janji (ikrar atau baiat) nya lantas dihukum di dunia, maka itu sebagai kaffarat baginya, dan barangsiapa yang melanggarnya lantas Allah menutupinya (membiarkannya), maka urusannya kepada Allah, jika Allah berkenan Allah akan menyiksanya, dan jika berkenan ia memaafkannya.\" maka kami pun berbaiat kepadanya untuk sedemikian ini."},"6340":{"ar":"حَدَّثَنَا مَحْمُودٌ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُبَايِعُ النِّسَاءَ بِالْكَلَامِ بِهَذِهِ الْآيَةِ{ لَا يُشْرِكْنَ بِاللَّهِ شَيْئًا }قَالَتْ وَمَا مَسَّتْ يَدُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَ امْرَأَةٍ إِلَّا امْرَأَةً يَمْلِكُهَا","id":"Telah menceritakan kepada kami [Mahmud] telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Urwah] dari [Aisyah] radliallahu 'anha, mengatakan, Nabi shallallahu 'alaihi wasallam Shallallahu'alaihiwasallam membaiat wanita cukup dengan lisan (tidak berjabat tangan) dengan ayat ini; 'Untuk tidak menyekutukan Allah dengan sesuatu apapun….' sampai akhir (QS. Almumtahanah 12) kata Aisyah; Tangan Rasulullah Shallallahu'alaihiwasallam sama sekali tidak pernah menyentuh wanita selain wanita yang beliau miliki (isterinya)."},"6341":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ أَيُّوبَ عَنْ حَفْصَةَ عَنْ أُمِّ عَطِيَّةَ قَالَتْبَايَعْنَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَرَأَ عَلَيْنَا{ أَنْ لَا يُشْرِكْنَ بِاللَّهِ شَيْئًا }وَنَهَانَا عَنْ النِّيَاحَةِ فَقَبَضَتْ امْرَأَةٌ مِنَّا يَدَهَا فَقَالَتْ فُلَانَةُ أَسْعَدَتْنِي وَأَنَا أُرِيدُ أَنْ أَجْزِيَهَا فَلَمْ يَقُلْ شَيْئًا فَذَهَبَتْ ثُمَّ رَجَعَتْ فَمَا وَفَتْ امْرَأَةٌ إِلَّا أُمُّ سُلَيْمٍ وَأُمُّ الْعَلَاءِ وَابْنَةُ أَبِي سَبْرَةَ امْرَأَةُ مُعَاذٍ أَوْ ابْنَةُ أَبِي سَبْرَةَ وَامْرَأَةُ مُعَاذٍ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abdul Warits] dari [Ayyub] dari [Hafshah] dari [Ummu 'Athiyyah] mengatakan, kami berbaiat kepada Nabi shallallahu 'alaihi wasallam, lantas beliau membacakan ayat: 'Untuk tidak menyekutukan Allah dengan sesuatu apapun….' sampai akhir(QS. Almumtahanah 12), dan beliau melarang kami dari niyahah (meratap, menjerit-jerit atau menapuk pipi ketika kematian). Kemudian ada seseorang yang mencabut tangannya dari kami dan mengatakan; 'wanita fulanah telah membahagiakanku dan aku ingin membalasnya, ' namun Nabi tidak mengucapkan apa-apa, lantas si wanita itu terus ngeloyor dan kembali lagi, sehingga tak ada yang memenuhi janji setianya (baiat) selain Ummu Sulaim, Ummul 'Ala, anak perempuan Abu Sabrah yang ia adalah isteri Mu'adz atau anak perempuan Abu Sabrah, dan isteri Mu'adz."},"6342":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ سَمِعْتُ جَابِرًا قَالَجَاءَ أَعْرَابِيٌّ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ بَايِعْنِي عَلَى الْإِسْلَامِ فَبَايَعَهُ عَلَى الْإِسْلَامِ ثُمَّ جَاءَ الْغَدَ مَحْمُومًا فَقَالَ أَقِلْنِي فَأَبَى فَلَمَّا وَلَّى قَالَ الْمَدِينَةُ كَالْكِيرِ تَنْفِي خَبَثَهَا وَيَنْصَعُ طِيبُهَا","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Muhammad bin Al Munkadir], aku mendengar [Jabir] mengatakan; 'Seorang arab badui (nomade) mendatangi Nabi shallallahu 'alaihi wasallam dan berujar \"Baiatlah aku untuk Islam, \" maka Nabi membaiatnya untuk Islam. Keesokan harinya si arab badui tadi datang dalam keadaan demam, dan berujar; \"batalkanlah baiatku\" namun Nabi enggan. Ketika si arab badui sudah berpaling, Nabi bersabda: \"Madinah ini bagaikan tungku api yang menghilangkan karat-karatnya dan menyaring yang baik saja.\""},"6343":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا سُلَيْمَانُ بْنُ بِلَالٍ عَنْ يَحْيَى بْنِ سَعِيدٍ سَمِعْتُ الْقَاسِمَ بْنَ مُحَمَّدٍ قَالَ قَالَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَاوَارَأْسَاهْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاكِ لَوْ كَانَ وَأَنَا حَيٌّ فَأَسْتَغْفِرُ لَكِ وَأَدْعُو لَكِ فَقَالَتْ عَائِشَةُ وَا ثُكْلِيَاهْ وَاللَّهِ إِنِّي لَأَظُنُّكَ تُحِبُّ مَوْتِي وَلَوْ كَانَ ذَاكَ لَظَلَلْتَ آخِرَ يَوْمِكَ مُعَرِّسًا بِبَعْضِ أَزْوَاجِكَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَلْ أَنَا وَارَأْسَاهْ لَقَدْ هَمَمْتُ أَوْ أَرَدْتُ أَنْ أُرْسِلَ إِلَى أَبِي بَكْرٍ وَابْنِهِ فَأَعْهَدَ أَنْ يَقُولَ الْقَائِلُونَ أَوْ يَتَمَنَّى الْمُتَمَنُّونَ ثُمَّ قُلْتُ يَأْبَى اللَّهُ وَيَدْفَعُ الْمُؤْمِنُونَ أَوْ يَدْفَعُ اللَّهُ وَيَأْبَى الْمُؤْمِنُونَ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Sulaiman bin Bilal] dari [Yahya binSa'id] aku mendengar [Al Qasim bin Muhammad] mengatakan, [Aisyah] radliallahu 'anha mengeluh; \"Aduh (sakitnya) kepalaku!\" Lantas Rasulullah Shallallahu'alaihiwasallam berujar; \"Kalaulah aku masih hidup, niscaya aku memintakan ampun untukmu dan mendoakan bagimu!\" Lantas Aisyah mengatakan; 'Duhai malangnya, demi Allah, aku berprasangka engkau menyukai kematianku, kalaulah demikian, lebih baik akhir-akhir harimu menjadi pengantin di rumah salah satu isterimu.' Lantas Rasulullah shallallahu 'alaihi wasallam menyahut: \"Bahkan aku, aduh sakitnya kepalaku! Saya berkeinginan sekali untuk mengutus utusan kepada Abu Bakar dan anaknya dan mewasiatkan (kekhilafahan kepadanya), (karena aku tidak suka) orang-orang berkata (khilafah untukku atau untuk fulan) atau (karena khawatir) orang-orang mengangan-angankannya, kemudian aku katakan; 'Allah enggan (kekhilafahan untuk selain Abu Bakar), dan orang-orang mukmin menolak (selain dia), \" atau dengan redaksi; \"Allah menolak (selain dia) dan orang-orang mukmin enggan (kekhilafahan untuk selain Abu Bakar).\""},"6344":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ أَخْبَرَنَا سُفْيَانُ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَقِيلَ لِعُمَرَ أَلَا تَسْتَخْلِفُ قَالَ إِنْ أَسْتَخْلِفْ فَقَدْ اسْتَخْلَفَ مَنْ هُوَ خَيْرٌ مِنِّي أَبُو بَكْرٍ وَإِنْ أَتْرُكْ فَقَدْ تَرَكَ مَنْ هُوَ خَيْرٌ مِنِّي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَثْنَوْا عَلَيْهِ فَقَالَ رَاغِبٌ رَاهِبٌ وَدِدْتُ أَنِّي نَجَوْتُ مِنْهَا كَفَافًا لَا لِي وَلَا عَلَيَّ لَا أَتَحَمَّلُهَا حَيًّا وَلَا مَيِّتًا","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah mengabarkan kepada kami [Sufyan] dari [Hisyam bin Urwah] dari [ayahnya] dari [Abdullah bin Umar] radliallahu 'anhuma, ia mengatakan, [Umar] ditanya; 'mengapa engkau tidak mengangkat pengganti (untuk menjadi) khalifah? ' Umar menjawab; 'Kalaulah aku mengangkat pengganti (untuk menjadi) khalifah, sungguh orang yang lebih baik dari diriku Abu Bakar telah mengangkat pengganti (untuk menjadi) khalifah, dan kalaulah aku tinggalkan, orang yang lebih baik dari diriku juga telah meninggalkannya, yaitu Rasulullah Shallallahu'alaihiwasallam.' maka para sahabat memujinya, sehingga Umar mengatakan; 'Sungguh aku berharap-harap cemas, saya berharap sendainya aku selamat dari bahaya kekhilafahan ini dalam keadaan netral, tidak mendapat ganjaran, tidak juga mendapat dosa yang harus saya tanggung, baik ketika hidupku maupun kematianku.'"},"6345":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامٌ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ أَخْبَرَنِي أَنَسُ بْنُ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَنَّهُ سَمِعَ خُطْبَةَ عُمَرَ الْآخِرَةَ حِينَ جَلَسَ عَلَى الْمِنْبَرِ وَذَلِكَ الْغَدَ مِنْ يَوْمٍ تُوُفِّيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَشَهَّدَ وَأَبُو بَكْرٍ صَامِتٌ لَا يَتَكَلَّمُ قَالَ كُنْتُ أَرْجُو أَنْ يَعِيشَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى يَدْبُرَنَا يُرِيدُ بِذَلِكَ أَنْ يَكُونَ آخِرَهُمْ فَإِنْ يَكُ مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ مَاتَ فَإِنَّ اللَّهَ تَعَالَى قَدْ جَعَلَ بَيْنَ أَظْهُرِكُمْ نُورًا تَهْتَدُونَ بِهِ هَدَى اللَّهُ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِنَّ أَبَا بَكْرٍ صَاحِبُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَانِيَ اثْنَيْنِ فَإِنَّهُ أَوْلَى الْمُسْلِمِينَ بِأُمُورِكُمْ فَقُومُوا فَبَايِعُوهُ وَكَانَتْ طَائِفَةٌ مِنْهُمْ قَدْ بَايَعُوهُ قَبْلَ ذَلِكَ فِي سَقِيفَةِ بَنِي سَاعِدَةَ وَكَانَتْ بَيْعَةُ الْعَامَّةِ عَلَى الْمِنْبَرِقَالَ الزُّهْرِيُّ عَنْ أَنَسِ بْنِ مَالِكٍ سَمِعْتُ عُمَرَ يَقُولُ لِأَبِي بَكْرٍ يَوْمَئِذٍ اصْعَدْ الْمِنْبَرَ فَلَمْ يَزَلْ بِهِ حَتَّى صَعِدَ الْمِنْبَرَ فَبَايَعَهُ النَّاسُ عَامَّةً","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] telah mengabarkan kepada kami [Hisyam] dari [Ma'mar] dari [Az Zuhri] telah mengabarkan kepadaku [Anas bin Malik] radliallahu 'anhu, ia mendengar khutbah Umar yang terakhir ketika dia duduk diatas minbar, itu terjadi keesokan harinya setelah kewafatan Nabi shallallahu 'alaihi wasallam, [Umar] mengucapkan syahadat sedang Abu Bakar diam membisu tidak berbicara sama sekali. Kata Umar; 'aku sangat berharap seandainya Rasulullah Shallallahu'alaihiwasallam masih hidup hingga beliau hidup di belakang kita.' -Maksud Umar adalah seandainya Nabi shallallahu 'alaihi wasallam yang meninggal terakhir kali diantara para sahabat.- 'meskipun Muhammad Shallallahu'alaihiwasallam telah meninggal, tapi sesungguhnya Allah ta'ala telah menjadikan cahaya ditengah-tengah kalian yang bisa kalian jadikan untuk petunjuk. Allah telah menganugerahkan petunjuk kepada Muhammad Shallallahu'alaihiwasallam, dan sesungguhnya Abu Bakar adalah sahabat Rasulullah Shallallahu'alaihiwasallam, satu diantara dua orang (yang bersama beliau di gua tsur), dia adalah manusia yang paling utama untuk memegang amanat kepemimpinan urusan kalian, maka berdirilah kalian dan berbaiatlah kepadanya.' Sebagian diantara mereka ketika itu telah berbaiat kepadanya sebelum moment itu di Saqifah Bani Sa'idah, dan itulah bai'at umum diatas minbar. Az Zuhri mengatakan, dari Anas bin Malik, aku mendengar Umar mengatakan kepada Abu bakar ketika itu; \"Naiklah engkau ke minbar!\" Umar tiada henti-hentinya membujuknya hingga Abu bakar naik minbar, serta merta manusia secara umum berbaiat kepadanya."},"6346":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ أَبِيهِ عَنْ مُحَمَّدِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ أَبِيهِ قَالَأَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ امْرَأَةٌ فَكَلَّمَتْهُ فِي شَيْءٍ فَأَمَرَهَا أَنْ تَرْجِعَ إِلَيْهِ قَالَتْ يَا رَسُولَ اللَّهِ أَرَأَيْتَ إِنْ جِئْتُ وَلَمْ أَجِدْكَ كَأَنَّهَا تُرِيدُ الْمَوْتَ قَالَ إِنْ لَمْ تَجِدِينِي فَأْتِي أَبَا بَكْرٍ","id":"Telah menceritakan kepada kami [Abdul Aziz bin Abdullah] telah menceritakan kepada kami [Ibrahim bin sa'd] dari [Ayahnya] dari [Muhammad bin Jubair bin Muth'im] dari [Ayahnya] mengatakan, ada seorang wanita menemui Nabi shallallahu 'alaihi wasallam dan mengajak beliau bicara tentang suatu hal. Lantas beliau menyuruh si wanita itu untuk menemuinya di kemudian hari. Si wanita menjawab; 'hai Rasulullah, bagaimana kalau aku datang namun tidak mendapatkanmu? - sepertinya yang wanita maksudkan, jangan-jangan Nabi shallallahu 'alaihi wasallam sudah meninggal- Nabi menjawab \"Jika kau tidak menemukan aku, datangilah Abu bakar.\""},"6347":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ حَدَّثَنِي قَيْسُ بْنُ مُسْلِمٍ عَنْ طَارِقِ بْنِ شِهَابٍ عَنْ أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُقَالَ لِوَفْدِ بُزَاخَةَ تَتْبَعُونَ أَذْنَابَ الْإِبِلِ حَتَّى يُرِيَ اللَّهُ خَلِيفَةَ نَبِيِّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْمُهَاجِرِينَ أَمْرًا يَعْذِرُونَكُمْ بِهِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Sufyan] telah menceritakan kepadaku [Qais bin Muslim] dari [Thariq bin Syihab] dari [Abu Bakar] radliallahu 'anhu. Ia berkata kepada utusan Buzakhakh; 'hendaknya kalian mengikuti ekor-ekor unta sampai Allah memperlihatkan kepada khalifah Nabi-NYA Shallallahu'alaihiwasallam dan kaum muhajirin, satu keputusan yang dapat dijadikan alasan untuk memaafkan kalian.'"},"6348":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الْمَلِكِ سَمِعْتُ جَابِرَ بْنَ سَمُرَةَ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَكُونُ اثْنَا عَشَرَ أَمِيرًا فَقَالَ كَلِمَةً لَمْ أَسْمَعْهَا فَقَالَ أَبِي إِنَّهُ قَالَ كُلُّهُمْ مِنْ قُرَيْشٍ","id":"Telah menceritakan kepadaku [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Abdul Malik], aku mendengar [Jabir bin Samurah] mengatakan, aku mendengar Nabi shallallahu 'alaihi wasallam bersabda; \"akan muncul dua belas pemimpin, \" kemudian beliau mengucapkan kalimat yang tidak dapat kami dengar, maka [ayahku] berkata; beliau mengatakan: \"Kesemuanya dari qurasy.\""},"6349":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنِي مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ لَقَدْ هَمَمْتُ أَنْ آمُرَ بِحَطَبٍ يُحْتَطَبُ ثُمَّ آمُرَ بِالصَّلَاةِ فَيُؤَذَّنَ لَهَا ثُمَّ آمُرَ رَجُلًا فَيَؤُمَّ النَّاسَ ثُمَّ أُخَالِفَ إِلَى رِجَالٍ فَأُحَرِّقَ عَلَيْهِمْ بُيُوتَهُمْ وَالَّذِي نَفْسِي بِيَدِهِ لَوْ يَعْلَمُ أَحَدُكُمْ أَنَّهُ يَجِدُ عَرْقًا سَمِينًا أَوْ مِرْمَاتَيْنِ حَسَنَتَيْنِ لَشَهِدَ الْعِشَاءَ","id":"Telah menceritakan kepada kami [Ismail] telah menceritakan kepadaku [Malik] dari [Abu Zanad] dari [Al A'raj] dari [Abu Hurairah] radliallahu 'anhu, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Demi Dzat yang jiwaku berada di tangan-NYA, sungguh aku berkeinginan untuk dicarikan kayu bakar, kemudian kusuruh agar shalat dikumandangkan kemudian kusuruh seseorang untuk mengimami manusia, kemudian aku datangi orang-orang yang meninggalkan shalat kemudian aku bakar rumah mereka, Demi Dzat yang jiwaku berada di tangan-NYA, kalau salah seorang diantara kalian tahu akan mendapat sekerat daging gemuk atau dua bagian yang baik, niscaya ia akan menghadiri shalat isya\"."},"6350":{"ar":"حَدَّثَنِي يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍ أَنَّ عَبْدَ اللَّهِ بْنَ كَعْبِ بْنِ مَالِكٍوَكَانَ قَائِدَ كَعْبٍ مِنْ بَنِيهِ حِينَ عَمِيَ قَالَ سَمِعْتُ كَعْبَ بْنَ مَالِكٍ قَالَ لَمَّا تَخَلَّفَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ تَبُوكَ فَذَكَرَ حَدِيثَهُ وَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُسْلِمِينَ عَنْ كَلَامِنَا فَلَبِثْنَا عَلَى ذَلِكَ خَمْسِينَ لَيْلَةً وَآذَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِتَوْبَةِ اللَّهِ عَلَيْنَا","id":"Telah menceritakan kepadaku [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari [Abdurrahman bin Abdullah bin Ka'b bin Malik], bahwasanya [Abdullah bin Ka'b bin Malik], ia termasuk anaknya yang menuntun Ka'ab ketika telah buta (tuna netra), Abdullah mengatakan, aku mendengar [Ka'b bin Malik] mengatakan tatkala ketinggalan (duduk berpangku tangan) dari Rasulullah Shallallahu'alaihiwasallam dalam perang Tabuk. Ia menceritakan hadistnya yang panjang, dan menyebutkan bahwa; 'Rasulullah Shallallahu'alaihi wa sallam melarang kaum muslimin mengajak kami bicara, dan itu terus terjadi pada diri kami hingga lima puluh malam, dan Rasulullah Shallallahu'alaihiwasallam mengumumkan pengampunan Allah terhadap taubat kami.'"},"6351":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عُفَيْرٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ خَالِدٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ وَسَعِيدِ بْنِ الْمُسَيَّبِ أَنَّ أَبَا هُرَيْرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ وَالَّذِي نَفْسِي بِيَدِهِ لَوْلَا أَنَّ رِجَالًا يَكْرَهُونَ أَنْ يَتَخَلَّفُوا بَعْدِي وَلَا أَجِدُ مَا أَحْمِلُهُمْ مَا تَخَلَّفْتُ لَوَدِدْتُ أَنِّي أُقْتَلُ فِي سَبِيلِ اللَّهِ ثُمَّ أُحْيَا ثُمَّ أُقْتَلُ ثُمَّ أُحْيَا ثُمَّ أُقْتَلُ ثُمَّ أُحْيَا ثُمَّ أُقْتَلُ","id":"Telah menceritakan kepada kami [Sa'id bin Ufair] telah menceritakan kepadaku [Al Laits] telah menceritakan kepadaku [Abdurrahman bin Khalid] dari [Ibnu Syihab] dari [Abu Salamah] dan [Sa'id bin Musayyab], bahwa [Abu Hurairah] mengatakan; aku mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Demi Dzat yang jiwaku berada di tangan-NYA, kalaulah bukan karena pertimbangan beberapa orang yang tidak suka jika mereka ketinggalan atau pun aku memang tidak punya kendaraan untuk mengangkut mereka, niscaya aku tidak pernah absen (dari peperangan), sungguh aku berkeinginan jika terbunuh dalam rangka (perang) fi sabilillah kemudian dihidupkan, kemudian terbunuh, kemudian dihidupkan, kemudian terbunuh, kemudian dihidupkan, kemudian terbunuh.\""},"6352":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ وَدِدْتُ أَنِّي أُقَاتِلُ فِي سَبِيلِ اللَّهِ فَأُقْتَلُ ثُمَّ أُحْيَا ثُمَّ أُقْتَلُ ثُمَّ أُحْيَا ثُمَّ أُقْتَلُ فَكَانَ أَبُو هُرَيْرَةَ يَقُولُهُنَّ ثَلَاثًا أَشْهَدُ بِاللَّهِ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah mengabarkan kepada kami [Malik] dari [Abu Az Zanad] dari [Al A'raj] dari [Abu Hurairah], bahwasanya Rasulullah Shallallahu'alaihiwasalla bersabda; \"Demi Dzat yang jiwaku berada di tangan-NYA, sungguh aku suka jika aku berperang fi sabilillah lantas aku terbunuh, kemudian dihidupkan, kemudian terbunuh, kemudian dihidupkan, kemudian terbunuh.\" Abu Hurairah mengulanginya tiga kali; \"saya bersaksi atas nama Allah.\""},"6353":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ نَصْرٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ هَمَّامٍ سَمِعَ أَبَا هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْ كَانَ عِنْدِي أُحُدٌ ذَهَبًا لَأَحْبَبْتُ أَنْ لَا يَأْتِيَ عَلَيَّ ثَلَاثٌ وَعِنْدِي مِنْهُ دِينَارٌ لَيْسَ شَيْءٌ أَرْصُدُهُ فِي دَيْنٍ عَلَيَّ أَجِدُ مَنْ يَقْبَلُهُ","id":"Telah menceritakan kepada kami [Ishaq bin Nashr] telah menceritakan kepada kami [Abdurrazaq] dari [Ma'mar] dari [Hammam] ia mendengar [Abu Hurairah] dari Nabi Shallallahu'alaihiwasallam, beliau bersabda; \"Sekiranya aku mempunyai emas sebesar gunung Uhud, sungguh aku pun tetap berkeinginan untuk tidak mempunyai tiga dinar padahal aku masih mempunyai satu dinar, itupun tak ada alasan bagiku untuk mencarinya selain karena ada hutang yang harus kubayar, yang kuharap ada orang menerima pembayaran hutangku.\""},"6354":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ حَدَّثَنِي عُرْوَةُ أَنَّ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ اسْتَقْبَلْتُ مِنْ أَمْرِي مَا اسْتَدْبَرْتُ مَا سُقْتُ الْهَدْيَ وَلَحَلَلْتُ مَعَ النَّاسِ حِينَ حَلُّوا","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] telah menceritakan kepadaku ['Urwah], bahwasanya [Aisyah] mengatakan, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika aku bisa mengulang kembali apa yang telah lewat, niscaya tidak kutuntun binatang korban ini, dan aku bertahallul bersama orang-orang ketika mereka bertahallul.\""},"6355":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عُمَرَ حَدَّثَنَا يَزِيدُ عَنْ حَبِيبٍ عَنْ عَطَاءٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَبَّيْنَا بِالْحَجِّ وَقَدِمْنَا مَكَّةَ لِأَرْبَعٍ خَلَوْنَ مِنْ ذِي الْحِجَّةِ فَأَمَرَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَطُوفَ بِالْبَيْتِ وَبِالصَّفَا وَالْمَرْوَةِ وَأَنْ نَجْعَلَهَا عُمْرَةً وَنَحِلَّ إِلَّا مَنْ كَانَ مَعَهُ هَدْيٌ قَالَ وَلَمْ يَكُنْ مَعَ أَحَدٍ مِنَّا هَدْيٌ غَيْرَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَطَلْحَةَ وَجَاءَ عَلِيٌّ مِنْ الْيَمَنِ مَعَهُ الْهَدْيُ فَقَالَ أَهْلَلْتُ بِمَا أَهَلَّ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا نَنْطَلِقُ إِلَى مِنًى وَذَكَرُ أَحَدِنَا يَقْطُرُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَوْ اسْتَقْبَلْتُ مِنْ أَمْرِي مَا اسْتَدْبَرْتُ مَا أَهْدَيْتُ وَلَوْلَا أَنَّ مَعِي الْهَدْيَ لَحَلَلْتُ قَالَ وَلَقِيَهُ سُرَاقَةُ وَهُوَ يَرْمِي جَمْرَةَ الْعَقَبَةِ فَقَالَ يَا رَسُولَ اللَّهِ أَلَنَا هَذِهِ خَاصَّةً قَالَ لَا بَلْ لِأَبَدٍ قَالَ وَكَانَتْ عَائِشَةُ قَدِمَتْ مَعَهُ مَكَّةَ وَهِيَ حَائِضٌ فَأَمَرَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تَنْسُكَ الْمَنَاسِكَ كُلَّهَا غَيْرَ أَنَّهَا لَا تَطُوفُ وَلَا تُصَلِّي حَتَّى تَطْهُرَ فَلَمَّا نَزَلُوا الْبَطْحَاءَ قَالَتْ عَائِشَةُ يَا رَسُولَ اللَّهِ أَتَنْطَلِقُونَ بِحَجَّةٍ وَعُمْرَةٍ وَأَنْطَلِقُ بِحَجَّةٍ قَالَ ثُمَّ أَمَرَ عَبْدَ الرَّحْمَنِ بْنَ أَبِي بَكْرٍ الصِّدِّيقِ أَنْ يَنْطَلِقَ مَعَهَا إِلَى التَّنْعِيمِ فَاعْتَمَرَتْ عُمْرَةً فِي ذِي الْحَجَّةِ بَعْدَ أَيَّامِ الْحَجِّ","id":"Telah menceritakan kepada kami [Al Hasan bin Umar] telah menceritakan kepada kami [Yazid] dari [Habib] dari ['Atho`] dari [Jabir bin Abdullah] mengatakan; 'kami bersama Rasulullah Shallallahu'alaihiwasallam, kemudian kami mengucapkan niat talbiyah untuk haji, ketika kami tiba di Mekkah tanggal empat Dzul hijjah, Nabi shallallahu 'alaihi wasallam memerintahkan kami untuk melakukan thawaf di baitullah dan (sa'i) di Shafa dan Marwa, dan agar kami menjadikannya sebagai Umrah, maka kami bertahallul kecuali bagi mereka yang terlanjur membawa korban.' Kata Jabir; 'dan tidak ada seorangpun dari kami yang membawa binatang korban selain Nabi shallallahu 'alaihi wasallam dan Tolhah. Datanglah Ali dari Yaman sambil membawa binatang korban, kemudian ia berucap; 'Saya mengucapkan niat sebagaimana Rasulullah Shallallahu'alaihiwasallam berniat.' Para sahabat berujar; 'Kami akan berangkat ke Mina, sedang kemaluan salah seorang diantara kami meneteskan air mani.' Maka Rasulullah Shallallahu'alaihiwasallam bersabda; \"kalaulah aku bisa mengulang kembali apa yang telah lewat, niscaya aku tidak menyembelih korban, kalaulah aku tidak membawa binatang korban niscaya aku akan bertahallul.\" Kata Jabir; kemudian Suraqah menemui beliau yang saat itu sedang melempar jumrah 'aqabah, ia berujar; \"Wahai Rasulullah, apakah umrah seperti ini khusus bagi kami?\" Nabi menjawab: \"TIDAK, bahkan untuk selamanya.\" Kata Jabir; 'dan Aisyah bersama Beliau tiba di Makkah dalam keadaan haidh, maka Nabi memerintahkannya untuk melakukan seluruh manasik kecuali ia tidak boleh thawaf dan tidak shalat hingga suci. Tatkala mereka telah singgah di Bathha`, Aisyah berkata; \"Wahai Rasulullah, apakah kalian bertolak untuk haji dan 'umrah sedang aku hanya untuk haji?\" Jabir melanjutkan; kemudian Rasulullah memerintahkan Abdurrahman bin Abu Bakar as Siddiq untuk bertolak bersamanya ke Tan'im, dan Aisyah berumrah di bulan Dzulhijjah, masih dalam hari-hari haji."},"6356":{"ar":"حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ حَدَّثَنِي يَحْيَى بْنُ سَعِيدٍ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عَامِرِ بْنِ رَبِيعَةَ قَالَ قَالَتْ عَائِشَةُأَرِقَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ لَيْلَةٍ فَقَالَ لَيْتَ رَجُلًا صَالِحًا مِنْ أَصْحَابِي يَحْرُسُنِي اللَّيْلَةَ إِذْ سَمِعْنَا صَوْتَ السِّلَاحِ قَالَ مَنْ هَذَا قَالَ سَعْدٌ يَا رَسُولَ اللَّهِ جِئْتُ أَحْرُسُكَ فَنَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى سَمِعْنَا غَطِيطَهُقَالَ أَبُو عَبْد اللَّهِ وَقَالَتْ عَائِشَةُ قَالَ بِلَالٌأَلَا لَيْتَ شِعْرِي هَلْ أَبِيتَنَّ لَيْلَةًبِوَادٍ وَحَوْلِي إِذْخِرٌ وَجَلِيلُفَأَخْبَرْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Khalid bin makhlad] telah menceritakan kepada kami [Sulaiman bin Bilal] telah menceritakan kepadaku [Yahya bin sa'id], aku mendengar [Abdullah bin Amir bin Rabi'ah] mengatakan, [Aisyah] menuturkan; Suatu malam Rasulullah Shallallahu'alaihiwasallam tidak bisa tidur, lantas beliau mengatakan: \"Duhai sekiranya ada seorang laki-laki shalih dari sahabatku menjagaku malam ini\" Tiba-tiba kami mendengar suara senjata. Nabi bertanya: \"siapa ini?\" Sa'd menjawab; \"Ya Rasulullah, aku datang untuk menjagamu!\" maka Nabi shallallahu 'alaihi wasallam tidur hingga aku mendengar suara nafas beliau. Abu Abdullah mengatakan \"dan Aisyah mengatakan, Bilal mengatakan; \"duhai seandainya aku tinggal pada malam ini, di suatu lembah di sekelilingku idkhir dan jalil.\""},"6357":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَحَاسُدَ إِلَّا فِي اثْنَتَيْنِ رَجُلٌ آتَاهُ اللَّهُ الْقُرْآنَ فَهُوَ يَتْلُوهُ آنَاءَ اللَّيْلِ وَالنَّهَارِ يَقُولُ لَوْ أُوتِيتُ مِثْلَ مَا أُوتِيَ هَذَا لَفَعَلْتُ كَمَا يَفْعَلُ وَرَجُلٌ آتَاهُ اللَّهُ مَالًا يُنْفِقُهُ فِي حَقِّهِ فَيَقُولُ لَوْ أُوتِيتُ مِثْلَ مَا أُوتِيَ لَفَعَلْتُ كَمَا يَفْعَلُحَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا جَرِيرٌ بِهَذَا","id":"Telah menceritakan kepada kami [Ustman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] mengatakan, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak diperbolehkan dengki selain dalam dua hal, seseorang yang Allah beri al qur`an lantas ia baca sepanjang malam dan siang, sehingga ada orang lain berkata; 'Kalaulah aku diberi kurnia seperti orang itu, niscaya kulakukan sebagaimana yang dia lakukan.' Dan seseorang yang Allah beri harta, ia belanjakan menurut haknya sehingga orang mengatakan; 'Kalaulah aku diberi seperti yang dikaruniakan kepada dia, niscaya kulakukan sebagaimana yang dia lakukan.'\" Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Jarir] dengan hadist ini."},"6358":{"ar":"حَدَّثَنَا حَسَنُ بْنُ الرَّبِيعِ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ عَاصِمٍ عَنْ النَّضْرِ بْنِ أَنَسٍ قَالَ قَالَ أَنَسٌ رَضِيَ اللَّهُ عَنْهُلَوْلَا أَنِّي سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَتَمَنَّوْا الْمَوْتَ لَتَمَنَّيْتُ","id":"Telah menceritakan kepada kami [Hasan bin Rabi'] telah menceritakan kepada kami [Abul Ahwash] dari ['Ashim] dari [Nadhr bin Anas] mengatakan, [Anas] radliallahu 'anhu menuturkan; kalaulah aku tidak mendengar Rasulullah Shallallahu'alaihi wa sallam bersabda: \"Janganlah kalian mengharap kematian, \" niscya aku mengharapkannya.'"},"6359":{"ar":"حَدَّثَنَا مُحَمَّدٌ حَدَّثَنَا عَبْدَةُ عَنْ ابْنِ أَبِي خَالِدٍ عَنْ قَيْسٍ قَالَ أَتَيْنَا خَبَّابَ بْنَ الْأَرَتِّنَعُودُهُ وَقَدْ اكْتَوَى سَبْعًا فَقَالَ لَوْلَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَانَا أَنْ نَدْعُوَ بِالْمَوْتِ لَدَعَوْتُ بِهِ","id":"Telah menceritakan kepada kami [Muhammad] telah menceritakan kepada kami ['Abdah] dari [Ibnu abi Khalid] dari [Qais] mengatakan; Pernah kami mendatangi [Khabbab bin Al Arat] untuk membesuknya, yang ketika itu ia telah berobat dengan kay (di temple dengan besi panas) sebanyak tujuh kali, dia mengatakan; 'Kalaulah Rasulullah Shallallahu'alaihiwasallam tidak melarang kami memohon kematian, niscaya aku memohonnya.'"},"6360":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا هِشَامُ بْنُ يُوسُفَ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي عُبَيْدٍ اسْمُهُ سَعْدُ بْنُ عُبَيْدٍ مَوْلَى عَبْدِ الرَّحْمَنِ بْنِ أَزْهَرَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَتَمَنَّى أَحَدُكُمْ الْمَوْتَ إِمَّا مُحْسِنًا فَلَعَلَّهُ يَزْدَادُ وَإِمَّا مُسِيئًا فَلَعَلَّهُ يَسْتَعْتِبُ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] telah menceritakan kepada kami [Hisyam bin Yusuf] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Abu Ubaid], namanya Sa'd bin Ubaid maula Abdurrahman bin Azhar, dari [Abu Hurairah], bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jangan salah seorang diantara kalian mengharapkan kematian, kalaulah dia orang baik, siapa tahu bisa menambah kebaikannya, kalaulah dia jahat, siapa tahu ia bisa meminta penangguhan (untuk bertaubat).\""},"6361":{"ar":"حَدَّثَنَ�� عَبْدَانُ أَخْبَرَنِي أَبِي عَنْ شُعْبَةَ حَدَّثَنَا أَبُو إِسْحَاقَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْقُلُ مَعَنَا التُّرَابَ يَوْمَ الْأَحْزَابِ وَلَقَدْ رَأَيْتُهُ وَارَى التُّرَابُ بَيَاضَ بَطْنِهِ يَقُولُ لَوْلَا أَنْتَ مَا اهْتَدَيْنَا نَحْنُ وَلَا تَصَدَّقْنَا وَلَا صَلَّيْنَا فَأَنْزِلَنْ سَكِينَةً عَلَيْنَا إِنَّ الْأُلَى وَرُبَّمَا قَالَ الْمَلَا قَدْ بَغَوْا عَلَيْنَا إِذَا أَرَادُوا فِتْنَةً أَبَيْنَا أَبَيْنَا يَرْفَعُ بِهَا صَوْتَهُ","id":"Telah menceritakan kepada kami [Abdan] telah mengabarkan kepada kami [Ayahku] dari [Syu'bah] telah menceritakan kepada kami [Abu Ishaq] dari [Albara` bin 'Azib] mengatakan; Nabi shallallahu 'alaihi wasallam bersama kami memindahkan tanah pada perang Ahzab, dan aku lihat beliau menimbun tanah yang mengakibatkan kelihatan putih kedua ketiaknya, beliau mengucapkan; \"Kalaulah bukan karena Engkau kami tidak dapat petunjuk, tidak pula bersedekah, tidak juga shalat. Maka turunkanlah ketenangan bagi kami, Sesungguhnya sekelompok kaum --atau sepertinya Barra' mengatakan pemuka kaum- telah sewenang-wenang terhadap kami, jika mereka ingin berbuat onar kami mengelak, kami mengelak,,, \" sambil beliau tinggikan volume suaranya."},"6362":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا مُعَاوِيَةُ بْنُ عَمْرٍو حَدَّثَنَا أَبُو إِسْحَاقَ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ سَالِمٍ أَبِي النَّضْرِ مَوْلَى عُمَرَ بْنِ عُبَيْدِ اللَّهِوَكَانَ كَاتِبًا لَهُ قَالَ كَتَبَ إِلَيْهِ عَبْدُ اللَّهِ بْنُ أَبِي أَوْفَى فَقَرَأْتُهُ فَإِذَا فِيهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَتَمَنَّوْا لِقَاءَ الْعَدُوِّ وَسَلُوا اللَّهَ الْعَافِيَةَ","id":"Telah menceritakan kepadaku [Abdullah bin Muhammad] telah menceritakan kepada kami [Mu'awiyah bin Umar] telah menceritakan kepada kami [Abu Ishaq] dari [Musa bin Uqbah] dari [Salim abu an Nadhr], maula Umar bin Ubaidullah yang ia sekaligus penulisnya, mengatakan, [Abdullah bin Abu Awfa] berkirim surat kepadanya dan aku membacanya, yang dalam isi suratnya tertulis; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jangan kalian mengharapkan bertemu musuh, dan mintalah keselamatan kepada Allah.\""},"6363":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ قَالَ ذَكَرَ ابْنُ عَبَّاسٍالْمُتَلَاعِنَيْنِ فَقَالَ عَبْدُ اللَّهِ بْنُ شَدَّادٍ أَهِيَ الَّتِي قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ كُنْتُ رَاجِمًا امْرَأَةً مِنْ غَيْرِ بَيِّنَةٍ قَالَ لَا تِلْكَ امْرَأَةٌ أَعْلَنَتْ","id":"Telah menceritakan kepada kami ['Ali bin Abdullah] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Abu Az Zanad] dari [Al Qashim bin Muhammad] mengatakan, [Ibnu 'Abbas] mengisahkan perihal dua orang yang saling meli'an. Lantas Abdullah bin Syadad bertanya; Itukah wanita yang dimaksudkan Rasulullah shallallahu 'alaihi wasallam dalam sabdanya; \"Kalaulah aku merajam seorang wanita tanpa bukti, (niscaya kurajam), \" Ibnu Abbas menjawab \"tidak, justru wanita yang dirajam dengan tanpa bukti ialah jika ia secara terang-terangan mengakui perzinahannya.\""},"6364":{"ar":"حَدَّثَنَا عَلِيٌّ حَدَّثَنَا سُفْيَانُ قَالَ عَمْرٌو حَدَّثَنَا عَطَاءٌ قَالَأَعْتَمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْعِشَاءِ فَخَرَجَ عُمَرُ فَقَالَ الصَّلَاةَ يَا رَسُولَ اللَّهِ رَقَدَ النِّسَاءُ وَالصِّبْيَانُ فَخَرَجَ وَرَأْسُهُ يَقْطُرُ يَقُولُ لَوْلَا أَنْ أَشُقَّ عَلَى أُمَّتِي أَوْ عَلَى النَّاسِ وَقَالَ سُفْيَانُ أَيْضًا عَلَى أُمَّتِي لَأَمَرْتُهُمْ بِالصَّلَاةِ هَذِهِ السَّاعَةَقَالَ ابْنُ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ أَخَّرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذِهِ الصَّلَاةَ فَجَاءَ عُمَرُ فَقَالَ يَا رَسُولَ اللَّهِ رَقَدَ النِّسَاءُ وَالْوِلْدَانُ فَخَرَجَ وَهُوَ يَمْسَحُ الْمَاءَ عَنْ شِقِّهِ يَقُولُ إِنَّهُ لَلْوَقْتُ لَوْلَا أَنْ أَشُقَّ عَلَى أُمَّتِي وَقَالَ عَمْرٌو حَدَّثَنَا عَطَاءٌ لَيْسَ فِيهِ ابْنُ عَبَّاسٍ أَمَّا عَمْرٌو فَقَالَ رَأْسُهُ يَقْطُرُ وَقَالَ ابْنُ جُرَيْجٍ يَمْسَحُ الْمَاءَ عَنْ شِقِّهِ وَقَالَ عَمْرٌو لَوْلَا أَنْ أَشُقَّ عَلَى أُمَّتِي وَقَالَ ابْنُ جُرَيْجٍ إِنَّهُ لَلْوَقْتُ لَوْلَا أَنْ أَشُقَّ عَلَى أُمَّتِي وَقَالَ إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا مَعْنٌ حَدَّثَنِي مُحَمَّدُ بْنُ مُسْلِمٍ عَنْ عَمْرٍو عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami ['Ali] telah menceritakan kepada kami [Sufyan], ['Amru] mengatakan, telah menceritakan kepada kami ' [Atho'] mengatakan, Nabi shallallahu 'alaihi wasallam menangguhkan shalat isya' agak malam, maka Umar keluar (dari masjid) dan mengatakan; 'Mari tegakkan shalat ya Rasulullah, wanita dan anak-anak telah tidur! ' Nabi muncul dari kamarnya dan kepalanya meneteskan air sambil berkata: \"Kalaulah tidak memberatkan umatku -atau dengan redaksi; tidak memberatkan manusia -, \" sedangkan Sufyan mengatakan; atas umatku - niscaya kuperintahkan kepada mereka untuk shalat dengan waktu seperti ini.\" [Ibnu Juraij] mengatakan, dari ['Atho`] dari [Ibnu 'Abbas] menuturkan; Nabi shallallahu 'alaihi wasallam menangguhkan shalat ini, maka Umar datang dan mengatakan; 'Ya Rasulullah, para wanita dan anak-anak telah tertidur' lantas beliau muncul sedang beliau sambil mengusap air dari lambungnya sambil mengatakan; \"inilah waktu untuk shalat isya', kalau saja tidak memberatkan umatku.\" Dan [Amru] mengatakan telah menceritakan kepada kami ['Atho], dalam sanadnya tidak menyebutkan Ibnu Abbas. Amru mengatakan; kepalanya meneteskan (air). sedang Ibnu Juraij mengatakan; mengusap air dari lambungnya. Dan Amru mengatakan; \"Kalaulah tidak memberatkan atas umatku.\" Sedang Ibnu Juraij mengatakan; \"sungguh ini adalah waktu semestinya, kalaulah tidak memberatkan umatku.\" Sedang [Ibrahim bin Al Mundzir] mengatakan, telah menceritakan kepada kami [Ma'an], telah menceritakan kepadaku [Muhammad bin Muslim] dari ['Amru] dari ['Atho`] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam."},"6365":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ جَعْفَرِ بْنِ رَبِيعَةَ عَنْ عَبْدِ الرَّحْمَنِ سَمِعْتُ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْلَا أَنْ أَشُقَّ عَلَى أُمَّتِي لَأَمَرْتُهُمْ بِالسِّوَاكِ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari [Ja'far bin Rabi'ah] dari [Abdurrahman] aku mendengar [Abu Hurairah] radliallahu 'anhu, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kalaulah tidak memberatkan umatku, niscaya kuperintahkan mereka bersiwak.\""},"6366":{"ar":"حَدَّثَنَا عَيَّاشُ بْنُ الْوَلِيدِ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا حُمَيْدٌ عَنْ ثَابِتٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَوَاصَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ آخِرَ الشَّهْرِ وَوَاصَلَ أُنَاسٌ مِنْ النَّاسِ فَبَلَغَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَوْ مُدَّ بِيَ الشَّهْرُ لَوَاصَلْتُ وِصَالًا يَدَعُ الْمُتَعَمِّقُونَ تَعَمُّقَهُمْ إِنِّي لَسْتُ مِثْلَكُمْ إِنِّي أَظَلُّ يُطْعِمُنِي رَبِّي وَيَسْقِينِتَابَعَهُ سُلَيْمَانُ بْنُ مُغِيرَةَ عَنْ ثَابِتٍ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami ['Ayyasy bin Al Walid] telah menceritakan kepada kami [Abdul A'la] telah menceritakan kepada kami [Humaid] dari [Tsabit] dari [Anas] radliallahu 'anhu, mengatakan; Nabi shallallahu 'alaihi wasallam menyambung akhir bulan (untuk tetap berpuasa) sehingga sahabat lain menyambungnya (wishal). Berita ini sampai kepada Nabi shallallahu 'alaihi wasallam, sehingga beliau bersabda; \"Kalaulah bulan dipanjangkan bagiku, niscaya kulakuan puasa wishal, sehingga orang-orang yang berlebihan dalam beragama meninggalkan kebiasaan berlebih-lebihannya, Sungguh aku tidak seperti kalian, Tuhanku senantiasa memberiku makan dan minum.\" hadist ini diperkuat oleh [Sulaiman bin Mughirah] dari [Tsabit] dari [Anas] dari Nabi shallallahu 'alaihi wasallam. "},"6367":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ وَقَالَ اللَّيْثُ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ خَالِدٍ عَنْ ابْنِ شِهَابٍ أَنَّ سَعِيدَ بْنَ الْمُسَيَّبِ أَخْبَرَهُ أَنَّ أَبَا هُرَيْرَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْوِصَالِ قَالُوا فَإِنَّكَ تُوَاصِلُ قَالَ أَيُّكُمْ مِثْلِي إِنِّي أَبِيتُ يُطْعِمُنِي رَبِّي وَيَسْقِينِ فَلَمَّا أَبَوْا أَنْ يَنْتَهُوا وَاصَلَ بِهِمْ يَوْمًا ثُمَّ يَوْمًا ثُمَّ رَأَوْا الْهِلَالَ فَقَالَ لَوْ تَأَخَّرَ لَزِدْتُكُمْ كَالْمُنَكِّلِ لَهُمْ","id":"Telah menceritakan kepada kami [Abul Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dan [Al Laits] berkata; telah menceritakan kepadaku [Abdurrahman bin Khalid] dari [Ibn Syihab] bahwasanya [Sa'id bin Musayyab] mengabarkan kepadanya, bahwa [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang puasa wishal, Para sahabat mengemukakan alasan, \"Anda sendiri puasa wishal ya Rasulullah!\" Nabi menjawab: \"Siapa di antara kalian yang bisa sepertiku, sungguh tuhanku selalu memberiku makan dan minum.\" Tatkala para sahabat enggan menghentikan wishalnya, beliau menyambung puasanya bersama mereka hari demi hari, kemudian mereka melihat hilal (bulan sabit), lantas Nabi berkata: \"Jika bulan itu terlambat, niscaya kutambah lagi puasanya, \" seolah-olah beliau ingin menghukum para sahabatnya.\""},"6368":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو الْأَحْوَصِ حَدَّثَنَا أَشْعَثُ عَنْ الْأَسْوَدِ بْنِ يَزِيدَ عَنْ عَائِشَةَ قَالَتْسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْجَدْرِ أَمِنَ الْبَيْتِ هُوَ قَالَ نَعَمْ قُلْتُ فَمَا لَهُمْ لَمْ يُدْخِلُوهُ فِي الْبَيْتِ قَالَ إِنَّ قَوْمَكِ قَصَّرَتْ بِهِمْ النَّفَقَةُ قُلْتُ فَمَا شَأْنُ بَابِهِ مُرْتَفِعًا قَالَ فَعَلَ ذَاكِ قَوْمُكِ لِيُدْخِلُوا مَنْ شَاءُوا وَيَمْنَعُوا مَنْ شَاءُوا وَلَوْلَا أَنَّ قَوْمَكِ حَدِيثٌ عَهْدُهُمْ بِالْجَاهِلِيَّةِ فَأَخَافُ أَنْ تُنْكِرَ قُلُوبُهُمْ أَنْ أُدْخِلَ الْجَدْرَ فِي الْبَيْتِ وَأَنْ أَلْصِقْ بَابَهُ فِي الْأَرْضِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abul Ahwash] telah menceritakan kepada kami [Asy'ats] dari [Al Aswad bin Yazid] dari ['Aisyah] berkata, \"Aku bertanya Nabi shallallahu 'alaihi wasallam tentang Hijir Ismail, apakah termasuk baitullah?\" Nabi menjawab: \"Ya.\" Aku bertanya, \"Mengapa para sahabat tidak memasukkannya dalam baitullah?\" Nabi menjawab: \"Kaummu dahulu kekurangan dana renovasi.\" Aku bertanya, \"Lantas bagaimana pintunya ditinggikan?\" Nabi menjawab: \"Kaummu melakukan yang sedemikian untuk memasukkan siapa saja yang dikehendakinya, dan melarang siapa saja yang dikehendaki, kalaulah bukan karena kaummu yang baru saja masuk Islam sehingga aku khawatir hati mereka menolak, niscaya kumasukkan Hijir Ismail dalam Ka'bah, dan kuratakan pintunya dengan tanah.\""},"6369":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْلَا الْهِجْرَةُ لَكُنْتُ امْرَأً مِنْ الْأَنْصَارِ وَلَوْ سَلَكَ النَّاسُ وَادِيًا وَسَلَكَتْ الْأَنْصَارُ وَادِيًا أَوْ شِعْبًا لَسَلَكْتُ وَادِيَ الْأَنْصَارِ أَوْ شِعْبَ الْأَنْصَارِ","id":"Telah menceritakan kepada kami [Abul Yaman] telah mengabarkan kepada kami [Syu'aib] telah menceritakan kepada kami [Abuz Zinad] dari [Al A'raj] dari [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kalaulah bukan karena hijrah, maka aku adalah seorang Anshar, kalaulah manusia mengarungi lembah dan Anshar mengarungi lembah lain atau lereng gunung, niscaya aku mengarungi lembah Anshar atau lereng gunung Anshar.\""},"6370":{"ar":"حَدَّثَنَا مُوسَى حَدَّثَنَا وُهَيْبٌ عَنْ عَمْرِو بْنِ يَحْيَى عَنْ عَبَّادِ بْنِ تَمِيمٍ عَنْ عَبْدِ اللَّهِ بْنِ زَيْدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّم�� قَالَ لَوْلَا الْهِجْرَةُ لَكُنْتُ امْرَأً مِنْ الْأَنْصَارِ وَلَوْ سَلَكَ النَّاسُ وَادِيًا أَوْ شِعْبًا لَسَلَكْتُ وَادِيَ الْأَنْصَارِ وَشِعْبَهَاتَابَعَهُ أَبُو التَّيَّاحِ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الشِّعْبِ","id":"Telah menceritakan kepada kami [Musa] telah menceritakan kepada kami [Wuhaib] dari ['Amru bin Yahya] dari ['Abbad bin Tamim] dari ['Abdullah bin Zaid] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Kalaulah bukan karena hijrah, niscaya aku menjadi orang Anhsar, dan kalaulah manusia menempuh sebuah lembah atau lereng gunung, niscaya aku mengarungi lembah Anshar atau lereng gunungnya.\" Hadis ini diperkuat oleh [Abu Thayyah] dari [Anas] dari Nabi shallallahu 'alaihi wasallam."},"6371":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي قِلَابَةَ حَدَّثَنَا مَالِكُ بْنُ الْحُوَيْرِثِ قَالَأَتَيْنَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ شَبَبَةٌ مُتَقَارِبُونَ فَأَقَمْنَا عِنْدَهُ عِشْرِينَ لَيْلَةً وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَفِيقًا فَلَمَّا ظَنَّ أَنَّا قَدْ اشْتَهَيْنَا أَهْلَنَا أَوْ قَدْ اشْتَقْنَا سَأَلَنَا عَمَّنْ تَرَكْنَا بَعْدَنَا فَأَخْبَرْنَاهُ قَالَ ارْجِعُوا إِلَى أَهْلِيكُمْ فَأَقِيمُوا فِيهِمْ وَعَلِّمُوهُمْ وَمُرُوهُمْ وَذَكَرَ أَشْيَاءَ أَحْفَظُهَا أَوْ لَا أَحْفَظُهَا وَصَلُّوا كَمَا رَأَيْتُمُونِي أُصَلِّي فَإِذَا حَضَرَتْ الصَّلَاةُ فَلْيُؤَذِّنْ لَكُمْ أَحَدُكُمْ وَلْيَؤُمَّكُمْ أَكْبَرُكُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami ['Abdul Wahhab] telah menceritakan kepada kami [Ayyub] dari [Abu Qilabah] telah menceritakan kepada kami [Malik bin Al Huwairits] berkata, \"Kami mendatangi Nabi shallallahu 'alaihi wasallam yang ketika itu kami masih muda sejajar umurnya, kemudian kami bermukim di sisi beliau selama dua puluh malam. Rasulullah shallallahu 'alaihi wasallam adalah seorang pribadi yang lembut. Maka ketika beliau menaksir bahwa kami sudah rindu dan selera terhadap isteri-isteri kami, beliau bersabda: \"Kembalilah kalian untuk menemui isteri-isteri kalian, berdiamlah bersama mereka, ajari dan suruhlah mereka, \" dan beliau menyebut beberapa perkara yang sebagian kami ingat dan sebagiannya tidak, \"dan shalatlah sebagaimana kalian melihat aku shalat. Jika shalat telah tiba, hendaklah salah seorang di antara kalian melakukan adzan dan yang paling dewasa menjadi imam.\""},"6372":{"ar":"حَدَّثَنَا مُسَدَّدٌ عَنْ يَحْيَى عَنْ التَّيْمِيِّ عَنْ أَبِي عُثْمَانَ عَنْ ابْنِ مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَمْنَعَنَّ أَحَدَكُمْ أَذَانُ بِلَالٍ مِنْ سَحُورِهِ فَإِنَّهُ يُؤَذِّنُ أَوْ قَالَ يُنَادِي لِيَرْجِعَ قَائِمَكُمْ وَيُنَبِّهَ نَائِمَكُمْ وَلَيْسَ الْفَجْرُ أَنْ يَقُولَ هَكَذَا وَجَمَعَ يَحْيَى كَفَّيْهِ حَتَّى يَقُولَ هَكَذَا وَمَدَّ يَحْيَى إِصْبَعَيْهِ السَّبَّابَتَيْنِ","id":"Telah menceritakan kepada kami [Musaddad] dari [Yahya] dari [At Taimi] dari [Abu Utsman] dari [Ibn Mas'ud] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah adzan bilal mencegah kalian dari makan sahur, sebab dia adzan -atau ia katakan dengan redaksi 'memanggil'- agar orang yang shalat malam pulang, dan yang tidur agar bangun, fajar itu bukan, beliau katakan begini -Yahya mendemontrasikannya dengan menyatukan kedua telapak tangannya-hingga beliau katakan begini -Yahya mendemontrasikannya dengan merenggangkan kedua jarinya, telunjuk dan jari tengah.\""},"6373":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُسْلِمٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دِينَارٍ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ بِلَالًا يُنَادِي بِلَيْلٍ فَكُلُوا وَاشْرَبُوا حَتَّى يُنَادِيَ ابْنُ أُمِّ مَكْتُومٍ","id":"Telah menceritakan kepada kami [Musa bin Ismail] telah menceritakan kepada kami ['Abdul Aziz bin Muslim] telah menceritakan kepada kami [Abdullah bin Dinar], aku mendengar [Abdullah bin Umar] radliallahu 'anhuma dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Bilal mengumandangkan adzan di waktu malam, silahkan makan dan minumlah kalian hingga Ibnu Ummi Maktum mengumandangkan adzan.\""},"6374":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَصَلَّى بِنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظُّهْرَ خَمْسًا فَقِيلَ أَزِيدَ فِي الصَّلَاةِ قَالَ وَمَا ذَاكَ قَالُوا صَلَّيْتَ خَمْسًا فَسَجَدَ سَجْدَتَيْنِ بَعْدَ مَا سَلَّمَ","id":"Telah menceritakan kepada kami [Hafs bin Umar] telah menceritakan kepada kami [Syu'bah] [Al Hakam] dari [Ibrahim] dari ['Alqamah] dari [Abdullah] berkata, \"Nabi shallallahu 'alaihi wasallam mengimami kami shalat zhuhur sebanyak lima rakaat, maka beliau ditegur 'Apakah shalat sekarang ditambah? ' Nabi bertanya: 'Memang berapa shalatku? ' para sahabat menjawab, \"Lima rakaat, \" maka beliau sujud dua kali setelah mengucapkan salam.\""},"6375":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنِي مَالِكٌ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْصَرَفَ مِنْ اثْنَتَيْنِ فَقَالَ لَهُ ذُو الْيَدَيْنِ أَقَصُرَتْ الصَّلَاةُ يَا رَسُولَ اللَّهِ أَمْ نَسِيتَ فَقَالَ أَصَدَقَ ذُو الْيَدَيْنِ فَقَالَ النَّاسُ نَعَمْ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى رَكْعَتَيْنِ أُخْرَيَيْنِ ثُمَّ سَلَّمَ ثُمَّ كَبَّرَ ثُمَّ سَجَدَ مِثْلَ سُجُودِهِ أَوْ أَطْوَلَ ثُمَّ رَفَعَ ثُمَّ كَبَّرَ فَسَجَدَ مِثْلَ سُجُودِهِ ثُمَّ رَفَعَ","id":"Telah menceritakan kepada kami [Ismail] telah menceritakan kepadaku [Malik] dari [Ayyub] dari [Muhammad] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam menyelesaikan shalatnya padahal baru melakukan dua rakaat. Karenanya Dzul Yadaini bertanya, 'Apakah engkau meringkas shalat ya Rasulullah, ataukah engkau sekedar lupa? ' Nabi balik bertanya: 'Apakah Dzul Yadaini benar? ' Para sahabat menjawab, 'Benar! Lantas Rasulullah shallallahu 'alaihi wasallam berdiri dan melanjutkan shalat dua rakaat berikutnya, kemudian beliau mengucapkan salam, kemudian bertakbir, kemudian sujud seperti sujudnya atau lebih lama, kemudian mengangkat sujudnya, kemudian bertakbir dan sujud seperti sujudnya, kemudian beliau mengangkat sujudnya.\""},"6376":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنِي مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَبَيْنَا النَّاسُ بِقُبَاءٍ فِي صَلَاةِ الصُّبْحِ إِذْ جَاءَهُمْ آتٍ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أُنْزِلَ عَلَيْهِ اللَّيْلَةَ قُرْآنٌ وَقَدْ أُمِرَ أَنْ يَسْتَقْبِلَ الْكَعْبَةَ فَاسْتَقْبِلُوهَا وَكَانَتْ وُجُوهُهُمْ إِلَى الشَّأْمِ فَاسْتَدَارُوا إِلَى الْكَعْبَةِ","id":"Telah menceritakan kepada kami [Ismail] telah menceritakan kepadaku [Malik] dari [Abdullah bin Dinar] dari [Abdullah bin Umar] berkata, \"Tatkala para sahabat di Quba' sedang melakukan shalat subuh, tiba-tiba ada seorang utusan mendatangi mereka seraya berkata, 'Rasulullah shallallahu 'alaihi wasallam malam tadi diturunkan kepadanya ayat Al Qur'an yang berisi perintah untuk menghadap Ka'bah! ' Waktu itu wajah mereka sedang menghadap ke arah Syam, maka secara spontan mereka memalingkan ke Ka'bah.\""},"6377":{"ar":"حَدَّثَنَا يَحْيَى حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَاقَ عَنْ الْبَرَاءِ قَالَلَمَّا قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ صَلَّى نَحْوَ بَيْتِ الْمَقْدِسِ سِتَّةَ عَشَرَ أَوْ سَبْعَةَ عَشَرَ شَهْرًا وَكَانَ يُحِبُّ أَنْ يُوَجَّهَ إِلَى الْكَعْبَةِ فَأَنْزَلَ اللَّهُ تَعَالَى{ قَدْ نَرَى تَقَلُّبَ وَجْهِكَ فِي السَّمَاءِ فَلَنُوَلِّيَنَّكَ قِبْلَةً تَرْضَاهَا }فَوُجِّهَ نَحْوَ الْكَعْبَةِ وَصَلَّى مَعَهُ رَجُلٌ الْعَصْرَ ثُمَّ خَرَجَ فَمَرَّ عَلَى قَوْمٍ مِنْ الْأَنْصَارِ فَقَالَ هُوَ يَشْهَدُ أَنَّهُ صَلَّى مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَّهُ قَدْ وُجِّهَ إِلَى الْكَعْبَةِ فَانْحَرَفُوا وَهُمْ رُكُوعٌ فِي صَلَاةِ الْعَصْرِ","id":"Telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Waki'] dari [Israil] dari [Abu Ishaq] dari [Al Bara'] ia berkata, \"Tatkala Rasulullah shallallahu 'alaihi wasallam tiba di Madinah, beliau shalat menghadap Baitul Maqdis selama enam belas atau tujuh belas bulan, padahal beliau amat senang jika disuruh menghadap Ka'bah. Maka Allah pun menurunkan ayat: '(Kami telah melihat penglihatan wajahmu di langit, maka kami palingkan kamu ke kiblat yang kamu ridhai) ' (Qs. Al Baqarah: 144), maka beliau dihadapkan wajahnya ke Ka'bah, ketika itu seseorang shalat 'ashar bersama beliau, lantas keluar dan melewati sekelompok orang-orang Anshar, lalu ia katakan kepada mereka sekaligus bersaksi bahwa ia telah shalat bersama nabi shallallahu 'alaihi wasallam, dan kiblat beliau telah di hadapkan ke Ka'bah, maka mereka pun menggeser kiblatnya yang ketika itu mereka sedang rukuk pada shalat 'ashar.\""},"6378":{"ar":"حَدَّثَنِي يَحْيَى بْنُ قَزَعَةَ حَدَّثَنِي مَالِكٌ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَكُنْتُ أَسْقِي أَبَا طَلْحَةَ الْأَنْصَارِيَّ وَأَبَا عُبَيْدَةَ بْنَ الْجَرَّاحِ وَأُبَيَّ بْنَ كَعْبٍ شَرَابًا مِنْ فَضِيخٍ وَهُوَ تَمْرٌ فَجَاءَهُمْ آتٍ فَقَالَ إِنَّ الْخَمْرَ قَدْ حُرِّمَتْ فَقَالَ أَبُو طَلْحَةَ يَا أَنَسُ قُمْ إِلَى هَذِهِ الْجِرَارِ فَاكْسِرْهَا قَالَ أَنَسٌ فَقُمْتُ إِلَى مِهْرَاسٍ لَنَا فَضَرَبْتُهَا بِأَسْفَلِهِ حَتَّى انْكَسَرَتْ","id":"Telah menceritakan kepadaku [Yahya bin Qaza'ah] telah menceritakan kepadaku [Malik] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas bin Malik] ia berkata, \"Pernah aku memberi minum Abu Thalhah Al Anshari, Abu Ubaidah bin Al Jarrah dan Ubbay bin Ka'b berupa minuman dari fadhih atau kurma. Lantas ada seorang utusan mendatangi mereka dan berkata, 'Hai..sungguh, khamer telah diharamkan! Secara spontan Abu Thalhah berkata, 'Wahai Anas, bangkit dan pecahkanlah kendi-kendi minuman itu! ' Anas berkata, \"Maka aku pun ke arah gentong-gentong kami dan kubanting bagian bawahnya hingga remuk.\""},"6379":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ عَنْ صِلَةَ عَنْ حُذَيْفَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِأَهْلِ نَجْرَانَ لَأَبْعَثَنَّ إِلَيْكُمْ رَجُلًا أَمِينًا حَقَّ أَمِينٍ فَاسْتَشْرَفَ لَهَا أَصْحَابُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَعَثَ أَبَا عُبَيْدَةَ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dari [Shilah] dari [Khudzaifah], bahwa Nabi shallallahu 'alaihi wasallam berkata kepada penduduk Najran: \"Sungguh, akan aku utus untuk kalian seorang laki-laki dan benar-benar terpercaya!\" Para sahabat nabi shallallahu 'alaihi wasallam akhirnya mengharap untuk mendapatkan kehormatan tersebut, akhirnya beliau mengutus Abu 'Ubaidah bin Al Jarrah.\""},"6380":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ خَالِدٍ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِكُلِّ أُمَّةٍ أَمِينٌ وَأَمِينُ هَذِهِ الْأُمَّةِ أَبُو عُبَيْدَةَ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Syu'bah] dari [Khalid] dari [Abu Qilabah] dari [Anas] radliallahu 'anhu, Nabi shallallahu 'alaihi wasallam bersabda: \"Setiap umat mempunyai orang kepercayaan, dan kepercayaan umat ini ialah Abu 'Ubaidah bin Al Jarrah.\""},"6381":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ بْنِ الْمَدِينِيِّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا ابْنُ الْمُنْكَدِرِ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ قَالَنَدَبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّاسَ يَوْمَ الْخَنْدَقِ فَانْتَدَبَ الزُّبَيْرُ ثُمَّ نَدَبَهُمْ فَان��تَدَبَ الزُّبَيْرُ ثُمَّ نَدَبَهُمْ فَانْتَدَبَ الزُّبَيْرُ ثَلَاثًا فَقَالَ لِكُلِّ نَبِيٍّ حَوَارِيٌّ وَحَوَارِيَّ الزُّبَيْرُقَالَ سُفْيَانُ حَفِظْتُهُ مِنْ ابْنِ الْمُنْكَدِرِ وَقَالَ لَهُ أَيُّوبُ يَا أَبَا بَكْرٍ حَدِّثْهُمْ عَنْ جَابِرٍ فَإِنَّ الْقَوْمَ يُعْجِبُهُمْ أَنْ تُحَدِّثَهُمْ عَنْ جَابِرٍ فَقَالَ فِي ذَلِكَ الْمَجْلِسِ سَمِعْتُ جَابِرًا فَتَابَعَ بَيْنَ أَحَادِيثَ سَمِعْتُ جَابِرًا قُلْتُ لِسُفْيَانَ فَإِنَّ الثَّوْرِيَّ يَقُولُ يَوْمَ قُرَيْظَةَ فَقَالَ كَذَا حَفِظْتُهُ مِنْهُ كَمَا أَنَّكَ جَالِسٌ يَوْمَ الْخَنْدَقِ قَالَ سُفْيَانُ هُوَ يَوْمٌ وَاحِدٌ وَتَبَسَّمَ سُفْيَانُ","id":"Telah menceritakan kepada kami ['Ali bin Abdullah bin Al Madini] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Ibnul Munkadir] berkata, \"Aku mendengar [Jabir bin Abdullah] berkata, \"Pada perang Khandaq Rasulullah shallallahu 'alaihi wasallam memberi sebuah anjuran. Anjuran itu langsung dikerjakan oleh Zubair. Rasul memberi anjuran mereka lagi, dan secara spontan anjuran itu dikerjakan oleh Zubair. Nabi memberi anjuran lagi, dan lagi-lagi segera disambut oleh Zubair (ia mengulanginya tiga kali). Lantas nabi bersabda: \"Setiap nabi mempunyai pembela, dan pembelaku adalah Zubair.\" Sufyan berkata, \"Aku menghafalnya dari Ibnul munkadir, \" Ayyub kemudian berkata kepadanya (Sufyan), 'Wahai Abu Bakar, ceritakanlah kepada mereka yang berasal dari Jabir, sebab orang-orang itu merasa senang jika engkau menceritakan kepada mereka dari Jabir! Kemudian Sufyan berkata di majlis tersebut \"Aku mendengar Jabir -lantas ia perkuat antara hadis-hadis-, 'Aku mendengar Jabir.\" Aku bertanya kepada Sufyan, \"'Ats Tsauri berkata bahwa itu terjadi di hari perang Quraizhah, lantas ia katakan, 'Demikian aku menghafalnya dari Jabir, sebagaimana engkau duduk di perang Khandaq.' Sufyan berkata, 'Itu terjadi sama-sama dalam satu hari, ' lantas Sufyan tersenyum.\""},"6382":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ أَبِي عُثْمَانَ عَنْ أَبِي مُوسَىأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ حَائِطًا وَأَمَرَنِي بِحِفْظِ الْبَابِ فَجَاءَ رَجُلٌ يَسْتَأْذِنُ فَقَالَ ائْذَنْ لَهُ وَبَشِّرْهُ بِالْجَنَّةِ فَإِذَا أَبُو بَكْرٍ ثُمَّ جَاءَ عُمَرُ فَقَالَ ائْذَنْ لَهُ وَبَشِّرْهُ بِالْجَنَّةِ ثُمَّ جَاءَ عُثْمَانُ فَقَالَ ائْذَنْ لَهُ وَبَشِّرْهُ بِالْجَنَّةِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Abu Utsman] dari [Abu Musa], bahwa Nabi shallallahu 'alaihi wasallam pernah masuk kebun dan menyuruhku untuk menjaga pintu. Setelah itu datanglah seseorang dan minta ijin untuk masuk, nabi kemudian berkata: \"Berilah ia ijin, dan berilah kabar gembira kepadanya dengan surga!\" Tak tahunya yang datang adalah Abu Bakar. Kemudian Umar datang dan nabi berkata: \"Berilah ijin dia, dan berilah kabar gembira dengan surga.\" Kemudian Utsman datang dan nabi berkata: \"Berilah ia ijin, dan berilah kabar gembira dengan surga.\""},"6383":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ عَنْ يَحْيَى عَنْ عُبَيْدِ بْنِ حُنَيْنٍ سَمِعَ ابْنَ عَبَّاسٍ عَنْ عُمَرَ رَضِيَ اللَّهُ عَنْهُمْ قَالَجِئْتُ فَإِذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَشْرُبَةٍ لَهُ وَغُلَامٌ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْوَدُ عَلَى رَأْسِ الدَّرَجَةِ فَقُلْتُ قُلْ هَذَا عُمَرُ بْنُ الْخَطَّابِ فَأَذِنَ لِي","id":"Telah menceritakan kepada kami [Abdul Aziz bin Abdullah] telah menceritakan kepada kami [Sulaiman bin Bilal] dari [Yahya] dari ['Ubaid bin Hunain] ia mendengar [Ibnu Abbas] dari [Umar] radliallahu 'anhum berkata, \"Aku datang, tak tahunya Rasulullah shallallahu 'alaihi wasallam sedang berada sebuah tempat minumnya, dan pelayan Rasulullah shallallahu 'alaihi wasallam yang hitam sedang berada puncak tangga. Aku katakan 'Tolong sampaikan, Aku Umar bin Khattab! Nabi pun mengijinkanku.\""},"6384":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنِي اللَّيْثُ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ أَنَّهُ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ أَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ بِكِتَابِهِ إِلَى كِسْرَى فَأَمَرَهُ أَنْ يَدْفَعَهُ إِلَى عَظِيمِ الْبَحْرَيْنِ يَدْفَعُهُ عَظِيمُ الْبَحْرَيْنِ إِلَى كِسْرَى فَلَمَّا قَرَأَهُ كِسْرَى مَزَّقَهُ فَحَسِبْتُ أَنَّ ابْنَ الْمُسَيَّبِ قَالَ فَدَعَا عَلَيْهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُمَزَّقُوا كُلَّ مُمَزَّقٍ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari [Yunus] dari [Ibn Syihab] bahwa ia berkata, telah mengabarkan kepadaku [Ubaidullah bin Utbah] bahwa [Abdullah bin Abbas] mengabarkan kepadanya, \"Rasulullah shallallahu 'alaihi wasallam mengutus utusan membawa suratnya ke Kisra, beliau perintahkan ajudannya untuk menyerahkannya ke penguasa Bahrain, dan penguasa Bahran agar menyampaikan kepada Kisra. Ketika Kisra membacanya, ia langsung merobek-robeknya.\" Dan kutaksir Ibnul Musayyab menyebutkan, \"Dan Rasulullah shallallahu 'alaihi wasallam mendoakan kecelakaan atas mereka, agar dihancurkan sehancur-hancurnya.\""},"6385":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ يَزِيدَ بْنِ أَبِي عُبَيْدٍ حَدَّثَنَا سَلَمَةُ بْنُ الْأَكْوَعِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِرَجُلٍ مِنْ أَسْلَمَ أَذِّنْ فِي قَوْمِكَ أَوْ فِي النَّاسِ يَوْمَ عَاشُورَاءَ أَنَّ مَنْ أَكَلَ فَلْيُتِمَّ بَقِيَّةَ يَوْمِهِ وَمَنْ لَمْ يَكُنْ أَكَلَ فَلْيَصُمْ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Yazid bin Abu Ubaid] telah menceritakan kepada kami [Salamah bin Al Akwa'], bahwa Rasulullah shallallahu 'alaihi wasallam pernah bersabda kepada seseorang bani Aslam: 'Umumkanlah di kalangan kaummu atau di tengah-tengah masyarakat di hari 'Asyura, siapa yang terlanjur makan hendaklah menyempurnakan sisa harinya, dan siapa yang belum makan hendaklah berpuasa.\""},"6386":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ الْجَعْدِ أَخْبَرَنَا شُعْبَةُ ح و حَدَّثَنِي إِسْحَاقُ أَخْبَرَنَا النَّضْرُ أَخْبَرَنَا شُعْبَةُ عَنْ أَبِي جَمْرَةَ قَالَ كَانَ ابْنُ عَبَّاسٍ يُقْعِدُنِي عَلَى سَرِيرِهِ فَقَالَلِي إِنَّ وَفْدَ عَبْدِ الْقَيْسِ لَمَّا أَتَوْا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ الْوَفْدُ قَالُوا رَبِيعَةُ قَالَ مَرْحَبًا بِالْوَفْدِ أَوْ الْقَوْمِ غَيْرَ خَزَايَا وَلَا نَدَامَى قَالُوا يَا رَسُولَ اللَّهِ إِنَّ بَيْنَنَا وَبَيْنَكَ كُفَّارَ مُضَرَ فَمُرْنَا بِأَمْرٍ نَدْخُلُ بِهِ الْجَنَّةَ وَنُخْبِرُ بِهِ مَنْ وَرَاءَنَا فَسَأَلُوا عَنْ الْأَشْرِبَةِ فَنَهَاهُمْ عَنْ أَرْبَعٍ وَأَمَرَهُمْ بِأَرْبَعٍ أَمَرَهُمْ بِالْإِيمَانِ بِاللَّهِ قَالَ هَلْ تَدْرُونَ مَا الْإِيمَانُ بِاللَّهِ قَالُوا اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ شَهَادَةُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ وَإِقَامُ الصَّلَاةِ وَإِيتَاءُ الزَّكَاةِ وَأَظُنُّ فِيهِ صِيَامُ رَمَضَانَ وَتُؤْتُوا مِنْ الْمَغَانِمِ الْخُمُسَ وَنَهَاهُمْ عَنْ الدُّبَّاءِ وَالْحَنْتَمِ وَالْمُزَفَّتِ وَالنَّقِيرِ وَرُبَّمَا قَالَ الْمُقَيَّرِ قَالَ احْفَظُوهُنَّ وَأَبْلِغُوهُنَّ مَنْ وَرَاءَكُمْ","id":"Telah menceritakan kepada kami [Ali bin Al Ja'd] telah mengabarkan kepada kami [Syu'bah]. (dalam jalur lain disebutkan) telah menceritakan kepadaku [Ishaq] telah mengabarkan kepada kami [An Nadlr] telah mengabarkan kepada kami [Syu'bah] dari [Abu Jamrah] ia berkata, \" [Ibnu Abbas] mendudukkan aku di atas tempat tidurnya dan berkata kepadaku, \"Utusan Abdul Qais tatkala mendatangi Rasulullah shallallahu 'alaihi wasallam, beliau bertanya: 'Siapa utusan-utusan ini? ' Mereka menjawab, \"Rabi'ah!\" Nabi kemudian mengucapkan: \"Selamat datang wahai para utusan -atau sepertinya mengucapkan-, Selamat datang kaum, dengan tanpa terhinakan dan penyesalan.\" Mereka katakan, \"Ya Rasulullah, antara kami dan engkau ada orang-orang kafir Mudlar, maka suruhlah kami dengan sebuah perintah yang karenanya kami bisa masuk surga dan bisa kami kabarkan kepada orang-orang yang di belakang kami.\" Lantas mereka bertanya perihal minuman-minuman. Kemudian Rasul melarang mereka empat hal, dan memerintahkan mereka empat hal. Memerintahkan mereka beriman kepada Allah. Beliau bertanya: \"Tahukah kalian iman kepada Allah?\" Mereka menjawab, \"Allah dan Rasul-Nya lah yang lebih tahu!\" Beliau menjawab: \"Yaitu persaksian bahwa tidak ada sesembahan yang hak selain Allah semata yang tiada sekutu bagi-Nya, dan bahwasanya Muhammad adalah utusan Allah, mendirikan shalat, membayar zakat -dan aku taksir dalam perintahnya ada puasa bulan ramadhan-, dan kalian bayarkan seperlima bagian ghanimah.\" Dan nabi melarang mereka dari duba', hantam, muzaffat, naqir, dan rupanya beliau juga berkata almuqayyar. Nabi meneruskan: \"Jagalah itu semua, dan sampaikan itu semua kepada orang yang berada di belakang kalian.\" "},"6387":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْوَلِيدِ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ تَوْبَةَ الْعَنْبَرِيِّ قَالَ قَالَ لِي الشَّعْبِيُّأَرَأَيْتَ حَدِيثَ الْحَسَنِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَاعَدْتُ ابْنَ عُمَرَ قَرِيبًا مِنْ سَنَتَيْنِ أَوْ سَنَةٍ وَنِصْفٍ فَلَمْ أَسْمَعْهُ يُحَدِّثُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيْرَ هَذَا قَالَ كَانَ نَاسٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهِمْ سَعْدٌ فَذَهَبُوا يَأْكُلُونَ مِنْ لَحْمٍ فَنَادَتْهُمْ امْرَأَةٌ مِنْ بَعْضِ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُ لَحْمُ ضَبٍّ فَأَمْسَكُوا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُوا أَوْ اطْعَمُوا فَإِنَّهُ حَلَالٌ أَوْ قَالَ لَا بَأْسَ بِهِ شَكَّ فِيهِ وَلَكِنَّهُ لَيْسَ مِنْ طَعَامِي","id":"Telah menceritakan kepada kami [Muhammad bin Al Walid] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Taubah Al 'Anbari] berkata, [Asy Sya'bi] berkata kepadaku, \"Tahukah engkau hadits Al Hasan dari nabi shallallahu 'alaihi wasallam? Dan aku sering duduk bersama [Ibnu Umar] kurang lebih dua tahun atau setahun setengah, namun aku tidak mendengarnya dari Nabi shallallahu 'alaihi wasallam selain ini, ia katakan \"Beberapa orang sahabat nabi shallallahu 'alaihi wasallam yang di antaranya adalah Sa'd makan daging. Lantas seorang isteri Nabi shallallahu 'alaihi wasallam memanggil mereka \"Hai.. itu daging biawak!\" Maka mereka menghentikan santapannya. Lantas Rasulullah shallallahu 'alaihi wasallam bersabda: \"Makanlah, \" atau dengan redaksi \"santaplah, ia adalah halal.\" Atau dengan redaksi \"Tidak masalah, \" perawi ragu, namun biawak bukan makananku.\""},"6388":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الزُّبَيْرِ الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ عَنْ مِسْعَرٍ وَغَيْرِهِ عَنْ قَيْسِ بْنِ مُسْلِمٍ عَنْ طَارِقِ بْنِ شِهَابٍ قَالَق��الَ رَجُلٌ مِنْ الْيَهُودِ لِعُمَرَ يَا أَمِيرَ الْمُؤْمِنِينَ لَوْ أَنَّ عَلَيْنَا نَزَلَتْ هَذِهِ الْآيَةُ{ الْيَوْمَ أَكْمَلْتُ لَكُمْ دِينَكُمْ وَأَتْمَمْتُ عَلَيْكُمْ نِعْمَتِي وَرَضِيتُ لَكُمْ الْإِسْلَامَ دِينًا }لَاتَّخَذْنَا ذَلِكَ الْيَوْمَ عِيدًا فَقَالَ عُمَرُ إِنِّي لَأَعْلَمُ أَيَّ يَوْمٍ نَزَلَتْ هَذِهِ الْآيَةُ نَزَلَتْ يَوْمَ عَرَفَةَ فِي يَوْمِ جُمُعَةٍسَمِعَ سُفْيَانُ مِنْ مِسْعَرٍ وَمِسْعَرٌ قَيْسًا وَقَيْسٌ طَارِقًا","id":"Telah menceritakan kepada kami [Abdullah bin Zubair Al Humaidi] telah menceritakan kepada kami [Sufyan] dari [Mis'ar] dan lainnya dari [Qais bin Muslim] dari [Thariq bin Syihab] ia berkata, \"Seorang laki-laki Yahudi berkata kepada [Umar], \"Wahai Amirul Mukminin, kalaulah ayat ini diturunkan kepada kami, yaitu ayat: '(Hari ini telah Aku sempurnakan untk kalian agama kalian, dan Aku semurkan bagi kalian Nikmat-Ku dan Aku ridhai Islam sebagai agama kalian) ' (Qs. Al Maidah: 2), niscaya telah kami jadikan hari itu sebagai hari raya.\" Lantas Umar berkata, \"Sungguh, aku tahu hari apa ayat itu diturunkan. Ayat itu diturunkan di hari Arafah pada hari jumat.\" Sufyan mendengar dari Mis'ar, Mis'ar mendengar dari Qais, dan Qais mendengar dari Thariq."},"6389":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي أَنَسُ بْنُ مَالِكٍ أَنَّهُ سَمِعَ عُمَرَالْغَدَ حِينَ بَايَعَ الْمُسْلِمُونَ أَبَا بَكْرٍ وَاسْتَوَى عَلَى مِنْبَرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَشَهَّدَ قَبْلَ أَبِي بَكْرٍ فَقَالَ أَمَّا بَعْدُ فَاخْتَارَ اللَّهُ لِرَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الَّذِي عِنْدَهُ عَلَى الَّذِي عِنْدَكُمْ وَهَذَا الْكِتَابُ الَّذِي هَدَى اللَّهُ بِهِ رَسُولَكُمْ فَخُذُوا بِهِ تَهْتَدُوا وَإِنَّمَا هَدَى اللَّهُ بِهِ رَسُولَهُ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari [Uqail] dari [Ibn Syihab] telah mengabarkan kepadaku [Anas bin Malik], ia mendengar [Umar] sehari setelah kewafatan Nabi, ketika kaum muslimin berbaiat kepada Abu Bakar dan berdiri di atas mimbar Rasulullah shallallahu 'alaihi wasallam, Umar memberi kesaksian sebelum Abu Bakar seraya berkata, \"Amma ba'du. Allah memilih untuk Rasul-Nya shallallahu 'alaihi wasallam apa yang berada di sisi-Nya, untuk mengatasi apa yang berada di sisi kalian, dan kitab inilah yang dengannya Allah memberi petunjuk kepada rasul kalian, maka ambillah sebagai petunjuk, niscaya kalian mendapatkan petunjuk, hanyasanya dengan kitab itulah Allah memberi petunjuk (hidayah) rasul-Nya.\""},"6390":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا وُهَيْبٌ عَنْ خَالِدٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَضَمَّنِي إِلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ اللَّهُمَّ عَلِّمْهُ الْكِتَابَ","id":"Telah menceritakan kepada kami [Musa bin Ismail] telah menceritakan kepada kami [Wuhaib] dari [Khalid] dari [Ikrimah] dari [Ibn Abbas] ia berkata, \"Nabi shallallahu 'alaihi wasallam pernah mendekapku sambil berdoa: \"Ya Allah, ajarkanlah padanya al kitab (al Quran).\""},"6391":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ صَبَّاحٍ حَدَّثَنَا مُعْتَمِرٌ قَالَ سَمِعْتُ عَوْفًا أَنَّ أَبَا الْمِنْهَالِ حَدَّثَهُ أَنَّهُ سَمِعَ أَبَا بَرْزَةَ قَالَإِنَّ اللَّهَ يُغْنِيكُمْ أَوْ نَعَشَكُمْ بِالْإِسْلَامِ وَبِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ أَبُو عَبْد اللَّهِ وَقَعَ هَاهُنَا يُغْنِيكُمْ وَإِنَّمَا هُوَ نَعَشَكُمْ يُنْظَرُ فِي أَصْلِ كِتَابِ الِاعْتِصَامِ","id":"Telah menceritakan kepada kami [Abdullah bin Sabah] telah menceritakan kepada kami [Mu'tamir] berkata, aku mendengar [Auf], bahwa [Abul Minhal] menceritakan kepadanya, ia mendengar [Abu Barzah] berkata, \"Sesungguhnya Allah telah mengkayakan atau meninggikan derajat kalian dengan Islam dan dengan Muhammad shallallahu 'alaihi wasallam.\" Abu Abdullah berkata, \"Di sini tertulis 'Allah mengkayakan kalian', padahal dengan redaksi 'Hanyasanya ketinggian derajat kalian', ini bisa dilihat dalam asli kitab yang berjudul al-I'tisham (karangan Imam Bukhari lainnya).\""},"6392":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنِي مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَكَتَبَ إِلَى عَبْدِ الْمَلِكِ بْنِ مَرْوَانَ يُبَايِعُهُ وَأُقِرُّ لَكَ بِذَلِكَ بِالسَّمْعِ وَالطَّاعَةِ عَلَى سُنَّةِ اللَّهِ وَسُنَّةِ رَسُولِهِ فِيمَا اسْتَطَعْتُ","id":"Telah menceritakan kepada kami [Ismail] telah menceritakan kepadaku [Malik] dari [Abdullah bin Dinar], bahwa [Abdullah bin Umar] berkirim surat kepada Abdul Malik bin Marwan sebagai pernyataan baiat terhadapnya, isinya, 'Aku berikrar terhadapmu atas yang demikian dengan mendengar dan taat, di atas sunnah Allah dan sunnah rasul-Nya semaksimal kemampuanku'.\""},"6393":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بُعِثْتُ بِجَوَامِعِ الْكَلِمِ وَنُصِرْتُ بِالرُّعْبِ وَبَيْنَا أَنَا نَائِمٌ رَأَيْتُنِي أُتِيتُ بِمَفَاتِيحِ خَزَائِنِ الْأَرْضِ فَوُضِعَتْ فِي يَدِي قَالَ أَبُو هُرَيْرَةَ فَقَدْ ذَهَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنْتُمْ تَلْغَثُونَهَا أَوْ تَرْغَثُونَهَا أَوْ كَلِمَةً تُشْبِهُهَا","id":"Telah menceritakan kepada kami [Abdul 'Aziz bin Abdullah] telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Ibn Syihab] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah] radliallahu 'anhu, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku diutus dengan kalimat singkat yang padat makna, dan aku ditolong dengan rasa takut yang dihunjamkan dalam dada musuh-musuhku, dan ketika aku tidur, aku bermimpi diberi kunci-kunci perbendaharaan bumi lantas diletakkan di tanganku, \" Abu Hurairah berkata, 'Rasulullah shallallahu 'alaihi wasallam pergi (wafat) sedang kalian telah menikmati limpahan kekayaan itu -atau menghisap perbendaharaan bumi itu-atau kalimat-kalimat yang semisal.\""},"6394":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا اللَّيْثُ عَنْ سَعِيدٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مِنْ الْأَنْبِيَاءِ نَبِيٌّ إِلَّا أُعْطِيَ مِنْ الْآيَاتِ مَا مِثْلُهُ أُومِنَ أَوْ آمَنَ عَلَيْهِ الْبَشَرُ وَإِنَّمَا كَانَ الَّذِي أُوتِيتُ وَحْيًا أَوْحَاهُ اللَّهُ إِلَيَّ فَأَرْجُو أَنِّي أَكْثَرُهُمْ تَابِعًا يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami ['Abdul 'Aziz bin Abdullah] telah menceritakan kepada kami [Al Laits] dari [Sa'id] dari [ayahnya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak seorang nabi pun kecuali ia diberi beberapa mukjizat yang tak bisa diserupai oleh apapun sehingga manusia mengimaninya -atau dengan redaksi 'sehingga manusia dijadikan beriman'-, namun yang diberikan kepadaku hanyalah berupa wahyu yang Allah wahyukan kepadaku, maka aku berharap menjadi manusia yang paling banyak pengikutnya di hari kiamat.\""},"6395":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَبَّاسٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنْ وَاصِلٍ عَنْ أَبِي وَائِلٍ قَالَ جَلَسْتُ إِلَى شَيْبَةَفِي هَذَا الْمَسْجِدِ قَالَ جَلَسَ إِلَيَّ عُمَرُ فِي مَجْلِسِكَ هَذَا فَقَالَ لَقَدْ هَمَمْتُ أَنْ لَا أَدَعَ فِيهَا صَفْرَاءَ وَلَا بَيْضَاءَ إِلَّا قَسَمْتُهَا بَيْنَ الْمُسْلِمِينَ قُلْتُ مَا أَنْتَ بِفَاعِلٍ قَالَ لِمَ قُلْتُ لَمْ يَفْعَلْهُ صَاحِبَاكَ قَالَ هُمَا الْمَرْءَانِ يُقْتَدَى بِهِمَا","id":"Telah menceritakan kepada kami ['Amru bin Abbas] telah menceritakan kepada kami [Abdurrahman] telah menceritakan kepada kami [Sufyan] dari [Washil] dari [Abu Wail] berkata, \"Aku duduk mendekati [Syaibah] di masjid ini, ia katakan, \"Dan [Umar] pernah duduk kepadaku di majlismu lantas berkata, \"Sungguh aku berkeinginan tidak meninggalkan yang kuning tidak pula yang putih, selain kubagikan di antara muslimin.\" Maka aku katakan kepadanya, \"Engkau tak bakalan bisa melakukannya.\" Umar pun berkata, \"Mengapa!\" Aku jawab, \"Sebab kedua sahabatmu (Rasulullah dan Abu Bakar) belum pernah melakukannya.\" Lantas ia berkata, \"Keduanya adalah manusia yang menjadi keteladanan.\""},"6396":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ سَأَلْتُ الْأَعْمَشَ فَقَالَ عَنْ زَيْدِ بْنِ وَهْبٍ سَمِعْتُ حُذَيْفَةَ يَقُولُحَدَّثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ الْأَمَانَةَ نَزَلَتْ مِنْ السَّمَاءِ فِي جَذْرِ قُلُوبِ الرِّجَالِ وَنَزَلَ الْقُرْآنُ فَقَرَءُوا الْقُرْآنَ وَعَلِمُوا مِنْ السُّنَّةِ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Sufyan] ia berkata; aku bertanya kepada [Al A'masy], dan ia berkata dari [Zaid bin Wahb] aku mendengar [Hudzaifah] berkata, telah menceritakan kepada kami Rasulullah shallallahu 'alaihi wasallam, bahwa amanat turun dari langit di relung hati laki-laki, dan alquran turun lantas mereka baca alquran dan tahu assunnah.\""},"6397":{"ar":"حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ حَدَّثَنَا شُعْبَةُ أَخْبَرَنَا عَمْرُو بْنُ مُرَّةَ سَمِعْتُ مُرَّةَ الْهَمْدَانِيَّ يَقُولُ قَالَ عَبْدُ اللَّهِإِنَّ أَحْسَنَ الْحَدِيثِ كِتَابُ اللَّهِ وَأَحْسَنَ الْهَدْيِ هَدْيُ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَشَرَّ الْأُمُورِ مُحْدَثَاتُهَا وَ{ إِنَّ مَا تُوعَدُونَ لَآتٍ وَمَا أَنْتُمْ بِمُعْجِزِينَ }","id":"Telah menceritakan kepada kami [Adam bin Abu Iyas] telah menceritakan kepada kami [Syu'bah] telah mengabarkan kepada kami [Amru bin Murrah], aku mendengar [Murrah Al Hamdani] berkata, [Abdullah] berkata, \"Sebaik-baik pembicaraan adalah kitabullah dan sebaik-baik petunjuk adalah petunjuk Muhammad shallallahu 'alaihi wasallam, dan seburuk-buruk perbuatan adalah perkara baru, \" kemudian beliau mengutip ayat: '(Apa yang dijanjikan untuk kalian pasti akan datang) ' (Qs. Al an'aam: 134)."},"6398":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا الزُّهْرِيُّ عَنْ عُبَيْدِ اللَّهِ عَنْ أَبِي هُرَيْرَةَ وَزَيْدِ بْنِ خَالِدٍ قَالَكُنَّا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَأَقْضِيَنَّ بَيْنَكُمَا بِكِتَابِ اللَّهِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Az Zuhri] dari [Ubaidullah] dari [Abu Hurairah] dan [Zaid bin Khalid] ia berkata, \"Pernah kami di sisi Nabi shallallahu 'alaihi wasallam, lantas beliau bersabda: \"Sungguh, aku akan putuskan kalian berdua dengan kitabullah.\""},"6399":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سِنَانٍ حَدَّثَنَا فُلَيْحٌ حَدَّثَنَا هِلَالُ بْنُ عَلِيٍّ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُلُّ أُمَّتِي يَدْخُلُونَ الْجَنَّةَ إِلَّا مَنْ أَبَى قَالُوا يَا رَسُولَ اللَّهِ وَمَنْ يَأْبَى قَالَ مَنْ أَطَاعَنِي دَخَلَ الْجَنَّةَ وَمَنْ عَصَانِي فَقَدْ أَبَى","id":"Telah menceritakan kepada kami [Muhammad bin Sinan] telah menceritakan kepada kami [Fulaih] telah menceritakan kepada kami [Hilal bin Ali] dari ['Atha bin Yasar] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap umatku masuk surga selain yang enggan, \" Para sahabat bertanya, \"Wahai Rasulullah, lantas siapa yang enggan?\" Nabi menjawab: \"Siapa yang taat kepadaku masuk surga dan siapa yang membangkang aku berarti ia enggan.\""},"6400":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبَادَةَ أَخْبَرَنَا يَزِيدُ حَدَّثَنَا سَلِيمُ بْنُ حَيَّانَ وَأَثْنَى عَلَيْهِ حَدَّثَنَا سَعِيدُ بْنُ مِينَاءَ حَدَّثَنَا أَوْ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُجَاءَتْ مَلَائِكَةٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ نَائِمٌ فَقَالَ بَعْضُهُمْ إِنَّهُ نَائِمٌ وَقَالَ بَعْضُهُمْ إِنَّ الْعَيْنَ نَائِمَةٌ وَالْقَلْبَ يَقْظَانُ فَقَالُوا إِنَّ لِصَاحِبِكُمْ هَذَا مَثَلًا فَاضْرِبُوا لَهُ مَثَلًا فَقَالَ بَعْضُهُمْ إِنَّهُ نَائِمٌ وَقَالَ بَعْضُهُمْ إِنَّ الْعَيْنَ نَائِمَةٌ وَالْقَلْبَ يَقْظَانُ فَقَالُوا مَثَلُهُ كَمَثَلِ رَجُلٍ بَنَى دَارًا وَجَعَلَ فِيهَا مَأْدُبَةً وَبَعَثَ دَاعِيًا فَمَنْ أَجَابَ الدَّاعِيَ دَخَلَ الدَّارَ وَأَكَلَ مِنْ الْمَأْدُبَةِ وَمَنْ لَمْ يُجِبْ الدَّاعِيَ لَمْ يَدْخُلْ الدَّارَ وَلَمْ يَأْكُلْ مِنْ الْمَأْدُبَةِ فَقَالُوا أَوِّلُوهَا لَهُ يَفْقَهْهَا فَقَالَ بَعْضُهُمْ إِنَّهُ نَائِمٌ وَقَالَ بَعْضُهُمْ إِنَّ الْعَيْنَ نَائِمَةٌ وَالْقَلْبَ يَقْظَانُ فَقَالُوا فَالدَّارُ الْجَنَّةُ وَالدَّاعِي مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَنْ أَطَاعَ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَدْ أَطَاعَ اللَّهَ وَمَنْ عَصَى مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَدْ عَصَى اللَّهَ وَمُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرْقٌ بَيْنَ النَّاسِتَابَعَهُ قُتَيْبَةُ عَنْ لَيْثٍ عَنْ خَالِدٍ عَنْ سَعِيدِ بْنِ أَبِي هِلَالٍ عَنْ جَابِرٍ خَرَجَ عَلَيْنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Ubadah] Telah mengabarkan kepada kami [Yazid] telah menceritakan kepada kami [Salim bin Hayyan] dan ia memujinya, telah menceritakan kepada kami [Sa'id bin Mina'] telah menceritakan kepada kami, atau aku mendengar [Jabir bin 'Abdullah] berkata, \"Malaikat datang kepada nabi shallallahu 'alaihi wasallam yang ketika itu sedang tidur, lantas sebagian malaikat berkata \"Dia sedang tidur!\" Sedang sebagian mengatakan \"Mata dia tidur, namun hatinya selalu terjaga.\" Lantas mereka katakan, \"Sesungguhnya sahabat kalian ini adalah perumpamaan, maka buatlah perumpamaan baginya.\" Lantas sebagian berkata, \"Dia sedang tidur!\" Sebagian lagi mengatakan, \"Mata dia tidur, namun hatinya selalu terjaga.\" Lantas mereka katakan, \"Perumpaman dia bagaikan seseorang yang membangun rumah, dan mengisi rumahnya dengan hidangan, lantas mengutus seorang juru undang, maka barangsiapa memenuhi undangan si pengundang, ia masuk rumah dan menyantap hidangan, sebaliknya barangsiapa tidak memenuhi sang pengundang, ia tak bakalan masuk rumah dan tidak pula menyantap hidangan.\" Para malaikat berkata, \"Tolong takwilkanlah perumpaan itu agar dia paham.\" Lantas sebagian mengatakan \"Sesungguhnya ia sedang tidur!\" Sebagian lagi berkata, \"Mata bolehlah tidur namun hatinya selalu terjaga.\" Lantas mereka katakan, \"Rumah itu adalah surga, dan Sang pengundang adalah Muhammad shallallahu 'alaihi wasallam, artinya barangsiapa menaati Muhammad shallallahu 'alaihi wasallam, berarti ia menaati Allah, dan barangsiapa membangkang Muhammad shallallahu 'alaihi wasallam telah membangkang Allah.\" Hadits ini diperkuat oleh [Qutaibah] dari [Al Laits] dari [Khalid] dari [Sa'id bin Abu Hilal] dari [Jabir], 'Nabi shallallahu 'alaihi wasallam shallallahu 'alaihi wasallam menemui kami.\""},"6401":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ هَمَّامٍ عَنْ حُذَيْفَةَ قَالَيَا مَعْشَرَ الْقُرَّاءِ اسْتَقِيمُوا فَقَدْ سَبَقْتُمْ سَبْقًا بَعِيدًا فَإِنْ أَخَذْتُمْ يَمِينًا وَشِمَالًا لَقَدْ ضَلَلْتُمْ ضَلَالًا بَعِيدًا","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Ibrahim] dari [Hammam] dari [Khudzaifah] berkata, \"Wahai ahli alquran, bersikap istiqamahlah kalian, dengan demikian kalian telah menjadi pemenang yang jauh, sebaliknya jika kalian oleng kanan kiri, kalian telah sesat sesesat-sesatnya.\""},"6402":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَىعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا مَثَلِي وَمَثَلُ مَا بَعَثَنِي اللَّهُ بِهِ كَمَثَلِ رَجُلٍ أَتَى قَوْمًا فَقَالَ يَا قَوْمِ إِنِّي رَأَيْتُ الْجَيْشَ بِعَيْنَيَّ وَإِنِّي أَنَا النَّذِيرُ الْعُرْيَانُ فَالنَّجَاءَ فَأَطَاعَهُ طَائِفَةٌ مِنْ قَوْمِهِ فَأَدْلَجُوا فَانْطَلَقُوا عَلَى مَهَلِهِمْ فَنَجَوْا وَكَذَّبَتْ طَائِفَةٌ مِنْهُمْ فَأَصْبَحُوا مَكَانَهُمْ فَصَبَّحَهُمْ الْجَيْشُ فَأَهْلَكَهُمْ وَاجْتَاحَهُمْ فَذَلِكَ مَثَلُ مَنْ أَطَاعَنِي فَاتَّبَعَ مَا جِئْتُ بِهِ وَمَثَلُ مَنْ عَصَانِي وَكَذَّبَ بِمَا جِئْتُ بِهِ مِنْ الْحَقِّ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abu Usamah] dari [Buraid] dari [Abu Burdah] dari [Abu Musa] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Perumpamaanku dan perumpamaan risalah yang kubawa adalah bagaikan seseorang yang mendatangi sebuah kaum, lantas ia katakan, 'Hai kaum, aku telah melihat sebuah pasukan dengan kedua mataku, dan aku adalah pemberi peringatan orang yang telanjang, maka selamatkanlah kalian, selamatkanlah kalian.' Lantas sebagian kelompok kaumnya mentaatinya sehingga mereka meneruskan perjalanan sehingga selamat, namun sebagian lain mendustakan dan tetap berada di tempatnya hingga pasukan menyerangnya mereka di pagi buta dan menyandera mereka, itulah perumpamaan orang yang mentaatiku dan mengikuti risalah yang kubawa, dan perumpaman orang yang membangkangku dan mendustakan kebenaran yang kubawa.\""},"6403":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ عَنْ عُقَيْلٍ عَنْ الزُّهْرِيِّ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ أَبِي هُرَيْرَةَ قَالَلَمَّا تُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاسْتُخْلِفَ أَبُو بَكْرٍ بَعْدَهُ وَكَفَرَ مَنْ كَفَرَ مِنْ الْعَرَبِ قَالَ عُمَرُ لِأَبِي بَكْرٍ كَيْفَ تُقَاتِلُ النَّاسَ وَقَدْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمِرْتُ أَنْ أُقَاتِلَ النَّاسَ حَتَّى يَقُولُوا لَا إِلَهَ إِلَّا اللَّهُ فَمَنْ قَالَ لَا إِلَهَ إِلَّا اللَّهُ عَصَمَ مِنِّي مَالَهُ وَنَفْسَهُ إِلَّا بِحَقِّهِ وَحِسَابُهُ عَلَى اللَّهِ فَقَالَ وَاللَّهِ لَأُقَاتِلَنَّ مَنْ فَرَّقَ بَيْنَ الصَّلَاةِ وَالزَّكَاةِ فَإِنَّ الزَّكَاةَ حَقُّ الْمَالِ وَاللَّهِ لَوْ مَنَعُونِي عِقَالًا كَانُوا يُؤَدُّونَهُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَاتَلْتُهُمْ عَلَى مَنْعِهِفَقَالَ عُمَرُ فَوَاللَّهِ مَا هُوَ إِلَّا أَنْ رَأَيْتُ اللَّهَ قَدْ شَرَحَ صَدْرَ أَبِي بَكْرٍ لِلْقِتَالِ فَعَرَفْتُ أَنَّهُ الْحَقُّ قَالَ ابْنُ بُكَيْرٍ وَعَبْدُ اللَّهِ عَنْ اللَّيْثِ عَنَاقًا وَهُوَ أَصَحُّ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits] dari [Uqail] dari [Az Zuhri] telah mengabarkan kepadaku [Ubaidullah bin Abdullah bin Utbah] dari [Abu Hurairah] berkata, \"Tatkala Rasululah shallallahu 'alaihi wasallam wafat dan Abu Bakar diangkat menjadi khalifah sesudahnya, serta beberapa orang Arab kembali kafir, [Umar] berujar kepada [Abu Bakar], \"Bagaimana engkau memerangi manusia padahal Rasulullah shallallahu 'alaihi wasallam telah bersabda 'Aku diperintahkan untuk memerangi manusia hingga mereka mengucapkan Laa-ilaaha-illallah, barangsiapa mengucapkan Laa-ilaaha ilallah, berarti ia telah menjaga darah dan jiwanya dariku kecuali karena alasan yang dibenarkan, dan hisabnya ada pada Allah, ' Lantas Abu Bakar berkata, \"Demi Allah, sungguh akan aku perangi siapa saja yang memisahkan antara shalat dan zakat, sesungguhnya zakat adalah hak harta, demi Allah, kalaulah mereka mencegahku dari membayar unta yang pernah mereka bayarkan kepada Rasulullah shallallahu 'alaihi wasallam, niscaya kuperangi karena mencegahnya.\" Lantas [Umar] berkata, \"Demi Allah, tiba-tiba tak ada pendapat lain selain aku melihat bahwa Allah telah melapangkan dada Abu Bakar untuk memerangi, aku sadar bahwa dia adalah benar.\" [Ibn Bukair] dan [Abdullah] menyebutkan dari [Al Laits] dengan redaksi 'inaaq Bukan `iqaal, sekalipun maknanya sama, unta, dan ini lebih shahih.\""},"6404":{"ar":"حَدَّثَنِي إِسْمَاعِيلُ حَدَّثَنِي ابْنُ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ أَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَدِمَ عُيَيْنَةُ بْنُ حِصْنِ بْنِ حُذَيْفَةَ بْنِ بَدْرٍ فَنَزَلَ عَلَى ابْنِ أَخِيهِ الْحُرِّ بْنِ قَيْسِ بْنِ حِصْنٍ وَكَانَ مِنْ النَّفَرِ الَّذِينَ يُدْنِيهِمْ عُمَرُ وَكَانَ الْقُرَّاءُ أَصْحَابَ مَجْلِسِ عُمَرَ وَمُشَاوَرَتِهِ كُهُولًا كَانُوا أَوْ شُبَّانًا فَقَالَ عُيَيْنَةُ لِابْنِ أَخِيهِ يَا ابْنَ أَخِي هَلْ لَكَ وَجْهٌ عِنْدَ هَذَا الْأَمِيرِ فَتَسْتَأْذِنَ لِي عَلَيْهِ قَالَ سَأَسْتَأْذِنُ لَكَ عَلَيْهِ قَالَ ابْنُ عَبَّاسٍ فَاسْتَأْذَنَ لِعُيَيْنَةَ فَلَمَّا دَخَلَ قَالَ يَا ابْنَ الْخَطَّابِ وَاللَّهِ مَا تُعْطِينَا الْجَزْلَ وَمَا تَحْكُمُ بَيْنَنَا بِالْعَدْلِ فَغَضِبَ عُمَرُ حَتَّى هَمَّ بِأَنْ يَقَعَ بِهِ فَقَالَ الْحُرُّ يَا أَمِيرَ الْمُؤْمِنِينَ إِنَّ اللَّهَ تَعَالَى قَالَ لِنَبِيِّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ خُذْ الْعَفْوَ وَأْمُرْ بِالْعُرْفِ وَأَعْرِضْ عَنْ الْجَاهِلِينَ }وَإِنَّ هَذَا مِنْ الْجَاهِلِينَ فَوَاللَّهِ مَا جَاوَزَهَا عُمَرُ حِينَ تَلَاهَا عَلَيْهِ وَكَانَ وَقَّافًا عِنْدَ كِتَابِ اللَّهِ","id":"Telah menceritakan kepadaku [Ismail] telah menceritakan kepadaku [Ibn Wahb] dari [Yunus] dari [Ibn Syihab] telah menceritakan kepadaku [Ubaidullah bin Abdullah bin Utbah], bahwa [Abdullah bin Abbas] radliallahu 'anhuma berkata, \"Uyainah bin Hishn bin Khudaifah bin Badr datang dan singgah menemui anak saudaranya (keponakannya), Al Hurr bin Qais bin Hishn, dan dia termasuk sekian di antara sekelompok orang yang selalu didekati oleh Umar, qurra` (ahli baca alquran), dan selalu mengikuti majlis Umar dan musyawarah-musyarahnya, baik yang berusia dewasa atau muda. Kemudian 'Uyainah berkata kepada keponakannya, 'Wahai keponakanku, apakah engkau mempunyai kedekatan dengan amir ini sehingga bisa memintakannya ijin untukku sehingga aku bisa menemuinya? Al Hurr bin Qais lalu menjawab, \"Baik, aku akan memintakannya ijin untukmu.\" Ibn Abbas berkata, \"Lantas Al Hurr bin Qais meminta ijin untuk 'Uyainah. Tatkala Uyainah sudah menemui Umar, ia berkata \"Wahai Ibnul khattab, demi Allah, engkau belum memberi pemberian yang banyak kepada kami, dan belum juga engkau berbuat adil diantara kami.\" Spontan Umar marah hingga ia ingin menghukumnya. Namun Uyainah mengatakan, \"Bebaskan aku dari hukumanmu wahai amirul mukminin, sebab Allah berfirman kepada nabi shallallahu 'alaihi wasallam-Nya: '(Maafkanlah, lakukanlah yang ma'ruf dan berpalinglah dari orang-orang jahil' (Qs. Al A'raf 199), dan hukuman ini di antara kelakuan orang-orang bodoh. Demi Allah, maka Umar tidak jadi melakukan hukumannya ketika Uyainah membacakan kepadanya, Umar adalah orang yang selalu memegang teguh Kitabullah.\""},"6405":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ الْمُقْرِئُ حَدَّثَنَا سَعِيدٌ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ عَنْ عَامِرِ بْنِ سَعْدِ بْنِ أَبِي وَقَّاصٍ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَعْظَمَ الْمُسْلِمِينَ جُرْمًا مَنْ سَأَلَ عَنْ شَيْءٍ لَمْ يُحَرَّمْ فَحُرِّمَ مِنْ أَجْلِ مَسْأَلَتِهِ","id":"Telah menceritakan kepada kami [Abdullah bin Yazid Al Muqri'] Telah menceritakan kepadaku [Said] telah menceritakan kepadaku [Uqail] dari [Ibnu Syihab] dari ['Amir bin Sa'id bin Abu Waqash] dari [Bapaknya] bahwa Nabi shallallahu 'alaihi wasallam, beliau berkata: \"Kaum muslimin yang paling besar dosanya adalah yang bertanya tentang sesuatu, lantas sesuatu tersebut diharamkan karena pertanyaannya, padahal sebelumnya tidak diharamkan.\""},"6406":{"ar":"حَدَّثَنَا إِسْحَاقُ أَخْبَرَنَا عَفَّانُ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ سَمِعْتُ أَبَا النَّضْرِ يُحَدِّثُ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ زَيْدِ بْنِ ثَابِتٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اتَّخَذَ حُجْرَةً فِي الْمَسْجِدِ مِنْ حَصِيرٍ فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهَا لَيَالِيَ حَتَّى اجْتَمَعَ إِلَيْهِ نَاسٌ ثُمَّ فَقَدُوا صَوْتَهُ لَيْلَةً فَظَنُّوا أَنَّهُ قَدْ نَامَ فَجَعَلَ بَعْضُهُمْ يَتَنَحْنَحُ لِيَخْرُجَ إِلَيْهِمْ فَقَالَ مَا زَالَ بِكُمْ الَّذِي رَأَيْتُ مِنْ صَنِيعِكُمْ حَتَّى خَشِيتُ أَنْ يُكْتَبَ عَلَيْكُمْ وَلَوْ كُتِبَ عَلَيْكُمْ مَا قُمْتُمْ بِهِ فَصَلُّوا أَيُّهَا النَّاسُ فِي بُيُوتِكُمْ فَإِنَّ أَفْضَلَ صَلَاةِ الْمَرْءِ فِي بَيْتِهِ إِلَّا الصَّلَاةَ الْمَكْتُوبَةَ","id":"Telah menceritakan kepada kami [Ishaq] telah mengabarkan kepada kami ['Affan] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Musa bin Uqbah] aku mendengar [Abu Nadlr] menceritakan dari [Busr bin sa'id] dari [Zaid bin Tsabit], bahwa Nabi shallallahu 'alaihi wasallam pernah mengambil kamar di masjid dari tikar, lantas Rasulullah shallallahu 'alaihi wasallam shalat di sana beberapa malam hingga beberapa sahabat berkumpul kepadanya, lalu disuatu malam mereka tidak mendengar suara beliau hingga mereka menyangka bahwa beliau tertidur. Sebagian sahabat lalu pura-pura batuk agar Nabi muncul menemui mereka, maka beliau pun bersabda: \"Masih saja aku lihat kalian melakukan perbuatan kalian itu (shalat malam), hingga aku khawatir bahwa itu akan diwajibkan atas kalian, padahal jika diwajibkan atas kalian, niscaya kalian tak bisa melakukannya. Shalatlah hai manusia di rumah kalian, sebab seutama-utama shalat seseorang adalah di rumahnya selain shalat wajib.\""},"6407":{"ar":"حَدَّثَنَا يُوسُفُ بْنُ مُوسَى حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدِ بْنِ أَبِي بُرْدَةَ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّ قَالَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَشْيَاءَ كَرِهَهَا فَلَمَّا أَكْثَرُوا عَلَيْهِ الْمَسْأَلَةَ غَضِبَ وَقَالَ سَلُونِي فَقَامَ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ مَنْ أَبِي قَالَ أَبُوكَ حُذَافَةُ ثُمَّ قَامَ آخَرُ فَقَالَ يَا رَسُولَ اللَّهِ مَنْ أَبِي فَقَالَ أَبُوكَ سَالِمٌ مَوْلَى شَيْبَةَ فَلَمَّا رَأَى عُمَرُ مَا بِوَجْهِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْغَضَبِ قَالَ إِنَّا نَتُوبُ إِلَى اللَّهِ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Yusuf bin Musa] telah menceritakan kepada kami [Abu Usamah] dari [Buraid bin Abu Burdah] dari [Abu Burdah] dari [Abu Musa Al Asy'ari] berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah ditanya tentang beberapa perkara yang tidak beliau sukai, tatkala mereka memperbanyak pertanyaan, maka beliau marah dan mengatakan: \"Bertanyalah kalian kepadaku.\" Lantas ada seseorang berdiri dan bertanya, 'Ya Rasulullah, Siapa ayahku? ' Rasulullah menjawab: \"Ayahmu Hudzafah.\" Kemudian ada laki-laki lain berdiri dan bertanya, \"Wahai Rasulullah, siapa ayahku? ' Rasulullah menjawab: \"Ayahmu Salim, budak Syaibah.\" Dikala Umar melihat apa yang terjadi pada wajah Rasulullah shallallahu 'alaihi wasallam karena marah, Umar berkata, \"Kami bertaubat kepada Allah 'azza wajalla.\""},"6408":{"ar":"حَدَّثَنَا مُوسَى حَدَّثَنَا أَبُو عَوَانَةَ حَدَّثَنَا عَبْدُ الْمَلِكِ عَنْ وَرَّادٍ كَاتِبِ الْمُغِيرَةِ قَالَ كَتَبَ مُعَاوِيَةُ إِلَى الْمُغِيرَةِاكْتُبْ إِلَيَّ مَا سَمِعْتَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَتَبَ إِلَيْهِ إِنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ فِي دُبُرِ كُلِّ صَلَاةٍ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ اللَّهُمَّ لَا مَانِعَ لِمَا أَعْطَيْتَ وَلَا مُعْطِيَ لِمَا مَنَعْتَ وَلَا يَنْفَعُ ذَا الْجَدِّ مِنْكَ الْجَدُّ وَكَتَبَ إِلَيْهِ إِنَّهُ كَانَ يَنْهَى عَنْ قِيلَ وَقَالَ وَكَثْرَةِ السُّؤَالِ وَإِضَاعَةِ الْمَالِ وَكَانَ يَنْهَى عَنْ عُقُوقِ الْأُمَّهَاتِ وَوَأْدِ الْبَنَاتِ وَمَنْعٍ وَهَاتِ","id":"Telah menceritakan kepada kami [Musa] telah menceritakan kepada kami [Abu 'Awanah] telah menceritakan kepada kami [Abdul Malik] dari [Warrad] juru tulis Mughirah, berkata, \"Mu'awiyah berkirim surat kepada [Mughirah], 'Tolong tulislah kepadaku segala yang kau dengar dari Rasulullah shallallahu 'alaihi wasallam! Lantas Mughirah menulis 'Nabiyullah shallallahu 'alaihi wasallam sehabis shalat selalu memanjatkan doa: LAA-ILAAHA ILLALLAAH, WAHDAHU LAA SYARIIKA LAHU, LAHUL MULKU WALAHUL HAMDU WAHUWA 'ALAA KULLI SYAI`IN QADIIR, ALLAAHUMMA LAA MAANI'A LIMAA A'THAITA WALAA MU'THIYA LIMAA MANA'TA WALAA YANFA'U DZAL JADDI MINKAL JADDU (Tiada sesembahan yang hak selain Allah, tiada sekutu bagi-Nya, Milik-Nya lah segala kerajaan dan bagi-Nya segala puji dan Dia Maha berkuasa atas segala sesuatu. Ya Allah, tiada yang menghalangi apa yang Engkau berikan, dan tidak ada yang bisa memberi apa yang Engkau cegah, dan tidak bermanfaat kekayaan, dari-Mulah segala kekayaan) '. Dan Mughirah menulis, \"Beliau melarang mengatakan sesuatu yang tidak jelas sumbernya, banyak bertanya dan menghambur-hamburkan harta. Beliau juga melarang mendurhakai ibu, mengubur hidup-hidup anak perempuan serta menghalangi orang lain memperoleh kemanfaatan.\""},"6409":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَكُنَّا عِنْدَ عُمَرَ فَقَالَ نُهِينَا عَنْ التَّكَلُّفِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Tsabit] dari [Anas] berkata, \"Pernah kami di sisi [Umar] dan beliau berkata, \"Kami dilarang mengada-ada.\""},"6410":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ ح و حَدَّثَنِي مَحْمُودٌ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ أَخْبَرَنِي أَنَسُ بْنُ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ حِينَ زَاغَتْ الشَّمْسُ فَصَلَّى الظُّهْرَ فَلَمَّا سَلَّمَ قَامَ عَلَى الْمِنْبَرِ فَذَكَرَ السَّاعَةَ وَذَكَرَ أَنَّ بَيْنَ يَدَيْهَا أُمُورًا عِظَامًا ثُمَّ قَالَ مَنْ أَحَبَّ أَنْ يَسْأَلَ عَنْ شَيْءٍ فَلْيَسْأَلْ عَنْهُ فَوَاللَّهِ لَا تَسْأَلُونِي عَنْ شَيْءٍ إِلَّا أَخْبَرْتُكُمْ بِهِ مَا دُمْتُ فِي مَقَامِي هَذَا قَالَ أَنَسٌ فَأَكْثَرَ النَّاسُ الْبُكَاءَ وَأَكْثَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَقُولَ سَلُونِي فَقَالَ أَنَسٌ فَقَامَ إِلَيْهِ رَجُلٌ فَقَالَ أَيْنَ مَدْخَلِي يَا رَسُولَ اللَّهِ قَالَ النَّارُ فَقَامَ عَبْدُ اللَّهِ بْنُ حُذَافَةَ فَقَالَ مَنْ أَبِي يَا رَسُولَ اللَّهِ قَالَ أَبُوكَ حُذَافَةُ قَالَ ثُمَّ أَكْثَرَ أَنْ يَقُولَ سَلُونِي سَلُونِي فَبَرَكَ عُمَرُ عَلَى رُكْبَتَيْهِ فَقَالَ رَضِينَا بِاللَّهِ رَبًّا وَبِالْإِسْلَامِ دِينًا وَبِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَسُولًا قَالَ فَسَكَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ قَالَ عُمَرُ ذَلِكَ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي نَفْسِي بِيَدِهِ لَقَدْ عُرِضَتْ عَلَيَّ الْجَنَّةُ وَالنَّارُ آنِفًا فِي عُرْضِ هَذَا الْحَائِطِ وَأَنَا أُصَلِّي فَلَمْ أَرَ كَالْيَوْمِ فِي الْخَيْرِ وَالشَّرِّ","id":"Telah menceritakan kepada kami [Abul Yaman] Telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri]. (dalam jalur lain disebutkan) telah menceritakan kepadaku [Mahmud] telah menceritakan kepada kami [Abdurrazaq] Telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] telah mengabarkan kepadaku [Anas bin Malik] radliallahu 'anhu, Nabi shallallahu 'alaihi wasallam berangkat ketika matahari telah miring, lalu beliau shalat zhuhur, selesai salam beliau berdiri di atas mimbar dan mengingatkan kiamat, beliau ceritakan bahwa menjelang kiamat terjadi peristiwa-peristiwa besar, kemudian berkata: \"Siapa yang ingin bertanya sesuatu, silahkan! Demi Allah, tidaklah kalian bertanya kepadaku tentang sesuatu, selain kuberitakan kepada kalian selama aku masih berada di tempatku ini.\" Anas berkata, \"Lantas Orang-orang menangis terisak-isak dan Rasulullah shallallahu 'alaihi wasallam memperbanyak bertanya: \"Bertanyalah kalian kepadaku!\" Anas melanjutkan, \"Lantas ada seseorang berdiri menuju beliau dan bertanya, \"Dimanakah tempat tinggalku ya Rasulullah?\" Beliau menjawab: \"Kamu di neraka.\" Lantas Abdullah bin Khudzaifah berdiri dan bertanya, \"Siapa ayahku ya Rasulullah?\" Nabi menjawab: \"Ayahmu Hudzaifah.\" Anas melanjutkan perkataannya, \"Nabi memperbanyak bertanya: \"Bertanyalah kalian kepadaku, bertanyalah kalian kepadaku.\" Lantas Umar meletakkan kedua lututnya dan berkata, 'Kami ridla Allah sebagai Rabb, Islam sebagai agama, dan Muhammad shallallahu 'alaihi wasallam sebagai Rasul.\" Rasulullah shallallahu 'alaihi wasallam lantas terdiam ketika Umar mengucapkan yang demikian. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Demi Dzat yang diriku berada di tangan-Nya, tadi telah diperlihatkan kepadaku surga dan neraka dibalik tembok ini ketika aku shalat, dan belum pernah kulihat kebaikan dan keburukan seperti hari ini.\""},"6411":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ أَخْبَرَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا شُعْبَةُ أَخْبَرَنِي مُوسَى بْنُ أَنَسٍ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ قَالَقَالَ رَجُلٌ يَا نَبِيَّ اللَّهِ مَنْ أَبِي قَالَ أَبُوكَ فُلَانٌ وَنَزَلَتْ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَسْأَلُوا عَنْ أَشْيَاءَ }الْآيَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Abdurrahim] Telah mengabarkan kepada kami [Rauh bin Ubadah] telah menceritakan kepada kami [Syu'bah] telah mengabarkan kepadaku [Musa bin Anas] berkata, \"Aku mendengar [Anas bin Malik] berkata, \"Seseorang bertanya 'Wahai nabiyullah, siapa ayahku?\" Rasul menjawab: \"Ayahmu si A.\" Lantas turunlah ayat: '(Wahai orang-orang yang beriman, janganlah kalian bertanya tentang sesuatu…). (Qs. Al Maidah: 101) "},"6412":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ صَبَّاحٍ حَدَّثَنَا شَبَابَةُ حَدَّثَنَا وَرْقَاءُ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَنْ يَبْرَحَ النَّاسُ يَتَسَاءَلُونَ حَتَّى يَقُولُوا هَذَا اللَّهُ خَالِقُ كُلِّ شَيْءٍ فَمَنْ خَلَقَ اللَّهَ","id":"Telah menceritakan kepada kami [Al Hasan bin Shabbah] telah menceritakan kepada kami [Syababah] telah menceritakan kepada kami [Warqa'] dari [Abdullah bin Abdurrahman] aku mendengar [Anas bin Malik] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Manusia tidak henti-hentinya bertanya hingga saling bertanya 'Allah adalah pencipta segala sesuatu, lantas siapa yang menciptakan Allah? '"},"6413":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدِ بْنِ مَيْمُونٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ ابْنِ مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُ قَالَكُنْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَرْثٍ بِالْمَدِينَةِ وَهُوَ يَتَوَكَّأُ عَلَى عَسِيبٍ فَمَرَّ بِنَفَرٍ مِنْ الْيَهُودِ فَقَالَ بَعْضُهُمْ سَلُوهُ عَنْ الرُّوحِ وَقَالَ بَعْضُهُمْ لَا تَسْأَلُوهُ لَا يُسْمِعُكُمْ مَا تَكْرَهُونَ فَقَامُوا إِلَيْهِ فَقَالُوا يَا أَبَا الْقَاسِمِ حَدِّثْنَا عَنْ الرُّوحِ فَقَامَ سَاعَةً يَنْظُرُ فَعَرَفْتُ أَنَّهُ يُوحَى إِلَيْهِ فَتَأَخَّرْتُ عَنْهُ حَتَّى صَعِدَ الْوَحْيُ ثُمَّ قَالَ{ وَيَسْأَلُونَكَ عَنْ الرُّوحِ قُلْ الرُّوحُ مِنْ أَمْرِ رَبِّي }","id":"Telah menceritakan kepada kami [Muhammad bin Ubaid bin Maimun] telah menceritakan kepada kami ['Isa bin Yunus] dari [Al A'masy] dari [Ibrahim] dari ['Alqamah] dari [Ibn Mas'ud] rahiyallahu'anhu berkata, \"Pernah aku bersama nabi shallallahu 'alaihi wasallam di sebuah kebun Madinah sedang beliau menyandarkan punggung, lantas beberapa orang Yahudi lewat, dan sebagian mereka mengatakan 'Coba tanyailah dia tentang roh! ' Sebagian berkata 'Jangan kalian tanyai dia tentang itu, sebab yang kalian benci tidak bisa memperdengarkan kepada kalian.' Namun sebagian mereka berdiri dan bertanya \"Wahai Abul Qasim, beritahukanlah kami tentang roh! ' Lantas beliau berdiri beberapa saat mengamat-amati, maka aku tahu bahwa beliau sedang menerima wahyu, maka aku berusaha menyingkir dari beliau, hingga wahyu terangkat, kemudian beliau bersabda mengutip ayat: '(Mereka bertanya kepadamu tentang roh, katakanlah bahwa roh itu urusan Rabbiku) ' (Qs. Al Israa`: 85)."},"6414":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَاتَّخَذَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَاتَمًا مِنْ ذَهَبٍ فَاتَّخَذَ النَّاسُ خَوَاتِيمَ مِنْ ذَهَبٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي اتَّخَذْتُ خَاتَمًا مِنْ ذَهَبٍ فَنَبَذَهُ وَقَالَ إِنِّي لَنْ أَلْبَسَهُ أَبَدًا فَنَبَذَ النَّاسُ خَوَاتِيمَهُمْ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Abdullah bin Dinar] dari [Ibn Umar] radliallahu 'anhuma, ia berkata, \"Nabi shallallahu 'alaihi wasallam memakai cincin emas, lantas para sahabat juga membuat cincin emas, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Sungguh, aku dahulu memang memakai cincin emas, \" lantas beliau membuangnya dan bersabda: \"Sekali-kali aku tidak bakalan memakainya lagi, \" maka para sahabat juga membuang cincin mereka.\""},"6415":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا هِشَامٌ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُوَاصِلُوا قَالُوا إِنَّكَ تُوَاصِلُ قَالَ إِنِّي لَسْتُ مِثْلَكُمْ إِنِّي أَبِيتُ يُطْعِمُنِي رَبِّي وَيَسْقِينِي فَلَمْ يَنْتَهُوا عَنْ الْوِصَالِ قَالَ فَوَاصَلَ بِهِمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَيْنِ أَوْ لَيْلَتَيْنِ ثُمَّ رَأَوْا الْهِلَالَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ تَأَخَّ��َ الْهِلَالُ لَزِدْتُكُمْ كَالْمُنَكِّلِ لَهُمْ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] telah menceritakan kepada kami [Hisyam] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] mengatakan, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Jangan kalian berpuasa wishal!\" Para sahabat menyatakan protesnya \"Namun anda sendiri berpuasa wishal!\" Nabi menjawab: \"Aku tidak seperti kalian, Tuhanku selalu memberiku makan dan minum.\" Namun para sahabat tidak juga menghentikan wishalnya.\" Abu Hurairah melanjutkan, \"Maka Rasulullah shallallahu 'alaihi wasallam terus melakukan wishal bersama mereka dua hari atau dua malam, kemudian para sahabat melihat hilal (bulan sabit). Lantas Nabi shallallahu 'alaihi wasallam bersabda: \"Kalaulah bulan sabit ini terlambat, niscaya aku tambah puasa wishalnya, \" seolah-olah beliau ingin menghukum mereka.\""},"6416":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ حَدَّثَنِي إِبْرَاهِيمُ التَّيْمِيُّ حَدَّثَنِي أَبِي قَالَ خَطَبَنَا عَلِيٌّ رَضِيَ اللَّهُ عَنْهُعَلَى مِنْبَرٍ مِنْ آجُرٍّ وَعَلَيْهِ سَيْفٌ فِيهِ صَحِيفَةٌ مُعَلَّقَةٌ فَقَالَ وَاللَّهِ مَا عِنْدَنَا مِنْ كِتَابٍ يُقْرَأُ إِلَّا كِتَابُ اللَّهِ وَمَا فِي هَذِهِ الصَّحِيفَةِ فَنَشَرَهَا فَإِذَا فِيهَا أَسْنَانُ الْإِبِلِ وَإِذَا فِيهَا الْمَدِينَةُ حَرَمٌ مِنْ عَيْرٍ إِلَى كَذَا فَمَنْ أَحْدَثَ فِيهَا حَدَثًا فَعَلَيْهِ لَعْنَةُ اللَّهِ وَالْمَلَائِكَةِ وَالنَّاسِ أَجْمَعِينَ لَا يَقْبَلُ اللَّهُ مِنْهُ صَرْفًا وَلَا عَدْلًا وَإِذَا فِيهِ ذِمَّةُ الْمُسْلِمِينَ وَاحِدَةٌ يَسْعَى بِهَا أَدْنَاهُمْ فَمَنْ أَخْفَرَ مُسْلِمًا فَعَلَيْهِ لَعْنَةُ اللَّهِ وَالْمَلَائِكَةِ وَالنَّاسِ أَجْمَعِينَ لَا يَقْبَلُ اللَّهُ مِنْهُ صَرْفًا وَلَا عَدْلًا وَإِذَا فِيهَا مَنْ وَالَى قَوْمًا بِغَيْرِ إِذْنِ مَوَالِيهِ فَعَلَيْهِ لَعْنَةُ اللَّهِ وَالْمَلَائِكَةِ وَالنَّاسِ أَجْمَعِينَ لَا يَقْبَلُ اللَّهُ مِنْهُ صَرْفًا وَلَا عَدْلًا","id":"Telah menceritakan kepada kami ['Umar bin Hafs bin Ghiyats] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Al A'masy] Telah menceritakan kepadaku [Ibrahim At Taimi] Telah menceritakan kepadaku [Ayahku] mengatakan, \" [Ali] radliallahu 'anhu berpidato kepada kami di atas mimbar dari batu bata yang dipanggang yang di atasnya tergeletak pedang berisikan lembaran catatan yang menggantung. Lantas Ali berkata, \"Demi Allah, kami tidak mempunyai kitab suci yang dibaca selain Kitabullah dan apa yang terdapat dalam lembaran catatan ini.\" Lantas Ali membukanya, ternyata isinya gigi-gigi unta dan ternyata isinya ada pernyataan, \"Kota Madinah adalah haram semenjak 'Air (gunung di Madinah) hingga sini, maka barangsiapa melakukan keonaran (pelanggaran) di sana, maka baginya laknat Allah, laknat malikat dam manusia secara keseluruhan, Allah tidak menerima amalannya, baik yang wajib maupun yang sunnah, dan dalam lembaran catatan itu ada pernyataan 'Barangsiapa bersekutu kepada suatu kaum tanpa seijin sekutu sebelumnya, maka baginya laknat Allah, malaikat dan seluruh manusia, Allah tidak menerima amalannya, baik yang wajib maupun yang sunnah.\""},"6417":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ حَدَّثَنَا مُسْلِمٌ عَنْ مَسْرُوقٍ قَالَ قَالَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَاصَنَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْئًا تَرَخَّصَ فِيهِ وَتَنَزَّهَ عَنْهُ قَوْمٌ فَبَلَغَ ذَلِكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ مَا بَالُ أَقْوَامٍ يَتَنَزَّهُونَ عَنْ الشَّيْءِ أَصْنَعُهُ فَوَاللَّهِ إِنِّي أَعْلَمُهُمْ بِاللَّهِ وَأَشَدُّهُمْ لَهُ خَشْيَةً","id":"Telah menceritakan kepada kami [Umar bin Hafs] telah menceritakan kepada kami [Ayahku] telah mencerikan kepadaku [Al A'masy] telah menceritakan kepada kami [Muslim] dari [Masruq] berkata, \" [Aisyah] radliallahu 'anha berkata, \"Nabi shallallahu 'alaihi wasallam membuat sesuatu yang diperbolehkan bagi beliau, namun ada beberapa sahabat yang mengingkarinya (tidak mau menyatapnya). Berita itu kemudian sampai kepada nabi shallallahu 'alaihi wasallam, beliau kemudian memuja dan memuji Allah, lantas berkata: \"Apa alasan mereka itu menyingkiri sesuatu yang aku buat, demi Allah, aku adalah manusia yang paling mengenal Allah dan paling takut kepada-Nya.\""},"6418":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَخْبَرَنَا وَكِيعٌ أَخْبَرَنَا نَافِعُ بْنُ عُمَرَ عَنْ ابْنِ أَبِي مُلَيْكَةَ قَالَكَادَ الْخَيِّرَانِ أَنْ يَهْلِكَا أَبُو بَكْرٍ وَعُمَرُ لَمَّا قَدِمَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفْدُ بَنِي تَمِيمٍ أَشَارَ أَحَدُهُمَا بِالْأَقْرَعِ بْنِ حَابِسٍ التَّمِيمِيِّ الْحَنْظَلِيِّ أَخِي بَنِي مُجَاشِعٍ وَأَشَارَ الْآخَرُ بِغَيْرِهِ فَقَالَ أَبُو بَكْرٍ لِعُمَرَ إِنَّمَا أَرَدْتَ خِلَافِي فَقَالَ عُمَرُ مَا أَرَدْتُ خِلَافَكَ فَارْتَفَعَتْ أَصْوَاتُهُمَا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَزَلَتْ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَرْفَعُوا أَصْوَاتَكُمْ فَوْقَ صَوْتِ النَّبِيِّ إِلَى قَوْلِهِ عَظِيمٌ }قَالَ ابْنُ أَبِي مُلَيْكَةَ قَالَ ابْنُ الزُّبَيْرِ فَكَانَ عُمَرُ بَعْدُ وَلَمْ يَذْكُرْ ذَلِكَ عَنْ أَبِيهِ يَعْنِي أَبَا بَكْرٍ إِذَا حَدَّثَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِحَدِيثٍ حَدَّثَهُ كَأَخِي السِّرَارِ لَمْ يُسْمِعْهُ حَتَّى يَسْتَفْهِمَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil] telah mengabarkan kepada kami [Waki'] telah mengabarkan kepada kami [Nafi' bin Umar] dari [Ibn Abu Mulaikah] berkata, \"Hampir saja dua orang pilihan, Abu Bakar dan Umar, binasa tatkala utusan Bani Tamim menemui Nabi shallallahu 'alaihi wasallam, salah satu diantara dua sahabat pilihan itu menunjuk Aqra' bin Habis At Tamimi Al Hanzhali, saudara Bani Mujasyi', sedang lainnya menunjuk lainnya. Maka Abu Bakar berkata kepada Umar, 'Kamu inginnya menyelisihiku saja!\" Umar mengelak seraya mengatakan, \"Aku sama sekali tak berniat menyelisihimu! Suara keduanya terus semakin gaduh di sisi Nabi shallallahu 'alaihi wasallam, sehingga turunlah ayat: '(Wahai orang-orang yang beriman, jangan kalian meninggikan suara kalian diatas suara Nabi) ' (Qs. Al Hujurat: 2-3). Ibnu Abu Mulaikah berkata, \" [Ibnu Zubair] berkata, \"Di kemudian hari Umar -dan ia tidak menyebutkan dari kakeknya maksudnya Abu bakar- jika mengajak bicara dengan nabi shallallahu 'alaihi wasallam dengan suatu pembicaraan seperti orang yang mengadakan pembicaraan rahasia, tidak sampai terdengar orang lain hingga betul-betul ia memahaminya.\""},"6419":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنِي مَالِكٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ أُمِّ الْمُؤْمِنِينَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي مَرَضِهِ مُرُوا أَبَا بَكْرٍ يُصَلِّي بِالنَّاسِ قَالَتْ عَائِشَةُ قُلْتُ إِنَّ أَبَا بَكْرٍ إِذَا قَامَ فِي مَقَامِكَ لَمْ يُسْمِعْ النَّاسَ مِنْ الْبُكَاءِ فَمُرْ عُمَرَ فَلْيُصَلِّ لِلنَّاسِ فَقَالَ مُرُوا أَبَا بَكْرٍ فَلْيُصَلِّ بِالنَّاسِ فَقَالَتْ عَائِشَةُ فَقُلْتُ لِحَفْصَةَ قُولِي إِنَّ أَبَا بَكْرٍ إِذَا قَامَ فِي مَقَامِكَ لَمْ يُسْمِعْ النَّاسَ مِنْ الْبُكَاءِ فَمُرْ عُمَرَ فَلْيُصَلِّ بِالنَّاسِ فَفَعَلَتْ حَفْصَةُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّكُنَّ لَأَنْتُنَّ صَوَاحِبُ يُوسُفَ مُرُوا أَبَا بَكْرٍ فَلْيُصَلِّ لِلنَّاسِ فَقَالَتْ حَفْصَةُ لِعَائِشَةَ مَا كُنْتُ لِأُصِيبَ مِنْكِ خَيْرًا","id":"Telah menceritakan kepada kami [Ismail] telah menceritakan kepadaku [Malik] dari [Hisyam bin Urwah] dari [ayahnya] dari ['Aisyah] Ummul Mukminin, Rasulullah shallallahu 'alaihi wasallam bersabda ketika sakitnya: \"Suruhlah Abu bakar untuk mengimami orang-orang.\" 'Aisyah berkata, \"Aku katakan, 'Abu Bakar jika menggantimu, ia tidak bisa membaca bacaan secara keras hingga terdengar makmum karena suka menangis, suruh saja Umar untuk mengimami orang-orang! Namun Nabi tetap berkata: \"Suruhlah Abu Bakar untuk mengimami orang-orang! Aisyah katakan, \"Karenanya aku sarankan kepada Hafsah 'Tolong sampaikan kepada nabi, 'Abu Bakar jika menggantikanmu, ia tidak bisa membaca dengan keras sehingga terdengar makmum karena suka menangis, suruh saja Umar untuk mengimami orang-orang! ' Hafshah kontan mengerjakan saran Aisyah. Lantas Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kalian ini seperti saudara-saudara Yusuf saja (yang gemar berkomplot), suruh Abu bakar untuk mengimami orang-orang!\" Maka Hafshah berkata kepada Aisyah, \"Ternyata aku tidak memperoleh kebaikan dari saranmu.\""},"6420":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ أَبِي ذِئْبٍ حَدَّثَنَا الزُّهْرِيُّ عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّ قَالَجَاءَ عُوَيْمِرٌ الْعَجْلَانِيُّ إِلَى عَاصِمِ بْنِ عَدِيٍّ فَقَالَ أَرَأَيْتَ رَجُلًا وَجَدَ مَعَ امْرَأَتِهِ رَجُلًا فَيَقْتُلُهُ أَتَقْتُلُونَهُ بِهِ سَلْ لِي يَا عَاصِمُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ فَكَرِهَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَسَائِلَ وَعَابَهَا فَرَجَعَ عَاصِمٌ فَأَخْبَرَهُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَرِهَ الْمَسَائِلَ فَقَالَ عُوَيْمِرٌ وَاللَّهِ لَآتِيَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ وَقَدْ أَنْزَلَ اللَّهُ تَعَالَى الْقُرْآنَ خَلْفَ عَاصِمٍ فَقَالَ لَهُ قَدْ أَنْزَلَ اللَّهُ فِيكُمْ قُرْآنًا فَدَعَا بِهِمَا فَتَقَدَّمَا فَتَلَاعَنَا ثُمَّ قَالَ عُوَيْمِرٌ كَذَبْتُ عَلَيْهَا يَا رَسُولَ اللَّهِ إِنْ أَمْسَكْتُهَا فَفَارَقَهَا وَلَمْ يَأْمُرْهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِفِرَاقِهَا فَجَرَتْ السُّنَّةُ فِي الْمُتَلَاعِنَيْنِ وَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْظُرُوهَا فَإِنْ جَاءَتْ بِهِ أَحْمَرَ قَصِيرًا مِثْلَ وَحَرَةٍ فَلَا أُرَاهُ إِلَّا قَدْ كَذَبَ وَإِنْ جَاءَتْ بِهِ أَسْحَمَ أَعْيَنَ ذَا أَلْيَتَيْنِ فَلَا أَحْسِبُ إِلَّا قَدْ صَدَقَ عَلَيْهَا فَجَاءَتْ بِهِ عَلَى الْأَمْرِ الْمَكْرُوهِ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Muhammad bin Abdurrahman bin Abu Dzi'b] telah memberitakan kepada kami [Az Zuhri] dari [Sahl bin Sa'd as Sa'idi] berkata, \"Uwaimir Al 'Ajlani datang kepada 'Ashim bin Adi dan berkata, 'Bagaimana pendapatmu jika seorang laki-laki menemukan isterinya bersama laki-laki lain, lantas si suami membunuh laki-laki itu, apakah kalian lantas membunuh si suami karena pembunuhannya? Tolong tanyakan kepada Rasulullah untukku wahai Ashim!\" Lantas 'Ashim bertanya Nabi shallallahu 'alaihi wasallam. Rupanya nabi shallallahu 'alaihi wasallam tidak menyukai banyak tanya dan bahkan mencelanya. 'Ashim pun pulang dan mengabarkan kepadanya bahwa nabi shallallahu 'alaihi wasallam tidak menyukai banyak tanya. Spontan 'Uwaimir berkata, 'Sungguh akan kudatangi Nabi shallallahu 'alaihi wasallam! ' Uwaimir datang, sedang Allah ta'ala telah menurunkan alquran di belakang 'Ashim. Nabi terus berkata: \"Allah telah menurunkan alquran di tengah-tengah kalian.\" Lantas Rasul memanggil suami-isteri itu. Keduanya hadir dan saling meli'an. Kemudian Uwaimir berkata, 'Berarti kau dusta terhadap isteriku ya Rasulullah, jika aku terus mempertahankannya. Nabi pun langsung memisahkan si wanita dan tidak menyuruh si suami untuk memisahkan, dan pemisahan ini menjadi sunnah (pedoman) bagi suami-isteri yang saling meli'an. Kemudian Nabi shallallahu 'alaihi wasallam bersabda \"Tolong cermatilah bayinya, jika si wanita melahirkan bayi yang merah dan pendek, seperti tokek, maka aku tak berpendapat selain Uwaimir telah bohong, namun jika si wanita melahirkan bayi yang matanya hitam kelam yang mempunyai dua pantat, maka aku tak berpendpat selain Uwaimir telah jujur sehingga si wanita yang keliru.\" Di kemudian hari si wanita melahirkan bayi yang ciri-cirinya sangat disanksikan (sangat tidak menyerupai ayahnya).\""},"6421":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا اللَّيْثُ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي مَالِكُ بْنُ أَوْسٍ النَّصْرِيُّ وَكَانَ مُحَمَّدُ بْنُ جُبَيْرِ بْنِ مُطْعِمٍ ذَكَرَ لِيذِكْرًا مِنْ ذَلِكَ فَدَخَلْتُ عَلَى مَالِكٍ فَسَأَلْتُهُ فَقَالَ انْطَلَقْتُ حَتَّى أَدْخُلَ عَلَى عُمَرَ أَتَاهُ حَاجِبُهُ يَرْفَا فَقَالَ هَلْ لَكَ فِي عُثْمَانَ وَعَبْدِ الرَّحْمَنِ وَالزُّبَيْرِ وَسَعْدٍ يَسْتَأْذِنُونَ قَالَ نَعَمْ فَدَخَلُوا فَسَلَّمُوا وَجَلَسُوا فَقَالَ هَلْ لَكَ فِي عَلِيٍّ وَعَبَّاسٍ فَأَذِنَ لَهُمَا قَالَ الْعَبَّاسُ يَا أَمِيرَ الْمُؤْمِنِينَ اقْضِ بَيْنِي وَبَيْنَ الظَّالِمِ اسْتَبَّا فَقَالَ الرَّهْطُ عُثْمَانُ وَأَصْحَابُهُ يَا أَمِيرَ الْمُؤْمِنِينَ اقْضِ بَيْنَهُمَا وَأَرِحْ أَحَدَهُمَا مِنْ الْآخَرِ فَقَالَ اتَّئِدُوا أَنْشُدُكُمْ بِاللَّهِ الَّذِي بِإِذْنِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ هَلْ تَعْلَمُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ يُرِيدُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَفْسَهُقَالَ الرَّهْطُ قَدْ قَالَ ذَلِكَ فَأَقْبَلَ عُمَرُ عَلَى عَلِيٍّ وَعَبَّاسٍ فَقَالَ أَنْشُدُكُمَا بِاللَّهِ هَلْ تَعْلَمَانِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ذَلِكَ قَالَا نَعَمْ قَالَ عُمَرُ فَإِنِّي مُحَدِّثُكُمْ عَنْ هَذَا الْأَمْرِ إِنَّ اللَّهَ كَانَ خَصَّ رَسُولَهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذَا الْمَالِ بِشَيْءٍ لَمْ يُعْطِهِ أَحَدًا غَيْرَهُ فَإِنَّ اللَّهَ يَقُولُ{ مَا أَفَاءَ اللَّهُ عَلَى رَسُولِهِ مِنْهُمْ فَمَا أَوْجَفْتُمْ }الْآيَةَ فَكَانَتْ هَذِهِ خَالِصَةً لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ وَاللَّهِ مَا احْتَازَهَا دُونَكُمْ وَلَا اسْتَأْثَرَ بِهَا عَلَيْكُمْ وَقَدْ أَعْطَاكُمُوهَا وَبَثَّهَا فِيكُمْ حَتَّى بَقِيَ مِنْهَا هَذَا الْمَالُ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُنْفِقُ عَلَى أَهْلِهِ نَفَقَةَ سَنَتِهِمْ مِنْ هَذَا الْمَالِ ثُمَّ يَأْخُذُ مَا بَقِيَ فَيَجْعَلُهُ مَجْعَلَ مَالِ اللَّهِ فَعَمِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِذَلِكَ حَيَاتَهُ أَنْشُدُكُمْ بِاللَّهِ هَلْ تَعْلَمُونَ ذَلِكَ فَقَالُوا نَعَمْ ثُمَّ قَالَ لِعَلِيٍّ وَعَبَّاسٍ أَنْشُدُكُمَا اللَّهَ هَلْ تَعْلَمَانِ ذَلِكَ قَالَا نَعَمْ ثُمَّ تَوَفَّى اللَّهُ نَبِيَّهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَبُو بَكْرٍ أَنَا وَلِيُّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَبَضَهَا أَبُو بَكْرٍ فَعَمِلَ فِيهَا بِمَا عَمِلَ فِيهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنْتُمَا حِينَئِذٍ وَأَقْبَلَ عَلَى عَلِيٍّ وَعَبَّاسٍ تَزْعُمَانِ أَنَّ أَبَا بَكْرٍ فِيهَا كَذَا وَاللَّهُ يَعْلَمُ أَنَّهُ فِيهَا صَادِقٌ بَارٌّ رَاشِدٌ تَابِعٌ لِلْحَقِّ ثُمَّ تَوَفَّى اللَّهُ أَبَا بَكْرٍ فَقُلْتُ أَنَا وَلِيُّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبِي بَكْرٍ فَقَبَضْتُهَا سَنَتَيْنِ أَعْمَلُ فِيهَا بِمَا عَمِلَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ ثُمَّ جِئْتُمَانِي وَكَلِمَتُكُمَا عَلَى كَلِمَةٍ وَاحِدَةٍ وَأَمْرُكُمَا جَمِيعٌ جِئْتَنِي تَسْأَلُنِي نَصِيبَكَ مِنْ ابْنِ أَخِيكِ وَأَتَانِي هَذَا يَسْأَلُنِي نَصِيبَ امْرَأَتِهِ مِنْ أَبِيهَا فَقُلْتُ إِنْ شِئْتُمَا دَفَعْتُهَا إِلَيْكُمَا عَلَى أَنَّ عَلَيْكُمَا عَهْدَ اللَّهِ وَمِيثَاقَهُ لَتَعْمَلَانِ فِيهَا بِمَا عَمِلَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبِمَا عَمِلَ فِيهَا أَبُو بَكْرٍ وَبِمَا عَمِلْتُ فِيهَا مُنْذُ وَلِيتُهَا وَإِلَّا فَلَا تُكَلِّمَانِي فِيهَا فَقُلْتُمَا ادْفَعْهَا إِلَيْنَا بِذَلِكَ فَدَفَعْتُهَا إِلَيْكُمَا بِذَلِكَ أَنْشُدُكُمْ بِاللَّهِ هَلْ دَفَعْتُهَا إِلَيْهِمَا بِذَلِكَ قَالَ الرَّهْطُ نَعَمْ فَأَقْبَلَ عَلَى عَلِيٍّ وَعَبَّاسٍ فَقَالَ أَنْشُدُكُمَا بِاللَّهِ هَلْ دَفَعْتُهَا إِلَيْكُمَا بِذَلِكَ قَالَا نَعَمْ قَالَ أَفَتَلْتَمِسَانِ مِنِّي قَضَاءً غَيْرَ ذَلِكَ فَوَالَّذِي بِإِذْنِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ لَا أَقْضِي فِيهَا قَضَاءً غَيْرَ ذَلِكَ حَتَّى تَقُومَ السَّاعَةُ فَإِنْ عَجَزْتُمَا عَنْهَا فَادْفَعَاهَا إِلَيَّ فَأَنَا أَكْفِيكُمَاهَا","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] telah menceritakan kepada kami [Al Laits] telah menceritakan kepadaku ['Uqail] dari [Ibn Syihab] berkata, telah mengabarkan kepadaku [Malik bin Aus an Nashri], dan [Muhammad bin Jubair bin Muth'im] pernah mengingatkan aku tentang hal itu. AKu menemui Malik dan aku bertanya kepadanya.\" Ia meneruskan, \"Aku terus bertolak hingga kutemui [Umar], kemudian penjaga rumahnya bertanya, \"Apakah engkau berkenan memberi ijin [Utsman], [Abdurrahman bin Auf], [Zubair], dan [Sa'd] untuk bertemu?\" Umar menjawab, \"Ya.\" Mereka pun masuk, mengucapkan salam dan duduk. Si penjaga pintu bertanya lagi, \"Apakah anda memberi ijin untuk [Ali] dan [Abbas]\" Umar pun mengijinkan keduanya. Abbas kemudian bertanya, \"Wahai Amirul Mukminin, putuskanlah antara aku dan orang yang zhalim yang mencela.\" Sekelompok orang yang di antaranya Utsman dan para sahabatnya kemudian berkata, \"Wahai Amirul Mukminin, putuskanlah antara keduanya dan nyamankanlah salah satunya dari yang lain.\" Umar menjawab, \"Tolong kalian yang bijak, aku bersumpah atas kalian dengan nama Allah yang karena ijin-Nya langit dan bumi tegak. Tahukah kalian bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: 'Kami tidak diwarisi, apa yang kami tinggalkan adalah sedekah (bukan warisan) '? Maka kumpulan sahabat tadi menjawab, \"Memang beliau pernah bersabda yang demikian ini.\" Umar lalu menemui Ali dan Abbas seraya berkata, \"Aku bersumpah atas kalian dengan nama Allah, bukankah kalian berdua tahu bahwa Rasulullah pernah bersabda yang sedemikian tadi?\" Keduanya menjawab, \"Ya.\" Umar lalu berkata, \"Karenanya aku sekarang bicara kepada kalian tentang masalah (harta nabi). Sesungguhnya Allah mengkhususkan hanya untuk rasul-Nya shallallahu 'alaihi wasallam dalam hal harta ini, suatu yang tak akan diberikan-Nya kepada seorang pun, sebab Allah berfirman: '(Apa yang Allah berikan kepada rasul-Nya dari para tawanan, yang kamu dapatkan dengan tanpa mengerahkan… dan seterusnya (Qs. Al Hasyr; 6), kesemuanya ini adalah khusus bagi Rasulullah shallallahu 'alaihi wasallam. Kemudian demi Allah, beliau tidak memberikannya dan tidak pula menganugerahkanya secara khusus untuk kalian. Dahulu Rasul telah memberikannya kepada kalian dan membagikannya di tengah-tengah kalian, hingga harta ini masih tersisa. Dan Nabi shallallahu 'alaihi wasallam memberi belanja tahunan kepada keluarganya dari harta ini, kemudian beliau tarik sisanya dan beliau jadikan sebagai harta Allah, dan begitulah beliau mengelola hartanya semasa hidupnya. Aku bersumpah atas kalian dengan nama Allah, bukankah kalian tahu terhadap itu semua? Mereka menjawab, \"Ya.\" Kemudian Umar berkata kepada Ali dan Abbas, \"Aku bersumpah atas kalian dengan nama Allah, bukankah kalian berdua tahu tentang ini semua?\" keduanya menjawab, \"Ya.\" Umar meneruskan bicaranya, \"Kemudian Allah mewafatkan nabi-Nya shallallahu 'alaihi wasallam, lantas Abu Bakar mengatakan aku adalah wali Rasulullah shallallahu 'alaihi wasallam sehingga Abu Bakar mewenanginya dan mengelolanya sebagaimana Rasulullah shallallahu 'alaihi wasallam mengelolanya, dan kamu ketika itu juga ada.\" Lantas Umar menghadap Ali dan Abbas dengan mengatakan, \"Kalian beranggapan bahwa Abu Bakar seperti ini dan seperti ini, padahal Allah tahu bahwa dia terhadap harta itu betul-betul jujur, baik, lurus, dan mengikuti kebenaran. Kemudian Allah mewafatkan Abu bakar, maka aku (Umar) katakan bahwa aku sekarang adalah wali Rasulullah shallallahu 'alaihi wasallam dan juga wali Abu bakar, maka aku mewenangi harta itu dua tahun yang aku kelola sebagaimana Rasulullah shallallahu 'alaihi wasallam dan Abu Bakar mengelola, lantas anehnya kalian berdua mendatangi aku sedang kalian kompak, sama-sama sepakat, kamu menemuiku untuk meminta bagianmu dari anak saudaramu (ucapan ini Umar tujukan kepada Abbas, sebab ia adalah paman Rasulullah), sedang si ini (maksudnya Ali) datang kepadaku memintaku bagian isterinya dari ayahnya (Ucapan ini Umar tujukan kepada Ali, sebab ia adalah menantu Rasulullah). Maka aku katakan, 'Jikalah kalian berkenan, harta itu aku serahkan kepada kalian berdua, hanya kalian harus menerima resiko tanggung jawab dari janji Allah dan ikrar-Nya, yaitu agar kalian berdua mengelolanya sebagaimana Rasulullah shallallahu 'alaihi wasallam mengelola, dan juga sebagaimana Abu Bakar mengelola, dan juga sebagaimana aku mengolala semenjak aku mewenanginya. Kalaulah kamu berdua tidak bisa, tolong jangan kalian berdua mengajakku bicara tentang harta itu, jangan kalian berdua berkata, 'Serahkan harta itu kepada kami berdua' lantas aku katakan, 'kuserahkan kepadamu berdua'. Adapun sekarang, aku bersumpah kepada kalian dengan nama Allah, bukankah telah aku serahkan sekarang kepada keduanya?\" Beberapa kumpulan sahabat yang hadir menjawab, \"Benar, \" lantas Umar menghadap Ali dan Abbas seraya berkata, \"Aku bersumpah atas kalian berdua (dengan nama Allah), bukankah telah aku serahkan kepada kalian berdua masalah harta itu?\" Keduanya menjawab, \"Benar.\" Umar kemudian berkata, \"Apakah kalian berdua mencari-cari keputusan selain itu setelah memperolehnya dariku? Demi Dzat yang karena seijin-Nya bumi dan langit menjadi tegak, selama-lamanya aku tidak akan memutuskan keputusan selain itu hingga kiamat tiba. Maka jika kalian berdua tidak mampu, serahkan saja kepadaku, sebab aku bisa mengganti kalian berdua.\""},"6422":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا عَاصِمٌ قَالَ قُلْتُ لِأَنَسٍأَحَرَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ قَالَ نَعَمْ مَا بَيْنَ كَذَا إِلَى كَذَا لَا يُقْطَعُ شَجَرُهَا مَنْ أَحْدَثَ فِيهَا حَدَثًا فَعَلَيْهِ لَعْنَةُ اللَّهِ وَالْمَلَائِكَةِ وَالنَّاسِ أَجْمَعِينَ قَالَ عَاصِمٌ فَأَخْبَرَنِي مُوسَى بْنُ أَنَسٍ أَنَّهُ قَالَ أَوْ آوَى مُحْدِثًا","id":"Telah menceritakan kepada kami [Musa bin Ismail] telah menceritakan kepada kami ['Abdul Wahid] telah menceritakan kepada kami ['Ashim] berkata, \"Aku bertanya kepada [Anas], \"Bukankah Rasulullah shallallahu 'alaihi wasallam telah mengharamkan Madinah?\" Ia menjawab, \"Benar, yaitu antara ini hingga itu, demikian pula tidak dibenarkan pohonnya ditebang, barangsiapa mengada-adakan keonaran (pelanggaran) di sana, maka baginya laknat Allah, malaikat dan semua manusia.\" 'Ashim berkata, \"Musa bin Anas mengabarkan kepadaku, bahwa beliau mengatakan: \"Atau melindungi orang yang berbuat salah.\""},"6423":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ تَلِيدٍ حَدَّثَنِي ابْنُ وَهْبٍ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ شُرَيْحٍ وَغَيْرُهُ عَنْ أَبِي الْأَسْوَدِ عَنْ عُرْوَةَ قَالَ حَجَّ عَلَيْنَا عَبْدُ اللَّهِ بْنُ عَمْرٍو فَسَمِعْتُهُ يَقُولُسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ لَا يَنْزِعُ الْعِلْمَ بَعْدَ أَنْ أَعْطَاكُمُوهُ انْتِزَاعًا وَلَكِنْ يَنْتَزِعُهُ مِنْهُمْ مَعَ قَبْضِ الْعُلَمَاءِ بِعِلْمِهِمْ فَيَبْقَى نَاسٌ جُهَّالٌ يُسْتَفْتَوْنَ فَيُفْتُونَ بِرَأْيِهِمْ فَيُضِلُّونَ وَيَضِلُّونَ فَحَدَّثْتُ بِهِ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ إِنَّ عَبْدَ اللَّهِ بْنَ عَمْرٍو حَجَّ بَعْدُ فَقَالَتْ يَا ابْنَ أُخْتِي انْطَلِقْ إِلَى عَبْدِ اللَّهِ فَاسْتَثْبِتْ لِي مِنْهُ الَّذِي حَدَّثْتَنِي عَنْهُ فَجِئْتُهُ فَسَأَلْتُهُ فَحَدَّثَنِي بِهِ كَنَحْوِ مَا حَدَّثَنِي فَأَتَيْتُ عَائِشَةَ فَأَخْبَرْتُهَا فَعَجِبَتْ فَقَالَتْ وَاللَّهِ لَقَدْ حَفِظَ عَبْدُ اللَّهِ بْنُ عَمْرٍو","id":"Telah menceritakan kepada kami [Sa'id bin Talid] telah menceritakan kepadaku [Ibn Wahb] telah menceritakan kepadaku [Abdurrahman bin Syuraikh] dan lainnya dari [Abul Aswad] dari ['Urwah] berkata, \" [Abdullah bin Amru] mendatangi kami dan kudengar ia berkata, 'Aku mendengar Nabi shallallahu 'alaihi wasallam shallallahu 'alaihi wasallam bersabda: \"Allah tidak mencabut ilmu setelah Ia berikan kepada kalian secara spontanitas (sekaligus), namun Allah mencabutnya dari mereka dengan cara mewafatkan para 'ulama yang sekaligus tercabut keilmuan mereka, sehingga yang tinggal hanyalah manusia-manusia bodoh, mereka dimintai fatwa, lalu mereka memberikan fatwa berdasarkan logika mereka sendiri, mereka sesat dan juga menyesatkan.\" Hadits ini kemudian aku ceritakan kepada 'Aisyah, isteri nabi shallallahu 'alaihi wasallam, Ketika Abdullah bin Amru berhaji, 'Aisyah berkata, \"Wahai anak saudaraku, tolong temuilah Abdullah dan carilah kepastian (riwayat) darinya sebagaimana riwayat engkau ambil darinya. Aku pun mendatangi Abdullah dan aku tanyakan kepadanya. Abdullah kemudian menceritakan kepadaku dengannya seperti yang ia ceritakan kepadaku, lalu kudatangi 'Aisyah dan aku kabarkan kepadanya. Ia pun terkagum-kagum dan berkata \"Demi Allah, 'Abdullah bin 'Amru memang betul-betul hafal.\""},"6424":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا أَبُو حَمْزَةَ سَمِعْتُ الْأَعْمَشَ قَالَ سَأَلْتُ أَبَا وَائِلٍ هَلْ شَهِدْتَ صِفِّينَ قَالَ نَعَمْ فَسَمِعْتُ سَهْلَ بْنَ حُنَيْفٍ يَقُولُ ح و حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ قَالَ قَالَ سَهْلُ بْنُ حُنَيْفٍيَا أَيُّهَا النَّاسُ اتَّهِمُوا رَأْيَكُمْ عَلَى دِينِكُمْ لَقَدْ رَأَيْتُنِي يَوْمَ أَبِي جَنْدَلٍ وَلَوْ أَسْتَطِيعُ أَنْ أَرُدَّ أَمْرَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْهِ لَرَدَدْتُهُ وَمَا وَضَعْنَا سُيُوفَنَا عَلَى عَوَاتِقِنَا إِلَى أَمْرٍ يُفْظِعُنَا إِلَّا أَسْهَلْنَ بِنَا إِلَى أَمْرٍ نَعْرِفُهُ غَيْرَ هَذَا الْأَمْرِ قَالَ وَقَالَ أَبُو وَائِلٍ شَهِدْتُ صِفِّينَ وَبِئْسَتْ صِفُّونَ","id":"Telah menceritakan kepada kami ['Abdan] telah mengabarkan kepada kami [Abu Hamzah] aku mendengar [Al A'masy] ia berkata, \"Aku mendengar [Abu Wail] berkata, \"Apakah engkau menyaksikan perang Shiffin?\" Ia menjawab, \"Ya. Aku mendengar [Sahl bin Hunaif] berkata.\" (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Musa bin Ismail] telah menceritakan kepada kami [Abu Awanah] dari [Al A'masy] dari [Abu Wail] ia berkata; [Sahl bin Hunaif] berkata, \"Wahai manusia, telitilah logika kalian terhadap agama kalian, sebab ketika hari-hari Abu jandal disiksa, aku berpendapat kalaulah bisa akan kutolak perintah Rasulullah shallallahu 'alaihi wasallam, dan tidak akan kami letakkan pedang kami yang berada di atas pundak kami karena suatu hal yang menjadikan hati kami sangat miris, hanya pendapat kami --alhamdullillah-memudahkan kami menerima sesuatu yang akhirnya bisa kami sadari, yang sangat berlawanan dengan kejadian yang ada.\" Al A'masy berkata, \"Abu Wail berkata, \"Aku pernah menyaksikan perang Shiffin, dan alangkah buruk tragedi perang shiffin.\" "},"6425":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ سَمِعْتُ ابْنَ الْمُنْكَدِرِ يَقُولُ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُمَرِضْتُ فَجَاءَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُنِي وَأَبُو بَكْرٍ وَهُمَا مَاشِيَانِ فَأَتَانِي وَقَدْ أُغْمِيَ عَلَيَّ فَتَوَضَّأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ صَبَّ وَضُوءَهُ عَلَيَّ فَأَفَقْتُ فَقُلْتُ يَا رَسُولَ اللَّهِ وَرُبَّمَا قَالَ سُفْيَانُ فَقُلْتُ أَيْ رَسُولَ اللَّهِ كَيْفَ أَقْضِي فِي مَالِي كَيْفَ أَصْنَعُ فِي مَالِي قَالَ فَمَا أَجَابَنِي بِشَيْءٍ حَتَّى نَزَلَتْ آيَةُ الْمِيرَاثِ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Sufyan] berkata, aku mendengar [Ibnul Munakdir] berkata, aku mendengar [Jabir bin Abdullah] mengatakan, \"Saat aku sakit Rasulullah shallallahu 'alaihi wasallam dan Abu Bakar membesukku dengan berjalan kaki. Keduanya menjengukku sedang aku dalam keadaan pingsan. Lantas Rasulullah shallallahu 'alaihi wasallam berwudlu dan menuangkan wudlunya kepadaku sehingga aku siuman. Kemudian aku katakan, \"Wahai Rasulullah, \" dan terkadang Sufyan menyebutkan \"Hai Rasulullah (bukan Wahai namun Hai), bagaimana harus aku putuskan masalah hartaku? Dan bagaimana yang harus kuperbuat terhadap hartaku?\" Jabir berkata, \"Beliau tidak menjawabku dengan suatu apapaun hingga ayat tentang waris diturunkan.\""},"6426":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَصْبَهَانِيِّ عَنْ أَبِي صَالِحٍ ذَكْوَانَ عَنْ أَبِي سَعِيدٍجَاءَتْ امْرَأَةٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ ذَهَبَ الرِّجَالُ بِحَدِيثِكَ فَاجْعَلْ لَنَا مِنْ نَفْسِكَ يَوْمًا نَأْتِيكَ فِيهِ تُعَلِّمُنَا مِمَّا عَلَّمَكَ اللَّهُ فَقَالَ اجْتَمِعْنَ فِي يَوْمِ كَذَا وَكَذَا فِي مَكَانِ كَذَا وَكَذَا فَاجْتَمَعْنَ فَأَتَاهُنَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَلَّمَهُنَّ مِمَّا عَلَّمَهُ اللَّهُ ثُمَّ قَالَ مَا مِنْكُنَّ امْرَأَةٌ تُقَدِّمُ بَيْنَ يَدَيْهَا مِنْ وَلَدِهَا ثَلَاثَةً إِلَّا كَانَ لَهَا حِجَابًا مِنْ النَّارِ فَقَالَتْ امْرَأَةٌ مِنْهُنَّ يَا رَسُولَ اللَّهِ أَوْ اثْنَيْنِ قَالَ فَأَعَادَتْهَا مَرَّتَيْنِ ثُمَّ قَالَ وَاثْنَيْنِ وَاثْنَيْنِ وَاثْنَيْنِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abu'Awanah] dari [Abdurrahman bin Al Ashbahani] dari [Abu Shalih Dzakwan] dari [Abu Sa'id], bahwa seorang wanita menemui Rasulullah shallallahu 'alaihi wasallam dan menyampaikan uneg-unegnya, \"Wahai Rasulullah, orang laki-laki sudah biasa datang kepadamu dan menimba hadits, maka tolong berilah kami jatah harimu sehingga kami bisa menemuimu dan anda dapat mengajarkan kepada kami ilmu yang telah Allah ajarkan kepada anda.\" Rasul mengiayakan dengan bersabda: \"Boleh, berkumpullah kalian pada hari ini dan ini, di tempat si fulan dan fulan, \" maka para wanita pun berkumpul dan Rasulullah shallallahu 'alaihi wasallam mengajari mereka ilmu yang telah Allah ajarkan kepada beliau. Kemudian Rasulullah shallallahu 'alaihi wasallam mengatakan kepada para wanita itu: \"Tidaklah salah seorang di antara kalian melahirkan tiga anak (yang shalih), kecuali ketiga anak itu akan menjadi penghalang neraka baginya.\" Maka ada seorang wanita yang bertanya, 'Wahai Rasulullah, bagaimana kalau hanya dua?\" Wanita itu mengulanginya hingga dua kali. Maka Rasulullah menjawab: \"Sekalipun hanya dua, sekalipun hanya dua.\""},"6427":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْمَاعِيلَ عَنْ قَيْسٍ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَزَالُ طَائِفَةٌ مِنْ أُمَّتِي ظَاهِرِينَ حَتَّى يَأْتِيَهُمْ أَمْرُ اللَّهِ وَهُمْ ظَاهِرُونَ","id":"Telah menceritakan kepada kami [Ubaidullah bin Musa] dari [Ismail] dari [Qais] dari [Mughirah bin Syu'bah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Akan senantiasa ada sekelompok dari umatku yang tegar di jalan kebenaran hingga keputusan Allah datang kepada mereka, dan mereka selalu tegar dalam jalan kebenaran.\""},"6428":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي حُمَيْدٌ قَالَ سَمِعْتُ مُعَاوِيَةَ بْنَ أَبِي سُفْيَانَ يَخْطُبُ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ يُرِدْ اللَّهُ بِهِ خَيْرًا يُفَقِّهْهُ فِي الدِّينِ وَإِنَّمَا أَنَا قَاسِمٌ وَيُعْطِي اللَّهُ وَلَنْ يَزَالَ أَمْرُ هَذِهِ الْأُمَّةِ مُسْتَقِيمًا حَتَّى تَقُومَ السَّاعَةُ أَوْ حَتَّى يَأْتِيَ أَمْرُ اللَّهِ","id":"Telah menceritakan kepada kami [Ismail] telah menceritakan kepada kami [Ibn Wahb] dari [Yunus] dari [Ibn Syihab] telah mengabarkan kepadaku [Humaid] berkata, aku mendengar [Mu'awiyah bin Abu Sufyan] berpidato dengan berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda; \"Barangsiapa yang Allah kehendaki menjadi baik, maka Allah menjadikannya pandai terhadap urusan agamanya, hanyasanya aku membagi sedang Allah Sang pemberi, dan keadaan umat ini akan terus senantiasa lurus hingga kiamat tiba, atau dengan redaksi, 'hingga keputusan Allah tiba.\""},"6429":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ عَمْرٌو سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُلَمَّا نَزَلَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ قُلْ هُوَ الْقَادِرُ عَلَى أَنْ يَبْعَثَ عَلَيْكُمْ عَذَابًا مِنْ فَوْقِكُمْ }قَالَ أَعُوذُ بِوَجْهِكَ{ أَوْ مِنْ تَحْتِ أَرْجُلِكُمْ }قَالَ أَعُوذُ بِوَجْهِكَ فَلَمَّا نَزَلَتْ{ أَوْ يَلْبِسَكُمْ شِيَعًا وَيُذِيقَ بَعْضَكُمْ بَأْسَ بَعْضٍ }قَالَ هَاتَانِ أَهْوَنُ أَوْ أَيْسَرُ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Sufyan], ['Amru] berkata, \"Aku mendengar [Jabir bin Abdullah] radliallahu 'anhuma berkata, \"Ketika diturunkan kepada Rasulullah shallallahu 'alaihi wasallam ayat: '(Katakanlah, Dialah Allah yang mampu mengutus siksa kepada kalian dari atas kamu) ' (Qs. Al an'aam: 65), maka Rasulullah berdoa: 'Aku berlindung dengan wajah-Mu, '(Atau dari bawah kakimu) ', Nabi berdoa: \"Aku berlindung dengan wajah-Mu, \" maka dikala diturunkan: '(atau menjadikan kalian berkelompok-kelompok dan menjadikan sebagian di antara kalian merasakan keganasan sebagian yang lain) ', maka Rasulullah bersabda: \"Perpecahan dan keganasan konflik ini lebih ringan, atau beliau katakan 'lebih remeh.\""},"6430":{"ar":"حَدَّثَنَا أَصْبَغُ بْنُ الْفَرَجِ حَدَّثَنِي ابْنُ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَأَنَّ أَعْرَابِيًّا أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ امْرَأَتِي وَلَدَتْ غُلَامًا أَسْوَدَ وَإِنِّي أَنْكَرْتُهُ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ لَكَ مِنْ إِبِلٍ قَالَ نَعَمْ قَالَ فَمَا أَلْوَانُهَا قَالَ حُمْرٌ قَالَ هَلْ فِيهَا مِنْ أَوْرَقَ قَالَ إِنَّ فِيهَا لَوُرْقًا قَالَ فَأَنَّى تُرَى ذَلِكَ جَاءَهَا قَالَ يَا رَسُولَ اللَّهِ عِرْقٌ نَزَعَهَا قَالَ وَلَعَلَّ هَذَا عِرْقٌ نَزَعَهُ وَلَمْ يُرَخِّصْ لَهُ فِي الِانْتِفَاءِ مِنْهُ","id":"Telah menceritakan kepada kami [Asbagh bin Al Faraj] telah menceritakan kepadaku [Ibn Wahb] dari [Yunus] dari [Ibn Syihab] dari [Abu Salamah bin Abdurrahman] dari [Abu Hurairah], bahwa ada seorang laki-laki arab badui (nomade, primitive) mendatagi Rasulullah shallallahu 'alaihi wasallam dan berujar, \"Isteriku melahirkan bayi hitam pekat dan aku memungkirinya.\" Maka Rasulullah shallallahu 'alaihi wasallam bertanya: \"Bukankah engkau juga mempunyai unta?\" Ia menjawab, \"Benar.\" Nabi bertanya lagi: \"Lalu, apa warnanya? ' Ia menjawab, \"Merah.\" Nabi bertanya lagi: \"Bukankah di sana juga ada belang kecoklatan?\" Si arab badui menjawab, \"Betul, di sana ada belang warna coklat.\" Nabi bertanya lagi: \"Lantas dari mana warna itu datang?\" Si arab badui menjawab, \"Boleh jadi akar keturunan yang menurunkan warna itu, dan tidak memberi ruang untuk meniadakannya sama sekali.\""},"6431":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ امْرَأَةً جَاءَتْ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ إِنَّ أُمِّي نَذَرَتْ أَنْ تَحُجَّ فَمَاتَتْ قَبْلَ أَنْ تَحُجَّ أَفَأَحُجَّ عَنْهَا قَالَ نَعَمْ حُجِّي عَنْهَا أَرَأَيْتِ لَوْ كَانَ عَلَى أُمِّكِ دَيْنٌ أَكُنْتِ قَاضِيَتَهُ قَالَتْ نَعَمْ فَقَالَ اقْضُوا اللَّهَ الَّذِي لَهُ فَإِنَّ اللَّهَ أَحَقُّ بِالْوَفَاءِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibn Abbas], bahwa seorang wanita menemui Nabi shallallahu 'alaihi wasallam dan berujar, \"Ibuku bernadzar untuk haji, hanya terburu meninggal dunia, bolehkah aku menggantikan hajinya?\" Nabi shallallahu 'alaihi wasallam menjawab: \"Silahkan, berhajilah engkau untuk menggantikannya, bukankah engkau sependapat sekiranya ibumu mempunyai hutang, bukankah engkau yang melunasi?\" Wanita itu menjawab, \"Ya.\" Lantas Nabi berkata: \"Penuhilah hutang Allah, sebab Allah lebih berhak untuk dilunasi hutangnya.\""},"6432":{"ar":"حَدَّثَنَا شِهَابُ بْنُ عَبَّادٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ حُمَيْدٍ عَنْ إِسْمَاعِيلَ عَنْ قَيْسٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا حَسَدَ إِلَّا فِي اثْنَتَيْنِ رَجُلٌ آتَاهُ اللَّهُ مَالًا فَسُلِّطَ عَلَى هَلَكَتِهِ فِي الْحَقِّ وَآخَرُ آتَاهُ اللَّهُ حِكْمَةً فَهُوَ يَقْضِي بِهَا وَيُعَلِّمُهَا","id":"Telah menceritakan kepada kami [Syihab bin Ubbad] telah menceritakan kepada kami [Ibrahim bin Humaid] dari [Ismail] dari [Qais] dari ['Abdullah] mengatakan, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak boleh dengki kecuali dalam dua hal; Seseorang yang Allah beri harta, lantas ia mengelola perbelanjaannya dalam rangka kebenaran, dan seseorang yang Allah beri hikmah (ilmu) kemudian ia pergunakan untuk memutuskan masalah dan ia ajarkan.\""},"6433":{"ar":"حَدَّثَنَا مُحَمَّدٌ أَخْبَرَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَسَأَلَ عُمَرُ بْنُ الْخَطَّابِ عَنْ إِمْلَاصِ الْمَرْأَةِ هِيَ الَّتِي يُضْرَبُ بَطْنُهَا فَتُلْقِي جَنِينًا فَقَالَ أَيُّكُمْ سَمِعَ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهِ شَيْئًا فَقُلْتُ أَنَا فَقَالَ مَا هُوَ قُلْتُ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِيهِ غُرَّةٌ عَبْدٌ أَوْ أَمَةٌ فَقَالَ لَا تَبْرَحْ حَتَّى تَجِيئَنِي بِالْمَخْرَجِ فِيمَا قُلْتَ فَخَرَجْتُ فَوَجَدْتُ مُحَمَّدَ بْنَ مَسْلَمَةَ فَجِئْتُ بِهِ فَشَهِدَ مَعِي أَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِيهِ غُرَّةٌ عَبْدٌ أَوْ أَمَةٌتَابَعَهُ ابْنُ أَبِي الزِّنَادِ عَنْ أَبِيهِ عَنْ عُرْوَةَ عَنْ الْمُغِيرَةِ","id":"Telah menceritakan kepada kami [Muhammad] telah mengabarkan kepada kami [Abu Mu'awiyah] telah menceritakan kepada kami [Hisyam] dari [Ayahnya] dari [Mughirah bin Syu'bah] berkata, \"Umar bin Khattab pernah bertanya tentang imlash, yaitu perut seorang wanita yang sedang hamil dipukul agar janinnya keguguran. Umar tanyakan, \"Siapa di antara kalian yang mendengar nabi shallallahu 'alaihi wasallam bersabda tentang hal itu?\" Aku menjawab, \"Aku.\" Umar bertanya, 'Bagaimana menurutmu? ' Aku jawab, \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda tentangnya, yaitu membayar sepuluh diyat yang nilainya setara satu budak atau satu hamba sahaya.\" Umar lantas berkata, \"Tolong kamu jangan pergi jauh-jauh hingga engkau membawaku penegasan yang kamu katakan!\" Lantas aku keluar dan kutemukan [Muhammad bin Maslamah], aku membawanya dan ia bersaksi bersamaku bahwa ia mendengar Nabi shallallahu 'alaihi wasallam bersabda tentangnya, yaitu membayar sepuluh diyat yang senilai satu budak atau hamba sahaya.\" Hadits ini diperkuat oleh [Ibn Abu Az Zinad] dari [ayahnya] dari [Urwah] dari [Mughirah]."},"6434":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَقُومُ السَّاعَةُ حَتَّى تَأْخُذَ أُمَّتِي بِأَخْذِ الْقُرُونِ قَبْلَهَا شِبْرًا بِشِبْرٍ وَذِرَاعًا بِذِرَاعٍ فَقِيلَ يَا رَسُولَ اللَّهِ كَفَارِسَ وَالرُّومِ فَقَالَ وَمَنْ النَّاسُ إِلَّا أُولَئِكَ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Ibn Abu Dzi'b] dari [Al Maqburi] dari [Abu Hurairah] radliallahu 'anhu, dari Nabi shallallahu 'alaihi wasallam bersabda: \"Hari kiamat tak bakalan terjadi hingga umatku meniru generasi-generasi sebelumnya, sejengkal demi sejengkal, sehasta demi sehasta.\" Ditanyakan, \"Wahai Rasulullah, seperti Persi dan Romawi?\" Nabi menjawab: \"Manusia mana lagi selain mereka itu?\""},"6435":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْعَزِيزِ حَدَّثَنَا أَبُو عُمَرَ الصَّنْعَانِيُّ مِنْ الْيَمَنِ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَتَتْبَعُنَّ سَنَنَ مَنْ كَانَ قَبْلَكُمْ شِبْرًا شِبْرًا وَذِرَاعًا بِذِرَاعٍ حَتَّى لَوْ دَخَلُوا جُحْرَ ضَبٍّ تَبِعْتُمُوهُمْ قُلْنَا يَا رَسُولَ اللَّهِ الْيَهُودُ وَالنَّصَارَى قَالَ فَمَنْ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul Aziz] telah menceritakan kepada kami [Abu Umar Ash Shan'ani] dari Yaman dari [Zaid bin Aslam] dari ['Atha bin Yasar] dari [Abu Sa'id Al Khudzri] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sungguh, engkau akan mengikuti tradisi orang-orang sebelum kalian, sehasta demi sehasta, sejengkal demi sejengkal, hingga kalaulah mereka masuk liang biawak, niscaya kalian mengikuti mereka.\" Kami bertanya, \"Wahai Rasulullah, Yahudi dan nasranikah?\" Nabi menjawab: \"Siapa lagi kalau bukan mereka?\""},"6436":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا الْأَعْمَشُ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ مِنْ نَفْسٍ تُقْتَلُ ظُلْمًا إِلَّا كَانَ عَلَى ابْنِ آدَمَ الْأَوَّلِ كِفْلٌ مِنْهَا وَرُبَّمَا قَالَ سُفْيَانُ مِنْ دَمِهَا لِأَنَّهُ أَوَّلُ مَنْ سَنَّ الْقَتْلَ أَوَّلًا","id":"Telah menceritakan kepada kami [Al Humaidi] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Al A'masy] dari ['Abdullah bin Murrah] dari [Masruq] dari [Abdullah] mengatakan, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Tidaklah seseorang dibantai secara zhalim, selain anak Adam pertama turut menanggung dosanya.\" Adakalanya Sufyan menyebutkan dengan redaksi, \"Menanggung dosa darah yang ditumpahkan, sebab dialah yang pertama-tama melakukannya.\""},"6437":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنِي مَالِكٌ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ السَّلَمِيِّأَنَّ أَعْرَابِيًّا بَايَعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْإِسْلَامِ فَأَصَابَ الْأَعْرَابِيَّ وَعْكٌ بِالْمَدِينَةِ فَجَاءَ الْأَعْرَابِيُّ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَقِلْنِي بَيْعَتِي فَأَبَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ جَاءَهُ فَقَالَ أَقِلْنِي بَيْعَتِي فَأَبَى ثُمَّ جَاءَهُ فَقَالَ أَقِلْنِي بَيْعَتِي فَأَبَى فَخَرَجَ الْأَعْرَابِيُّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا الْمَدِينَةُ كَالْكِيرِ تَنْفِي خَبَثَهَا وَيَنْصَعُ طِيبُهَا","id":"Telah menceritakan kepada kami [Ismail] telah menceritakan kepadaku [Malik] dari [Muhammad bin Al Munkadir] dari [Jabir bin Abdullah as Salmi], bahwa seorang arab badui berbaiat kepada Rasulullah shallallahu 'alaihi wasallam untuk Islam, lantas si arab badui terkena demam di Madinah, sehingga ia menemui Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, tolong batalkanlah baiatku, \" namun Rasulullah enggan. Kemudian ia mendatangi beliau lagi dan berkata, \"Tolong batalkanlah baiatku!\" Namun Rasulullah tetap enggan. Kemudian ia datang lagi untuk kali ketiga dan berkata, \"Tolong batalkanlah baiatku.\" Namun Rasulullah menolak, lantas Rasulullah shallallahu 'alaihi wasallam bersabda: \"Madinah itu bagaikan mesin tungku api, ia membersihkan karat-karat (besi) dan menyaring yang baik-baik saja.\""},"6438":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكُنْتُ أُقْرِئُ عَبْدَ الرَّحْمَنِ بْنَ عَوْفٍ فَلَمَّا كَانَ آخِرُ حَجَّةٍ حَجَّهَا عُمَرُ فَقَالَ عَبْدُ الرَّحْمَنِ بِمِنًى لَوْ شَهِدْتَ أَمِيرَ الْمُؤْمِنِينَ أَتَاهُ رَجُلٌ قَالَ إِنَّ فُلَانًا يَقُولُ لَوْ مَاتَ أَمِيرُ الْمُؤْمِنِينَ لَبَايَعْنَا فُلَانًا فَقَالَ عُمَرُ لَأَقُومَنَّ الْعَشِيَّةَ فَأُحَذِّرَ هَؤُلَاءِ الرَّهْطَ الَّذِينَ يُرِيدُونَ أَنْ يَغْصِبُوهُمْ قُلْتُ لَا تَفْعَلْ فَإِنَّ الْمَوْسِمَ يَجْمَعُ رَعَاعَ النَّاسِ يَغْلِبُونَ عَلَى مَجْلِسِكَ فَأَخَافُ أَنْ لَا يُنْزِلُوهَا عَلَى وَجْهِهَا فَيُطِيرُ بِهَا كُلُّ مُطِيرٍ فَأَمْهِلْ حَتَّى تَقْدَمَ الْمَدِينَةَ دَارَ الْهِجْرَةِ وَدَارَ السُّنَّةِ فَتَخْلُصَ بِأَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْمُهَاجِرِينَ وَالْأَنْصَارِ فَيَحْفَظُوا مَقَالَتَكَ وَيُنْزِلُوهَا عَلَى وَجْهِهَا فَقَالَ وَاللَّهِ لَأَقُومَنَّ بِهِ فِي أَوّ��لِ مَقَامٍ أَقُومُهُ بِالْمَدِينَةِ قَالَ ابْنُ عَبَّاسٍ فَقَدِمْنَا الْمَدِينَةَ فَقَالَ إِنَّ اللَّهَ بَعَثَ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْحَقِّ وَأَنْزَلَ عَلَيْهِ الْكِتَابَ فَكَانَ فِيمَا أُنْزِلَ آيَةُ الرَّجْمِ","id":"Telah menceritakan kepada kami [Musa bin Ismail] telah menceritakan kepada kami [Abdul Wahid] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Ubaidullah bin Abdullah] berkata, telah menceritakan kepadaku [Ibn Abbas] radliallahu 'anhu, ia berkata, \"Dahulu aku membacakan Abdurrahman bin Auf. Dikala [Umar] melakukan haji yang terakhir kalinya, Abdurrahman berkata di Mina, \"Sekiranya saja engkau melihat Amirul Mukminin ketika didatangi seseorang yang berkata, si A berkata, 'Kalaulah Amirul Mukminin meninggal, niscaya aku berbaiat kepada si fulan dan si fulan.\" Lantas Umar berkata, \"Niscaya sore ini aku berdiri memberi peringatan orang-orang yang ingin merebut wewenang mereka.\" Abdurrahman berkata, \"Hai, jangan kau lakukan! Sebab musim haji ini menghimpun para pemimpin manusia yang memenuhi majlismu!\" Maka aku khawatir jangan-jangan mereka tidak menggunakan saranmu sesuai tempatnya sehingga mereka tafsirkan tidak tepat sasaran, maka tangguhkan saja hingga Madinah menjadi tempat hijrah dan tempat yang aman, serta dipenuhi oleh sahabat-sahabat Rasulullah shallallahu 'alaihi wasallam dari muhajirin dan Anshar. Kemudian mereka menjaga saran-saranmu dan menafsirkannya sesuai tempatnya.\" Lantas Ibn Abbas berkata, \"Demi Allah, sungguh aku berdiri bersamanya di awal-awal aku berdiri bersamanya di Madinah Munawwarah.\" Ibn Abbas melanjutkan, \"Lantas kami tiba di Madinah, dan ia katakan, \"Allah telah mengutus Muhammad shallallahu 'alaihi wasallam dengan membawa kebenaran dan menurunkan al Kitab bersamanya, yang diantara ayat yang diturunkan adalah ayat rajam.\""},"6439":{"ar":"حَدَّثَنَا سُلَيْ��َانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ قَالَ كُنَّا عِنْدَ أَبِي هُرَيْرَةَوَعَلَيْهِ ثَوْبَانِ مُمَشَّقَانِ مِنْ كَتَّانٍ فَتَمَخَّطَ فَقَالَ بَخْ بَخْ أَبُو هُرَيْرَةَ يَتَمَخَّطُ فِي الْكَتَّانِ لَقَدْ رَأَيْتُنِي وَإِنِّي لَأَخِرُّ فِيمَا بَيْنَ مِنْبَرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى حُجْرَةِ عَائِشَةَ مَغْشِيًّا عَلَيَّ فَيَجِيءُ الْجَائِي فَيَضَعْ رِجْلَهُ عَلَى عُنُقِي وَيُرَى أَنِّي مَجْنُونٌ وَمَا بِي مِنْ جُنُونٍ مَا بِي إِلَّا الْجُوعُ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Muhammad] berkata, \"Pernah kami berada di sisi [Abu Hurairah] yang saat itu mengenakan dua kain kapas yang sudah rombeng (koyak), \"Bakh..bakh (ungkapan karena senang), Abu Hurairah berbajukan kain wool?\" padahal aku pernah tersungkur antara mimbar Rasulullah shallallahu 'alaihi wasallam hingga kamar Aisyah dengan setengah pingsan, lantas ada seseorang datang dan meletakkan kakinya di tengkuknya, terlihat aku seolah-olah gila, padahal aku tidak gila, hanya karena aku sangat kelaparan.\""},"6440":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَابِسٍ قَالَ سُئِلَ ابْنُ عَبَّاسٍأَشَهِدْتَ الْعِيدَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ وَلَوْلَا مَنْزِلَتِي مِنْهُ مَا شَهِدْتُهُ مِنْ الصِّغَرِ فَأَتَى الْعَلَمَ الَّذِي عِنْدَ دَارِ كَثِيرِ بْنِ الصَّلْتِ فَصَلَّى ثُمَّ خَطَبَ وَلَمْ يَذْكُرْ أَذَانًا وَلَا إِقَامَةً ثُمَّ أَمَرَ بِالصَّدَقَةِ فَجَعَلَ النِّسَاءُ يُشِرْنَ إِلَى آذَانِهِنَّ وَحُلُوقِهِنَّ فَأَمَرَ بِلَالًا فَأَتَاهُنَّ ثُمَّ رَجَعَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] dari [Abdurrahman bin Abbas] berkata, \" [Ibn Abbas] pernah ditanya 'Apakah engkau pernah menghadiri shalat 'ied bersama Rasulullah shallallahu 'alaihi wasallam? ' ia menjawab, 'Benar, kalaulah bukan karena kedudukanku di sisi beliau, sungguh aku tak mungkin bisa menghadirinya semenjak kecil. Beliau mendatangi 'alam (tanda batas shalat) di perkampungan Katsir bin Shalt, kemudian beliau shalat, lalu berkhutbah.\" -Ibnu Abbas tidak menyebut-nyebut adzan dan tidak pula iqamat- Kemudian beliau perintahkan untuk bersedekah, sehingga para wanita melepaskan anting-anting yang berada di telinga mereka dan kalung yang berada di leher mereka, sementara Bilal mendatangi mereka untuk mengambil barang-barang itu, kemudian ia kembali menemui nabi shallallahu 'alaihi wasallam.\""},"6441":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَأْتِي قُبَاءً مَاشِيًا وَرَاكِبًا","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Abdullah bin Dinar] dari [Ibn Umar] radliallahu 'anhua, bahwa Nabi shallallahu 'alaihi wasallam pernah mendatangi Quba dengan berjalan kaki dan berkendaraan.\" "},"6442":{"ar":"حَدَّثَنَا عُبَيْدُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْلِعَبْدِ اللَّهِ بْنِ الزُّبَيْرِ ادْفِنِّي مَعَ صَوَاحِبِي وَلَا تَدْفِنِّي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْبَيْتِ فَإِنِّي أَكْرَهُ أَنْ أُزَكَّى","id":"Telah menceritakan kepada kami ['Ubaid bin Ismail] telah menceritakan kepada kami [Abu Usamah] dari [Hisyam] dari [ayahnya] dari ['Aisyah] berkata kepada Abdullah bin Zubair, \"Kuburkanlah aku bersama-sama sahabatku, dan jangan kuburkan aku bersama nabi shallallahu 'alaihi wasallam di rumah, sebab aku tidak suka dikeramatkan.\""},"6443":{"ar":"وَعَنْ هِشَامٍ عَنْ أَبِيهِأَنَّ عُمَرَ أَرْسَلَ إِلَى عَائِشَةَ ائْذَنِي لِي أَنْ أُدْفَنَ مَعَ صَاحِبَيَّ فَقَالَتْ إِي وَاللَّهِ قَالَ وَكَانَ الرَّجُلُ إِذَا أَرْسَلَ إِلَيْهَا مِنْ الصَّحَابَةِ قَالَتْ لَا وَاللَّهِ لَا أُوثِرُهُمْ بِأَحَدٍ أَبَدًا","id":"Dan (masih dari jalur periwayatan yang sama dengan hadits sebelumnya) dari [Hisyam] dari [Ayahnya], bahwa Umar pernah mengutus utusan kepada ['Aisyah] yang isinya, \"Maaf, berilah aku ijin agar aku dikuburkan bersama dua sahabatku (Nabi dan Abu Bakar), padahal hari-hari sebelumnya jika ada sahabat laki-laki yang mengutus utusan kepada Aisyah (agar dikuburkan bersama nabi atau Abu bakar), 'Aisyah selalu menjawab \"TIDAK, demi Allah, selamanya aku sama sekali tidak akan memberi kesempatan kepada seorangpun.\""},"6444":{"ar":"حَدَّثَنَا أَيُّوبُ بْنُ سُلَيْمَانَ حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي أُوَيْسٍ عَنْ سُلَيْمَانَ بْنِ بِلَالٍ عَنْ صَالِحِ بْنِ كَيْسَانَ قَالَ ابْنُ شِهَابٍ أَخْبَرَنِي أَنَسُ بْنُ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي الْعَصْرَ فَيَأْتِي الْعَوَالِيَ وَالشَّمْسُ مُرْتَفِعَةٌوَزَادَ اللَّيْثُ عَنْ يُونُسَ وَبُعْدُ الْعَوَالِيَ أَرْبَعَةُ أَمْيَالٍ أَوْ ثَلَاثَةٌ","id":"Telah menceritakan kepada kami [Ayyub bin Sulaiman] telah menceritakan kepada kami [Abu Bakar bin Abu Uwais] dari [Sulaiman bin Bilal] dari [Shalih bin Kisan], [Ibn Syihab] berkata, [Anas bin Malik] mengabarkan kepadaku, bahwasanya Rasulullah shallallahu 'alaihi wasallam shalat 'ashar, (selesai shalat) beliau mendatangi 'Awali sementara matahari masih meninggi.\" Dan [Al Laits] menambahkan dari [Yunus] 'dan jarak 'Awali empat atau tiga mil.'"},"6445":{"ar":"حَدَّثَنَا عَمْرُو بْنُ زُرَارَةَ حَدَّثَنَا الْقَاسِمُ بْنُ مَالِكٍ عَنْ الْجُعَيْدِ سَمِعْتُ السَّائِبَ بْنَ يَزِيدَ يَقُولُكَانَ الصَّاعُ عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُدًّا وَثُلُثًا بِمُدِّكُمْ الْيَوْمَ وَقَدْ زِيدَ فِيهِ سَمِعَ الْقَاسِمُ بْنُ مَالِكٍ الْجُعَيْدَ","id":"Telah menceritakan kepada kami ['Amru bin Zurarah] telah menceritakan kepada kami [Alqasim bin Malik] dari [Al Ju'aid] aku mendengar [As Saib bin Yazid] berkata, \"Satu sha' di jaman Nabi shallallahu 'alaihi wasallam adalah satu mud lebih sepertiga (mud kalian) hari ini, dan bahkan terkadang ditambahi lagi.\" Alqasim bin Malik mendengar dari Ju'aid."},"6446":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّهُمَّ بَارِكْ لَهُمْ فِي مِكْيَالِهِمْ وَبَارِكْ لَهُمْ فِي صَاعِهِمْ وَمُدِّهِمْ يَعْنِي أَهْلَ الْمَدِينَةِ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas bin Malik], bahwa Rasulullah shallallahu 'alaihi wasallam pernah memanjatkan doa: \"Ya Allah, berilah barakah bagi mereka dalam takaran mereka, juga berkahilah mereka dalam sha' dan mud mereka, \" maksudnya bagi penduduk Madinah.\""},"6447":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَأَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي صَلَاةِ الْفَجْرِ وَرَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ قَالَ اللَّهُمَّ رَبَّنَا وَلَكَ الْحَمْدُ فِي الْأَخِيرَةِ ثُمَّ قَالَ اللَّهُمَّ الْعَنْ فُلَانًا وَفُلَانًا فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ لَيْسَ لَكَ مِنْ الْأَمْرِ شَيْءٌ أَوْ يَتُوبَ عَلَيْهِمْ أَوْ يُعَذِّبَهُمْ فَإِنَّهُمْ ظَالِمُونَ }","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Salim] dari [Ibn Umar] ia mendengar nabi shallallahu 'alaihi wasallam berdoa ketika shalat fajar dan ketika mengangkat kepalanya dari rukuk: 'ALLAAHUMMA RABBANAA WALAKAL HAMDU (Ya Allah rabb kami, bagi-Mu segala puji) ', itu beliau ucapkan pada rukuk terakhir. Kemudian beliau berdoa: 'ALLAAHUMMA IL 'AN FULAANAN WAFULAANAN (Ya Allah, laknatlah si A dan si B) '. Lantas Allah menurunkan ayat: '(Sama sekali engkau tidak mempunyai wewenang terhadap urusan mereka itu, Allah mengampuni mereka atau menyiksa mereka, sebab mereka adalah orang-orang yang zhalim) ' (Qs. Ali'Imran: 128)."},"6448":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ ح حَدَّثَنِي مُحَمَّدُ بْنُ سَلَامٍ أَخْبَرَنَا عَتَّابُ بْنُ بَشِيرٍ عَنْ إِسْحَاقَ عَنْ الزُّهْرِيِّ أَخْبَرَنِي عَلِيُّ بْنُ حُسَيْنٍ أَنَّ حُسَيْنَ بْنَ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُمَا أَخْبَرَهُ أَنَّ عَلِيَّ بْنَ أَبِي طَالِبٍ قَالَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَرَقَهُ وَفَاطِمَةَ عَلَيْهَا السَّلَام بِنْتَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُمْ أَلَا تُصَلُّونَ فَقَالَ عَلِيٌّ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّمَا أَنْفُسُنَا بِيَدِ اللَّهِ فَإِذَا شَاءَ أَنْ يَبْعَثَنَا بَعَثَنَا فَانْصَرَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ قَالَ لَهُ ذَلِكَ وَلَمْ يَرْجِعْ إِلَيْهِ شَيْئًا ثُمَّ سَمِعَهُ وَهُوَ مُدْبِرٌ يَضْرِبُ فَخِذَهُ وَهُوَ يَقُولُ{ وَكَانَ الْإِنْسَانُ أَكْثَرَ شَيْءٍ جَدَلًا }قَالَ أَبُو عَبْد اللَّهِ يُقَالُ مَا أَتَاكَ لَيْلًا فَهُوَ طَارِقٌ وَيُقَالُ{ الطَّارِقُ }النَّجْمُ وَ{ الثَّاقِبُ }الْمُضِيءُ يُقَالُ أَثْقِبْ نَارَكَ لِلْمُوقِدِ","id":"Telah menceritakan kepada kami [Abul Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Azzuhri]. (dalam jalur lain disebutkan) telah menceritakan kepadaku [Muhammad bin Salam] Telah mengabarkan kepada kami ['Attab bin Basyir] dari [Ishaq] dari [Azzuhri] telah mengabarkan kepadaku [Ali bin Husain] bahwa [Husain bin Ali] radliyallahu'anhuma mengabarkan kepadanya, bahwa [Ali bin Abu Thalib] berkata, \"Rasulullah Shallallahu'alaihiwasallam membangunkannya di malam hari, dan juga beliau bangunkan Fatimah binti Rasulullah Shallallahu'alaihiwasallam, beliau berkata kepada mereka: \"Tidak sebaiknyakah kalian mendirikan shalat? Kata Ali, kujawab \"Wahai Rasulullah, jiwa kita ada di tangan Arrahman, kalaulah Dia berkenan membangunkan kita niscaya Dia membangunkan.\" Lantas Rasulullah Shallallahu'alaihiwasallam pergi ketika Ali menjawab sedemikian ini, dan sama sekali tidak kembali lagi, kemudian Ali mendengar Nabi membaca sebuah ayat ketika kembali sambil menepuk pahanya, ayat yang beliau baca: '(Sungguh manusia itu makhluk yang suka membantah (QS. Al Kahfi; 54). Abu Abdullah berkata; apa saja yang datang kepadamu malam hari, diistilahkan dengan Ath thariq. Istilah Ath Thariq juga diperuntukan untuk bintang, sedang atsaqib maknanya yang bercahaya atau menyala, seperti perkataan atsqib naaroka (nyalakan apimu).\""},"6449":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ سَعِيدٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَبَيْنَا نَحْنُ فِي الْمَسْجِدِ خَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ انْطَلِقُوا إِلَى يَهُودَ فَخَرَجْنَا مَعَهُ حَتَّى جِئْنَا بَيْتَ الْمِدْرَاسِ فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَادَاهُمْ فَقَالَ يَا مَعْشَرَ يَهُودَ أَسْلِمُوا تَسْلَمُوا فَقَالُوا قَدْ بَلَّغْتَ يَا أَبَا الْقَاسِمِ قَالَ فَقَالَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَلِكَ أُرِيدُ أَسْلِمُوا تَسْلَمُوا فَقَالُوا قَدْ بَلَّغْتَ يَا أَبَا الْقَاسِمِ فَقَالَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَلِكَ أُرِيدُ ثُمَّ قَالَهَا الثَّالِثَةَ فَقَالَ اعْلَمُوا أَنَّمَا الْأَرْضُ لِلَّهِ وَرَسُولِهِ وَأَنِّي أُرِيدُ أَنْ أُجْلِيَكُمْ مِنْ هَذِهِ الْأَرْضِ فَمَنْ وَجَدَ مِنْكُمْ بِمَالِهِ شَيْئًا فَلْيَبِعْهُ وَإِلَّا فَاعْلَمُوا أَنَّمَا الْأَرْضُ لِلَّهِ وَرَسُولِهِ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al laits] dari [Sa'id] dari [ayahnya] dari [Abu Hurairah] berkata, ketika kami di sebuah masjid, Rasulullah Shallallahu'alaihiwasallam datang dan bersabda: 'Berangkatlah kalian menuju kaum yahudi.\" Maka kami berangkat bersama beliau hingga kami tiba di Baitul madras. Nabi shallallahu 'alaihi wasallam berdiri dan menyeru mereka seraya berkata: \"Wahai segenap yahudi, masuk Islamlah kalian niscaya kalian selamat.\" Mereka menjawab, 'Telah engkau sampaikan wahai Abul qasim.' Rasulullah Shallallahu'alaihiwasallam kembali menyeru mereka seraya berkata: 'Yang kuimpikan, masuk Islamlah kalian, niscaya kalian selamat.' Namun mereka menjawab sama, 'Telah engkau sampaikan wahai Abul qasim.' Rasulullah Shallallahu'alaihiwasallam kembali menyeru mereka: 'Yang saya inginkan ialah….dan seterusnya. (beliau ulang tiga kali), hingga kali keempat beliau sabdakan: 'Ketahuilah, bahwasanya bumi adalah milik Allah dan rasul-Nya, dan sungguh saya akan mengusir kalian dari bumi ini, maka barangsiapa diantara kalian bisa menemukan sesuatu dari hartanya, juallah, kalaulah tidak, ketahuilah bahwa bumi adalah milik Allah dan rasul-Nya.\""},"6450":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ مَنْصُورٍ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا الْأَعْمَشُ حَدَّثَنَا أَبُو صَالِحٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُجَاءُ بِنُوحٍ يَوْمَ الْقِيَامَةِ فَيُقَالُ لَهُ هَلْ بَلَّغْتَ فَيَقُولُ نَعَمْ يَا رَبِّ فَتُسْأَلُ أُمَّتُهُ هَلْ بَلَّغَكُمْ فَيَقُولُونَ مَا جَاءَنَا مِنْ نَذِيرٍ فَيَقُولُ مَنْ شُهُودُكَ فَيَقُولُ مُحَمَّدٌ وَأُمَّتُهُ فَيُجَاءُ بِكُمْ فَتَشْهَدُونَ ثُمَّ قَرَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ وَكَذَلِكَ جَعَلْنَاكُمْ أُمَّةً وَسَطًا }قَالَ عَدْلًا{ لِتَكُونُوا شُهَدَاءَ عَلَى النَّاسِ وَيَكُونَ الرَّسُولُ عَلَيْكُمْ شَهِيدًا }وَعَنْ جَعْفَرِ بْنِ عَوْنٍ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي صَالِحٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepada kami [Al A'masy] telah menceritakan kepada kami [Abu Shalih] dari [Abu Sa'id alkhudzri] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Nabi Nuh didatangkan pada hari kiamat lantas ditanya, 'Sudahkah kamu menyampaikan? ' ia menjawab, 'Benar ya Rabbi'. Ummatnya kemudian ditanya, 'Apakah dia memang benar telah menyampaikan kepada kalian? ' Mereka menjawab, 'Belum ada seorang pemberi peringatan kepada kita.' Lantas Allah bertanya lagi: 'Siapa yang menjadi saksimu? ' Nuh menjawab, 'Muhammad dan umatnya.' Lantas kalian didatangkan dan kalian bersaksi.\" Kemudian Rasulullah Shallallahu'alaihiwasallam membaca ayat: '(Dan demikianlah Kami jadikan kalian umat yang wasath) ' (Qs. Albaqarah 143). Kata Al A'masy, wasath artinya adil '(Agar kalian menjadi saksi atas semua manusia dan agar rasul sebagai saksi atas kalian) ' (Qs. Albaqarah 143). Dan dari [Ja'far bin Aun] telah menceritakan kepada kami [Al A'masy] dari [Abu Shalih] dari [Abu Sa'id alkhudzri] dari Nabi shallallahu 'alaihi wasallam dengan ini.\""},"6451":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ عَنْ أَخِيهِ عَنْ سُلَيْمَانَ بْنِ بِلَالٍ عَنْ عَبْدِ الْمَجِيدِ بْنِ سُهَيْلِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ أَنَّهُ سَمِعَ سَعِيدَ بْنَ الْمُسَيَّبِ يُحَدِّثُ أَنَّ أَبَا سَعِيدٍ الْخُدْرِيَّ وَأَبَا هُرَيْرَةَ حَدَّثَاهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ أَخَا بَنِي عَدِيٍّ الْأَنْصَارِيَّ وَاسْتَعْمَلَهُ عَلَى خَيْبَرَ فَقَدِمَ بِتَمْرٍ جَنِيبٍ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكُلُّ تَمْرِ خَيْبَرَ هَكَذَا قَالَ لَا وَاللَّهِ يَا رَسُولَ اللَّهِ إِنَّا لَنَشْتَرِي الصَّاعَ بِالصَّاعَيْنِ مِنْ الْجَمْعِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَفْعَلُوا وَلَكِنْ مِثْلًا بِمِثْلٍ أَوْ بِيعُوا هَذَا وَاشْتَرُوا بِثَمَنِهِ مِنْ هَذَا وَكَذَلِكَ الْمِيزَانُ","id":"Telah menceritakan kepada kami [Ismail] dari [saudaranya] dari [Sulaiman bin Bilal] dari [Abdul Majid bin Suhail bin Abdurrahman bin Auf] ia mendengar [Sa'id bin Musayyab] menceritakan bahwa [Abu Sa'id alkhudzri] dan [Abu Hurairah] menceritakan kepadanya, Rasulullah Shallallahu'alaihiwasallam mengutus saudara bani 'Adi Al anshari dan mempekerjakannya untuk mengelola kebun Khaibar, selanjutnya ia membawa kurma yang kualitasnya istimewa, maka Rasulullah Shallallahu'alaihiwasallam bertanya: 'Apa setiap kurma Khaibar seperti ini? ' Ia menjawab, 'Tidak, demi Allah ya Rasulullah, kami membeli satu sha' kurma ini dengan dua sha' kurma kami dari Jam' (Muzdalifah).' Maka Rasulullah Shallallahu'alaihiwasallam bersabda: \"Jangan seperti itu kau lakukan, namun jika kamu ingin menukar, tukarlah dengan takaran sama, atau jual dahulu kurmamu dan belilah kurma itu dengan uang hasil penjualanmu, demikian pula timbangan.\""},"6452":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ الْمُقْرِئُ الْمَكِّيُّ حَدَّثَنَا حَيْوَةُ بْنُ شُرَيْحٍ حَدَّثَنِي يَزِيدُ بْنُ عَبْدِ اللَّهِ بْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ بْنِ الْحَارِثِ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ أَبِي قَيْسٍ مَوْلَى عَمْرِو بْنِ الْعَاصِ عَنْ عَمْرِو بْنِ الْعَاصِ أَنَّهُسَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا حَكَمَ الْحَاكِمُ فَاجْتَهَدَ ثُمَّ أَصَابَ فَلَهُ أَجْرَانِ وَإِذَا حَكَمَ فَاجْتَهَدَ ثُمَّ أَخْطَأَ فَلَهُ أَجْرٌقَالَ فَحَدَّثْتُ بِهَذَا الْحَدِيثِ أَبَا بَكْرِ بْنَ عَمْرِو بْنِ حَزْمٍ فَقَالَ هَكَذَا حَدَّثَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ وَقَالَ عَبْدُ الْعَزِيزِ بْنُ الْمُطَّلِبِ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ أَبِي سَلَمَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Abdullah bin Yazid almuqri' almakki] telah menceritakan kepada kami [Haiwa bin Syuraikh] telah menceritakan kepadaku [Yazid bin Abdullah bin Al Had] dari [Muhammad bin Ibrahim bin Alharits] dari [Busr bin Sa'id] dari [Abu Qais] mantan budak Amru bin 'Ash, dari ['Amru bin 'ash] ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika seorang hakim mengadili dan berijtihad, kemudian ijtihadnya benar, maka ia mendapat dua pahala, dan jika seorang hakim berijtihad, lantas ijtihadnya salah (meleset), baginya dua pahala.\" Kata 'Amru, 'Maka aku ceritakan hadis ini kepada [Abu Bakar bin Amru bin Hazm], dan ia berkata, 'Beginilah [Abu Salamah bin Abdurrahman] mengabarkan kepadaku dari [Abu Hurairah]. Dan [Abdul 'Aziz bin Al Muththalib] dari [Abdullah bin Abu Bakar] dari [Abu Salamah] dari Nabi shallallahu 'alaihi wasallam Shallallahu'alaihiwa sallam semisalnya.\""},"6453":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ ابْنِ جُرَيْجٍ حَدَّثَنِي عَطَاءٌ عَنْ عُبَيْدِ بْنِ عُمَيْرٍ قَالَ اسْتَأْذَنَ أَبُو مُوسَىعَلَى عُمَرَ فَكَأَنَّهُ وَجَدَهُ مَشْغُولًا فَرَجَعَ فَقَالَ عُمَرُ أَلَمْ أَسْمَعْ صَوْتَ عَبْدِ اللَّهِ بْنِ قَيْسٍ ائْذَنُوا لَهُ فَدُعِيَ لَهُ فَقَالَ مَا حَمَلَكَ عَلَى مَا صَنَعْتَ فَقَالَ إِنَّا كُنَّا نُؤْمَرُ بِهَذَا قَالَ فَأْتِنِي عَلَى هَذَا بِبَيِّنَةٍ أَوْ لَأَفْعَلَنَّ بِكَ فَانْطَلَقَ إِلَى مَجْلِسٍ مِنْ الْأَنْصَارِ فَقَالُوا لَا يَشْهَدُ إِلَّا أَصَاغِرُنَا فَقَامَ أَبُو سَعِيدٍ الْخُدْرِيُّ فَقَالَ قَدْ كُنَّا نُؤْمَرُ بِهَذَا فَقَالَ عُمَرُ خَفِيَ عَلَيَّ هَذَا مِنْ أَمْرِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلْهَانِي الصَّفْقُ بِالْأَسْوَاقِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Ibnu Juraij] telah menceritakan kepadaku ['Atha] dari ['Ubaid bin Umair] berkata, \" [Abu Musa] meminta ijin Umar, lantas ia temukan seolah-olah Umar sangat sibuk sehingga Abu musa pulang. Maka Umar berkata, 'Tidakkah aku mendengar suara Abdullah bin Qais? Tolong berilah dia ijin (masuk).' Lantas Abdullah pun diundang. Kata Umar, 'Apa yang mendorongmu melakukan yang kau lakukan? ' Abdullah menjawab, 'Kami diperintahkan yang demikian.' Umar berkata, 'Berilah aku bukti atau aku akan mengerjaimu! ' Lantas Abdullah bertolak ke sebuah majlis anshar, lalu mereka katakan, 'Tidak ada yang bersaksi selain anak-anak muda kami! Lantas [Abu Sa'id alkhudzri] datang dan bersaksi, 'Kami diperintah demikian.' Lantas Umar berkata, 'Sayang, saya tidak mendapat penjelasan yang jelas dari tuntunan Nabi shallallahu 'alaihi wasallam dalam hal ini, aku dilalaikan oleh bisnisku di pasar.'"},"6454":{"ar":"حَدَّثَنَا عَلِيٌّ حَدَّثَنَا سُفْيَانُ حَدَّثَنِي الزُّهْرِيُّ أَنَّهُ سَمِعَهُ مِنَ الْأَعْرَجِ يَقُولُ أَخْبَرَنِي أَبُو هُرَيْرَةَ قَالَإِنَّكُمْ تَزْعُمُونَ أَنَّ أَبَا هُرَيْرَةَ يُكْثِرُ الْحَدِيثَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاللَّهُ الْمَوْعِدُ إِنِّي كُنْتُ امْرَأً مِسْكِينًا أَلْزَمُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى مِلْءِ بَطْنِي وَكَانَ الْمُهَاجِرُونَ يَشْغَلُهُمْ الصَّفْقُ بِالْأَسْوَاقِ وَكَانَتْ الْأَنْصَارُ يَشْغَلُهُمْ الْقِيَامُ عَلَى أَمْوَالِهِمْ فَشَهِدْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ يَوْمٍ وَقَالَ مَنْ يَبْسُطْ رِدَاءَهُ حَتَّى أَقْضِيَ مَقَالَتِي ثُمَّ يَقْبِضْهُ فَلَنْ يَنْسَى شَيْئًا سَمِعَهُ مِنِّي فَبَسَطْتُ بُرْدَةً كَانَتْ عَلَيَّ فَوَالَّذِي بَعَثَهُ بِالْحَقِّ مَا نَسِيتُ شَيْئًا سَمِعْتُهُ مِنْهُ","id":"Telah menceritakan kepada kami [Ali] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Azzuhri] ia mendengarnya dari [Al A'raj] berkata, [Abu Hurairah] mengabarkan kepadaku, ia berkata, \"Kalian beranggapan bahwa Abu hurairah (maksudnya dirinya sendiri) banyak meriwayatkan hadis dari Rasulullah Shallallahu'alaihiwasallam dan Allah sajalah yang memberi janji, aku adalah seorang miskin yang selalu menyertai Rasulullah Shallallahu'alaihiwasallam dengan perut cukup berisi makanan pokok saja, kaum muhajirin selalu disibukkan oleh perdagangan di pasar-pasar sedang orang anshar disibukan oleh pengelolaan hartanya, maka suatu hari kusaksikan Rasulullah Shallallahu'alaihiwasallam bersabda: 'Siapa yang mau membentangkan kainnya hingga aku menuntaskan ucapanku kemudian ia menggenggamnya dan tidak akan pernah lupa terhadap sesuatu yang ia dengarkan dariku? ' Spontan aku hamparkan kain yang ada padaku, Demi Dzat yang mengutusnya dengan kebenaran, aku tak pernah lagi melupakan suatupun yang aku dengar darinya.'"},"6455":{"ar":"حَدَّثَنَا حَمَّادُ بْنُ حُمَيْدٍ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ قَالَ رَأَيْتُ جَابِرَ بْنَ عَبْدِ اللَّهِيَحْلِفُ بِاللَّهِ أَنَّ ابْنَ الصَّائِدِ الدَّجَّالُ قُلْتُ تَحْلِفُ بِاللَّهِ قَالَ إِنِّي سَمِعْتُ عُمَرَ يَحْلِفُ عَلَى ذَلِكَ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يُنْكِرْهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Hammad bin Humaid] telah menceritakan kepada kami ['Ubaidullah bin Mu'adz] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Syu'bah] dari [Sa'd bin Ibrahim] dari [Muhammad bin Al Munkadir] berkata, 'Pernah aku melihat [Jabir bin Abdullah] bersumpah dengan nama Allah bahwa Ibnu Shaid adalah dajjal. Maka saya katakan, 'Engkau bersumpah atas nama Allah? ' ia jawab, 'Saya mendengar Umar bersumpah atas yang demikian disisi Nabi shallallahu 'alaihi wasallam, dan beliau Shallallahu'alaihiwasallam tidak memungkirinya.'"},"6456":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنِي مَالِكٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِي صَالِحٍ السَّمَّانِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْخَيْلُ لِثَلَاثَةٍ لِرَجُلٍ أَجْرٌ وَلِرَجُلٍ سِتْرٌ وَعَلَى رَجُلٍ وِزْرٌ فَأَمَّا الَّذِي لَهُ أَجْرٌ فَرَجُلٌ رَبَطَهَا فِي سَبِيلِ اللَّهِ فَأَطَالَ لَهَا فِي مَرْجٍ أَوْ رَوْضَةٍ فَمَا أَصَابَتْ فِي طِيَلِهَا ذَلِكَ مِنْ الْمَرْجِ أَوْ الرَّوْضَةِ كَانَ لَهُ حَسَنَاتٍ وَلَوْ أَنَّهَا قَطَعَتْ طِيَلَهَا فَاسْتَنَّتْ شَرَفًا أَوْ شَرَفَيْنِ كَانَتْ آثَارُهَا وَأَرْوَاثُهَا حَسَنَاتٍ لَهُ وَلَوْ أَنَّهَا مَرَّتْ بِنَهَرٍ فَشَرِبَتْ مِنْهُ وَلَمْ يُرِدْ أَنْ يَسْقِيَ بِهِ كَانَ ذَلِكَ حَسَنَاتٍ لَهُ وَهِيَ لِذَلِكَ الرَّجُلِ أَجْرٌ وَرَجُلٌ رَبَطَهَا تَغَنِّيًا وَتَعَفُّفًا وَلَمْ يَنْسَ حَقَّ اللَّهِ فِي رِقَابِهَا وَلَا ظُهُورِهَا فَهِيَ لَهُ سِتْرٌ وَرَجُلٌ رَبَطَهَا فَخْرًا وَرِيَاءً فَهِيَ عَلَى ذَلِكَ وِزْرٌ وَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْحُمُرِ قَالَ مَا أَنْزَلَ اللَّهُ عَلَيَّ فِيهَا إِلَّا هَذِهِ الْآيَةَ الْفَاذَّةَ الْجَامِعَةَ{ فَمَنْ يَعْمَلْ مِثْقَالَ ذَرَّةٍ خَيْرًا يَرَهُ وَمَنْ يَعْمَلْ مِثْقَالَ ذَرَّةٍ شَرًّا يَرَهُ }","id":"Telah menceritakan kepada kami [Ismail] telah menceritakan kepadaku [Malik] dari [Zaid bin Aslam] dari [Abu Shalih assiman] dari [Abu Hurairah] radliyallahu'anhu, bahwa Rasulullah Shallallahu'alaihiwasallam berkata: 'Kuda itu bagi tiga orang; bagi orang pertama mendatangkan pahala, bagi orang kedua sebagai penutup (penyelesaian, solusi), dan bagi orang ketiga mendatangkan dosa. Adapun kuda yang mendatang pahala adalah seseorang yang menambatkan kudanya di jalan Allah, lantas ia gembalakan kudanya di rerumputan luas atau kebun, maka segala yang dimakan kuda itu di padang gembalaan, baik kebun atau rerumputan luas selain tercatat sebagai kebaikan baginya, dan sekiranya kuda itu mengarungi padang gembalaan, lantas dia melangkah satu atau dua langkah, maka bekas dan kotorannya juga terhitung kebaikan baginya, dan sekiranya kuda itu melewati sungai dan meminumnya, padahal si pemilik tidak berniat memberinya minuman, maka itu terhitung kebaikan baginya, kesemuanya itu terhitung ganjaran baginya. Kuda kedua, adalah seseorang yang mengikatnya untuk mencari penghasilan dan untuk menjaga kehormatan diri, sedang ia tidak melupakan hak Allah terhadap ikatannya dan tidak pula terhadap punggungnya, maka kuda itu sebagai penyelesaian baginya. Adapun kuda ketiga adalah, seseorang yang mengikatnya untuk sekedar kebanggaan dan pamer, maka itu adalah bosa baginya. Dan Rasulullah Shallallahu'alaihiwasallam pernah ditanya tentang keledai. Maka beliau hanya menjawab: 'Allah tidak menurunkan kepadaku tentangnya selain satu ayat yang ringkas ini: '(Barangsiapa yang beramal kebaikan seberat biji atom, maka Allah akan melihatnya, sebaliknya barangsiapa yang beramal seberat biji atom keburukan, pasti ia melihatnya) ' (Qs. Al Zalzalah: 7-8)."},"6457":{"ar":"حَدَّثَنَا يَحْيَى حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ مَنْصُورِ بْنِ صَفِيَّةَ عَنْ أُمِّهِ عَنْ عَائِشَةَ أَنَّ امْرَأَةً سَأَلَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و حَدَّثَنَا مُحَمَّدٌ هُوَ ابْنُ عُقْبَةَ حَدَّثَنَا الْفُضَيْلُ بْنُ سُلَيْمَانَ النُّمَيْرِيُّ الْبَصْرِيُّ حَدَّثَنَا مَنْصُورُ بْنُ عَبْدِ الرَّحْمَنِ ابْنُ شَيْبَةَ حَدَّثَتْنِي أُمِّي عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ امْرَأَةً سَأَلَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْحَيْضِ كَيْفَ تَغْتَسِلُ مِنْهُ قَالَ تَأْخُذِينَ فِرْصَةً مُمَسَّكَةً فَتَوَضَّئِينَ بِهَا قَالَتْ كَيْفَ أَتَوَضَّأُ بِهَا يَا رَسُولَ اللَّهِ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّئِي قَالَتْ كَيْفَ أَتَوَضَّأُ بِهَا يَا رَسُولَ اللَّهِ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّئِينَ بِهَا قَالَتْ عَائِشَةُ فَعَرَفْتُ الَّذِي يُرِيدُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَذَبْتُهَا إِلَيَّ فَعَلَّمْتُهَا","id":"Telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Ibnu Uyainah] dari [Manshur bin Shafiyah] dari [Ibunya] dari [Aisyah] bahwa, ada seorang wanita bertanya Nabi shallallahu 'alaihi wasallam Shallallahu'alaihiwasallam -lewat jalur periwayatan lain-Dan telah menceritakan kepada kami [Muhammad] -yaitu Ibnu Uqbah- telah menceritakan kepada kami [Al Fudlail bin Sulaiman An Numairi Al Bashri] telah menceritakan kepada kami [Manshur bin Abdurrahman Ibn Syaibah] telah menceritakan kepadaku [Ibuku] dari [Aisyah] radliyallahu'anha, ada seorang wanita bertanya Nabi shallallahu 'alaihi wasallam tentang haidl, bagaimana ia harus mandi karena haidl? Nabi menjawab: 'Hendaklah kau ambil sepotong kapas, lantas kau berwudlu dengannya.' Wanita itu bertanya, 'Bagaimana aku berwudlu dengan kapas itu wahai Rasulullah? ' Nabi shallallahu 'alaihi wasallam menjawab: 'Berwudlulah.' Si wanita terus bertanya, 'Bagaimana aku harus berwudlu dengan kapas itu ya Rasulullah? Nabi shallallahu 'alaihi wasallam menjawab: 'Berwudlulah.' Si wanita terus bertanya, 'Bagaimana aku harus berwudlu dengan kapas itu ya Rasulullah? ' Maka Aisyah pun berkata, 'Aku mengerti yang Rasulullah maksudkan, sehingga kutarik wanita itu dan kuajari.'"},"6458":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ أُمَّ حُفَيْدٍ بِنْتَ الْحَارِثِ بْنِ حَزْنٍ أَهْدَتْ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمْنًا وَأَقِطًا وَأَضُبًّا فَدَعَا بِهِنَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأُكِلْنَ عَلَى مَائِدَتِهِ فَتَرَكَهُنَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَالْمُتَقَذِّرِ لَهُنَّ وَلَوْ كُنَّ حَرَامًا مَا أُكِلْنَ عَلَى مَائِدَتِهِ وَلَا أَمَرَ بِأَكْلِهِنَّ","id":"Telah menceritakan kepada kami [Musa bin Ismail] telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibn Abbas], bahwa Ummu Hufaid binti Al Harits bin Hazin menghadiahi Nabi shallallahu 'alaihi wasallam berupa minyak samin, keju dan daging biawak. Kemudian Nabi shallallahu 'alaihi wasallam mengundang para sahabat untuk menyantap makanan itu, dan makanan itu disantap diatas meja makannya, sedang Nabi shallallahu 'alaihi wasallam meninggalkannya seolah-olah merasa jijik, kalaulah makanan itu diharamkan, niscaya tidak dimakan diatas meja makannya dan tidak pula menyuruh untuk menyantapnya.\""},"6459":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عَطَاءُ بْنُ أَبِي رَبَاحٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَكَلَ ثُومًا أَوْ بَصَلًا فَلْيَعْتَزِلْنَا أَوْ لِيَعْتَزِلْ مَسْجِدَنَا وَلْيَقْعُدْ فِي بَيْتِهِ وَإِنَّهُ أُتِيَ بِبَدْرٍ قَالَ ابْنُ وَهْبٍ يَعْنِي طَبَقًا فِيهِ خَضِرَاتٌ مِنْ بُقُولٍ فَوَجَدَ لَهَا رِيحًا فَسَأَلَ عَنْهَا فَأُخْبِرَ بِمَا فِيهَا مِنْ الْبُقُولِ فَقَالَ قَرِّبُوهَا فَقَرَّبُوهَا إِلَى بَعْضِ أَصْحَابِهِ كَانَ مَعَهُ فَلَمَّا رَآهُ كَرِهَ أَكْلَهَا قَالَ كُلْ فَإِنِّي أُنَاجِي مَنْ لَا تُنَاجِيوَقَالَ ابْنُ عُفَيْرٍ عَنْ ابْنِ وَهْبٍ بِقِدْرٍ فِيهِ خَضِرَاتٌ وَلَمْ يَذْكُرِ اللَّيْثُ وَأَبُو صَفْوَانَ عَنْ يُونُسَ قِصَّةَ الْقِدْرِ فَلَا أَدْرِي هُوَ مِنْ قَوْلِ الزُّهْرِيِّ أَوْ فِي الْحَدِيثِ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami [Ibn Wahb] telah menceritakan kepadaku [Yunus] dari [Ibn Syihab] telah menceritakan kepadaku ['Atha bin Abu Rabah] dari [Jabir bin Abdullah] berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa makan bawang merah atau bawang putih, hendaklah menyingkir dari kami --atau dengan redaksi 'agar dia menyingkiri- masjid kami, dan duduklah di rumahnya.\" Pernah dalam perang badar beliau diberi hidangan yang berisi sayur-mayur, berupa kubis, dan beliau temukan mempunyai bau. Maka Nabi menanyakan perihal sayuran itu, dan dikabarkan bahwa sayuran itu diantaranya ada kubis. Beliau lantas bersabda: \"Coba tolong dekatkan!\" Lantas mereka pun mendekatkannya kepada beberapa sahabatnya yang ikut bersama beliau. Tatkala beliau melihatnya, beliau merasa risih memakannya dan bersabda: \"Saya menjauhi santapan yang kalian tidak menjauhinya.\" Sedang [Ibnu Ufair] dari [Ibnu Wahb] berkata dengan redaksi 'didatangkan kepada beliau periuk berisi kubis', dan [Al Laits] dan [Abu Shafwan] tidak menyebutkan dari [Yunus] tentang kisah periuk, maka aku tidak tahu apakah itu ucapan [Azzuhri] atau termasuk bagian hadis.\""},"6460":{"ar":"حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ سَعْدِ بْنِ إِبْرَاهِيمَ حَدَّثَنَا أَبِي وَعَمِّي قَالَا حَدَّثَنَا أَبِي عَنْ أَبِيهِ أَخْبَرَنِي مُحَمَّدُ بْنُ جُبَيْرٍ أَنَّ أَبَاهُ جُبَيْرَ بْنَ مُطْعِمٍ أَخْبَرَهُأَنَّ امْرَأَةً أَتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَلَّمَتْهُ فِي شَيْءٍ فَأَمَرَهَا بِأَمْرٍ فَقَالَتْ أَرَأَيْتَ يَا رَسُولَ اللَّهِ إِنْ لَمْ أَجِدْكَ قَالَ إِنْ لَمْ تَجِدِينِي فَأْتِي أَبَا بَكْرٍزَادَ لَنَا الْحُمَيْدِيُّ عَنْ إِبْرَاهِيمَ بْنِ سَعْدٍ كَأَنَّهَا تَعْنِي الْمَوْتَ","id":"Telah menceritakan kepadaku [Ubaidullah bin Sa'd bin Ibrahim] telah menceritakan kepada kami [Ayahku] dan [pamanku] berkata telah menceritakan kepada kami [Ayahku] dari [Ayahnya] telah menceritakan kepadaku [Muhammad bin Jubair] bahwa bapaknya [Jubair bin Muth'im] mengabarkan kepadanya, bahwa seorang wanita menemui Rasulullah Shallallahu'alaihiwasallam dan mengajak beliau bicara tentang sesuatu. Lantas si wanita tadi berkata, 'Menurut anda bagaimana ya rasulullah sekiranya aku datang lagi namun tidak bertemu dengan baginda? ' Nabi menjawab: \"Kalaulah engkau tidak menemuiku, temuilah Abu Bakar.\" [Al Humaidi] menambahkan untuk kami dari [Ibrahim bin sa'd] yang wanita maksudkan, adalah, sekiranya ia temukan nabi telah wafat.\""},"6461":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ أَخْبَرَنَا عَلِيُّ بْنُ الْمُبَارَكِ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ أَهْلُ الْكِتَابِ يَقْرَءُونَ التَّوْرَاةَ بِالْعِبْرَانِيَّةِ وَيُفَسِّرُونَهَا بِالْعَرَبِيَّةِ لِأَهْلِ الْإِسْلَامِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُصَدِّقُوا أَهْلَ الْكِتَابِ وَلَا تُكَذِّبُوهُمْ وَقُولُوا آمَنَّا بِاللَّهِ وَمَا أُنْزِلَ إِلَيْنَا وَمَا أُنْزِلَ إِلَيْكُمْ الْآيَةَ","id":"Telah menceritakan kepadaku [Muhammad bin Basyar] telah menceritakan kepada kami [Usman bin Umar] telah mengabarkan kepada kami [Ali bin Al Mubarak] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Abu Hurairah] berkata, 'Ahli kitab membaca Taurat dengan bahasa ibrani dan menafsirkannya dengan bahasa arab untuk pemeluk Islam! Spontan Rasulullah Shallallahu'alaihiwasallam bersabda: \"Jangan kalian benarkan ahli kitab, dan jangan pula kalian mendustakannya, dan katakan saja '(Kami beriman kepada Allah, dan apa yang diturunkan kepada kami dan yang diturunkan kepadamu) '.\""},"6462":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا إِبْرَاهِيمُ أَخْبَرَنَا ابْنُ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ أَنَّ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَيْفَ تَسْأَلُونَ أَهْلَ الْكِتَابِ عَنْ شَيْءٍ وَكِتَابُكُمْ الَّذِي أُنْزِلَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحْدَثُ تَقْرَءُونَهُ مَحْضًا لَمْ يُشَبْ وَقَدْ حَدَّثَكُمْ أَنَّ أَهْلَ الْكِتَابِ بَدَّلُوا كِتَابَ اللَّهِ وَغَيَّرُوهُ وَكَتَبُوا بِأَيْدِيهِمْ الْكِتَابَ وَقَالُوا هُوَ مِنْ عِنْدِ اللَّهِ لِيَشْتَرُوا بِهِ ثَمَنًا قَلِيلًا أَلَا يَنْهَاكُمْ مَا جَاءَكُمْ مِنْ الْعِلْمِ عَنْ مَسْأَلَتِهِمْ لَا وَاللَّهِ مَا رَأَيْنَا مِنْهُمْ رَجُلًا يَسْأَلُكُمْ عَنْ الَّذِي أُنْزِلَ عَلَيْكُمْ","id":"Telah menceritakan kepada kami [Musa bin Ismail] telah menceritakan kepada kami [Ibrahim] telah mengabarkan kepada kami [Ibn Syihab] dari ['Ubaidullah bin Abdullah] bahwa [Ibn Abbas] radliyallahu'anhuma berkata, \"Bagaimana kalian bertanya ahli kitab padahal kitab kalian yang diturunkan kepada Rasulullah shallallahu 'alaihi wasallam lebih baru kemurniannya dan belum terkotori? Sedang ahlu kitab menceritakan kepada kalian dengan mengubah-ubah kitabullah dan menggantinya, dan mereka tulis alkitab dengan tangannya dan mereka katakan, 'Ini dari sisi Allah' untuk mereka tukar dengan harga yang sedikit, tidak sebaiknyakah ilmu yang yang kalian miliki mencegah kalian dari bertanya kepada mereka? Tidak, demi Allah, takkan kulihat lagi seseorang diantara mereka bertanya kalian tentang yang diturunkan kepada kalian.'"},"6463":{"ar":"حَدَّثَنَا إِسْحَاقُ أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سَلَّامِ بْنِ أَبِي مُطِيعٍ عَنْ أَبِي عِمْرَانَ الْجَوْنِيِّ عَنْ جُنْدَبِ بْنِ عَبْدِ اللَّهِ الْبَجَلِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَءُوا الْقُرْآنَ مَا ائْتَلَفَتْ قُلُوبُكُمْ فَإِذَا اخْتَلَفْتُمْ فَقُومُوا عَنْهُقَالَ أَبُو عَبْد اللَّهِ سَمِعَ عَبْدُ الرَّحْمَنِ سَلَّامًا","id":"Telah menceritakan kepada kami [Ishaq] Telah mengabarkan kepada kami [Abdurrahman bin Mahdi] dari [Sallam bin Abu Muthi'] dari [Abu'Imran Al Jauni] dari [Jundab bin Abdullah Al Bajali] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bacalah alquran selama menjadikan hati kalian bersatu padu, namun jika kalian berselisih, tinggalkanlah.\" Abu Abdullah berkata, 'Abdurrahman mendengar Sallam (bukan sekedar dari).'"},"6464":{"ar":"حَدَّثَنَا إِسْحَاقُ أَخْبَرَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا أَبُو عِمْرَانَ الْجَوْنِيُّ عَنْ جُنْدَبِ بْنِ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اقْرَءُوا الْقُرْآنَ مَا ائْتَلَفَتْ عَلَيْهِ قُلُوبُكُمْ فَإِذَا اخْتَلَفْتُمْ فَقُومُوا عَنْهُقَالَ أَبُو عَبْد اللَّهِ وَقَالَ يَزِيدُ بْنُ هَارُونَ عَنْ هَارُونَ الْأَعْوَرِ حَدَّثَنَا أَبُو عِمْرَانَ عَنْ جُنْدَبٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ishaq] telah mengabarkan kepada kami [Abdushshamad] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Abu 'Imran Al Jauni] dari [Jundab bin Abdullah] bahwa Rasulullah Shallallahu'alaihiwasallam bersabda: \"Bacalah alquran, selama menjadikan hati kalian bersatu padu, namun jika kalian berselisih, tinggalkanlah.\" Abu Abdullah berkata, [Yazid bin harun] berkata dari [Harun Al Al'war] telah menceritakan kepada kami [Abu Imran] dari [Jundab] dari Nabi shallallahu 'alaihi wasallam.\""},"6465":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامٌ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا حُضِرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَفِي الْبَيْتِ رِجَالٌ فِيهِمْ عُمَرُ بْنُ الْخَطَّابِ قَالَ هَلُمَّ أَكْتُبْ لَكُمْ كِتَابًا لَنْ تَضِلُّوا بَعْدَهُ قَالَ عُمَرُ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَلَبَهُ الْوَجَعُ وَعِنْدَكُمْ الْقُرْآنُ فَحَسْبُنَا كِتَابُ اللَّهِ وَاخْتَلَفَ أَهْلُ الْبَيْتِ وَاخْتَصَمُوا فَمِنْهُمْ مَنْ يَقُولُ قَرِّبُوا يَكْتُبْ لَكُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كِتَابًا لَنْ تَضِلُّوا بَعْدَهُ وَمِنْهُمْ مَنْ يَقُولُ مَا قَالَ عُمَرُ فَلَمَّا أَكْثَرُوا اللَّغَطَ وَالِاخْتِلَافَ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قُومُوا عَنِّي قَالَ عُبَيْدُ اللَّهِ فَكَانَ ابْنُ عَبَّاسٍ يَقُولُ إِنَّ الرَّزِيَّةَ كُلَّ الرَّزِيَّةِ مَا حَالَ بَيْنَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبَيْنَ أَنْ يَكْتُبَ لَهُمْ ذَلِكَ الْكِتَابَ مِنْ اخْ��ِلَافِهِمْ وَلَغَطِهِمْ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] telah mengabarkan kepada kami [Hisyam] dari [Ma'mar] dari [Azzuhri] dari ['Ubaidullah bin Abdullah] dari [Ibn Abbas] berkata, \"Dikala Nabi shallallahu 'alaihi wasallam menjelang wafat, yang ketika itu di rumah nabi ada beberapa pemuka yang diantaranya Ummar bin Khattab, beliau berkata: 'Kesinilah, saya tuliskan untuk kalian tulisan yang sekali-kali kalian tidak bisa sesat selama-lamanya.' Umar berkata, 'Nabi shallallahu 'alaihi wasallam menderita kesakitan dan di sisi kalian ada alquran, maka cukuplah bagi kita kitabullah.' Ahlul bait menjadi berselisih dan bersengketa, di antaranya ada yang berkata 'Tolong kalian mendekatlah sehingga Rasulullah Shallallahu'alaihiwasallam bisa menuliskan tulisan untuk kalian yang sekali-kali kalian tak akan tersesat selama-lamanya.' Di antara mereka ada yang berpendapat sebagaimana ucapan Umar. Tatkala suara mereka semakin gaduh dan perselisihan semakin kencang di sisi Nabi shallallahu 'alaihi wasallam, Nabi berkata: 'Menyingkirlah kalian dariku! ' Ubaidullah berkata, 'Ibn Abbas berkata, 'Bencana dari segala bencana adalah yang menghalangi Rasulullah Shallallahu'alaihiwasallam untuk menulis catatan bagi mereka, karena mereka berselisih dan membuat kegaduhan.'"},"6466":{"ar":"حَدَّثَنَا الْمَكِّيُّ بْنُ إِبْرَاهِيمَ عَنْ ابْنِ جُرَيْجٍ قَالَ عَطَاءٌ قَالَ جَابِرٌ قَالَ أَبُو عَبْد اللَّهِ وَقَالَ مُحَمَّدُ بْنُ بَكْرٍ البُرْسَانِيُّ حَدَّثَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي عَطَاءٌ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِفِي أُنَاسٍ مَعَهُ قَالَ أَهْلَلْنَا أَصْحَابَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْحَجِّ خَالِصًا لَيْسَ مَعَهُ عُمْرَةٌ قَالَ عَطَاءٌ قَالَ جَابِرٌ فَقَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صُبْحَ رَابِعَةٍ مَضَتْ مِنْ ذِي الْحِجَّةِ فَلَمَّا قَدِمْنَا أَمَرَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَحِلَّ وَقَالَ أَحِلُّوا وَأَصِيبُوا مِنْ النِّسَاءِ قَالَ عَطَاءٌ قَالَ جَابِرٌ وَلَمْ يَعْزِمْ عَلَيْهِمْ وَلَكِنْ أَحَلَّهُنَّ لَهُمْ فَبَلَغَهُ أَنَّا نَقُولُ لَمَّا لَمْ يَكُنْ بَيْنَنَا وَبَيْنَ عَرَفَةَ إِلَّا خَمْسٌ أَمَرَنَا أَنْ نَحِلَّ إِلَى نِسَائِنَا فَنَأْتِي عَرَفَةَ تَقْطُرُ مَذَاكِيرُنَا الْمَذْيَ قَالَ وَيَقُولُ جَابِرٌ بِيَدِهِ هَكَذَا وَحَرَّكَهَا فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ قَدْ عَلِمْتُمْ أَنِّي أَتْقَاكُمْ لِلَّهِ وَأَصْدَقُكُمْ وَأَبَرُّكُمْ وَلَوْلَا هَدْيِي لَحَلَلْتُ كَمَا تَحِلُّونَ فَحِلُّوا فَلَوْ اسْتَقْبَلْتُ مِنْ أَمْرِي مَا اسْتَدْبَرْتُ مَا أَهْدَيْتُ فَحَلَلْنَا وَسَمِعْنَا وَأَطَعْنَا","id":"Telah menceritakan kepada kami [Al Makki bin Ibrahim] dari [Ibn Juraij], ['Atha'] berkata, [Jabir] berkata, Abu Abdullah berkata, [Muhammad bin bakar Al Bursani] berkata, telah menceritakan kepada kami [Ibn Juraij] berkata, telah mengabarkan kepadaku ['Atha'] aku mendengar [Jabir bin Abdullah] di tengah-tenghah manusia yang bersamanya berkata, 'Kami para sahabat Rasulullah Shallallahu'alaihiwasallam bertalbiyah dan berniyat haji semata tanpa disertai Umrah.' Kata 'Atha, \"Jabir berkata, \"Lantas Nabi shallallahu 'alaihi wasallam tiba pada waktu subuh hari keempat bulan Dzulhijjah, tatkala kami tiba, Rasulullah Shallallahu'alaihiwasallam memerintahkan kami untuk bertahallul. Beliau sabdakan: 'Bertahallullah kalian, dan gilirlah isteri-isteri kalian! 'Atha berkata, \"Jabir berkata, \"Nabi tidak mewajibkan atas mereka, hanya menghalalkan isteri-isteri itu untuk dikumpuli, kemudian Jabir pun mengabarkannya. Kami katakan, ketika itu jarak antara kami dan Arafah selain hanya lima, dan beliau perintahkan kami untuk bertahallul hingga isteri-isteri kami, lantas kami datangi Arafah sedang kemaluan kami meneteskan madzi.' Kata 'Atha, \"Jabir berkata, 'Demikian' sambil ia gerakkan tangannya. Lantas Rasulullah Shallallahu'alaihiwasallam berdiri dan bersabda: 'Kalian tahu bahwa aku adalah orang yang paling bertakwa diantara kalian dan paling jujur, paling baik, kalaulah bukan karena hewan sembelihanku, niscaya aku telah bertahallul sebagaimana kalian lakukan, maka bertahallullah kalian, kalaulah aku bisa mengulang kembali kejadian yang telah lewat, niscaya aku tidak membawa sembelihan.' Kami pun bertahallul, mendengar dan taat.\""},"6467":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ الْحُسَيْنِ عَنْ ابْنِ بُرَيْدَةَ حَدَّثَنِي عَبْدُ اللَّهِ الْمُزَنِيُّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صَلُّوا قَبْلَ صَلَاةِ الْمَغْرِبِ قَالَ فِي الثَّالِثَةِ لِمَنْ شَاءَ كَرَاهِيَةَ أَنْ يَتَّخِذَهَا النَّاسُ سُنَّةً","id":"Telah menceritakan kepada kami [Abu Ma'mar] telah menceritakan kepada kami [Abdul Warits] dari [Al Husain] dari [Ibn Buraidah] telah menceritakan kepadaku [Abdullah Al Muzanni] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Shalatlah kalian sebelum maghrib, shalatlah kalian sebelum maghrib, \" pada kali ketiga beliau katakan: \"Bagi siapa yang ingin, \" yang demikian karena beliau khawatir jangan-jangan manusia menjadikannya sunnah.\""},"6468":{"ar":"حَدَّثَنَا الْأُوَيْسِيُّ عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ حَدَّثَنِي عُرْوَةُ وَابْنُ الْمُسَيَّبِ وَعَلْقَمَةُ بْنُ وَقَّاصٍ وَعُبَيْدُ اللَّهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاحِينَ قَالَ لَهَا أَهْلُ الْإِفْكِ مَا قَالُوا قَالَتْ وَدَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلِيَّ بْنَ أَبِي طَالِبٍ وَأُسَامَةَ بْنَ زَيْدٍ رَضِيَ اللَّهُ عَنْهُمْ حِينَ اسْتَلْبَثَ الْوَحْيُ يَسْأَلُهُمَا وَهُوَ يَسْتَشِيرُهُمَا فِي فِرَاقِ أَهْلِهِ فَأَمَّا أُسَامَةُ فَأَشَارَ بِالَّذِي يَعْلَمُ مِنْ بَرَاءَةِ أَهْلِهِ وَأَمَّا عَلِيٌّ فَقَالَ لَمْ يُضَيِّقْ اللَّهُ عَلَيْكَ وَالنِّسَاءُ سِوَاهَا كَثِيرٌ وَسَلْ الْجَارِيَةَ تَصْدُقْكَ فَقَالَ هَلْ رَأَيْتِ مِنْ شَيْءٍ يَرِيبُكِ قَالَتْ مَا رَأَيْتُ أَمْرًا أَكْثَرَ مِنْ أَنَّهَا جَارِيَةٌ حَدِيثَةُ السِّنِّ تَنَامُ عَنْ عَجِينِ أَهْلِهَا فَتَأْتِي الدَّاجِنُ فَتَأْكُلُهُ فَقَامَ عَلَى الْمِنْبَرِ فَقَالَ يَا مَعْشَرَ الْمُسْلِمِينَ مَنْ يَعْذِرُنِي مِنْ رَجُلٍ بَلَغَنِي أَذَاهُ فِي أَهْلِي وَاللَّهِ مَا عَلِمْتُ عَلَى أَهْلِي إِلَّا خَيْرًا فَذَكَرَ بَرَاءَةَ عَائِشَةَوَقَالَ أَبُو أُسَامَةَ عَنْ هِشَامٍ","id":"Telah menceritakan kepada kami [Al Uwaisi Abdul Aziz bin Abdullah] telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Sahlih] dari [Ibn Syihab] telah menceritakan kepadaku ['Urwah] dan [Ibnul Musayyab] dan [Alqamah bin Waqqash] dan ['Ubaidullah] dari ['Aisyah] radliyallahu'anha, bahwa ketika orang-orang yang menyebarkan berita bohong melakukan aksinya, Aisyah berkata, \"Rasulullah Shallallahu'alaihiwasallam lantas memanggil Ali bin Abu Thalib dan Usamah bin Yazid radliyallahu'anhum, yakni saat wahyu belum turun, beliau menanyai dan meminta saran keduanya perihal perceraian terhadap isterinya. Adapun Usamah bin Zaid, ia memberi saran sejauh yang ia ketahui bahwa Aisyah terlepas diri dari apa yang mereka tuduhkan, adapun Ali bin Abu Thalib berkata, 'Allah tak bakalan menyesakkan dadamu, wanita selainnya juga masih banyak, dan tanyailah pembantu yang bisa jadi ia membenarkanmu.' Nabi bertanya kepada hamba sahaya tadi: \"Pernahkah kau lihat sesuatu yang menjadikanmu ragu terhadap diri Aisyah?\" hamba sahaya tadi menjawab, \"Belum pernah kulihat sesuatu yang kurang pada diri Aisyah selain tak lebih ketika ia masih masih belia, ia ketiduran dari adonan masakan keluarganya sehingga datang ternak yang kemudian menyantapnya.' Lantas Nabi berdiri di atas minbar dan berkata: \"Wahai segenap muslimin, siapa yang bisa memberiku alasan terhadap seseorang yang gangguannya terhadap isteriku telah kudengar? Demi Allah, aku tak tahu terhadap isteriku selain kebaikan semata, \" lantas beliau sebutkan kesucian Aisyah. Dan [Abu Usamah] berkata 'dari [Hisyam.] "},"6469":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ حَرْبٍ حَدَّثَنَا يَحْيَى بْنُ أَبِي زَكَرِيَّاءَ الْغَسَّانِيُّ عَنْ هِشَامٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطَبَ النَّاسَ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ وَقَالَ مَا تُشِيرُونَ عَلَيَّ فِي قَوْمٍ يَسُبُّونَ أَهْلِي مَا عَلِمْتُ عَلَيْهِمْ مِنْ سُوءٍ قَطُّ وَعَنْ عُرْوَةَ قَالَ لَمَّا أُخْبِرَتْ عَائِشَةُ بِالْأَمْرِ قَالَتْ يَا رَسُولَ اللَّهِ أَتَأْذَنُ لِي أَنْ أَنْطَلِقَ إِلَى أَهْلِي فَأَذِنَ لَهَا وَأَرْسَلَ مَعَهَا الْغُلَامَ وَقَالَ رَجُلٌ مِنْ الْأَنْصَارِ سُبْحَانَكَ{ مَا يَكُونُ لَنَا أَنْ نَتَكَلَّمَ بِهَذَا سُبْحَانَكَ هَذَا بُهْتَانٌ عَظِيمٌ }","id":"Telah menceritakan kepadaku [Muhammad bin Harb] telah menceritakan kepada kami [Yahya bin Abu Zakariya Al Ghassani] dari [Hisyam] dari ['Urwah] dari ['Aisyah] bahwa Rasulullah Shallallahu'alaihiwasallam berpidato kepada manusia, lantas memuja dan memuji Allah dan bersabda: \"Kalian tidak bisa memberiku alasan terhadap seseorang yang mencela isteriku, setahuku tak ada keburukan pada mereka sama sekali.\" Dan 'Urwah berkata, 'Dikala 'Aisyah dikabarkan selingkuh, ia berkata, 'Wahai Rasulullah, bersediakah engkau jika aku kembali kepada keluargaku? Maka Rasul memberinya ijin dan mengutus pelayan untuk menemaninya. Dan seorang laki-laki anshar berkata, 'Maha suci Engkau, tak sepantasnya kami berkata yang sedemikian ini. Maha suci Engkau, ini adalah kebohongan yang nyata.'"},"6470":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ حَدَّثَنَا زَكَرِيَّاءُ بْنُ إِسْحَاقَ عَنْ يَحْيَى بْنِ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ صَيْفِيٍّ عَنْ أَبِي مَعْبَدٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ مُعَاذًا إِلَى الْيَمَنِ","id":"Telah menceritakan kepada kami [Abu 'Ashim] telah menceritakan kepada kami [Zakariya bin Ishaq] dari [Yahya bin Muhammad bin Abdullah bin Shaifi] dari [Abu Ma'bad] dari [Ibn Abbas] radliyallahu'anhuma, bahwa Nabi shallallahu 'alaihi wasallam pernah mengutus Mu'adz ke negeri Yaman.\""},"6471":{"ar":"و حَدَّثَنِي عَبْدُ اللَّهِ بْنُ أَبِي الْأَسْوَدِ حَدَّثَنَا الْفَضْلُ بْنُ الْعَلَاءِ حَدَّثَنَا إِسْمَاعِيلُ بْنُ أُمَيَّةَ عَنْ يَحْيَى بْنِ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ صَيْفِيٍّ أَنَّهُ سَمِعَ أَبَا مَعْبَدٍ مَوْلَى ابْنِ عَبَّاسٍ يَقُولُ سَمِعْتُ ابْنَ عَبَّاسٍ يَقُولُلَمَّا بَعَثَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُعَاذَ بْنَ جَبَلٍ إِلَى نَحْوِ أَهْلِ الْيَمَنِ قَالَ لَهُ إِنَّكَ تَقْدَمُ عَلَى قَوْمٍ مِنْ أَهْلِ الْكِتَابِ فَلْيَكُنْ أَوَّلَ مَا تَدْعُوهُمْ إِلَى أَنْ يُوَحِّدُوا اللَّهَ تَعَالَى فَإِذَا عَرَفُوا ذَلِكَ فَأَخْبِرْهُمْ أَنَّ اللَّهَ قَدْ فَرَضَ عَلَيْهِمْ خَمْسَ صَلَوَاتٍ فِي يَوْمِهِمْ وَلَيْلَتِهِمْ فَإِذَا صَلَّوْا فَأَخْبِرْهُمْ أَنَّ اللَّهَ افْتَرَضَ عَلَيْهِمْ زَكَاةً فِي أَمْوَالِهِمْ تُؤْخَذُ مِنْ غَنِيِّهِمْ فَتُرَدُّ عَلَى فَقِيرِهِمْ فَإِذَا أَقَرُّوا بِذَلِكَ فَخُذْ مِنْهُمْ وَتَوَقَّ كَرَائِمَ أَمْوَالِ النَّاسِ","id":"Telah menceritakan kepadaku [Abdullah bin Abu Al Aswad] telah menceritakan kepada kami [Al Fadll bin Al 'Ala] telah menceritakan kepada kami [Ismail bin Umayyah] dari [Yahya bin Muhmmad bin Abdullah bin Shaifi] ia mendengar [Abu Ma'bad] mantan budak Ibn Abbas, berkata, aku mendengar [Ibn Abbas] berkata, \"Dikala Nabi shallallahu 'alaihi wasallam mengutus Mu'adz ke negeri Yaman, Nabi berpesan: \"Wahai Mu'adz, engkau mendatangi kaum ahli kitab, maka jadikanlah materi dakwah pertama-tama yang engkau sampaikan adalah agar mereka mentauhidkan Allah ta'ala. Jika mereka telah sadar terhadap hal ini, beritahulah mereka bahwa Allah mewajibkan lima shalat kepada mereka dalam sehari semalam. Jika mereka telah shalat, beritahulah mereka bahwa Allah mewajibkan zakat harta mereka, yang diambil dari yang kaya, dan diberikan kepada yang miskin, dan jika mereka telah mengikrarkan yang demikian, ambilah harta mereka dan jagalah harta mereka yang kesemuanya harus dijaga kehormatannya.\""},"6472":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي حَصِينٍ وَالْأَشْعَثِ بْنِ سُلَيْمٍ سَمِعَا الْأَسْوَدَ بْنَ هِلَالٍ عَنْ مُعَاذِ بْنِ جَبَلٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا مُعَاذُ أَتَدْرِي مَا حَقُّ اللَّهِ عَلَى الْعِبَادِ قَالَ اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ أَنْ يَعْبُدُوهُ وَلَا يُشْرِكُوا بِهِ شَيْئًا أَتَدْرِي مَا حَقُّهُمْ عَلَيْهِ قَالَ اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ أَنْ لَا يُعَذِّبَهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Abu Hushain] dan [Al Asy'ats bin Sulaim] keduanya mendengar [Al Aswad bin Hilal] dari [Mu'adz bin Jabal] berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Wahai Mu'adz, tahukah kamu hak Allah atas hamba?\" \"Allah dan rasul-Nya yang lebih tahu, \" Jawab Mu'adz. Nabi bersabda lagi: \"Yaitu agar mereka beribadah kepada-Nya dengan tidak menyekutukan-Nya dengan sesuatu apapun. Tahukah engkau apa hak mereka atas Allah?\" tanya Nabi selanjutnya.\"Allah dan Rasul-Nya yang lebih lebih tahu.\" Jawab Mu'adz. Nabi bersabda: \"Yaitu agar Dia tidak menyiksa mereka.\""},"6473":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنِي مَالِكٌ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي صَعْصَعَةَ عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَجُلًا سَمِعَ رَجُلًا يَقْرَأُ قُلْ هُوَ اللَّهُ أَحَدٌ يُرَدِّدُهَا فَلَمَّا أَصْبَحَ جَاءَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ لَهُ ذَلِكَ وَكَأَنَّ الرَّجُلَ يَتَقَالُّهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي نَفْسِي بِيَدِهِ إِنَّهَا لَتَعْدِلُ ثُلُثَ الْقُرْآنِزَادَ إِسْمَاعِيلُ بْنُ جَعْفَرٍ عَنْ مَالِكٍ عَنْ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ أَخْبَرَنِي أَخِي قَتَادَةُ بْنُ النُّعْمَانِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ismail] telah menceritakan kepadaku [Malik] dari [Abdurrahman bin Abdullah bin Abdurrahman bin Abu Sha'sha'ah] dari [Ayahnya] dari [Abu Sa'id Al Khudzri], bahwa ada seorang laki-laki mendengar seseorang yang membaca QULHUWALLAHU AHAD (QS.Surat al-ikhlas), ia mengulang-ulanginya. Pagi harinya, ia menemui Nabi shallallahu 'alaihi wasallam dan mengutarakan kisahnya yang seolah-olah si laki-laki tadi menganggap terlalu remeh (sedikit) bacaannya. Spontan Rasulullah Shallallahu'alaihiwasallam bersabda: \"Sungguh surat tadi menyamai sepertiga alquran.\" Dan [Ismail bin Ja'far] menambahkan dari [Malik] dari [Abdurrahman] dari [Ayahnya] dari [Abu Sa'id] telah mengabariku saudaraku [Qatadah bin Nu'man] dari nabi shallallahu 'alaihi wasallam.\""},"6474":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ حَدَّثَنَا عَمْرٌو عَنْ ابْنِ أَبِي هِلَالٍ أَنَّ أَبَا الرِّجَالِ مُحَمَّدَ بْنَ عَبْدِ الرَّحْمَنِ حَدَّثَهُ عَنْ أُمِّهِ عَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِوَكَانَتْ فِي حَجْرِ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ عَائِشَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ رَجُلًا عَلَى سَرِيَّةٍ وَكَانَ يَقْرَأُ لِأَصْحَابِهِ فِي صَلَاتِهِمْ فَيَخْتِمُ بِقُلْ هُوَ اللَّهُ أَحَدٌ فَلَمَّا رَجَعُوا ذَكَرُوا ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ سَلُوهُ لِأَيِّ شَيْءٍ يَصْنَعُ ذَلِكَ فَسَأَلُوهُ فَقَالَ لِأَنَّهَا صِفَةُ الرَّحْمَنِ وَأَنَا أُحِبُّ أَنْ أَقْرَأَ بِهَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبِرُوهُ أَنَّ اللَّهَ يُحِبُّهُ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami [Ibn Wahb] telah menceritakan kepada kami [Amru] dari [Ibnu Abu Hilal] bahwa [Abu Rijal Muhammad bin Abdurrahman] menceritakan kepadanya dari Ibunya [Amrah binti Abdurrahman] yang dahulu dalam asuhan Aisyah isteri Nabi shallallahu 'alaihi wasallam, dari ['Aisyah], bahwa Nabi shallallahu 'alaihi wasallam pernah mengutus seorang laki-laki dalam sebuah eskpedisi militer, lantas laki-laki tersebut membaca untuk sahabatnya dalam shalatnya dengan QULHUWALLAHU AHAD (Surat al Ikhlash) dan menutupnya juga dengan surat itu. Dikala mereka pulang, mereka menceritakan hal ini kepada Nabi shallallahu 'alaihi wasallam, lantas Nabi shallallahu 'alaihi wasallam bersabda: 'Tolong tanyailah dia, mengapa dia berbuat sedemikian? ' Mereka pun menanyainya, dan sahabat tadi menjawab, 'Sebab surat itu adalah menggambarkan sifat Arrahman, dan aku sedemikian menyukai membacanya.' Spontan Nabi shallallahu 'alaihi wasallam bersabda: 'Beritahukanlah kepadanya bahwa Allah menyukainya.\""},"6475":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَامٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ زَيْدِ بْنِ وَهْبٍ وَأَبِي ظَبْيَانَ عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَرْحَمُ اللَّهُ مَنْ لَا يَرْحَمُ النَّاسَ","id":"Telah menceritakan kepada kami [Muhammad bin Salam] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Zaid bin Wahb] dan [Abu dlabyan] dari [Jarir bin Abdullah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah tak bakalan menyayangi siapa saja yang tidak menyayangi manusia.\""},"6476":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَاصِمٍ الْأَحْوَلِ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ عَنْ أُسَامَةَ بْنِ زَيْدٍ قَالَكُنَّا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ جَاءَهُ رَسُولُ إِحْدَى بَنَاتِهِ يَدْعُوهُ إِلَى ابْنِهَا فِي الْمَوْتِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ارْجِعْ إِلَيْهَا فَأَخْبِرْهَا أَنَّ لِلَّهِ مَا أَخَذَ وَلَهُ مَا أَعْطَى وَكُلُّ شَيْءٍ عِنْدَهُ بِأَجَلٍ مُسَمًّى فَمُرْهَا فَلْتَصْبِرْ وَلْتَحْتَسِبْ فَأَعَادَتْ الرَّسُولَ أَنَّهَا قَدْ أَقْسَمَتْ لَتَأْتِيَنَّهَا فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَامَ مَعَهُ سَعْدُ بْنُ عُبَادَةَ وَمُعَاذُ بْنُ جَبَلٍ فَدُفِعَ الصَّبِيُّ إِلَيْهِ وَنَفْسُهُ تَقَعْقَعُ كَأَنَّهَا فِي شَنٍّ فَفَاضَتْ عَيْنَاهُ فَقَالَ لَهُ سَعْدٌ يَا رَسُولَ اللَّهِ مَا هَذَا قَالَ هَذِهِ رَحْمَةٌ جَعَلَهَا اللَّهُ فِي قُلُوبِ عِبَادِهِ وَإِنَّمَا يَرْحَمُ اللَّهُ مِنْ عِبَادِهِ الرُّحَمَاءَ","id":"Telah menceritakan kepada kami [Abu Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] dari ['Ashim Al ahwal] dari [Abu Utsman an Nahdi] dari [Usamah bin Zaid] berkata, \"Kami di sisi Nabi shallallahu 'alaihi wasallam, lantas utusan salah seorang di antara kedua puteri beliau memanggilnya karena anak laki-lakinya diambang kematian. Lantas Nabi bersabda kepada sang utusan: \"Pulanglah engkau ke rumah anak puteriku, dan beritahukanlah kepadanya bahwa segala milik Allah-lah yang diambil-Nya dan apa yang diberikan-Nya, dan segala sesuatu di sisi-Nya telah ada ketentuan yang ditetapkan. Suruhlah dia untuk bersabar dan mengharap-harap pahala.\" Anak puteri beliau kembali mengutus utusannya disertai sumpah yang isinya, 'Anda harus mendatanginya.' Kontan Nabi shallallahu 'alaihi wasallam berdiri bersama Sa'd bin Ubadah dan Muadz bin Jabal, lalu anak kecil dari puteri beliau diserahkan beliau sedang nyawanya sudah tersengal-sengal seolah-olah sudah di penghujung (sisa-sia) hayatnya. Kedua mata Nabi terus berlinang, maka Sa'd bertanya, 'Wahai Rasulullah, mengapa mata anda menangis? ' Nabi menjawab: \"Inilah rahmat yang Allah letakkan dalam hati hamba-Nya, hanyasanya Allah menyayangi hamba-Nya yang penyayang.\""},"6477":{"ar":"حَدَّثَنَا عَبْدَانُ عَنْ أَبِي حَمْزَةَ عَنْ الْأَعْمَشِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ أَبِي عَبْدِ الرَّحْمَنِ السُّلَمِيِّ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَحَدٌ أَصْبَرُ عَلَى أَذًى سَمِعَهُ مِنْ اللَّهِ يَدَّعُونَ لَهُ الْوَلَدَ ثُمَّ يُعَافِيهِمْ وَيَرْزُقُهُمْ","id":"Telah menceritakan kepada kami ['Abdan] dari [Abu Hamzah] dari [Al A'masy] dari [Sa'id bin Jubair] dari [Abu 'Abdurrahman assulami] dari [Abu Musa Al asy'ari] berkata, \"Nabi shallallahu 'alaihi wasallam Shallallahu'alaihiwasallam bersabda: \"Tidak ada seorang pun yang lebih bersabar atas gangguan yang didengarnya daripada Allah, ada manusia mengaku Allah mempunyai anak (yaitu orang nashrani), namun Allah masih juga memberi mereka kesehatan dan rejeki.\""},"6478":{"ar":"حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ دِينَارٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَفَاتِيحُ الْغَيْبِ خَمْسٌ لَا يَعْلَمُهَا إِلَّا اللَّهُ لَا يَعْلَمُ مَا تَغِيضُ الْأَرْحَامُ إِلَّا اللَّهُ وَلَا يَعْلَمُ مَا فِي غَدٍ إِلَّا اللَّهُ وَلَا يَعْلَمُ مَتَى يَأْتِي الْمَطَرُ أَحَدٌ إِلَّا اللَّهُ وَلَا تَدْرِي نَفْسٌ بِأَيِّ أَرْضٍ تَمُوتُ إِلَّا اللَّهُ وَلَا يَعْلَمُ مَتَى تَقُومُ السَّاعَةُ إِلَّا اللَّهُ","id":"Telah menceritakan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Sulaiman bin Bilal] telah menceritakan kepadaku [Abdullah bin Dinar] dari [Ibn Umar] radliyallahu'anhuma dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Kunci keghaiban ada lima; tidak mengetahuinya selain Allah, tidak ada yang mengetahui kandungan yang mengempes (gugur, berkurang) selain Allah, tidak ada yang mengetahui apa yang terjadi esok hari selain Allah, tidak ada yang mengetahui kapan hujan datang selain Allah, dan tidak ada siapapun manusia yang tahu di bumi mana berada akan meninggal selain Allah, dan tidak ada yang mengetahui kapan kiamat terjadi selain Allah.\""},"6479":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ إِسْمَاعِيلَ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْمَنْ حَدَّثَكَ أَنَّ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَبَّهُ فَقَدْ كَذَبَ وَهُوَ يَقُولُ{ لَا تُدْرِكُهُ الْأَبْصَارُ }وَمَنْ حَدَّثَكَ أَنَّهُ يَعْلَمُ الْغَيْبَ فَقَدْ كَذَبَ وَهُوَ يَقُولُ لَا يَعْلَمُ الْغَيْبَ إِلَّا اللَّهُ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Ismail] dari [Asy Sya'bi] dari [Masruq] dari ['Aisyah] radliyallahu'anhuma, ia berkata, \"Barangsiapa menceritakan kepadamu bahwa Muhammad Shallallahu'alaihiwasallam melihat Tuhannya berarti ia telah dusta, karena Allah berfirman: '(Ia tidak bisa dimengetahui oleh pandangan) ' (Qs. Al An'am: 103), dan barangsiapa menceritakan kepadamu bahwa ia tahu yang ghaib, berarti ia telah dusta, sebab Muhammad bersabda: 'Tidak ada yang tahu yang ghaib selain Allah'.\""},"6480":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا مُغِيرَةُ حَدَّثَنَا شَقِيقُ بْنُ سَلَمَةَ قَالَ قَالَ عَبْدُ اللَّهِكُنَّا نُصَلِّي خَلْفَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَقُولُ السَّلَامُ عَلَى اللَّهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ هُوَ السَّلَامُ وَلَكِنْ قُولُوا التَّحِيَّاتُ لِلَّهِ وَالصَّلَوَاتُ وَالطَّيِّبَاتُ السَّلَامُ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ السَّلَامُ عَلَيْنَا وَعَلَى عِبَادِ اللَّهِ الصَّالِحِينَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Mughirah] telah menceritakan kepada kami [Syaqiq bin Maslamah] berkata, [Abdullah] berkata, 'Pernah kami shalat di belakang Nabi shallallahu 'alaihi wasallam dan kami mengucapkan, 'ASSALAMU ALALLAHI (Semoga keselamatan atas Allah) ', maka beliau berkata: 'Sesungguhnya Allah adalah Assalaam', namun katakanlah olehmu sekalian: 'ATTAHIYAATULILLAH WA ASH SHALAWATU WATH THAYYIBAT ASSALAAMU ALAIKA AYYUHANNABIYU WA RAHMATULLAHI WA BARAKAATUHU ASSALAAMU 'ALAINA WA 'ALA 'IBAADILLAHISH SHAALIHIINA ASYHADU AN LAA ILAAHA ILLAALLAHU WA ASYHADU ANNA MUHAMMADAN 'ABDUHU WA RASUULUH (Segala pujian milik Allah', dan kesejahteraan serta segala kebaikan, semoga kesejahteraan atasmu wahai nabi shallallahu 'alaihi wasallam, juga rahmat Allah dan barakah-Nya. Dan semoga kesejahteraan terlimpahkan kepada kita, dan hamba-hamba Allah yang shalih, saya bersaksi bahwa tiada sesembahan yang hak selain Allah semata dan saya bersaksi bahwa Muhammad adalah hamba-Nya dan Rasul-Nya) '."},"6481":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدٍ هُوَ ابْنُ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَقْبِضُ اللَّهُ الْأَرْضَ يَوْمَ الْقِيَامَةِ وَيَطْوِي السَّمَاءَ بِيَمِينِهِ ثُمَّ يَقُولُ أَنَا الْمَلِكُ أَيْنَ مُلُوكُ الْأَرْضِوَقَالَ شُعَيْبٌ وَالزُّبَيْدِيُّ وَابْنُ مُسَافِرٍ وَإِسْحَاقُ بْنُ يَحْيَى عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami [Ibn Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibn Syihab] dari [Sa'id] -yaitu Ibnul Musayyab- dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Pada hari kiamat Allah menggenggam bumi dan melipat langit dengan tangan kanan-Nya serta berkata 'Akulah sang raja, mana raja-raja bumi?\" Dan [Syu'aib] dan [Azzubaidi] dan [Ibn Musafir] dan [Ishaq bin Yahya] juga berkata dari [Az Zuhri] dan [Abu Salmah] semisalnya.\""},"6482":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا حُسَيْنٌ الْمُعَلِّمُ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ عَنْ يَحْيَى بْنِ يَعْمَرَ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ أَعُوذُ بِعِزَّتِكَ الَّذِي لَا إِلَهَ إِلَّا أَنْتَ الَّذِي لَا يَمُوتُ وَالْجِنُّ وَالْإِنْسُ يَمُوتُونَ","id":"Telah menceritakan kepada kami [Abu Ma'mar] telah menceritakan kepada kami ['Abdul Warits] telah menceritakan kepada kami [Husain Al Mu'aliim] telah menceritakan kepadaku [Abdullah bin Buraidah] dari [Yahya bin Ya'mar] dari [Ibn Abbas] bahwa Nabi shallallahu 'alaihi wasallam pernah memanjatkan doa: 'AUUDZU BI'IZZATILLAHILLLADZII LAA ILAAHA ILLAA ANTAL LADZII LAA YAMUUTU WAL JINNU WAL INSU YAMUUTUUTUUNA (Saya berlindung dengan kekuasaan Allah yang tiada sesembahan yang hak selain Dia, yang tidak pernah mati sedang jin dan manusia akan mati) '.\""},"6483":{"ar":"حَدَّثَنَا ابْنُ أَبِي الْأَسْوَدِ حَدَّثَنَا حَرَمِيٌّ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَزَالُ يُلْقَى فِي النَّارِ ح و قَالَ لِي خَلِيفَةُ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَنَسٍ وَعَنْ مُعْتَمِرٍ سَمِعْتُ أَبِي عَنْ قَتَادَةَ عَنْ أَنَسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَزَالُ يُلْقَى فِيهَا{ وَتَقُولُ هَلْ مِنْ مَزِيدٍ }حَتَّى يَضَعَ فِيهَا رَبُّ الْعَالَمِينَ قَدَمَهُ فَيَنْزَوِي بَعْضُهَا إِلَى بَعْضٍ ثُمَّ تَقُولُ قَدْ قَدْ بِعِزَّتِكَ وَكَرَمِكَ وَلَا تَزَالُ الْجَنَّةُ تَفْضُلُ حَتَّى يُنْشِئَ اللَّهُ لَهَا خَلْقًا فَيُسْكِنَهُمْ فَضْلَ الْجَنَّةِ","id":"Telah menceritakan kepada kami [Ibn Abu Al Aswad] telah menceritakan kepada kami [Harami] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Anas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Terus saja -penghuninya- dimasukkan ke dalam Neraka.\" (dalam jalur lain disebutkan) Dan telah berkata kepadaku [Khalifah] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Anas] dan dari [Mu'tamir] aku mendengar [bapakku] dari [Qatadah] dari [Anas] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Terus saja -penghuninya- dimasukkan ke dalam Neraka '(sehingga ia berkata 'Masih adakah tambahan?\" (Qs. Qaaf: 30), hingga Allah Rabbul 'alamin meletakkan telapak kaki-Nya sehingga satu sama lain saling berdesak-desakan, hingga neraka berkata, 'Cukup-cukup' demi kemuliaan dan kehormatan-Mu. Sedangkan surga masih saja terlalu longgar sehingga Allah menciptakan makhluk baru dan meletakkan mereka ke dalam surga yang masih senggang.\""},"6484":{"ar":"حَدَّثَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ جُرَيْجٍ عَنْ سُلَيْمَانَ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْعُو مِنْ اللَّيْلِ اللَّهُمَّ لَكَ الْحَمْدُ أَنْتَ رَبُّ السَّمَوَاتِ وَالْأَرْضِ لَكَ الْحَمْدُ أَنْتَ قَيِّمُ السَّمَوَاتِ وَالْأَرْضِ وَمَنْ فِيهِنَّ لَكَ الْحَمْدُ أَنْتَ نُورُ السَّمَوَاتِ وَالْأَرْضِ قَوْلُكَ الْحَقُّ وَوَعْدُكَ الْحَقُّ وَلِقَاؤُكَ حَقٌّ وَالْجَنَّةُ حَقٌّ وَالنَّارُ حَقٌّ وَالسَّاعَةُ حَقٌّ اللَّهُمَّ لَكَ أَسْلَمْتُ وَبِكَ آمَنْتُ وَعَلَيْكَ تَوَكَّلْتُ وَإِلَيْكَ أَنَبْتُ وَبِكَ خَاصَمْتُ وَإِلَيْكَ حَاكَمْتُ فَاغْفِرْ لِي مَا قَدَّمْتُ وَمَا أَخَّرْتُ وَأَسْرَرْتُ وَأَعْلَنْتُ أَنْتَ إِلَهِي لَا إِلَهَ لِي غَيْرُكَحَدَّثَنَا ثَابِتُ بْنُ مُحَمَّدٍ حَدَّثَنَا سُفْيَانُ بِهَذَا وَقَالَ أَنْتَ الْحَقُّ وَقَوْلُكَ الْحَقُّ","id":"Telah menceritakan kepada kami [Qabishah] telah menceritakan kepada kami [Sufyan] dari [Ibn Juraij] dari [Sulaiman] dari [Thawus] dari [Ibn Abbas] radliyallahu'anhuma, ia berkata, \"Nabi shallallahu 'alaihi wasallam berdoa diwaktu malam: 'ALLAAHUMMA LAKAL HAMDU ANTA RABBUS SAMAAWAATI WAL ARDLI LAKAL HAMD, ANTA QAYYIMUS SAMAAWAATI WAL ARDL WAMAN FIIHINNA, LAKAL HAMDU ANTA NUURUS SAMAAWAATI WAL ARDLI, QOULUKAL HAQQ, WAWA'DUKAL HAQQ, WALIQAA'UKA HAQQ, WAL JANNATU HAQQ WAN NAARU HAQQ, WASSAA'ATU HAQQ, ALLAAHUMMA LAKA ASLAMTU WABIKA AAMANTU WA'ALAIKA TAWAKKALTU, WAILAIKA ANABTU WABIKA KHAASHAMTU, WAILAIKA HAAKAMTU, FAGHFIR LII MAA QADDAMTU WAMAAA AKHKHARTU WA ASRARTU WAMAA A'LANTU ANTA ILAAHII LAA-ILAAHA LII GHAIRUKA '(Ya Allah, bagi-Mu segala puji, Engkau Tuhan langit dan bumi, bagi-Mu segala puji, Engkau pengurus langit dan bumi dan semua penghuninya, bagi-Mu segala puji, Engkau adalah cahaya langit dan bumi, firman-Mu benar, janji-Mu benar, perjumpaan terhadap-Mu adalah benar, surga adalah benar, neraka adalah benar, hari kiamat benar, ya Allah, kepada-Mu aku berserah diri, kepada-Mu aku beriman, kepada-Mu aku bertawakkal, kepada-Mu aku bersandar, karena-Mu aku memusuhi (musuh), kepada-Mu aku berhakim, maka ampunilah bagiku apa yang pernah aku lakukan dan apa yang belum aku lakukan, apa yang aku lakukan secara sembunyi-sembunyi dan apa yang aku lakukan secara terang-terangan, Engkau adalah Tuhanku, tiada sesembahan yang hak bagiku selain Engkau) '.\" Dan telah menceritakan kepada kami [Tsabit bin Muhammad] telah menceritakan kepada kami [Sufyan] dengan hadis ini, dan ia menyebutkan dengan redaksi, 'Engkau adalah benar dan firman-Mu benar.'"},"6485":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ أَبِي عُثْمَانَ عَنْ أَبِي مُوسَى قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَكُنَّا إِذَا عَلَوْنَا كَبَّرْنَا فَقَالَ ارْبَعُوا عَلَى أَنْفُسِكُمْ فَإِنَّكُمْ لَا تَدْعُونَ أَصَمَّ وَلَا غَائِبًا تَدْعُونَ سَمِيعًا بَصِيرًا قَرِيبًا ثُمَّ أَتَى عَلَيَّ وَأَنَا أَقُولُ فِي نَفْسِي لَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ فَقَالَ لِي يَا عَبْدَ اللَّهِ بْنَ قَيْسٍ قُلْ لَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ فَإِنَّهَا كَنْزٌ مِنْ كُنُوزِ الْجَنَّةِ أَوْ قَالَ أَلَا أَدُلُّكَ بِهِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Abu Usman] dari [Abu Musa] berkata, \"Pernah kami bersama Nabi shallallahu 'alaihi wasallam dalam sebuah safar, jika kami menaiki tempat yang tinggi maka kami bertakbir, dan beliau bersabda: 'Sederhanakanlah kalian dalam berdoa, sebab kalian tidak menyeru Dzat yang tuli dan tidak pula yang ghaib, sesungguhnya kalian menyeru Tuhan yang Maha mendengar lagi Maha melihat dan Maha dekat.\" Kemudian beliau mendatangiku sedang aku berkata dalam hati: 'Laa haula walaa quwwata illaa billaah (Tiada daya dan kekuatan kecuali dengan pertolongan Allah) ', maka beliau berkata: \"Wahai Abdullah bin Qais, ucapkanlah laa haula walaa quwwata illaa billaah, sebab bacaan itu adalah perbendaharaan surga, atau beliau berkata dengan redaksi, 'Maukah aku tunjukkan ucapan itu?\""},"6486":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سُلَيْمَانَ حَدَّثَنِي ابْنُ وَهْبٍ أَخْبَرَنِي عَمْرٌو عَنْ يَزِيدَ عَنْ أَبِي الْخَيْرِ سَمِعَ عَبْدَ اللَّهِ بْنَ عَمْرٍو أَنَّ أَبَا بَكْرٍ الصِّدِّيقَ رَضِيَ اللَّهُ عَنْهُقَالَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا رَسُولَ اللَّهِ عَلِّمْنِي دُعَاءً أَدْعُو بِهِ فِي صَلَاتِي قَالَ قُلْ اللَّهُمَّ إِنِّي ظَلَمْتُ نَفْسِي ظُلْمًا كَثِيرًا وَلَا يَغْفِرُ الذُّنُوبَ إِلَّا أَنْتَ فَاغْفِرْ لِي مِنْ عِنْدِكَ مَغْفِرَةً إِنَّكَ أَنْتَ الْغَفُورُ الرَّحِيمُ","id":"Telah menceritakan kepada kami [Yahya bin Sulaiman] telah menceritakan kepadaku [Ibn Wahb] telah mengabarkan kepadaku [Amru] dari [Yazid] dari [Abul Khair] ia mendengar [Abdullah bin Amru] bahwa [Abu Bakar] Ashshiddiiq radliyallahu'anhu berkata kepada Nabi shallallahu 'alaihi wasallam, \"Wahai Rasulullah, ajarilah aku doa yang aku panjatkan dalam shalatku!\" Nabi pun berkata: \"Ucapkanlah: ALLAAHUMMA INII ZHALAMTU NAFSII ZHULMAN KATSIIRAN WALAA YAGHFIRUDZDZUNUUBA ILLAA ANTA FAHGHFIRLII MIN INDIKA MAGHFIRATAN INNAKA ANTAL GHAFUURURRAHIIM '(Ya Allah, sesungguhnya aku telah menzhalimi diriku sendiri dengan kezhaliman yang banyak, dan tidak ada yang bisa mengampuni dosa selain Engkau, maka ampunilah bagiku dari sisi-Mu, sesungguhnya Engkau Maha pengampun lagi Maha Penyayang) '.\""},"6487":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ حَدَّثَنِي عُرْوَةُ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا حَدَّثَتْهُقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ جِبْرِيلَ عَلَيْهِ السَّلَام نَادَانِي قَالَ إِنَّ اللَّهَ قَدْ سَمِعَ قَوْلَ قَوْمِكَ وَمَا رَدُّوا عَلَيْكَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Ibn Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibn Syihab] telah menceritakan kepadaku ['Urwah] bahwa [Aisyah] radliyallahu'anhuma menceritakan kepadanya, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Jibril memanggilku dan berkata: 'Sesungguhnya Allah mendengar ucapan kaummu namun mereka tidak bisa mencelakaimu'.\""},"6488":{"ar":"حَدَّثَنِي إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا مَعْنُ بْنُ عِيسَى حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ أَبِي الْمَوَالِي قَالَ سَمِعْتُ مُحَمَّدَ بْنَ الْمُنْكَدِرِ يُحَدِّثُ عَبْدَ اللَّهِ بْنَ الْحَسَنِ يَقُولُ أَخْبَرَنِي جَابِرُ بْنُ عَبْدِ اللَّهِ السَّلَمِيُّ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعَلِّمُ أَصْحَابَهُ الِاسْتِخَارَةَ فِي الْأُمُورِ كُلِّهَا كَمَا يُعَلِّمُهُمْ السُّورَةَ مِنْ الْقُرْآنِ يَقُولُ إِذَا هَمَّ أَحَدُكُمْ بِالْأَمْرِ فَلْيَرْكَعْ رَكْعَتَيْنِ مِنْ غَيْرِ الْفَرِيضَةِ ثُمَّ لِيَقُلْ اللَّهُمَّ إِنِّي أَسْتَخِيرُكَ بِعِلْمِكَ وَأَسْتَقْدِرُكَ بِقُدْرَتِكَ وَأَسْأَلُكَ مِنْ فَضْلِكَ فَإِنَّكَ تَقْدِرُ وَلَا أَقْدِرُ وَتَعْلَمُ وَلَا أَعْلَمُ وَأَنْتَ عَلَّامُ الْغُيُوبِ اللَّهُمَّ فَإِنْ كُنْتَ تَعْلَمُ هَذَا الْأَمْرَ ثُمَّ تُسَمِّيهِ بِعَيْنِهِ خَيْرًا لِي فِي عَاجِلِ أَمْرِي وَآجِلِهِ قَالَ أَوْ فِي دِينِي وَمَعَاشِي وَعَاقِبَةِ أَمْرِي فَاقْدُرْهُ لِي وَيَسِّرْهُ لِي ثُمَّ بَارِكْ لِي فِيهِ اللَّهُمَّ وَإِنْ كُنْتَ تَعْلَمُ أَنَّهُ شَرٌّ لِي فِي دِينِي وَمَعَاشِي وَعَاقِبَةِ أَمْرِي أَوْ قَالَ فِي عَاجِلِ أَمْرِي وَآجِلِهِ فَاصْرِفْنِي عَنْهُ وَاقْدُرْ لِي الْخَيْرَ حَيْثُ كَانَ ثُمَّ رَضِّنِي بِهِ","id":"Telah menceritakan kepadaku [Ibrahim bin Al Mundzir] telah menceritakan kepada kami [Ma'an bin Isa] telah menceritakan kepadaku [Abdurrahman bin Abul Mawali] berkata, aku mendengar [Muhammad bin Al Munkadir] menceritakan Abdullah bin Al Hasan, dia berkata, telah mengabarkan kepadaku [Jabir bin Abdullah assalmi] berkata, \"Rasulullah Shallallahu'alaihiwasallam mengajari sahabat-sahabatnya untuk istikharah (meminta pilihan) dalam semua doanya sebagaimana beliau mengajarkan surat alquran kepada mereka, beliau sabdakan: \"Jika salah seorang dari kalian punya satu keinginan maka hendaklah ia kerjakan shalat dua rakaat (bukan shalat wajib) kemudian mengucapkan: 'ALLAAHUMMA INNII ASTAKHIIRUKA BI'ILMIKA, WA ASTAQDIRUKA BIQUDRATIKA WA AS'ALUKA MIN FADLLIKA, FAINNAKA TAQDIRU WALAA AQDIRU WATA'LAMU WALAA A'LAMU WA ANTA 'ALLAAMUL GHUYUUB, ALLAAHUMMA FAIN KUNTA TA'LAMU HAADZAL AMRA KHAIRAN LII FII 'AAJILI AMRII WA AAJILIHI -Qaala-- AW FII DIINII WAMA'AASYII WA'AAQIBATU AMRII FAQDURHU LII WAYASSIRHU LII TSUMMA BAARIK LII FIIHI, ALLAAHUMMA WAIN KUNTA TA'LAMU ANNAHU YARRUN LII FII DIINIII WAMA'AASYII WA'AAQIBATI -Aw qaala-FII 'AAJILI AMRII WA AAJILIHI FASHRIFNII 'ANHU WQDIRLIL KHIARA HAITSU KAANA TSUMMA ARDLINII BIHI (Ya Allah, Saya meminta pilihan kepada-Mu dengan ilmu-Mu, dan saya meminta keputusan dengan keputusan-Mu, dan saya meminta-Mu dengan kurnia-Mu, sesungguhnya Engkau memutuskan dan saya tidak bisa memutuskan, dan Engkau Maha tahu sedang aku tidak mengetahui, dan Engkau Maha mengetahui yang ghaib, Ya Allah, jikalah Engkau tahu bahwa urusan ini (Si Pemohon menyebut nama urusannya) adalah baik bagiku baik untuk masa yang dekat maupun masa yang akan datang -atau sepertinya ia berkata-dalam urusan agamaku dan duniaku, serta kesudahan urusanku, maka tetapkanlah untukku dan mudahkanlah bagiku, kemudian berilah aku barakah padanya. Ya Allah, sebaliknya jika Engkau tahu bahwa urusan ini adalah buruk bagiku dalam urusan agamaku dan kehidupanku, serta kesudahan urusanku- atau sepertinya ia berkata-dalam kesudahan yang dekat maupun yang akan datang, maka palingkanlah aku daripadanya dan tetapkanlah kebaikan bagiku darimana saja berada kemudian jadikanlah aku ridla terhadapnya) '.\""},"6489":{"ar":"حَدَّثَنِي سَعِيدُ بْنُ سُلَيْمَانَ عَنْ ابْنِ الْمُبَارَكِ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ سَالِمٍ عَنْ عَبْدِ اللَّهِ قَالَأَكْثَرُ مَا كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَحْلِفُ لَا وَمُقَلِّبِ الْقُلُوبِ","id":"Telah menceritakan kepadaku [Said bin Sulaiman] dari [Ibnul Mubarak] dari [Musa bin Uqbah] dari [Salim] dari [Abdullah] berkata, \"Sumpah yang paling sering dipergunakan oleh Nabi ShallAllahu 'alaihi wa Salam adalah \"Tidak! Ya Muqallibal quluub (Wahai Dzat yang membolak-balikkan hati)\"."},"6490":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ لِلَّهِ تِسْعَةً وَتِسْعِينَ اسْمًا مِائَةً إِلَّا وَاحِدًا مَنْ أَحْصَاهَا دَخَلَ الْجَنَّةَ{ أَحْصَيْنَاهُ }حَفِظْنَاهُ","id":"Telah menceritakan kepada kami [Abul Yaman] Telah mengabarkan kepada kami [Syu'aib] telah menceritakan kepada kami [Abuz Zinad] dari [Al A'raj] dari [Abu Hurairah] Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah mempunyai sembilan puluh sembilan nama, seratus kurang satu, siapa yang meng-ihsha'nya, maka ia masuk surga.\" Dan makna meng-ihsha' adalah menjaga sebagaimana firman Allah: 'Ahshainaa (Kami menjaganya) ' (Qs. Yasin: 12)."},"6491":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنِي مَالِكٌ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا جَاءَ أَحَدُكُمْ فِرَاشَهُ فَلْيَنْفُضْهُ بِصَنِفَةِ ثَوْبِهِ ثَلَاثَ مَرَّاتٍ وَلْيَقُلْ بِاسْمِكَ رَبِّ وَضَعْتُ جَنْبِي وَبِكَ أَرْفَعُهُ إِنْ أَمْسَكْتَ نَفْسِي فَاغْفِرْ لَهَا وَإِنْ أَرْسَلْتَهَا فَاحْفَظْهَا بِمَا تَحْفَظُ بِهِ عِبَادَكَ الصَّالِحِينَتَابَعَهُ يَحْيَى وَبِشْرُ بْنُ الْمُفَضَّلِ عَنْ عُبَيْدِ اللَّهِ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَزَادَ زُهَيْرٌ وَأَبُو ضَمْرَةَ وَإِسْمَاعِيلُ بْنُ زَكَرِيَّاءَ عَنْ عُبَيْدِ اللَّهِ عَنْ سَعِيدٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَوَاهُ ابْنُ عَجْلَانَ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abdul Aziz bin Abdullah] telah menceritakan kepadaku [Malik] dari [Abu Sa'id Al Maqburi] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang diantara kalian mendatangi kasurnya (tidur), hendaklah ia mengibaskannya dengan ujung kainnya sebanyak tiga kali, dan hendaklah memanjatkan doa BISMIKA RABBII WADLA'TU JANBII WABIKA ARFA'UHU, IN AMSAKTA NAFSII FAGHFIR LAHAA, WAIN ARSALTAHAA FAHFAHZH-HAA BIMAA TAHFAZHU BIHI 'IBAADAKASHSHAALIHIINA (Dengan menyebut nama-Mu Wahai Tuhanku, aku baringkan pinggangku dan atas nama-Mu aku mengangkatnya, dan jika Engkau menahan diriku, maka berilah ampunan terhadapnya, dan jika Engkau melepaskannya, maka jagalah sebagaimana Engkau menjaga hamba-Mu yang shalih) '.\" Hadis ini diperkuat oleh [Yahya] dan [Bisyr bin Mufadldlal] dari ['Ubaidullah] dari [Sa'id] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, sedang [Zuhair] dan [Abu Dlamrah] dan [Ismail bin Zakariya] menambahkan dari [Ubaidullah] dari [Sa'id] dari [Ayahnya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, dan juga diriwayatkan oleh [Ibnu 'Ajlan] dari [Sa'id] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam.\""},"6492":{"ar":"حَدَّثَنَا مُسْلِمٌ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الْمَلِكِ عَنْ رِبْعِيٍّ عَنْ حُذَيْفَةَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَوَى إِلَى فِرَاشِهِ قَالَ اللَّهُمَّ بِاسْمِكَ أَحْيَا وَأَمُوتُ وَإِذَا أَصْبَحَ قَالَ الْحَمْدُ لِلَّهِ الَّذِي أَحْيَانَا بَعْدَ مَا أَمَاتَنَا وَإِلَيْهِ النُّشُورُ","id":"Telah menceritakan kepada kami [Muslim] telah menceritakan kepada kami [Syu'bah] dari [Abdul Malik] dari [Rib'i] dari [Hudzaifah] berkata, \"Nabi shallallahu 'alaihi wasallam jika mendatangi kasurnya, beliau memanjatkan doa: ALLAAHUMMA BISMIKA AHYAA WA AMUUTU (Ya Allah, dengan nama-Mu aku hidup dan dengan nama-Mu aku meningga) ', sebaliknya jika beliau bangun di pagi hari, beliau membaca: ALHAMDU LILLAHIL LADZII AHYAANAA BA'DA MAA AMAATANAA WAILAIHIN NUSYUUR (Segala puji bagi Allah Yang telah menghidupkan kami setelah mematikan kami dan kepada-Nya kita kembali) '.\""},"6493":{"ar":"حَدَّثَنَا سَعْدُ بْنُ حَفْصٍ حَدَّثَنَا شَيْبَانُ عَنْ مَنْصُورٍ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ خَرَشَةَ بْنِ الحُرِّ عَنْ أَبِي ذَرٍّ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَخَذَ مَضْجَعَهُ مِنْ اللَّيْلِ قَالَ بِاسْمِكَ نَمُوتُ وَنَحْيَا فَإِذَا اسْتَيْقَظَ قَالَ الْحَمْدُ لِلَّهِ الَّذِي أَحْيَانَا بَعْدَ مَا أَمَاتَنَا وَإِلَيْهِ النُّشُورُ","id":"Telah menceritakan kepada kami [Sa'd bin Hafsh] telah menceritakan kepada kami [Syaiban] dari [Manshur] dari [Rib'I bin Khirasy] dari [Kharasyah bin Alhurr] dari [Abu Dzar] berkata, \"Nabi shallallahu 'alaihi wasallam jika mendatangi tempat tidurnya (tidur) di malam hari, maka beliau memanjatkan doa: 'BISMIKA NAMUUTU WA NAHYAA (Dengan nama-Mu kami mati dan hidup), dan apabila bangun beliau membaca doa: ALHAMDULILLAAHILLDAZII AHYAANAA BA'DA MAA AMAATANAA WAILAIHINNUSYUUR (Segala puji bagi Allah yang telah menghidupkan kami setelah Dia mematikan kami dan kepada-Nya kita dibangkitkan).\""},"6494":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ سَالِمٍ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ أَنَّ أَحَدَكُمْ إِذَا أَرَادَ أَنْ يَأْتِيَ أَهْلَهُ فَقَالَ بِاسْمِ اللَّهِ اللَّهُمَّ جَنِّبْنَا الشَّيْطَانَ وَجَنِّبْ الشَّيْطَانَ مَا رَزَقْتَنَا فَإِنَّهُ إِنْ يُقَدَّرْ بَيْنَهُمَا وَلَدٌ فِي ذَلِكَ لَمْ يَضُرُّهُ شَيْطَانٌ أَبَدًا","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Salim] dari [Kuraib] dari [Ibn Abbas] radliyallahu'anhuma berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekiranya salah seorang diantara kalian ingin mendatangi isterinya, maka panjatkanlah doa: 'BISMIKALLAAHUMMA JANNIBNASY WAJANNIBISYSYAITHAANA MAA RAZAQTANAA (Dengan nama Allah, jauhkanlah kami dari setan dan jauhkanlah setan yang Engkau anugerahkan kepada kami) ', jika ditakdirkan memperoleh anak dari keduanya, maka setan tak bakalan membahayakannya selama-lamanya.\""},"6495":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا فُضَيْلٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ هَمَّامٍ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ أُرْسِلُ كِلَابِي الْمُعَلَّمَةَ قَالَ إِذَا أَرْسَلْتَ كِلَابَكَ الْمُعَلَّمَةَ وَذَكَرْتَ اسْمَ اللَّهِ فَأَمْسَكْنَ فَكُلْ وَإِذَا رَمَيْتَ بِالْمِعْرَاضِ فَخَزَقَ فَكُلْ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] telah menceritakan kepada kami [Fudlail] dari [Manshur] dari [Ibrahim] dari [Hammam] dari [Adi bin Hatim] berkata, \"Aku pernah bertanya Nabi shallallahu 'alaihi wasallam, aku katakan, 'Saya biasa melepas anjingku yang terlatih! Nabi menjawab: \"Jika kau lepas anjingmu yang terlatih dengan kau sebut nama Allah, lantas anjingmu menerkam mangsanya, maka makanlah dari yang diterkamnya, dan jika kamu melempar dengan batang panah namun batang panah itu melukai (melukai kulit, atau mengalirkan darah,) maka makanlah.\""},"6496":{"ar":"حَدَّثَنَا يُوسُفُ بْنُ مُوسَى حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ قَالَ سَمِعْتُ هِشَامَ بْنَ عُرْوَةَ يُحَدِّثُ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْقَالُوا يَا رَسُولَ اللَّهِ إِنَّ هَا هُنَا أَقْوَامًا حَدِيثٌ عَهْدُهُمْ بِشِرْكٍ يَأْتُونَا بِلُحْمَانٍ لَا نَدْرِي يَذْكُرُونَ اسْمَ اللَّهِ عَلَيْهَا أَمْ لَا قَالَ اذْكُرُوا أَنْتُمْ اسْمَ اللَّهِ وَكُلُواتَابَعَهُ مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ وَالدَّرَاوَرْدِيُّ وَأُسَامَةُ بْنُ حَفْصٍ","id":"Telah menceritakan kepada kami [Yusuf bin Musa] telah menceritakan kepada kami [Abu Khalid Al Ahmar] berkata, aku mendengar [Hisyam bin Urwah] menceritakan dari [Ayahnya] dari ['Aisyah] berkata, \"Wahai Rasulullah, di sini ada beberapa kaum yang baru saja meninggalkan kesyirikan (KeIslamannya baru-baru saja), mereka biasa membawakan daging untuk kami yang kami tidak tahu dengan menyebut nama Allah ataukah tidak (lantas bagaimana)? ' Nabi menjawab: \"Sebutlah oleh kalian nama Allah, dan makanlah.\" Hadis ini diperkuat oleh [Muhammad bin Abdurrahman] dan [Darawardi] dan [Usamah bin Hafsh]."},"6497":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَضَحَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِكَبْشَيْنِ يُسَمِّي وَيُكَبِّرُ","id":"Telah menceritakan kepada kami [Hafs bin Umar] telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari [Anas] berkata, \"Nabi shallallahu 'alaihi wasallam pernah berkurban dengan dua kambing, beliau sebut nama Allah dan beliau bertakbir.\""},"6498":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ الْأَسْوَدِ بْنِ قَيْسٍ عَنْ جُنْدَبٍأَنَّهُ شَهِدَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ النَّحْرِ صَلَّى ثُمَّ خَطَبَ فَقَالَ مَنْ ذَبَحَ قَبْلَ أَنْ يُصَلِّيَ فَلْيَذْبَحْ مَكَانَهَا أُخْرَى وَمَنْ لَمْ يَذْبَحْ فَلْيَذْبَحْ بِاسْمِ اللَّهِ","id":"Telah menceritakan kepada kami [Hafs bin Umar] telah menceritakan kepada kami [Syu'bah] dari [Al Aswad bin Qais] dari [Jundab] ia pernah menyaksikan Nabi shallallahu 'alaihi wasallam di hari raya kurban (idul adla) mendirikan shalat, kemudian berkhutbah dan bersabda: \"Barangsiapa menyembelih sebelum shalat, hendaklah ia menyembelih kembali dengan sembelihan lain sebagai gantinya, dan barangsiapa belum menyembelih, hendaklah menyembelih dengan menyebut nama Allah.\""},"6499":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا وَرْقَاءُ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَحْلِفُوا بِآبَائِكُمْ وَمَنْ كَانَ حَالِفًا فَلْيَحْلِفْ بِاللَّهِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Warqa'] dari ['Abdullah bin Dinar] dari [Ibn Umar] radliyallahu'anhuma mengatakan, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Jangan kalian bersumpah dengan nama bapak-bapak kalian, dan barangsiapa bersumpah, hendaklah bersumpah dengan nama Allah.\""},"6500":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ أَخْبَرَنِي عَمْرُو بْنُ أَبِي سُفْيَانَ بْنِ أَسِيدِ بْنِ جَارِيَةَ الثَّقَفِيُّ حَلِيفٌ لِبَنِي زُهْرَةَ وَكَانَ مِنْ أَصْحَابِ أَبِي هُرَيْرَةَ أَنَّ أَبَا هُرَيْرَةَ قَالَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَشَرَةً مِنْهُمْ خُبَيْبٌ الْأَنْصَارِيُّ فَأَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عِيَاضٍ أَنَّ ابْنَةَ الْحَارِثِ أَخْبَرَتْهُ أَنَّهُمْ حِينَ اجْتَمَعُوا اسْتَعَارَ مِنْهَا مُوسَى يَسْتَحِدُّ بِهَا فَلَمَّا خَرَجُوا مِنْ الْحَرَمِ لِيَقْتُلُوهُ قَالَ خُبَيْبٌ الْأَنْصَارِيُّ وَلَسْتُ أُبَالِي حِينَ أُقْتَلُ مُسْلِمًاعَلَى أَيِّ شِقٍّ كَانَ لِلَّهِ مَصْرَعِيوَذَلِكَ فِي ذَاتِ الْإِلَهِ وَإِنْ يَشَأْيُبَارِكْ عَلَى أَوْصَالِ شِلْوٍ مُمَزَّعِفَقَتَ��َهُ ابْنُ الْحَارِثِ فَأَخْبَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَصْحَابَهُ خَبَرَهُمْ يَوْمَ أُصِيبُوا","id":"Telah menceritakan kepada kami [Abul Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Azzuhri] telah mengabarkan kepadaku ['Amru bin Abu Sufyan bin Usaid bin Jariyah Atstsaqafi] sekutu bani Zuhrah yang merupakan salah seorang sahabat Abu Hurairah, bahwa [Abu Hurairah] berkata, \"Pernah Rasulullah Shallallahu'alaihiwasallam mengutus sepuluh orang sahabatnya yang di antaranya ialah Khubaib Al anshari, lantas [Ubaidullah bin Iyadl] memberitakan kepadaku bahwa [anak perempuan Al Harits] mengabarkan kepadanya, tatkala mereka (Banu Harits bin Amir bin Naufal) berkumpul, Khubaib bin 'Adi meminjam sebuah pisau kepada anak perempuan itu untuk membersihkan rambut-rambut tubuhnya. Tatkala mereka keluarkan Khubaib dari tanah haram untuk mereka bunuh, Khubaib Al anshari berkata, \"Aku tak peduli ketika aku terbunuh sebagai seorang muslim # Di bagian tubuh manapun aku terbunuh karena Allah # Asalkan itu semua demi Dzat Allah # Kalaulah Allah berkenan Ia memberi barakah di semua sambungan daging yang tercabik-cabik.\" Khubaib kemudian dibunuh oleh anak laki-laki Al Harits, dan nabi shallallahu 'alaihi wasallam kabarkan berita kematian Khubaib dan teman-temannya kepada sahabat-sahabatnya ketika mereka memperoleh musibah yang menimpanya.\""}};
